export type Outcome =
  | { kind: "statement"; cost: bigint; rowsAffected: number | null }
  | {
      kind: "query";
      columnNames: string[];
      columnTypes: string[];
      rows: Value[][];
      cost: bigint;
    };

// Retype an IDENTITY-owned sequence with PostgreSQL's ALTER SEQUENCE AS rules: old default bounds
// become the new type defaults, explicit bounds are preserved, and START/current must fit.
function retypeIdentitySequence(
  existing: SequenceDef,
  oldType: SeqDataType,
  newType: SeqDataType,
): SequenceDef {
  const def = { ...existing };
  const [oldMin, oldMax] = seqDataTypeDefaultBounds(oldType, def.increment);
  const [newMin, newMax] = seqDataTypeDefaultBounds(newType, def.increment);
  if (def.minValue === oldMin) def.minValue = newMin;
  if (def.maxValue === oldMax) def.maxValue = newMax;
  const [typeMin, typeMax] = seqDataTypeRange(newType);
  if (def.maxValue > typeMax)
    throw engineError(
      "invalid_parameter_value",
      `MAXVALUE (${def.maxValue}) is out of range for sequence data type ${seqDataTypePgName(newType)}`,
    );
  if (def.minValue < typeMin)
    throw engineError(
      "invalid_parameter_value",
      `MINVALUE (${def.minValue}) is out of range for sequence data type ${seqDataTypePgName(newType)}`,
    );
  if (def.minValue >= def.maxValue)
    throw engineError(
      "invalid_parameter_value",
      `MINVALUE (${def.minValue}) must be less than MAXVALUE (${def.maxValue})`,
    );
  seqBoundCheckStart(def.start, def.minValue, def.maxValue);
  seqBoundCheckLast(def.lastValue, def.minValue, def.maxValue);
  return def;
}

// SelectResult is the full result of running a SELECT (runSelect): the output column names and
// their resolved types, the rows in result order, and the accrued cost. Internal — executeSelect
// drops the types into the public Outcome, while INSERT ... SELECT uses the types to gate
// assignability up front (spec/design/grammar.md §24).
export type SelectResult = {
  columnNames: string[];
  columnTypes: ResolvedType[];
  rows: Value[][];
  cost: bigint;
};

// EmitMode is how an Emitter's rows are emitted (spec/design/streaming.md §4, S4):
//   - "project": the buffer rows are unprojected — emission evaluates the projection list (charging
//     its operatorEvals) + rowProduced per windowed row.
//   - "identity": the buffer rows are already the projected output (the DISTINCT dedup projected them
//     up front — the §3 asymmetry), so emission charges only rowProduced per windowed row.
//   - "final": the rows are a fully-formed result (the special input-streaming paths already projected
//     AND charged them) — emission hands them out with no further charge.
//   - "sorted": the streaming external sort's output, yielded LAZILY from the `sorted` pull iterator
//     (positioned past the OFFSET) — emission pulls the next sorted row, charges rowProduced, and
//     evaluates the projection list per windowed row, [0, end). So the output array is never built and a
//     caller's early exit skips the projection (and rowProduced) of the rows it never pulls (§4/§7).
export type EmitMode = "project" | "identity" | "final" | "sorted" | "columnar";

// Emitter describes how a SelectPlan's output rows are emitted (spec/design/streaming.md §4, S4): a
// SELECT runs its blocking part (scan/join/WHERE/window/sort/GROUP BY/DISTINCT) into a buffer, then
// emits a row at a time. execSelectEmit returns this so the emission can be driven EAGERLY (the
// materialized execute() path — execSelectPlan's drainEmitterEager builds the array) or LAZILY (the
// query() path — a bufferedRows generator yields it row by row, bounding output memory and
// short-circuiting a caller's early exit). Both drives charge the identical units at the identical
// sites (streaming.md §6). For "project"/"identity" the buffer is windowed to [start, end); for
// "final" start/end span the whole result; for "sorted" `sorted` is the streaming-sort output pull
// iterator (positioned past the OFFSET) and [0, end) is the window.
export type Emitter = {
  rows: Value[][];
  start: number;
  end: number;
  mode: EmitMode;
  // Set only for "sorted": the streaming-sort output pull iterator, positioned past the OFFSET.
  sorted?: SortedRows;
  // Set only for "columnar" (the projectColumnar fast path, packed-leaf.md §11 Track A2/A3): `cols` are
  // the pre-gathered dense per-column lanes (indexed by table ordinal) and `projCols` the projection's
  // column indices into them; emission builds output row j as [cols[projCols[0]][l], …] where l = sel[j]
  // (the A3 selection vector's survivor — a filtered scan) or j (all rows, sel undefined) — a bare-column
  // projection with no full-width row, charging rowProduced per windowed row exactly like "project" over
  // a bare column ref (a zero-cost slot read). Windowed to [start, end).
  cols?: Value[][];
  projCols?: number[];
  sel?: number[];
};

// finalEmitter wraps an already-projected-and-charged result (the special input-streaming paths) as a
// "final" Emitter — emission hands the rows out with no further charge (spec/design/streaming.md §4).
export function finalEmitter(rows: Value[][]): Emitter {
  return { rows, start: 0, end: rows.length, mode: "final" };
}

// sortedEmitter wraps the streaming external sort's output (positioned past the OFFSET, with `remaining`
// windowed rows still to emit) as a "sorted" Emitter — emission pulls + projects + charges rowProduced
// per row, so the output array is never built (spec/design/streaming.md §4/§7).
export function sortedEmitter(sorted: SortedRows, remaining: number): Emitter {
  return { rows: [], start: 0, end: remaining, mode: "sorted", sorted };
}

// Engine is the whole database: catalog + per-table in-memory stores. Single
// committed state (CLAUDE.md §3); the staging-buffer commit model lands later. Names
// are keyed case-insensitively (lowercased).
// DEFAULT_PAGE_SIZE is the default serialization page size (8 KiB — spec/design/storage.md §3),
// used for a fresh in-memory or newly-created database when no explicit size is given.
export const DEFAULT_PAGE_SIZE = 8192;

// DEFAULT_MAX_SQL_LENGTH is the default per-handle input-SQL byte limit (1 MiB — CLAUDE.md §13;
// spec/design/api.md §8, cost.md §7). The §13 input-size gate's default ceiling: generous for
// hand-written / ORM SQL, yet bounds the parse tree to a few MB so unbounded untrusted input
// cannot exhaust memory. A caller raises it (trusted bulk loads) or sets 0 for unlimited via
// setMaxSqlLength. Identical across cores (§8).
export const DEFAULT_MAX_SQL_LENGTH = 1 << 20;

// DEFAULT_TEMP_BUFFERS is the default per-session storage budget for SESSION-LOCAL temporary tables,
// in BYTES (spec/design/temp-tables.md §7). Temp tables RETAIN bytes across statements, which neither
// the per-statement cost ceiling (maxCost) nor the cumulative budget (lifetimeMaxCost) bounds, so
// tempBuffers is the §13 gate that does: the instant a session's resident temp storage (byte-identical
// on-disk record bytes) would exceed it, the write aborts 54P03. 0 ⇒ unlimited (a trusted handle).
// Identical across cores (§8); the abort point is part of the cross-core contract.
export const DEFAULT_TEMP_BUFFERS = 32 << 20;

// MAX_COMPOSITE_DEPTH is the maximum composite-type nesting depth (CLAUDE.md §13; cost.md §7b). A
// composite type's depth is the length of its deepest chain of nested composites, counting itself: a
// row of scalars is depth 1, `CREATE TYPE b AS (x a)` is `1 + depth(a)`, and an array field counts
// as its element (array levels are not composite levels — compositeRefName looks through one array
// level the same way). A CREATE TYPE whose result would exceed this is rejected 54001, and a loaded
// catalog that exceeds it is treated as corrupt XX001 — bounding the native recursion of every
// derived walk (value codec, comparator, record_out/record_in, resolveColType) at the two producers
// (DDL + load) so all downstream walks are transitively stack-safe. A fixed, cross-core constant like
// MAX_EXPR_DEPTH (§8). The chain is built across many cheap statements, so neither the per-statement
// input-size cap nor the parser nesting counter sees it (cost.md §7).
export const MAX_COMPOSITE_DEPTH = 32;

// SQL_BYTE_ENCODER measures a statement's UTF-8 byte length for the input-size gate (cost.md §7),
// matching the byte counts Rust (&str::len) and Go (len(string)) use, so the cap accepts / rejects
// identically across cores (§8). A TextEncoder is available in Node and the browser (the OPFS
// host), so this stays host-agnostic.
export const SQL_BYTE_ENCODER = new TextEncoder();

// Catalog names are ordered by the UTF-8 bytes of their lowercased form, matching Rust/Go raw
// string ordering. String#localeCompare is locale/ICU-sensitive and JavaScript's native UTF-16
// ordering differs from UTF-8 for supplementary code points.
export function compareLowerName(a: { name: string }, b: { name: string }): number {
  return compareBytes(
    SQL_BYTE_ENCODER.encode(a.name.toLowerCase()),
    SQL_BYTE_ENCODER.encode(b.name.toLowerCase()),
  );
}
// checkReservedName rejects a USER-written catalog object name beginning jed_ — the prefix is
// reserved for the engine's own catalog relations (spec/design/introspection.md §4). Case-insensitive
// (resolution folds case and there is no quoted-identifier escape — grammar.md §3). Engine-GENERATED
// names (a serial's <table>_<col>_seq, an index auto-name — both legal for a table named jed) never
// pass through here; the check sits with each site's namespace-collision check so established
// validation orders (42P01/42703 before name checks) are preserved. kind is the object word in the
// message: table / index / sequence / type / constraint.
export function checkReservedName(kind: string, name: string): void {
  if (name.length >= 4 && name.slice(0, 4).toLowerCase() === "jed_") {
    throw engineError(
      "reserved_name",
      `${kind} name ${name} is reserved (the jed_ prefix is reserved for system objects)`,
    );
  }
}

export function utf8ByteLength(s: string): number {
  return SQL_BYTE_ENCODER.encode(s).length;
}

// === string / text function kernels (spec/design/string-functions.md) ===============

// MAX_RESULT_CHARS is the character-count cap for the result-amplifying string functions (lpad /
// rpad / repeat): PostgreSQL's MaxAllocSize (0x3FFFFFFF). A requested length above it traps 54000
// (program_limit_exceeded), bounding the allocation an untrusted query can request (CLAUDE.md §13).
export const MAX_RESULT_CHARS = 0x3fffffffn;

// padChars is lpad/rpad over CODE POINTS (string-functions.md §3): pad s to `length` characters with
// `fill` (cyclically), on the left if `left` else the right; a string longer than `length` is
// truncated to its first `length` characters; an empty fill cannot pad (returns the truncated
// string); a length ≤ 0 is empty. A length above MAX_RESULT_CHARS traps 54000. Matches PG lpad/rpad.
export function padChars(s: string, length: bigint, fill: string, left: boolean): string {
  if (length > MAX_RESULT_CHARS)
    throw engineError("program_limit_exceeded", "requested length too large");
  if (length <= 0n) return "";
  const chars = [...s];
  const slen = BigInt(chars.length);
  if (slen >= length) return chars.slice(0, Number(length)).join("");
  const fchars = [...fill];
  if (fchars.length === 0) return s;
  const need = Number(length - slen);
  const flen = fchars.length;
  let pad = "";
  for (let i = 0; i < need; i++) pad += fchars[i % flen];
  return left ? pad + s : s + pad;
}

// trimChars is btrim/ltrim/rtrim over CODE POINTS (string-functions.md §3): remove from the chosen
// end(s) the longest run of characters each present in the set (a SET of code points, not a
// substring; default a single space). An empty set trims nothing. Matches PostgreSQL's *trim.
export function trimChars(s: string, set: string, doLeft: boolean, doRight: boolean): string {
  const inSet = new Set([...set]);
  const chars = [...s];
  let start = 0;
  let end = chars.length;
  if (doLeft) while (start < end && inSet.has(chars[start]!)) start++;
  if (doRight) while (end > start && inSet.has(chars[end - 1]!)) end--;
  return chars.slice(start, end).join("");
}

// translateChars is translate(s, from, to) over CODE POINTS (string-functions.md §3): each
// character of s that occurs in from is replaced by the character at the same position in to, or
// DELETED if to is shorter; a character's FIRST occurrence in from wins. Matches PostgreSQL.
export function translateChars(s: string, from: string, to: string): string {
  const tochars = [...to];
  const fromchars = [...from];
  const map = new Map<string, string | null>(); // null = delete
  for (let i = 0; i < fromchars.length; i++) {
    const c = fromchars[i]!;
    if (!map.has(c)) map.set(c, i < tochars.length ? tochars[i]! : null);
  }
  let out = "";
  for (const c of s) {
    if (map.has(c)) {
      const r = map.get(c);
      if (r != null) out += r; // null = delete (skip)
    } else {
      out += c;
    }
  }
  return out;
}

// repeatText is repeat(s, n) (string-functions.md §3): concatenate s n times; n ≤ 0 is empty. The
// result's byte size is bounded at MAX_RESULT_CHARS (PG's MaxAllocSize, a UTF-8-byte cap matching
// Rust/Go) — an over-large n·bytes traps 54000. Matches PostgreSQL's repeat.
export function repeatText(s: string, n: bigint): string {
  if (n <= 0n || s.length === 0) return "";
  const bytes = BigInt(utf8ByteLength(s));
  if (n > MAX_RESULT_CHARS / bytes)
    throw engineError("program_limit_exceeded", "requested length too large");
  return s.repeat(Number(n));
}

// splitPart is split_part(s, delim, n) (string-functions.md §3): split s on the substring delim and
// return the n-th field (1-based; a negative n counts from the end). Out of range → ''; n = 0 traps
// 22023. An EMPTY delim treats the whole string as one field (String.split would otherwise split
// into characters — a cross-core trap). Matches PostgreSQL's split_part.
export function splitPart(s: string, delim: string, n: bigint): string {
  if (n === 0n) throw engineError("invalid_parameter_value", "field position must not be zero");
  const fields = delim === "" ? [s] : s.split(delim);
  const len = BigInt(fields.length);
  const idx = n > 0n ? n - 1n : len + n;
  if (idx < 0n || idx >= len) return "";
  return fields[Number(idx)]!;
}

// chrText is chr(n) (string-functions.md §3): the one-character string for the Unicode code point n.
// PostgreSQL's error split: a negative n traps 22023; 0, a value above U+10FFFF, and a UTF-16
// surrogate (U+D800..U+DFFF) trap 54000.
export function chrText(n: bigint): string {
  if (n < 0n) throw engineError("invalid_parameter_value", "character number must be positive");
  if (n === 0n) throw engineError("program_limit_exceeded", "null character not permitted");
  if (n > 0x10ffffn)
    throw engineError("program_limit_exceeded", `requested character too large for encoding: ${n}`);
  if (n >= 0xd800n && n <= 0xdfffn)
    throw engineError("program_limit_exceeded", `requested character not valid for encoding: ${n}`);
  return String.fromCodePoint(Number(n));
}

// BASE64_ALPHABET is the standard RFC 4648 base64 alphabet (string-functions.md §3, encode/decode).
export const BASE64_ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";

// encodeBytea is encode(bytes, format) (string-functions.md §3): render binary as text. hex = two
// lowercase hex digits per byte; base64 = RFC 4648 wrapped at 76 chars with \n (PostgreSQL's style);
// escape = printable bytes verbatim, 0x00 → \000, backslash doubled, high-bit bytes → \nnn octal. An
// unrecognized format traps 22023.
export function encodeBytea(bytes: Uint8Array, format: string): string {
  if (format === "hex") {
    let out = "";
    for (const b of bytes) out += b.toString(16).padStart(2, "0");
    return out;
  }
  if (format === "escape") {
    let out = "";
    for (const b of bytes) {
      if (b === 0x00) out += "\\000";
      else if (b === 0x5c) out += "\\\\";
      else if (b >= 0x80) out += `\\${b.toString(8).padStart(3, "0")}`;
      else out += String.fromCharCode(b); // 0x01..0x7f except backslash
    }
    return out;
  }
  if (format === "base64") return base64EncodeWrapped(bytes);
  throw engineError("invalid_parameter_value", `unrecognized encoding: "${format}"`);
}

// base64EncodeWrapped is RFC 4648 base64 wrapped at 76 chars with \n (no trailing newline).
export function base64EncodeWrapped(bytes: Uint8Array): string {
  let b64 = "";
  for (let i = 0; i < bytes.length; i += 3) {
    const has1 = i + 1 < bytes.length;
    const has2 = i + 2 < bytes.length;
    const n = (bytes[i]! << 16) | ((has1 ? bytes[i + 1]! : 0) << 8) | (has2 ? bytes[i + 2]! : 0);
    b64 += BASE64_ALPHABET[(n >> 18) & 63];
    b64 += BASE64_ALPHABET[(n >> 12) & 63];
    b64 += has1 ? BASE64_ALPHABET[(n >> 6) & 63] : "=";
    b64 += has2 ? BASE64_ALPHABET[n & 63] : "=";
  }
  let out = "";
  for (let i = 0; i < b64.length; i++) {
    if (i > 0 && i % 76 === 0) out += "\n";
    out += b64[i];
  }
  return out;
}

// quoteLiteralText is quote_literal(s) (string-functions.md §3): wrap s as a SQL string literal —
// single-quoted, each internal ' doubled; if s contains a backslash, each \ is doubled and the
// literal is E-prefixed (matching PostgreSQL). Shared by quote_literal and quote_nullable.
export function quoteLiteralText(s: string): string {
  const hasBackslash = s.includes("\\");
  let inner = "";
  for (const c of s) {
    if (c === "'") inner += "''";
    else if (c === "\\") inner += "\\\\";
    else inner += c;
  }
  return hasBackslash ? `E'${inner}'` : `'${inner}'`;
}

// quoteIdentText is quote_ident(s) (string-functions.md §3): wrap s as a SQL identifier — returned
// unchanged if it is already a safe unquoted identifier (^[a-z_][a-z0-9_]*$), else double-quoted
// with each internal " doubled. jed quotes by the LEXICAL pattern only — no reserved-keyword
// quoting (jed has no enumerated keyword set), a documented divergence from PostgreSQL.
export function quoteIdentText(s: string): string {
  let safe = s.length > 0;
  for (let i = 0; i < s.length && safe; i++) {
    const code = s.charCodeAt(i);
    const lower = code === 95 || (code >= 97 && code <= 122); // '_' or a-z
    safe = i === 0 ? lower : lower || (code >= 48 && code <= 57); // + 0-9 after the first
  }
  if (safe) return s;
  let out = '"';
  for (const c of s) out += c === '"' ? '""' : c;
  return out + '"';
}

// decodeText is decode(s, format) (string-functions.md §3): the inverse of encode. hex and base64
// ignore whitespace; a malformed hex/base64 string traps 22023; a malformed escape sequence traps
// 22P02 (PostgreSQL's split). An unrecognized format traps 22023. Operates on the input's UTF-8
// bytes (SQL_BYTE_ENCODER), matching Rust (as_bytes) / Go ([]byte).
export function decodeText(s: string, format: string): Uint8Array {
  const bytes = SQL_BYTE_ENCODER.encode(s);
  if (format === "hex") return decodeHex(bytes);
  if (format === "base64") return decodeBase64(bytes);
  if (format === "escape") return decodeEscape(bytes);
  throw engineError("invalid_parameter_value", `unrecognized encoding: "${format}"`);
}

export function hexNibble(c: number): number | null {
  if (c >= 48 && c <= 57) return c - 48; // 0-9
  if (c >= 97 && c <= 102) return c - 97 + 10; // a-f
  if (c >= 65 && c <= 70) return c - 65 + 10; // A-F
  return null;
}

export function isAsciiWhitespace(c: number): boolean {
  return c === 32 || c === 9 || c === 10 || c === 13 || c === 11 || c === 12;
}

// decodeHex: pairs of hex digits (case-insensitive); whitespace ignored; non-hex / odd → 22023.
export function decodeHex(bytes: Uint8Array): Uint8Array {
  const nibbles: number[] = [];
  for (const b of bytes) {
    if (isAsciiWhitespace(b)) continue;
    const v = hexNibble(b);
    if (v === null) throw engineError("invalid_parameter_value", "invalid hexadecimal digit");
    nibbles.push(v);
  }
  if (nibbles.length % 2 !== 0)
    throw engineError("invalid_parameter_value", "invalid hexadecimal data: odd number of digits");
  const out = new Uint8Array(nibbles.length / 2);
  for (let i = 0; i < out.length; i++) out[i] = (nibbles[2 * i]! << 4) | nibbles[2 * i + 1]!;
  return out;
}

// decodeBase64 (RFC 4648); whitespace ignored; out-of-alphabet / data-after-pad → 22023.
export function decodeBase64(bytes: Uint8Array): Uint8Array {
  const out: number[] = [];
  let acc = 0;
  let nbits = 0;
  let padded = false;
  for (const b of bytes) {
    if (isAsciiWhitespace(b)) continue;
    if (b === 61) {
      padded = true;
      continue;
    } // '='
    if (padded) throw engineError("invalid_parameter_value", "invalid base64 end sequence");
    let v: number;
    if (b >= 65 && b <= 90)
      v = b - 65; // A-Z
    else if (b >= 97 && b <= 122)
      v = b - 97 + 26; // a-z
    else if (b >= 48 && b <= 57)
      v = b - 48 + 52; // 0-9
    else if (b === 43)
      v = 62; // +
    else if (b === 47)
      v = 63; // /
    else throw engineError("invalid_parameter_value", "invalid base64 end sequence");
    acc = (acc << 6) | v;
    nbits += 6;
    if (nbits >= 8) {
      nbits -= 8;
      out.push((acc >> nbits) & 0xff);
    }
  }
  return Uint8Array.from(out);
}

// decodeEscape: \\ → backslash, \nnn (exactly 3 octal digits ≤ 255) → that byte, any other byte →
// itself. A lone/short backslash or an octal > 255 traps 22P02.
export function decodeEscape(bytes: Uint8Array): Uint8Array {
  const bad = () =>
    engineError("invalid_text_representation", "invalid input syntax for type bytea");
  const oct = (c: number): number | null => (c >= 48 && c <= 55 ? c - 48 : null);
  const out: number[] = [];
  let i = 0;
  while (i < bytes.length) {
    if (bytes[i] !== 0x5c) {
      out.push(bytes[i]!);
      i++;
      continue;
    }
    if (i + 1 < bytes.length && bytes[i + 1] === 0x5c) {
      out.push(0x5c);
      i += 2;
    } else if (i + 3 < bytes.length) {
      const a = oct(bytes[i + 1]!);
      const b = oct(bytes[i + 2]!);
      const c = oct(bytes[i + 3]!);
      if (a === null || b === null || c === null) throw bad();
      const v = a * 64 + b * 8 + c;
      if (v > 255) throw bad();
      out.push(v);
      i += 4;
    } else {
      throw bad();
    }
  }
  return Uint8Array.from(out);
}

// initcapAscii is initcap(s) (string-functions.md §3): uppercase the first character of each word
// and lowercase the rest, where a word is a maximal run of ASCII alphanumerics. jed classifies word
// boundaries by ASCII alphanumerics and folds ASCII case only (by char-code arithmetic, so it is
// deterministic and cross-core-identical — full Unicode word classification would risk the
// cross-core Unicode-version trap). PostgreSQL agrees for ASCII; a non-ASCII letter is a word
// boundary (a documented divergence). Iterates code points ([...s]) for UTF-16 safety.
export function initcapAscii(s: string): string {
  let out = "";
  let wordStart = true;
  for (const c of s) {
    const code = c.codePointAt(0)!;
    if (code >= 48 && code <= 57) {
      // ASCII digit
      out += c;
      wordStart = false;
    } else if (code >= 65 && code <= 90) {
      // ASCII upper
      out += wordStart ? c : String.fromCharCode(code + 32);
      wordStart = false;
    } else if (code >= 97 && code <= 122) {
      // ASCII lower
      out += wordStart ? String.fromCharCode(code - 32) : c;
      wordStart = false;
    } else {
      out += c;
      wordStart = true;
    }
  }
  return out;
}

// substrChars is substr(s, start[, count]) over CODE POINTS (string-functions.md §3): 1-based; the
// window [start, start+count) (or [start, ∞) for the 2-arg form) intersected with [1, n]. A start
// ≤ 0 / past the end clips; a NEGATIVE count traps 22011. Matches PostgreSQL's text substr. Indices
// are bigint (so start+count never overflows); [...s] yields code points, not UTF-16 units.
export function substrChars(s: string, start: bigint, count: bigint | null): string {
  const chars = [...s];
  const n = BigInt(chars.length);
  let to: bigint;
  if (count !== null) {
    if (count < 0n) throw engineError("substring_error", "negative substring length not allowed");
    to = start + count;
    if (to > n + 1n) to = n + 1n;
  } else {
    to = n + 1n;
  }
  const from = start < 1n ? 1n : start;
  if (to <= from) return "";
  return chars.slice(Number(from - 1n), Number(to - 1n)).join("");
}

// leftChars is left(s, n) over CODE POINTS (string-functions.md §3): the first n characters; a
// negative n returns all but the last |n|. Matches PostgreSQL's left.
export function leftChars(s: string, n: bigint): string {
  const chars = [...s];
  const len = BigInt(chars.length);
  let end: bigint;
  if (n < 0n) {
    end = len + n;
    if (end < 0n) end = 0n;
  } else {
    end = n > len ? len : n;
  }
  return chars.slice(0, Number(end)).join("");
}

// rightChars is right(s, n) over CODE POINTS (string-functions.md §3): the last n characters; a
// negative n returns all but the first |n|. Matches PostgreSQL's right.
export function rightChars(s: string, n: bigint): string {
  const chars = [...s];
  const len = BigInt(chars.length);
  let start: bigint;
  if (n < 0n) {
    const skip = -n;
    start = skip > len ? len : skip;
  } else {
    start = len - n;
    if (start < 0n) start = 0n;
  }
  return chars.slice(Number(start)).join("");
}

// CollationVerdict is the slice-2d version-skew verdict for one referenced collation
// (spec/design/collation.md §12, compatibility.md §7). "full" ⇒ a loaded bundle provides the name at
// the file's pinned (unicode, cldr), so the collation's objects are read-write. "skewed" ⇒ a loaded
// bundle provides it at a DIFFERENT version, so its objects are read-only (reads recompute against the
// loaded table — the heap-scan fallback; a write raises XX002). A pure comparison of the file pin (§5)
// vs the loaded set — every core computes the identical verdict (the §10 cross-core contract).
export type CollationVerdict = "full" | "skewed";

// CollationInfo is introspection metadata for one loaded collation (db.collations,
// spec/design/collation.md §1). contentHash is the CRC-32 of the compiled table (the reference-mode
// stamp, §3/§4); description is provenance, excluded from the hash. verdict is the slice-2d
// version-skew verdict (§12) — "full" for the engine-global loaded set (it IS the reference); for a
// database's referenced collations it is "skewed" when the file's pin differs from the loaded bundle's.
export type CollationInfo = {
  name: string;
  unicodeVersion: string;
  cldrVersion: string;
  contentHash: number;
  description: string;
  isDefault: boolean;
  verdict: CollationVerdict;
};

// FkDependent is one FOREIGN KEY dependent surfaced by a multi-table DROP TABLE's dependency scan
// (spec/design/grammar.md §13): an FK on a table that survives the drop, referencing a table being
// dropped. RESTRICT formats refTableName/fkName/droppedName into its 2BP01 detail; CASCADE uses
// refTableKey/fkName to remove the now-dangling constraint.
export type FkDependent = {
  refTableKey: string; // lowercased key of the (surviving) referencing table — for the CASCADE removal
  fkName: string; // the FK constraint's name
  refTableName: string; // canonical referencing-table name — for the RESTRICT detail
  droppedName: string; // canonical name of the dropped table the FK references — for the RESTRICT detail
};

export class Engine {
  // The last committed, immutable state — what fresh readers (and autocommit reads) see.
  committed: Snapshot;
  // core is the shared core this engine's session belongs to (attached-databases.md §5), or null for a
  // bare/transient engine (a test engine, a snapshotEngine, a committed introspection engine — none of
  // which see attachments). It is the engine's route to the core-owned attachment registry
  // (core.attachments) during a commit persist; the READ view of attachments is attachedCommitted below.
  core: AttachmentCore | null = null;
  // attachedCommitted is the PINNED committed root of every host-attached DATABASE-scoped database
  // (attached-databases.md §5), keyed by lowercased name — this session's stable read view, snapshot
  // isolated: refreshed from the core's attached roots at each autocommit statement and pinned for the
  // life of an explicit BEGIN block. Empty when nothing is attached. Session-local temp is NOT here (it
  // is on SessionState.tempCommitted); this is only the Database-scoped roots.
  attachedCommitted: Map<string, Snapshot> = new Map();
  // The DEFAULT SESSION (spec/design/session.md §2.1): the per-connection state this handle runs
  // statements through — the open transaction (the Idle/Open/Failed machine, §2.2), the relocated
  // settings (maxCost/maxSqlLength/workMem, the entropy/clock seam), and the currval/lastval session
  // state. A bare Engine IS committed storage + this one long-lived stateful default session; the
  // convenience methods operate on it. newSession mints additional independent sessions (run
  // sequentially on this single-threaded handle by swapping into this slot for a call).
  session: SessionState;
  // Persistence identity (spec/design/api.md §2): the backing file path (null for in-memory) and
  // the page size this database serializes with. The commit counter lives in `committed.txid`.
  path: string | null;
  pageSize: number;
  // pageCount is the on-disk page high-water — the index an incremental commit extends at when the
  // free-list is exhausted (spec/fileformat/format.md). Set from the file's meta on open, from the
  // initial image on create; 0 (unused) for an in-memory database.
  pageCount: number;
  // freePages is the free-list (P6.2): page indices a prior root abandoned, reusable by the next
  // incremental commit (spec/fileformat/format.md *Reclamation*). Reconstructed on open as
  // [2, pageCount) minus the committed root's reachable pages; drawn lowest-first before the file is
  // extended. A page leaves the list only by being allocated into a new committed version, so it is
  // reachable from no live snapshot and reuse is torn-write-safe. Empty for an in-memory database and
  // for a freshly-created file (a from-scratch image leaks nothing).
  freePages: number[];
  // persistHook is the durable-write seam (spec/design/storage.md §2): null for an in-memory
  // database, set by a durable host (file.ts Node `fs` / opfs.ts Browser/OPFS — both to the shared
  // incremental commit, persist.ts) — and so the signal that a commit advances txid + persists (used
  // by commitTx). It is called by commitTx with the working snapshot being published (transactions.md
  // §4.1/§9). Injecting it here keeps the executor free of a host-module dependency (no import cycle).
  persistHook: ((db: Engine, snap: Snapshot) => void) | null;
  // paging is the shared paging context for a file-backed database (spec/design/pager.md): the open
  // pager (kept for the handle's life) + the bounded leaf buffer pool, shared with every table store
  // so reads fault OnDisk leaves through the one pool. The load reads pages through it and every commit
  // writes through it. null for an in-memory database (persistHook is then null too); set by file.ts
  // open/create, dropped by close. A type-only import keeps the executor free of a file-module dependency.
  paging: SharedPaging | null;
  // readOnly marks a handle opened read-only (spec/design/api.md §2.1, OpenOptions.readOnly). A
  // read-only handle behaves like PostgreSQL hot standby: every transaction defaults to READ ONLY,
  // an explicit READ WRITE request and any write statement are 25006, and the file is opened
  // without write access, so it is never written. Always false for an in-memory or
  // normally-opened database.
  readOnly: boolean;
  // spillSink is the host backing for the ORDER BY external merge sort's spilled runs (spec/design/
  // spill.md §4): set by a durable host that can spill to disk (file.ts → FileSpillSink), null for an
  // in-memory or OPFS database (which never spills — sorts stay resident, spill.md §2). A type-only
  // import keeps the executor free of any node:* dependency (the Node `fs` impl lives in spillfile.ts),
  // so the engine runs in a browser bundle (the OPFS host).
  spillSink: SpillSink | null;
  // reclaimWithinSession turns on within-session free-list compaction (persist.ts maybeCompact): the
  // never-reopened in-RAM temp domains set it (temp-tables.md §6, bplus-reshape.md), so their
  // copy-on-write orphans are reclaimed rather than leaked. The main file/in-memory domain ALSO sets it
  // (v25 continuous reclamation); its within-session reuse is watermark-gated by freeGenTxid (§8). When
  // TS models a "storage" it is an Engine, so this rides here.
  reclaimWithinSession: boolean;
  // liveAtCompaction is the reachable page count recorded at the last compaction — the cheap trigger
  // basis: compaction re-runs only once the high-water passes ~2× it (periodic ~2× bound, no per-commit
  // walk).
  liveAtCompaction: number;
  // freeGenTxid is the version the current freePages list is "as of" — the last compaction's txid, or the
  // committed version at open. It gates within-session reuse under the reader-liveness watermark
  // (transactions.md §8): a page dead at generation G is safe to reuse only once no live reader pins a
  // version older than G. persistImpl reuses the free-list only when oldest_live ≥ freeGenTxid; otherwise
  // it allocates from the high-water and the free-list waits (still persisted). With no reader pinning an
  // older version (single-handle, reconstruct-on-open, all readers current) the gate always passes, so the
  // on-disk byte layout is byte-for-byte unchanged.
  freeGenTxid: bigint;
  // tempStorage is the SESSION-LOCAL temp domain's storage Engine (temp-tables.md §6): the private in-RAM
  // MemoryBlockStore + pager + pinned pool its temp tables ride, with within-session compaction on.
  // Created lazily on the first session-local temp DDL (newTempStorage); null until then. Its pageCount
  // is the domain's footprint — the page-based temp budget.
  tempStorage: Engine | null;
  // openStreams counts this handle's live streaming cursors (Query's pull source, not a materialized
  // result). A streaming cursor pins a snapshot it faults lazily, so while one is open a temp-domain
  // compaction (persistTemp → maybeCompact) must NOT reclaim pages — it could free one the cursor still
  // faults. Incremented when a streaming Rows opens (shared.ts), decremented on Close.
  openStreams: number;

  constructor() {
    this.committed = new Snapshot();
    this.session = new SessionState();
    this.path = null;
    this.pageSize = DEFAULT_PAGE_SIZE;
    this.pageCount = 0;
    this.freePages = [];
    this.persistHook = null;
    this.paging = null;
    this.readOnly = false;
    this.spillSink = null;
    this.reclaimWithinSession = false;
    this.liveAtCompaction = 0;
    this.freeGenTxid = 0n;
    this.tempStorage = null;
    this.openStreams = 0;
  }

  // setMaxCost sets the execution-cost ceiling for statements run on this handle (CLAUDE.md §13;
  // spec/design/api.md §8). A positive limit bounds every subsequent statement: it aborts with 54P01
  // the instant accrued cost reaches limit (spec/design/cost.md §6). limit <= 0n (the default) is
  // unlimited. The primary guard for safely evaluating untrusted, user-supplied queries; a handle
  // setting, not stored in the file.
  setMaxCost(limit: bigint): void {
    this.session.maxCost = limit;
  }

  // setLifetimeMaxCost sets the PER-SESSION cumulative cost budget on the default session
  // (spec/design/session.md §5.4); limit <= 0n (the default) is unlimited. Where maxCost bounds one
  // statement (54P01), this bounds the whole session: the instant the session's running cumulative
  // cost reaches limit the in-flight statement aborts 54P02, and once spent every further statement is
  // rejected 54P02 at admission. The multi-tenant / untrusted-host gate atop maxCost; a handle
  // setting, not stored in the file.
  setLifetimeMaxCost(limit: bigint): void {
    this.session.lifetime.limit = limit;
  }

  // lifetimeMaxCost is the default session's per-session cumulative cost budget (0n ⇒ unlimited).
  lifetimeMaxCost(): bigint {
    return this.session.lifetime.limit;
  }

  // lifetimeCost is the default session's running CUMULATIVE execution cost so far
  // (spec/design/session.md §5.4) — the gauge the lifetime_max_cost budget bounds. Tracked even when
  // unlimited; survives a transaction rollback (session state, not snapshot state).
  lifetimeCost(): bigint {
    return this.session.lifetime.total;
  }

  // setDefaultPrivileges replaces the default session's default table-privilege set — the
  // GRANT … ON ALL TABLES default (spec/design/session.md §5.3). PrivilegeSet.empty().with("select")
  // makes the session read-only (a write resolves to 42501). A handle setting, not stored in the file.
  setDefaultPrivileges(privs: PrivilegeSet): void {
    this.session.privileges.setDefaultTable(privs);
  }

  // grant grants privs on a specific object (table or function) on the default session (§5.3).
  grant(privs: PrivilegeSet, object: string): void {
    this.session.privileges.grant(privs, object);
  }

  // revoke revokes privs from a specific object on the default session (revoke wins, §5.3).
  revoke(privs: PrivilegeSet, object: string): void {
    this.session.privileges.revoke(privs, object);
  }

  // resetPrivileges resets the default session's authorization envelope to fully permissive — every
  // table privilege, no per-object delta, DDL allowed (§5.3). The conformance harness calls this
  // before each record so a # default_privileges: / # grant: / # revoke: / # allow_ddl: directive
  // never leaks past the record it decorates.
  resetPrivileges(): void {
    this.session.privileges = new Privileges();
    this.session.allowDdl = true;
    // The temp-DDL gate is part of the authorization envelope (temp-tables.md §5); reset it with the
    // rest so a # allow_temp_ddl: directive never leaks past its record. Default-inherit allowDdl=true.
    this.session.allowTempDdl = true;
  }

  // privileges is read-only access to the default session's authorization envelope (§5.3).
  privileges(): Privileges {
    return this.session.privileges;
  }

  // setAllowDdl sets whether DDL is permitted on the default session (§5.3); a denied change is 42501.
  setAllowDdl(allow: boolean): void {
    this.session.allowDdl = allow;
  }

  // allowDdl reports whether DDL is permitted on the default session.
  allowDdl(): boolean {
    return this.session.allowDdl;
  }

  // setAllowTempDdl sets whether session-local temporary-table DDL is permitted on the default session
  // (spec/design/temp-tables.md §5) — the temp-scoped split of allowDdl; a denied temp DDL is 42501.
  setAllowTempDdl(allow: boolean): void {
    this.session.allowTempDdl = allow;
  }

  // allowTempDdl reports whether session-local temporary-table DDL is permitted on the default session.
  allowTempDdl(): boolean {
    return this.session.allowTempDdl;
  }

  // setTempBuffers sets the default session's per-session temp-table storage budget in BYTES
  // (spec/design/temp-tables.md §7); 0 ⇒ unlimited. An over-budget temp write aborts 54P03.
  setTempBuffers(bytes: number): void {
    this.session.tempBuffers = bytes;
  }

  // tempBuffers reports the default session's per-session temp-table storage budget (0 ⇒ unlimited).
  tempBuffers(): number {
    return this.session.tempBuffers;
  }

  // setVar sets a session variable on the default session (spec/design/session.md §6.1). Custom
  // variables must be namespaced (a dotted name); a non-dotted name throws 42704. Read it back in SQL
  // with current_setting('name'[, missing_ok]).
  setVar(name: string, value: string): void {
    this.session.setVar(name, value);
  }

  // resetVar clears a session variable on the default session (§6.1); a non-dotted name throws 42704.
  resetVar(name: string): void {
    this.session.resetVar(name);
  }

  // var reads a session variable's value on the default session (§6.1), or undefined if it is not set.
  var(name: string): string | undefined {
    return this.session.var(name);
  }

  // resetVars clears every session variable on the default session (§6.1) — PostgreSQL's RESET ALL for
  // the variable map (also the conformance harness # set: reset hook).
  resetVars(): void {
    this.session.resetVars();
  }

  // setTimeZone sets the time zone on the default session (spec/design/session.md §6.2, timezones.md
  // §9.4): the zone a timestamptz is decomposed in by date_trunc / EXTRACT / the cross-family casts.
  // Accepts UTC, a fixed ±HH:MM offset, or a named IANA zone a loaded JTZ bundle provides; else 22023.
  setTimeZone(zone: string): void {
    this.session.setTimeZone(zone);
  }

  // setMaxSqlLength sets the maximum input SQL length, in bytes, accepted on this handle (CLAUDE.md
  // §13; spec/design/api.md §8). A statement whose text exceeds bytes is rejected with 54000 at
  // parse entry, before lexing — the §13 input-size gate (cost.md §7). 0 is unlimited (a trusted
  // caller's opt-out); the default is DEFAULT_MAX_SQL_LENGTH (1 MiB). A handle setting, not stored
  // in the file (mirrors setMaxCost).
  setMaxSqlLength(bytes: number): void {
    this.session.maxSqlLength = bytes;
  }

  // parse parses one statement from sql, first enforcing this handle's maxSqlLength input-size limit
  // (CLAUDE.md §13; spec/design/api.md §8, cost.md §7). The §13 input-size gate: an over-limit
  // statement is rejected with 54000 before lexing, so unbounded untrusted input cannot exhaust
  // parse memory/CPU (the cost meter cannot catch this — parsing precedes metering). maxSqlLength
  // == 0 is unlimited. Every handle-bound parse path routes through here (execute/executeParams/
  // prepare/the session handles), so the per-handle limit has no hole. The byte length is the UTF-8
  // byte count, matching Rust/Go's byte-length idiom for cross-core identity (§8) — a JS UTF-16
  // .length would diverge on multi-byte input.
  parse(sql: string): Statement {
    const max = this.session.maxSqlLength;
    // Fast reject without encoding: a string's UTF-8 byte length is always >= its UTF-16 .length,
    // so if even the UTF-16 length exceeds the cap the statement is over-limit. Otherwise measure
    // the exact UTF-8 byte length (then bounded by the cap, so the encode is bounded).
    if (max > 0 && (sql.length > max || utf8ByteLength(sql) > max)) {
      throw engineError(
        "program_limit_exceeded",
        `SQL statement exceeds the maximum length of ${max} bytes`,
      );
    }
    return parseSQL(sql);
  }

  // setRandomSource injects a random source for the uuid generators (spec/design/entropy.md §6) —
  // the deterministic / reproducible path. Pass seededRandomSource for a byte-identical cross-core
  // stream (the conformance # seed: directive). clearRandomSource returns to the OS CSPRNG, drawn
  // per value (production — unpredictable output).
  setRandomSource(f: RandomFill): void {
    this.session.seam.randomFill = f;
  }

  clearRandomSource(): void {
    this.session.seam.randomFill = undefined;
  }

  // setClockSource injects a clock source for uuidv7 (entropy.md §6) — e.g. fixedClock (the # clock:
  // directive). clearClockSource returns to the wall clock.
  setClockSource(f: ClockFunc): void {
    this.session.seam.clock = f;
  }

  clearClockSource(): void {
    this.session.seam.clock = undefined;
  }

  // setWorkMem sets the work-memory budget (in bytes) for blocking operators run on this handle
  // (spec/design/spill.md §3, api.md §2.1): the ORDER BY external merge sort holds at most roughly
  // this many bytes of rows resident before it spills sorted runs to disk. 0 is unlimited (never
  // spill). It never changes what a query observes (results + cost are invariant — spill.md §6),
  // only when an operator spills; an in-memory database ignores it. A handle setting, not stored in
  // the file (mirrors setMaxCost).
  setWorkMem(bytes: number): void {
    this.session.workMem = bytes;
  }

  // readSnap is the snapshot a read sees: the read pin if one is set (a data-modifying WITH statement
  // pins the pre-statement snapshot so every sub-statement reads it — writable-cte.md §2), else the
  // open transaction's working (read-your-writes for a writable tx; the pinned snapshot for a
  // read-only tx), else the committed snapshot.
  private readSnap(): Snapshot {
    if (this.session.readPin !== null) {
      return this.session.readPin;
    }
    return this.session.tx !== null ? this.session.tx.working : this.committed;
  }

  // working is the snapshot a write mutates — the open transaction's working. A write only ever
  // runs with a transaction open (autocommit opens one implicitly), so tx is non-null here.
  private working(): Snapshot {
    // Mark the main image dirty so the commit knows to persist it; a temp-only transaction never
    // reaches here (it writes via the temp funnels) and so makes zero file writes (temp-tables.md §2).
    this.session.tx!.mainDirty = true;
    return this.session.tx!.working;
  }

  // tempSnap is the session's temp-table snapshot for READS (spec/design/temp-tables.md §2): the open
  // transaction's tempWorking, else the session's committed temp state. The temp analogue of readSnap
  // (it does not consult readPin — a writable-CTE pins only the main snapshot).
  private tempSnap(): Snapshot {
    return this.session.tx !== null ? this.session.tx.tempWorking : this.session.tempCommitted;
  }

  // tempDomainPaging returns the MemoryBlockStore paging context for the session-local temp domain
  // (temp-tables.md §6), lazily creating the domain's storage Engine (newTempStorage — a private
  // in-RAM store + pinned pool with within-session compaction on) on first use.
  tempDomainPaging(): SharedPaging {
    if (this.tempStorage === null) this.tempStorage = newTempStorage(this.pageSize);
    return this.tempStorage.paging!;
  }

  // isTempTable reports whether name resolves to a SESSION-LOCAL temporary table in the visible temp
  // snapshot (spec/design/temp-tables.md §3). Preclude-overlaps guarantees a name is temp XOR
  // persistent, so this is the routing predicate the table/store funnels use.
  private isTempTable(name: string): boolean {
    return this.tempSnap().table(name) !== undefined;
  }

  // checkTableQualifier validates an optional database qualifier on a table reference against the
  // implicit scope (spec/design/attached-databases.md §3, Slice 1a). A qualified name reaches a
  // specific database: `main` (the file / persistent database) or `temp` (the session-local domain) —
  // the two reserved implicit qualifiers this slice recognizes; a host-attached database arrives in
  // Slice 1b, so any other qualifier is 42P01 "database … is not attached". Because jed precludes
  // overlaps (a name is temp XOR persistent within a session, §3), a valid qualifier resolves to the
  // SAME store the bare name would, so this is a VALIDATION GATE, not a routing change: it asserts the
  // named relation lives in the claimed database (else 42P01), and the downstream temp-first funnel
  // then resolves it to the matching scope. An undefined qualifier (a bare, implicit-scope name) always
  // passes. The qualifier is matched case-insensitively (unquoted identifiers fold to lower case).
  private checkTableQualifier(qualifier: string | undefined, name: string): void {
    if (qualifier === undefined) {
      return;
    }
    switch (qualifier.toLowerCase()) {
      case "temp":
        if (!this.isTempTable(name)) {
          throw engineError("undefined_table", `relation "temp.${name}" does not exist`);
        }
        break;
      case "main":
        if (this.readSnap().table(name) === undefined) {
          throw engineError("undefined_table", `relation "main.${name}" does not exist`);
        }
        break;
      default: {
        // A host-attached database (attached-databases.md §5): resolve its pinned/working snapshot, then
        // assert the relation lives there. An unknown name is 42P01 "not attached"; a known database
        // missing the table is 42P01 "relation … does not exist".
        const snap = this.attachReadSnap(qualifier.toLowerCase());
        if (snap === undefined) {
          throw engineError("undefined_table", `database "${qualifier}" is not attached`);
        }
        if (snap.table(name) === undefined) {
          throw engineError("undefined_table", `relation "${qualifier}.${name}" does not exist`);
        }
      }
    }
  }

  // checkAttachmentWritable rejects a WRITE (DML or DDL) targeting a READ-ONLY host attachment with
  // 25006 (attached-databases.md §4), before any I/O. An undefined scope, or `main`/`temp` (never
  // read-only via a qualifier — the read-only handle path is separate), or a read-write attachment
  // passes. Unknown attachments are caught by the qualifier gate, so this only inspects the mode.
  private checkAttachmentWritable(scope: string | undefined): void {
    if (scope === undefined || this.core === null) return;
    const name = scope.toLowerCase();
    if (name === "main" || name === "temp") return;
    const att = this.core.attachments.get(name);
    if (att?.readOnly) {
      throw engineError(
        "read_only_sql_transaction",
        `cannot write to read-only database "${scope}"`,
      );
    }
  }

  // attachReadSnap returns the READ snapshot of a host-attached database (attached-databases.md §5) —
  // the transaction's working clone if this tx wrote it, else the pinned committed root
  // (attachedCommitted). undefined when no attachment is named `name` (the caller raises 42P01). name
  // is expected lowercased.
  private attachReadSnap(name: string): Snapshot | undefined {
    const tx = this.session.tx;
    if (tx !== null && tx.attachWorking !== undefined) {
      const ws = tx.attachWorking.get(name);
      if (ws !== undefined) return ws;
    }
    return this.attachedCommitted.get(name);
  }

  // attachWriteSnap returns the WRITE snapshot of a host-attached database, cloning the pinned committed
  // root into the transaction's per-attachment working set on first write and marking it dirty (the
  // attachment analogue of working()/tempWorking). undefined if the attachment is unknown (unreachable
  // after the qualifier gate). name is expected lowercased.
  private attachWriteSnap(name: string): Snapshot | undefined {
    const tx = this.session.tx!;
    if (tx.attachWorking === undefined) {
      tx.attachWorking = new Map();
      tx.attachDirty = new Set();
    }
    const existing = tx.attachWorking.get(name);
    if (existing !== undefined) {
      tx.attachDirty!.add(name);
      return existing;
    }
    const base = this.attachedCommitted.get(name);
    if (base === undefined) return undefined;
    const ws = base.clone();
    tx.attachWorking.set(name, ws);
    tx.attachDirty!.add(name);
    return ws;
  }

  // attachPageSize is the page size of a host attachment's OWN page space (attached-databases.md §2) —
  // used to build its NEW stores (CREATE TABLE / CREATE INDEX) at the size its commit serializes to. A
  // file attachment carries its own page size, baked into the file, which may differ from main's; an
  // in-memory one matches main. The attachment is known to exist (the qualifier gate passed).
  private attachPageSize(name: string): number {
    return this.core!.attachments.get(name)!.storage.pageSize;
  }

  // attachReadView returns the current READ view of every attached database — the transaction's working
  // clone where this tx wrote it, else the pinned committed root — as one frozen map. Used to freeze a
  // snapshotEngine's attachment view (whose own tx is null, so it reads straight from this map). Returns
  // attachedCommitted directly when no attachment has been written this tx (the common case, no alloc).
  private attachReadView(): Map<string, Snapshot> {
    const tx = this.session.tx;
    if (tx === null || tx.attachWorking === undefined || tx.attachWorking.size === 0) {
      return this.attachedCommitted;
    }
    const view = new Map(this.attachedCommitted);
    for (const [k, v] of tx.attachWorking) view.set(k, v);
    return view;
  }

  // snapForScope returns the READ snapshot for an explicit database qualifier (attached-databases.md
  // §3): `main` / `temp` / a host attachment. Used only when scope is defined; an undefined scope keeps
  // the bare temp-first funnels (a name is temp XOR persistent). undefined for an unknown attachment
  // (the qualifier gate already raised 42P01, so unreachable in practice).
  //
  // This funnel IS where Slice 1c's "temp is an implicit in-memory attachment" reframe is realized
  // (attached-databases.md §6): `temp`, `main`, and every host attachment resolve through one
  // scoped-routing path, so a temp table is a citizen of the same mechanism an attachment is. What stays
  // deliberately distinct is temp's lifecycle — it is SESSION-SCOPED (tempSnap reads session-private
  // state; commit lands on the session's temp root with no cross-session roots publish; its reclamation
  // watermark is the session's open-cursor count, not the Database-wide live registry). That divergence
  // is correct, not a gap: relocating temp into the Database-scoped attachment registry would re-share
  // it across sessions (what Slice 0 removed). So temp routes like an attachment here but keeps its own
  // home.
  private snapForScope(scope: string): Snapshot | undefined {
    switch (scope.toLowerCase()) {
      case "temp":
        return this.tempSnap();
      case "main":
        return this.readSnap();
      default:
        return this.attachReadSnap(scope.toLowerCase());
    }
  }

  // lkpTableScoped resolves a table's catalog entry honoring an explicit database qualifier
  // (attached-databases.md §3); an undefined scope keeps the bare temp-first walk.
  private lkpTableScoped(scope: string | undefined, name: string): Table | undefined {
    if (scope === undefined) return this.lkpTable(name);
    return this.snapForScope(scope)?.table(name);
  }

  // lkpStoreScoped resolves a table's READ store honoring an explicit database qualifier; an undefined
  // scope keeps the bare temp-first funnel.
  private lkpStoreScoped(scope: string | undefined, name: string): TableStore {
    if (scope === undefined) return this.lkpStore(name);
    return this.snapForScope(scope)!.store(name);
  }

  // writeStoreScoped resolves a table's WRITE store honoring an explicit database qualifier, marking the
  // right domain dirty (main / temp / the attachment); an undefined scope keeps the bare temp-first funnel.
  private writeStoreScoped(scope: string | undefined, name: string): TableStore {
    if (scope === undefined) return this.writeStore(name);
    switch (scope.toLowerCase()) {
      case "temp":
        this.session.tx!.tempDirty = true;
        return this.session.tx!.tempWorking.store(name);
      case "main":
        return this.working().store(name);
      default:
        return this.attachWriteSnap(scope.toLowerCase())!.store(name);
    }
  }

  // lkpIndexStoreScoped / writeIndexStoreScoped are the index-store analogues of lkpStoreScoped /
  // writeStoreScoped: an index belongs to the same database as its table, so the DML target's scope
  // routes them. An undefined scope keeps the bare temp-first funnel.
  private lkpIndexStoreScoped(scope: string | undefined, nameKey: string): TableStore {
    if (scope === undefined) return this.lkpIndexStore(nameKey);
    return this.snapForScope(scope)!.indexStore(nameKey);
  }

  private writeIndexStoreScoped(scope: string | undefined, nameKey: string): TableStore {
    if (scope === undefined) return this.writeIndexStore(nameKey);
    switch (scope.toLowerCase()) {
      case "temp":
        this.session.tx!.tempDirty = true;
        return this.session.tx!.tempWorking.indexStore(nameKey);
      case "main":
        return this.working().indexStore(nameKey);
      default:
        return this.attachWriteSnap(scope.toLowerCase())!.indexStore(nameKey);
    }
  }

  // compositeDependentAny is the DROP TYPE … RESTRICT dependency check across every visible scope
  // (spec/design/temp-tables.md §8): the main image (tables + composite fields), then the visible
  // session-local temp snapshot (its tables). A composite type is always persistent, but a TEMP table
  // column may reference it, so dropping the type while such a temp table exists is 2BP01 — matching the
  // persistent case (PostgreSQL blocks the drop). A session sees only its own session-local temp tables
  // (another session's private temp table is invisible by design — and its resolved ColType is
  // self-contained, so it keeps working regardless).
  private compositeDependentAny(name: string): string | null {
    return this.readSnap().compositeDependent(name) ?? this.tempSnap().compositeDependent(name);
  }

  // isTempIndex reports whether name is a secondary index on a SESSION-LOCAL temp table
  // (spec/design/temp-tables.md §8) — the index analogue of isTempTable, used to gate (allowTempDdl)
  // and route a DROP INDEX of a temp index. Preclude-overlaps keeps an index name in one scope.
  private isTempIndex(name: string): boolean {
    return this.tempSnap().findIndex(name) !== null;
  }

  // sequence resolves a sequence by name along the resolution walk session-local → persistent
  // (spec/design/sequences.md + temp-tables.md §8). Preclude-overlaps keeps a name in at most one scope
  // (the shared relation namespace), so this is just "where the sequence lives". Every sequence READ
  // (nextval/currval/setval resolution, DROP/ALTER SEQUENCE) goes through here, so a serial/IDENTITY
  // column's OWNED temp sequence resolves exactly like a persistent one.
  private sequence(name: string): SequenceDef | undefined {
    return this.tempSnap().sequence(name) ?? this.readSnap().sequence(name);
  }

  // isTempSequence reports whether name is a sequence in the SESSION-LOCAL temp snapshot
  // (temp-tables.md §8) — the sequence analogue of isTempTable. A temp sequence only ever arises from a
  // serial/IDENTITY temp column (standalone CREATE SEQUENCE is always persistent), so it is always owned.
  private isTempSequence(name: string): boolean {
    return this.tempSnap().sequence(name) !== undefined;
  }

  // putSequenceRouted stages a sequence def into whichever scope currently owns its name (flagging the
  // matching dirty bit): session-local temp, else the main working set. A serial/IDENTITY temp column's
  // owned sequence advances (nextval flush) into its temp snapshot — like the table's rows, zero file
  // writes (temp-tables.md §2); a brand-new persistent sequence is absent from the temp scope and lands
  // in the main image.
  private putSequenceRouted(def: SequenceDef): void {
    if (this.isTempSequence(def.name)) {
      this.session.tx!.tempDirty = true;
      this.session.tx!.tempWorking.putSequence(def);
    } else {
      this.working().putSequence(def);
    }
  }

  // removeSequenceRouted removes a sequence from whichever scope owns its name (the routed analogue of
  // putSequenceRouted). Used by DROP SEQUENCE and DROP TABLE's owned-sequence auto-drop.
  private removeSequenceRouted(name: string): void {
    const key = name.toLowerCase();
    if (this.isTempSequence(name)) {
      this.session.tx!.tempDirty = true;
      this.session.tx!.tempWorking.removeSequence(key);
    } else {
      this.working().removeSequence(key);
    }
  }

  // setColumnDefaultExprRouted rewrites a column's stored DEFAULT expression in whichever scope owns the
  // table — the routed analogue used by ALTER SEQUENCE … RENAME of an owned sequence (temp-tables.md §8),
  // so a renamed owned TEMP sequence's nextval default is rewritten in the temp snapshot.
  private setColumnDefaultExprRouted(tableKey: string, column: number, de: DefaultExpr): void {
    if (this.isTempTable(tableKey)) {
      this.session.tx!.tempDirty = true;
      this.session.tx!.tempWorking.setColumnDefaultExpr(tableKey, column, de);
    } else {
      this.working().setColumnDefaultExpr(tableKey, column, de);
    }
  }

  // lkpTable resolves a table by name along the resolution walk session-local → persistent
  // (temp-tables.md §3). Preclude-overlaps keeps a name in at most one scope, so this is just "where it lives".
  private lkpTable(name: string): Table | undefined {
    return this.tempSnap().table(name) ?? this.readSnap().table(name);
  }

  // lkpStore returns a table's store for READS, routing by the resolution walk (session-local temp →
  // visible main snapshot — temp-tables.md §2). No dirty flag — reads never persist.
  private lkpStore(name: string): TableStore {
    if (this.isTempTable(name)) return this.tempSnap().store(name);
    return this.readSnap().store(name);
  }

  // writeStore returns a table's store for MUTATION, routing a session-local temp write to tempWorking
  // (flagging tempDirty) and a persistent write to working (which flags mainDirty) — so a pure-temp
  // transaction leaves the main image untouched (temp-tables.md §2).
  private writeStore(name: string): TableStore {
    if (this.isTempTable(name)) {
      this.session.tx!.tempDirty = true;
      return this.session.tx!.tempWorking.store(name);
    }
    return this.working().store(name);
  }

  // lkpIndexStore returns a secondary index's store for READS, walking session-local → main
  // (temp-tables.md §8).
  private lkpIndexStore(nameKey: string): TableStore {
    if (this.tempSnap().hasIndexStore(nameKey)) {
      return this.tempSnap().indexStore(nameKey);
    }
    return this.readSnap().indexStore(nameKey);
  }

  // writeIndexStore returns a secondary index's store for MUTATION, walking session-local → main
  // (flagging the matching dirty bit).
  private writeIndexStore(nameKey: string): TableStore {
    if (this.tempSnap().hasIndexStore(nameKey)) {
      this.session.tx!.tempDirty = true;
      return this.session.tx!.tempWorking.indexStore(nameKey);
    }
    return this.working().indexStore(nameKey);
  }

  // columnCollations resolves each column's frozen collation (Column.collation, the name) to its
  // baked table, indexed by column ordinal — null for a C / non-text column (the fast path). The key
  // encoders (§2.12) consult colls[ci] to pick a text column's key form.
  private columnCollations(columns: Column[]): (Collation | null)[] {
    const snap = this.readSnap();
    return columns.map((c) =>
      c.collation !== null ? (snap.resolveCollation(c.collation) ?? null) : null,
    );
  }

  // ensureCollationsWritable refuses a WRITE that would maintain a collated B-tree under a
  // version-skewed collation (the slice-2d verdict, spec/design/collation.md §12/§14): if any of
  // columns carries a collation the file pinned to a different (unicode, cldr) than the loaded bundle
  // provides, an insert/update/delete/index-build would mix two orderings in one tree and corrupt it,
  // so the whole table is read-only until a REINDEX migration (deferred) rebuilds + re-pins it. XX002,
  // naming the collation + both versions. Reads never call this — they recompute against the loaded
  // table (the heap-scan fallback, compatibility.md §8). Per-table granularity: one skewed column
  // collation makes the table read-only (finer per-index gating is a follow-on).
  private ensureCollationsWritable(columns: Column[]): void {
    const snap = this.readSnap();
    for (const c of columns) {
      if (c.collation === null) continue;
      const skew = snap.collationSkew(c.collation);
      if (skew !== undefined) {
        const [fu, fc, lu, lc] = skew;
        throw engineError(
          "collation_version_mismatch",
          `collation "${c.collation}" version mismatch: this database's keys were built under ${fu}/${fc} ` +
            `but the loaded bundle is ${lu}/${lc}; tables using it are read-only until a REINDEX migration rebuilds them`,
        );
      }
    }
  }

  // seqNextval is nextval('name') (spec/design/sequences.md §4): advance the named sequence and
  // return the new value. The running state lives in pendingSeq, seeded from the working snapshot on
  // first touch this statement, and is flushed into the working snapshot + sessionSeq on statement
  // success (flushPendingSequences). A missing sequence is 42P01; advancing past a bound without
  // CYCLE is 2200H.
  seqNextval(name: string): bigint {
    const key = name.toLowerCase();
    let def = this.session.pendingSeq.get(key);
    if (def === undefined) {
      const committed = this.sequence(name);
      if (committed === undefined) {
        throw engineError("undefined_table", `relation does not exist: ${name}`);
      }
      def = { ...committed };
    } else {
      def = { ...def };
    }
    let result: bigint;
    if (!def.isCalled) {
      // The first nextval returns START (the current lastValue) without incrementing.
      def.isCalled = true;
      result = def.lastValue;
    } else {
      // Advance by increment, treating an i64 overflow or a bound crossing identically (bigint never
      // overflows, so a wrap is detected purely by the bound test).
      const stepped = def.lastValue + def.increment;
      let next: bigint;
      if (def.increment > 0n && stepped <= def.maxValue) {
        next = stepped;
      } else if (def.increment < 0n && stepped >= def.minValue) {
        next = stepped;
      } else if (def.cycle) {
        next = def.increment > 0n ? def.minValue : def.maxValue;
      } else {
        throw engineError(
          "sequence_generator_limit_exceeded",
          `nextval: reached ${def.increment > 0n ? "maximum" : "minimum"} value of sequence ${name}`,
        );
      }
      def.lastValue = next;
      result = next;
    }
    this.session.pendingSeq.set(key, def);
    // nextval defines this session's currval for the sequence AND makes it the lastval target (the
    // most-recent-nextval sequence; lastval then reads its current session value — §6).
    this.session.pendingCurrval.set(key, result);
    this.session.pendingLastName = key;
    return result;
  }

  // seqSetval is setval('name', n) / setval('name', n, isCalled) (spec/design/sequences.md §4): set
  // the sequence's counter directly and return n. A missing sequence is 42P01; n outside
  // [minValue, maxValue] is 22003. lastValue = n, isCalled = the flag (default true); when isCalled
  // is true the value also defines this session's currval (PG: isCalled=false leaves currval
  // untouched). setval never updates lastval (PG — §6).
  seqSetval(name: string, n: bigint, isCalled: boolean): bigint {
    const key = name.toLowerCase();
    let def = this.session.pendingSeq.get(key);
    if (def === undefined) {
      const committed = this.sequence(name);
      if (committed === undefined) {
        throw engineError("undefined_table", `relation does not exist: ${name}`);
      }
      def = { ...committed };
    } else {
      def = { ...def };
    }
    if (n < def.minValue || n > def.maxValue) {
      throw engineError(
        "numeric_value_out_of_range",
        `setval: value ${n} is out of bounds for sequence ${name} (${def.minValue}..${def.maxValue})`,
      );
    }
    def.lastValue = n;
    def.isCalled = isCalled;
    this.session.pendingSeq.set(key, def);
    // currval is defined only when isCalled (PG do_setval: elm->last_valid set iff iscalled).
    if (isCalled) this.session.pendingCurrval.set(key, n);
    return n;
  }

  // seqLastval is lastval() (spec/design/sequences.md §6): the CURRENT session value of the sequence
  // the most recent nextval (of any sequence) ran on IN THIS SESSION — PG reads the last-used
  // sequence's cached value, so a setval on that same sequence is reflected, while a setval on a
  // different sequence is not. Takes no name argument (no 42P01); 55000 before the first nextval. The
  // effective name and its value both honor the statement's running updates over the session state.
  seqLastval(): bigint {
    const key = this.session.pendingLastName ?? this.session.sessionLastName;
    if (key === null) {
      throw engineError(
        "object_not_in_prerequisite_state",
        "lastval is not yet defined in this session",
      );
    }
    const pending = this.session.pendingCurrval.get(key);
    if (pending !== undefined) return pending;
    const v = this.session.sessionSeq.get(key);
    if (v !== undefined) return v;
    // A nextval always defines the sequence's session value, so a recorded last-name with no value is
    // unreachable; fall back to 55000 defensively rather than returning a wrong value.
    throw engineError(
      "object_not_in_prerequisite_state",
      "lastval is not yet defined in this session",
    );
  }

  // seqCurrval is currval('name') (spec/design/sequences.md §6): the value nextval/setval(…,true)
  // last produced for this sequence IN THIS SESSION. Resolves the name against the catalog first
  // (42P01 if absent), then reads the running update this statement (pendingCurrval) else the session
  // value (sessionSeq); 55000 if it has not been defined this session.
  seqCurrval(name: string): bigint {
    if (this.sequence(name) === undefined) {
      throw engineError("undefined_table", `relation does not exist: ${name}`);
    }
    const key = name.toLowerCase();
    const pending = this.session.pendingCurrval.get(key);
    if (pending !== undefined) return pending;
    const v = this.session.sessionSeq.get(key);
    if (v !== undefined) return v;
    throw engineError(
      "object_not_in_prerequisite_state",
      `currval of sequence ${name} is not yet defined in this session`,
    );
  }

  // flushPendingSequences flushes the statement's pending sequence advances into the working
  // snapshot (so a commit persists them) and the pending session updates into sessionSeq/
  // sessionLastName (so currval/lastval see them). Called on the success of a sequence-advancing
  // statement, while a write transaction is open; a no-op when nothing advanced. On statement error
  // the pending state is instead discarded (cleared at the next statement), giving the transactional
  // rollback of the advance (sequences.md §5).
  private flushPendingSequences(): void {
    for (const def of this.session.pendingSeq.values()) {
      // Route each advance to its owning scope (temp-tables.md §8): a serial/IDENTITY temp column's
      // owned sequence flushes into its temp snapshot (zero file writes), a persistent one into main.
      this.putSequenceRouted(def);
    }
    for (const [key, v] of this.session.pendingCurrval) {
      this.session.sessionSeq.set(key, v);
    }
    if (this.session.pendingLastName !== null) {
      this.session.sessionLastName = this.session.pendingLastName;
    }
    this.session.pendingSeq.clear();
    this.session.pendingCurrval.clear();
    this.session.pendingLastName = null;
  }

  // restoreSessionState restores the handle's currval/lastval session state from a discarded
  // transaction's captured copy (spec/design/sequences.md §5/§6) — the rollback of any in-block
  // nextval/setval session updates. Called wherever a transaction is dropped without publishing.
  private restoreSessionState(tx: ActiveTx): void {
    this.session.sessionSeq = tx.savedSessionSeq;
    this.session.sessionLastName = tx.savedSessionLastName;
  }

  // newTx opens a transaction over a clone of the committed snapshot, capturing the handle's
  // currval/lastval session state so it can be restored if the transaction is discarded (the
  // rollback of any in-block nextval/setval session updates — spec/design/sequences.md §5/§6).
  private newTx(writable: boolean): ActiveTx {
    return {
      writable,
      failed: false,
      working: this.committed.clone(),
      tempWorking: this.session.tempCommitted.clone(),
      mainDirty: false,
      tempDirty: false,
      savedSessionSeq: new Map(this.session.sessionSeq),
      savedSessionLastName: this.session.sessionLastName,
    };
  }

  // The monotonic commit counter (spec/design/api.md §2): the committed snapshot's version.
  get txid(): bigint {
    return this.committed.txid;
  }

  // oldestLiveTxid is the oldest still-live snapshot's txid (spec/design/transactions.md §8) — the
  // Phase-6 free-list reclamation gate. Single-handle (P5.3a) it is trivially the committed txid;
  // the P5.3b shared read snapshots make it meaningful.
  oldestLiveTxid(): bigint {
    return this.committed.txid;
  }

  // inTransaction reports whether an explicit transaction block is currently open on the DEFAULT
  // session (spec/design/transactions.md §4.2). False under autocommit. Used by the host Transaction
  // surface.
  inTransaction(): boolean {
    return this.session.tx !== null;
  }

  // status reports the DEFAULT session's transaction status (Idle/Open/Failed, spec/design/session.md
  // §2.2) — the explicit three-state machine the convenience methods drive.
  status(): TxStatus {
    return txStatusOf(this.session.tx);
  }

  // executeScript runs a multi-statement sql SCRIPT on the default session (spec/design/session.md
  // §4.2): split it, run each statement in order, DISCARD the result rows (keeping only counts), and
  // return the O(1) ScriptSummary. The dominant migration/import path — "run this script; I only
  // care that it succeeded."
  //
  //   - Idle at entry  ⇒ the whole run is one implicit transaction, all-or-nothing: a statement
  //     error rolls the wrapper back (nothing is committed) and rethrows that error.
  //   - Open at entry  ⇒ the run joins that transaction (no wrapper, no auto-commit); a mid-run error
  //     leaves the block Failed for the caller to roll back.
  //   - In-script transaction control (BEGIN/COMMIT/ROLLBACK) is 0A000 — the implicit wrapper owns
  //     the boundary (partitioning is deferred, session.md §11); a host that needs self-managed
  //     transactions writes its own splitStatements loop instead.
  executeScript(sql: string): ScriptSummary {
    // We own an implicit wrapper iff the session is Idle at entry. beginTx(null) honors the handle's
    // read-only mode (READ ONLY wrapper on a read-only handle — a write inside is 25006).
    const ownsWrapper = !this.inTransaction();
    if (ownsWrapper) this.beginTx(null);
    try {
      const summary = this.runScriptBody(sql);
      if (ownsWrapper) this.commitTx(); // publish the all-or-nothing run
      return summary;
    } catch (e) {
      if (ownsWrapper) this.rollbackTx(); // discard everything; rethrow the original error
      throw e;
    }
  }

  // runScriptBody splits sql and runs each statement on the current transaction, accumulating the
  // ScriptSummary. Separated so executeScript's wrapper commit/rollback runs once on either path —
  // and so Session.executeScript (shared.ts) can reuse it under a shared-core-aware wrapper (§2.4).
  runScriptBody(sql: string): ScriptSummary {
    let statementsRun = 0;
    let rowsAffectedTotal = 0;
    let cost = 0n;
    for (const span of splitStatements(sql)) {
      const ast = this.parse(span.text);
      // Transaction control inside a script is the v1 narrowing (session.md §4.2): the implicit
      // wrapper owns the boundary, so BEGIN/COMMIT/ROLLBACK is 0A000 (partitioning deferred).
      if (ast.kind === "begin" || ast.kind === "commit" || ast.kind === "rollback") {
        throw engineError(
          "feature_not_supported",
          "transaction control (BEGIN/COMMIT/ROLLBACK) is not supported inside execute_script; " +
            "use splitStatements to run a self-managed multi-statement transaction",
        );
      }
      const out = this.executeStmtParams(ast, []);
      statementsRun++;
      if (out.kind === "statement" && out.rowsAffected !== null)
        rowsAffectedTotal += out.rowsAffected;
      cost += out.cost;
    }
    return { statementsRun, rowsAffectedTotal, cost };
  }

  // table looks up a table definition by name (case-insensitive) in the visible snapshot.
  table(name: string): Table | undefined {
    return this.readSnap().table(name);
  }

  // compositeType looks up a composite type definition by name (case-insensitive) in the visible
  // snapshot (spec/design/composite.md).
  compositeType(name: string): CompositeType | undefined {
    return this.readSnap().compositeType(name);
  }

  // resolveCollationByName resolves a collation for USE — the database's resolved set then the
  // engine-global loaded set (spec/design/collation.md §2/§9). The reference-only read path; undefined
  // ⇒ neither has it (resolver → 42704).
  resolveCollationByName(name: string): Collation | undefined {
    return this.readSnap().resolveCollation(name);
  }

  // colTypeOf resolves a catalog Type into a self-contained ColType against the visible snapshot's
  // composite definitions (the codec/coercion tree — spec/design/composite.md §4). Used to coerce a
  // composite-element array literal (array-of-composite, array.md §12 AC1).
  colTypeOf(ty: Type): ColType {
    return resolveColType(ty, this.readSnap().types);
  }

  // tableNames is the canonical name of every table in the visible snapshot, sorted ascending
  // by lowercased name (the catalog's standing order — no map-iteration order may leak,
  // CLAUDE.md §8; keys are ASCII, so code-unit sort == byte sort). Secondary indexes are not
  // tables and are excluded (api.md §6).
  tableNames(): string[] {
    const snap = this.readSnap();
    return [...snap.tables.keys()].sort().map((k) => snap.tables.get(k)!.name);
  }

  // putTable registers a new table and its empty store in the working snapshot (DDL is
  // transactional — transactions.md §4.5).
  putTable(t: Table): void {
    this.working().putTable(t, this.pageSize);
  }

  // importCollation / exportCollation are GONE (the reference-only pivot, spec/design/collation.md
  // §4.2): a collation is provided by a host-loaded bundle and used by name, never loaded into a
  // database. There is no runtime path that constructs or bakes a collation table — the only load is
  // loadUnicodeData of jed's own pinned bundle bytes.

  // loadUnicodeData loads a JUCD Unicode-data bundle (db.loadUnicodeData, spec/design/collation.md
  // §4.2): its collations become resolvable by name for COLLATE, per-column collation, and ORDER BY …
  // COLLATE. The loaded set is ENGINE-GLOBAL (§9), so a bundle loaded through any handle is visible
  // everywhere — including to a later Engine.open of a file that REFERENCES one of its collations.
  // Privileged host op (not SQL-reachable, no path, no engine I/O — §11); ADDITIVE and idempotent for
  // an already-loaded bundle. Browser-safe (Uint8Array, no node:fs). A malformed bundle is XX001.
  // (Mirrors the free loadUnicodeData, which the host may call before opening any file.)
  loadUnicodeData(data: Uint8Array): void {
    loadUnicodeDataGlobal(data);
  }

  // loadTimeZoneData loads a JTZ time-zone bundle into the engine-global loaded set
  // (db.loadTimeZoneData, spec/design/timezones.md §3.3). The bytes are jed's own pinned TZif (RFC
  // 8536) wrapped in a manifest; the loaded zones become usable by AT TIME ZONE. Like the collation
  // seam, this is a privileged host op (not SQL-reachable, no path, no engine I/O — §10), additive and
  // idempotent, engine-global so it may be called before open. Browser-safe. A malformed bundle is
  // XX001. (UTC and fixed offsets are built in and need no load.)
  loadTimeZoneData(data: Uint8Array): void {
    loadTimeZoneDataGlobal(data);
  }

  // loadedTimeZones introspects the engine-global loaded zone set (db.loadedTimeZones, timezones.md
  // §3.3) — every named zone (and alias) a loaded bundle provides, ascending by name. A property of
  // the running engine, not of this database. UTC and fixed offsets are built in and not listed.
  loadedTimeZones(): TimeZoneInfo[] {
    return loadedTimeZonesGlobal();
  }

  // loadedCollations introspects the engine-global LOADED collation set (db.loadedCollations,
  // spec/design/collation.md §4.2) — every collation a loaded bundle provides, available to any
  // database on this handle, ascending by name. A property of the running ENGINE, not of this
  // database; for the collations this database references, use Engine.collations. isDefault is
  // always false here (that is a per-database property). C is built in and not listed.
  loadedCollations(): CollationInfo[] {
    return loadedCollationTables().map((c) => ({
      name: c.name,
      unicodeVersion: c.unicodeVersion,
      cldrVersion: c.cldrVersion,
      contentHash: crc32Ieee(serializeTable(c)),
      description: c.description,
      isDefault: false,
      // The loaded set IS the version reference — it can never be skewed against itself.
      verdict: "full" as const,
    }));
  }

  // setDefaultCollation sets the per-database default collation (db.setDefaultCollation,
  // spec/design/collation.md §1). "C" resets to byte order; any other name must be a LOADED
  // collation (else 42704). Persisted as the is_default flag on that collation's reference entry at
  // the next commit (the entry is emitted because the default references it — §5).
  setDefaultCollation(name: string): void {
    if (name === "C") {
      this.committed.defaultCollation = null;
      return;
    }
    if (this.committed.resolveCollation(name) === undefined) {
      throw engineError("undefined_object", `collation "${name}" does not exist`);
    }
    this.committed.defaultCollation = name;
  }

  // defaultCollation returns the per-database default collation name — "C" unless setDefaultCollation
  // moved it (db.defaultCollation, spec/design/collation.md §1).
  defaultCollation(): string {
    return this.committed.defaultCollation ?? "C";
  }

  // upgradeCollations adopts a newly-loaded Unicode version for this database's skewed collations
  // (the REINDEX / COLLATION UPGRADE migration, spec/design/collation.md §12). A privileged host op
  // like setDefaultCollation — NOT SQL-reachable, so an untrusted query can never trigger it
  // (CLAUDE.md §13). For every collation whose file pin differs from the loaded bundle (Skewed) it
  // rebuilds the collated keys (PK + indexes) under the loaded table and re-pins the stamp, clearing
  // the skew so the affected tables are read-write again and regain collated-index pushdown.
  // Whole-database + atomic (the rebuild stages in a snapshot clone swapped in only on success);
  // idempotent (no skew ⇒ a no-op returning 0). Persisted by the next explicit commit. Returns the
  // number of collations re-pinned.
  upgradeCollations(): number {
    const work = this.committed.clone();
    const n = work.upgradeCollations(this.pageSize);
    if (n > 0) this.committed = work;
    return n;
  }

  // collations introspects the collations THIS DATABASE references (db.collations,
  // spec/design/collation.md §4.2) — every collation its schema uses (a column's COLLATE, or the
  // per-database default), in ascending name order. This is the per-file view; for the engine-global
  // LOADED set, use Engine.loadedCollations. C is built in and not listed.
  collations(): CollationInfo[] {
    const dflt = this.committed.defaultCollation;
    // referencedCollations resolves each referenced name (from a loaded bundle).
    let refs: Collation[];
    try {
      refs = this.committed.referencedCollations();
    } catch {
      return [];
    }
    return refs.map((c) => ({
      name: c.name,
      unicodeVersion: c.unicodeVersion,
      cldrVersion: c.cldrVersion,
      contentHash: crc32Ieee(serializeTable(c)),
      description: c.description,
      isDefault: dflt === c.name,
      // The slice-2d verdict: "skewed" when the file's pin differs from the loaded bundle's version
      // (the object is read-only), else "full" (collation.md §12).
      verdict: (this.committed.collationSkew(c.name) !== undefined
        ? "skewed"
        : "full") as CollationVerdict,
    }));
  }

  // executeStmt executes one parsed statement with no bind parameters.
  executeStmt(stmt: Statement): Outcome {
    return this.executeStmtParams(stmt, []);
  }

  // execute parses and runs one statement, binding $N params, and returns its command tag — the method
  // form of the exec-side seam, so the low-level Engine satisfies the same {changes, cost} shape as
  // Session/Database (their `.execute` drains the streaming `query` seam; the bare Engine runs the
  // materialized path directly, results/cost-identical, and cannot import the api.ts query seam without
  // a cycle). The white-box storage/catalog tests that legitimately stay on the internal Engine reach
  // it through the shared test helpers (util.ts's Handle); production hosts use Session/Database.
  execute(sql: string, params: Value[] = []): RunResult {
    const out = this.executeStmtParams(this.parse(sql), params);
    return {
      changes: out.kind === "statement" ? (out.rowsAffected ?? 0) : 0,
      cost: out.cost,
    };
  }

  // executeStmtParams executes one parsed statement, binding params to its $N placeholders (an
  // empty array for an unparameterized statement). DDL statements take no parameters — supplying
  // any is a 42601 (spec/design/api.md §5).
  //
  // Transaction control (BEGIN/COMMIT/ROLLBACK) drives the handle's current-transaction state
  // directly (spec/design/transactions.md §4.2). Otherwise the statement runs either inside the
  // open explicit block or, with none open, under autocommit (§4.1):
  //
  //   - Inside a block (§4.2/§6): an aborted block rejects every statement but COMMIT/ROLLBACK with
  //     25P02; a write in a READ ONLY block is 25006; otherwise the statement runs against the
  //     working set in place — no per-statement durable write (the block publishes once, at COMMIT).
  //     ANY statement error aborts the block (it enters the failed state); the statement's own
  //     two-phase pass already guarantees it wrote nothing partial (§6), so the whole working set is
  //     discarded only at ROLLBACK.
  //   - Autocommit (§4.1): a read runs against the committed state directly; a write is its own
  //     transaction — the committed state is captured first (the stores are O(1) clones via the
  //     persistent map, pmap.ts), the statement runs, and on success the change is made durable (the
  //     persistHook, synchronous=on). Any failure — in the statement or the durable write — restores
  //     the captured state (rollback-on-error, discarding partial work and any rowid allocations,
  //     §7). For an in-memory database persistHook is null, so autocommit is pure in-memory.
  executeStmtParams(stmt: Statement, params: Value[]): Outcome {
    switch (stmt.kind) {
      case "begin":
        return this.beginTx(stmt.writable);
      case "commit":
        return this.commitTx();
      case "rollback":
        return this.rollbackTx();
    }
    // Fresh per-statement sequence-advance scratch (a prior statement's error may have left it
    // populated — it is discarded, not flushed, on error; sequences.md §5).
    this.session.pendingSeq.clear();
    this.session.pendingCurrval.clear();
    this.session.pendingLastName = null;

    // Inside an explicit block?
    const tx = this.session.tx;
    if (tx !== null) {
      if (tx.failed) {
        throw engineError(
          "in_failed_sql_transaction",
          "current transaction is aborted, commands ignored until end of transaction block",
        );
      }
      // Run the statement; ANY error aborts the block (it enters the failed state — §6).
      try {
        if (stmtIsWrite(stmt) && !tx.writable) {
          throw engineError(
            "read_only_sql_transaction",
            "cannot execute " + stmtKind(stmt) + " in a read-only transaction",
          );
        }
        const outcome = this.dispatchStmt(stmt, params);
        // Enforce the temp-storage budget after a successful temp write (temp-tables.md §7): an
        // over-budget statement (session-local tempBuffers) throws 54P03, which aborts the block (the
        // staged temp rows roll back at ROLLBACK). A no-op for non-temp statements.
        this.checkTempBudget();
        // Land any nextval advances into the block's working snapshot; COMMIT publishes them,
        // ROLLBACK discards them with the rest of the working set (sequences.md §5).
        this.flushPendingSequences();
        return outcome;
      } catch (e) {
        tx.failed = true;
        throw e;
      }
    }

    // Autocommit (no open block): an autocommit write runs as an implicit single-statement
    // transaction — open a working snapshot off committed, run, then commit on success / discard on
    // error. Because the write mutates only working, an error leaves committed untouched (no restore
    // needed); rolled-back rowid allocations vanish with working (§7).
    if (!stmtIsWrite(stmt)) {
      return this.dispatchStmt(stmt, params);
    }
    // On a read-only handle the implicit transaction is READ ONLY (PostgreSQL hot-standby
    // behavior — api.md §2.1), so an autocommit write fails exactly like a write inside a
    // READ ONLY block.
    if (this.readOnly) {
      throw engineError(
        "read_only_sql_transaction",
        "cannot execute " + stmtKind(stmt) + " in a read-only transaction",
      );
    }
    this.session.tx = this.newTx(true);
    let outcome: Outcome;
    try {
      outcome = this.dispatchStmt(stmt, params);
      // Enforce the temp-storage budget before committing (temp-tables.md §7): an over-budget temp
      // write in this implicit transaction (session-local tempBuffers) is discarded (rolling back temp
      // + main) and surfaces 54P03.
      this.checkTempBudget();
    } catch (e) {
      // The statement failed before any flush, so session state is untouched; restore from the
      // captured copy anyway to keep the discard path uniform (sequences.md §6).
      this.restoreSessionState(this.session.tx);
      this.session.tx = null;
      throw e;
    }
    // Persist any nextval advances into the working snapshot before publishing it (sequences.md §5);
    // a non-sequence statement flushes nothing.
    this.flushPendingSequences();
    this.commitTx();
    return outcome;
  }

  // beginTx opens an explicit transaction (spec/design/transactions.md §4.2). A nested BEGIN (a
  // block is already open) is 25001. writable is the *requested* access mode: null (unspecified)
  // defaults to READ WRITE on a normal handle and READ ONLY on a read-only handle (PostgreSQL
  // hot-standby behavior — api.md §2.1); requesting READ WRITE on a read-only handle is 25006.
  // The committed snapshot is captured as the transaction's working snapshot — a writable tx
  // mutates it in place; a read-only tx reads it unchanged (read-your-snapshot, §4.3). Cheap: the
  // persistent stores clone O(1) (pmap.ts) and the catalog is shallow. committed is untouched
  // until commit.
  beginTx(writable: boolean | null): Outcome {
    if (this.session.tx !== null) {
      throw engineError("active_sql_transaction", "there is already a transaction in progress");
    }
    if (writable === true && this.readOnly) {
      throw engineError(
        "read_only_sql_transaction",
        "cannot set transaction read-write mode on a read-only database",
      );
    }
    this.session.tx = this.newTx(writable ?? !this.readOnly);
    return { kind: "statement", cost: 0n, rowsAffected: null };
  }

  // commitTx commits the current transaction (spec/design/transactions.md §4.2). With no open block
  // it is a lenient no-op success. A failed block, or any read-only tx, publishes nothing — the
  // working snapshot is dropped (a failed COMMIT is thus a ROLLBACK, PostgreSQL). A READ WRITE block
  // publishes its working snapshot: bump its txid (a durable/persistent database — one with a
  // persistHook; an in-memory database has none and stays at txid 0), make it durable (the
  // persistHook, §9), then swap it in as committed. A durable-write failure leaves committed untouched
  // and rethrows. Returns to autocommit.
  commitTx(): Outcome {
    const tx = this.session.tx;
    if (tx === null) return { kind: "statement", cost: 0n, rowsAffected: null };
    this.session.tx = null;
    if (tx.failed || !tx.writable) {
      // A failed or read-only block publishes nothing — a failed COMMIT is a ROLLBACK (PG), so any
      // in-block session updates revert with the discarded working set (§5/§6). The discarded
      // tempWorking rolls back temp changes too.
      this.restoreSessionState(tx);
      return { kind: "statement", cost: 0n, rowsAffected: null };
    }
    const working = tx.working;
    // One durable writer per transaction (attached-databases.md §5): at most one FILE-backed database —
    // MAIN or an attached file — may be written per tx (any number of in-memory attachments + session
    // temp are free). Checked here, before any durable page is written (the shared-core main persist is
    // deferred to Session.publish, and the attachment durable commits are the loop below), so a violating
    // tx commits nothing. Deterministic (a count, order-independent).
    if (this.oneDurableWriterExceeded(tx)) {
      throw engineError(
        "feature_not_supported",
        "a transaction may modify at most one durable database",
      );
    }
    // Persist the main image when it changed; a transaction that touched ONLY session-local temp tables
    // skips it entirely so a temp table makes ZERO file writes (spec/design/temp-tables.md §2). An empty
    // block (no kind dirty) still persists, preserving prior behavior. Temp state is adopted regardless
    // — never serialized, only swapped into the in-memory committed temp snapshot.
    const pureTemp = !tx.mainDirty && tx.tempDirty;
    if (!pureTemp) {
      // The txid advances for a durable database, signalled by the presence of a persistHook (the file
      // and OPFS hosts set one; an in-memory database has none and stays at txid 0). Keyed on persistHook,
      // not `path`: the OPFS host is durable but has no filesystem path (it leaves `path` null so the
      // disk-spill in newSorterFor stays off), so `path` alone would wrongly hold its txid at the create
      // value and reuse the same meta slot. For the file and in-memory hosts the two are equivalent
      // (path and persistHook are set or unset together), so this is observably identical there.
      if (this.persistHook !== null) working.txid = this.committed.txid + 1n;
      // persistHook (if any) throws on an I/O failure before committed is swapped, so committed is
      // left untouched (the commit failed; the working snapshot is discarded).
      if (this.persistHook !== null) this.persistHook(this, working);
      this.committed = working;
    }
    // Adopt the transaction's temp changes into the committed temp snapshot (temp-tables.md §5) — the
    // temp analogue of publishing committed, but purely in memory. Session-local temp lives on the
    // session.
    // A dirty session-local temp domain materializes its working snapshot into its MemoryBlockStore
    // (compact packed leaves + within-session compaction) before it is adopted — zero main-file writes
    // (temp-tables.md §6). Compaction is safe iff no streaming cursor holds an older temp tree.
    if (tx.tempDirty && this.tempStorage !== null) {
      persistTemp(this.tempStorage, tx.tempWorking, this.openStreams === 0);
    }
    this.session.tempCommitted = tx.tempWorking;
    // Adopt each dirtied host-attached database (attached-databases.md §5, the N-root commit):
    // materialize its working snapshot into the attachment's in-RAM block store (persistTemp-style — the
    // same incremental copy-on-write pack as temp, NO fsync, since an in-memory attachment has no
    // durability barrier) and adopt it into this engine's pinned attached view, so publish (shared.ts)
    // swaps the new attached roots in one atomic step. Like temp this touches no MAIN file; unlike temp
    // the root is DATABASE-scoped (published, cross-session-visible). Within-session compaction is safe
    // only when no cross-session reader pins an older root (the live-registry watermark — the committing
    // writer holds the gate but is not itself a live reader). Skipped for a bare/core-less engine.
    if (tx.attachDirty !== undefined && tx.attachDirty.size > 0 && this.core !== null) {
      const na = new Map(this.attachedCommitted);
      const canReclaim = !this.core.hasLiveReaders();
      for (const name of tx.attachDirty) {
        const att = this.core.attachments.get(name);
        if (att === undefined) continue; // detached mid-transaction (unreachable) — nothing to persist
        const ws = tx.attachWorking!.get(name)!;
        // A FILE attachment commits DURABLY (dirty pages + alternating meta slot + fsync, its own page
        // space); an in-memory one packs persist_temp-style (NO fsync). At most one file attachment is
        // dirty here (the one-durable-writer check above), so ≤1 fsync path runs.
        if (att.storage.path !== null) {
          ws.txid = (this.attachedCommitted.get(name)?.txid ?? 0n) + 1n; // alternating meta slot + reopen
          commitDurableAttachment(att.storage, ws, canReclaim);
        } else {
          persistTemp(att.storage, ws, canReclaim);
        }
        na.set(name, ws);
      }
      this.attachedCommitted = na;
    }
    return { kind: "statement", cost: 0n, rowsAffected: null };
  }

  // oneDurableWriterExceeded reports whether this transaction would write more than one FILE-backed
  // (durable) database — MAIN or an attached file (attached-databases.md §5). In-memory attachments and
  // session temp are free (their commit is a crash-free pointer swap). > 1 durable is 0A000 (the honest
  // v1 narrowing — multi-file atomic write is Slice 3).
  private oneDurableWriterExceeded(tx: ActiveTx): boolean {
    let durable = tx.mainDirty && this.mainIsDurable() ? 1 : 0;
    if (this.core !== null && tx.attachDirty !== undefined) {
      for (const name of tx.attachDirty) {
        const att = this.core.attachments.get(name);
        if (att !== undefined && att.storage.path !== null) durable++;
      }
    }
    return durable > 1;
  }

  // mainIsDurable reports whether this handle's MAIN database is file-backed (durable) — the input to the
  // one-durable-writer count (§5). In the shared-core path the core knows (its storage's backing path);
  // a standalone engine is durable iff it carries a persistHook (the file/OPFS host set one).
  private mainIsDurable(): boolean {
    return this.core !== null ? this.core.mainIsDurable() : this.persistHook !== null;
  }

  // rollbackTx rolls back the current transaction (spec/design/transactions.md §4.2). With no open
  // block it is a no-op success. Otherwise the working snapshot is dropped — every staged
  // INSERT/UPDATE/DELETE and DDL CREATE/DROP, plus any rowid allocations (§7), vanish with it;
  // committed was never mutated, so there is nothing to restore there. The handle's currval/lastval
  // session state, however, was updated in place by in-block nextval/setval, so it is restored from
  // the block's captured copy (sequences.md §5/§6).
  rollbackTx(): Outcome {
    if (this.session.tx !== null) this.restoreSessionState(this.session.tx);
    this.session.tx = null;
    return { kind: "statement", cost: 0n, rowsAffected: null };
  }

  // dispatchStmt routes one parsed statement to its executor. The autocommit transaction
  // handling (capture / durable commit / rollback-on-error) lives in executeStmtParams.
  // checkPrivileges enforces the session's authorization envelope for stmt (spec/design/session.md
  // §5.3). A fully-permissive session (the default) needs no check. Otherwise DDL is gated by
  // allowDdl, and DML requires a per-table privilege for each table it reads (SELECT) or writes
  // (INSERT/UPDATE/DELETE) and EXECUTE for each named function it calls. Enforcement is at name
  // resolution: a table privilege is required only for a name that resolves to an existing catalog
  // table (a missing table stays 42P01; a CTE / derived-table label is statement-local). Missing
  // privilege → 42501.
  // checkLifetimeAdmission rejects a statement at admission when the session's lifetime cost budget is
  // already spent (spec/design/session.md §5.4): if a budget is set and the session's cumulative cost
  // has reached it, no further statement may run (it "cannot accrue") — 54P02. A no-op when the budget
  // is unlimited (the default), so the common path pays one comparison.
  private checkLifetimeAdmission(): void {
    const limit = this.session.lifetime.limit;
    const total = this.session.lifetime.total;
    if (limit > 0n && total >= limit) {
      throw engineError(
        "session_cost_limit_exceeded",
        `session exceeded the lifetime cost limit of ${limit} (accrued ${total})`,
      );
    }
  }

  // checkTempBudget enforces the per-session temp-table storage budget (tempBuffers, spec/design/
  // temp-tables.md §7) — the §13 gate on RETAINED temp bytes. Checked after each temp-writing
  // statement: if the session's temp footprint (byte-identical on-disk record bytes, summed over every
  // temp table + index) EXCEEDS the budget, throw 54P03. The over-budget write is in tempWorking, so
  // the abort discards it (autocommit) or fails the block (rolled back at ROLLBACK) — nothing commits.
  // tempBuffers 0 ⇒ unlimited; a transaction that did not touch temp cannot have grown it, so the check
  // self-gates on tempDirty and is a no-op for ordinary (persistent) statements. Within-statement bound
  // is maxCost.
  private checkTempBudget(): void {
    const limit = this.session.tempBuffers;
    if (limit === 0) return;
    if (this.session.tx === null || !this.session.tx.tempDirty) return;
    // Page-based footprint of the session-local temp domain (temp-tables.md §7, Design decision 3): the
    // committed MemoryBlockStore high-water × page size — the honest resident-RAM measure now that temp
    // rides a pager (a record-byte walk would skip demoted OnDisk leaves and undercount a multi-leaf temp
    // table, defeating the §13 bound). Deterministic and cross-core-identical: pageCount is a pure
    // function of operations via the B+tree + within-session compaction. It reflects the state one commit
    // behind (the pending write commits at statement end), so a domain already over budget aborts the
    // NEXT temp write and rolls it back — the "already over budget ⇒ further writes abort" contract (§7).
    const used = this.tempStorage !== null ? this.tempStorage.pageCount * this.pageSize : 0;
    if (used > limit) {
      throw engineError(
        "temp_storage_limit_exceeded",
        `temporary table storage exceeded the limit of ${limit} bytes`,
      );
    }
  }

  private checkPrivileges(stmt: Statement): void {
    // Fast path: a session that allows ALL DDL (persistent + temp) and grants every privilege pays
    // nothing. Both gates must be on, since temp DDL now has its own gate (§5).
    if (
      this.session.allowDdl &&
      this.session.allowTempDdl &&
      this.session.privileges.isPermissive()
    ) {
      return;
    }
    const req: PrivReq = {
      tables: [],
      functions: [],
      isDdl: false,
      isTempDdl: false,
    };
    collectStmtPrivs(stmt, req);
    // UPDATE's DEFAULT marker has no expression subtree. Add the selected catalog default's named
    // functions during preflight so a revoked function cannot be invoked through
    // `SET column = DEFAULT` (session.md §5.3).
    this.collectUpdateDefaultPrivs(stmt, req);
    if (req.isDdl) {
      // DDL is gated by the kind of relation it targets (temp-tables.md §5): a session-local temp
      // table by allowTempDdl, everything else (persistent) by allowDdl. A CREATE TABLE is classified
      // statically; the rest by resolving the name — a DROP TABLE / CREATE INDEX by its target table, a
      // DROP INDEX by the index (preclude-overlaps keeps a name in one scope).
      let allowed: boolean;
      if (
        req.isTempDdl ||
        (stmt.kind === "dropTable" && stmt.names.some((n) => this.isTempTable(n))) ||
        (stmt.kind === "createIndex" && this.isTempTable(stmt.table)) ||
        (stmt.kind === "dropIndex" && this.isTempIndex(stmt.name)) ||
        (stmt.kind === "dropSequence" && stmt.names.some((n) => this.isTempSequence(n))) ||
        (stmt.kind === "alterTable" &&
          (stmt.db !== undefined
            ? stmt.db.toLowerCase() === "temp"
            : this.isTempTable(stmt.name))) ||
        (stmt.kind === "alterSequence" && this.isTempSequence(stmt.name))
      ) {
        allowed = this.session.allowTempDdl;
      } else {
        allowed = this.session.allowDdl;
      }
      if (!allowed) {
        throw engineError(
          "insufficient_privilege",
          "permission denied: DDL is not permitted in this session",
        );
      }
    }
    const snap = this.readSnap();
    for (const t of req.tables) {
      const key = t.name.toLowerCase();
      // Only a name that resolves to an existing catalog table is privilege-checked; a missing one is
      // left to raise 42P01 in execution (existence before authorization). A built-in catalog relation
      // (jed_tables / jed_columns) is gated exactly like a user table — per-table SELECT on its own
      // name under the session envelope, no special case (introspection.md §5) — so an explicit-grant
      // session sees the schema only if the host granted it.
      const exists = isCatalogRelName(key) || snap.table(key) !== undefined;
      if (exists && !this.session.privileges.allowsTable(key, t.priv)) {
        throw engineError("insufficient_privilege", "permission denied for table " + key);
      }
    }
    for (const fn of req.functions) {
      const key = fn.toLowerCase();
      if (!this.session.privileges.allowsFunction(key)) {
        throw engineError("insufficient_privilege", "permission denied for function " + key);
      }
    }
  }

  // Add named functions reached through UPDATE SET column = DEFAULT. Ordinary assignment
  // expressions are covered by collectStmtPrivs; this catalog-dependent walk includes top-level,
  // writable-CTE, and EXPLAIN-contained UPDATEs. Missing targets are skipped so execution retains
  // its existing 42P01/42703 error precedence.
  private collectUpdateDefaultPrivs(stmt: Statement, req: PrivReq): void {
    if (stmt.kind === "update") this.collectOneUpdateDefaultPrivs(stmt, req);
    else if (stmt.kind === "with") {
      for (const cte of stmt.ctes) this.collectCteDefaultPrivs(cte.body, req);
      this.collectCteDefaultPrivs(stmt.body, req);
    } else if (stmt.kind === "explain") this.collectUpdateDefaultPrivs(stmt.inner, req);
  }

  private collectCteDefaultPrivs(body: CteBody, req: PrivReq): void {
    if (body.kind === "update") this.collectOneUpdateDefaultPrivs(body, req);
  }

  private collectOneUpdateDefaultPrivs(upd: Update, req: PrivReq): void {
    const table = this.lkpTableScoped(upd.db, upd.table);
    if (table === undefined) return;
    const locals = new Set<string>();
    for (const assignment of upd.assignments) {
      if (!assignment.isDefault) continue;
      const col = table.columns.find(
        (candidate) => candidate.name.toLowerCase() === assignment.column.toLowerCase(),
      );
      if (col !== undefined && col.defaultExpr !== null) {
        collectExprPrivs(col.defaultExpr.expr, req, locals);
      }
    }
  }

  // gateReadLanes runs the admission gates the lazy read lanes (tryScanQuery / tryDeferredQuery) would
  // otherwise skip. Those gates live on the materialized dispatchStmt path, but a SELECT served by a
  // streaming/deferred cursor never reaches it — so a read through the total query seam would bypass
  // authorization entirely (a §13 hole). Enforcing them here makes query a total AND safe seam: a read
  // inside a failed block is 25P02, a lifetime-exhausted session is 54P02, and a restricted read is
  // 42501 — whichever lane serves it. The caller applies this only to reads (transaction control must
  // still work in a failed block, and a write keeps its gating inside dispatch); the three checks are
  // pure, so a read that falls through to the materialized path re-running them is harmless (identical
  // result). (CLAUDE.md §13 — the safe-total-query contract.)
  gateReadLanes(stmt: Statement): void {
    if (this.session.tx?.failed) {
      throw engineError(
        "in_failed_sql_transaction",
        "current transaction is aborted, commands ignored until end of transaction block",
      );
    }
    this.checkLifetimeAdmission();
    this.checkPrivileges(stmt);
  }

  // failOpenBlock puts an open, failable transaction block into the aborted state (tx.failed). A no-op
  // outside a block, and idempotent. This is the block-abort a lazy read lane bypasses: the materialized
  // executeStmtParams poisons in its block branch, but a SELECT served by a streaming / deferred cursor
  // never reaches it (transactions.md §6). PostgreSQL aborts a block on ANY statement error, so a
  // failing read has to poison here — an OPEN-time lane error (the query call site's catch) or a
  // DRAIN-time fault (the Rows onErr hook the call site attaches). Only reads reach these paths
  // (transaction control and writes go to dispatch, which self-poisons with the right nuance — a nested
  // BEGIN's 25001 must NOT abort).
  failOpenBlock(): void {
    if (this.session.tx !== null) {
      this.session.tx.failed = true;
    }
  }

  private dispatchStmt(stmt: Statement, params: Value[]): Outcome {
    // Lifetime budget admission (spec/design/session.md §5.4): once the session's cumulative cost has
    // reached lifetime_max_cost, every further statement is rejected 54P02 BEFORE it can accrue —
    // checked ahead of privileges/existence, so an exhausted session runs nothing. A no-op when the
    // budget is unlimited (the default). Transaction control (BEGIN/COMMIT/ROLLBACK) never reaches
    // dispatch (handled earlier), so an exhausted session can still close out an open block.
    this.checkLifetimeAdmission();
    // Authorization (spec/design/session.md §5.3): enforce the session's privilege envelope before the
    // statement runs — DDL gated by allowDdl, DML by per-table/per-function privileges, all 42501.
    // Skipped on a fully-permissive session (the default), so the common path pays nothing. The
    // physical access-mode gate (25006) is checked earlier in executeStmtParams, so it wins when both
    // apply.
    this.checkPrivileges(stmt);
    const out = this.dispatchStmtBody(stmt, params);
    // Keep each GiST index's resident R-tree current: after a statement that mutated the main image,
    // rebuild it from the (now-updated) leaf store so the next read descends a fresh tree (gist.md
    // §3/§4.1). A no-op for reads / temp-only writes (mainDirty unset), preserving the
    // temp-no-file-write invariant. GiST on a temp table is 0A000, so only the main snapshot is
    // refreshed.
    const tx = this.session.tx;
    if (tx?.mainDirty) tx.working.rebuildGistTrees();
    return out;
  }

  private dispatchStmtBody(stmt: Statement, params: Value[]): Outcome {
    switch (stmt.kind) {
      case "createTable":
        rejectParamsForDDL(params);
        return this.executeCreateTable(stmt);
      case "dropTable":
        rejectParamsForDDL(params);
        return this.executeDropTable(stmt);
      case "alterTable":
        rejectParamsForDDL(params);
        return this.executeAlterTable(stmt);
      case "createIndex":
        rejectParamsForDDL(params);
        return this.executeCreateIndex(stmt);
      case "dropIndex":
        rejectParamsForDDL(params);
        return this.executeDropIndex(stmt);
      case "createType":
        rejectParamsForDDL(params);
        return this.executeCreateType(stmt);
      case "dropType":
        rejectParamsForDDL(params);
        return this.executeDropType(stmt);
      case "createSequence":
        rejectParamsForDDL(params);
        return this.executeCreateSequence(stmt);
      case "alterSequence":
        rejectParamsForDDL(params);
        return this.executeAlterSequence(stmt);
      case "dropSequence":
        rejectParamsForDDL(params);
        return this.executeDropSequence(stmt);
      case "insert":
        return this.executeInsert(stmt, params, EMPTY_CTE_CTX);
      case "select":
        return this.executeSelect(stmt, params);
      case "setOp":
        return this.executeSetOp(stmt, params);
      case "with":
        return this.executeWith(stmt, params);
      case "update":
        return this.executeUpdate(stmt, params, EMPTY_CTE_CTX);
      case "delete":
        return this.executeDelete(stmt, params, EMPTY_CTE_CTX);
      case "explain":
        return this.executeExplain(stmt, params);
      default:
        // Transaction control (begin/commit/rollback) is handled by executeStmtParams before
        // dispatch; it never reaches here.
        throw engineError("syntax_error", "unexpected statement kind");
    }
  }

  // executeExplain plans the inner statement and renders the plan as a deterministic result set
  // (spec/design/explain.md). Plain EXPLAIN never executes the inner statement — renderExplain produces
  // the plan structs, which renderQueryPlan walks. The EXPLAIN statement's own cost is one rowProduced
  // per emitted plan row. EXPLAIN ANALYZE (analyze true) delegates to executeExplainAnalyze, which also
  // runs the inner statement.
  private executeExplain(ex: Explain, params: Value[]): Outcome {
    if (ex.analyze) {
      return this.executeExplainAnalyze(ex.inner, params);
    }
    if (params.length > 0) {
      // Plain EXPLAIN renders the plan structurally (a $N bound source prints as "$N", not its bound
      // value), so supplied parameters are neither needed nor bound.
      throw engineError("syntax_error", "bind parameters are not allowed in EXPLAIN");
    }
    const r = new ExplainRender();
    this.renderExplain(r, ex.inner, 0);
    return this.explainOutcome(r.rows);
  }

  // executeExplainAnalyze renders the plan AND runs the inner statement, reporting the inner's ACTUAL
  // accrued cost + row count on an "Analyze" root node (spec/design/explain.md §3). Because jed's cost
  // meter is a deterministic cross-core contract, those figures are byte-identical across cores, so the
  // output is corpus-assertable. The plan is rendered from the pre-execution catalog; then the inner
  // statement executes for real (a DML inner mutates, and the outer autocommit commits it — EXPLAIN
  // ANALYZE of a write IS a write, classified by stmtIsWrite). The EXPLAIN statement's OWN cost is one
  // rowProduced per emitted plan row (independent of the inner cost, which appears only in the root).
  private executeExplainAnalyze(inner: Statement, params: Value[]): Outcome {
    // Render the plan tree first (plan-only, no execution — pre-mutation).
    const body = new ExplainRender();
    this.renderExplain(body, inner, 0);
    // Execute the inner statement for real, capturing its actual accrued cost + row count. Privileges
    // and the lifetime budget were already admitted on the EXPLAIN (dispatchStmt recurses into the
    // inner), and the write gate / commit are handled by the outer autocommit.
    const innerOut = this.dispatchStmtBody(inner, params);
    const actualRows =
      innerOut.kind === "statement"
        ? BigInt(innerOut.rowsAffected ?? 0) // a DML statement without RETURNING
        : BigInt(innerOut.rows.length);
    // Assemble: the Analyze root carries the actual figures; the plan tree sits one level deeper.
    const r = new ExplainRender();
    r.emit(0, "Analyze", `cost=${innerOut.cost} rows=${actualRows}`);
    for (const row of body.rows) {
      r.rows.push({ depth: row.depth + 1, node: row.node, detail: row.detail });
    }
    return this.explainOutcome(r.rows);
  }

  // explainOutcome wraps rendered plan rows as a query Outcome, charging the EXPLAIN's own cost — one
  // rowProduced per emitted plan row (a deterministic function of the plan-row count).
  private explainOutcome(rows: ExplainRow[]): Outcome {
    const meter = this.session.newMeter();
    meter.charge(COSTS.rowProduced * BigInt(rows.length));
    return {
      kind: "query",
      columnNames: ["depth", "node", "detail"],
      columnTypes: ["i32", "text", "text"],
      rows: rows.map((row) => [
        intValue(BigInt(row.depth)),
        textValue(row.node),
        textValue(row.detail),
      ]),
      cost: meter.accrued,
    };
  }

  // renderExplain renders the plan for the inner statement (spec/design/explain.md). A DML statement is
  // rendered by explainInsert/explainUpdate/explainDelete (plan-only — never executing, so an EXPLAIN of
  // a DELETE deletes nothing); a read query is planned by planExplainInner and walked by renderQueryPlan.
  private renderExplain(r: ExplainRender, inner: Statement, depth: number): void {
    switch (inner.kind) {
      case "insert":
        this.explainInsert(r, inner, depth);
        return;
      case "update":
        this.explainUpdate(r, inner, depth);
        return;
      case "delete":
        this.explainDelete(r, inner, depth);
        return;
      default:
        this.renderQueryPlan(r, this.planExplainInner(inner), depth);
    }
  }

  // explainInsert renders an INSERT plan: the Insert root (with an ON CONFLICT note), then the row
  // source — a planned SELECT subtree (INSERT … SELECT) or a Values leaf (INSERT … VALUES). It resolves
  // the source but never writes.
  private explainInsert(r: ExplainRender, ins: Insert, depth: number): void {
    if (this.lkpTable(ins.table) === undefined) {
      throw engineError("undefined_table", "table does not exist: " + ins.table);
    }
    r.emit(depth, "Insert " + ins.table, insertDetail(ins));
    if (ins.source.kind === "select") {
      const plan = this.planQuery(ins.source.select, null, [], new ParamTypes());
      this.renderQueryPlan(r, plan, depth + 1);
      return;
    }
    r.emit(depth + 1, "Values", `rows=${ins.source.rows.length}`);
  }

  // explainUpdate renders an UPDATE plan: the Update root (with the assignment count), the residual
  // Filter, then the target scan with its chosen access path. It resolves the WHERE and the scan bound
  // via the same detectors the executor uses, but never writes.
  private explainUpdate(r: ExplainRender, upd: Update, depth: number): void {
    const table = this.lkpTable(upd.table);
    if (table === undefined) {
      throw engineError("undefined_table", "table does not exist: " + upd.table);
    }
    const filter = this.explainDmlFilter(table, upd.filter);
    r.emit(depth, "Update " + upd.table, `sets=${upd.assignments.length}`);
    this.renderDmlScan(r, table, upd.table, filter, depth + 1);
  }

  // explainDelete renders a DELETE plan: the Delete root, the residual Filter, then the target scan
  // with its chosen access path. It resolves the WHERE and the scan bound but never writes.
  private explainDelete(r: ExplainRender, del: Delete, depth: number): void {
    const table = this.lkpTable(del.table);
    if (table === undefined) {
      throw engineError("undefined_table", "table does not exist: " + del.table);
    }
    const filter = this.explainDmlFilter(table, del.filter);
    r.emit(depth, "Delete " + del.table, "-");
    this.renderDmlScan(r, table, del.table, filter, depth + 1);
  }

  // explainDmlFilter resolves an UPDATE/DELETE WHERE predicate against a single-table scope (the same
  // prologue the executors use), or returns null for a bare (no-WHERE) statement.
  private explainDmlFilter(table: Table, where: Expr | null): RExpr | null {
    if (where === null) return null;
    return resolveBooleanFilter(Scope.single(this, table), where, new ParamTypes());
  }

  // renderDmlScan emits the residual Filter (when present) and the target Scan for an UPDATE/DELETE,
  // choosing the access path with the SAME detectors the executor uses (PK bound, then GIN, then GiST —
  // UPDATE/DELETE do not use secondary B-tree index bounds, indexes.md §5). The touched-set count is a
  // DML cost detail left to EXPLAIN ANALYZE, so it is not shown here.
  private renderDmlScan(
    r: ExplainRender,
    table: Table,
    name: string,
    filter: RExpr | null,
    depth: number,
  ): void {
    let d = depth;
    if (filter !== null) {
      r.emit(d, "Filter", `conjuncts=${conjunctCount(filter)}`);
      d++;
    }
    r.emit(d, "Scan " + name, this.scanDetail(name, this.dmlScanBound(table, filter), false, null));
  }

  // dmlScanBound picks an UPDATE/DELETE target's scan bound with the executor's own detectors: the
  // single-column PK range bound first, then a GIN bound, then a GiST bound; else a full scan (null).
  private dmlScanBound(table: Table, filter: RExpr | null): ScanBound | null {
    const bp = mutationPkBound(table, filter, this.readSnap());
    if (bp !== null) return { kind: "pk", pk: bp };
    const gb = detectGinBound(filter, table.indexes, table.columns, 0);
    if (gb !== null) return { kind: "gin", gin: gb };
    const gp = detectGistBound(filter, table.indexes, table.columns, 0);
    if (gp !== null) return { kind: "gist", gist: gp };
    const ks = pkSetFor(table, filter, this.readSnap());
    if (ks !== null) return { kind: "pkSet", pkSet: ks };
    return null;
  }

  // planExplainInner resolves the inner statement into a QueryPlan WITHOUT executing it. It handles the
  // read-query forms — SELECT, a top-level set operation, and a read-only top-level WITH; DML is
  // rendered by explainInsert/Update/Delete. A top-level WITH is planned as a nested WITH expression
  // (there are no enclosing CTEs to inherit at the top level), which produces the same WithPlan to
  // render.
  private planExplainInner(inner: Statement): QueryPlan {
    const ptypes = new ParamTypes();
    switch (inner.kind) {
      case "select":
      case "setOp":
        return this.planQuery(inner, null, [], ptypes);
      case "with": {
        const body = cteBodyAsQuery(inner.body);
        if (body === null) {
          // A data-modifying primary (writable CTE) — a DML EXPLAIN, handled in a later slice.
          throw engineError(
            "feature_not_supported",
            "EXPLAIN of a data-modifying WITH is not yet supported",
          );
        }
        return this.planWithExpr(
          { kind: "withExpr", ctes: inner.ctes, recursive: inner.recursive, body },
          null,
          ptypes,
        );
      }
      default:
        throw engineError(
          "feature_not_supported",
          "EXPLAIN of this statement is not yet supported",
        );
    }
  }

  // renderQueryPlan walks a QueryPlan arm at the given depth: a SELECT plan, a set operation, a VALUES
  // relation, or a WITH plan.
  private renderQueryPlan(r: ExplainRender, qp: QueryPlan, depth: number): void {
    switch (qp.kind) {
      case "select":
        this.renderSelectPlan(r, qp, depth);
        return;
      case "setOp":
        this.renderSetOpPlan(r, qp, depth);
        return;
      case "values":
        r.emit(depth, "Values", `rows=${qp.rows.length}`);
        return;
      case "with":
        this.renderWithPlan(r, qp, depth);
    }
  }

  // renderSelectPlan emits a SelectPlan's nodes in operator order — outermost first, each the pre-order
  // parent of the next, so the tree reads top-down as the executor's pipeline reads bottom-up: Limit,
  // Sort, Distinct, Window, Aggregate, Filter (WHERE), then the FROM tree. A Sort is emitted only when
  // the order is NOT elided; an elided ORDER BY (served by the scan / index / join order) is instead
  // noted on the FROM tree's top node (spec/design/explain.md §5).
  private renderSelectPlan(r: ExplainRender, sp: SelectPlan, depth: number): void {
    let d = depth;
    if (sp.limit !== null || sp.offset !== null) {
      r.emit(d, "Limit", limitDetail(sp.limit, sp.offset));
      d++;
    }
    let orderNote = "";
    if (sp.order.length > 0) {
      if (sp.phys.pkOrdered) {
        orderNote = "pk ordered";
        if (sp.phys.pkReverse) orderNote += " (reverse)";
      } else if (sp.phys.indexOrder !== null) {
        orderNote = "index order: " + sp.phys.indexOrder.nameKey;
      } else if (sp.phys.joinPkOrdered) {
        orderNote = "join pk ordered";
      } else {
        r.emit(d, "Sort", `keys=${sp.order.length}`);
        d++;
      }
    }
    if (sp.distinct) {
      r.emit(d, "Distinct", "-");
      d++;
    }
    if (sp.hasWindow) {
      r.emit(d, "Window", `funcs=${sp.windowSpecs.length}`);
      d++;
    }
    if (sp.isAgg) {
      r.emit(d, "Aggregate", aggDetail(sp));
      d++;
    }
    if (sp.filter !== null) {
      r.emit(d, "Filter", `conjuncts=${conjunctCount(sp.filter)}`);
      d++;
    }
    this.renderFrom(r, sp, d, orderNote);
  }

  // renderFrom emits the FROM tree: a left-deep chain of Nested Loop joins over the plan's relations,
  // or a single relation leaf, or a Result node for a FROM-less query. orderNote, when non-empty,
  // records an elided ORDER BY on the tree's top node.
  private renderFrom(r: ExplainRender, sp: SelectPlan, depth: number, orderNote: string): void {
    const n = sp.rels.length;
    if (n === 0) {
      r.emit(depth, "Result", withNote("-", orderNote));
      return;
    }
    this.renderJoinTree(r, sp, n, depth, orderNote);
  }

  // renderJoinTree emits the left-deep join over the first n relations: the outermost node is the last
  // join (joins[n-2]), whose left subtree is the join over the first n-1 relations and whose right child
  // is rels[n-1]. note tags the outermost node with an elided ORDER BY.
  private renderJoinTree(
    r: ExplainRender,
    sp: SelectPlan,
    n: number,
    depth: number,
    note: string,
  ): void {
    if (n === 1) {
      this.renderRelLeaf(r, sp, 0, depth, note);
      return;
    }
    const j = sp.joins[n - 2]!;
    r.emit(depth, "Nested Loop", withNote(joinDetail(j), note));
    this.renderJoinTree(r, sp, n - 1, depth + 1, "");
    this.renderRelLeaf(r, sp, n - 1, depth + 1, "");
  }

  // renderRelLeaf emits one relation: a base-table Scan (with its access path), an SRF, a CTE Scan, or a
  // Subquery (a derived table, whose inner plan recurses one level deeper). note tags a base Scan with
  // an elided ORDER BY (only a single base-table relation can carry one).
  private renderRelLeaf(
    r: ExplainRender,
    sp: SelectPlan,
    i: number,
    depth: number,
    note: string,
  ): void {
    const rel = sp.rels[i]!;
    if (rel.srf !== undefined) {
      // A catalog relation (introspection.md §5) is computed, not scanned — its own node name (it
      // is a relation, not a function) plus the database scope it reads.
      if (
        rel.srf.kind === "jed_tables" ||
        rel.srf.kind === "jed_columns" ||
        rel.srf.kind === "jed_indexes" ||
        rel.srf.kind === "jed_constraints"
      ) {
        r.emit(
          depth,
          "Catalog Scan " + rel.tableName,
          withNote("db=" + rel.srf.introspectScope, note),
        );
        return;
      }
      r.emit(depth, "SRF " + rel.tableName, withNote("-", note));
      return;
    }
    if (rel.cte !== undefined) {
      r.emit(depth, "CTE Scan " + rel.tableName, withNote("-", note));
      return;
    }
    if (rel.derived !== undefined) {
      r.emit(depth, "Subquery " + rel.tableName, withNote("-", note));
      this.renderQueryPlan(r, rel.derived, depth + 1);
      return;
    }
    // An index-nested-loop bound (per-outer-row seek) takes precedence over the once-materialized
    // bound in the access-path label (cost.md §3 "JOIN").
    const inl = sp.phys.relINLBounds[i] !== null;
    const bound = inl ? sp.phys.relINLBounds[i]! : sp.phys.relBounds[i]!;
    r.emit(
      depth,
      "Scan " + rel.tableName,
      withNote(this.scanDetail(rel.tableName, bound, inl, sp.relMasks[i]!), note),
    );
  }

  // renderSetOpPlan emits a set operation: any trailing Limit / Sort on the combined result, the
  // Union / Intersect / Except node, then the left and right operand plans as children.
  private renderSetOpPlan(r: ExplainRender, sop: SetOpPlan, depth: number): void {
    let d = depth;
    if (sop.limit !== null || sop.offset !== null) {
      r.emit(d, "Limit", limitDetail(sop.limit, sop.offset));
      d++;
    }
    if (sop.order.length > 0) {
      r.emit(d, "Sort", `keys=${sop.order.length}`);
      d++;
    }
    r.emit(d, setOpNodeName(sop.op), sop.all ? "all" : "distinct");
    this.renderQueryPlan(r, sop.lhs, d + 1);
    this.renderQueryPlan(r, sop.rhs, d + 1);
  }

  // renderWithPlan emits a WITH plan: the WITH node, each common-table expression as a CTE child (its
  // body one level deeper), then the main body plan.
  private renderWithPlan(r: ExplainRender, wp: WithPlan, depth: number): void {
    r.emit(depth, "WITH", `ctes=${wp.bindings.length}`);
    for (let i = 0; i < wp.bindings.length; i++) {
      const b = wp.bindings[i]!;
      const mode: CteMode = i < wp.modes.length ? wp.modes[i]! : "inline";
      r.emit(depth + 1, "CTE " + b.name, cteDetail(b, mode));
      // A data-modifying CTE has no query plan to render (a "dml" source); a plain / recursive CTE
      // renders its body (the recursive anchor plan for a RECURSIVE CTE) one level deeper.
      if (b.source.kind === "query") {
        this.renderQueryPlan(r, b.source.plan, depth + 2);
      }
    }
    this.renderQueryPlan(r, wp.body, depth + 1);
  }

  // scanDetail renders a Scan node's attributes: the access path (from the relation's chosen scan
  // bound, null = a full scan), then the touched-column count when the query references any column.
  private scanDetail(
    tableName: string,
    b: ScanBound | null,
    inl: boolean,
    mask: boolean[] | null,
  ): string {
    const parts = [this.accessPath(tableName, b, inl)];
    const n = countTrue(mask);
    if (n > 0) parts.push(`touched=${n}`);
    return parts.join("; ");
  }

  // accessPath renders the chosen access path for a relation (spec/design/explain.md §5): a full scan,
  // a primary-key range bound, or a secondary-index / GIN / GiST bound (the last three by index name).
  // inl marks an index-nested-loop bound (cost.md §3 "JOIN") — a per-outer-row seek whose source is a
  // sibling column — with a leading label.
  private accessPath(tableName: string, b: ScanBound | null, inl: boolean): string {
    if (b === null) return "Full scan";
    const prefix = inl ? "Index-nested-loop " : "";
    switch (b.kind) {
      case "pk":
        return prefix + "PK bound: " + renderBoundTerms(this.firstPKColName(tableName), b.pk.terms);
      case "index":
        return prefix + "Index bound: using " + b.index.nameKey;
      case "gin":
        return "GIN bound: using " + b.gin.nameKey;
      case "gist":
        return "GiST bound: using " + b.gist.nameKey;
      case "pkSet":
        return (
          prefix + "PK point set: " + renderKeySet(this.firstPKColName(tableName), b.pkSet.srcs)
        );
      case "indexSet":
        return prefix + "Index point set: using " + b.indexSet.nameKey;
    }
  }

  // firstPKColName returns the name of a table's first primary-key column (in key order), or "pk" when
  // the table is not found or has no primary key (a defensive fallback — the plan-only path already
  // resolved the table, and a bounded scan implies a PK).
  private firstPKColName(tableName: string): string {
    const t = this.lkpTable(tableName);
    if (t !== undefined && t.pk.length > 0 && t.pk[0]! < t.columns.length) {
      return t.columns[t.pk[0]!]!.name;
    }
    return "pk";
  }

  // rowsInKeyOrder returns a table's rows in primary-key (encoded byte) order in the visible
  // snapshot, or [] if the table does not exist.
  rowsInKeyOrder(name: string): Row[] {
    return this.readSnap().rowsInKeyOrder(name);
  }

  // executeCreateTable resolves each column's type name, enforces a single primary key
  // across both forms (column-level and the table-level PRIMARY KEY (a, b, ...) constraint —
  // which is implicitly NOT NULL per member), rejects duplicate table and column names, then
  // registers it. Constraint checks mirror PostgreSQL's order (oracle-probed,
  // constraints.md §3): a second primary key traps 42P16 before its members resolve; members
  // resolve left to right (unknown 42703, repeated 42701); then the jed narrowings — the
  // declaration-order rule and the per-member key-type gate — trap 0A000.
  private executeCreateTable(ct: CreateTable): Outcome {
    // A session-local temporary table (spec/design/temp-tables.md) is built exactly like a persistent
    // one but registered into the session temp snapshot at the end (§2), so it makes zero file writes.
    // FOREIGN KEY on a temp table is deferred this slice (§8) — rejected HERE, before any persistent
    // parent resolves, so the error is a clean 0A000. The other temp narrowings (composite/collated
    // columns, serial/IDENTITY) are checked just before registration, once the columns are built.
    //
    // Resolve the optional database qualifier (attached-databases.md §3, Slice 1b): `main`/`temp` fold
    // into the implicit scope (main = bare persistent, temp = TEMP); a host-attached name routes the new
    // table INTO that attachment's working snapshot (§6). TEMP with an explicit database is
    // contradictory unless the database IS `temp` (42601).
    let targetTemp = ct.temp;
    let attachName = "";
    if (ct.db !== undefined) {
      switch (ct.db.toLowerCase()) {
        case "main":
          if (ct.temp) {
            throw engineError("syntax_error", `cannot create a TEMP table in database "main"`);
          }
          break;
        case "temp":
          targetTemp = true;
          break;
        default:
          if (ct.temp) {
            throw engineError("syntax_error", "cannot create a TEMP table in an attached database");
          }
          attachName = ct.db.toLowerCase();
          if (this.attachReadSnap(attachName) === undefined) {
            throw engineError("undefined_table", `database "${ct.db}" is not attached`);
          }
          // A DDL write to a READ-ONLY attachment is 25006 before any work (attached-databases.md §4).
          this.checkAttachmentWritable(ct.db);
      }
    }
    if (targetTemp && ct.excludes.length > 0) {
      // An EXCLUDE constraint's backing GiST index would live on the temp snapshot — deferred with
      // the rest of the GiST-on-temp narrowing (spec/design/gist.md §11), a clean 0A000.
      throw engineError(
        "feature_not_supported",
        "an EXCLUDE constraint on a temporary table is not yet supported",
      );
    }
    if (targetTemp && ct.fks.length > 0) {
      throw engineError(
        "feature_not_supported",
        "FOREIGN KEY on a temporary table is not yet supported",
      );
    }
    // Deferred narrowings on an attached-database table this slice (attached-databases.md §8), each a
    // clean 0A000 before any column work: FOREIGN KEY and EXCLUDE (their probe/backing structures would
    // need cross-scope catalog access this slice does not thread). Serial/IDENTITY and composite/collated
    // columns are checked just before registration, once the columns are built (as for temp).
    if (attachName !== "") {
      if (ct.fks.length > 0) {
        throw engineError(
          "feature_not_supported",
          "FOREIGN KEY on an attached-database table is not supported yet",
        );
      }
      if (ct.excludes.length > 0) {
        throw engineError(
          "feature_not_supported",
          "an EXCLUDE constraint on an attached-database table is not supported yet",
        );
      }
    }
    checkReservedName("table", ct.name);
    // The relation namespace is shared between tables and indexes (indexes.md §2), so a CREATE TABLE
    // colliding with either kind is the same 42P07 — PG's "relation" word. For a bare/main/temp target
    // relationExists is temp-aware (a temp name collides with temp + persistent alike — temp-tables.md
    // §3); an attachment target checks its OWN snapshot's namespace (each attached database is
    // independent, §3).
    if (attachName !== "") {
      const as = this.attachReadSnap(attachName)!;
      if (as.table(ct.name) !== undefined || as.findIndex(ct.name) !== null) {
        throw engineError("duplicate_table", "relation already exists: " + ct.name);
      }
    } else if (this.relationExists(ct.name)) {
      throw engineError("duplicate_table", "relation already exists: " + ct.name);
    }

    const columns: Column[] = [];
    // pk is the primary-key member ordinals in KEY order (constraints.md §3): the
    // column-level form is the one-member case; the table-level list below records its
    // own order.
    let pk: number[] = [];
    let pkSeen = false;
    // The OWNED sequences a serial column desugars to (spec/design/sequences.md §12), collected
    // during the column walk and staged into the working snapshot only after the whole CREATE TABLE
    // validates — so a later failure (e.g. a bad CHECK) discards them with the statement.
    const pendingSerials: SequenceDef[] = [];
    for (const def of ct.columns) {
      for (const c of columns) {
        if (c.name.toLowerCase() === def.name.toLowerCase()) {
          throw engineError("duplicate_column", "duplicate column name: " + def.name);
        }
      }
      // Resolve the column type: a built-in scalar, or a user-defined composite referenced by name
      // (spec/design/composite.md §3). An unknown name is 42704. A composite column carries no typmod
      // (the composite's fields carry their own); a type modifier written on a composite column is
      // rejected (0A000). A composite column is storable (the recursive value codec — §4) but never
      // keyable — the PK gate below rejects it 0A000 (§6).
      // A serial / bigserial / smallserial pseudo-type (spec/design/sequences.md §12): CREATE TABLE
      // sugar for an integer column that is NOT NULL with a DEFAULT nextval(...) backed by a
      // newly-created OWNED sequence. Here we only resolve the underlying integer type; the
      // desugaring (the owned sequence + default + NOT NULL force) happens below. serial[] is NOT a
      // serial column (it falls to the array branch as an unknown element type — §12.1).
      const serialKind = serialPseudoType(def.typeName);
      let colType: Type;
      let decimal: DecimalTypmod | null;
      let varcharLen: number | null = null;
      const ctype = this.compositeType(def.typeName);
      if (serialKind !== undefined) {
        // A serial column takes no typmod (serial(5) is 42601) and no [] (the array branch).
        if (def.typeMod !== null) {
          throw engineError(
            "syntax_error",
            "type modifier is not allowed for type " + def.typeName,
          );
        }
        colType = scalarT(serialKind);
        decimal = null;
      } else if (def.typeName.endsWith("[]")) {
        // An array column (spec/design/array.md §3). The element type is a scalar or a
        // previously-defined composite (array-of-composite, §12 AC1 — element_type_code 14 + name);
        // a nested-array element and an array typmod (numeric(p,s)[]) stay deferred (0A000).
        const base = def.typeName.slice(0, -2);
        if (def.typeMod !== null) {
          throw engineError(
            "feature_not_supported",
            "a type modifier on an array type is not supported yet",
          );
        }
        const elemScalar = scalarTypeFromName(base);
        const baseComposite = this.compositeType(base);
        if (elemScalar !== undefined) {
          colType = arrayT(scalarT(elemScalar));
        } else if (baseComposite !== undefined) {
          colType = arrayT(compositeT(baseComposite.name));
        } else {
          throw engineError("undefined_object", "type does not exist: " + base);
        }
        decimal = null;
      } else if (rangeByName(def.typeName) !== undefined) {
        // A range column (spec/design/ranges.md §3): structural like array, the element carried
        // inline. A range takes no typmod (numrange(10,2) is not a thing — the element is the
        // unconstrained subtype), so a type modifier is rejected.
        if (def.typeMod !== null) {
          throw engineError(
            "feature_not_supported",
            "a type modifier on a range type is not supported",
          );
        }
        const rdesc = rangeByName(def.typeName)!;
        colType = rangeT(scalarT(elementScalar(rdesc)));
        decimal = null;
      } else if (scalarTypeFromName(def.typeName) !== undefined) {
        const [s, d, vl] = resolveTypeAndTypmod(def.typeName, def.typeMod);
        // jsonpath is literal-only this slice (P1a) — a jsonpath COLUMN is 0A000, like a J0-stage
        // json column (a storable jsonpath is a follow-on).
        if (s === "jsonpath") {
          throw engineError("feature_not_supported", "a jsonpath column is not supported yet");
        }
        colType = scalarT(s);
        decimal = d;
        varcharLen = vl;
      } else if (ctype !== undefined) {
        if (def.typeMod !== null) {
          throw engineError(
            "feature_not_supported",
            "a type modifier is not supported for composite type " + def.typeName,
          );
        }
        colType = compositeT(ctype.name);
        decimal = null;
      } else {
        throw engineError("undefined_object", "type does not exist: " + def.typeName);
      }
      // J1: json/jsonb columns are storable (the format-v19 value codec — spec/design/json.md §2/§4).
      // A json/jsonb PRIMARY KEY is still rejected 0A000 by the key-encodability gate below (PG ships
      // no json btree opclass; jsonb-as-key is a deferred §11 follow-on).
      if (def.primaryKey) {
        // Integers, boolean, and uuid may be a key. uuid is the first non-integer key type (fixed
        // uuid-raw16, spec/design/encoding.md §2.7) and boolean the second (fixed 1-byte bool-byte,
        // §2.9). text/bytea (…-terminated-escape §2.4/§2.6) and decimal (decimal-order-preserving
        // §2.5) are also allowed — their variable-width key encodings are self-delimiting, so they
        // compose in composite keys / index suffixes; an oversized one trips the RECORD_MAX
        // oversized-item 0A000 (PG's btree key limit). interval is the fixed 16-byte span key
        // (interval-span-i128, §2.10), range the first container key (range-bounds, §2.11), the array
        // the second (array-elements-terminated, §2.14 — keyable when its element is keyable,
        // INCLUDING float), and float the fixed-width float-order-preserving key (§2.8 — the last
        // scalar to become keyable, so EVERY scalar is now keyable). Still rejected 0A000: only the
        // recursive composite container. timestamp / timestamptz / date share the i64/i32 int-be-signflip
        // key (timestamp.md §6).
        if (
          !typeIsInteger(colType) &&
          !typeIsBoolean(colType) &&
          !typeIsText(colType) &&
          !typeIsBytea(colType) &&
          !typeIsDecimal(colType) &&
          !typeIsUuid(colType) &&
          !typeIsTimestamp(colType) &&
          !typeIsTimestamptz(colType) &&
          !typeIsDate(colType) &&
          !typeIsInterval(colType) &&
          !typeIsFloat(colType) &&
          !typeIsRange(colType) &&
          !typeIsArrayKeyable(colType)
        ) {
          throw engineError(
            "feature_not_supported",
            "a " + typeCanonicalName(colType) + " primary key is not supported yet",
          );
        }
        if (pkSeen) {
          throw engineError(
            "invalid_table_definition",
            "multiple primary keys for table " + ct.name + " are not allowed",
          );
        }
        pkSeen = true;
        pk.push(columns.length); // this column's ordinal (pushed below)
      }
      // Classify the DEFAULT by syntactic form (constraints.md §2). A bad default fails at
      // CREATE TABLE either way; NOT NULL is NOT enforced here (notNull=false), so a DEFAULT
      // NULL on a NOT NULL column is accepted and traps 23502 only when applied.
      //   - a bare literal is pre-evaluated + type-coerced to a constant value (the fast-path:
      //     out of range 22003, cross-family 42804, decimal rounded to typmod);
      //   - any other expression is validated (structural pre-walk, then resolved against an
      //     EMPTY scope — a default may not reference a column — then its result type is checked
      //     assignable to the column, 42804) and stored as text for per-row eval.
      let def_default: Value | null = null;
      let def_defaultExpr: DefaultExpr | null = null;
      let identityKind: IdentityKind | null = null;
      // A serial pseudo-type OR a GENERATED … AS IDENTITY constraint both desugar to an
      // auto-numbered column: an OWNED sequence + a synthesized DEFAULT nextval(...) + NOT NULL
      // (sequences.md §12/§13). Identity additionally records ALWAYS/BY DEFAULT and gates the
      // column type to i16/i32/i64.
      if (serialKind !== undefined || def.identity !== null) {
        // IDENTITY type gate: the declared column type must be smallint/integer/bigint
        // (sequences.md §13.1). serial's type is the pseudo-type (always integer), so this only
        // bites an identity column written on a non-integer type.
        if (def.identity !== null && !typeIsInteger(colType)) {
          throw engineError(
            "invalid_parameter_value",
            "identity column type must be smallint, integer, or bigint",
          );
        }
        // Conflicts (42601, sequences.md §13.2). An explicit DEFAULT — or a serial type, itself a
        // synthesized default — alongside IDENTITY is "both default and identity"; a serial column
        // with its own explicit DEFAULT is "multiple default values" (the S3 message, unchanged).
        if (def.identity !== null && (def.default !== null || serialKind !== undefined)) {
          throw engineError(
            "syntax_error",
            `both default and identity specified for column ${def.name} of table ${ct.name}`,
          );
        }
        if (serialKind !== undefined && def.default !== null) {
          throw engineError(
            "syntax_error",
            `multiple default values specified for column ${def.name} of table ${ct.name}`,
          );
        }
        // Create the OWNED sequence — a default ascending i64 for serial, or the IDENTITY column's
        // `( seq_options )` (defaulting the same way) — and synthesize the DEFAULT nextval(...)
        // expression default (format_version 8 mechanism).
        const seqName = this.chooseSerialSeqName(
          ct.name,
          def.name,
          pendingSerials,
          [],
        );
        const owner: SeqOwner = { table: ct.name, column: columns.length }; // this column's ordinal
        const opts = def.identity !== null ? def.identity.options : emptySeqOptions();
        // The owned sequence's data type follows the column (§14): serial → the pseudo-type,
        // identity → the column type. An explicit `AS` inside the identity `( … )` options conflicts
        // with that — 42601 (PG: "conflicting or redundant options"). serial carries no parsed
        // options, so this only fires for identity.
        if (opts.dataType !== null) {
          throw engineError("syntax_error", "conflicting or redundant options");
        }
        // serial fixes the scalar to its pseudo-type; identity's column type is a gated integer
        // scalar (typeIsInteger above), so colType is always a scalar in the identity branch.
        const seqScalar = serialKind ?? (colType.kind === "scalar" ? colType.scalar : undefined);
        const seqDtype = seqScalar === undefined ? undefined : seqDataTypeForScalar(seqScalar);
        if (seqDtype === undefined) {
          // Unreachable: a serial / identity column is i16/i32/i64 (gated above).
          throw engineError("invalid_parameter_value", "serial / identity column is i16/i32/i64");
        }
        opts.dataType = seqDtype;
        pendingSerials.push(buildSequenceDef(seqName, opts, owner));
        // Render the synthetic default exactly as the parser would the equivalent
        // DEFAULT nextval('<seqName>') (space-joined tokens — the canonical expression-text form),
        // so the in-memory expr matches what reload re-parses. The seqName is a lowercased
        // identifier-derived name, so the quoting is always safe.
        const exprText = `nextval ( '${seqName.replace(/'/g, "''")}' )`;
        def_defaultExpr = { exprText, expr: parseExpression(exprText) };
        if (def.identity !== null) identityKind = def.identity.always ? "always" : "byDefault";
      } else if (
        colType.kind === "composite" ||
        colType.kind === "array" ||
        colType.kind === "range"
      ) {
        // A DEFAULT on a composite-/array-typed column is not supported this slice (composite.md §12
        // / array.md §12); a range column is not storable at all yet (ranges.md §8 — unreachable,
        // CREATE TABLE rejects it).
        if (def.default !== null) {
          throw engineError(
            "feature_not_supported",
            "a DEFAULT on a composite- or array-typed column is not supported yet",
          );
        }
      } else if (def.default !== null) {
        const sty = colType.scalar;
        // A clock-relative date string DEFAULT ('today'/'now'/…) must NOT fold at CREATE TABLE:
        // it routes to the EXPRESSION path below, re-resolved to the STABLE dateClock node and
        // evaluated per INSERT — where PostgreSQL folds the literal to the table-creation day,
        // the documented fold-footgun divergence (date.md §6). 'epoch' and every ordinary date
        // string stay foldable constants.
        const clockDefault =
          sty === "date" &&
          def.default.expr.kind === "literal" &&
          def.default.expr.literal.kind === "text" &&
          dateClockIsRelative(def.default.expr.literal.text);
        if (def.default.expr.kind === "literal" && !clockDefault) {
          def_default = storeValue(
            literalToValue(def.default.expr.literal),
            sty,
            decimal,
            varcharLen,
            false,
            def.name,
          );
        } else {
          rejectDefaultStructure(def.default.expr);
          const { type: rt } = resolve(
            Scope.empty(this),
            def.default.expr,
            sty,
            { collecting: false, groupKeys: [], specs: [] },
            new ParamTypes(),
          );
          if (!assignableTo(rt, sty)) {
            throw typeError(
              `column ${def.name} is of type ${canonicalName(sty)} but default expression is of type ${rtName(rt)}`,
            );
          }
          def_defaultExpr = {
            exprText: def.default.text,
            expr: def.default.expr,
          };
        }
      }
      // The column's effective collation, frozen now (spec/design/collation.md §1). An explicit
      // COLLATE "name" is text-only (42804) and must name a loaded collation or C (42704); a text
      // column without a clause inherits the per-database default. A C effective collation stores as
      // null (the fast path).
      let collation: string | null = null;
      if (def.collation !== null) {
        if (!typeIsText(colType)) {
          throw typeError(`collations are not supported by type ${typeCanonicalName(colType)}`);
        }
        resolveCollationName(this, def.collation); // validates loaded; 42704 if not
        if (def.collation !== "C") collation = def.collation;
      } else if (typeIsText(colType)) {
        collation = this.readSnap().defaultCollation;
      }
      columns.push({
        name: def.name,
        type: colType,
        decimal,
        varcharLen,
        primaryKey: def.primaryKey,
        // PRIMARY KEY ⇒ NOT NULL; a serial or IDENTITY column is NOT NULL too (sequences.md §12/§13).
        notNull: def.primaryKey || def.notNull || serialKind !== undefined || def.identity !== null,
        default: def_default,
        defaultExpr: def_defaultExpr,
        identity: identityKind,
        collation,
      });
    }

    // Table-level PRIMARY KEY (a, b, ...) constraints (constraints.md §3). Check order
    // mirrors PostgreSQL (oracle-probed): a second primary key is 42P16 before its
    // members resolve; members resolve left to right (42703 unknown, 42701 repeated).
    // The LIST order is the KEY order — it may differ from declaration order (the v5
    // catalog persists the ordinal list; the old 0A000 narrowing is lifted). The
    // per-member key-type gate (0A000) remains.
    for (const pkList of ct.tablePks) {
      if (pkSeen) {
        throw engineError(
          "invalid_table_definition",
          "multiple primary keys for table " + ct.name + " are not allowed",
        );
      }
      pkSeen = true;
      const indices: number[] = [];
      for (const name of pkList) {
        const lower = name.toLowerCase();
        const idx = columns.findIndex((c) => c.name.toLowerCase() === lower);
        if (idx < 0) {
          throw engineError("undefined_column", "column " + name + " named in key does not exist");
        }
        if (indices.includes(idx)) {
          throw engineError(
            "duplicate_column",
            "column " + name + " appears twice in primary key constraint",
          );
        }
        indices.push(idx);
      }
      for (const i of indices) {
        const ty = columns[i]!.type;
        if (
          !typeIsInteger(ty) &&
          !typeIsBoolean(ty) &&
          !typeIsText(ty) &&
          !typeIsBytea(ty) &&
          !typeIsDecimal(ty) &&
          !typeIsUuid(ty) &&
          !typeIsTimestamp(ty) &&
          !typeIsTimestamptz(ty) &&
          !typeIsDate(ty) &&
          !typeIsInterval(ty) &&
          !typeIsFloat(ty) &&
          !typeIsRange(ty) &&
          !typeIsArrayKeyable(ty)
        ) {
          throw engineError(
            "feature_not_supported",
            "a " + typeCanonicalName(ty) + " primary key is not supported yet",
          );
        }
        columns[i]!.primaryKey = true;
        columns[i]!.notNull = true; // PRIMARY KEY ⇒ NOT NULL, per member
      }
      pk = indices;
    }

    // UNIQUE constraints (constraints.md §5.1): resolve members in textual definition
    // order, AFTER the PRIMARY KEY constraints and BEFORE any CHECK validates (PG's
    // order, oracle-probed — transformIndexConstraint runs first). Each member must
    // exist (42703, PG's "named in key" wording), appear once (42701), and be of a
    // key-encodable type (0A000 — the same narrowing as a PK member / index key column;
    // unlike a PK member it stays nullable). Folding + naming happen LAST (after check
    // naming), mirroring PG's index_create-at-execution timing.
    const runiques: { name: string | null; cols: number[] }[] = [];
    for (const u of ct.uniques) {
      const indices: number[] = [];
      for (const cname of u.columns) {
        const lower = cname.toLowerCase();
        const idx = columns.findIndex((c) => c.name.toLowerCase() === lower);
        if (idx < 0) {
          throw engineError("undefined_column", "column " + cname + " named in key does not exist");
        }
        if (indices.includes(idx)) {
          throw engineError(
            "duplicate_column",
            "column " + cname + " appears twice in unique constraint",
          );
        }
        indices.push(idx);
      }
      for (const i of indices) {
        const ty = columns[i]!.type;
        if (
          !typeIsInteger(ty) &&
          !typeIsBoolean(ty) &&
          !typeIsText(ty) &&
          !typeIsBytea(ty) &&
          !typeIsDecimal(ty) &&
          !typeIsUuid(ty) &&
          !typeIsTimestamp(ty) &&
          !typeIsTimestamptz(ty) &&
          !typeIsDate(ty) &&
          !typeIsInterval(ty) &&
          !typeIsFloat(ty) &&
          !typeIsRange(ty) &&
          !typeIsArrayKeyable(ty)
        ) {
          throw engineError(
            "feature_not_supported",
            "a " + typeCanonicalName(ty) + " unique constraint member is not supported yet",
          );
        }
      }
      runiques.push({ name: u.name, cols: indices });
    }

    // CHECK constraints (constraints.md §4). All validation runs first, in textual
    // definition order, AFTER the PRIMARY KEY constraints resolved (PG's order,
    // oracle-probed); naming follows in a second pass, so a 42703 in a later check fires
    // before a 42710 between earlier ones. Resolution needs a catalog Table, so build it
    // now (checks attach below, before putTable).
    const table: Table = {
      name: ct.name,
      columns,
      pk,
      checks: [],
      indexes: [],
      fks: [],
      exclusions: [],
    };
    for (const def of ct.checks) {
      // Structural rejections first (a single pre-walk — a documented micro-order
      // divergence from PG, which interleaves them with name/type resolution): subquery
      // 0A000, aggregate 42803, bind parameter 42P02 (constraints.md §4.1).
      rejectCheckStructure(def.expr);
      const scope = Scope.single(this, table);
      const { type } = resolve(
        scope,
        def.expr,
        null,
        { collecting: false, groupKeys: [], specs: [] },
        new ParamTypes(),
      );
      if (type.kind !== "bool" && type.kind !== "null") {
        throw typeError("argument of CHECK must be boolean");
      }
    }
    // Naming (constraints.md §4.3): a single pass in textual order. An explicit name is
    // used as written; a derived name is built from the LOWERCASED table/column names —
    // `<table>_<col>_check` when the expression references exactly one distinct column,
    // else `<table>_check` — suffixed with the smallest positive integer that frees it. A
    // collision (case-insensitive, PG folds) is 42710; derived names never yield to a
    // later explicit one (oracle-probed).
    const checks: CheckConstraint[] = [];
    const nameTaken = (name: string): boolean =>
      checks.some((c) => c.name.toLowerCase() === name.toLowerCase());
    for (const def of ct.checks) {
      let name: string;
      if (def.name !== null) {
        if (nameTaken(def.name)) {
          throw engineError(
            "duplicate_object",
            "constraint " + def.name + " for relation " + table.name + " already exists",
          );
        }
        name = def.name;
      } else {
        const cols = checkReferencedColumns(def.expr, columns);
        const base =
          cols.length === 1
            ? table.name.toLowerCase() + "_" + columns[cols[0]!]!.name.toLowerCase() + "_check"
            : table.name.toLowerCase() + "_check";
        name = base;
        for (let suffix = 1; nameTaken(name); suffix++) name = base + suffix.toString();
      }
      checks.push({ name, exprText: def.text, expr: def.expr });
    }
    // Evaluation (and on-disk) order: ascending byte order of the lowercased name
    // (constraints.md §4.4 — PG evaluates checks sorted by name, oracle-probed).
    checks.sort(compareLowerName);
    table.checks = checks;

    // UNIQUE fold + naming (constraints.md §5.2/§5.3, PG-probed). Fold first: a
    // constraint whose member list equals the primary key's (same order) creates
    // nothing; identical lists fold into the first occurrence, the surviving name being
    // the first explicitly-named one's. Then each survivor names its backing index in
    // textual order: an explicit name checks the relation namespace (42P07 — existing
    // relations, the table being created, and the statement's earlier indexes) before
    // the table's constraint names (42710); a derived `<table>_<cols>_key` suffix-walks
    // past BOTH namespaces.
    const sameCols = (a: number[], b: number[]): boolean =>
      a.length === b.length && a.every((v, i) => v === b[i]);
    const survivors: { name: string | null; cols: number[] }[] = [];
    for (const ru of runiques) {
      if (sameCols(ru.cols, table.pk)) continue;
      const existing = survivors.find((sv) => sameCols(sv.cols, ru.cols));
      if (existing) {
        if (existing.name === null) existing.name = ru.name;
        continue;
      }
      survivors.push(ru);
    }
    const relationTaken = (n: string): boolean =>
      this.relationExists(n) ||
      table.name.toLowerCase() === n.toLowerCase() ||
      table.indexes.some((ix) => ix.name.toLowerCase() === n.toLowerCase());
    const checkNameTaken = (n: string): boolean =>
      table.checks.some((c) => c.name.toLowerCase() === n.toLowerCase());
    for (const ru of survivors) {
      let name: string;
      if (ru.name !== null) {
        // A named UNIQUE constraint IS its backing index (constraints.md §5), so the
        // user-written name enters the relation namespace — reserved-prefix checked like
        // any relation name (introspection.md §4).
        checkReservedName("constraint", ru.name);
        if (relationTaken(ru.name)) {
          throw engineError("duplicate_table", "relation already exists: " + ru.name);
        }
        if (checkNameTaken(ru.name)) {
          throw engineError(
            "duplicate_object",
            "constraint " + ru.name + " for relation " + table.name + " already exists",
          );
        }
        name = ru.name;
      } else {
        let base = table.name.toLowerCase();
        for (const i of ru.cols) base += "_" + columns[i]!.name.toLowerCase();
        base += "_key";
        name = base;
        for (let suffix = 1; relationTaken(name) || checkNameTaken(name); suffix++) {
          name = base + suffix.toString();
        }
      }
      // Insert in catalog (ascending lowercased-name) order — indexes.md §6.
      let pos = table.indexes.findIndex((ix) => compareLowerName(ix, { name }) > 0);
      if (pos < 0) pos = table.indexes.length;
      table.indexes.splice(pos, 0, {
        name,
        keys: ru.cols.map((c) => ({ kind: "column", column: c })),
        unique: true,
        kind: "btree",
      });
    }

    // FOREIGN KEY constraints (constraints.md §6). Resolved AFTER the PK / UNIQUE / CHECK
    // constraints (PG's order), each in textual definition order: resolve the local columns
    // (42703/42701) against this table; look up the parent (42P01, or the table itself for a
    // self-reference); resolve the referenced columns (default to the parent PK, 42704 if it has
    // none); check the arity (42830); name the constraint (explicit collision 42710, else derive
    // `<table>_<cols>_fkey` with a suffix walk through the constraint namespace); reject the
    // unsupported write-actions (0A000); require the referenced columns to be the parent PK or a
    // UNIQUE set (42830); and require same-type pairing (42804, stricter than PG). An FK owns no
    // B-tree — enforcement probes the parent at every write (§6.4/§6.5).
    const resolvedFks: ForeignKey[] = [];
    for (const fk of ct.fks) {
      // 1. Local (referencing) columns into this table.
      const local: number[] = [];
      for (const cname of fk.columns) {
        const idx = columnIndex(table, cname);
        if (idx < 0) {
          throw engineError("undefined_column", "column " + cname + " named in key does not exist");
        }
        if (local.includes(idx)) {
          throw engineError(
            "duplicate_column",
            "column " + cname + " appears twice in foreign key constraint",
          );
        }
        local.push(idx);
      }
      // 2. Parent table — a self-reference resolves against the in-progress definition.
      const selfRef = fk.refTable.toLowerCase() === table.name.toLowerCase();
      let parent: Table;
      if (selfRef) {
        parent = table;
      } else {
        const found = this.table(fk.refTable);
        if (found === undefined) {
          throw engineError("undefined_table", "table does not exist: " + fk.refTable);
        }
        parent = found;
      }
      // 3. Referenced columns into the parent (default to the parent's primary key).
      let refs: number[];
      if (fk.refColumns === null) {
        if (parent.pk.length === 0) {
          // Omitting the referenced list defaults to the parent's PRIMARY KEY; a parent without
          // one is 42704 (PG's code here — undefined_object — even when the parent has a UNIQUE),
          // distinct from the explicit-no-match 42830.
          throw engineError(
            "undefined_object",
            "there is no primary key for referenced table " + parent.name,
          );
        }
        refs = [...parent.pk];
      } else {
        refs = [];
        for (const cname of fk.refColumns) {
          const idx = columnIndex(parent, cname);
          if (idx < 0) {
            throw engineError(
              "undefined_column",
              "column " + cname + " named in key does not exist",
            );
          }
          if (refs.includes(idx)) {
            throw engineError(
              "duplicate_column",
              "column " + cname + " appears twice in foreign key constraint",
            );
          }
          refs.push(idx);
        }
      }
      // 4. Referencing/referenced count must agree.
      if (local.length !== refs.length) {
        throw engineError(
          "invalid_foreign_key",
          "number of referencing and referenced columns for foreign key disagree",
        );
      }
      // 5. Name — the per-table constraint namespace, shared with CHECK (§6.2/§6.7).
      const nameTakenFk = (n: string): boolean =>
        table.checks.some((c) => c.name.toLowerCase() === n.toLowerCase()) ||
        resolvedFks.some((f) => f.name.toLowerCase() === n.toLowerCase());
      let fkName: string;
      if (fk.name !== null) {
        if (nameTakenFk(fk.name)) {
          throw engineError(
            "duplicate_object",
            "constraint " + fk.name + " for relation " + table.name + " already exists",
          );
        }
        fkName = fk.name;
      } else {
        let base = table.name.toLowerCase();
        for (const i of local) base += "_" + table.columns[i]!.name.toLowerCase();
        base += "_fkey";
        fkName = base;
        for (let suffix = 1; nameTakenFk(fkName); suffix++) fkName = base + suffix.toString();
      }
      // 6. Reject the unsupported write-actions (§6.6).
      const onDelete = fkAction(fk.onDelete, "DELETE");
      const onUpdate = fkAction(fk.onUpdate, "UPDATE");
      // 7. The referenced columns must be the parent's PK or a UNIQUE set (§6.2).
      const refSet = sortedUnique(refs);
      const matchesUnique =
        (parent.pk.length > 0 && sameSet(sortedUnique(parent.pk), refSet)) ||
        parent.indexes.some((i) => {
          const cols = indexColumnOrdinals(i);
          return i.unique && cols !== null && sameSet(sortedUnique(cols), refSet);
        });
      if (!matchesUnique) {
        throw engineError(
          "invalid_foreign_key",
          "there is no unique constraint matching given keys for referenced table " + parent.name,
        );
      }
      // 8. Same-type pairing (§6.2). Because the referenced columns are a PK/UNIQUE key they are
      // key-encodable, so a same-typed local column is key-encodable too — no separate 0A000 type
      // gate is needed.
      for (let p = 0; p < local.length; p++) {
        const li = local[p]!;
        const ri = refs[p]!;
        if (!fkTypesEqual(table.columns[li]!.type, parent.columns[ri]!.type)) {
          throw engineError(
            "datatype_mismatch",
            "foreign key constraint " +
              fkName +
              " cannot be implemented: key columns " +
              table.columns[li]!.name +
              " and " +
              parent.columns[ri]!.name +
              " are of incompatible types: " +
              typeCanonicalName(table.columns[li]!.type) +
              " and " +
              typeCanonicalName(parent.columns[ri]!.type),
          );
        }
      }
      resolvedFks.push({
        name: fkName,
        columns: local,
        refTable: parent.name,
        refColumns: refs,
        onDelete,
        onUpdate,
      });
    }
    // Held in ascending lowercased-name order (the catalog's on-disk + evaluation order, §6.9).
    resolvedFks.sort(compareLowerName);
    table.fks = resolvedFks;

    // EXCLUDE constraints (spec/design/gist.md §7). Resolved AFTER the PK / UNIQUE / CHECK / FK
    // constraints, each in textual order: resolve the element columns (42703/42701) and the WITH
    // operators against the column types (42704 no-opclass / 0A000 deferred-or-unsupported), name the
    // constraint + its backing GiST index (the constraint IS its index — they share a name;
    // 42P07/42710 across the relation + constraint namespaces), and build the MULTI-COLUMN GiST index
    // that enforces it. The probe + 23P01 live in INSERT/UPDATE.
    for (const exc of ct.excludes) {
      const { columns: indices, elements } = resolveExclusionDefinition(table, exc);
      // Name the constraint (= its backing index name). An explicit name checks the relation
      // namespace (42P07) then the table's constraint names (42710); a derived `<table>_<cols>_excl`
      // suffix-walks both.
      const relTaken = (n: string): boolean =>
        this.relationExists(n) ||
        table.name.toLowerCase() === n.toLowerCase() ||
        table.indexes.some((ix) => ix.name.toLowerCase() === n.toLowerCase());
      const conTaken = (n: string): boolean =>
        table.checks.some((c) => c.name.toLowerCase() === n.toLowerCase()) ||
        table.fks.some((f) => f.name.toLowerCase() === n.toLowerCase()) ||
        table.exclusions.some((e) => e.name.toLowerCase() === n.toLowerCase());
      let name: string;
      if (exc.name !== null) {
        // The named EXCLUDE constraint's backing GiST index carries the user-written name
        // into the relation namespace (introspection.md §4).
        checkReservedName("constraint", exc.name);
        if (relTaken(exc.name)) {
          throw engineError("duplicate_table", "relation already exists: " + exc.name);
        }
        if (conTaken(exc.name)) {
          throw engineError(
            "duplicate_object",
            "constraint " + exc.name + " for relation " + table.name + " already exists",
          );
        }
        name = exc.name;
      } else {
        let base = table.name.toLowerCase();
        for (const i of indices) base += "_" + table.columns[i]!.name.toLowerCase();
        base += "_excl";
        name = base;
        for (let suffix = 1; relTaken(name) || conTaken(name); suffix++) {
          name = base + suffix.toString();
        }
      }
      // Insert the backing GiST index in catalog (ascending lowercased-name) order.
      let pos = table.indexes.findIndex((ix) => compareLowerName(ix, { name }) > 0);
      if (pos < 0) pos = table.indexes.length;
      table.indexes.splice(pos, 0, {
        name,
        keys: indices.map((c) => ({ kind: "column", column: c })),
        unique: false,
        kind: "gist",
      });
      table.exclusions.push({ name, index: name, elements });
    }
    // Held in ascending lowercased-name order (the catalog's on-disk order — gist.md §8).
    table.exclusions.sort(compareLowerName);

    if (attachName !== "") {
      // Deferred narrowings on an attached-database table this slice (attached-databases.md §8), each a
      // clean 0A000: a COMPOSITE-typed column (its type lives in the MAIN catalog — no cross-scope type
      // reference this slice), a serial/IDENTITY column (its OWNED sequence would be a cross-scope
      // sequence), and a collated column (the attachment snapshot carries no collation catalog). Plain
      // scalar / array / range / decimal columns with PK / NOT NULL / DEFAULT / CHECK / UNIQUE and
      // secondary btree indexes are fully supported.
      for (const c of table.columns) {
        if (c.type.kind === "composite") {
          throw engineError(
            "feature_not_supported",
            "a composite-typed column on an attached-database table is not supported yet",
          );
        }
        if (c.collation !== null) {
          throw engineError(
            "feature_not_supported",
            `COLLATE on an attached-database-table column ${c.name} is not yet supported`,
          );
        }
      }
      if (pendingSerials.length > 0) {
        throw engineError(
          "feature_not_supported",
          "a serial / IDENTITY column on an attached-database table is not supported yet",
        );
      }
      // Register into the attachment's working snapshot (attached-databases.md §6) — never the main
      // image; published into the attached roots at commit (N-root commit, §5). attachWriteSnap clones
      // the attachment's committed root on first write and marks it dirty. Its NEW stores bind to the
      // attachment's own paging (the storePaging seam — the same one temp/in-memory main use).
      const ws = this.attachWriteSnap(attachName)!;
      ws.storePaging = this.core!.attachments.get(attachName)!.storage.paging;
      const mainTypes = this.readSnap().types;
      const colTypes = table.columns.map((c) => resolveColType(c.type, mainTypes));
      // Build the attachment's new stores at ITS OWN page size (§2) — a file attachment may serialize at
      // a different page size than main, and its records must split to match.
      const aps = this.attachPageSize(attachName);
      ws.putTableResolved(table, colTypes, aps);
      for (const ix of table.indexes) {
        ws.putIndexStore(ix.name.toLowerCase(), new TableStore(pagePayload(aps), []));
      }
      return { kind: "statement", cost: 0n, rowsAffected: null };
    }

    if (targetTemp) {
      // Deferred narrowing on a temp table this slice (spec/design/temp-tables.md §8), a clean 0A000:
      // a collated column (needs the temp snapshot to carry the collation catalog). Plain
      // scalar/array/range/decimal columns with PK / NOT NULL / DEFAULT / CHECK / UNIQUE,
      // serial/IDENTITY columns (the OWNED sequence is staged into the same temp snapshot below), and
      // COMPOSITE-typed columns (resolved against the MAIN type catalog just below) are fully supported.
      for (const c of table.columns) {
        if (c.collation !== null) {
          throw engineError(
            "feature_not_supported",
            `COLLATE on temporary-table column ${c.name} is not yet supported`,
          );
        }
      }
      // Resolve each column's ColType against the MAIN snapshot's composite-type catalog
      // (spec/design/temp-tables.md §8): composites are always persistent (CREATE TYPE is persistent
      // DDL), so the temp snapshot's own types map is empty — resolving there would miss a composite
      // reference. The resulting ColType tree is self-contained, so the temp store needs nothing from
      // the catalog after this (composite.md §4).
      const mainTypes = this.readSnap().types;
      const colTypes = table.columns.map((c) => resolveColType(c.type, mainTypes));
      // Register into the session-local temp snapshot — never the main image, so the table makes zero
      // file writes (§2). Flag tempDirty so the commit can skip persisting the main image.
      this.session.tx!.tempDirty = true;
      const ts: Snapshot = this.session.tx!.tempWorking;
      // The session-local temp snapshot rides a per-domain MemoryBlockStore pager (temp-tables.md §6):
      // lazily create the domain storage on first use and stamp its paging onto this working snapshot, so
      // putTableResolved / putIndexStore attach it to every temp store.
      ts.storePaging = this.tempDomainPaging();
      ts.putTableResolved(table, colTypes, this.pageSize);
      for (const ix of table.indexes) {
        ts.putIndexStore(ix.name.toLowerCase(), new TableStore(pagePayload(this.pageSize), []));
      }
      // Stage each serial/IDENTITY column's OWNED sequence into the SAME temp snapshot
      // (spec/design/sequences.md §12, temp-tables.md §8) — never the main image, so the sequence
      // (like the table) makes zero file writes and is dropped with the table. The names were resolved
      // collision-free during the column walk (relationExists is temp-aware); nextval resolves and
      // advances them via the scope-aware sequence funnel.
      for (const s of pendingSerials) ts.putSequence(s);
      return { kind: "statement", cost: 0n, rowsAffected: null };
    }

    this.putTable(table);
    // The table is brand new (no rows), so each backing index store starts empty.
    for (const ix of table.indexes) {
      this.working().putIndexStore(
        ix.name.toLowerCase(),
        new TableStore(pagePayload(this.pageSize), []),
      );
    }
    // Stage each serial column's OWNED sequence now that the table validated
    // (spec/design/sequences.md §12). The names were resolved (collision-free) during the column
    // walk; the table is in the catalog, so a DROP TABLE will auto-drop these.
    for (const s of pendingSerials) this.working().putSequence(s);
    // DDL touches no rows and evaluates no expressions: zero cost.
    return { kind: "statement", cost: 0n, rowsAffected: null };
  }

  // chooseSerialSeqName chooses the auto-generated name for a serial column's OWNED sequence
  // (spec/design/sequences.md §12), matching PostgreSQL: lower(table)_lower(column)_seq, with the
  // smallest integer suffix 1, 2, … appended until the name is free in the relation namespace — not
  // taken by an existing relation, not equal to the table being created, not already chosen by an
  // earlier serial column of the same statement (pending), and not held by a caller-known pending
  // relation. All-lowercase identifier-derived.
  private chooseSerialSeqName(
    table: string,
    column: string,
    pending: SequenceDef[],
    reserved: string[],
  ): string {
    const base = `${table.toLowerCase()}_${column.toLowerCase()}_seq`;
    const taken = (c: string): boolean =>
      this.relationExists(c) ||
      c.toLowerCase() === table.toLowerCase() ||
      pending.some((s) => s.name.toLowerCase() === c.toLowerCase()) ||
      reserved.some((name) => name.toLowerCase() === c.toLowerCase());
    if (!taken(base)) return base;
    for (let n = 1; ; n++) {
      const cand = base + n.toString();
      if (!taken(cand)) return cand;
    }
  }

  // resolveChecks resolves a table's CHECK constraints for a write statement: each stored
  // expression against a one-relation scope, in the catalog's (evaluation/name) order.
  // Cannot fail for a catalog produced by CREATE TABLE or a well-formed file (both
  // validated); a hand-corrupted expression surfaces its natural resolve error.
  private resolveChecks(table: Table): NamedCheck[] {
    if (table.checks.length === 0) return [];
    const scope = Scope.single(this, table);
    return table.checks.map((c) => ({
      name: c.name,
      node: resolve(
        scope,
        c.expr,
        null,
        { collecting: false, groupKeys: [], specs: [] },
        new ParamTypes(),
      ).node,
    }));
  }

  // maintenanceEnv builds the unmetered eval env for phase-1 index-expression / CHECK evaluation
  // (spec/design/indexes.md §4): params/CTEs are empty (an index expression cannot reference them) and
  // the seam rng is shared/threaded (an immutable index expression never reads it). Used by the index
  // maintenance helpers and CREATE INDEX build.
  private maintenanceEnv(rng: StmtRng): EvalEnv {
    return {
      params: [],
      outer: [],
      runSubquery: (p, o) => this.execQueryPlan(p, o, [], EMPTY_CTE_CTX),
      seam: this.session.seam,
      rng,
      ctes: EMPTY_CTE_CTX,
      exec: this,
    };
  }

  // resolveIndex resolves an index's key elements for one statement's maintenance
  // (spec/design/indexes.md §4), modeled on resolveChecks: a column key keeps its ordinal; an
  // expression key resolves against the table's columns to an RExpr + its encoding Type + collation.
  // The expression was validated (immutable, indexable result) at CREATE INDEX, so resolution here
  // cannot newly fail (an aggregate/window/subquery/param was rejected then, and re-resolving under
  // the Forbidden agg mode is inert). Returns an owned ResolvedIndex, so the write paths can hold it
  // while mutating stores.
  resolveIndex(table: Table, def: IndexDef): ResolvedIndex {
    const keys: ResolvedKey[] = def.keys.map((k) => {
      if (k.kind === "column") return { kind: "column", column: k.column };
      const scope = Scope.single(this, table);
      const { node, type } = resolve(
        scope,
        k.expr,
        null,
        { collecting: false, groupKeys: [], specs: [] },
        new ParamTypes(),
      );
      const ty = resolvedToKeyType(type);
      if (ty === null) {
        throw new Error("index expression result type validated indexable at CREATE INDEX");
      }
      const coll = resolveDeriv(scope.catalog, deriveCollation(scope, k.expr));
      return { kind: "expr", expr: node, type: ty, coll };
    });
    // A partial index's predicate (indexes.md §9), re-resolved against the table's columns — it was
    // validated boolean + immutable at CREATE INDEX, so this cannot newly fail.
    let predicate: RExpr | undefined;
    if (def.predicate) {
      predicate = resolveBooleanFilter(
        Scope.single(this, table),
        def.predicate.expr,
        new ParamTypes(),
      );
    }
    return { name: def.name, unique: def.unique, kind: def.kind, keys, predicate };
  }

  // resolveTableIndexes resolves every index of a table once per statement (the maintenance driver —
  // INSERT / UPDATE / DELETE build their ResolvedIndex list up front, parallel to table.indexes).
  resolveTableIndexes(table: Table): ResolvedIndex[] {
    return table.indexes.map((d) => this.resolveIndex(table, d));
  }

  // indexEntries is a row's secondary-index entry keys for maintenance (spec/design/indexes.md §4),
  // building the unmetered eval env internally (an index expression is immutable). Callers compute all
  // entries through this before mutating a store.
  private indexEntries(
    columns: Column[],
    colls: (Collation | null)[],
    rindex: ResolvedIndex,
    storageKey: Uint8Array,
    row: Row,
  ): Uint8Array[] {
    return indexEntryKeys(
      columns,
      colls,
      rindex,
      storageKey,
      row,
      this.maintenanceEnv(new StmtRng()),
    );
  }

  // indexPrefix is a row's uniqueness-probe prefix for one index (spec/design/indexes.md §8), building
  // the unmetered eval env internally (as indexEntries).
  private indexPrefix(
    columns: Column[],
    colls: (Collation | null)[],
    rindex: ResolvedIndex,
    row: Row,
  ): Uint8Array | null {
    return indexPrefixKey(columns, colls, rindex, row, this.maintenanceEnv(new StmtRng()));
  }

  // arbiterProbeKey is a candidate row's arbiter key for ON CONFLICT (spec/design/upsert.md §3),
  // building the unmetered eval env internally (an expression-index arbiter evaluates its keys).
  private arbiterProbeKey(
    arb: Arbiter,
    table: Table,
    pk: number[],
    colls: (Collation | null)[],
    rindexes: ResolvedIndex[],
    row: Row,
  ): Uint8Array | null {
    return arbiterKey(arb, table, pk, colls, rindexes, row, this.maintenanceEnv(new StmtRng()));
  }

  // resolveDefaultExprs resolves each column's EXPRESSION default (constraints.md §2) to an
  // RExpr, once per INSERT statement — insertRows (and the VALUES DEFAULT-keyword
  // materialization) evaluate it per omitted/DEFAULT slot. Returns a slot per column (parallel
  // to table.columns): the resolved node for an expression default, null for a column with a
  // constant default or no default. The default resolves against an EMPTY scope (no columns; a
  // column reference was rejected 0A000 at CREATE TABLE) with the column's type as the operand
  // hint.
  private resolveDefaultExprs(table: Table): (RExpr | null)[] {
    return table.columns.map((col) => {
      if (col.defaultExpr === null) return null;
      return resolve(
        Scope.empty(this),
        col.defaultExpr.expr,
        typeScalar(col.type),
        { collecting: false, groupKeys: [], specs: [] },
        new ParamTypes(),
      ).node;
    });
  }

  // evalDefault is the value an omitted column or a DEFAULT value slot takes (constraints.md §2):
  // the column's pre-evaluated constant (col.default, or NULL when it has none), OR — for an
  // expression default — the resolved RExpr evaluated against an empty row through the
  // per-statement seam/clock (rng) and metered (operator_eval per node). Reused by the VALUES
  // materialization (a DEFAULT keyword) and insertRows (an omitted column), sharing ONE StmtRng
  // so a multi-row DEFAULT uuidv7() stays monotonic. defaultRExpr is null for a constant/no default.
  private evalDefault(col: Column, defaultRExpr: RExpr | null, rng: StmtRng, meter: Meter): Value {
    if (defaultRExpr === null) return col.default ?? nullValue();
    meter.guard();
    const env: EvalEnv = {
      params: [],
      outer: [],
      runSubquery: (p, o) => this.execQueryPlan(p, o, [], EMPTY_CTE_CTX),
      seam: this.session.seam,
      rng,
      ctes: EMPTY_CTE_CTX,
      exec: this,
    };
    return evalExpr(defaultRExpr, [], env, meter);
  }

  // executeDropTable runs a DROP TABLE [IF EXISTS] a [, …] [CASCADE | RESTRICT]: remove each named
  // table's definition and row store from the catalog (keyed by lower-cased name). Two-phase /
  // all-or-nothing (spec/design/grammar.md §13): every name is resolved and validated first — a
  // missing table is 42P01 (unless IF EXISTS skips just that name), a non-table relation is 42809,
  // and an external FK dependent is 2BP01 under RESTRICT — and only if the whole list checks out is
  // anything removed. A repeated name is deduplicated; a FK between two tables both in the drop set
  // never blocks; CASCADE drops the surviving tables' now-dangling FK constraints. Like CREATE TABLE
  // it touches no rows and evaluates no expression tree, so it accrues zero cost.
  private executeDropTable(dt: DropTable): Outcome {
    // ---- Phase 1: resolve & classify every name into the drop set. Nothing is removed yet. A
    // repeated name is deduplicated (PG collects the targets into a set, so `DROP TABLE a, a` drops
    // `a` once and succeeds); `seen` is the set of lowercased keys actually being dropped.
    type Scope = "temp" | "persistent";
    const targets: { key: string; scope: Scope }[] = [];
    const seen = new Set<string>();
    for (const name of dt.names) {
      const key = name.toLowerCase();
      if (seen.has(key)) continue; // already resolved this exact target (deduplicated)
      // A built-in catalog relation resolves BEFORE the user catalog (introspection.md §5), and a
      // system relation cannot be dropped: 42809. IF EXISTS does not suppress this (the relation
      // exists — this is a kind rejection, not a missing name).
      if (isCatalogRelName(key)) {
        throw engineError("wrong_object_type", `cannot drop system relation "${key}"`);
      }
      // Resolution walk: session-local temp → persistent. Preclude-overlaps keeps a name in at most one
      // scope, so this is just "where it lives" (temp-tables.md §3).
      let scope: Scope;
      if (this.isTempTable(name)) {
        scope = "temp";
      } else if (this.readSnap().table(name)) {
        scope = "persistent";
      } else {
        // Not a table in any scope. An index's name is the wrong object kind (42809 — indexes.md
        // §2); IF EXISTS does NOT suppress this. Otherwise a missing table is 42P01, unless IF
        // EXISTS makes it a no-op for just this name (PG turns the missing-table error into a notice).
        if (this.findIndex(name)) {
          throw engineError("wrong_object_type", name + " is not a table");
        }
        if (dt.ifExists) continue;
        throw engineError("undefined_table", "table does not exist: " + name);
      }
      seen.add(key);
      targets.push({ key, scope });
    }
    // ---- Phase 2: FK dependency check (RESTRICT) / removal collection (CASCADE). Only a persistent
    // table can be an FK parent (a temp table never is, §8), so the scan runs over the persistent
    // snapshot; a dependent whose referencing table is itself in the drop set does not count (the
    // drop-set exclusion is the whole `seen` set, so `DROP TABLE parent, child` succeeds even under
    // RESTRICT).
    const deps = this.readSnap().fkDependentsExcluding(seen);
    let cascadeRemovals: FkDependent[] = [];
    if (dt.cascade) {
      cascadeRemovals = deps;
    } else if (deps.length > 0) {
      // RESTRICT (the default, and the bare form's behavior): an external FK dependent blocks the
      // drop with 2BP01 — the same message the single-table check produced.
      const d = deps[0];
      throw engineError(
        "dependent_objects_still_exist",
        "cannot drop table " +
          d.droppedName +
          " because other objects depend on it: constraint " +
          d.fkName +
          " on table " +
          d.refTableName,
      );
    }
    // ---- Phase 3: apply. CASCADE first drops each surviving table's now-dangling FK constraint (in
    // place, preserving its rows). A FK only ever lives on a persistent table (temp tables reject FKs
    // at CREATE), so the removal routes to the main working snapshot.
    for (const d of cascadeRemovals) {
      this.working().removeForeignKey(d.refTableKey, d.fkName);
    }
    // Then remove every target from its own scope, auto-dropping the sequences it owns — a
    // serial/IDENTITY column's owned sequence (spec/design/sequences.md §12; an owned sequence is
    // never an FK dependent, so the phase-2 check never blocked on it). A temp drop touches only its
    // temp snapshot, never the main image, so it makes zero file writes.
    for (const tgt of targets) {
      if (tgt.scope === "temp") {
        this.session.tx!.tempDirty = true;
        const ts = this.tempSnap();
        for (const sk of ts.sequencesOwnedBy(tgt.key)) ts.removeSequence(sk);
        ts.removeTable(tgt.key);
      } else {
        const ownedSeqs = this.readSnap().sequencesOwnedBy(tgt.key);
        const w = this.working();
        for (const sk of ownedSeqs) w.removeSequence(sk);
        w.removeTable(tgt.key);
      }
    }
    return { kind: "statement", cost: 0n, rowsAffected: null };
  }

  // executeAlterTable implements ALTER TABLE slices 1-5 (alter.md §1-§3.4).
  private executeAlterTable(at: AlterTable): Outcome {
    checkCatalogRelWrite(at.name);
    this.checkAttachmentWritable(at.db);
    let snap: Snapshot | undefined;
    if (at.db === undefined)
      snap =
        this.isTempTable(at.name) ||
        this.tempSnap().findIndex(at.name) !== null ||
        this.tempSnap().sequence(at.name) !== undefined
          ? this.tempSnap()
          : this.readSnap();
    else
      switch (at.db.toLowerCase()) {
        case "temp":
          snap = this.tempSnap();
          break;
        case "main":
          snap = this.readSnap();
          break;
        default:
          snap = this.attachReadSnap(at.db.toLowerCase());
          if (snap === undefined)
            throw engineError("undefined_table", `database "${at.db}" is not attached`);
      }
    const original = snap.table(at.name);
    if (original === undefined) {
      if (snap.findIndex(at.name) !== null || snap.sequence(at.name) !== undefined)
        throw engineError("wrong_object_type", `${at.name} is not a table`);
      if (at.ifExists) return { kind: "statement", cost: 0n, rowsAffected: null };
      throw engineError("undefined_table", `table does not exist: ${at.name}`);
    }
    const oldKey = original.name.toLowerCase();
    let table: Table = {
      ...original,
      columns: original.columns.map((c) => ({ ...c })),
      checks: original.checks.map((c) => ({ ...c })),
      indexes: original.indexes.map((i) => ({ ...i, keys: i.keys.map((k) => ({ ...k })) })),
      fks: original.fks.map((f) => ({ ...f })),
      exclusions: original.exclusions.map((e) => ({ ...e })),
    };
    let renameTable = false;
    let indexRename: { oldName: string; newName: string } | undefined;
    const tempScope =
      at.db === undefined ? this.isTempTable(at.name) : at.db.toLowerCase() === "temp";
    const attachmentScope =
      at.db !== undefined && at.db.toLowerCase() !== "main" && at.db.toLowerCase() !== "temp";
    const relationTaken = (name: string) =>
      attachmentScope
        ? snap.table(name) !== undefined ||
          snap.findIndex(name) !== null ||
          snap.sequence(name) !== undefined
        : this.relationExists(name);
    const pendingSerials: SequenceDef[] = [];
    const workingRelationTaken = (name: string): boolean => {
      if (pendingSerials.some((s) => s.name.toLowerCase() === name.toLowerCase())) return true;
      if (table.indexes.some((i) => i.name.toLowerCase() === name.toLowerCase())) return true;
      if (original.indexes.some((i) => i.name.toLowerCase() === name.toLowerCase())) return false;
      return relationTaken(name);
    };
    const addedConstraints = new Set<string>();
    type ColumnSource = { kind: "original"; column: number } | { kind: "added"; column: Column };
    const columnSources: ColumnSource[] = original.columns.map((_, column) => ({
      kind: "original",
      column,
    }));
    const typeChangedColumns = original.columns.map(() => false);
    type RowStep =
      | { kind: "add"; column: Column; defaultExpr: RExpr | null }
      | { kind: "drop"; column: number }
      | { kind: "setType"; column: number; value: RExpr };
    const rowSteps: RowStep[] = [];
    let typeChanged = false;
    let prepCost = 0n;
    const cascadeUniqueCols: number[][] = [];
    const cascadeDroppedColumnFks = new Set<string>();
    const rewriteExprs = (
      column?: { oldName: string; newName: string },
      tableRename?: string,
    ): void => {
      const rw = (text: string) =>
        column
          ? rewriteColumnIdentifier(text, table.name, column.oldName, column.newName)
          : rewriteTableQualifier(text, table.name, tableRename!);
      table.checks = table.checks.map((c) => ({
        ...c,
        ...(() => {
          const x = rw(c.exprText);
          return { exprText: x.text, expr: x.expr };
        })(),
      }));
      table.columns = table.columns.map((c) =>
        c.defaultExpr === null
          ? c
          : (() => {
              const x = rw(c.defaultExpr!.exprText);
              return { ...c, defaultExpr: { exprText: x.text, expr: x.expr } };
            })(),
      );
      table.indexes = table.indexes.map((idx) => ({
        ...idx,
        keys: idx.keys.map((k) =>
          k.kind === "column"
            ? k
            : (() => {
                const x = rw(k.exprText);
                return { ...k, exprText: x.text, expr: x.expr };
              })(),
        ),
        predicate:
          idx.predicate === undefined
            ? undefined
            : (() => {
                const x = rw(idx.predicate!.exprText);
                return { exprText: x.text, expr: x.expr };
              })(),
      }));
    };

    switch (at.action.kind) {
      case "renameTable": {
        checkReservedName("table", at.action.newName);
        if (relationTaken(at.action.newName)) {
          throw engineError("duplicate_table", `relation already exists: ${at.action.newName}`);
        }
        rewriteExprs(undefined, at.action.newName);
        table = { ...table, name: at.action.newName };
        renameTable = true;
        break;
      }
      case "renameColumn": {
        const ci = columnIndex(table, at.action.oldName);
        if (ci < 0)
          throw engineError("undefined_column", `column does not exist: ${at.action.oldName}`);
        if (columnIndex(table, at.action.newName) >= 0)
          throw engineError("duplicate_column", `column already exists: ${at.action.newName}`);
        rewriteExprs({ oldName: at.action.oldName, newName: at.action.newName });
        table.columns[ci] = { ...table.columns[ci]!, name: at.action.newName };
        break;
      }
      case "renameConstraint": {
        const old = at.action.oldName,
          next = at.action.newName;
        const exists = (name: string) =>
          table.checks.some((c) => c.name.toLowerCase() === name.toLowerCase()) ||
          table.indexes.some((i) => i.unique && i.name.toLowerCase() === name.toLowerCase()) ||
          table.fks.some((f) => f.name.toLowerCase() === name.toLowerCase()) ||
          table.exclusions.some((e) => e.name.toLowerCase() === name.toLowerCase());
        if (!exists(old))
          throw engineError("undefined_object", `constraint does not exist: ${old}`);
        if (exists(next))
          throw engineError("duplicate_object", `constraint already exists: ${next}`);
        table.checks = table.checks.map((c) =>
          c.name.toLowerCase() === old.toLowerCase() ? { ...c, name: next } : c,
        );
        table.fks = table.fks.map((f) =>
          f.name.toLowerCase() === old.toLowerCase() ? { ...f, name: next } : f,
        );
        table.exclusions = table.exclusions.map((e) => {
          if (e.name.toLowerCase() !== old.toLowerCase()) return e;
          indexRename = { oldName: old, newName: next };
          return { ...e, name: next, index: next };
        });
        table.indexes = table.indexes.map((i) => {
          if (
            (!i.unique && indexRename === undefined) ||
            i.name.toLowerCase() !== old.toLowerCase()
          )
            return i;
          indexRename = { oldName: old, newName: next };
          return { ...i, name: next };
        });
        if (indexRename) {
          checkReservedName("constraint", next);
          if (relationTaken(next))
            throw engineError("duplicate_table", `relation already exists: ${next}`);
        }
        table.checks.sort(compareLowerName);
        table.indexes.sort(compareLowerName);
        table.fks.sort(compareLowerName);
        table.exclusions.sort(compareLowerName);
        break;
      }
      case "actions": {
        const added = addedConstraints;
        const taken = (n: string) =>
          table.checks.some((c) => c.name.toLowerCase() === n.toLowerCase()) ||
          table.indexes.some((i) => i.unique && i.name.toLowerCase() === n.toLowerCase()) ||
          table.fks.some((f) => f.name.toLowerCase() === n.toLowerCase()) ||
          table.exclusions.some((e) => e.name.toLowerCase() === n.toLowerCase());
        const actions = [...at.action.actions];
        while (actions.length > 0) {
          const action = actions.shift()!;
          if (action.kind === "addColumn") {
            if (columnIndex(table, action.column.name) >= 0) {
              if (action.ifNotExists) continue;
              throw engineError(
                "duplicate_column",
                `column already exists: ${action.column.name}`,
              );
            }
            if (action.foreignKeys.length > 0 && (tempScope || attachmentScope))
              throw engineError(
                "feature_not_supported",
                "this constraint is not supported in this table scope",
              );
            // Earlier index actions already live in table; named inline UNIQUE constraints are
            // queued only after this column resolves. Both reserve their relation names while an
            // owned serial/identity sequence chooses its name.
            const reservedRelationNames = table.indexes.map((i) => i.name);
            if (!action.column.primaryKey)
              reservedRelationNames.push(
                ...action.uniques.flatMap((u) => (u.name === null ? [] : [u.name])),
              );
            const col = this.buildAlterAddedColumn(
              table,
              action.column,
              pendingSerials,
              reservedRelationNames,
              tempScope,
              attachmentScope,
            );
            table.columns.push(col);
            if (col.primaryKey) table.pk = [table.columns.length - 1];
            columnSources.push({ kind: "added", column: col });
            typeChangedColumns.push(false);
            rowSteps.push({
              kind: "add",
              column: col,
              defaultExpr: this.resolveDefaultExprs({
                ...table,
                columns: [col],
                pk: [],
                checks: [],
                indexes: [],
                fks: [],
                exclusions: [],
              })[0]!,
            });
            actions.unshift(
              ...action.checks.map(
                (def) =>
                  ({
                    kind: "addConstraint",
                    constraint: { kind: "check", def },
                  }) as const,
              ),
              ...action.uniques.filter(() => !col.primaryKey).map(
                (def) =>
                  ({
                    kind: "addConstraint",
                    constraint: { kind: "unique", def },
                  }) as const,
              ),
              ...action.foreignKeys.map(
                (def) =>
                  ({
                    kind: "addConstraint",
                    constraint: { kind: "foreignKey", def },
                  }) as const,
              ),
            );
            continue;
          }
          if (action.kind === "dropColumn") {
            const ci = columnIndex(table, action.name);
            if (ci < 0) {
              if (action.ifExists) continue;
              throw engineError("undefined_column", `column does not exist: ${action.name}`);
            }
            if (table.pk.includes(ci))
              throw engineError(
                "feature_not_supported",
                "dropping a primary-key column is not supported yet",
              );
            const usesExpr = (expr: Expr) => checkReferencedColumns(expr, table.columns).includes(ci);
            const indexUses = (index: IndexDef) =>
              index.keys.some((key) =>
                key.kind === "column" ? key.column === ci : usesExpr(key.expr),
              ) || (index.predicate !== undefined && usesExpr(index.predicate.expr));
            // PostgreSQL owns an FK through its local (referencing) columns. Dropping one removes
            // the whole FK under RESTRICT. A self-FK that uses the column only on the referenced
            // side remains a dependency.
            const fkUsesLocalColumn = (fk: ForeignKey) => fk.columns.includes(ci);
            const fkUsesSelfRefColumn = (fk: ForeignKey) =>
              fk.refTable.toLowerCase() === table.name.toLowerCase() &&
              fk.refColumns.includes(ci);
            const selfRefFkDep = table.fks.some(
              (fk) => fkUsesSelfRefColumn(fk) && !fkUsesLocalColumn(fk),
            );
            const source = columnSources[ci]!;
            const incomingDep =
              source.kind === "original" &&
              [...snap.tables].some(
                ([key, child]) =>
                  key.toLowerCase() !== oldKey &&
                  child.fks.some(
                    (fk) =>
                      fk.refTable.toLowerCase() === original.name.toLowerCase() &&
                      fk.refColumns.includes(source.column) &&
                      !cascadeDroppedColumnFks.has(`${key.toLowerCase()}\0${fk.name.toLowerCase()}`) &&
                      !cascadeUniqueCols.some((cols) => sameSet(sortedUnique(fk.refColumns), cols)),
                  ),
              );
            if (!action.cascade && (selfRefFkDep || incomingDep))
              throw engineError(
                "dependent_objects_still_exist",
                `cannot drop column ${action.name} because other objects depend on it`,
              );
            if (action.cascade) {
              if (source.kind === "original")
                for (const [key, child] of snap.tables)
                  if (key.toLowerCase() !== oldKey)
                    for (const fk of child.fks)
                      if (
                        fk.refTable.toLowerCase() === original.name.toLowerCase() &&
                        fk.refColumns.includes(source.column)
                      )
                        cascadeDroppedColumnFks.add(
                          `${key.toLowerCase()}\0${fk.name.toLowerCase()}`,
                        );
            }
            // PostgreSQL treats same-table CHECKs, indexes (including UNIQUE), and EXCLUDE
            // constraints as internally dependent on their columns. They disappear even under
            // RESTRICT; CASCADE is needed only for external dependents such as incoming FKs.
            table.checks = table.checks.filter((check) => {
              const keep = !usesExpr(check.expr);
              if (!keep) added.delete(check.name.toLowerCase());
              return keep;
            });
            table.indexes = table.indexes.filter((index) => {
              const keep = !indexUses(index);
              if (!keep) added.delete(index.name.toLowerCase());
              return keep;
            });
            table.exclusions = table.exclusions.filter((ex) => {
              const keep = !ex.elements.some((el) => el.column === ci);
              if (!keep) added.delete(ex.name.toLowerCase());
              return keep;
            });
            // A local-side FK is internally owned by the dropped column and disappears without
            // CASCADE. CASCADE also removes referenced-side-only self-FKs.
            table.fks = table.fks.filter((fk) => {
              const keep =
                !fkUsesLocalColumn(fk) && !(action.cascade && fkUsesSelfRefColumn(fk));
              if (!keep) added.delete(fk.name.toLowerCase());
              return keep;
            });
            table.columns.splice(ci, 1);
            columnSources.splice(ci, 1);
            typeChangedColumns.splice(ci, 1);
            rowSteps.push({ kind: "drop", column: ci });
            table.pk = table.pk.map((column) => (column > ci ? column - 1 : column));
            table.indexes = table.indexes.map((index) => ({
              ...index,
              keys: index.keys.map((key) =>
                key.kind === "column" && key.column > ci
                  ? { ...key, column: key.column - 1 }
                  : key,
              ),
            }));
            table.fks = table.fks.map((fk) => ({
              ...fk,
              columns: fk.columns.map((column) => (column > ci ? column - 1 : column)),
              refColumns:
                fk.refTable.toLowerCase() === table.name.toLowerCase()
                  ? fk.refColumns.map((column) => (column > ci ? column - 1 : column))
                  : fk.refColumns,
            }));
            table.exclusions = table.exclusions.map((ex) => ({
              ...ex,
              elements: ex.elements.map((el) =>
                el.column > ci ? { ...el, column: el.column - 1 } : el,
              ),
            }));
            // The owned sequence is part of the dropped column. Release an existing one during action
            // processing so later actions can reuse its name and cannot advance it through a later
            // DEFAULT.
            if (source.kind === "original")
              for (const key of snap.sequencesOwnedBy(original.name)) {
                const seq = snap.sequence(key);
                if (seq?.ownedBy?.column === source.column) snap.removeSequence(key);
              }
            for (let i = pendingSerials.length - 1; i >= 0; i--) {
              const seq = pendingSerials[i]!, owner = seq.ownedBy;
              if (owner === undefined || owner.table.toLowerCase() !== table.name.toLowerCase())
                continue;
              if (owner.column === ci) pendingSerials.splice(i, 1);
              else if (owner.column > ci)
                pendingSerials[i] = { ...seq, ownedBy: { ...owner, column: owner.column - 1 } };
            }
            continue;
          }
          if (action.kind === "addPrimaryKey") {
            if (table.pk.length > 0)
              throw engineError(
                "invalid_table_definition",
                `multiple primary keys for table ${table.name} are not allowed`,
              );
            const pk: number[] = [];
            for (const name of action.columns) {
              const ci = columnIndex(table, name);
              if (ci < 0)
                throw engineError(
                  "undefined_column",
                  `column ${name} named in key does not exist`,
                );
              if (pk.includes(ci))
                throw engineError(
                  "duplicate_column",
                  `column ${name} appears twice in primary key`,
                );
              const type = table.columns[ci]!.type;
              if (
                type.kind === "composite" ||
                (type.kind === "array" && !typeIsArrayKeyable(type)) ||
                (type.kind !== "array" && type.kind !== "range" && !typeIsKeyableScalar(type))
              )
                throw engineError(
                  "feature_not_supported",
                  `a ${typeCanonicalName(type)} primary key is not supported yet`,
                );
              pk.push(ci);
            }
            table.columns = table.columns.map((column, ci) =>
              pk.includes(ci) ? { ...column, primaryKey: true, notNull: true } : column,
            );
            table.pk = pk;
            continue;
          }
          if (action.kind === "dropPrimaryKey") {
            if (table.pk.length === 0)
              throw engineError("undefined_object", "primary key does not exist");
            const oldPk = sortedUnique(table.pk);
            const localDeps = table.fks.some(
              (fk) =>
                fk.refTable.toLowerCase() === table.name.toLowerCase() &&
                sameSet(sortedUnique(fk.refColumns), oldPk),
            );
            const incomingDeps = [...snap.tables].some(
              ([key, child]) =>
                key.toLowerCase() !== oldKey &&
                child.fks.some(
                  (fk) =>
                    fk.refTable.toLowerCase() === original.name.toLowerCase() &&
                    sameSet(sortedUnique(fk.refColumns), oldPk),
                ),
            );
            if (!action.cascade && (localDeps || incomingDeps))
              throw engineError(
                "dependent_objects_still_exist",
                "cannot drop primary key because other objects depend on it",
              );
            if (action.cascade) {
              table.fks = table.fks.filter(
                (fk) =>
                  fk.refTable.toLowerCase() !== table.name.toLowerCase() ||
                  !sameSet(sortedUnique(fk.refColumns), oldPk),
              );
              cascadeUniqueCols.push(oldPk);
            }
            table.columns = table.columns.map((column, ci) =>
              table.pk.includes(ci) ? { ...column, primaryKey: false } : column,
            );
            table.pk = [];
            continue;
          }
          if (action.kind === "addConstraint") {
            const c = action.constraint;
            if (c.kind === "foreignKey" || c.kind === "exclude") {
              if (tempScope)
                throw engineError(
                  "feature_not_supported",
                  "this constraint is not supported on a temporary table",
                );
              if (attachmentScope)
                throw engineError(
                  "feature_not_supported",
                  "this constraint is not supported on an attached-database table",
                );
            }
            if (c.kind === "check") {
              const d = c.def;
              rejectCheckStructure(d.expr);
              const rt = resolve(
                Scope.single(this, table),
                d.expr,
                null,
                { collecting: false, groupKeys: [], specs: [] },
                new ParamTypes(),
              ).type;
              if (rt.kind !== "bool" && rt.kind !== "null")
                throw typeError("argument of CHECK must be boolean");
              let name = d.name ?? `${table.name.toLowerCase()}_check`;
              if (d.name === null) {
                const rs = checkReferencedColumns(d.expr, table.columns);
                if (rs.length === 1)
                  name = `${table.name.toLowerCase()}_${table.columns[rs[0]!]!.name.toLowerCase()}_check`;
                for (let n = 1; taken(name); n++) name = name.replace(/\d+$/, "") + n;
              } else if (taken(name))
                throw engineError(
                  "duplicate_object",
                  `constraint ${name} for relation ${table.name} already exists`,
                );
              table.checks.push({ name, exprText: d.text, expr: d.expr });
              table.checks.sort(compareLowerName);
              added.add(name.toLowerCase());
            } else if (c.kind === "unique") {
              const d = c.def,
                cols: number[] = [];
              for (const n of d.columns) {
                const ci = columnIndex(table, n);
                if (ci < 0)
                  throw engineError("undefined_column", `column ${n} named in key does not exist`);
                if (cols.includes(ci))
                  throw engineError(
                    "duplicate_column",
                    `column ${n} appears twice in unique constraint`,
                  );
                cols.push(ci);
              }
              for (const ci of cols) {
                const ty = table.columns[ci]!.type;
                if (
                  !typeIsInteger(ty) &&
                  !typeIsBoolean(ty) &&
                  !typeIsText(ty) &&
                  !typeIsBytea(ty) &&
                  !typeIsDecimal(ty) &&
                  !typeIsUuid(ty) &&
                  !typeIsTimestamp(ty) &&
                  !typeIsTimestamptz(ty) &&
                  !typeIsDate(ty) &&
                  !typeIsInterval(ty) &&
                  !typeIsFloat(ty) &&
                  !typeIsRange(ty) &&
                  !typeIsArrayKeyable(ty)
                )
                  throw engineError(
                    "feature_not_supported",
                    `a ${typeCanonicalName(ty)} unique constraint member is not supported yet`,
                  );
              }
              let name: string;
              if (d.name !== null) {
                name = d.name;
                checkReservedName("constraint", name);
                if (workingRelationTaken(name))
                  throw engineError("duplicate_table", `relation already exists: ${name}`);
                if (taken(name))
                  throw engineError(
                    "duplicate_object",
                    `constraint ${name} for relation ${table.name} already exists`,
                  );
              } else {
                const base = `${table.name.toLowerCase()}_${cols.map((i) => table.columns[i]!.name.toLowerCase()).join("_")}_key`;
                name = base;
                for (let suffix = 1; workingRelationTaken(name) || taken(name); suffix++)
                  name = base + suffix.toString();
              }
              table.indexes.push({
                name,
                keys: cols.map((column) => ({ kind: "column", column })),
                unique: true,
                kind: "btree",
              });
              table.indexes.sort(compareLowerName);
              added.add(name.toLowerCase());
            } else if (c.kind === "foreignKey") {
              const d = c.def,
                local: number[] = [];
              for (const n of d.columns) {
                const ci = columnIndex(table, n);
                if (ci < 0)
                  throw engineError("undefined_column", `column ${n} named in key does not exist`);
                if (local.includes(ci))
                  throw engineError(
                    "duplicate_column",
                    `column ${n} appears twice in foreign key constraint`,
                  );
                local.push(ci);
              }
              const parent =
                d.refTable.toLowerCase() === table.name.toLowerCase()
                  ? table
                  : snap.table(d.refTable);
              if (!parent)
                throw engineError("undefined_table", `table does not exist: ${d.refTable}`);
              let refs: number[];
              if (d.refColumns === null) refs = [...parent.pk];
              else {
                refs = [];
                for (const n of d.refColumns) {
                  const i = columnIndex(parent, n);
                  if (i < 0)
                    throw engineError(
                      "undefined_column",
                      `column ${n} named in key does not exist`,
                    );
                  if (refs.includes(i))
                    throw engineError(
                      "duplicate_column",
                      `column ${n} appears twice in foreign key constraint`,
                    );
                  refs.push(i);
                }
              }
              if (refs.length === 0)
                throw engineError(
                  "undefined_object",
                  `there is no primary key for referenced table ${parent.name}`,
                );
              if (local.length !== refs.length)
                throw engineError(
                  "invalid_foreign_key",
                  "number of referencing and referenced columns for foreign key disagree",
                );
              const rs = sortedUnique(refs);
              if (
                !(
                  sameSet(sortedUnique(parent.pk), rs) ||
                  parent.indexes.some((i) => {
                    const x = indexColumnOrdinals(i);
                    return i.unique && x !== null && sameSet(sortedUnique(x), rs);
                  })
                )
              )
                throw engineError(
                  "invalid_foreign_key",
                  `there is no unique constraint matching given keys for referenced table ${parent.name}`,
                );
              let name: string;
              if (d.name !== null) {
                name = d.name;
                if (taken(name))
                  throw engineError(
                    "duplicate_object",
                    `constraint ${name} for relation ${table.name} already exists`,
                  );
              } else {
                const base = `${table.name.toLowerCase()}_${local.map((i) => table.columns[i]!.name.toLowerCase()).join("_")}_fkey`;
                name = base;
                for (let suffix = 1; taken(name); suffix++) name = base + suffix.toString();
              }
              for (let p = 0; p < local.length; p++) {
                const li = local[p]!,
                  ri = refs[p]!;
                if (!fkTypesEqual(table.columns[li]!.type, parent.columns[ri]!.type))
                  throw engineError(
                    "datatype_mismatch",
                    `foreign key constraint ${name} cannot be implemented: key columns ${table.columns[li]!.name} and ${parent.columns[ri]!.name} are of incompatible types: ${typeCanonicalName(table.columns[li]!.type)} and ${typeCanonicalName(parent.columns[ri]!.type)}`,
                  );
              }
              table.fks.push({
                name,
                columns: local,
                refTable: parent.name,
                refColumns: refs,
                onDelete: fkAction(d.onDelete, "DELETE"),
                onUpdate: fkAction(d.onUpdate, "UPDATE"),
              });
              table.fks.sort(compareLowerName);
              added.add(name.toLowerCase());
            } else {
              const d = c.def;
              const { columns: cols, elements } = resolveExclusionDefinition(table, d);
              let name: string;
              if (d.name !== null) {
                name = d.name;
                checkReservedName("constraint", name);
                if (workingRelationTaken(name))
                  throw engineError("duplicate_table", `relation already exists: ${name}`);
                if (taken(name))
                  throw engineError(
                    "duplicate_object",
                    `constraint ${name} for relation ${table.name} already exists`,
                  );
              } else {
                const base = `${table.name.toLowerCase()}_${cols.map((i) => table.columns[i]!.name.toLowerCase()).join("_")}_excl`;
                name = base;
                for (let suffix = 1; workingRelationTaken(name) || taken(name); suffix++)
                  name = base + suffix.toString();
              }
              table.indexes.push({
                name,
                keys: cols.map((column) => ({ kind: "column", column })),
                unique: false,
                kind: "gist",
              });
              table.exclusions.push({ name, index: name, elements });
              table.indexes.sort(compareLowerName);
              table.exclusions.sort(compareLowerName);
              added.add(name.toLowerCase());
            }
            continue;
          }
          if (action.kind === "dropConstraint") {
            const k = action.name.toLowerCase();
            let found = false;
            const before = table.checks.length;
            table.checks = table.checks.filter((c) => c.name.toLowerCase() !== k);
            found = table.checks.length !== before || found;
            const bf = table.fks.length;
            table.fks = table.fks.filter((f) => f.name.toLowerCase() !== k);
            found = table.fks.length !== bf || found;
            const ex = table.exclusions.find((e) => e.name.toLowerCase() === k);
            if (ex) {
              table.exclusions = table.exclusions.filter((e) => e !== ex);
              table.indexes = table.indexes.filter(
                (i) => i.name.toLowerCase() !== ex.index.toLowerCase(),
              );
              found = true;
            }
            const ux = table.indexes.find((i) => i.unique && i.name.toLowerCase() === k);
            if (ux) {
              const cols = sortedUnique(indexColumnOrdinals(ux)!);
              const originalCols = cols.flatMap((column) => {
                const source = columnSources[column];
                return source?.kind === "original" ? [source.column] : [];
              });
              const hasOriginalCols = originalCols.length === cols.length;
              const localDeps = table.fks.filter(
                  (f) =>
                    f.refTable.toLowerCase() === table.name.toLowerCase() &&
                    sameSet(sortedUnique(f.refColumns), cols),
                );
              const externalDeps: ForeignKey[] = [];
              for (const [key, ot] of snap.tables)
                if (ot.name.toLowerCase() !== table.name.toLowerCase() && hasOriginalCols)
                  externalDeps.push(
                    ...ot.fks.filter(
                      (f) =>
                        f.refTable.toLowerCase() === table.name.toLowerCase() &&
                        sameSet(sortedUnique(f.refColumns), sortedUnique(originalCols)) &&
                        !cascadeDroppedColumnFks.has(
                          `${key.toLowerCase()}\0${f.name.toLowerCase()}`,
                        ) &&
                        !cascadeUniqueCols.some((prior) =>
                          sameSet(prior, sortedUnique(f.refColumns)),
                        ),
                    ),
                  );
              const deps = [...localDeps, ...externalDeps];
              if (deps.length && !action.cascade)
                throw engineError(
                  "dependent_objects_still_exist",
                  `cannot drop constraint ${action.name} because other objects depend on it`,
                );
              if (action.cascade && hasOriginalCols)
                cascadeUniqueCols.push(sortedUnique(originalCols));
              if (action.cascade)
                table.fks = table.fks.filter(
                  (f) => !localDeps.some((d) => d.name.toLowerCase() === f.name.toLowerCase()),
                );
              table.indexes = table.indexes.filter((i) => i !== ux);
              found = true;
            }
            if (!found && !action.ifExists)
              throw engineError("undefined_object", `constraint does not exist: ${action.name}`);
            added.delete(k);
            continue;
          }
          const edit = action.edit;
          const ci = columnIndex(table, edit.column);
          if (ci < 0)
            throw engineError("undefined_column", `column does not exist: ${edit.column}`);
          const col = table.columns[ci]!;
          switch (edit.action.kind) {
            case "setDefault":
              if (col.identity !== null)
                throw engineError("syntax_error", "identity column cannot have a default");
              table.columns[ci] = this.buildAlterDefault(col, edit.action.default);
              break;
            case "dropDefault":
              if (col.identity !== null)
                throw engineError("syntax_error", "identity column cannot drop its default");
              table.columns[ci] = { ...col, default: null, defaultExpr: null };
              break;
            case "setNotNull":
              table.columns[ci] = { ...col, notNull: true };
              break;
            case "dropNotNull":
              if (col.identity !== null)
                throw engineError("syntax_error", "identity column cannot drop not null");
              if (col.primaryKey)
                throw engineError("invalid_table_definition", "column is in a primary key");
              table.columns[ci] = { ...col, notNull: false };
              break;
            case "setType": {
              const oldColumn = col;
              let target = this.buildAlterAddedColumn(
                table,
                {
                  name: col.name,
                  typeName: edit.action.typeName,
                  typeMod: edit.action.typeMod,
                  primaryKey: false,
                  notNull: false,
                  default: null,
                  identity: null,
                  collation: null,
                },
                [],
                [],
                tempScope,
                attachmentScope,
              );
              if (
                oldColumn.primaryKey &&
                (target.type.kind === "composite" ||
                  (target.type.kind === "array" && !typeIsArrayKeyable(target.type)) ||
                  (target.type.kind !== "array" &&
                    target.type.kind !== "range" &&
                    !typeIsKeyableScalar(target.type)))
              )
                throw engineError(
                  "feature_not_supported",
                  `a ${typeCanonicalName(target.type)} primary key is not supported yet`,
                );
              if (col.identity !== null && !typeIsInteger(target.type))
                throw engineError(
                  "invalid_parameter_value",
                  "identity column type must be smallint, integer, or bigint",
                );
              const source: Expr = edit.action.using ?? { kind: "column", name: col.name };
              const cast: Expr = {
                kind: "cast",
                inner: source,
                typeName: edit.action.typeName,
                typeMod: edit.action.typeMod,
              };
              const resolved = resolve(
                Scope.single(this, table),
                cast,
                null,
                { collecting: false, groupKeys: [], specs: [] },
                new ParamTypes(),
              );
              if (!resolvedTypeEqual(resolved.type, resolvedTypeOfCol(target.type, this)))
                throw typeError(`USING expression is not of type ${typeCanonicalName(target.type)}`);
              target = {
                ...target,
                primaryKey: oldColumn.primaryKey,
                notNull: oldColumn.notNull,
                identity: oldColumn.identity,
              };
              if (oldColumn.default !== null) {
                const defaultCast: Expr = {
                  kind: "cast",
                  inner: { kind: "column", name: oldColumn.name },
                  typeName: edit.action.typeName,
                  typeMod: edit.action.typeMod,
                };
                const node = resolve(
                  Scope.single(this, { ...table, columns: [oldColumn], pk: [], checks: [], indexes: [], fks: [], exclusions: [] }),
                  defaultCast,
                  null,
                  { collecting: false, groupKeys: [], specs: [] },
                  new ParamTypes(),
                ).node;
                const m = this.session.newMeter();
                target = { ...target, default: evalExpr(node, [oldColumn.default], this.maintenanceEnv(new StmtRng()), m) };
                prepCost += m.accrued;
              } else if (oldColumn.defaultExpr !== null) {
                const defaultCast: Expr = {
                  kind: "cast",
                  inner: oldColumn.defaultExpr.expr,
                  typeName: edit.action.typeName,
                  typeMod: edit.action.typeMod,
                };
                resolve(Scope.empty(this), defaultCast, null, { collecting: false, groupKeys: [], specs: [] }, new ParamTypes());
                const tm = edit.action.typeMod,
                  typeSql =
                    tm === null
                      ? edit.action.typeName
                      : `${edit.action.typeName} (${tm.precision}${tm.scale === null ? "" : `, ${tm.scale}`})`;
                target = {
                  ...target,
                  defaultExpr: {
                    exprText: `CAST ( ${oldColumn.defaultExpr.exprText} AS ${typeSql} )`,
                    expr: defaultCast,
                  },
                };
              }
              if (oldColumn.identity !== null) {
                const oldScalar = typeAsScalar(oldColumn.type),
                  newScalar = typeAsScalar(target.type),
                  oldDtype =
                    oldScalar === undefined ? undefined : seqDataTypeForScalar(oldScalar),
                  newDtype =
                    newScalar === undefined ? undefined : seqDataTypeForScalar(newScalar);
                if (oldDtype === undefined || newDtype === undefined)
                  throw new Error("identity column is integer");
                const pi = pendingSerials.findIndex(
                  (seq) =>
                    seq.ownedBy !== undefined &&
                    seq.ownedBy.table.toLowerCase() === table.name.toLowerCase() &&
                    seq.ownedBy.column === ci,
                );
                if (pi >= 0)
                  pendingSerials[pi] = retypeIdentitySequence(
                    pendingSerials[pi]!,
                    oldDtype,
                    newDtype,
                  );
                else {
                  const source = columnSources[ci];
                  if (source?.kind !== "original")
                    throw new Error("added identity column has pending sequence");
                  const key = snap
                    .sequencesOwnedBy(original.name)
                    .find((name) => snap.sequence(name)?.ownedBy?.column === source.column);
                  if (key === undefined) throw new Error("identity column has owned sequence");
                  this.putSequenceRouted(
                    retypeIdentitySequence(snap.sequence(key)!, oldDtype, newDtype),
                  );
                }
              }
              table.columns[ci] = target;
              typeChangedColumns[ci] = true;
              typeChanged = true;
              rowSteps.push({ kind: "setType", column: ci, value: resolved.node });
              for (const check of table.checks) addedConstraints.add(check.name.toLowerCase());
              for (const index of table.indexes) addedConstraints.add(index.name.toLowerCase());
              for (const fk of table.fks) addedConstraints.add(fk.name.toLowerCase());
              for (const exclusion of table.exclusions)
                addedConstraints.add(exclusion.name.toLowerCase());
              break;
            }
          }
        }
        break;
      }
    }

    if (typeChanged) {
      for (const fk of table.fks) {
        const parent =
          fk.refTable.toLowerCase() === table.name.toLowerCase() ? table : snap.table(fk.refTable)!;
        fk.columns.forEach((local, i) => {
          const ref = fk.refColumns[i]!;
          if (!fkTypesEqual(table.columns[local]!.type, parent.columns[ref]!.type))
            throw typeError(
              `foreign key constraint ${fk.name} cannot be implemented: key columns ${table.columns[local]!.name} and ${parent.columns[ref]!.name} are of incompatible types: ${typeCanonicalName(table.columns[local]!.type)} and ${typeCanonicalName(parent.columns[ref]!.type)}`,
            );
        });
      }
      for (const [key, child] of snap.tables) {
        if (key.toLowerCase() === oldKey) continue;
        for (const fk of child.fks) {
          if (fk.refTable.toLowerCase() !== original.name.toLowerCase()) continue;
          if (
            cascadeDroppedColumnFks.has(`${key.toLowerCase()}\0${fk.name.toLowerCase()}`) ||
            cascadeUniqueCols.some((cols) => sameSet(cols, sortedUnique(fk.refColumns)))
          )
            continue;
          fk.columns.forEach((local, i) => {
            const oldRef = fk.refColumns[i]!,
              newRef = columnSources.findIndex(
                (source) => source.kind === "original" && source.column === oldRef,
              );
            if (newRef >= 0 && !fkTypesEqual(child.columns[local]!.type, table.columns[newRef]!.type))
              throw typeError(
                `foreign key constraint ${fk.name} cannot be implemented: key columns ${child.columns[local]!.name} and ${table.columns[newRef]!.name} are of incompatible types: ${typeCanonicalName(child.columns[local]!.type)} and ${typeCanonicalName(table.columns[newRef]!.type)}`,
              );
          });
        }
      }
    }

    const alterPageSize = attachmentScope ? this.attachPageSize(at.db!.toLowerCase()) : this.pageSize;
    const rewriteNeeded =
      columnSources.length !== original.columns.length ||
      columnSources.some(
        (source, i) => source.kind !== "original" || source.column !== i,
      );
    const pkRekeyed =
      table.pk.length !== original.pk.length ||
      table.pk.some((column, i) => {
        const source = columnSources[column];
        return source?.kind !== "original" || source.column !== original.pk[i];
      }) ||
      table.pk.some((column) => typeChangedColumns[column]);
    const tableRewriteNeeded = rewriteNeeded || rowSteps.length > 0 || pkRekeyed;
    const rewriteColTypes =
      !tableRewriteNeeded
        ? null
        : table.columns.map((c) => resolveColType(c.type, this.readSnap().types));
    const meter = this.session.newMeter();
    meter.charge(prepCost);
    meter.guard();
    let rewriteRows: Entry[] | null = null;
    let rewriteNextRowid = 0n;
    if (tableRewriteNeeded) {
      for (const seq of pendingSerials) {
        let sw: Snapshot;
        if (at.db === undefined) {
          if (tempScope) {
            this.session.tx!.tempDirty = true;
            sw = this.session.tx!.tempWorking;
          } else sw = this.working();
        } else if (at.db.toLowerCase() === "temp") {
          this.session.tx!.tempDirty = true;
          sw = this.session.tx!.tempWorking;
        } else if (at.db.toLowerCase() === "main") sw = this.working();
        else sw = this.attachWriteSnap(at.db.toLowerCase())!;
        sw.putSequence(seq);
      }
      const store = this.lkpStoreScoped(at.db, original.name);
      const scan = store.scanWithUnits(original.columns.map(() => true));
      rewriteNextRowid = store.nextSyntheticRowid();
      if (pkRekeyed && table.pk.length === 0) rewriteNextRowid = 0n;
      meter.charge(COSTS.pageRead * BigInt(scan.pages) + COSTS.valueDecompress * BigInt(scan.slabs));
      const rng = new StmtRng();
      const env = this.maintenanceEnv(rng);
      const colls = this.columnCollations(table.columns);
      const seenKeys = new Set<string>();
      let compressUnits = 0n;
      rewriteRows = scan.entries.map((entry) => {
        meter.guard();
        meter.charge(COSTS.storageRowRead);
        const row = [...store.resolveAll(entry.row)];
        for (const step of rowSteps) {
          if (step.kind === "add")
            row.push(this.evalDefault(step.column, step.defaultExpr, rng, meter));
          else if (step.kind === "drop") row.splice(step.column, 1);
          else row[step.column] = evalExpr(step.value, row, env, meter);
        }
        row.forEach((value, i) => {
          if (table.columns[i]!.notNull && value.kind === "null")
            throw notNullViolation(table.columns[i]!.name);
        });
        const key = pkRekeyed
          ? table.pk.length === 0
            ? encodeInt("i64", rewriteNextRowid++)
            : encodePkKey(table, table.pk, colls, row)
          : entry.key;
        if (pkRekeyed) {
          const hash = Array.from(key).join(",");
          if (seenKeys.has(hash)) throw uniqueViolation(table.name, pkeyName(table.name));
          seenKeys.add(hash);
        }
        compressUnits += BigInt(
          recordCompressUnits(rewriteColTypes!, key, row, pagePayload(alterPageSize)),
        );
        return { key, row };
      });
      meter.charge(COSTS.valueCompress * compressUnits);
      meter.guard();
    }
    const mask = original.columns.map(() => false);
    const notNullNames = original.columns.map(() => "");
    for (let i = 0; i < columnSources.length; i++) {
      const source = columnSources[i]!;
      if (
        source.kind === "original" &&
        !original.columns[source.column]!.notNull &&
        table.columns[i]!.notNull
      ) {
        mask[source.column] = true;
        notNullNames[source.column] = table.columns[i]!.name;
      }
    }
    if (mask.some(Boolean)) {
      const store = this.lkpStoreScoped(at.db, original.name);
      const { entries, pages, slabs } = store.scanWithUnits(mask);
      meter.charge(COSTS.pageRead * BigInt(pages) + COSTS.valueDecompress * BigInt(slabs));
      for (const entry of entries) {
        meter.guard();
        meter.charge(COSTS.storageRowRead);
        const row = store.resolveInlineColumns(entry.row);
        for (let i = 0; i < mask.length; i++)
          if (mask[i] && row[i]!.kind === "null") throw notNullViolation(notNullNames[i]!);
      }
    }
    const constraintEntries = new Map<string, Uint8Array[]>();
    if (addedConstraints.size > 0) {
      // Presence in this map is also the publication-time identity marker for a newly-added backing
      // index. Seed empty indexes so DROP+ADD name reuse cannot retain the old store.
      for (const index of table.indexes)
        if (addedConstraints.has(index.name.toLowerCase()))
          constraintEntries.set(index.name.toLowerCase(), []);
      const store = this.lkpStoreScoped(at.db, original.name),
        all =
          rewriteRows === null
            ? store.scanWithUnits(table.columns.map(() => true))
            : { entries: rewriteRows, pages: 0, slabs: 0 };
      if (rewriteRows === null)
        meter.charge(COSTS.pageRead * BigInt(all.pages) + COSTS.valueDecompress * BigInt(all.slabs));
      const checks = this.resolveChecks(table),
        colls = this.columnCollations(table.columns),
        seen = new Map<string, Set<string>>();
      for (const entry of all.entries) {
        meter.guard();
        if (rewriteRows === null) meter.charge(COSTS.storageRowRead);
        const row = store.resolveInlineColumns(entry.row);
        for (const ck of checks)
          if (addedConstraints.has(ck.name.toLowerCase()))
            evalChecks([ck], table.name, row, this.maintenanceEnv(new StmtRng()), meter);
        for (const ix of table.indexes) {
          const k = ix.name.toLowerCase();
          if (!addedConstraints.has(k)) continue;
          const ri = this.resolveIndex(table, ix);
          if (ix.unique) {
            const p = this.indexPrefix(table.columns, colls, ri, row);
            if (p) {
              let s = seen.get(k);
              if (!s) {
                s = new Set();
                seen.set(k, s);
              }
              const h = Array.from(p).join(",");
              if (s.has(h)) throw uniqueViolation(table.name, ix.name);
              s.add(h);
            }
          }
          const es = constraintEntries.get(k) ?? [];
          es.push(...this.indexEntries(table.columns, colls, ri, entry.key, row));
          constraintEntries.set(k, es);
        }
      }
      for (const fk of table.fks)
        if (addedConstraints.has(fk.name.toLowerCase())) {
          const parent =
            fk.refTable.toLowerCase() === table.name.toLowerCase()
              ? table
              : snap.table(fk.refTable)!;
          const pc = this.columnCollations(parent.columns);
          for (const entry of all.entries) {
            const row = store.resolveInlineColumns(entry.row),
              p = fkProbe(fk, parent, pc, row, fk.columns);
            if (p !== null) {
              let hit: boolean;
              if (parent === table) {
                hit = all.entries.some((candidate) => {
                  meter.charge(COSTS.constraintCheck);
                  meter.guard();
                  const pp = fkProbe(
                    fk,
                    parent,
                    pc,
                    store.resolveInlineColumns(candidate.row),
                    fk.refColumns,
                  );
                  return pp !== null && compareBytes(fkProbeBytes(p), fkProbeBytes(pp)) === 0;
                });
              } else hit = this.fkProbeHits(p, parent.name);
              if (!hit) throw fkViolationInsert(table.name, fk.name);
            }
          }
        }
      for (const ex of table.exclusions)
        if (addedConstraints.has(ex.name.toLowerCase()))
          for (let i = 0; i < all.entries.length; i++)
            for (let j = 0; j < i; j++) {
              meter.charge(COSTS.constraintCheck);
              meter.guard();
              if (
                exclusionPairConflicts(
                  table.columns,
                  ex,
                  store.resolveInlineColumns(all.entries[i]!.row),
                  store.resolveInlineColumns(all.entries[j]!.row),
                )
              )
                throw exclusionViolation(table.name, ex.name);
            }
      for (const es of constraintEntries.values()) es.sort(compareBytes);
    }
    const rekeyed = rewriteRows !== null && pkRekeyed;
    if (rekeyed) {
      constraintEntries.clear();
      const colls = this.columnCollations(table.columns);
      for (const index of table.indexes) {
        const resolved = this.resolveIndex(table, index);
        const entries: Uint8Array[] = [];
        for (const row of rewriteRows!)
          entries.push(
            ...this.indexEntries(table.columns, colls, resolved, row.key, row.row),
          );
        entries.sort(compareBytes);
        constraintEntries.set(index.name.toLowerCase(), entries);
      }
    }
    let ws: Snapshot;
    if (at.db === undefined) {
      if (this.isTempTable(original.name)) {
        this.session.tx!.tempDirty = true;
        ws = this.session.tx!.tempWorking;
      } else ws = this.working();
    } else
      switch (at.db.toLowerCase()) {
        case "temp":
          this.session.tx!.tempDirty = true;
          ws = this.session.tx!.tempWorking;
          break;
        case "main":
          ws = this.working();
          break;
        default:
          ws = this.attachWriteSnap(at.db.toLowerCase())!;
      }
    if (rewriteRows !== null) {
      ws.alterTableRewrite(table, rewriteColTypes!, rewriteRows, rewriteNextRowid, alterPageSize);
    } else ws.alterTableCatalog(oldKey, table, renameTable, indexRename);
    if (rekeyed)
      ws.rebuildAlterIndexes(original, table, constraintEntries, alterPageSize);
    else ws.syncAlterConstraintIndexes(original, table, constraintEntries, alterPageSize);
    for (const cols of cascadeUniqueCols) {
      for (const [key, child] of [...ws.tables]) {
        if (child.name.toLowerCase() === table.name.toLowerCase()) continue;
        const fks = child.fks.filter(
          (fk) =>
            fk.refTable.toLowerCase() !== table.name.toLowerCase() ||
            !sameSet(sortedUnique(fk.refColumns), cols),
        );
        if (fks.length !== child.fks.length) ws.tables.set(key, { ...child, fks });
      }
    }
    if (rewriteNeeded) {
      const originalToNew = original.columns.map(() => -1);
      columnSources.forEach((source, next) => {
        if (source.kind === "original") originalToNew[source.column] = next;
      });
      ws.remapAlterColumnDependents(
        table.name,
        originalToNew,
        new Set(pendingSerials.map((seq) => seq.name.toLowerCase())),
      );
    }
    return { kind: "statement", cost: meter.accrued, rowsAffected: null };
  }

  private buildAlterDefault(col: Column, def: DefaultDef): Column {
    const sty = typeAsScalar(col.type);
    if (sty === undefined)
      throw engineError(
        "feature_not_supported",
        "a DEFAULT on this container type is not supported yet",
      );
    const clockDefault =
      sty === "date" &&
      def.expr.kind === "literal" &&
      def.expr.literal.kind === "text" &&
      dateClockIsRelative(def.expr.literal.text);
    if (def.expr.kind === "literal" && !clockDefault) {
      return {
        ...col,
        default: storeValue(
          literalToValue(def.expr.literal),
          sty,
          col.decimal,
          col.varcharLen,
          false,
          col.name,
        ),
        defaultExpr: null,
      };
    }
    rejectDefaultStructure(def.expr);
    const { type: rt } = resolve(
      Scope.empty(this),
      def.expr,
      sty,
      { collecting: false, groupKeys: [], specs: [] },
      new ParamTypes(),
    );
    if (!assignableTo(rt, sty))
      throw typeError(
        `column ${col.name} is of type ${canonicalName(sty)} but default expression is of type ${rtName(rt)}`,
      );
    return { ...col, default: null, defaultExpr: { exprText: def.text, expr: def.expr } };
  }

  private buildAlterAddedColumn(
    table: Table,
    def: ColumnDef,
    pending: SequenceDef[],
    reservedRelationNames: string[],
    tempScope: boolean,
    attachmentScope: boolean,
  ): Column {
    const serialKind = serialPseudoType(def.typeName);
    let type: Type;
    let decimal: DecimalTypmod | null = null;
    let varcharLen: number | null = null;
    if (serialKind !== undefined) {
      if (def.typeMod !== null)
        throw engineError(
          "syntax_error",
          `type modifier is not allowed for type ${def.typeName}`,
        );
      type = scalarT(serialKind);
    } else if (def.typeName.endsWith("[]")) {
      if (def.typeMod !== null)
        throw engineError(
          "feature_not_supported",
          "a type modifier on an array type is not supported yet",
        );
      const base = def.typeName.slice(0, -2);
      const scalar = scalarTypeFromName(base),
        composite = this.compositeType(base);
      if (scalar !== undefined) type = arrayT(scalarT(scalar));
      else if (composite !== undefined) type = arrayT(compositeT(composite.name));
      else throw engineError("undefined_object", `type does not exist: ${base}`);
    } else if (rangeByName(def.typeName) !== undefined) {
      if (def.typeMod !== null)
        throw engineError(
          "feature_not_supported",
          "a type modifier on a range type is not supported",
        );
      type = rangeT(scalarT(elementScalar(rangeByName(def.typeName)!)));
    } else if (scalarTypeFromName(def.typeName) !== undefined) {
      const [scalar, d, vl] = resolveTypeAndTypmod(def.typeName, def.typeMod);
      if (scalar === "jsonpath")
        throw engineError("feature_not_supported", "a jsonpath column is not supported yet");
      type = scalarT(scalar);
      decimal = d;
      varcharLen = vl;
    } else {
      const composite = this.compositeType(def.typeName);
      if (composite === undefined)
        throw engineError("undefined_object", `type does not exist: ${def.typeName}`);
      if (def.typeMod !== null)
        throw engineError(
          "feature_not_supported",
          `a type modifier is not supported for composite type ${def.typeName}`,
        );
      type = compositeT(composite.name);
    }

    let collation: string | null = null;
    if (def.collation !== null) {
      if (!typeIsText(type))
        throw typeError(`collations are not supported by type ${typeCanonicalName(type)}`);
      resolveCollationName(this, def.collation);
      if (def.collation !== "C") collation = def.collation;
    } else if (typeIsText(type)) collation = this.readSnap().defaultCollation;
    if (tempScope && collation !== null)
      throw engineError(
        "feature_not_supported",
        "COLLATE on a temporary-table column is not yet supported",
      );
    if (attachmentScope && (type.kind === "composite" || collation !== null))
      throw engineError(
        "feature_not_supported",
        "this column type or collation is not supported on an attached-database table",
      );

    let col: Column = {
      name: def.name,
      type,
      decimal,
      varcharLen,
      primaryKey: def.primaryKey,
      notNull:
        def.primaryKey ||
        def.notNull ||
        serialKind !== undefined ||
        def.identity !== null,
      default: null,
      defaultExpr: null,
      identity: null,
      collation,
    };
    if (def.primaryKey) {
      if (table.pk.length > 0)
        throw engineError(
          "invalid_table_definition",
          `multiple primary keys for table ${table.name} are not allowed`,
        );
      if (
        !typeIsInteger(type) &&
        !typeIsBoolean(type) &&
        !typeIsText(type) &&
        !typeIsBytea(type) &&
        !typeIsDecimal(type) &&
        !typeIsUuid(type) &&
        !typeIsTimestamp(type) &&
        !typeIsTimestamptz(type) &&
        !typeIsDate(type) &&
        !typeIsInterval(type) &&
        !typeIsFloat(type) &&
        !typeIsRange(type) &&
        !typeIsArrayKeyable(type)
      )
        throw engineError(
          "feature_not_supported",
          `a ${typeCanonicalName(type)} primary key is not supported yet`,
        );
    }
    if (serialKind !== undefined || def.identity !== null) {
      if (attachmentScope)
        throw engineError(
          "feature_not_supported",
          "a serial / IDENTITY column on an attached-database table is not supported yet",
        );
      if (def.identity !== null && !typeIsInteger(type))
        throw engineError(
          "invalid_parameter_value",
          "identity column type must be smallint, integer, or bigint",
        );
      if (def.identity !== null && (def.default !== null || serialKind !== undefined))
        throw engineError(
          "syntax_error",
          `both default and identity specified for column ${def.name} of table ${table.name}`,
        );
      if (serialKind !== undefined && def.default !== null)
        throw engineError(
          "syntax_error",
          `multiple default values specified for column ${def.name} of table ${table.name}`,
        );
      const seqName = this.chooseSerialSeqName(
        table.name,
        def.name,
        pending,
        reservedRelationNames,
      );
      const opts = { ...(def.identity?.options ?? emptySeqOptions()) };
      if (opts.dataType !== null)
        throw engineError("syntax_error", "conflicting or redundant options");
      const scalar = serialKind ?? (type.kind === "scalar" ? type.scalar : undefined);
      const dtype = scalar === undefined ? undefined : seqDataTypeForScalar(scalar);
      if (dtype === undefined) throw new Error("serial/identity integer");
      opts.dataType = dtype;
      pending.push(
        buildSequenceDef(seqName, opts, { table: table.name, column: table.columns.length }),
      );
      const exprText = `nextval ( '${seqName.replace(/'/g, "''")}' )`;
      col = {
        ...col,
        defaultExpr: { exprText, expr: parseExpression(exprText) },
        identity:
          def.identity === null ? null : def.identity.always ? "always" : "byDefault",
      };
    } else if (type.kind === "composite" || type.kind === "array" || type.kind === "range") {
      if (def.default !== null)
        throw engineError(
          "feature_not_supported",
          "a DEFAULT on a composite-, array-, or range-typed column is not supported yet",
        );
    } else if (def.default !== null) col = this.buildAlterDefault(col, def.default);
    return col;
  }

  // findIndex finds the table owning the named index in the visible snapshot
  // (case-insensitive).
  private findIndex(name: string): [string, IndexDef] | null {
    return this.readSnap().findIndex(name);
  }

  // relationExists reports whether name is taken in the shared relation namespace (a
  // table OR an index OR a sequence — spec/design/indexes.md §2, sequences.md §2),
  // case-insensitively.
  private relationExists(name: string): boolean {
    // Session-local temp tables + their (UNIQUE) index names join the namespace too, so a name
    // colliding with any temp relation is also 42P07 (preclude-overlaps — spec/design/temp-tables.md
    // §3). this.table is persistent-only, so the temp snapshot is checked explicitly.
    return (
      this.table(name) !== undefined ||
      this.tempSnap().table(name) !== undefined ||
      this.findIndex(name) !== null ||
      this.tempSnap().findIndex(name) !== null ||
      // The sequence funnel walks session-local → persistent, so an owned TEMP sequence's name joins
      // the namespace (temp-tables.md §8) — a collision with it is 42P07 too.
      this.sequence(name) !== undefined
    );
  }

  // fkProbeHits reports whether the parent currently holds the key/prefix `probe` (committed +
  // working state) — the child-side foreign-key existence test (spec/design/constraints.md §6.4).
  // `parentTable` is the referenced table's name. Unmetered, like the PK/UNIQUE probes (cost.md §3).
  private fkProbeHits(probe: FkProbe, parentTable: string): boolean {
    if (probe.kind === "pk") {
      return this.lkpStore(parentTable).get(probe.bytes) !== undefined;
    }
    return (
      this.readSnap().indexStore(probe.index).rangeEntries(uniqueProbeBound(probe.prefix)).length >
      0
    );
  }

  // fkChildReferences reports whether any row of `childTable` references the parent tuple `target`
  // (the parent key bytes, in the byte space fkProbe produces) via `fk` — the reverse of the
  // child-side probe, a full scan since child FK columns are not index-backed
  // (spec/design/constraints.md §6.5). MATCH SIMPLE: a child row with any NULL FK column references
  // nothing. Rows whose storage key is in `exclude` are skipped — the END STATE for a
  // self-reference, whose child IS the table being mutated (so its deleted/updated rows must not
  // count). `parent` is the referenced table's catalog. Unmetered validation.
  private fkChildReferences(
    childTable: string,
    fk: ForeignKey,
    parent: Table,
    target: Uint8Array,
    exclude: Set<string>,
  ): boolean {
    // target is in the parent's stored-key byte space, so the child probe encodes a collated parent
    // key column with the PARENT's collation (§2.12).
    const parentColls = this.columnCollations(parent.columns);
    for (const e of this.lkpStore(childTable).entriesInKeyOrder()) {
      if (exclude.has(e.key.join(","))) continue;
      const probe = fkProbe(fk, parent, parentColls, e.row, fk.columns);
      if (probe !== null && bytesEq(fkProbeBytes(probe), target)) return true;
    }
    return false;
  }

  // fkReferencers returns every (child table name, FK) pair in the visible snapshot whose FK
  // references `parentName` (case-insensitive), including a self-reference — the inbound FKs a
  // parent DELETE/UPDATE must not strand (spec/design/constraints.md §6.5). Sorted by (lowercased
  // child table, FK name) for a deterministic report order. The FK objects are the snapshot's
  // (the caller probes stores without mutating the catalog).
  private fkReferencers(parentName: string): { childTable: string; fk: ForeignKey }[] {
    const snap = this.readSnap();
    const key = parentName.toLowerCase();
    const out: { childTable: string; fk: ForeignKey }[] = [];
    const tkeys = [...snap.tables.keys()].sort();
    for (const tk of tkeys) {
      const t = snap.tables.get(tk)!;
      for (const fk of t.fks) {
        if (fk.refTable.toLowerCase() === key) out.push({ childTable: t.name, fk });
      }
    }
    return out;
  }

  // executeCreateIndex analyzes and runs a CREATE INDEX (spec/design/indexes.md §2).
  // Validation mirrors PostgreSQL's order (oracle-probed): the table must exist (42P01);
  // each key column, in list order, must exist (42703) and be of a key-encodable type
  // (0A000 — the same narrowing as a PRIMARY KEY member); then an explicit name is
  // checked against the shared relation namespace (42P07), or an omitted name derives
  // PG's choice — the lowercased <table>_<col>..._idx with the smallest free suffix. The
  // index is then built by scanning the table once: page_read per node + storage_row_read
  // per row (the metered build scan — cost.md §3); maintenance thereafter is unmetered.
  private executeCreateIndex(ci: CreateIndex): Outcome {
    // A standalone CREATE INDEX targets whichever scope owns the table — session-local temp, persistent,
    // or a host-attached database (spec/design/temp-tables.md §8, attached-databases.md §3). The build
    // below is scope-agnostic (the scoped lkpTable/lkpStore/writeIndexStore funnels route by the
    // qualifier + resolution walk; the cost meter, UNIQUE validation, naming/namespace collision, and the
    // storage budget are all generic); only the catalog putIndex write must target the owning snapshot,
    // so the routing happens there.
    // A built-in catalog relation cannot be indexed (introspection.md §5): 42809, checked by NAME
    // before qualifier validation, like the DML targets.
    checkCatalogRelWrite(ci.table);
    // A DDL write to a READ-ONLY host attachment is 25006 before any work — checked BEFORE the qualifier
    // existence gate so a read-only attachment refuses the write deterministically (attached-databases.md §4).
    this.checkAttachmentWritable(ci.db);
    this.checkTableQualifier(ci.db, ci.table); // attached-databases.md §3
    const attachName = isAttachmentScope(ci.db) ? ci.db!.toLowerCase() : "";
    const table = this.lkpTableScoped(ci.db, ci.table);
    if (!table) {
      throw engineError("undefined_table", "table does not exist: " + ci.table);
    }
    const tableKey = table.name.toLowerCase();
    const columns = table.columns;
    // Refuse building a collated index on a version-skewed table (slice 2d, collation.md §12, XX002):
    // the new B-tree would be pinned inconsistently with the file's other structures.
    this.ensureCollationsWritable(columns);
    // Per-column frozen collations for the collated text key form (§2.12); null everywhere for a
    // C-only / non-text table (the fast path).
    const colls = this.columnCollations(columns);
    // Resolve the access method (spec/design/gin.md §3): undefined / "btree" is the ordered
    // B-tree, "gin" a GIN inverted index; an unknown method is 42704. Resolved here (not in the
    // parser) so the error is the resolve-time undefined_object, after the table-exists check.
    const method = (ci.using ?? "btree").toLowerCase();
    let kind: "btree" | "gin" | "gist";
    if (method === "btree") kind = "btree";
    else if (method === "gin") kind = "gin";
    else if (method === "gist") kind = "gist";
    else throw engineError("undefined_object", "access method does not exist: " + ci.using);
    const ciKeys: IndexKey[] = [];
    for (const elem of ci.keys) {
      // An EXPRESSION key element (spec/design/indexes.md §1/§2): resolve it against the table's
      // columns, validate it is immutable + indexable-typed, and store its canonical text (persisted,
      // format_version 26). Expression keys are B-tree only this slice — GIN/GiST take a single plain
      // column.
      if (elem.kind === "expr") {
        if (kind !== "btree") {
          throw engineError(
            "feature_not_supported",
            `an expression key on a ${ci.using ?? ""} index is not supported yet`,
          );
        }
        // A subquery is not a deterministic function of the row — 0A000 (the resolver admits an
        // uncorrelated one, so it is rejected here, before resolution).
        if (indexExprHasSubquery(elem.expr)) {
          throw engineError("feature_not_supported", "cannot use subquery in index expression");
        }
        // Resolve against the table (an aggregate 42803 / window 42P20 / bind parameter 42P02 fall
        // out of the resolver, as for a CHECK).
        const scope = Scope.single(this, table);
        const pt = new ParamTypes();
        const { type: rtype } = resolve(
          scope,
          elem.expr,
          null,
          { collecting: false, groupKeys: [], specs: [] },
          pt,
        );
        // Immutability (§2): a non-immutable seam/sequence/current_setting call, a
        // session-timezone-dependent expression (one that reads or produces a timestamptz —
        // conservatively fail-closed), or a resolved STABLE node (the runtime text→date cast,
        // flagged at its birth — ParamTypes.nonimmutable), is 42P17.
        const refs = checkReferencedColumns(elem.expr, columns);
        const tzHazard =
          rtype.kind === "timestamptz" || refs.some((i) => typeIsTimestamptz(columns[i]!.type));
        if (indexExprNonimmutableCall(elem.expr) || tzHazard || pt.nonimmutable) {
          throw engineError(
            "invalid_object_definition",
            "functions in index expression must be marked IMMUTABLE",
          );
        }
        // The result type must be key-encodable (a composite result is 0A000).
        if (resolvedToKeyType(rtype) === null) {
          throw engineError(
            "feature_not_supported",
            "an index on an expression of this result type is not supported yet",
          );
        }
        ciKeys.push({ kind: "expr", exprText: elem.text, expr: elem.expr });
        continue;
      }
      const name = elem.name;
      const idx = columnIndex(table, name);
      if (idx < 0) {
        throw engineError("undefined_column", "column does not exist: " + name);
      }
      const ty = columns[idx]!.type;
      if (kind === "gin") {
        // GIN needs an operator class for the column type: only an array has one (else 42704),
        // and only a FIXED-WIDTH KEY-ENCODABLE element type (else 0A000) — the GIN term IS that
        // element's key encoding (gin.md §3/§4), so the admitted set is the integers, boolean, uuid,
        // date, timestamp, timestamptz (interval's GIN-element support is a separate follow-on — its
        // key landed but the GIN slice has not; gin.md §3/§10).
        if (ty.kind !== "array") {
          throw engineError(
            "undefined_object",
            "data type " +
              typeCanonicalName(ty) +
              " has no default operator class for access method gin",
          );
        }
        if (!isGinElementType(ty.elem)) {
          throw engineError(
            "feature_not_supported",
            "a gin index on " + typeCanonicalName(ty) + " is not supported yet",
          );
        }
      } else if (kind === "gist") {
        // GiST opclasses (gist.md §5/§6): range_ops over a range column, or the in-core
        // btree_gist-equivalent scalar `=` opclass over a FIXED-WIDTH keyable scalar (integers /
        // boolean / uuid / date / timestamp / timestamptz — its bound is [min,max] over that type's
        // order-preserving key encoding, all pure byte comparison). A keyable-but-deferred scalar
        // (text / bytea / decimal / interval) is 0A000 — we will support it (the GIN element-staging
        // precedent, §11); any other type has no GiST opclass at all — 42704 (PG's wording).
        if (!typeIsRange(ty)) {
          if (isGistScalarType(ty)) {
            // supported scalar `=` opclass — ok
          } else if (isGistDeferredScalarType(ty)) {
            throw engineError(
              "feature_not_supported",
              "a gist index on " + typeCanonicalName(ty) + " is not supported yet",
            );
          } else {
            throw engineError(
              "undefined_object",
              "data type " +
                typeCanonicalName(ty) +
                " has no default operator class for access method gist",
            );
          }
        }
      } else if (
        !typeIsInteger(ty) &&
        !typeIsBoolean(ty) &&
        !typeIsText(ty) &&
        !typeIsBytea(ty) &&
        !typeIsDecimal(ty) &&
        !typeIsUuid(ty) &&
        !typeIsTimestamp(ty) &&
        !typeIsTimestamptz(ty) &&
        !typeIsDate(ty) &&
        !typeIsInterval(ty) &&
        !typeIsFloat(ty) &&
        !typeIsRange(ty) &&
        !typeIsArrayKeyable(ty)
      ) {
        throw engineError(
          "feature_not_supported",
          "a " + typeCanonicalName(ty) + " index column is not supported yet",
        );
      }
      // A duplicate column in the list is ALLOWED (PostgreSQL allows it — indexes.md §1).
      ciKeys.push({ kind: "column", column: idx });
    }
    // GIN narrowings this slice (spec/design/gin.md §3): no uniqueness (undefined for an inverted
    // index) and a single column only — both deferred 0A000.
    if (kind === "gin") {
      if (ci.unique) {
        throw engineError(
          "feature_not_supported",
          "access method gin does not support unique indexes",
        );
      }
      if (ciKeys.length !== 1) {
        throw engineError("feature_not_supported", "a multi-column gin index is not supported yet");
      }
    }
    // GiST narrowings (gist.md §1/§5/§11): no uniqueness (express it as EXCLUDE … WITH =, GX3) and a
    // single column only (multi-column GiST is GX2/GX3). A GiST index on a TEMP table is 0A000 (its
    // resident R-tree would live on the temp snapshot — deferred). File persistence landed in GX1b.
    if (kind === "gist") {
      if (ci.unique) {
        throw engineError(
          "feature_not_supported",
          "access method gist does not support unique indexes",
        );
      }
      if (ciKeys.length !== 1) {
        throw engineError(
          "feature_not_supported",
          "a multi-column gist index is not supported yet",
        );
      }
      if (this.isTempTable(ci.table)) {
        throw engineError(
          "feature_not_supported",
          "a gist index on a temporary table is not supported yet",
        );
      }
    }
    // A non-btree (GIN / GiST) index on an attached-database table is a deferred narrowing this slice
    // (attached-databases.md §8) — the attachment stores only btree PK / UNIQUE / secondary indexes.
    if (attachName !== "" && kind !== "btree") {
      throw engineError(
        "feature_not_supported",
        `a ${ci.using} index on an attached-database table is not supported yet`,
      );
    }
    // The optional `WHERE predicate` making the index PARTIAL (spec/design/indexes.md §9): a boolean
    // expression over the table's own columns, validated with PG-agreeing codes. B-tree only this slice.
    // Validated after the key elements and stored as canonical text (format_version 27).
    let predicate: { exprText: string; expr: Expr } | undefined;
    if (ci.predicate) {
      if (kind !== "btree") {
        throw engineError(
          "feature_not_supported",
          `a partial (WHERE) ${ci.using} index is not supported yet`,
        );
      }
      // Structural pre-walk: a subquery is 0A000 and a bind parameter 42P02 (both admitted by the
      // resolver). The aggregate 42803 / window 42P20 / non-boolean 42804 rejections then fall out of
      // the Forbidden-context boolean resolve below.
      rejectIndexPredicateStructure(ci.predicate.expr);
      const predPt = new ParamTypes();
      resolveBooleanFilter(Scope.single(this, table), ci.predicate.expr, predPt);
      // Immutability (§9), the same rule an expression key carries: a non-immutable seam/clock/sequence
      // call, a timestamptz-dependent subexpression (references a timestamptz column — conservatively
      // fail-closed), or a resolved STABLE node (the runtime text→date cast, ParamTypes.nonimmutable),
      // is 42P17.
      let tzHazard = false;
      for (const ref of checkReferencedColumns(ci.predicate.expr, columns)) {
        const sc = typeAsScalar(columns[ref]!.type);
        if (sc === "timestamptz") {
          tzHazard = true;
          break;
        }
      }
      if (indexExprNonimmutableCall(ci.predicate.expr) || tzHazard || predPt.nonimmutable) {
        throw engineError(
          "invalid_object_definition",
          "functions in index predicate must be marked IMMUTABLE",
        );
      }
      predicate = { exprText: ci.predicate.text, expr: ci.predicate.expr };
    }
    // relationTaken checks the namespace of the target scope: an attachment's OWN snapshot for an
    // attached table (each attached database is an independent namespace, §3), else the temp-aware
    // implicit namespace.
    const relationTaken = (n: string): boolean => {
      if (attachName !== "") {
        const as = this.attachReadSnap(attachName)!;
        return as.table(n) !== undefined || as.findIndex(n) !== null;
      }
      return this.relationExists(n);
    };
    let name: string;
    if (ci.name !== null) {
      checkReservedName("index", ci.name);
      if (relationTaken(ci.name)) {
        throw engineError("duplicate_table", "relation already exists: " + ci.name);
      }
      name = ci.name;
    } else {
      // PG's ChooseIndexName / ChooseIndexColumnNames (probed): lowercased table + one name part per
      // key element (list order, duplicates included) + "idx", then the smallest free suffix. A
      // column key's part is the column name; a bare-function-call expression's is the function name
      // (`lower(email)` → `lower`); any other expression's is the literal `expr` (indexes.md §2).
      let base = tableKey;
      for (const elem of ci.keys) base += "_" + indexNamePart(elem);
      base += "_idx";
      name = base;
      for (let suffix = 1; relationTaken(name); suffix++) name = base + suffix.toString();
    }

    // The build scan (cost.md §3): page_read per table-tree node + storage_row_read per row. The
    // touched set is the columns the key elements read — an index column for a column key, or every
    // column an expression key references (which may be variable-width, so a spilled value adds its
    // value_decompress slabs — indexes.md §5). An empty table charges 0. Entries are computed here
    // against the pre-index store; the writes below are unmetered. An expression key evaluating with
    // an error aborts the build (nothing is registered — indexes.md §4), preserving all-or-nothing.
    const meter = this.session.newMeter();
    const mask = columns.map(() => false);
    for (const k of ciKeys) {
      if (k.kind === "column") mask[k.column] = true;
      else for (const c of checkReferencedColumns(k.expr, columns)) mask[c] = true;
    }
    // A partial index's predicate is evaluated per row during the build (indexes.md §9), so the columns
    // it references join the touched set — keeping the build cost deterministic + cross-core identical.
    if (predicate) for (const c of checkReferencedColumns(predicate.expr, columns)) mask[c] = true;
    const def: IndexDef = { name, keys: ciKeys, unique: ci.unique, kind, predicate };
    // Resolve the index once (column ordinals + resolved expression keys); an env for any expression
    // key (a fresh statement rng — index expressions are immutable, so it is never read).
    const rindex = this.resolveIndex(table, def);
    const env = this.maintenanceEnv(new StmtRng());
    const store = this.lkpStoreScoped(ci.db, ci.table);
    const { entries: stored, pages: nodes, slabs } = store.scanWithUnits(mask);
    meter.charge(COSTS.pageRead * BigInt(nodes) + COSTS.valueDecompress * BigInt(slabs));
    const entries: Uint8Array[] = [];
    // A UNIQUE build verifies the existing rows before the index is registered
    // (indexes.md §8): two rows sharing a fully-non-NULL key tuple — i.e. an exempt-free
    // prefix — trap 23505 and create nothing. Unmetered validation (cost.md §3).
    const seenPrefixes = new Set<string>();
    for (const e of stored) {
      meter.guard(); // enforce the cost ceiling per scanned row (CLAUDE.md §13)
      meter.charge(COSTS.storageRowRead);
      // Resolve a faulted row's touched columns before encoding (an expression key may read a spilled
      // value; the evaluator's Unfetched backstop also handles it).
      const row = store.resolveInlineColumns(e.row);
      if (def.unique) {
        const prefix = indexPrefixKey(columns, colls, rindex, row, env);
        if (prefix !== null) {
          const k = prefix.join(",");
          if (seenPrefixes.has(k)) {
            throw uniqueViolation(ci.table, def.name);
          }
          seenPrefixes.add(k);
        }
      }
      entries.push(...indexEntryKeys(columns, colls, rindex, e.key, row, env));
    }
    meter.guard();

    const nameKey = def.name.toLowerCase();
    // Register the index catalog entry + its (empty) store in the snapshot that owns the table (the
    // resolution walk — temp-tables.md §2/§8): a session-local temp table's index lives in the session
    // temp snapshot, so the index makes ZERO file writes (the dirty bit lets the commit skip the main
    // image). The entry writes below then route through writeIndexStore, which finds the new store in
    // that same temp snapshot.
    if (attachName !== "") {
      // The attachment's index catalog entry + (empty) store live in its working snapshot, published
      // into the attached roots at commit (attached-databases.md §5/§6). attachWriteSnap marks it dirty.
      const ws = this.attachWriteSnap(attachName)!;
      ws.storePaging = this.core!.attachments.get(attachName)!.storage.paging;
      ws.putIndex(tableKey, def, this.attachPageSize(attachName)); // the attachment's own page space (§2)
    } else if (this.isTempTable(ci.table)) {
      this.session.tx!.tempDirty = true;
      this.session.tx!.tempWorking.putIndex(tableKey, def, this.pageSize);
    } else {
      this.working().putIndex(tableKey, def, this.pageSize);
    }
    const istore = this.writeIndexStoreScoped(ci.db, nameKey);
    // Insert sorted by entry key (indexes.md §1): every insert is then a right-edge append,
    // so the built tree packs ~full instead of splintering under the storage-key order the
    // scan produced (random in entry-key space). Part of the byte contract — the sort fixes
    // the built tree's shape across cores.
    entries.sort(compareBytes);
    for (const ek of entries) {
      if (!istore.insert(ek, [])) {
        throw new Error("index entry keys are unique (storage-key suffix)");
      }
    }
    return { kind: "statement", cost: meter.accrued, rowsAffected: null };
  }

  // executeDropIndex runs a DROP INDEX (spec/design/indexes.md §2): a table's name is
  // 42809, a missing one 42704. A pure catalog edit — zero cost, like DROP TABLE. The index is
  // resolved along the resolution walk (session-local → persistent — temp-tables.md §8) and removed
  // from the snapshot that owns it, so dropping a temp table's index makes zero file writes.
  private executeDropIndex(di: DropIndex): Outcome {
    // lkpTable covers both scopes, so DROP INDEX naming a table is 42809 regardless of kind.
    if (this.lkpTable(di.name)) {
      throw engineError("wrong_object_type", di.name + " is not an index");
    }
    const nameKey = di.name.toLowerCase();
    if (this.isTempIndex(di.name)) {
      const tableKey = this.tempSnap().findIndex(di.name)![0];
      this.session.tx!.tempDirty = true;
      this.session.tx!.tempWorking.removeIndex(tableKey, nameKey);
    } else {
      const found = this.findIndex(di.name);
      if (!found) {
        throw engineError("undefined_object", "index does not exist: " + di.name);
      }
      // An index that backs an EXCLUDE constraint cannot be dropped directly — the constraint owns it
      // (the UNIQUE-backing precedent; jed has no ALTER TABLE … DROP CONSTRAINT yet). 2BP01, matching
      // PG's "cannot drop index … because constraint … requires it" (gist.md §7).
      const owner = this.table(found[0]);
      if (owner?.exclusions.some((e) => e.index.toLowerCase() === nameKey)) {
        throw engineError(
          "dependent_objects_still_exist",
          "cannot drop index " +
            di.name +
            " because constraint " +
            di.name +
            " on table " +
            owner.name +
            " requires it",
        );
      }
      this.working().removeIndex(found[0], nameKey);
    }
    return { kind: "statement", cost: 0n, rowsAffected: null };
  }

  // executeCreateType analyzes and runs a CREATE TYPE (spec/design/composite.md): reject a
  // duplicate type name (42710), resolve each field's type (a built-in scalar, or a
  // *previously-defined* composite — 42704 if unknown; no self- or forward-reference), reject a
  // duplicate field name (42701), then register the composite type in the catalog. Named
  // composites only.
  private executeCreateType(ct: CreateType): Outcome {
    checkReservedName("type", ct.name);
    if (this.compositeType(ct.name) !== undefined) {
      throw engineError("duplicate_object", "type " + ct.name + " already exists");
    }
    const fields: CompositeField[] = [];
    for (const f of ct.fields) {
      for (const g of fields) {
        if (g.name.toLowerCase() === f.name.toLowerCase()) {
          throw engineError(
            "duplicate_column",
            "attribute " + f.name + " specified more than once",
          );
        }
      }
      let fty: Type;
      let fdecimal: DecimalTypmod | null = null;
      let fvarchar: number | null = null;
      if (f.typeName.endsWith("[]")) {
        // An array-typed field (spec/design/array.md §12 — the mirror of an array-of-composite
        // element). The element is a scalar or a previously-defined composite (element_type_code
        // 14 + name on disk); a nested-array element and an array typmod stay deferred (0A000),
        // exactly as for an array column.
        const base = f.typeName.slice(0, -2);
        if (f.typeMod !== null) {
          throw engineError(
            "feature_not_supported",
            "a type modifier on an array type is not supported yet",
          );
        }
        const elemScalar = scalarTypeFromName(base);
        const baseComposite = this.compositeType(base);
        if (elemScalar !== undefined) {
          fty = arrayT(scalarT(elemScalar));
        } else if (baseComposite !== undefined) {
          fty = arrayT(compositeT(baseComposite.name));
        } else {
          throw engineError("undefined_object", "type does not exist: " + base);
        }
      } else if (scalarTypeFromName(f.typeName) !== undefined) {
        const [s, d, vl] = resolveTypeAndTypmod(f.typeName, f.typeMod);
        fty = scalarT(s);
        fdecimal = d;
        fvarchar = vl;
      } else if (rangeByName(f.typeName) !== undefined) {
        // A range-typed composite field (a range inside CREATE TYPE) is deferred this slice (only
        // range *columns* are storable — spec/design/ranges.md §3); the type name IS known, so this
        // is 0A000, not the 42704 below.
        throw engineError(
          "feature_not_supported",
          "a range-typed composite field (" + f.typeName + ") is not supported yet",
        );
      } else if (this.compositeType(f.typeName) !== undefined) {
        if (f.typeMod !== null) {
          throw engineError(
            "feature_not_supported",
            "a type modifier is not supported for composite type " + f.typeName,
          );
        }
        fty = compositeT(f.typeName);
      } else {
        throw engineError("undefined_object", "type does not exist: " + f.typeName);
      }
      fields.push({
        name: f.name,
        type: fty,
        decimal: fdecimal,
        varcharLen: fvarchar,
        notNull: f.notNull,
      });
    }
    // Bound composite-type nesting depth (CLAUDE.md §13; cost.md §7b). A chain of CREATE TYPEs each
    // nesting the previous (`a`, `b AS (x a)`, …) builds unbounded depth across many cheap statements —
    // invisible to the per-statement input-size cap and the parser nesting counter — and every derived
    // recursive walk (codec, comparator, record_out/in, resolveColType) recurses to this depth. Reject
    // at the producer so no over-deep type enters the catalog and every downstream walk stays
    // stack-safe. Fields reference only existing types (each already ≤ MAX_COMPOSITE_DEPTH), so this
    // depth computation's recursion is itself bounded.
    const cache = new Map<string, number>();
    let maxField = 0;
    for (const f of fields)
      maxField = Math.max(maxField, this.readSnap().compositeTypeDepth(f.type, cache));
    const depth = 1 + maxField;
    if (depth > MAX_COMPOSITE_DEPTH) {
      throw engineError(
        "statement_too_complex",
        `composite type ${ct.name} nesting depth ${depth} exceeds the maximum of ${MAX_COMPOSITE_DEPTH}`,
      );
    }
    this.working().putType({ name: ct.name, fields });
    return { kind: "statement", cost: 0n, rowsAffected: null };
  }

  // executeDropType analyzes and runs a DROP TYPE (spec/design/composite.md §7). RESTRICT (the only
  // behavior this slice): a missing type is 42704 unless IF EXISTS; if any table column or composite
  // field still references the type, 2BP01; otherwise remove it from the catalog.
  private executeDropType(dt: DropType): Outcome {
    if (this.compositeType(dt.name) === undefined) {
      if (dt.ifExists) return { kind: "statement", cost: 0n, rowsAffected: null };
      throw engineError("undefined_object", "type does not exist: " + dt.name);
    }
    const dep = this.compositeDependentAny(dt.name);
    if (dep !== null) {
      throw engineError(
        "dependent_objects_still_exist",
        "cannot drop type " + dt.name + " because other objects depend on it: " + dep,
      );
    }
    this.working().removeType(dt.name.toLowerCase());
    return { kind: "statement", cost: 0n, rowsAffected: null };
  }

  // executeCreateSequence analyzes and runs a CREATE SEQUENCE (spec/design/sequences.md). Resolve
  // the option overrides against the INCREMENT sign's type defaults, validate the set (22023),
  // reject a relation-namespace collision (42P07 unless IF NOT EXISTS), and register the sequence.
  private executeCreateSequence(cs: CreateSequence): Outcome {
    // The reservation is not a collision, so IF NOT EXISTS does not suppress it
    // (spec/design/introspection.md §4).
    checkReservedName("sequence", cs.name);
    if (this.relationExists(cs.name)) {
      if (cs.ifNotExists) return { kind: "statement", cost: 0n, rowsAffected: null };
      throw engineError("duplicate_table", `relation already exists: ${cs.name}`);
    }
    this.working().putSequence(buildSequenceDef(cs.name, cs.options, undefined));
    return { kind: "statement", cost: 0n, rowsAffected: null };
  }

  // executeDropSequence analyzes and runs a DROP SEQUENCE (spec/design/sequences.md §1).
  // RESTRICT-only: a missing sequence is 42P01 unless IF EXISTS. No dependency tracking this slice
  // (a plain `DEFAULT nextval('s')` creates none — PG). Multiple names are dropped left to right.
  private executeDropSequence(ds: DropSequence): Outcome {
    for (const name of ds.names) {
      // Missing → 42P01 (unless IF EXISTS). An OWNED (serial) sequence has a dependent — its
      // column's default — so RESTRICT (the only mode this slice; CASCADE 0A000) is 2BP01
      // (spec/design/sequences.md §12).
      const seq = this.sequence(name);
      if (seq === undefined) {
        if (ds.ifExists) continue;
        throw engineError("undefined_table", `sequence does not exist: ${name}`);
      }
      if (seq.ownedBy !== undefined) {
        // The owning table is always present (its own DROP TABLE would auto-drop this sequence
        // first), so the column name for the detail resolves. The scope-aware lkpTable finds an
        // owned TEMP sequence's temp owner (temp-tables.md §8).
        const owner = seq.ownedBy;
        const t = this.lkpTable(owner.table);
        const tableName = t?.name ?? owner.table;
        const colName = t?.columns[owner.column]?.name ?? "";
        throw engineError(
          "dependent_objects_still_exist",
          `cannot drop sequence ${seq.name} because other objects depend on it: default value for column ${colName} of table ${tableName} depends on sequence ${seq.name}`,
        );
      }
      // Not owned: remove from whichever scope owns it (a temp sequence is always owned, so this
      // routed path is reached only for a plain persistent sequence — temp-tables.md §8).
      this.removeSequenceRouted(name);
    }
    return { kind: "statement", cost: 0n, rowsAffected: null };
  }

  // executeAlterSequence analyzes and runs an ALTER SEQUENCE [IF EXISTS] s <action>
  // (spec/design/sequences.md §4/§15). A missing sequence is 42P01 unless IF EXISTS (then a no-op).
  // The option form re-edits the definition (PG init_params, isInit=false — only written options
  // change, the counter preserved unless RESTART); RENAME TO moves the catalog key. Touches no
  // session state (currval/lastval unchanged). A catalog write (the write path, transactional, §5).
  private executeAlterSequence(as: AlterSequence): Outcome {
    const committed = this.sequence(as.name);
    if (committed === undefined) {
      if (as.ifExists) return { kind: "statement", cost: 0n, rowsAffected: null };
      throw engineError("undefined_table", `relation does not exist: ${as.name}`);
    }
    if (as.action.kind === "rename") {
      this.alterSequenceRename(committed, as.action.newName);
    } else {
      // AS type on ALTER is 0A000 — the value type is not persisted (sequences.md §14.4), so the
      // original type for re-deriving a default bound is gone.
      if (as.action.options.dataType !== null) {
        throw engineError("feature_not_supported", "ALTER SEQUENCE ... AS type is not supported");
      }
      const newDef = applySeqAlter(committed, as.action.options, as.action.restart);
      this.putSequenceRouted(newDef);
    }
    return { kind: "statement", cost: 0n, rowsAffected: null };
  }

  // alterSequenceRename implements ALTER SEQUENCE s RENAME TO s2 (spec/design/sequences.md §15.3): a
  // collision with any relation — including s itself — is 42P07; otherwise move the entry to the new
  // key. For an OWNED sequence, the owning column's DEFAULT nextval('s') text is rewritten in place
  // to nextval('s2') (the rows survive — not via putTable) so a later INSERT still advances the
  // renamed sequence (jed resolves the sequence by name, unlike PG's OID reference).
  private alterSequenceRename(existing: SequenceDef, newName: string): void {
    checkReservedName("sequence", newName);
    if (this.relationExists(newName)) {
      throw engineError("duplicate_table", `relation already exists: ${newName}`);
    }
    if (existing.ownedBy !== undefined) {
      const exprText = `nextval ( '${newName.toLowerCase().replace(/'/g, "''")}' )`;
      // Route to the owner's scope so a renamed owned TEMP sequence rewrites its column default in the
      // temp snapshot (temp-tables.md §8).
      this.setColumnDefaultExprRouted(
        existing.ownedBy.table.toLowerCase(),
        existing.ownedBy.column,
        {
          exprText,
          expr: parseExpression(exprText),
        },
      );
    }
    // Capture the owning scope BEFORE the remove: after dropping the old key the new name is in no
    // scope, so a post-remove route would wrongly default to the main image (temp-tables.md §8).
    let w: Snapshot;
    if (this.isTempSequence(existing.name)) {
      this.session.tx!.tempDirty = true;
      w = this.session.tx!.tempWorking;
    } else {
      w = this.working();
    }
    w.removeSequence(existing.name.toLowerCase());
    w.putSequence({ ...existing, name: newName });
  }

  // indexBoundRows executes an index equality bound (cost.md §3 "index-bounded scan"):
  // fetch the rows the equality admits, in index-entry order (= storage-key order among
  // equal values), and return them with the scan's up-front units (pages, slabs) — the
  // index-tree nodes overlapping the prefix range plus, per admitted entry, the
  // table-tree nodes of that row's point lookup and its touched-column decompress slabs.
  // The caller feeds the rows through the same scanSource as any bounded scan (page_read
  // block + per-row storage_row_read). A provably empty bound (NULL / contradictory
  // equalities / out-of-range) returns nothing and charges nothing.
  indexBoundRows(
    tableName: string,
    ib: IndexBound,
    params: Value[],
    outer: Row[],
    mask: boolean[],
    left: Row,
  ): { rows: Row[]; pages: number; slabs: number } {
    const built = buildIndexBound(ib, params, outer, left);
    if (built === null) return { rows: [], pages: 0, slabs: 0 }; // provably empty — charge nothing
    return this.indexScanBound(
      tableName,
      ib.nameKey,
      ib.suffixTypes,
      built.bound,
      built.prefixLen,
      mask,
    );
  }

  // indexScanBound range-scans the index B-tree over an already-built key bound and point-looks-up each
  // admitted entry's row, returning them in index-entry order with the scan's up-front (pages, slabs)
  // block — the index-tree nodes overlapping the range plus, per entry, the row's point lookup.
  // prefixByteLen is the equality-prefix byte length skipped before the fixed-width suffix-skip that
  // recovers each entry's row storage key (indexes.md §5.1). Shared by the access-predicate bound
  // (indexBoundRows) and the OR / IN-list point-set (indexPointRows) so both drive the identical
  // per-entry fetch — same cost by construction (cost.md §3 "index-bounded scan" / "OR / IN-list").
  indexScanBound(
    tableName: string,
    nameKey: string,
    suffixTypes: ScalarType[],
    b: KeyBound,
    prefixByteLen: number,
    mask: boolean[],
  ): { rows: Row[]; pages: number; slabs: number } {
    const istore = this.lkpIndexStore(nameKey);
    // The index store has no payload columns, so its mask is empty and its fused scan
    // contributes only the index-tree page_read count (no spill/compress units).
    const iscan = istore.rangeScanWithUnits(b, []);
    let pages = iscan.pages;
    const store = this.lkpStore(tableName);
    let slabs = 0;
    const rows: Row[] = [];
    for (const e of iscan.entries) {
      // Skip the equality prefix by its known byte length, then each remaining key component by width
      // (self-delimiting — a 0x01 NULL tag alone, or 0x00 + the fixed width, indexes.md §5.1); the
      // suffix after them is the row's storage key (indexes.md §3).
      let at = prefixByteLen;
      for (const ty of suffixTypes) {
        at += e.key[at] === 0x01 ? 1 : 1 + widthBytes(ty);
      }
      const rowKey = e.key.slice(at);
      const u = store.getWithUnits(rowKey, mask);
      pages += u.pages;
      slabs += u.slabs;
      if (u.row === undefined) throw new Error("an index entry references a stored row");
      rows.push(u.row);
    }
    return { rows, pages, slabs };
  }

  // indexPointRows fetches the rows a SINGLE already-encoded leading-column index value admits — the
  // equality prefix scan [0x00‖value, byte-successor) over the index B-tree plus, per admitted entry,
  // the row's point lookup. Used by the OR / IN-list secondary-index point-set (indexKeySetRows), where
  // each distinct list value is one such point probe. suffixTypes are the trailing key components
  // (columns[1..], fixed-width), width-skipped past the single leading slot.
  indexPointRows(
    tableName: string,
    nameKey: string,
    suffixTypes: ScalarType[],
    valueKey: Uint8Array,
    mask: boolean[],
  ): { rows: Row[]; pages: number; slabs: number } {
    // The entry-key prefix: the §2.2 present tag + the value's bare key bytes. The range
    // is every entry extending the prefix: [prefix, byte-successor(prefix)).
    const prefix = new Uint8Array(1 + valueKey.length);
    prefix.set(valueKey, 1);
    const b: KeyBound = { lo: prefix, loInc: true, hi: prefixSuccessor(prefix), hiInc: false };
    return this.indexScanBound(tableName, nameKey, suffixTypes, b, prefix.length, mask);
  }

  // pkKeySetRows executes a primary-key OR / IN-list point-set bound (cost.md §3 "OR / IN-list"):
  // each distinct encoded key is a point probe [k, k] over the row's own B-tree, and the admitted
  // rows are concatenated in ascending key order (the same order a full scan would yield). The
  // per-probe (pages, slabs) blocks sum, so the metered cost is the sum of the individual point
  // lookups — a core that full-scans instead computes a different cost (the cross-core contract, §8).
  // Returns the (key, row) entries so the mutation paths can remove/replace by key; SELECT discards
  // the keys. The SELECT/mutation feeds share the one lazy reconstruction (the masked/unmasked
  // split is collapsed — bplus-reshape.md B4); both charge the identical (pages, slabs) driven by
  // the shared mask.
  pkKeySetRows(
    store: TableStore,
    ks: PkKeySet,
    params: Value[],
    outer: Row[],
    mask: boolean[],
    left: Row,
  ): { entries: Entry[]; pages: number; slabs: number } {
    const entries: Entry[] = [];
    let pages = 0;
    let slabs = 0;
    for (const k of encodeKeySet(ks.pkType, ks.srcs, params, outer, ks.coll, left)) {
      const b: KeyBound = { lo: k, loInc: true, hi: k, hiInc: true };
      const u = store.rangeScanWithUnits(b, mask);
      for (const e of u.entries) entries.push(e);
      pages += u.pages;
      slabs += u.slabs;
    }
    return { entries, pages, slabs };
  }

  // indexKeySetRows executes a secondary-index OR / IN-list point-set bound (cost.md §3 "OR /
  // IN-list"): each distinct encoded value is an index point probe (indexPointRows), and the rows are
  // gathered in ascending value order. Because a row has exactly one value for the indexed column,
  // distinct values probe disjoint row sets — no row is fetched twice. The per-probe (pages, slabs)
  // blocks sum, matching the PK point-set cost contract.
  indexKeySetRows(
    tableName: string,
    ks: IndexKeySet,
    params: Value[],
    outer: Row[],
    mask: boolean[],
    left: Row,
  ): { rows: Row[]; pages: number; slabs: number } {
    const rows: Row[] = [];
    let pages = 0;
    let slabs = 0;
    for (const k of encodeKeySet(ks.colType, ks.srcs, params, outer, ks.coll, left)) {
      const r = this.indexPointRows(tableName, ks.nameKey, ks.tailTypes, k, mask);
      for (const row of r.rows) rows.push(row);
      pages += r.pages;
      slabs += r.slabs;
    }
    return { rows, pages, slabs };
  }

  // ginBoundRows executes a GIN-bounded scan (spec/design/gin.md §6, cost.md §3). Evaluates the
  // constant query operand, extracts its terms + mode via the array_ops opclass (an array for @>/&&/=;
  // a single scalar term for = ANY — "member"; the array's distinct non-NULL terms for = — "equal"),
  // gathers each term's posting list (a prefix range scan of the GIN entry tree), combines them by
  // mode (@>, = ANY, and = → intersection, && → union) into the candidate storage-key set, and
  // point-looks-up each candidate in storage-key order. The original predicate stays the residual
  // WHERE filter (re-applied downstream), so the result is always correct. Returns the candidate rows
  // + the scan's up-front (pages, slabs); gin_entry (per posting entry visited) is charged on meter
  // directly. Degenerate constant queries (gin.md §6): a NULL Q, an @> whose Q holds a NULL element,
  // an && with no non-NULL term, and a NULL = ANY scalar are provably empty; @> '{}' and array = with
  // no non-NULL term fall back to the full scan.
  ginBoundRows(
    tableName: string,
    gb: GinBound,
    query: RExpr | null,
    env: EvalEnv,
    meter: Meter,
    mask: boolean[],
  ): { entries: Entry[]; pages: number; slabs: number } {
    const store = this.lkpStore(tableName);
    if (query === null) return { entries: [], pages: 0, slabs: 0 };
    // Extract the query's terms (extract_query_terms) — a pure planning step, NOT metered (cost.md
    // §3): evaluate Q on a scratch meter. Q is a constant, so the empty row suffices.
    const qv = evalExpr(query, [], env, new Meter());
    // Each term is the element's order-preserving key encoding (gin.md §4) — the SAME bytes the
    // entries carry, so a term doubles as its posting-list prefix below. Encoding now lets us dedup
    // distinct terms by bytes (a bijection: byte-dedup == value-dedup, byte-sort == value-sort)
    // generically over every admitted element type.
    const terms: Uint8Array[] = [];
    let hasNull = false;
    let isEmpty = false;
    if (gb.strategy === "member") {
      // `c = ANY(col)`: the query operand is a SCALAR, not an array. A NULL c can equal no element,
      // so the bound is provably empty (gin.md §6). c is in the element type's domain by resolution
      // (jed coerces c to the element type, rejecting an out-of-range integer constant 22003 before
      // exec); inRange is a defensive guard against silently truncating an out-of-range integer into
      // a wrong term.
      if (qv.kind === "null") return { entries: [], pages: 0, slabs: 0 };
      if (qv.kind === "int" && !inRange(gb.elemType, qv.int))
        return { entries: [], pages: 0, slabs: 0 };
      // a GIN element is fixed-width (no text), so the term never collates.
      terms.push(encodeKeyValue(gb.elemType, qv, null));
    } else {
      if (qv.kind !== "array") return { entries: [], pages: 0, slabs: 0 }; // NULL/non-array → provably empty
      const seen = new Set<string>();
      for (const el of qv.elements) {
        if (el.kind === "null") {
          hasNull = true; // a NULL element carries no term
          continue;
        }
        const t = encodeKeyValue(gb.elemType, el, null);
        const k = byteKey(t);
        if (!seen.has(k)) {
          seen.add(k);
          terms.push(t);
        }
      }
      isEmpty = qv.elements.length === 0;
      terms.sort(cmpBytes);
    }

    if (gb.strategy === "contains") {
      if (isEmpty) {
        // @> '{}': every non-NULL array contains the empty array — not derivable from the index;
        // fall back to the full scan (the residual filter keeps the right rows — gin.md §6).
        const u = store.scanWithUnits(mask);
        return { entries: u.entries, pages: u.pages, slabs: u.slabs };
      }
      if (hasNull) return { entries: [], pages: 0, slabs: 0 }; // @> a query with a NULL element is never TRUE
    } else if (gb.strategy === "equal") {
      if (terms.length === 0) {
        // col = Q with NO non-NULL term — '{}' (isEmpty) or an all-NULL Q (hasNull, no non-NULL
        // element). The rows it matches ({}, {NULL}, …) carry NO index terms, so the index cannot
        // enumerate them: fall back to the full scan and let the residual = keep them (gin.md §6).
        // NOT a provably-empty bound — and a Q with ≥1 non-NULL element is NOT caught here (it
        // gathers, even when it also has a NULL element).
        const u = store.scanWithUnits(mask);
        return { entries: u.entries, pages: u.pages, slabs: u.slabs };
      }
    } else if (gb.strategy === "overlaps") {
      if (terms.length === 0) return { entries: [], pages: 0, slabs: 0 }; // && with no non-NULL term
    }

    // Gather each term's posting list: the entry range [encode(term), successor) of the GIN tree
    // (gin.md §4). The entry is encode(term) ‖ storage_key; the fixed-width term self-delimits, so
    // the storage key is the suffix after termWidth bytes.
    const istore = this.lkpIndexStore(gb.nameKey);
    const termWidth = widthBytes(gb.elemType);
    let pages = 0;
    let entriesVisited = 0;
    const postings: Uint8Array[][] = [];
    for (const prefix of terms) {
      const b: KeyBound = {
        lo: prefix,
        loInc: true,
        hi: prefixSuccessor(prefix),
        hiInc: false,
      };
      const scan = istore.rangeScanWithUnits(b, []);
      pages += scan.pages;
      entriesVisited += scan.entries.length;
      postings.push(scan.entries.map((e) => e.key.slice(termWidth)));
    }
    meter.charge(COSTS.ginEntry * BigInt(entriesVisited));

    // Combine into the candidate storage keys, ascending byte (= storage-key) order, so the point
    // lookups and emitted rows follow storage order exactly as a full scan (gin.md §6/§8). @> ALL →
    // intersection; = ANY (member) is a single term, so its intersection is that lone posting list;
    // array = (equal) gathers the same superset as @> over Q's distinct non-NULL terms (the residual
    // = makes it exact downstream); && ANY → union.
    const cand = gb.strategy === "overlaps" ? unionPostings(postings) : intersectPostings(postings);

    let slabs = 0;
    const entries: Entry[] = [];
    for (const key of cand) {
      const u = store.getWithUnits(key, mask);
      pages += u.pages;
      slabs += u.slabs;
      if (u.row === undefined) throw new Error("a GIN entry references a stored row");
      entries.push({ key, row: u.row });
    }
    return { entries, pages, slabs };
  }

  // gistBoundRows gathers a GiST-bounded scan's candidate rows (spec/design/gist.md §5). Evaluates the
  // constant query operand, then DESCENDS the index's resident R-tree visiting only children
  // consistent with the query, collecting candidate storage keys at the leaves; each candidate row is
  // point-looked-up in storage-key order. The original &&/@> predicate stays the residual WHERE filter
  // (always-recheck), so the result is exactly the full-scan result — the bound only narrows which
  // rows are fetched. Returns the candidate (key, row) entries + the up-front (pages, slabs) block;
  // gist_descent (per interior node) is charged on meter directly. Degenerate constant queries (gist.md
  // §5): a NULL Q and an empty && query match nothing; an empty @> query (col @> 'empty') matches every
  // row → full-scan fallback (the empty bound is invisible to the overlap-descend).
  gistBoundRows(
    tableName: string,
    gb: GistBound,
    query: RExpr | null,
    env: EvalEnv,
    meter: Meter,
    mask: boolean[],
  ): { entries: Entry[]; pages: number; slabs: number } {
    const store = this.lkpStore(tableName);
    if (query === null) return { entries: [], pages: 0, slabs: 0 };
    // The query operand is a constant; evaluating it (extract query) is a planning step, NOT metered.
    const qv = evalExpr(query, [], env, new Meter());
    // Form the resident-tree search query from the constant, handling strategy-specific degenerate
    // cases. A NULL query is never TRUE for any row (all strategies).
    let gq: GistQuery;
    if (gb.strategy === "equal") {
      // scalar `=` (gist.md §6): encode the constant to its order-preserving key bytes.
      if (qv.kind === "null") return { entries: [], pages: 0, slabs: 0 };
      gq = { skey: encodeKeyValue(gb.scalarType!, qv, null) };
    } else {
      if (qv.kind !== "range") return { entries: [], pages: 0, slabs: 0 }; // NULL/non-range never TRUE
      if (qv.empty) {
        if (gb.strategy === "contains") {
          // col @> 'empty' is TRUE for every row, but an empty bound is absorbed by the union, so it
          // is invisible to the overlap-descend (a false-negative trap, gist.md §5). Fall back to the
          // full scan; the residual @> keeps every row.
          const u = store.scanWithUnits(mask);
          return { entries: u.entries, pages: u.pages, slabs: u.slabs };
        }
        return { entries: [], pages: 0, slabs: 0 }; // col && 'empty' overlaps nothing
      }
      gq = { rng: qv };
    }
    // Descend the resident R-tree (rebuilt at each mutating statement, gist.md §3/§4.1) — no per-query
    // build. page_read per node touched + gist_descent per interior node.
    let pages = 0;
    let skeys: Uint8Array[] = [];
    const tree = this.readSnap().gistTreeFor(gb.nameKey);
    if (tree !== undefined) {
      const r = gistSearch(tree, [gq], [gb.strategy]);
      skeys = r.keys;
      pages += r.nodes;
      meter.charge(COSTS.gistDescent * BigInt(r.interior));
    }
    // Point-look-up each candidate in storage-key order (the candidates ARE storage keys).
    skeys.sort(cmpBytes);
    const deduped: Uint8Array[] = [];
    for (const k of skeys) {
      if (deduped.length === 0 || cmpBytes(deduped[deduped.length - 1]!, k) !== 0) deduped.push(k);
    }
    let slabs = 0;
    const entries: Entry[] = [];
    for (const key of deduped) {
      const u = store.getWithUnits(key, mask);
      pages += u.pages;
      slabs += u.slabs;
      if (u.row === undefined) throw new Error("a GiST entry references a stored row");
      entries.push({ key, row: u.row });
    }
    return { entries, pages, slabs };
  }

  // executeInsert runs an INSERT whose rows come from a VALUES list or a SELECT (grammar.md
  // §12 / §24). An optional column list names the target columns (unknown → 42703, duplicate →
  // 42701); an unlisted column, or a DEFAULT keyword slot, takes the column's stored default
  // else NULL. Each value is type-checked (NULL into NOT NULL traps 23502; an integer outside the
  // column type's range traps 22003 — CLAUDE.md §8); a duplicate primary key traps 23505. An
  // INSERT is two-phase / all-or-nothing, mirroring UPDATE: every row is validated — including its
  // storage key — before any row is inserted, so a mid-batch failure stores nothing. The two
  // sources differ only in where the candidate rows come from and in cost: VALUES is zero
  // (literals + constant defaults), SELECT is the embedded query's accrued cost. The SELECT
  // source additionally validates output arity (42601) and per-column type assignability (42804)
  // up front, before any row is produced — so both fire even over an empty source.
  private executeInsert(ins: Insert, params: Value[], ctx: CteCtx): Outcome {
    // A catalog relation is read-only (introspection.md §5): a DML target naming one is 42809,
    // checked by NAME before qualifier validation (the built-in resolves in every database).
    checkCatalogRelWrite(ins.table);
    // A write to a READ-ONLY host attachment is 25006 before any I/O — checked BEFORE the qualifier
    // existence gate so a read-only attachment refuses the write deterministically (attached-databases.md §4).
    this.checkAttachmentWritable(ins.db);
    this.checkTableQualifier(ins.db, ins.table); // attached-databases.md §3
    // ON CONFLICT into a host attachment is a deferred narrowing this slice (attached-databases.md §8):
    // the conflict path resolves index stores unscoped. A clean 0A000 before any planning.
    if (ins.onConflict !== null && isAttachmentScope(ins.db)) {
      throw engineError(
        "feature_not_supported",
        "ON CONFLICT on an attached-database table is not supported yet",
      );
    }
    const table = this.lkpTableScoped(ins.db, ins.table); // scope-aware temp-first (temp-tables.md §3)
    if (!table) {
      throw engineError("undefined_table", "table does not exist: " + ins.table);
    }
    // Refuse the write if any of this table's collated keys are version-skewed (slice 2d): a
    // maintained B-tree would mix two orderings (collation.md §12, XX002).
    this.ensureCollationsWritable(table.columns);
    const store = this.writeStoreScoped(ins.db, ins.table); // routes a temp / attachment INSERT to its working snapshot
    // The key members in key order — one for a single-column PK, several for a composite
    // (constraints.md §3), empty for a no-PK (rowid) table.
    const pk = pkIndices(table);
    // The CHECK constraints, resolved once per statement in evaluation (name) order;
    // insertRows evaluates them per candidate row (constraints.md §4.4).
    const checks = this.resolveChecks(table);
    // Each column's EXPRESSION default, resolved once per statement (constraints.md §2);
    // applied per omitted column / DEFAULT slot, sharing one per-statement StmtRng.
    const defaultExprs = this.resolveDefaultExprs(table);
    const stmtRng = new StmtRng();

    // Resolve the optional column list once. provided[i] >= 0 means table column i takes that
    // value position in each row; -1 means column i is omitted (its default, else NULL). With no
    // list it is the identity over all columns. arity is how many values each row must carry (for
    // a SELECT source, how many columns it must project).
    const n = table.columns.length;
    const provided: number[] = new Array(n);
    let arity = n;
    if (ins.columns !== null) {
      provided.fill(-1);
      for (let p = 0; p < ins.columns.length; p++) {
        const name = ins.columns[p]!;
        const idx = columnIndex(table, name);
        if (idx < 0) {
          throw engineError(
            "undefined_column",
            `column ${name} of relation ${table.name} does not exist`,
          );
        }
        if (provided[idx]! >= 0) {
          throw engineError(
            "duplicate_column",
            "column " + table.columns[idx]!.name + " specified more than once",
          );
        }
        provided[idx] = p;
      }
      arity = ins.columns.length;
    } else {
      for (let i = 0; i < n; i++) provided[i] = i;
    }

    // IDENTITY column handling (spec/design/sequences.md §13). OVERRIDING USER VALUE discards any
    // supplied value for every identity column and uses its sequence instead — modeled by treating
    // the column as omitted (provided[i] = -1, so its nextval default applies). Apply it before the
    // GENERATED ALWAYS gate below so a User-overridden ALWAYS column needs no further check.
    if (ins.overriding === "user") {
      for (let i = 0; i < n; i++) {
        if (table.columns[i]!.identity !== null) provided[i] = -1;
      }
    }
    // The GENERATED ALWAYS columns still explicitly targeted (and not OVERRIDING SYSTEM VALUE):
    // supplying a non-DEFAULT value to one is 428C9. Collected as (column ordinal, value position)
    // so the source branches can enforce it (VALUES per-row, SELECT up-front).
    const alwaysTargeted: { col: number; pos: number }[] = [];
    if (ins.overriding !== "system") {
      for (let i = 0; i < n; i++) {
        const col = table.columns[i]!;
        if (col.identity === "always" && provided[i]! >= 0) {
          alwaysTargeted.push({ col: i, pos: provided[i]! });
        }
      }
    }

    if (ins.source.kind === "select") {
      // GENERATED ALWAYS gate (sequences.md §13.3): a SELECT projection always supplies an explicit
      // value, so targeting an ALWAYS identity column without OVERRIDING SYSTEM VALUE is 428C9 —
      // raised up front (PG raises it at rewrite), firing even over a zero-row source.
      if (alwaysTargeted.length > 0) {
        throw engineError(
          "generated_always",
          `cannot insert a non-DEFAULT value into column ${table.columns[alwaysTargeted[0]!.col]!.name}`,
        );
      }
      // SELECT source (§24). Plan the source query, then resolve the RETURNING projection
      // (PostgreSQL's analysis order — both precede any execution), threading ONE ParamTypes
      // so a $N shared by the source and the RETURNING list unifies statement-wide (api.md
      // §5). The source returns OWNED rows, so a self-insert (INSERT INTO t SELECT ... FROM
      // t) reads the pre-insert snapshot, then writes.
      const ptypes = new ParamTypes();
      // The source query (and the RETURNING sublinks) see the statement's CTE bindings
      // (writable-cte.md) — the move-rows idiom INSERTs a SELECT over a CTE buffer.
      const plan = this.planQuery(ins.source.select, null, ctx.bindings, ptypes);
      const ret =
        ins.returning !== null
          ? this.resolveReturning(table, ins.returning, false, ctx.bindings, ptypes)
          : null;
      const cplan =
        ins.onConflict !== null ? this.resolveOnConflict(table, ins.onConflict, ptypes) : null;
      const bound = bindParams(params, ptypes.finalize());
      const meter = this.session.newMeter();
      const foldCost = { value: 0n };
      this.foldUncorrelatedInPlan(plan, bound, ctx, foldCost);
      // Uncorrelated subqueries in the RETURNING list fold once (cost.md §3), reading the
      // pre-statement snapshot (grammar.md §32). They see the statement's CTE bindings
      // (writable-cte.md) via `ctx`.
      if (ret !== null) {
        ret.nodes = ret.nodes.map((node) =>
          this.foldUncorrelatedInRExpr(node, bound, ctx, foldCost),
        );
      }
      this.foldConflictPlan(cplan, bound, foldCost);
      meter.charge(foldCost.value);
      const q = this.execQueryPlan(plan, [], bound, ctx);
      // Arity: the SELECT's output column count must match the target — checked before any row is
      // produced, so it fires even when the source returns zero rows.
      if (q.columnNames.length !== arity) {
        const noun = arity === 1 ? "column" : "columns";
        throw engineError(
          "syntax_error",
          `INSERT into table ${table.name} has ${arity} target ${noun} but SELECT produces ${q.columnNames.length}`,
        );
      }
      // Type-assignability, the up-front PostgreSQL gate (§24): each projected column's TYPE must
      // be assignable to its target column. Fires even at zero rows (the difference from per-row
      // checking). The per-row storeValue in insertRows then still range-checks values (22003)
      // and enforces NOT NULL.
      for (let i = 0; i < n; i++) {
        const p = provided[i]!;
        if (p < 0) continue;
        const col = table.columns[i]!;
        // INSERT ... SELECT into a composite column lands in a later slice (the VALUES + ROW(…)
        // path is S3 — spec/design/composite.md §12).
        if (col.type.kind === "composite") {
          throw engineError(
            "feature_not_supported",
            "INSERT ... SELECT into composite column " + col.name + " is not supported yet",
          );
        }
        if (col.type.kind === "array") {
          throw engineError(
            "feature_not_supported",
            "INSERT ... SELECT into array column " + col.name + " is not supported yet",
          );
        }
        if (col.type.kind === "range") {
          // INSERT ... SELECT into a range column is deferred (the VALUES + range literal/cast path
          // is the supported input — spec/design/ranges.md §1), like array.
          throw engineError(
            "feature_not_supported",
            "INSERT ... SELECT into range column " + col.name + " is not supported yet",
          );
        }
        if (!assignableTo(q.columnTypes[p]!, col.type.scalar)) {
          throw typeError(
            `column ${col.name} is of type ${typeCanonicalName(col.type)} but expression is of type ${rtName(q.columnTypes[p]!)}`,
          );
        }
      }
      // Cost = the embedded SELECT's accrued cost (§24) plus the disposition plan's
      // compression attempts for over-RECORD_MAX rows (value_compress, cost.md §3) plus the
      // RETURNING projection; storing the rows themselves stays unmetered. One meter keeps
      // one ceiling over the whole statement.
      meter.charge(q.cost);
      const { affected, returned } = this.runInsertRows(
        table,
        store,
        ins.db,
        pk,
        checks,
        defaultExprs,
        stmtRng,
        provided,
        q.rows,
        cplan,
        ret?.nodes ?? null,
        bound,
        ctx,
        meter,
      );
      return dmlOutcome(ret?.names ?? null, ret?.types ?? null, returned, affected, meter.accrued);
    }

    // VALUES source. A $N in a VALUES slot is typed as its TARGET COLUMN's type. Collect those
    // types across every row (a $N reused under two columns unifies; spec/design/api.md §5), then
    // bind the supplied values up front so a bad bind fails before any row is stored.
    const rowsIn = ins.source.rows;
    const ptypes = new ParamTypes();
    for (const values of rowsIn) {
      if (values.length !== arity) {
        const which = ins.columns !== null ? "target columns are" : "columns are";
        throw engineError(
          "syntax_error",
          `INSERT row has ${values.length} values but ${arity} ${which} expected for table ${table.name}`,
        );
      }
      for (let i = 0; i < n; i++) {
        const p = provided[i]!;
        if (p >= 0 && p < values.length) {
          const iv = values[p]!;
          // A top-level $N slot takes its target column's scalar type; a composite-column param
          // stays untyped (42P18 at finalize this slice — materializeInsertValue handles ROW(…)).
          const ct = table.columns[i]!.type;
          if (iv.kind === "param" && ct.kind === "scalar") {
            ptypes.note(iv.index - 1, ct.scalar);
          }
        }
      }
    }
    // GENERATED ALWAYS gate (sequences.md §13.3): an explicit (non-DEFAULT) value targeting an
    // ALWAYS identity column without OVERRIDING SYSTEM VALUE is 428C9. Statement-level — fires
    // before any row is materialized; an all-DEFAULT column is fine. Arity is validated above, so
    // values[pos] is in range.
    for (const at of alwaysTargeted) {
      if (rowsIn.some((values) => values[at.pos]!.kind !== "default")) {
        throw engineError(
          "generated_always",
          `cannot insert a non-DEFAULT value into column ${table.columns[at.col]!.name}`,
        );
      }
    }
    // Resolve the RETURNING projection after the source (PostgreSQL's analysis order) and
    // before binding/execution — a 42703 here beats a would-be 23505 (grammar.md §32).
    const ret =
      ins.returning !== null
        ? this.resolveReturning(table, ins.returning, false, ctx.bindings, ptypes)
        : null;
    const cplan =
      ins.onConflict !== null ? this.resolveOnConflict(table, ins.onConflict, ptypes) : null;
    const bound = bindParams(params, ptypes.finalize());

    // INSERT ... VALUES reads no rows; with only literal values and constant defaults it
    // evaluates no expression tree (leaves), so a plain fully-inline insert still costs zero. An
    // EXPRESSION default (DEFAULT uuidv7()) evaluates a tree per application — operator_eval per
    // node — the documented exception (constraints.md §2, like CHECK). Other metered work: the
    // disposition plan's compression attempts for over-RECORD_MAX rows (value_compress) and the
    // RETURNING projection. The meter is created here (before materialization) so a
    // DEFAULT-keyword expression default charges it too.
    const meter = this.session.newMeter();

    // Materialize each row into its value-position-indexed candidates (length arity, checked
    // above), resolving each slot: a literal, a bound $N, or a DEFAULT keyword → that column's
    // default (a constant, or its expression evaluated for this row through the shared stmtRng).
    // The shared insertRows then builds the declaration-order row and applies OMITTED defaults.
    const rows: Value[][] = [];
    for (const values of rowsIn) {
      const rv: Value[] = new Array(arity);
      for (let i = 0; i < n; i++) {
        const col = table.columns[i]!;
        const p = provided[i]!;
        if (p >= 0) {
          const iv = values[p]!;
          // DEFAULT at the top level → the column's default (constant or per-row expression). A
          // ROW(…) / literal / $N slot is materialized against the column's resolved ColType
          // (composite-aware — composite.md §1/§4); coerceForStore in insertRows then range-checks.
          const ct = store.columnTypes()[i]!;
          if (iv.kind === "default") {
            rv[p] = this.evalDefault(col, defaultExprs[i]!, stmtRng, meter);
          } else if (
            ct.kind === "scalar" &&
            ct.scalar === "date" &&
            iv.kind === "lit" &&
            iv.lit.kind === "text" &&
            dateClockSpecial(iv.lit.text) !== null
          ) {
            // A date-special string in a VALUES slot is LITERAL adaptation (date.md §6): 'epoch'
            // is the constant 1970-01-01, and a clock-relative word ('today'/'now'/…) names the
            // statement-clock day in the session zone, computed here through the shared stmtRng —
            // never a stored constant. An ordinary date string takes the normal materialize path
            // (parse to a value); non-literal text DATA (INSERT … SELECT, a $N bind) stays
            // strict — the specials are literal/cast syntax, not an assignment coercion.
            const sp = dateClockSpecial(iv.lit.text)!;
            rv[p] = sp.epoch
              ? dateValue(0n)
              : dateClockValue(this, stmtRng, this.session.seam, meter, sp.offsetDays);
          } else {
            rv[p] = materializeInsertValue(iv, ct, bound);
          }
        }
      }
      rows.push(rv);
    }
    // Uncorrelated subqueries in the RETURNING list and the DO UPDATE SET/WHERE fold once
    // (cost.md §3), reading the pre-statement snapshot (grammar.md §32).
    const foldCost = { value: 0n };
    if (ret !== null) {
      ret.nodes = ret.nodes.map((node) => this.foldUncorrelatedInRExpr(node, bound, ctx, foldCost));
    }
    this.foldConflictPlan(cplan, bound, foldCost);
    meter.charge(foldCost.value);
    const { affected, returned } = this.runInsertRows(
      table,
      store,
      ins.db,
      pk,
      checks,
      defaultExprs,
      stmtRng,
      provided,
      rows,
      cplan,
      ret?.nodes ?? null,
      bound,
      ctx,
      meter,
    );
    return dmlOutcome(ret?.names ?? null, ret?.types ?? null, returned, affected, meter.accrued);
  }

  // insertRows runs phase 1 + phase 2 of an INSERT, shared by the VALUES and SELECT sources. Each
  // element of rows is one row's candidate values indexed by VALUE POSITION p (length arity); the
  // declaration-order stored row is built via provided (an omitted column takes its default else
  // NULL) and each value is type-coerced + range-checked by storeValue (23502 / 22003 / 22P02 /
  // 42804). The storage key is computed and checked for a duplicate (23505 — within this batch via
  // seenKeys AND against the store) BEFORE any row is written; only once every row validates are
  // they all inserted (phase 2), allocating a fresh monotonic rowid in row order for a no-PK
  // table. All-or-nothing: a failure leaves the store untouched and burns no rowids.
  // `returning` is the resolved RETURNING projection (grammar.md §32), evaluated over the
  // validated rows after every check passes and BEFORE phase 2 writes — so its subqueries
  // observe the pre-statement snapshot and a ceiling abort stays all-or-nothing; `params`
  // feeds its $Ns. Returns the projected output rows, null without a clause.
  private insertRows(
    table: Table,
    store: TableStore,
    // dbScope is the INSERT target's explicit database qualifier (attached-databases.md §5): its
    // existence probe + unique-index probes resolve through the scope-aware funnels, so an attachment
    // target hits its own snapshot. undefined for a bare (implicit-scope) target — the temp-first funnel.
    dbScope: string | undefined,
    pk: number[],
    checks: NamedCheck[],
    defaultExprs: (RExpr | null)[],
    rng: StmtRng,
    provided: number[],
    rows: Value[][],
    returning: RExpr[] | null,
    params: Value[],
    ctes: CteCtx,
    meter: Meter,
  ): Value[][] | null {
    const n = table.columns.length;
    // The columns' resolved ColTypes (a scalar, or a composite resolved to its field tree), for
    // composite-aware store coercion (spec/design/composite.md §4).
    const colTypes = store.columnTypes();
    // Per-column frozen collations for the collated text key form (§2.12); null everywhere for a
    // C-only / non-text table (the fast path).
    const colls = this.columnCollations(table.columns);
    // Phase-1 existence probes read the VISIBLE snapshot (the read pin under a data-modifying WITH —
    // writable-cte.md §2; else working == read-your-writes), so a self-insert sees the pre-insert
    // state and an earlier sub-statement's staged key is invisible here (its collision is caught at
    // phase 2 — §7). The passed `store` is the working set the phase-2 inserts land in.
    const readStore = this.lkpStoreScoped(dbScope, table.name);
    const prepared: { key: Uint8Array | null; row: Row }[] = [];
    const seenKeys = new Set<string>();
    // Resolve the table's indexes once for this statement (column ordinals + resolved expression keys
    // — spec/design/indexes.md §4), parallel to table.indexes. An expression key is evaluated per row
    // (unmetered) to build its entry; done in phase 1 (below) so a failing expression aborts before any
    // write (all-or-nothing).
    const rindexes = this.resolveTableIndexes(table);
    // The eval env for phase-1 index-expression evaluation (unmetered; params/CTEs empty — an index
    // expression cannot reference them). Reuses the statement rng (an immutable index expr never reads it).
    const env = this.maintenanceEnv(rng);
    // Per UNIQUE index (catalog/name order), the prefixes earlier rows of this batch
    // claimed — an in-batch duplicate traps 23505 like a stored one (indexes.md §8).
    const uniqDefs = rindexes.filter((d) => d.unique);
    const seenPrefixes = uniqDefs.map(() => new Set<string>());
    // Per prepared row, the secondary-index entry keys WITHOUT the storage-key suffix — one sub-array
    // per index (rindexes order), computed in phase 1 (so expression eval errors abort before any
    // write). Phase 2 appends the row's final storage key (the rowid, allocated there) to each —
    // entry = prefix ‖ key is byte-identical to building it with the key directly (indexes.md §3/§4).
    const entryPrefixes: Uint8Array[][][] = [];
    let cunits = 0n;
    for (const values of rows) {
      const row: Row = new Array(n);
      for (let i = 0; i < n; i++) {
        const col = table.columns[i]!;
        const p = provided[i]!;
        // An omitted column takes its default — a constant, or its expression evaluated for
        // this row through the shared per-statement seam/clock (constraints.md §2). evalDefault
        // charges operator_eval for an expression default; a constant (or no default → NULL) is
        // free.
        const candidate: Value =
          p >= 0 ? values[p]! : this.evalDefault(col, defaultExprs[i]!, rng, meter);
        try {
          row[i] = coerceForStore(
            candidate,
            colTypes[i]!,
            col.decimal,
            col.varcharLen,
            col.notNull,
            col.name,
          );
        } catch (e) {
          // Stamp the target relation onto a column-store failure (23502/22003/22001) — the
          // relation is in scope here, not inside the coercion (spec/design/error-fields.md §4).
          throw stampTable(e, table.name);
        }
      }

      // CHECK constraints, in name order, on the fully-coerced candidate row — after NOT
      // NULL (storeValue above), before the key/duplicate check (PG's per-row order,
      // constraints.md §4.4). TRUE and NULL pass; the first FALSE aborts the whole
      // statement (two-phase — nothing has been written). Evaluation is metered
      // expression work (operator_eval), so guard the ceiling per checked row. The
      // per-statement rng is shared with the default evaluation above (one StmtRng).
      if (checks.length > 0) {
        meter.guard();
        const env: EvalEnv = {
          params: [],
          outer: [],
          runSubquery: (p, o) => this.execQueryPlan(p, o, [], EMPTY_CTE_CTX),
          seam: this.session.seam,
          rng,
          ctes: EMPTY_CTE_CTX,
          exec: this,
        };
        evalChecks(checks, table.name, row, env, meter);
      }

      let key: Uint8Array | null = null;
      if (pk.length > 0) {
        // The composite key is the concatenation of the members' bare encodings in key order
        // (encoding.md §2.3 — encodePkKey); a single-column key is the one-member case.
        key = encodePkKey(table, pk, colls, row);
        // The PK's 23505 reports PostgreSQL's derived auto-name for the PK index,
        // `<table>_pkey` — jed persists/reserves no such relation (constraints.md §5.4).
        const seen = key.join(",");
        if (seenKeys.has(seen) || readStore.get(key) !== undefined) {
          throw uniqueViolation(table.name, pkeyName(table.name));
        }
        seenKeys.add(seen);
      }
      // UNIQUE-index probes (indexes.md §8), AFTER the primary-key duplicate check (PG
      // reports the PK first when both are violated — probed): per unique index in
      // catalog (name) order, a fully-non-NULL key tuple (its slot prefix) must match no
      // existing entry and no earlier row of this batch. Unmetered validation, like the
      // PK duplicate check (cost.md §3).
      for (let u = 0; u < uniqDefs.length; u++) {
        const def = uniqDefs[u]!;
        const prefix = indexPrefixKey(table.columns, colls, def, row, env);
        if (prefix === null) continue;
        const istore = this.lkpIndexStoreScoped(dbScope, def.name.toLowerCase());
        const stored = istore.rangeEntries(uniqueProbeBound(prefix));
        const k = prefix.join(",");
        if (stored.length > 0 || seenPrefixes[u]!.has(k)) {
          throw uniqueViolation(table.name, def.name);
        }
        seenPrefixes[u]!.add(k);
      }
      // Meter the row's disposition-plan compression attempts (value_compress, cost.md §3).
      // For a no-PK table the synthetic rowid is allocated in phase 2; only the key LENGTH
      // feeds the plan, so an 8-byte placeholder stands in deterministically.
      cunits += BigInt(store.writeCompressUnits(key ?? new Uint8Array(8), row));
      // Compute this row's per-index entry keys WITHOUT the suffix (phase 1 — evaluates every
      // expression key, so an eval error aborts here before any write; unmetered). Phase 2 appends the
      // final storage key.
      entryPrefixes.push(
        rindexes.map((rindex) =>
          indexEntryKeys(table.columns, colls, rindex, new Uint8Array(0), row, env),
        ),
      );
      prepared.push({ key, row });
    }

    // FOREIGN KEY existence (constraints.md §6.4) — after all candidate rows are prepared, so the
    // check sees the statement's batch END STATE (a later row may supply an earlier row's parent
    // key; a self-reference resolves within the batch — PG's end-of-statement semantics). Unmetered
    // validation, like the PK/UNIQUE probes, and before any write (all-or-nothing). MATCH SIMPLE: a
    // row with any NULL local column is exempt.
    const relation = table.name;
    const fks = this.table(table.name)?.fks ?? [];
    for (const fk of fks) {
      // The parent exists (validated at CREATE TABLE; DROP TABLE refuses to drop a referenced
      // table — §6.10), so a consistent catalog always finds it.
      const parent = this.table(fk.refTable);
      if (parent === undefined) continue;
      // The probe matches the parent's stored key, so a collated parent key column uses the
      // PARENT's collation (§2.12).
      const parentColls = this.columnCollations(parent.columns);
      // Only a self-reference can satisfy against this statement's batch (a different parent table
      // is unchanged by this INSERT). Collect the parent keys the batch supplies.
      const batch = new Set<string>();
      if (fk.refTable.toLowerCase() === relation.toLowerCase()) {
        for (const pr of prepared) {
          const p = fkProbe(fk, parent, parentColls, pr.row, fk.refColumns);
          if (p !== null) batch.add(fkProbeBytes(p).join(","));
        }
      }
      for (const pr of prepared) {
        const probe = fkProbe(fk, parent, parentColls, pr.row, fk.columns);
        if (probe === null) continue; // a NULL local column → exempt (MATCH SIMPLE)
        if (batch.has(fkProbeBytes(probe).join(","))) continue;
        if (!this.fkProbeHits(probe, fk.refTable)) {
          throw fkViolationInsert(relation, fk.name);
        }
      }
    }

    // EXCLUDE constraints (spec/design/gist.md §7), after FK existence — a batch pass over the
    // statement's END STATE: each new row must conflict with no STORED row (probe the backing GiST
    // tree, whose leaf recheck is the full (expr_i op_i) conjunction) and no OTHER new row of this
    // batch (pairwise — the resident tree holds only stored rows). The NULL rule / empty-range exempt
    // a row. Unmetered validation, before any write.
    const exclusions = this.table(table.name)?.exclusions ?? [];
    if (exclusions.length > 0) {
      const tcols = table.columns;
      for (const exc of exclusions) {
        const ikey = exc.index.toLowerCase();
        for (const pr of prepared) {
          const probe = exclusionProbeQuery(tcols, exc, pr.row);
          if (probe === null) continue; // exempt
          const tree = this.readSnap().gistTreeFor(ikey);
          const conflict =
            tree !== undefined && gistSearch(tree, probe.query, probe.strats).keys.length > 0;
          if (conflict) {
            throw exclusionViolation(table.name, exc.name);
          }
        }
        for (let i = 0; i < prepared.length; i++) {
          for (let j = 0; j < i; j++) {
            if (exclusionPairConflicts(tcols, exc, prepared[i]!.row, prepared[j]!.row)) {
              throw exclusionViolation(table.name, exc.name);
            }
          }
        }
      }
    }

    // Charge + enforce the ceiling BEFORE phase 2 writes anything (all-or-nothing).
    meter.charge(COSTS.valueCompress * cunits);
    meter.guard();

    // The RETURNING projection (grammar.md §32, cost.md §3): evaluate over the validated
    // rows — every check has passed, nothing is written yet, so subqueries in the list read
    // the pre-statement snapshot and a 54P01 here leaves the store untouched.
    const returned =
      returning !== null
        ? this.projectReturning(
            returning,
            prepared.map((pr) => pr.row),
            null,
            params,
            ctes,
            meter,
          )
        : null;

    // Phase 2 — every row validated, so each insert is guaranteed to succeed. A synthetic
    // rowid is allocated here, in row order, so a failed validation pass burns none
    // (spec/fileformat/format.md, grammar.md §12). Each stored row's secondary-index
    // entries are computed against its final key (the rowid included) and written after
    // the rows (indexes.md §4 — an index write cannot fail, so all-or-nothing is
    // unchanged).
    const indexInserts: Uint8Array[][] = table.indexes.map(() => []);
    for (let ri = 0; ri < prepared.length; ri++) {
      const pr = prepared[ri]!;
      const key = pr.key ?? encodeInt("i64", store.allocRowid());
      // Append the final storage key to each phase-1 entry prefix (byte-identical to building the
      // entry with the key directly — indexes.md §3/§4).
      for (let k = 0; k < table.indexes.length; k++) {
        for (const p of entryPrefixes[ri]![k]!) {
          indexInserts[k]!.push(concatBytes([p, key]));
        }
      }
      if (!store.insert(key, pr.row)) {
        // A collision here can only happen under the writable-CTE read pin (writable-cte.md §7): an
        // EARLIER data-modifying sub-statement of the same WITH staged this key, which phase 1
        // (reading the pin) did not see. Matches PostgreSQL's unique violation; the whole statement
        // aborts all-or-nothing. For a single statement, phase 1 already caught every duplicate, so
        // this is never reached.
        throw uniqueViolation(table.name, pkeyName(table.name));
      }
    }
    for (let k = 0; k < table.indexes.length; k++) {
      const def = table.indexes[k]!;
      const istore = this.writeIndexStoreScoped(dbScope, def.name.toLowerCase());
      for (const ek of indexInserts[k]!) {
        if (!istore.insert(ek, [])) {
          // A cross-sub-statement unique-index collision under the read pin (as above).
          throw uniqueViolation(table.name, def.name);
        }
      }
    }
    return returned;
  }

  // resolveOnConflict resolves an ON CONFLICT clause (spec/design/upsert.md §2/§5) into a
  // ConflictPlan: the arbiter, plus — for DO UPDATE — the resolved SET assignment plans and the
  // optional WHERE filter, both resolved against the [existing | excluded] scope. Threads the
  // statement ptypes so a $N in a SET/WHERE unifies with the rest of the INSERT.
  private resolveOnConflict(table: Table, oc: OnConflict, ptypes: ParamTypes): ConflictPlan {
    const arb = resolveArbiter(table, oc.target);
    if (!oc.doUpdate) {
      return { arb, doUpdate: false, assignments: [], filter: null };
    }
    // DO UPDATE requires a target (spec/design/upsert.md §2) — PostgreSQL's message.
    if (arb === null) {
      throw engineError(
        "syntax_error",
        "ON CONFLICT DO UPDATE requires inference specification or constraint name",
      );
    }
    const scope = Scope.onConflictExcluded(this, table);
    const pkMembers = pkIndices(table);
    const plans: AssignPlan[] = [];
    for (const a of oc.assignments) {
      const idx = columnIndex(table, a.column);
      if (idx < 0) throw engineError("undefined_column", "column does not exist: " + a.column);
      if (table.columns[idx]!.identity === "always") {
        throw engineError("generated_always", `column ${a.column} can only be updated to DEFAULT`);
      }
      // Assigning a PRIMARY KEY member in DO UPDATE remains deferred (0A000, upsert.md §5/§9):
      // the standalone UPDATE re-keying has landed (§11 step 6), but extending it to the upsert
      // conflict path is a separate follow-on.
      if (pkMembers.includes(idx)) {
        throw engineError(
          "feature_not_supported",
          "updating a primary key column is not supported",
        );
      }
      for (const p of plans) {
        if (p.idx === idx) {
          throw engineError("duplicate_column", "column " + a.column + " assigned more than once");
        }
      }
      const col = table.columns[idx]!;
      if (col.type.kind === "composite") {
        throw engineError(
          "feature_not_supported",
          "updating composite column " + a.column + " is not supported yet",
        );
      }
      if (col.type.kind === "array") {
        throw engineError(
          "feature_not_supported",
          "updating array column " + a.column + " is not supported yet",
        );
      }
      if (col.type.kind === "range") {
        throw engineError(
          "feature_not_supported",
          "updating range column " + a.column + " is not supported yet",
        );
      }
      const targetScalar = col.type.scalar;
      const { node, type } = resolve(
        scope,
        a.value,
        targetScalar,
        { collecting: false, groupKeys: [], specs: [] },
        ptypes,
      );
      requireAssignable(type, targetScalar, a.column);
      plans.push({
        idx,
        name: col.name,
        target: targetScalar,
        decimal: col.decimal,
        varcharLen: col.varcharLen,
        notNull: col.notNull,
        source: node,
      });
    }
    const filter = oc.filter !== null ? resolveBooleanFilter(scope, oc.filter, ptypes) : null;
    return { arb, doUpdate: true, assignments: plans, filter };
  }

  // arbiterExisting looks up the EXISTING (committed) conflicting row for an arbiter key
  // (spec/design/upsert.md §3): always a committed row (an in-batch row sharing the arbiter key was
  // caught earlier by the proposed-arbiter set). Returns { key, row } or null.
  private arbiterExisting(
    arb: Arbiter,
    store: TableStore,
    table: Table,
    ak: Uint8Array,
  ): { key: Uint8Array; row: Row } | null {
    if (arb.isPK) {
      const row = store.get(ak);
      if (row === undefined) return null;
      return { key: ak, row: store.resolveAll(row) };
    }
    const def = table.indexes[arb.indexPos]!;
    const entries = this.readSnap()
      .indexStore(def.name.toLowerCase())
      .rangeEntries(uniqueProbeBound(ak));
    if (entries.length === 0) return null;
    const suffix = entries[0]!.key.slice(ak.length);
    const row = store.get(suffix);
    if (row === undefined) throw new Error("a unique-index entry points at a live row");
    return { key: suffix, row: store.resolveAll(row) };
  }

  // rowConflictsCommitted reports whether a candidate row conflicts with a COMMITTED row on the
  // primary key or any unique index (the no-target DO NOTHING skip test — spec/design/upsert.md §2).
  // NULLS DISTINCT: a unique tuple with any NULL component never conflicts.
  private rowConflictsCommitted(
    store: TableStore,
    table: Table,
    pk: number[],
    colls: (Collation | null)[],
    rindexes: ResolvedIndex[],
    row: Row,
  ): boolean {
    if (pk.length > 0 && store.get(encodePkKey(table, pk, colls, row)) !== undefined) return true;
    for (const rindex of rindexes) {
      if (!rindex.unique) continue;
      const prefix = this.indexPrefix(table.columns, colls, rindex, row);
      if (prefix === null) continue;
      if (
        this.readSnap().indexStore(rindex.name.toLowerCase()).rangeEntries(uniqueProbeBound(prefix))
          .length > 0
      ) {
        return true;
      }
    }
    return false;
  }

  // foldConflictPlan folds globally-uncorrelated subqueries in a DO UPDATE's SET/WHERE once (their
  // cost is added a single time — cost.md §3), exactly as UPDATE folds its assignment/filter.
  private foldConflictPlan(
    plan: ConflictPlan | null,
    bound: Value[],
    foldCost: { value: bigint },
  ): void {
    if (plan === null || !plan.doUpdate) return;
    plan.assignments = plan.assignments.map((ap) => ({
      ...ap,
      source: this.foldUncorrelatedInRExpr(ap.source, bound, EMPTY_CTE_CTX, foldCost),
    }));
    if (plan.filter !== null) {
      plan.filter = this.foldUncorrelatedInRExpr(plan.filter, bound, EMPTY_CTE_CTX, foldCost);
    }
  }

  // runInsertRows dispatches the validated candidate rows to the plain or the ON CONFLICT insert
  // path, shared by both INSERT sources. Returns { affected, returned }: a plain insert affects
  // every candidate row; an ON CONFLICT may insert, update, or skip (spec/design/upsert.md §3).
  private runInsertRows(
    table: Table,
    store: TableStore,
    // dbScope is the INSERT target's explicit database qualifier (attached-databases.md §5), threaded
    // to insertRows so its existence / unique-index probes resolve stores in the right database.
    // undefined for a bare (implicit-scope) target. ON CONFLICT is reached only for a reserved scope (an
    // attachment target is gated 0A000 up front), so the conflict path takes no scope.
    dbScope: string | undefined,
    pk: number[],
    checks: NamedCheck[],
    defaultExprs: (RExpr | null)[],
    rng: StmtRng,
    provided: number[],
    rows: Value[][],
    conflict: ConflictPlan | null,
    returning: RExpr[] | null,
    params: Value[],
    ctes: CteCtx,
    meter: Meter,
  ): { affected: number; returned: Value[][] | null } {
    if (conflict !== null) {
      return this.insertRowsOnConflict(
        table,
        store,
        pk,
        checks,
        defaultExprs,
        rng,
        provided,
        rows,
        conflict,
        returning,
        params,
        ctes,
        meter,
      );
    }
    const returned = this.insertRows(
      table,
      store,
      dbScope,
      pk,
      checks,
      defaultExprs,
      rng,
      provided,
      rows,
      returning,
      params,
      ctes,
      meter,
    );
    return { affected: rows.length, returned };
  }

  // insertRowsOnConflict runs phase 1 + phase 2 of an INSERT ... ON CONFLICT (spec/design/upsert.md
  // §3), the UPSERT analogue of insertRows. Phase 1 walks the candidate rows in source order,
  // classifying each as a planned INSERT, a planned UPDATE of an existing row, or a SKIP; the
  // planned inserts + updates are then validated against the statement END STATE (PK / unique /
  // CHECK / FK) before phase 2 writes anything (all-or-nothing). returning projects the AFFECTED
  // rows (inserts with an all-NULL old side, updates with their pre-update existing row).
  private insertRowsOnConflict(
    table: Table,
    store: TableStore,
    pk: number[],
    checks: NamedCheck[],
    defaultExprs: (RExpr | null)[],
    rng: StmtRng,
    provided: number[],
    rows: Value[][],
    plan: ConflictPlan,
    returning: RExpr[] | null,
    params: Value[],
    ctes: CteCtx,
    meter: Meter,
  ): { affected: number; returned: Value[][] | null } {
    const n = table.columns.length;
    const relation = table.name;
    const colTypes = store.columnTypes();
    // Phase-1 existence/arbiter probes read the VISIBLE snapshot (the read pin under a data-modifying
    // WITH — writable-cte.md §2; else working == read-your-writes); the passed `store` is the working
    // set the phase-2 inserts/replaces land in.
    const readStore = this.lkpStore(table.name);
    // Per-column frozen collations for the collated text key form (§2.12); null everywhere for a
    // C-only / non-text table (the fast path).
    const colls = this.columnCollations(table.columns);
    // Resolve the table's indexes once (column ordinals + resolved expression keys — indexes.md §4),
    // parallel to table.indexes; every uniqueness probe / arbiter / entry build below evaluates any
    // expression key through it (unmetered, via the index-maintenance helpers).
    const rindexes = this.resolveTableIndexes(table);
    // The unique-index positions in table.indexes (no-target skip test + end-state pass).
    const uniqIdx: number[] = [];
    for (let i = 0; i < table.indexes.length; i++) if (table.indexes[i]!.unique) uniqIdx.push(i);

    const inserts: Row[] = [];
    const updates: { key: Uint8Array; newRow: Row; oldRow: Row }[] = [];
    // Arbiter keys this statement has already proposed (the §4 second-affect rule).
    const proposedArb = new Set<string>();
    // For the no-target DO NOTHING path: the planned inserts' keys/prefixes (the arbiter path uses
    // proposedArb instead).
    const insPk = new Set<string>();
    const insPrefixes = uniqIdx.map(() => new Set<string>());

    const checkEnv = (): EvalEnv => ({
      params: [],
      outer: [],
      runSubquery: (p, o) => this.execQueryPlan(p, o, [], EMPTY_CTE_CTX),
      seam: this.session.seam,
      rng,
      ctes: EMPTY_CTE_CTX,
      exec: this,
    });

    for (const values of rows) {
      // Build + coerce the candidate row, then CHECK — the INSERT per-row order (NOT NULL before
      // CHECK before conflict; constraints.md §4.4).
      const row: Row = new Array(n);
      for (let i = 0; i < n; i++) {
        const col = table.columns[i]!;
        const p = provided[i]!;
        const candidate: Value =
          p >= 0 ? values[p]! : this.evalDefault(col, defaultExprs[i]!, rng, meter);
        try {
          row[i] = coerceForStore(
            candidate,
            colTypes[i]!,
            col.decimal,
            col.varcharLen,
            col.notNull,
            col.name,
          );
        } catch (e) {
          // Stamp the target relation onto a column-store failure (23502/22003/22001) — the
          // relation is in scope here, not inside the coercion (spec/design/error-fields.md §4).
          throw stampTable(e, table.name);
        }
      }
      if (checks.length > 0) {
        meter.guard();
        evalChecks(checks, relation, row, checkEnv(), meter);
      }

      if (plan.arb === null) {
        // No-target DO NOTHING: skip on ANY uniqueness conflict (committed OR an earlier planned
        // insert); else insert (upsert.md §2/§3).
        const pkk = pk.length > 0 ? encodePkKey(table, pk, colls, row) : null;
        let conflictHit = this.rowConflictsCommitted(store, table, pk, colls, rindexes, row);
        if (!conflictHit && pkk !== null && insPk.has(pkk.join(","))) conflictHit = true;
        if (!conflictHit) {
          for (let u = 0; u < uniqIdx.length; u++) {
            const prefix = this.indexPrefix(table.columns, colls, rindexes[uniqIdx[u]!]!, row);
            if (prefix !== null && insPrefixes[u]!.has(prefix.join(","))) {
              conflictHit = true;
              break;
            }
          }
        }
        if (conflictHit) continue; // skip
        if (pkk !== null) insPk.add(pkk.join(","));
        for (let u = 0; u < uniqIdx.length; u++) {
          const prefix = this.indexPrefix(table.columns, colls, rindexes[uniqIdx[u]!]!, row);
          if (prefix !== null) insPrefixes[u]!.add(prefix.join(","));
        }
        inserts.push(row);
        continue;
      }

      // Arbiter present (DO UPDATE always; DO NOTHING with a target).
      const ak = this.arbiterProbeKey(plan.arb, table, pk, colls, rindexes, row);
      if (ak === null) {
        // A NULL-bearing arbiter key never conflicts (NULLS DISTINCT) — plain insert.
        inserts.push(row);
        continue;
      }
      const akKey = ak.join(",");
      if (proposedArb.has(akKey)) {
        // A second proposed row with the same arbiter key (§4).
        if (plan.doUpdate) {
          throw engineError(
            "cardinality_violation",
            "ON CONFLICT DO UPDATE command cannot affect row a second time",
          );
        }
        continue; // DO NOTHING → skip
      }
      proposedArb.add(akKey);
      const existing = this.arbiterExisting(plan.arb, readStore, table, ak);
      if (existing === null) {
        // No committed conflict on the arbiter → insert (a non-arbiter conflict is caught by the
        // end-state validation below).
        inserts.push(row);
        continue;
      }
      if (!plan.doUpdate) continue; // DO NOTHING → skip
      // DO UPDATE: the combined eval row [existing | proposed] the §5 scope resolves against.
      const combined = existing.row.concat(row);
      const env: EvalEnv = {
        params,
        outer: [],
        runSubquery: (p, o) => this.execQueryPlan(p, o, params, EMPTY_CTE_CTX),
        seam: this.session.seam,
        rng,
        ctes: EMPTY_CTE_CTX,
        exec: this,
      };
      // An optional WHERE that is not TRUE skips the update (existing row unchanged, not returned)
      // — but the arbiter key was already proposed, so a second row still trips §4.
      if (plan.filter !== null && !isTrue(evalExpr(plan.filter, combined, env, meter))) continue;
      const newRow = existing.row.slice();
      for (const ap of plan.assignments) {
        try {
          newRow[ap.idx] = checkAssign(ap, evalExpr(ap.source, combined, env, meter));
        } catch (e) {
          throw stampTable(e, table.name);
        }
      }
      if (checks.length > 0) evalChecks(checks, relation, newRow, checkEnv(), meter);
      updates.push({ key: existing.key, newRow, oldRow: existing.row });
    }

    // End-state validation (upsert.md §3), before any write. PRIMARY KEY: each insert's key must be
    // free in the committed store and distinct from the other inserts — a collision is 23505 on
    // <table>_pkey (a non-arbiter PK conflict).
    if (pk.length > 0 && inserts.length > 0) {
      const seen = new Set<string>();
      for (const row of inserts) {
        const k = encodePkKey(table, pk, colls, row);
        const ks = k.join(",");
        if (readStore.get(k) !== undefined || seen.has(ks)) {
          throw uniqueViolation(table.name, pkeyName(table.name));
        }
        seen.add(ks);
      }
    }

    // UNIQUE indexes: validate the END STATE over the updated NEW rows + the inserted rows
    // (indexes.md §8 — the same end-state model as UPDATE).
    if (uniqIdx.length > 0 && (inserts.length > 0 || updates.length > 0)) {
      const rewritten = new Set<string>(updates.map((u) => u.key.join(",")));
      const newRows = updates.map((u) => u.newRow).concat(inserts);
      for (const ix of uniqIdx) {
        const def = table.indexes[ix]!;
        const istore = this.lkpIndexStore(def.name.toLowerCase());
        const batch = new Set<string>();
        for (const newRow of newRows) {
          const prefix = this.indexPrefix(table.columns, colls, rindexes[ix]!, newRow);
          if (prefix === null) continue;
          const k = prefix.join(",");
          const conflict =
            batch.has(k) ||
            istore
              .rangeEntries(uniqueProbeBound(prefix))
              .some((e) => !rewritten.has(e.key.slice(prefix.length).join(",")));
          if (conflict) {
            throw uniqueViolation(table.name, def.name);
          }
          batch.add(k);
        }
      }
    }

    // FOREIGN KEY child-side (constraints.md §6.4): each inserted row, and each updated row that
    // assigned an FK local column, must reference an existing parent key — the committed parent
    // state plus (for a self-reference) the statement's end state.
    const assigned = new Set<number>(plan.doUpdate ? plan.assignments.map((a) => a.idx) : []);
    const fks = this.table(relation)?.fks ?? [];
    for (const fk of fks) {
      const parent = this.table(fk.refTable);
      if (parent === undefined) continue;
      // The probe matches the parent's stored key, so a collated parent key column uses the
      // PARENT's collation (§2.12).
      const parentColls = this.columnCollations(parent.columns);
      const checkUpdates = fk.columns.some((c) => assigned.has(c));
      const batch = new Set<string>();
      if (fk.refTable.toLowerCase() === relation.toLowerCase()) {
        for (const row of inserts) {
          const p = fkProbe(fk, parent, parentColls, row, fk.refColumns);
          if (p !== null) batch.add(fkProbeBytes(p).join(","));
        }
        for (const u of updates) {
          const p = fkProbe(fk, parent, parentColls, u.newRow, fk.refColumns);
          if (p !== null) batch.add(fkProbeBytes(p).join(","));
        }
      }
      const toCheck = inserts.concat(checkUpdates ? updates.map((u) => u.newRow) : []);
      for (const row of toCheck) {
        const probe = fkProbe(fk, parent, parentColls, row, fk.columns);
        if (probe === null) continue; // a NULL local column → exempt (MATCH SIMPLE)
        if (batch.has(fkProbeBytes(probe).join(","))) continue;
        if (!this.fkProbeHits(probe, fk.refTable)) {
          throw fkViolationInsert(relation, fk.name);
        }
      }
    }

    // FOREIGN KEY parent-side (constraints.md §6.5): an updated referenced row must not strand a
    // child (only a referenced UNIQUE column is at risk; inserts add rows, never strand a child).
    const referencers = this.fkReferencers(relation);
    if (referencers.length > 0 && updates.length > 0) {
      const parent = this.table(relation)!;
      const updatedKeys = new Set<string>(updates.map((u) => u.key.join(",")));
      for (const { childTable, fk } of referencers) {
        // parent is the insert target itself, so its key columns use colls (§2.12).
        const newPresent = new Set<string>();
        for (const u of updates) {
          const p = fkProbe(fk, parent, colls, u.newRow, fk.refColumns);
          if (p !== null) newPresent.add(fkProbeBytes(p).join(","));
        }
        for (const u of updates) {
          const oldProbe = fkProbe(fk, parent, colls, u.oldRow, fk.refColumns);
          if (oldProbe === null) continue;
          const newProbe = fkProbe(fk, parent, colls, u.newRow, fk.refColumns);
          if (newProbe !== null && bytesEq(fkProbeBytes(newProbe), fkProbeBytes(oldProbe)))
            continue;
          if (newPresent.has(fkProbeBytes(oldProbe).join(","))) continue;
          if (this.fkChildReferences(childTable, fk, parent, fkProbeBytes(oldProbe), updatedKeys)) {
            throw fkViolationDelete(parent.name, fk.name, childTable);
          }
        }
      }
    }

    // Meter the disposition-plan compression attempts (value_compress, cost.md §3) for the inserted
    // + updated rows; enforce the ceiling BEFORE phase 2 writes (all-or-nothing).
    let cunits = 0n;
    const placeholder = new Uint8Array(8);
    for (const row of inserts) {
      const kb = pk.length > 0 ? encodePkKey(table, pk, colls, row) : placeholder;
      cunits += BigInt(store.writeCompressUnits(kb, row));
    }
    for (const u of updates) cunits += BigInt(store.writeCompressUnits(u.key, u.newRow));
    meter.charge(COSTS.valueCompress * cunits);
    meter.guard();

    // RETURNING (grammar.md §32): project the affected rows — inserts (old side all-NULL) then
    // updates (old side the pre-update existing row) — after all validation, before any write.
    let returned: Value[][] | null = null;
    if (returning !== null) {
      const nullRow: Row = table.columns.map(() => nullValue());
      const prows: Row[] = [];
      const olds: Row[] = [];
      for (const row of inserts) {
        prows.push(row);
        olds.push(nullRow);
      }
      for (const u of updates) {
        prows.push(u.newRow);
        olds.push(u.oldRow);
      }
      returned = this.projectReturning(returning, prows, olds, params, ctes, meter);
    }

    const affected = inserts.length + updates.length;

    // Precompute all secondary-index entries in a pass BEFORE any write (evaluating every expression
    // key — an error aborts before any write): each inserted row's entry PREFIXES (empty suffix; phase
    // 2 appends its storage key — the rowid is allocated there) and each updated row's old/new entry
    // sets (keys already known).
    const insertPrefixes: Uint8Array[][][] = inserts.map((row) =>
      rindexes.map((rindex) =>
        this.indexEntries(table.columns, colls, rindex, new Uint8Array(0), row),
      ),
    );
    const indexMoves: { removals: Uint8Array[]; insertions: Uint8Array[] }[][] = table.indexes.map(
      () => [],
    );
    for (const u of updates) {
      for (let k = 0; k < table.indexes.length; k++) {
        const oldEks = this.indexEntries(table.columns, colls, rindexes[k]!, u.key, u.oldRow);
        const newEks = this.indexEntries(table.columns, colls, rindexes[k]!, u.key, u.newRow);
        const removals = bytesDiff(oldEks, newEks);
        const insertions = bytesDiff(newEks, oldEks);
        if (removals.length > 0 || insertions.length > 0)
          indexMoves[k]!.push({ removals, insertions });
      }
    }
    // Phase 2 — every row validated. Insert the new rows (rowid alloc for a no-PK table; append each
    // row's storage key to its precomputed entry prefixes), then replace the updated rows (entries moved).
    const indexAdds: Uint8Array[][] = table.indexes.map(() => []);
    for (let ri = 0; ri < inserts.length; ri++) {
      const row = inserts[ri]!;
      const key =
        pk.length > 0 ? encodePkKey(table, pk, colls, row) : encodeInt("i64", store.allocRowid());
      for (let k = 0; k < table.indexes.length; k++) {
        for (const p of insertPrefixes[ri]![k]!) indexAdds[k]!.push(concatBytes([p, key]));
      }
      if (!store.insert(key, row)) throw new Error("pre-validated INSERT key must be unique");
    }
    for (const u of updates) store.replace(u.key, u.newRow);
    for (let k = 0; k < table.indexes.length; k++) {
      const istore = this.writeIndexStore(table.indexes[k]!.name.toLowerCase());
      for (const ek of indexAdds[k]!) {
        if (!istore.insert(ek, []))
          throw new Error("index entry keys are unique (storage-key suffix)");
      }
      for (const mv of indexMoves[k]!) {
        for (const oldEk of mv.removals) istore.remove(oldEk);
        for (const newEk of mv.insertions) {
          if (!istore.insert(newEk, []))
            throw new Error("index entry keys are unique (storage-key suffix)");
        }
      }
    }
    return { affected, returned };
  }

  // resolveReturning resolves a RETURNING item list against the target table's one-relation
  // scope (grammar.md §32): aggregates are 42803 (the non-collecting AggCtx), subqueries
  // resolve (and may correlate against the returned row), output names follow §8. Returns the
  // projection nodes, names, and the canonical type names (Outcome columnTypes — conformance.md §7).
  // The scope is the RETURNING scope (Scope.returning — the table at offset 0 plus the
  // old/new qualifier-only pseudo-relations over the [base | other] projection row, with
  // baseIsOld true for DELETE).
  private resolveReturning(
    table: Table,
    items: SelectItems,
    baseIsOld: boolean,
    ctes: CteBinding[],
    ptypes: ParamTypes,
  ): { nodes: RExpr[]; names: string[]; types: string[] } {
    const scope = Scope.returning(this, table, baseIsOld);
    scope.ctes = ctes;
    const { nodes, names, types } = resolveProjections(
      scope,
      items,
      { collecting: false, groupKeys: [], specs: [] },
      ptypes,
    );
    return { nodes, names, types: typeNames(types) };
  }

  // projectReturning evaluates a resolved RETURNING projection over the affected rows
  // (grammar.md §32, cost.md §3): per returned row, guard the ceiling, charge one
  // row_produced, then evaluate each item — metered expression work, exactly a SELECT's
  // projection (a correlated subquery re-runs here, its outer reference reading the row being
  // returned). Callers run this after all validation and BEFORE any write.
  // The evaluation row is the concatenation [base | other] the RETURNING scope resolved
  // against: others[i] is the row's opposite version (UPDATE's old rows), null the all-NULL
  // row (INSERT's old side, DELETE's new side).
  private projectReturning(
    nodes: RExpr[],
    rows: Row[],
    others: Row[] | null,
    params: Value[],
    ctes: CteCtx,
    meter: Meter,
  ): Value[][] {
    const env: EvalEnv = {
      params,
      outer: [],
      runSubquery: (p, o) => this.execQueryPlan(p, o, params, ctes),
      seam: this.session.seam,
      rng: new StmtRng(),
      ctes,
      exec: this,
    };
    const out: Value[][] = [];
    rows.forEach((row, i) => {
      meter.guard();
      meter.charge(COSTS.rowProduced);
      const combined = row.concat(others !== null ? others[i]! : row.map(() => nullValue()));
      out.push(nodes.map((node) => evalExpr(node, combined, env, meter)));
    });
    return out;
  }

  // executeDelete resolves the table and optional predicate, collects the keys of
  // matching rows (only a TRUE predicate matches — Kleene), then removes them. No WHERE
  // deletes every row. Keys are collected before mutating.
  private executeDelete(del: Delete, params: Value[], ctx: CteCtx): Outcome {
    // A catalog relation is read-only (introspection.md §5): a DML target naming one is 42809,
    // checked by NAME before qualifier validation (the built-in resolves in every database).
    checkCatalogRelWrite(del.table);
    // A write to a READ-ONLY host attachment is 25006 before any I/O — checked BEFORE the qualifier
    // existence gate so a read-only attachment refuses the write deterministically (attached-databases.md §4).
    this.checkAttachmentWritable(del.db);
    this.checkTableQualifier(del.db, del.table); // attached-databases.md §3
    const table = this.lkpTableScoped(del.db, del.table); // scope-aware temp-first (temp-tables.md §3)
    if (!table) {
      throw engineError("undefined_table", "table does not exist: " + del.table);
    }
    // Refuse the write if any collated key is version-skewed (slice 2d, collation.md §12, XX002): a
    // DELETE must locate + remove a stored key, which a skewed encoding cannot match.
    this.ensureCollationsWritable(table.columns);
    // Per-column frozen collations for the collated text key form (§2.12) — indexes both the FK
    // parent-side probe (parent is this table) and the index-entry path.
    const colls = this.columnCollations(table.columns);
    // DELETE is single-table; resolve its WHERE against a one-relation scope. The RETURNING
    // projection resolves after it (PostgreSQL's analysis order), against the same scope
    // (grammar.md §32). The statement's CTE bindings (writable-cte.md) are visible so a WHERE /
    // RETURNING sublink may reference an earlier CTE.
    const scope = Scope.single(this, table);
    scope.ctes = ctx.bindings;
    const ptypes = new ParamTypes();
    let filter = del.filter ? resolveBooleanFilter(scope, del.filter, ptypes) : null;
    const ret =
      del.returning !== null
        ? this.resolveReturning(table, del.returning, true, ctx.bindings, ptypes)
        : null;
    const bound = bindParams(params, ptypes.finalize());

    // Fold globally-uncorrelated WHERE subqueries once (their cost is added a single time —
    // spec/design/grammar.md §26, cost.md §3); a correlated one stays and re-runs per row via the
    // per-row outer environment below (it pushes the current row, so `target.col` reads it). The
    // uncorrelated execution reads the pre-DELETE snapshot (keys are collected before mutating).
    // Each scanned row and each filter evaluation accrues cost (CLAUDE.md §13; cost.md §3).
    const meter = this.session.newMeter();
    if (filter !== null) {
      const cost = { value: 0n };
      filter = this.foldUncorrelatedInRExpr(filter, bound, ctx, cost);
      meter.charge(cost.value);
    }
    // Uncorrelated subqueries in the RETURNING list fold once (cost.md §3), reading the
    // pre-statement snapshot (grammar.md §32).
    if (ret !== null) {
      const cost = { value: 0n };
      ret.nodes = ret.nodes.map((node) => this.foldUncorrelatedInRExpr(node, bound, ctx, cost));
      meter.charge(cost.value);
    }
    const env: EvalEnv = {
      params: bound,
      outer: [],
      runSubquery: (p, o) => this.execQueryPlan(p, o, bound, ctx),
      seam: this.session.seam,
      rng: new StmtRng(),
      ctes: ctx,
      exec: this,
    };
    // The SCAN reads the visible snapshot (the read pin under a data-modifying WITH — writable-cte.md
    // §2; else working == read-your-writes); the phase-2 REMOVAL writes the transaction's working set.
    const store = this.lkpStoreScoped(del.db, del.table);
    // matched collects (key, row) pairs before mutating; the rows feed phase 2's
    // index-entry removal (indexed columns are fixed-width and always resident).
    const matched: { key: Uint8Array; row: Row }[] = [];
    // DELETE's touched set (cost.md §3): the filter's columns plus the RETURNING items'
    // OLD-side references — a returned old value is a logical read of the dropped row,
    // while a new.col is the constant NULL row and reads nothing. The RETURNING mask spans
    // the [base | other] projection row (2 x ncols); only the base (old) half maps back to
    // storage. A bare DELETE still charges no chain/decompress units at all.
    const mask: boolean[] = new Array(table.columns.length).fill(false);
    if (filter !== null) collectTouched(filter, 0, mask);
    if (ret !== null) {
      const retMask: boolean[] = new Array(2 * table.columns.length).fill(false);
      for (const node of ret.nodes) collectTouched(node, 0, retMask);
      for (let i = 0; i < mask.length; i++) {
        if (retMask[i]) mask[i] = true;
      }
    }
    // A primary-key bound seeks/ranges instead of walking the whole B-tree (cost.md §3 "bounded
    // scan"); an empty bound deletes nothing — with RETURNING that is still a query result
    // (empty rows), never a bare statement (grammar.md §32). The whole WHERE stays the
    // residual filter below. page_read per visited node (block, before the rows), then
    // storageRowRead per scanned row.
    // A host-attached target full-scans this slice (attached-databases.md §8) — a bounded scan would
    // resolve its index store through the unscoped funnel. The whole WHERE stays the residual filter.
    const attach = isAttachmentScope(del.db);
    const mb = attach ? null : mutationPkBound(table, filter, this.readSnap());
    let entries: Entry[] | null;
    let overlap: number;
    let slabs: number;
    if (mb !== null) {
      ({ entries, overlap, slabs } = scanEntries(store, mb, bound, mask));
    } else if (attach) {
      const u = store.scanWithUnits(mask);
      entries = u.entries;
      overlap = u.pages;
      slabs = u.slabs;
    } else {
      // GIN bound (gin.md §6): when no PK bound applies, a GIN-accelerable WHERE conjunct bounds the
      // delete's target-row scan through the index instead of a full scan (PK-then-GIN-then-full; the
      // ordered-index bound stays SELECT-only). readSnap()==working() during a mutation (tx open), so
      // this reads the read-your-writes state. ginEntry charged inside; the block below.
      const gb = detectGinBound(filter, table.indexes, table.columns, 0);
      const gtb = gb === null ? detectGistBound(filter, table.indexes, table.columns, 0) : null;
      const ks = gb === null && gtb === null ? pkSetFor(table, filter, this.readSnap()) : null;
      if (gb !== null) {
        const m = filter !== null ? ginMatch(filter, gb.colGlobal) : null;
        const r = this.ginBoundRows(del.table, gb, m?.query ?? null, env, meter, mask);
        entries = r.entries;
        overlap = r.pages;
        slabs = r.slabs;
      } else if (gtb !== null) {
        // GiST-bounded delete (gist.md §5): gather candidates by descending the resident R-tree; the
        // &&/@> predicate stays the residual filter re-applied per candidate below.
        const q = filter !== null ? gistQueryOperand(filter, gtb) : null;
        const r = this.gistBoundRows(del.table, gtb, q, env, meter, mask);
        entries = r.entries;
        overlap = r.pages;
        slabs = r.slabs;
      } else if (ks !== null) {
        // Merged PK point-set delete (cost.md §3 "OR / IN-list"): a union of point probes over the
        // distinct sorted keys; whole rows so index entries can be removed. The predicate stays the
        // residual filter below.
        const r = this.pkKeySetRows(store, ks, bound, [], mask, []);
        entries = r.entries;
        overlap = r.pages;
        slabs = r.slabs;
      } else {
        const u = store.scanWithUnits(mask);
        entries = u.entries;
        overlap = u.pages;
        slabs = u.slabs;
      }
    }
    if (entries === null)
      return dmlOutcome(ret?.names ?? null, ret?.types ?? null, null, 0, meter.accrued); // empty bound
    meter.charge(COSTS.pageRead * BigInt(overlap) + COSTS.valueDecompress * BigInt(slabs));
    for (const e of entries) {
      meter.guard(); // enforce the cost ceiling per scanned row (CLAUDE.md §13)
      // A WHERE arithmetic can throw (22003/22012); the throw propagates naturally.
      meter.charge(COSTS.storageRowRead);
      // Materialize the filter's columns if the lazy load left them unfetched — exactly the
      // touched set the block above charged (large-values.md §14).
      const row = store.resolveColumns(e.row, mask);
      if (filter === null || isTrue(evalExpr(filter, row, env, meter))) {
        // The FK parent-side probe + index-entry removal below read this row's key/index columns
        // directly; resolve its inline-deferred values (lazy-record.md §5b — a key column is always
        // inline, so cost-free) so those paths see resident values.
        matched.push({ key: e.key, row: store.resolveInlineColumns(row) });
      }
    }

    // FOREIGN KEY parent-side (constraints.md §6.5): a DELETE must not strand a child. For each
    // inbound FK, every deleted row's referenced tuple disappears (the referenced columns are
    // unique, so each is unique to its row); if a child still references it → 23503. Unmetered,
    // before phase 2 (all-or-nothing). For a self-reference the child IS this table, whose end
    // state excludes the rows being deleted.
    const delReferencers = this.fkReferencers(del.table);
    if (delReferencers.length > 0) {
      const parent = this.table(del.table)!;
      const deletedKeys = new Set<string>(matched.map((m) => m.key.join(",")));
      const empty = new Set<string>();
      for (const { childTable, fk } of delReferencers) {
        const exclude = childTable.toLowerCase() === del.table.toLowerCase() ? deletedKeys : empty;
        for (const m of matched) {
          // parent is the delete target itself, so its key columns use colls (§2.12).
          const probe = fkProbe(fk, parent, colls, m.row, fk.refColumns);
          if (probe === null) continue; // a NULL referenced value cannot be referenced (MATCH SIMPLE)
          if (this.fkChildReferences(childTable, fk, parent, fkProbeBytes(probe), exclude)) {
            throw fkViolationDelete(parent.name, fk.name, childTable);
          }
        }
      }
    }

    // The RETURNING projection (grammar.md §32, cost.md §3): evaluate over the matched rows'
    // OLD values before anything is removed — subqueries in the list read the pre-statement
    // snapshot, and a 54P01 here deletes nothing (all-or-nothing).
    const returned =
      ret !== null
        ? this.projectReturning(
            ret.nodes,
            matched.map((m) => m.row),
            null,
            bound,
            ctx,
            meter,
          )
        : null;
    // Precompute the entries to remove for each index in a pass (evaluating any expression key
    // against the stored row) BEFORE the removals below. Resolve the table's indexes once;
    // toRemove[kx] is index kx's entries (rindexes order = indexes order).
    const rindexes = this.resolveTableIndexes(table);
    const toRemove: Uint8Array[][] = rindexes.map((rindex) => {
      const acc: Uint8Array[] = [];
      for (const m of matched)
        acc.push(...this.indexEntries(table.columns, colls, rindex, m.key, m.row));
      return acc;
    });
    // Phase 2: remove the rows, then their secondary-index entries (indexes.md §4 —
    // unmetered write work; an index removal cannot fail).
    const writeStore = this.writeStoreScoped(del.db, del.table);
    for (const m of matched) writeStore.remove(m.key);
    for (let kx = 0; kx < table.indexes.length; kx++) {
      const def = table.indexes[kx]!;
      const istore = this.writeIndexStoreScoped(del.db, def.name.toLowerCase());
      for (const ek of toRemove[kx]!) istore.remove(ek);
    }
    return dmlOutcome(
      ret?.names ?? null,
      ret?.types ?? null,
      returned,
      matched.length,
      meter.accrued,
    );
  }

  // executeUpdate is two-phase / all-or-nothing: phase 1 builds and type-checks every
  // matching row's new values (assignments evaluate against the OLD row, so
  // `SET a = b, b = a` swaps); a 22003/23502 aborts with no writes. Phase 2 applies.
  // Assigning a PRIMARY KEY column RE-KEYS the row (its storage key is recomputed and the
  // row moves, §11 step 6); the new keys are validated against the statement's end state —
  // a collision with another row's key traps 23505 (<table>_pkey). A duplicate target
  // column traps 42701. No WHERE updates every row.
  private executeUpdate(upd: Update, params: Value[], ctx: CteCtx): Outcome {
    // A catalog relation is read-only (introspection.md §5): a DML target naming one is 42809,
    // checked by NAME before qualifier validation (the built-in resolves in every database).
    checkCatalogRelWrite(upd.table);
    // A write to a READ-ONLY host attachment is 25006 before any I/O — checked BEFORE the qualifier
    // existence gate so a read-only attachment refuses the write deterministically (attached-databases.md §4).
    this.checkAttachmentWritable(upd.db);
    this.checkTableQualifier(upd.db, upd.table); // attached-databases.md §3
    const table = this.lkpTableScoped(upd.db, upd.table); // scope-aware temp-first (temp-tables.md §3)
    if (!table) {
      throw engineError("undefined_table", "table does not exist: " + upd.table);
    }
    // Refuse the write if any collated key is version-skewed (slice 2d, collation.md §12, XX002): an
    // UPDATE re-encodes + re-places keys, which a skewed encoding would corrupt.
    this.ensureCollationsWritable(table.columns);
    // Per-column frozen collations for the collated text key form (§2.12) — indexes both the FK
    // probe and the index-entry move path.
    const colls = this.columnCollations(table.columns);
    // Resolve the table's indexes once (column ordinals + resolved expression keys — indexes.md §4),
    // parallel to table.indexes; the unique end-state validation and the entry-move computation below
    // evaluate any expression key through it (unmetered).
    const rindexes = this.resolveTableIndexes(table);

    // UPDATE is single-table; the RHS / WHERE resolve against a one-relation scope so the
    // shared resolver serves it too (a qualified `WHERE t.a` against the sole table is fine).
    // The statement's CTE bindings (writable-cte.md) are visible so a SET / WHERE / RETURNING
    // sublink may reference an earlier CTE.
    const scope = Scope.single(this, table);
    scope.ctes = ctx.bindings;
    const ptypes = new ParamTypes();

    // Resolve assignments up front (fail fast, deterministic). Assigning a key member is
    // allowed and re-keys the row — the storage key is derived from the PK (constraints.md §3),
    // so a new key is recomputed and the row is moved in phase 2.
    // UPDATE SET col = DEFAULT reuses INSERT's once-per-statement resolution of expression
    // defaults. Constant/no defaults become constant RExpr nodes below, so applying them is free;
    // expression defaults evaluate once per matched row through the UPDATE meter and statement RNG.
    const defaultExprs = upd.assignments.some((a) => a.isDefault)
      ? this.resolveDefaultExprs(table)
      : [];
    const pkMembers = pkIndices(table);
    const plans: AssignPlan[] = [];
    for (const a of upd.assignments) {
      const idx = columnIndex(table, a.column);
      if (idx < 0) {
        throw engineError("undefined_column", "column does not exist: " + a.column);
      }
      // A GENERATED ALWAYS identity column can only be set to DEFAULT (sequences.md §13.4).
      // An ordinary assignment is 428C9; DEFAULT is allowed and advances the owned sequence.
      if (table.columns[idx]!.identity === "always" && !a.isDefault) {
        throw engineError("generated_always", `column ${a.column} can only be updated to DEFAULT`);
      }
      for (const p of plans) {
        if (p.idx === idx) {
          throw engineError("duplicate_column", "column " + a.column + " assigned more than once");
        }
      }
      const col = table.columns[idx]!;
      if (a.isDefault) {
        const source = defaultExprs[idx] ?? valueToRExpr(col.default ?? nullValue());
        if (col.type.kind === "scalar") {
          plans.push({
            idx,
            name: col.name,
            target: col.type.scalar,
            decimal: col.decimal,
            varcharLen: col.varcharLen,
            notNull: col.notNull,
            source,
          });
        } else {
          plans.push({
            idx,
            name: col.name,
            target: "i32",
            decimal: col.decimal,
            varcharLen: col.varcharLen,
            notNull: col.notNull,
            source,
            colType: scope.catalog.colTypeOf(col.type),
          });
        }
        continue;
      }
      // Updating a composite-typed column lands in a later slice (anonymous-record → named-composite
      // assignment coercion — composite.md §12); reject it for now (0A000). Range and array columns
      // ARE updatable (ranges.md §4 / array.md §4), via the container path below.
      if (col.type.kind === "composite") {
        throw engineError(
          "feature_not_supported",
          "updating composite column " + a.column + " is not supported yet",
        );
      }
      if (col.type.kind === "scalar") {
        const targetScalar = col.type.scalar;
        // The RHS is a general expression evaluated against the OLD row; a literal operand
        // adapts to the target column's type. The result must be assignable to the column's
        // family (integer/decimal/text or NULL; never boolean; decimal→int is explicit only).
        const { node, type } = resolve(
          scope,
          a.value,
          targetScalar,
          { collecting: false, groupKeys: [], specs: [] },
          ptypes,
        );
        requireAssignable(type, targetScalar, a.column);
        plans.push({
          idx,
          name: col.name,
          target: targetScalar,
          decimal: col.decimal,
          varcharLen: col.varcharLen,
          notNull: col.notNull,
          source: node,
        });
      } else {
        // A range or array column: the RHS adapts (a bare string literal via range_in/array_in, a
        // bare NULL to the typed NULL) or must resolve to the SAME container type. Stored through
        // coerceForStore (carried on the plan as colType).
        const node = resolveContainerAssign(
          scope,
          col,
          a.value,
          { collecting: false, groupKeys: [], specs: [] },
          ptypes,
        );
        plans.push({
          idx,
          name: col.name,
          target: "i32", // unused (colType drives checkAssign)
          decimal: col.decimal,
          varcharLen: col.varcharLen,
          notNull: col.notNull,
          source: node,
          colType: scope.catalog.colTypeOf(col.type),
        });
      }
    }
    // A re-keying UPDATE assigns at least one key member: each matched row's storage key is
    // recomputed (phase 1) and the row is moved (phase 2). An UPDATE that touches no key member
    // keeps every storage key in place — the in-place fast path (writeStore.replace).
    const pkChanged = pkMembers.length > 0 && plans.some((p) => pkMembers.includes(p.idx));

    let filter = upd.filter ? resolveBooleanFilter(scope, upd.filter, ptypes) : null;
    // The RETURNING projection resolves last (PostgreSQL's analysis order), against the same
    // one-relation scope; it evaluates each matched row's NEW values (grammar.md §32).
    const ret =
      upd.returning !== null
        ? this.resolveReturning(table, upd.returning, false, ctx.bindings, ptypes)
        : null;
    // The CHECK constraints, resolved once per statement in evaluation (name) order;
    // phase 1 evaluates them on each post-assignment row (constraints.md §4.4).
    const checks = this.resolveChecks(table);
    // All assignment RHSs + the WHERE + the RETURNING are resolved: finalize + bind before
    // any scan.
    const bound = bindParams(params, ptypes.finalize());

    // Fold globally-uncorrelated subqueries (in any assignment RHS or the WHERE) once — their
    // cost is added a single time (grammar.md §26, cost.md §3); a correlated one stays and re-runs
    // per row via the outer environment (which pushes the current OLD row). The uncorrelated
    // execution reads the pre-UPDATE snapshot (phase 1 only reads; phase 2 writes).
    //
    // Phase 1: build + validate every matching row's new values; no writes yet. Each scanned row,
    // the filter, and each assignment RHS accrue cost (the phase-2 writes do not — cost.md §3).
    const meter = this.session.newMeter();
    const foldCost = { value: 0n };
    for (const p of plans) p.source = this.foldUncorrelatedInRExpr(p.source, bound, ctx, foldCost);
    if (filter !== null) filter = this.foldUncorrelatedInRExpr(filter, bound, ctx, foldCost);
    if (ret !== null) {
      ret.nodes = ret.nodes.map((node) => this.foldUncorrelatedInRExpr(node, bound, ctx, foldCost));
    }
    meter.charge(foldCost.value);
    const env: EvalEnv = {
      params: bound,
      outer: [],
      runSubquery: (p, o) => this.execQueryPlan(p, o, bound, ctx),
      seam: this.session.seam,
      rng: new StmtRng(),
      ctes: ctx,
      exec: this,
    };
    // The SCAN + spilled-value reads + compress-cost weigh the visible snapshot (the read pin under a
    // data-modifying WITH — writable-cte.md §2; else working == read-your-writes); the phase-2 REPLACE
    // writes the transaction's working set.
    const store = this.lkpStoreScoped(upd.db, upd.table);
    // Each entry is (old key, new key, new row, OLD row) — the old row feeds the index
    // maintenance and the new key the re-keying; for a non-PK UPDATE the new key equals the old.
    const updates: { key: Uint8Array; newKey: Uint8Array; row: Row; oldRow: Row }[] = [];
    // UPDATE's touched set (cost.md §3): the filter's columns, every assignment SOURCE's, and
    // the RETURNING items' MINUS the assigned columns — an assigned column's returned value is
    // the freshly computed one, not a storage read. The rewrite re-stores an untouched spilled
    // value without logically re-reading it (large-values.md §14).
    const mask: boolean[] = new Array(table.columns.length).fill(false);
    if (filter !== null) collectTouched(filter, 0, mask);
    for (const p of plans) collectTouched(p.source, 0, mask);
    // The RETURNING mask spans the [base | other] projection row (new at 0, old at ncols):
    // the NEW side joins minus the assigned columns (an assigned column's returned value is
    // the freshly computed one, not a storage read); the OLD side joins unconditionally
    // (old.col is always a storage read, assigned or not).
    if (ret !== null) {
      const ncols = table.columns.length;
      const retMask: boolean[] = new Array(2 * ncols).fill(false);
      for (const node of ret.nodes) collectTouched(node, 0, retMask);
      for (let i = 0; i < ncols; i++) {
        if (retMask[i] && !plans.some((p) => p.idx === i)) mask[i] = true; // new side
        if (retMask[ncols + i]) mask[i] = true; // old side — always a storage read
      }
    }
    // A primary-key bound seeks/ranges instead of walking the whole B-tree (cost.md §3 "bounded
    // scan"); an empty bound updates nothing — with RETURNING that is still a query result
    // (empty rows), never a bare statement (grammar.md §32). The whole WHERE stays the
    // residual filter below. page_read per visited node (block, before the rows), then
    // storageRowRead per scanned row.
    // A host-attached target full-scans this slice (attached-databases.md §8) — a bounded scan would
    // resolve its index store through the unscoped funnel. The whole WHERE stays the residual filter.
    const attach = isAttachmentScope(upd.db);
    const mb = attach ? null : mutationPkBound(table, filter, this.readSnap());
    let entries: Entry[] | null;
    let overlap: number;
    let slabs: number;
    if (mb !== null) {
      ({ entries, overlap, slabs } = scanEntries(store, mb, bound, mask));
    } else if (attach) {
      const u = store.scanWithUnits(mask);
      entries = u.entries;
      overlap = u.pages;
      slabs = u.slabs;
    } else {
      // GIN bound (gin.md §6): when no PK bound applies, a GIN-accelerable WHERE conjunct bounds the
      // update's target-row scan through the index over the PRE-update state (PK-then-GIN-then-full;
      // the ordered-index bound stays SELECT-only). ginEntry charged inside; the block below.
      const gb = detectGinBound(filter, table.indexes, table.columns, 0);
      const gtb = gb === null ? detectGistBound(filter, table.indexes, table.columns, 0) : null;
      const ks = gb === null && gtb === null ? pkSetFor(table, filter, this.readSnap()) : null;
      if (gb !== null) {
        const m = filter !== null ? ginMatch(filter, gb.colGlobal) : null;
        const r = this.ginBoundRows(upd.table, gb, m?.query ?? null, env, meter, mask);
        entries = r.entries;
        overlap = r.pages;
        slabs = r.slabs;
      } else if (gtb !== null) {
        // GiST-bounded update (gist.md §5): gather candidates by descending the resident R-tree over
        // the PRE-update state; the &&/@> predicate stays the residual filter re-applied per candidate.
        const q = filter !== null ? gistQueryOperand(filter, gtb) : null;
        const r = this.gistBoundRows(upd.table, gtb, q, env, meter, mask);
        entries = r.entries;
        overlap = r.pages;
        slabs = r.slabs;
      } else if (ks !== null) {
        // Merged PK point-set update (cost.md §3 "OR / IN-list"): a union of point probes over the
        // distinct sorted keys of the PRE-update state; whole rows. The predicate stays the residual
        // filter below.
        const r = this.pkKeySetRows(store, ks, bound, [], mask, []);
        entries = r.entries;
        overlap = r.pages;
        slabs = r.slabs;
      } else {
        const u = store.scanWithUnits(mask);
        entries = u.entries;
        overlap = u.pages;
        slabs = u.slabs;
      }
    }
    if (entries === null)
      return dmlOutcome(ret?.names ?? null, ret?.types ?? null, null, 0, meter.accrued); // empty bound
    meter.charge(COSTS.pageRead * BigInt(overlap) + COSTS.valueDecompress * BigInt(slabs));
    for (const e of entries) {
      meter.guard(); // enforce the cost ceiling per scanned row (CLAUDE.md §13)
      meter.charge(COSTS.storageRowRead);
      // Materialize the filter's + assignment sources' columns if the lazy load left them
      // unfetched — exactly the touched set the block above charged (large-values.md §14).
      const filtered = store.resolveColumns(e.row, mask);
      if (filter !== null && !isTrue(evalExpr(filter, filtered, env, meter))) continue;
      // The OLD row is retained for index-entry removal (its key/index columns are read directly
      // below); resolve its inline-deferred values (lazy-record.md §5b — a key column is always
      // inline, so cost-free) so that maintenance sees resident values.
      const row = store.resolveInlineColumns(filtered);
      const newRow = row.slice();
      for (const p of plans) {
        try {
          newRow[p.idx] = checkAssign(p, evalExpr(p.source, row, env, meter));
        } catch (e) {
          throw stampTable(e, table.name);
        }
      }
      // The rewritten row is stored fully resident: resolve any still-unfetched (untouched)
      // columns so its weight/disposition re-plan exactly as an eager writer's would —
      // unmetered, part of the rewrite like commit work (large-values.md §14).
      const resident = store.resolveAll(newRow);
      // CHECK constraints, in name order, on the post-assignment row — after the
      // assignments coerced (22003/23502 in checkAssign above), on the fully-resident row
      // (constraints.md §4.4). Every check evaluates (not only those mentioning assigned
      // columns); TRUE and NULL pass, the first FALSE aborts the statement (phase 1 —
      // nothing has been written).
      evalChecks(checks, table.name, resident, env, meter);
      // The row's NEW storage key: recomputed from the post-assignment row when a key member
      // was assigned (re-keying), else the unchanged old key.
      const newKey = pkChanged ? encodePkKey(table, pkMembers, colls, resident) : e.key;
      updates.push({ key: e.key, newKey, row: resident, oldRow: row });
    }

    // PRIMARY KEY end-state validation for a re-keying UPDATE (the storage key changed): like
    // UNIQUE (indexes.md §8) this is an END-STATE check — the new keys must be distinct from each
    // other (in-batch) and from every NON-rewritten stored key (a rewritten row's old key is
    // vacated by this statement, so a row landing on it is fine). A collision traps 23505 on the
    // PK's derived <table>_pkey name, reported BEFORE the secondary UNIQUE probes (PG reports the
    // PK first). Unmetered, phase 1.
    if (pkChanged) {
      const rewritten = new Set<string>(updates.map((u) => u.key.join(",")));
      const batch = new Set<string>();
      for (const u of updates) {
        const nk = u.newKey.join(",");
        const collides = batch.has(nk) || (store.get(u.newKey) !== undefined && !rewritten.has(nk));
        if (collides) {
          throw uniqueViolation(table.name, pkeyName(table.name));
        }
        batch.add(nk);
      }
    }

    // UNIQUE validation against the statement's END STATE (indexes.md §8 — a documented
    // PG divergence: PG checks per-row in heap order, so a transient collision like
    // `SET v = v + 1` fails there and succeeds here). Per unique index in catalog (name)
    // order, over the rewritten rows in scan (storage-key) order: the new prefixes must
    // not collide with each other (in-batch), nor with an existing entry whose suffix is
    // NOT a rewritten row's key (a rewritten row's old entry is being replaced, so it
    // cannot conflict). Unmetered validation, phase 1.
    if (updates.length > 0 && table.indexes.some((d) => d.unique)) {
      const rewritten = new Set<string>(updates.map((u) => u.key.join(",")));
      for (const rindex of rindexes) {
        if (!rindex.unique) continue;
        const istore = this.lkpIndexStoreScoped(upd.db, rindex.name.toLowerCase());
        const batch = new Set<string>();
        for (const u of updates) {
          const prefix = this.indexPrefix(table.columns, colls, rindex, u.row);
          if (prefix === null) continue;
          const k = prefix.join(",");
          const conflict =
            batch.has(k) ||
            istore
              .rangeEntries(uniqueProbeBound(prefix))
              .some((e) => !rewritten.has(e.key.slice(prefix.length).join(",")));
          if (conflict) {
            throw uniqueViolation(table.name, rindex.name);
          }
          batch.add(k);
        }
      }
    }

    // EXCLUDE end-state validation (spec/design/gist.md §7), mirroring UNIQUE's: each updated NEW row
    // must conflict with no OTHER row in the statement's END STATE — neither a STORED row that is NOT
    // being updated (probe the backing GiST tree, drop a hit whose storage key is a rewritten OLD key
    // — that row is vacated) nor another updated NEW row (pairwise). The NULL rule / empty-range
    // exempt a row. An end-state-valid swap thus succeeds where PG fails the per-row transient (the
    // documented UNIQUE end-state divergence). Unmetered, phase 1, before any write.
    if (table.exclusions.length > 0 && updates.length > 0) {
      const rewritten = new Set<string>(updates.map((u) => u.key.join(",")));
      for (const exc of table.exclusions) {
        const ikey = exc.index.toLowerCase();
        for (const u of updates) {
          const probe = exclusionProbeQuery(table.columns, exc, u.row);
          if (probe === null) continue;
          const tree = this.readSnap().gistTreeFor(ikey);
          const conflict =
            tree !== undefined &&
            gistSearch(tree, probe.query, probe.strats).keys.some(
              (h) => !rewritten.has(h.join(",")),
            );
          if (conflict) {
            throw exclusionViolation(table.name, exc.name);
          }
        }
        for (let i = 0; i < updates.length; i++) {
          for (let j = 0; j < i; j++) {
            if (exclusionPairConflicts(table.columns, exc, updates[i]!.row, updates[j]!.row)) {
              throw exclusionViolation(table.name, exc.name);
            }
          }
        }
      }
    }

    // FOREIGN KEY child-side (constraints.md §6.4): re-validate an FK only when the statement
    // assigns one of its local columns (an unchanged value stays valid). Each updated NEW row must
    // reference an existing parent key — committed parent state, plus (for a self-reference) the
    // updated rows' new referenced values, so a row may reference a value another updated row now
    // supplies. Unmetered, phase 1, before any write.
    const relation = table.name;
    const assigned = new Set<number>(plans.map((p) => p.idx));
    const updFks = this.table(upd.table)?.fks ?? [];
    for (const fk of updFks) {
      if (!fk.columns.some((c) => assigned.has(c))) continue; // this FK's local columns were not assigned
      const parent = this.table(fk.refTable);
      if (parent === undefined) continue;
      // The probe matches the parent's stored key, so a collated parent key column uses the
      // PARENT's collation (§2.12).
      const parentColls = this.columnCollations(parent.columns);
      const batch = new Set<string>();
      if (fk.refTable.toLowerCase() === relation.toLowerCase()) {
        for (const u of updates) {
          const p = fkProbe(fk, parent, parentColls, u.row, fk.refColumns);
          if (p !== null) batch.add(fkProbeBytes(p).join(","));
        }
      }
      for (const u of updates) {
        const probe = fkProbe(fk, parent, parentColls, u.row, fk.columns);
        if (probe === null) continue; // a NULL local column → exempt (MATCH SIMPLE)
        if (batch.has(fkProbeBytes(probe).join(","))) continue;
        if (!this.fkProbeHits(probe, fk.refTable)) {
          throw fkViolationInsert(relation, fk.name);
        }
      }
    }

    // FOREIGN KEY parent-side (constraints.md §6.5): an UPDATE of a referenced row must not strand
    // a child. A referenced column — PRIMARY KEY (now re-keyable) or UNIQUE — may change. For each
    // inbound FK, a referenced tuple DISAPPEARS when an updated row's old value is absent from the
    // statement's new end state (old − new over the updated rows); if a child still references a
    // disappearing tuple → 23503. Unmetered, phase 1. A self-reference's child IS this table: the
    // committed scan excludes the rows being updated (their NEW references are checked separately,
    // newChildRefs, since a re-key can leave an updated row pointing at its own now-vacated value —
    // the child-side probe reads the pre-update parent, so it cannot see that).
    const updReferencers = this.fkReferencers(upd.table);
    if (updReferencers.length > 0) {
      const parent = this.table(upd.table)!;
      const updatedKeys = new Set<string>(updates.map((u) => u.key.join(",")));
      const empty = new Set<string>();
      for (const { childTable, fk } of updReferencers) {
        const selfRef = childTable.toLowerCase() === upd.table.toLowerCase();
        // The referenced tuples the updated rows now supply (so a swap re-supplies one).
        // parent is the update target itself, so its key columns use colls (§2.12).
        const newPresent = new Set<string>();
        for (const u of updates) {
          const p = fkProbe(fk, parent, colls, u.row, fk.refColumns);
          if (p !== null) newPresent.add(fkProbeBytes(p).join(","));
        }
        // For a self-reference, the FK tuples the updated rows now POINT AT (their new
        // local-column values): an updated row referencing a disappearing tuple dangles.
        const newChildRefs = new Set<string>();
        if (selfRef) {
          for (const u of updates) {
            const p = fkProbe(fk, parent, colls, u.row, fk.columns);
            if (p !== null) newChildRefs.add(fkProbeBytes(p).join(","));
          }
        }
        const exclude = selfRef ? updatedKeys : empty;
        for (const u of updates) {
          const oldProbe = fkProbe(fk, parent, colls, u.oldRow, fk.refColumns);
          if (oldProbe === null) continue; // a NULL old referenced value was referenced by nothing
          // Unchanged tuples (incl. a NULL → already skipped) do not disappear.
          const newProbe = fkProbe(fk, parent, colls, u.row, fk.refColumns);
          if (newProbe !== null && bytesEq(fkProbeBytes(newProbe), fkProbeBytes(oldProbe)))
            continue;
          // Re-supplied by another updated row (e.g. a value swap) → not disappearing.
          if (newPresent.has(fkProbeBytes(oldProbe).join(","))) continue;
          // Stranded if a committed (non-updated) child OR an updated row's NEW reference
          // still points at the disappearing tuple.
          if (
            this.fkChildReferences(childTable, fk, parent, fkProbeBytes(oldProbe), exclude) ||
            newChildRefs.has(fkProbeBytes(oldProbe).join(","))
          ) {
            throw fkViolationDelete(parent.name, fk.name, childTable);
          }
        }
      }
    }

    // Each rewritten row's disposition plan may attempt compression (a record over RECORD_MAX)
    // — meter the attempts (value_compress, cost.md §3) and enforce the ceiling BEFORE phase 2
    // writes anything, preserving all-or-nothing.
    let cunits = 0n;
    for (const u of updates) cunits += BigInt(store.writeCompressUnits(u.newKey, u.row));
    meter.charge(COSTS.valueCompress * cunits);
    meter.guard();

    // The RETURNING projection (grammar.md §32, cost.md §3): evaluate over the matched rows'
    // NEW (post-assignment, fully resident) values — all validation has passed, nothing is
    // written yet, so subqueries in the list read the pre-statement snapshot and a 54P01 here
    // writes nothing (all-or-nothing).
    const returned =
      ret !== null
        ? this.projectReturning(
            ret.nodes,
            updates.map((u) => u.row),
            updates.map((u) => u.oldRow),
            bound,
            ctx,
            meter,
          )
        : null;

    // Index maintenance (indexes.md §4): an entry moves only when its key CHANGED — equal
    // old/new keys leave the index tree untouched (part of the contract: it keeps the
    // copy-on-write dirty set, and so the commit's written pages, byte-identical across
    // cores). An entry key is `indexed-cols || storage-key`, so a re-keyed row moves EVERY
    // one of its entries (the suffix changed); a non-PK UPDATE keeps the suffix and moves
    // only entries whose indexed columns changed.
    const indexMoves: { removals: Uint8Array[]; insertions: Uint8Array[] }[][] = table.indexes.map(
      () => [],
    );
    for (const u of updates) {
      for (let k = 0; k < table.indexes.length; k++) {
        // The row's old and new entry SETS (one entry for an ordered index, one per term for GIN —
        // gin.md §5). Remove old−new, insert new−old: a shared entry is left untouched, keeping the
        // copy-on-write dirty set byte-identical across cores. Computed (evaluating any expression
        // key) before the phase-2 writes.
        const oldEks = this.indexEntries(table.columns, colls, rindexes[k]!, u.key, u.oldRow);
        const newEks = this.indexEntries(table.columns, colls, rindexes[k]!, u.newKey, u.row);
        const removals = bytesDiff(oldEks, newEks);
        const insertions = bytesDiff(newEks, oldEks);
        if (removals.length > 0 || insertions.length > 0) {
          indexMoves[k]!.push({ removals, insertions });
        }
      }
    }

    // Phase 2: write the validated rows, then move the changed index entries (unmetered write
    // work). Writes target the working set. A non-PK UPDATE replaces each row in place (the fast
    // path). A re-keying UPDATE vacates every OLD key first and then places each row at its NEW
    // key — a two-pass so a chain or swap of keys among the updated rows never transiently collides
    // (the end state is collision-free, validated above). The index entries move the same way (all
    // removals across rows, then all insertions), since a moved row's new entry can equal another
    // moved row's not-yet-removed old entry.
    const writeStore = this.writeStoreScoped(upd.db, upd.table);
    if (pkChanged) {
      for (const u of updates) writeStore.remove(u.key);
      for (const u of updates) {
        if (!writeStore.insert(u.newKey, u.row)) {
          // Reachable only under the writable-CTE read pin (writable-cte.md §7): an earlier
          // sub-statement staged this key, unseen by phase 1. Aborts all-or-nothing, matching
          // INSERT. For a single statement, phase 1's end-state check caught every duplicate.
          throw uniqueViolation(table.name, pkeyName(table.name));
        }
      }
      for (let k = 0; k < table.indexes.length; k++) {
        const istore = this.writeIndexStoreScoped(upd.db, table.indexes[k]!.name.toLowerCase());
        for (const mv of indexMoves[k]!) for (const oldEk of mv.removals) istore.remove(oldEk);
        for (const mv of indexMoves[k]!)
          for (const newEk of mv.insertions) {
            if (!istore.insert(newEk, [])) {
              // A cross-sub-statement collision under the read pin (as above).
              throw uniqueViolation(table.name, table.indexes[k]!.name);
            }
          }
      }
    } else {
      for (const u of updates) writeStore.replace(u.key, u.row);
      for (let k = 0; k < table.indexes.length; k++) {
        const istore = this.writeIndexStoreScoped(upd.db, table.indexes[k]!.name.toLowerCase());
        for (const mv of indexMoves[k]!) {
          for (const oldEk of mv.removals) istore.remove(oldEk);
          for (const newEk of mv.insertions) {
            if (!istore.insert(newEk, [])) {
              throw new Error("index entry keys are unique (storage-key suffix)");
            }
          }
        }
      }
    }
    return dmlOutcome(
      ret?.names ?? null,
      ret?.types ?? null,
      returned,
      updates.length,
      meter.accrued,
    );
  }

  // executeSelect runs a SELECT as a top-level statement: runSelect, then wrap as a query
  // Outcome (the projection types are internal — only INSERT ... SELECT consumes them).
  private executeSelect(sel: Select, params: Value[]): Outcome {
    const r = this.runSelect(sel, params);
    return {
      kind: "query",
      columnNames: r.columnNames,
      columnTypes: typeNames(r.columnTypes),
      rows: r.rows,
      cost: r.cost,
    };
  }

  // executeSetOp runs a set operation as a top-level statement: runSetOp, then wrap as a query
  // Outcome. Cost is lhs.cost + rhs.cost — the combine, sort, and window are unmetered (cost.md §3).
  private executeSetOp(so: SetOp, params: Value[]): Outcome {
    const r = this.runSetOp(so, params);
    return {
      kind: "query",
      columnNames: r.columnNames,
      columnTypes: typeNames(r.columnTypes),
      rows: r.rows,
      cost: r.cost,
    };
  }

  // runQueryExpr runs a query expression to a SelectResult — a lone SELECT via runSelect, or a set
  // operation via runSetOp (recursively, so a chain `a UNION b INTERSECT c` evaluates as the parsed
  // precedence tree).
  // runQueryExpr is the top-level orchestrator (spec/design/grammar.md §26): PLAN the whole
  // expression tree once against an empty scope chain (threading one ParamTypes so $N inference is
  // statement-wide), bind the parameters, then the foldUncorrelated pass executes each
  // globally-uncorrelated subquery once and folds it to a constant (preserving the once-only cost),
  // and finally EXECUTE against an empty outer-row environment. Correlated subqueries that survive
  // the fold are re-executed per outer row by the evaluator.
  private runQueryExpr(qe: QueryExpr, params: Value[]): SelectResult {
    const ptypes = new ParamTypes();
    const plan = this.planQuery(qe, null, [], ptypes);
    const bound = bindParams(params, ptypes.finalize());
    const subqueryCost = { value: 0n };
    this.foldUncorrelatedInPlan(plan, bound, EMPTY_CTE_CTX, subqueryCost);
    const r = this.execQueryPlan(plan, [], bound, EMPTY_CTE_CTX);
    return { ...r, cost: r.cost + subqueryCost.value };
  }

  // runSelect runs a lone SELECT — the entry point executeSelect and INSERT ... SELECT use.
  private runSelect(sel: Select, params: Value[]): SelectResult {
    return this.runQueryExpr(sel, params);
  }

  // runSetOp runs a set operation as a top-level statement.
  private runSetOp(so: SetOp, params: Value[]): SelectResult {
    return this.runQueryExpr(so, params);
  }

  // executeWith runs a WITH query (spec/design/cte.md) as a top-level statement: runWith, then wrap
  // as a query Outcome.
  private executeWith(wq: WithQuery, params: Value[]): Outcome {
    // A WITH containing any data-modifying part (a data-modifying CTE or a data-modifying primary)
    // runs through the writable-CTE orchestrator (spec/design/writable-cte.md): it pins the
    // pre-statement snapshot and runs the parts in lexical order, all-or-nothing. A pure-query WITH
    // keeps the existing read-only path (cte.md) unchanged.
    if (withHasDml(wq)) {
      return this.executeWithDml(wq, params);
    }
    const r = this.runWith(wq, params);
    return {
      kind: "query",
      columnNames: r.columnNames,
      columnTypes: typeNames(r.columnTypes),
      rows: r.rows,
      cost: r.cost,
    };
  }

  // planCteBindings plans every CTE in a WITH list into bindings (spec/design/cte.md §2,
  // writable-cte.md). Each body is planned against the prefix of EARLIER bindings (parent = null — a
  // body is an independent query, NOT correlated to a reference site). Under WITH RECURSIVE a query
  // CTE that references its own name is the recursive shape (its binding is pushed BEFORE planning the
  // recursive term, so the self-reference resolves to it). A DATA-MODIFYING CTE body resolves only its
  // RETURNING schema here (its effect runs later, in the orchestrator) — a data-modifying body is
  // never the recursive UNION shape, so it is always non-recursive. The `refs` counters are bumped as
  // later query bodies / a query primary reference each binding (a data-modifying part's references
  // are static-counted by the orchestrator, since it is not planned here).
  private planCteBindings(ctes: Cte[], recursive: boolean, ptypes: ParamTypes): CteBinding[] {
    const bindings: CteBinding[] = [];
    for (const cte of ctes) {
      const lname = cte.name.toLowerCase();
      if (bindings.some((b) => b.name === lname)) {
        throw engineError("duplicate_alias", `WITH query name ${lname} specified more than once`);
      }
      const bodyQuery = cteBodyAsQuery(cte.body);
      const shape =
        recursive && bodyQuery !== null
          ? analyzeRecursiveCte(lname, bodyQuery)
          : { recursive: false as const, unionAll: false };
      if (shape.recursive) {
        // The body is `anchor UNION[ALL] recursive_term` (analyzeRecursiveCte verified).
        const so = bodyQuery as SetOp;
        const anchorPlan = this.planQuery(so.lhs, null, bindings, ptypes);
        const table = cteSyntheticTable(lname, anchorPlan, cte.columns);
        bindings.push({
          name: lname,
          table,
          source: { kind: "query", plan: anchorPlan },
          recursive: null,
          hint: cte.materialized,
          refs: 0,
        });
        const bi = bindings.length - 1;
        const rhsPlan = this.planQuery(so.rhs, null, bindings, ptypes);
        const anchorSrc = bindings[bi]!.source;
        if (anchorSrc.kind !== "query") {
          throw new Error("the anchor binding was just pushed as a query source");
        }
        checkRecursiveColumnTypes(anchorSrc.plan, rhsPlan, lname);
        bindings[bi]!.recursive = { plan: rhsPlan, unionAll: shape.unionAll };
        continue;
      }
      if (bodyQuery !== null) {
        const plan = this.planQuery(bodyQuery, null, bindings, ptypes);
        const table = cteSyntheticTable(lname, plan, cte.columns);
        bindings.push({
          name: lname,
          table,
          source: { kind: "query", plan },
          recursive: null,
          hint: cte.materialized,
          refs: 0,
        });
      } else {
        // A data-modifying CTE (writable-cte.md): resolve its RETURNING schema for the synthetic
        // relation + capture the statement to run later.
        const { table, dm } = this.planDmCte(lname, cte.body, bindings, cte.columns, ptypes);
        bindings.push({
          name: lname,
          table,
          source: { kind: "dml", dm },
          recursive: null,
          hint: cte.materialized,
          refs: 0,
        });
      }
    }
    return bindings;
  }

  // planDmCte plans a data-modifying CTE body (spec/design/writable-cte.md): resolve its RETURNING
  // schema (against the EARLIER bindings, so a RETURNING sublink may reference an earlier CTE) to
  // build the synthetic relation, and capture the statement to execute later. A body with no
  // RETURNING yields a zero-column relation flagged noReturning (a FROM reference to it is 0A000,
  // §5). The target must be a base table — a CTE name / missing table is 42P01 (§1).
  private planDmCte(
    lname: string,
    body: CteBody,
    bindings: CteBinding[],
    rename: string[] | null,
    ptypes: ParamTypes,
  ): { table: Table; dm: DmCte } {
    let tableName: string;
    let returning: SelectItems | null;
    let baseIsOld: boolean;
    let stmt: DmStmt;
    if (body.kind === "insert") {
      tableName = body.table;
      returning = body.returning;
      baseIsOld = false;
      stmt = body;
    } else if (body.kind === "update") {
      tableName = body.table;
      returning = body.returning;
      baseIsOld = false;
      stmt = body;
    } else if (body.kind === "delete") {
      tableName = body.table;
      returning = body.returning;
      baseIsOld = true;
      stmt = body;
    } else {
      throw new Error("planDmCte requires a data-modifying body");
    }
    const tdef = this.lkpTable(tableName); // temp-first (temp-tables.md §3)
    if (tdef === undefined) {
      throw engineError("undefined_table", "table does not exist: " + tableName);
    }
    if (returning === null) {
      const table = cteSyntheticTableCols(lname, [], [], rename);
      return { table, dm: { stmt, noReturning: true } };
    }
    const scope = Scope.returning(this, tdef, baseIsOld);
    scope.ctes = bindings;
    const { names, types } = resolveProjections(
      scope,
      returning,
      { collecting: false, groupKeys: [], specs: [] },
      ptypes,
    );
    const table = cteSyntheticTableCols(lname, names, types, rename);
    return { table, dm: { stmt, noReturning: false } };
  }

  // runWith runs a pure-query WITH (spec/design/cte.md) — the path for a WITH with no data-modifying
  // part (a data-modifying WITH goes through executeWithDml). (1) PLAN every CTE binding against the
  // prefix; (2) plan the main body with all bindings visible, threading the one ParamTypes so $N
  // infers statement-wide; (3) decide each CTE's mode from its reference count + [NOT] MATERIALIZED
  // hint; (4) MATERIALIZE each referenced materialized CTE once, in list order (a later body sees the
  // earlier buffers); (5) fold + EXECUTE the main body with the CTE context. Cost composes like set
  // operations — a sum of the parts.
  private runWith(wq: WithQuery, params: Value[]): SelectResult {
    const ptypes = new ParamTypes();
    const bindings = this.planCteBindings(wq.ctes, wq.recursive, ptypes);
    // (2) Plan the main body with all bindings visible (the pure-query path always has a query
    //     primary — a data-modifying primary routes to executeWithDml).
    const bodyQuery = cteBodyAsQuery(wq.body);
    if (bodyQuery === null) {
      throw new Error("runWith is the pure-query path");
    }
    const plan = this.planQuery(bodyQuery, null, bindings, ptypes);
    const bound = bindParams(params, ptypes.finalize());
    const modes = cteModes(bindings);
    const { buffers, totalCost } = this.materializeCtes(bindings, modes, bound);

    // (5) Fold + execute the main body against the full CTE context.
    const ctx: CteCtx = { modes, bindings, buffers };
    const subqueryCost = { value: 0n };
    this.foldUncorrelatedInPlan(plan, bound, ctx, subqueryCost);
    const r = this.execQueryPlan(plan, [], bound, ctx);
    return { ...r, cost: r.cost + subqueryCost.value + totalCost };
  }

  // materializeCtes materializes each CTE once, in list order (spec/design/cte.md §3) — the shared
  // loop for the pure-query and writable-CTE paths' query/recursive CTEs. A data-modifying CTE is NOT
  // run here (the orchestrator runs it for its effect — runWithDml); its buffer slot is left empty for
  // the orchestrator to fill. Returns the filled buffers + the accrued materialization cost (a later
  // body sees the earlier buffers).
  private materializeCtes(
    bindings: CteBinding[],
    modes: CteMode[],
    bound: Value[],
  ): { buffers: Row[][]; totalCost: bigint } {
    const totalCost = { value: 0n };
    const buffers: Row[][] = [];
    for (let i = 0; i < bindings.length; i++) {
      const rt = bindings[i]!.recursive;
      let buf: Row[];
      if (rt) {
        buf = this.materializeRecursive(i, rt, modes, bindings, buffers, bound, totalCost);
      } else if (bindings[i]!.source.kind === "dml") {
        // A data-modifying CTE's buffer is filled by the orchestrator, not here.
        buf = [];
      } else if (modes[i] === "materialize") {
        const ctx: CteCtx = {
          modes: modes.slice(0, i),
          bindings: bindings.slice(0, i),
          buffers,
        };
        const src = bindings[i]!.source;
        if (src.kind !== "query") {
          throw new Error("the data-modifying arm was handled above");
        }
        const r = this.execQueryPlan(src.plan, [], bound, ctx);
        totalCost.value += r.cost;
        buf = r.rows;
      } else {
        buf = [];
      }
      buffers.push(buf);
    }
    return { buffers, totalCost: totalCost.value };
  }

  // materializeRecursive materializes a RECURSIVE CTE by iterating to a fixpoint — the PostgreSQL
  // working-table method (spec/design/recursive-cte.md §4). rt is the recursive term (which references
  // this CTE, index ci); the anchor is bindings[ci].source. priorBuffers are the earlier CTEs'
  // materialized rows (visible to both terms). totalCost accrues every term evaluation's cost and
  // gates the per-statement ceiling between iterations, so a non-terminating recursion of cheap
  // iterations still aborts 54P01 at the identical accrued cost in every core (recursive-cte.md §5).
  private materializeRecursive(
    ci: number,
    rt: RecursiveTerm,
    modes: CteMode[],
    bindings: CteBinding[],
    priorBuffers: Row[][],
    params: Value[],
    totalCost: { value: bigint },
  ): Row[] {
    const anchorSrc = bindings[ci]!.source;
    if (anchorSrc.kind !== "query") {
      throw new Error("a recursive CTE's anchor is a query plan");
    }
    const anchorPlan = anchorSrc.plan;
    const maxCost = this.session.maxCost;
    const guard = (total: bigint): void => {
      if (maxCost > 0n && total >= maxCost) {
        throw engineError(
          "cost_limit_exceeded",
          `query exceeded the cost limit of ${maxCost} (accrued ${total})`,
        );
      }
    };
    const anchorTypes = anchorPlan.columnTypes;
    const rhsTypes = rt.plan.columnTypes;

    // Evaluate the anchor: its rows seed both the result and the first working table.
    const ar = this.execQueryPlan(anchorPlan, [], params, {
      modes: modes.slice(0, ci),
      bindings: bindings.slice(0, ci),
      buffers: priorBuffers,
    });
    totalCost.value += ar.cost;
    guard(totalCost.value);

    // For UNION (distinct) a seen set drops rows duplicating any already-emitted row, keyed by the
    // NULL-safe distinctRowKey the set operators use.
    const seen = new Set<string>();
    const keep = (row: Row): boolean => {
      if (rt.unionAll) return true;
      const k = distinctRowKey(row);
      if (seen.has(k)) return false;
      seen.add(k);
      return true;
    };
    const result: Row[] = [];
    let working: Row[] = [];
    for (const row of ar.rows) {
      if (keep(row)) {
        result.push(row);
        working.push(row);
      }
    }

    // The recursive term scans the WORKING table through the CTE's own buffer slot (ci); the earlier
    // CTEs keep their full buffers. Build the buffer array once and swap slot ci per iteration.
    const rhsBuffers: Row[][] = priorBuffers.slice(0, ci);
    rhsBuffers.push([]); // slot ci

    while (working.length > 0) {
      rhsBuffers[ci] = working;
      working = [];
      const rr = this.execQueryPlan(rt.plan, [], params, {
        modes: modes.slice(0, ci + 1),
        bindings: bindings.slice(0, ci + 1),
        buffers: rhsBuffers,
      });
      totalCost.value += rr.cost;
      guard(totalCost.value);
      coerceSetopRows(rr.rows, rhsTypes, anchorTypes);
      for (const row of rr.rows) {
        if (keep(row)) {
          result.push(row);
          working.push(row);
        }
      }
    }
    return result;
  }

  // executeWithDml runs a data-modifying WITH statement (spec/design/writable-cte.md): a WITH
  // containing a data-modifying CTE and/or a data-modifying primary. It PINS the pre-statement
  // snapshot for every sub-statement's reads (§2 — so the parts cannot see each other's table writes;
  // data crosses only via a CTE's RETURNING buffer), runs the parts in lexical order, and returns the
  // primary's result. The whole statement is one all-or-nothing transaction — the autocommit (or
  // block) wrapper publishes the accumulated working only if this returns without throwing (§6).
  private executeWithDml(wq: WithQuery, params: Value[]): Outcome {
    // Pin the pre-statement snapshot. A write statement runs with a transaction open (autocommit
    // opened one), and nothing is written yet, so the pin equals working == committed. Cleared on
    // every exit path so the next statement reads normally.
    const pin = this.readSnap().clone();
    this.session.readPin = pin;
    try {
      return this.runWithDml(wq, params);
    } finally {
      this.session.readPin = null;
    }
  }

  // runWithDml is the body of executeWithDml, run under the read pin. Plans every CTE binding + the
  // query primary, runs the data-modifying CTEs / materialized query CTEs in list order, then the
  // primary — every read against the pin, every write into the transaction's working.
  private runWithDml(wq: WithQuery, params: Value[]): Outcome {
    const { ctes, body, recursive } = wq;
    const ptypes = new ParamTypes();
    // (1) Plan every CTE binding (query plans + data-modifying RETURNING schemas).
    const bindings = this.planCteBindings(ctes, recursive, ptypes);
    // (2) Plan a query primary now (to bump refs + surface resolution errors, incl. a 0A000 FROM
    //     reference to a no-RETURNING data-modifying CTE). A data-modifying primary is resolved and
    //     run later (it sees the bindings via the threaded context); its references are
    //     static-counted in (2b).
    const primaryQuery = cteBodyAsQuery(body);
    const primaryPlan =
      primaryQuery !== null ? this.planQuery(primaryQuery, null, bindings, ptypes) : null;
    // (2b) Add the references each NON-planned data-modifying part (a data-modifying CTE body, or a
    //      data-modifying primary) contributes to each binding, so the inline-vs-materialize decision
    //      is correct for a query CTE referenced only by a data-modifying part (§3). Query bodies / a
    //      query primary were already plan-counted in (1)/(2).
    for (const cte of ctes) {
      if (cteBodyIsDataModifying(cte.body)) {
        for (const b of bindings) {
          b.refs += countCteRefsDml(cte.body, b.name);
        }
      }
    }
    if (cteBodyIsDataModifying(body)) {
      for (const b of bindings) {
        b.refs += countCteRefsDml(body, b.name);
      }
    }
    const bound = bindParams(params, ptypes.finalize());
    const modes = cteModes(bindings);

    // (3) Run each CTE in list order, filling its buffer. A data-modifying CTE executes for its
    //     effect + RETURNING buffer; the query/recursive CTEs use the shared materialize loop.
    const totalCost = { value: 0n };
    const buffers: Row[][] = [];
    for (let i = 0; i < bindings.length; i++) {
      const rt = bindings[i]!.recursive;
      let buf: Row[];
      if (rt) {
        buf = this.materializeRecursive(i, rt, modes, bindings, buffers, bound, totalCost);
      } else if (bindings[i]!.source.kind === "dml") {
        const ctx: CteCtx = {
          modes: modes.slice(0, i),
          bindings: bindings.slice(0, i),
          buffers,
        };
        const { rows, cost } = this.execDmCte(i, bindings, bound, ctx);
        totalCost.value += cost;
        buf = rows;
      } else if (modes[i] === "materialize") {
        const ctx: CteCtx = {
          modes: modes.slice(0, i),
          bindings: bindings.slice(0, i),
          buffers,
        };
        const src = bindings[i]!.source;
        if (src.kind !== "query") {
          throw new Error("the data-modifying arm was handled above");
        }
        const r = this.execQueryPlan(src.plan, [], bound, ctx);
        totalCost.value += r.cost;
        buf = r.rows;
      } else {
        buf = [];
      }
      buffers.push(buf);
    }

    // (4) Execute the primary against the full CTE context, adding the materialization cost.
    const ctx: CteCtx = { modes, bindings, buffers };
    let outcome: Outcome;
    if (body.kind === "select" || body.kind === "setOp" || body.kind === "withExpr") {
      const plan = primaryPlan!;
      const subqueryCost = { value: 0n };
      this.foldUncorrelatedInPlan(plan, bound, ctx, subqueryCost);
      const r = this.execQueryPlan(plan, [], bound, ctx);
      outcome = {
        kind: "query",
        columnNames: r.columnNames,
        columnTypes: typeNames(r.columnTypes),
        rows: r.rows,
        cost: r.cost + subqueryCost.value,
      };
    } else if (body.kind === "insert") {
      outcome = this.executeInsert(body, params, ctx);
    } else if (body.kind === "update") {
      outcome = this.executeUpdate(body, params, ctx);
    } else {
      outcome = this.executeDelete(body, params, ctx);
    }
    return addOutcomeCost(outcome, totalCost.value);
  }

  // execDmCte executes a data-modifying CTE (spec/design/writable-cte.md §3): run the
  // INSERT/UPDATE/DELETE at binding i for its effect, with the earlier bindings/buffers in scope (so
  // its inner queries may reference an earlier CTE), and return its RETURNING rows (the buffer the
  // later parts scan) + its cost. A body with no RETURNING runs for its effect and buffers no rows.
  private execDmCte(
    i: number,
    bindings: CteBinding[],
    params: Value[],
    ctx: CteCtx,
  ): { rows: Row[]; cost: bigint } {
    const src = bindings[i]!.source;
    if (src.kind !== "dml") {
      throw new Error("execDmCte requires a data-modifying binding");
    }
    const stmt = src.dm.stmt;
    let outcome: Outcome;
    if (stmt.kind === "insert") {
      outcome = this.executeInsert(stmt, params, ctx);
    } else if (stmt.kind === "update") {
      outcome = this.executeUpdate(stmt, params, ctx);
    } else {
      outcome = this.executeDelete(stmt, params, ctx);
    }
    if (outcome.kind === "query") {
      return { rows: outcome.rows, cost: outcome.cost };
    }
    return { rows: [], cost: outcome.cost };
  }

  // planQuery resolves a query expression into an owned QueryPlan against the scope chain (parent =
  // the enclosing query's scope, null at top level). A subquery is planned here, once (§26). `ctes`
  // is the statement's CTE bindings visible here (spec/design/cte.md §2) — inherited into every
  // nested scope, never via the parent chain.
  // Not private: the free function planSubquery calls it through scope.catalog (an internal seam).
  planQuery(
    qe: QueryExpr,
    parent: Scope | null,
    ctes: CteBinding[],
    ptypes: ParamTypes,
  ): QueryPlan {
    if (qe.kind === "select") return this.planSelect(qe, parent, ctes, ptypes);
    if (qe.kind === "withExpr") return this.planWithExpr(qe, parent, ptypes);
    return this.planSetOp(qe, parent, ctes, ptypes);
  }

  // planWithExpr plans a nested `WITH … query_expr` (spec/design/cte.md §7) into a WithPlan. The
  // nested CTEs establish their OWN scope: the bodies and the inner main query see ONLY these CTEs
  // (and the catalog) — the enclosing statement's CTE bindings are NOT inherited (a documented
  // narrowing, cte.md §7), so planCteBindings and the body are planned without the outer ctes. The
  // inner main query keeps the enclosing parent (so a LATERAL derived-table body still correlates to
  // its left siblings), while the CTE bodies stay independent (parent=null, inside planCteBindings).
  // A data-modifying CTE here is rejected 0A000 — PostgreSQL restricts a DML-WITH to the top level.
  private planWithExpr(we: WithExpr, parent: Scope | null, ptypes: ParamTypes): WithPlan {
    for (const c of we.ctes) {
      if (cteBodyIsDataModifying(c.body)) {
        throw engineError(
          "feature_not_supported",
          `WITH clause containing a data-modifying statement (${c.name}) is only supported at the top level`,
        );
      }
    }
    const bindings = this.planCteBindings(we.ctes, we.recursive, ptypes);
    const body = this.planQuery(we.body, parent, bindings, ptypes);
    return {
      kind: "with",
      bindings,
      modes: cteModes(bindings),
      body,
      columnNames: body.columnNames,
      columnTypes: body.columnTypes,
    };
  }

  // execQueryPlan executes a resolved plan against an outer-row environment (outer = the enclosing
  // rows, innermost last; empty at top level), the bound parameters, and the CTE context (a FROM
  // reference at any depth delivers a CTE's rows — spec/design/cte.md §5).
  private execQueryPlan(
    plan: QueryPlan,
    outer: Row[],
    params: Value[],
    ctes: CteCtx,
  ): SelectResult {
    if (plan.kind === "select") return this.execSelectPlan(plan, outer, params, ctes);
    if (plan.kind === "values") return this.execValuesPlan(plan, outer, params, ctes);
    if (plan.kind === "with") return this.execWithPlan(plan, outer, params);
    return this.execSetOpPlan(plan, outer, params, ctes);
  }

  // execWithPlan executes a nested WITH plan (spec/design/cte.md §7): materialize its CTE bindings
  // once (in list order, charging their cost), build a FRESH CTE context over them (the nested CTEs
  // establish their own scope — the enclosing context is NOT chained in, the documented narrowing
  // §7), and run the inner body against it. The body still sees the outer row environment (so a
  // LATERAL nested-WITH derived-table body correlates to its left siblings). The materialization cost
  // folds into the body's cost — the same shape as the top-level runWith (cte.md §3).
  private execWithPlan(plan: WithPlan, outer: Row[], params: Value[]): SelectResult {
    const { buffers, totalCost } = this.materializeCtes(plan.bindings, plan.modes, params);
    const ctx: CteCtx = {
      modes: plan.modes,
      bindings: plan.bindings,
      buffers,
    };
    const r = this.execQueryPlan(plan.body, outer, params, ctx);
    r.cost += totalCost;
    return r;
  }

  // planSetOp plans a set operation (spec/design/grammar.md §25): plan both operands with the same
  // parent scope, check arity + unify column types up front (so the 42601/42804 fire even over
  // empty operands), and resolve the trailing ORDER BY by output column name.
  private planSetOp(
    so: SetOp,
    parent: Scope | null,
    ctes: CteBinding[],
    ptypes: ParamTypes,
  ): SetOpPlan {
    const lhs = this.planQuery(so.lhs, parent, ctes, ptypes);
    const rhs = this.planQuery(so.rhs, parent, ctes, ptypes);

    if (lhs.columnTypes.length !== rhs.columnTypes.length) {
      throw engineError(
        "syntax_error",
        `each ${setopName(so.op)} query must have the same number of columns`,
      );
    }
    const columnTypes = lhs.columnTypes.map((l, i) =>
      unifySetopColumn(l, rhs.columnTypes[i]!, so.op),
    );
    const columnNames = lhs.columnNames;
    const order: OrderSlot[] = so.orderBy.map((key) => {
      const idx = resolveSetopOrderKey(key, columnNames);
      // An explicit COLLATE on a set-operation ORDER BY key (spec/design/collation.md §1): the output
      // column must be text (42804); the name resolves ("C", else loaded or 42704).
      let collation: Collation | null = null;
      if (key.collation !== null) {
        if (columnTypes[idx]!.kind !== "text") {
          throw typeError("collations are not supported by this column's type");
        }
        collation = resolveCollationName(this, key.collation);
      }
      return {
        idx,
        descending: key.descending,
        nullsFirst: key.nullsFirst,
        collation,
      };
    });
    return {
      kind: "setOp",
      op: so.op,
      all: so.all,
      lhs,
      rhs,
      columnNames,
      columnTypes,
      order,
      limit: so.limit,
      offset: so.offset,
    };
  }

  // execSetOpPlan executes a resolved set operation: run both operands against the outer
  // environment, coerce to the unified types, combine, then sort + window. Cost is lhs.cost +
  // rhs.cost — the combine, sort, and window are unmetered (cost.md §3).
  private execSetOpPlan(
    plan: SetOpPlan,
    outer: Row[],
    params: Value[],
    ctes: CteCtx,
  ): SelectResult {
    const left = this.execQueryPlan(plan.lhs, outer, params, ctes);
    const right = this.execQueryPlan(plan.rhs, outer, params, ctes);

    coerceSetopRows(left.rows, left.columnTypes, plan.columnTypes);
    coerceSetopRows(right.rows, right.columnTypes, plan.columnTypes);

    let rows = combineSetop(plan.op, plan.all, left.rows, right.rows);
    const cost = left.cost + right.cost;

    if (plan.order.length > 0) {
      sortRows(rows, plan.order);
    }

    const n = BigInt(rows.length);
    const start = plan.offset === null ? 0n : plan.offset < n ? plan.offset : n;
    const end = plan.limit !== null && plan.limit < n - start ? start + plan.limit : n;
    rows = rows.slice(Number(start), Number(end));

    return {
      columnNames: plan.columnNames,
      columnTypes: plan.columnTypes,
      rows,
      cost,
    };
  }

  // planValues resolves a VALUES-body relation into a ValuesPlan (spec/design/grammar.md §42) — the
  // body of a FROM (VALUES …) derived table. Each value resolves as a CONSTANT against an EMPTY
  // scope with parent=null: the body is non-LATERAL, so a column reference is unresolved
  // (42703/42P01) and an aggregate is 42803; it still sees the statement's CTE bindings (an
  // uncorrelated subquery inside a value resolves like anywhere). Every row must have the same arity
  // (42601); the columns' types unify across rows like a set operation (42804 on a mismatch). A bind
  // parameter is then noted at its column's unified type (so VALUES (1),($1) types $1 as int); a
  // column with no concrete type — all NULL/param — leaves its $N untyped, surfacing 42P18 at
  // finalize (jed's no-cross-context inference posture, §26).
  private planValues(
    rows: Expr[][],
    parent: Scope | null,
    ctes: CteBinding[],
    ptypes: ParamTypes,
  ): ValuesPlan {
    const arity = rows[0]!.length; // the parser guarantees at least one row, each with ≥1 value
    // A constant scope: no local relations. With parent===null (the usual case) any column reference
    // is unresolved (the non-LATERAL rule, §42); with a parent (a LATERAL VALUES body, §44) a column
    // reference correlates to the earlier FROM relations instead. CTE bindings stay visible and
    // subqueries are allowed (an uncorrelated one folds before the rows run).
    const scope = new Scope([], this, parent, true, ctes);
    const resolvedRows: RExpr[][] = [];
    const colTypes: ResolvedType[] = [];
    // Per column: the 0-based bind-parameter slots in it, typed in a second pass from the unified
    // column type (a $N takes its column's type, like a set-operation operand).
    const colParams: number[][] = Array.from({ length: arity }, () => []);
    rows.forEach((row, ri) => {
      if (row.length !== arity) {
        throw engineError("syntax_error", "VALUES lists must all be the same length");
      }
      const resolvedRow: RExpr[] = [];
      row.forEach((val, ci) => {
        // Forbidden aggregate context: an aggregate inside a value is 42803.
        const { node, type } = resolve(
          scope,
          val,
          null,
          { collecting: false, groupKeys: [], specs: [] },
          ptypes,
        );
        if (node.kind === "param") colParams[ci]!.push(node.index);
        if (ri === 0) colTypes.push(type);
        else colTypes[ci] = unifyValuesColumn(colTypes[ci]!, type);
        resolvedRow.push(node);
      });
      resolvedRows.push(resolvedRow);
    });
    // Second pass: note each column's bind parameters at the unified column type. A column with no
    // scalar type (all NULL/param) passes null — the parameter stays untyped (42P18).
    for (let ci = 0; ci < arity; ci++) {
      const hint = scalarForParamHint(colTypes[ci]!);
      for (const idx0 of colParams[ci]!) ptypes.note(idx0, hint);
    }
    // PostgreSQL names a VALUES relation's columns column1, column2, … ; the derived table's optional
    // column-rename list overrides them at the synthetic relation (cteSyntheticTable).
    const columnNames = Array.from({ length: arity }, (_, i) => `column${i + 1}`);
    return {
      kind: "values",
      rows: resolvedRows,
      columnTypes: colTypes,
      columnNames,
    };
  }

  // execValuesPlan executes a resolved VALUES-body relation (spec/design/grammar.md §42): evaluate
  // each row's values as constants over an EMPTY environment (no local row, no outer row —
  // non-LATERAL), coerce each to the unified column type (the only runtime change is int → decimal,
  // the set-operation rule), and emit the rows. Charges rowProduced per row plus each value's
  // operatorEval (the evaluator) — the derived table's intrinsic cost (cost.md §3), folded into the
  // caller's meter via execQueryPlan.
  private execValuesPlan(
    plan: ValuesPlan,
    outer: Row[],
    params: Value[],
    ctes: CteCtx,
  ): SelectResult {
    const env: EvalEnv = {
      params,
      outer,
      runSubquery: (p, o) => this.execQueryPlan(p, o, params, ctes),
      seam: this.session.seam,
      rng: new StmtRng(),
      ctes,
      exec: this,
    };
    const meter = this.session.newMeter();
    const rows: Value[][] = [];
    for (const row of plan.rows) {
      meter.guard(); // enforce the cost ceiling per produced row (CLAUDE.md §13)
      meter.charge(COSTS.rowProduced);
      const out: Value[] = [];
      for (let ci = 0; ci < plan.columnTypes.length; ci++) {
        let v = evalExpr(row[ci]!, [], env, meter);
        // int → decimal where the column unified to decimal (the set-operation rule); every other
        // unified type is a value no-op (int-width promotion is free — all ints are bigint).
        if (plan.columnTypes[ci]!.kind === "decimal" && v.kind === "int") {
          v = decimalValue(Decimal.fromBigInt(v.int));
        }
        out.push(v);
      }
      rows.push(out);
    }
    return {
      columnNames: plan.columnNames,
      columnTypes: plan.columnTypes,
      rows,
      cost: meter.accrued,
    };
  }

  // runSelect resolves projected columns and the WHERE/ORDER BY columns against the catalog,
  // scans in primary-key order, filters (three-valued — only TRUE keeps a row), optionally
  // re-sorts by ORDER BY, then projects. Returns the rows with each output column's NAME and
  // resolved TYPE (the types let INSERT ... SELECT gate assignability up front — §24) and the
  // accrued cost.
  // planSelect resolves a SELECT into a SelectPlan against the scope chain (parent = the enclosing
  // query's scope, for correlated references — grammar.md §26). The resolve half of the old
  // runSelect: build the FROM scope, resolve every clause, infer $N types into ptypes. No row is
  // touched and no parameter is bound here (runQueryExpr binds once, after the whole tree is planned).
  // Stage 1 of the planner (spec/design/planner.md §2): resolve decides names/types/errors — never
  // an access path — then computes the touched-set annotation (computeRelMasks) and hands the
  // logical plan to the physical/access-path selection pass (optimizeSelect, optimize.ts).
  private planSelect(
    sel: Select,
    parent: Scope | null,
    ctes: CteBinding[],
    ptypes: ParamTypes,
  ): SelectPlan {
    // Build the FROM scope: resolve each table reference (42P01 if unknown), compute each
    // relation's flat column offset in FROM order, and reject a duplicate label — a self-join
    // without distinct aliases is 42712 (spec/design/grammar.md §15). A FROM-less SELECT
    // (sel.from === null) builds an EMPTY scope: nothing local resolves, so bare columns fall
    // through to `parent` (the correlated-subquery rule) or 42703 at top level
    // (spec/design/grammar.md §34). The scope links to `parent` (correlation) + the catalog
    // (so a subquery resolves its own FROM); allowSubquery is true.
    // A FROM item is a base table, a set-returning function (grammar.md §35), or a derived table
    // (§42). For a LATERAL item (§44) the body / SRF args resolve against the PREFIX of relations to
    // its left (a dependent join), so the build runs in FROM order and a prefix scope over the
    // already-resolved rels is handed to the body.
    const tableRefs = sel.from === null ? [] : [sel.from, ...sel.joins.map((j) => j.table)];
    const rels: ScopeRel[] = [];
    const srfPlans: (SrfPlan | undefined)[] = []; // aligned with rels; undefined = a base table
    const derivedPlans: (QueryPlan | undefined)[] = []; // aligned with rels; non-undefined = derived
    // lateralFlags[i] is true when FROM item i is a CORRELATED lateral relation (§44) — its body /
    // SRF args reference an earlier sibling (or an enclosing query), so the executor re-materializes
    // it per combined left-hand row. A non-correlated item (or the first item) is materialized once.
    const lateralFlags: boolean[] = [];
    const seenLabels = new Set<string>();
    let offset = 0;
    for (let i = 0; i < tableRefs.length; i++) {
      const tref = tableRefs[i]!;
      let t: Table;
      let srf: SrfPlan | undefined;
      let cteIdx: number | undefined;
      let derived: QueryPlan | undefined;
      let lateral = false;
      const isDerived = tref.subquery !== undefined || tref.values !== undefined;
      // A FROM item is lateral-ELIGIBLE when it can see earlier siblings: a derived table / VALUES
      // body explicitly marked LATERAL, or ANY table function (implicitly lateral — §44). The first
      // item (i === 0) has no earlier sibling, so it is never lateral; an SRF there resolves against
      // `parent` (the enclosing query) exactly as before.
      const lateralEligible =
        i > 0 &&
        ((isDerived && tref.lateral === true) ||
          tref.args !== null ||
          tref.jsonTable !== undefined);
      // The prefix scope a LATERAL item resolves against: the relations to its left, chained to the
      // enclosing query's parent (so a sibling column correlates as Outer{level=1}, an enclosing one
      // deeper). null when not lateral-eligible.
      const lateralParent = lateralEligible ? new Scope([...rels], this, parent, true, ctes) : null;
      if (isDerived) {
        // Plan the body. LATERAL → parent is the prefix scope (a sibling/outer column correlates);
        // otherwise an INDEPENDENT query (parent=null, §42). A LATERAL VALUES body resolves its
        // values against the prefix too (a column ref then correlates instead of 42703).
        const bodyParent = lateralEligible ? lateralParent : null;
        const plan =
          tref.subquery !== undefined
            ? this.planQuery(tref.subquery, bodyParent, ctes, ptypes)
            : this.planValues(tref.values!, bodyParent, ctes, ptypes);
        lateral = lateralEligible && queryPlanReferencesOuter(plan, 0);
        const label = tref.alias === null ? "" : tref.alias.toLowerCase();
        t = cteSyntheticTable(label, plan, tref.columnAliases ?? null);
        derived = plan;
      } else if (tref.args !== null) {
        // A table function (SRF) — implicitly lateral. At i>0 its args resolve against the prefix
        // scope (a sibling column then correlates); at i==0 against `parent` (the enclosing query /
        // params), unchanged (functions.md §10).
        const srfParent = lateralEligible ? lateralParent : parent;
        const r = this.resolveSRF(
          tref.name,
          tref.args,
          tref.alias,
          tref.columnDefs ?? null,
          srfParent,
          ctes,
          ptypes,
        );
        t = r.table;
        srf = r.srf;
        lateral = lateralEligible && r.srf.args.some((a) => rexprReferencesOuter(a, 0));
      } else if (tref.jsonTable !== undefined) {
        // A JSON_TABLE source (T1, json-table.md §3) — implicitly lateral like an SRF; its `ctx`
        // resolves against the prefix scope (so `JSON_TABLE(sibling.doc, …)` works).
        const jtParent = lateralEligible ? lateralParent : parent;
        const r = this.resolveJsonTable(tref.jsonTable, tref.alias, jtParent, ctes, ptypes);
        t = r.table;
        srf = r.srf;
        lateral = lateralEligible && r.srf.args.some((a) => rexprReferencesOuter(a, 0));
      } else if (tref.db !== undefined) {
        // A database-QUALIFIED name reaches an attachment's table directly (attached-databases.md §3):
        // it never resolves to a CTE (a CTE has no database qualifier, so `main.x`/`temp.x` cannot name
        // one) and the qualifier fixes the scope (no temp-vs-persistent shadow).
        // A built-in catalog relation resolves in EVERY database's relation namespace
        // (temp.jed_tables, reports.jed_tables — introspection.md §5), before the user catalog;
        // only the qualifier itself needs validating.
        const kind = catalogRelKind(tref.name);
        if (kind !== undefined) {
          const scope = this.resolveCatalogScope(tref.db);
          t = catalogRelTable(kind);
          srf = { kind, args: [], introspectScope: scope };
        } else {
          // Validate the qualifier against the implicit scope, then resolve through the temp-first
          // funnel (which, by preclude-overlaps, lands in the validated scope).
          this.checkTableQualifier(tref.db, tref.name);
          // Route to the qualified database's catalog (attached-databases.md §3): main/temp fall through
          // to the temp-first funnel (preclude-overlaps lands them in the validated scope), a host
          // attachment resolves in its own snapshot — where its table lives ONLY. The 1a read path used
          // the bare lkpTable here, which 42P01'd on an attachment table (the routing gotcha).
          const tbl = this.lkpTableScoped(tref.db, tref.name);
          if (!tbl) {
            throw engineError(
              "undefined_table",
              "table does not exist: " + tref.db + "." + tref.name,
            );
          }
          t = tbl;
        }
      } else {
        // A plain FROM name (not an SRF call) may resolve to a CTE, which SHADOWS a catalog table of
        // the same name (cte.md §2); lookup is case-insensitive. A hit bumps the binding's reference
        // count (the inline-vs-materialize decision — cost.md §3).
        const lname = tref.name.toLowerCase();
        const ci = ctes.findIndex((b) => b.name === lname);
        if (ci >= 0) {
          // A data-modifying CTE with no RETURNING produces no columns, so a FROM reference to it is
          // 0A000 (writable-cte.md §5; PostgreSQL's addRangeTableEntryForCTE check), raised at
          // resolution before any execution.
          const src = ctes[ci]!.source;
          if (src.kind === "dml" && src.dm.noReturning) {
            throw engineError(
              "feature_not_supported",
              `WITH query ${lname} does not have a RETURNING clause`,
            );
          }
          ctes[ci]!.refs += 1;
          t = ctes[ci]!.table;
          cteIdx = ci;
        } else {
          // A built-in catalog relation (introspection.md §5), checked AFTER a CTE (a CTE shadows
          // it — PG-matching) and BEFORE the user catalog. Unqualified = the implicit scope (main).
          const kind = catalogRelKind(tref.name);
          if (kind !== undefined) {
            t = catalogRelTable(kind);
            srf = { kind, args: [], introspectScope: "main" };
          } else {
            const tbl = this.lkpTable(tref.name); // temp-first (temp-tables.md §3)
            if (!tbl) throw engineError("undefined_table", "table does not exist: " + tref.name);
            t = tbl;
          }
        }
      }
      // RIGHT/FULL JOIN to a CORRELATED lateral item is rejected (§44): the right side cannot be both
      // kept whole and evaluated per left row. (i ≥ 1 here, so the item carries a join kind.)
      if (lateral && (sel.joins[i - 1]!.kind === "right" || sel.joins[i - 1]!.kind === "full")) {
        throw engineError(
          "invalid_column_reference",
          "invalid reference to FROM-clause entry for a LATERAL item: the combining JOIN type must be INNER or LEFT",
        );
      }
      const label = (tref.alias ?? t.name).toLowerCase();
      // An unaliased derived table (grammar.md §42, PG 18) has an EMPTY label — it has no qualifier,
      // so two of them never collide and the duplicate-label check is skipped (its bare columns still
      // resolve, and stay ambiguous via resolveBare). Every other relation has a non-empty label.
      if (label !== "") {
        if (seenLabels.has(label)) {
          throw engineError("duplicate_alias", "table name " + label + " specified more than once");
        }
        seenLabels.add(label);
      }
      rels.push({ label, table: t, offset, cte: cteIdx, db: tref.db });
      srfPlans.push(srf);
      derivedPlans.push(derived);
      lateralFlags.push(lateral);
      offset += t.columns.length;
    }

    // USING/NATURAL merged columns + every join's resolved predicate (grammar.md §15) — computed
    // BEFORE the scope so GROUP BY / DISTINCT / projection / WHERE all see the merge columns; a plain
    // ON join resolves here too. Joins are processed left-to-right so a later join's left side sees
    // the merges introduced by earlier ones (a USING chain). For each USING column the synthesized
    // predicate is `left.col = right.col` (3-valued, like any ON); the SURVIVING side becomes the
    // single merge column — the left for INNER/LEFT, the right for RIGHT (FULL JOIN USING, a COALESCE,
    // is 0A000). Both copies are hidden from `*`. Merges/predicates respect the comma SEGMENT (commit 1).
    const merges: MergeCol[] = [];
    const hidden: number[] = [];
    const joinPreds: (RExpr | null)[] = [];
    for (let k = 0; k < sel.joins.length; k++) {
      const j = sel.joins[k]!;
      let seg = k + 1;
      while (seg >= 1 && !sel.joins[seg - 1]!.comma) seg--;
      const segOff = rels[seg]!.offset;
      const segMerges = merges.filter((m) => m.index >= segOff);
      const segHidden = hidden.filter((i) => i >= segOff);
      const mkScope = (lo: number, hi: number): Scope => {
        const s = new Scope(rels.slice(lo, hi + 1), this, parent, true, ctes);
        s.merges = segMerges;
        s.hidden = segHidden;
        return s;
      };
      // A NATURAL join (grammar.md §15) derives its USING list as the column names common to both
      // sides (left order); an explicit USING uses its written list. A NATURAL join with NO common
      // column degenerates to a CROSS join (an empty list → no predicate, no merge).
      const usingCols =
        j.using !== undefined
          ? j.using
          : j.natural === true
            ? naturalCommonCols(rels, seg, k)
            : undefined;
      if (usingCols !== undefined && usingCols.length > 0) {
        if (j.kind === "full") {
          throw engineError(
            "feature_not_supported",
            "FULL JOIN with a merged (USING/NATURAL) condition is not supported yet",
          );
        }
        const left = mkScope(seg, k);
        let predAst: Expr | null = null;
        for (const name of usingCols) {
          let li = -1;
          try {
            const lr = left.resolveBare(name);
            if (lr.level === 0) li = lr.index;
          } catch {
            // fall through to the USING-specific error below
          }
          if (li < 0) {
            throw engineError(
              "undefined_column",
              `column "${name}" specified in USING clause does not exist in left table`,
            );
          }
          const [llabel, lname] = relOfIndex(rels, li);
          const rightRel = rels[k + 1]!;
          const rl = columnIndex(rightRel.table, name);
          if (rl < 0) {
            throw engineError(
              "undefined_column",
              `column "${name}" specified in USING clause does not exist in right table`,
            );
          }
          const ri = rightRel.offset + rl;
          const eq: Expr = {
            kind: "binary",
            op: "eq",
            lhs: { kind: "qualifiedColumn", qualifier: llabel, name: lname },
            rhs: { kind: "qualifiedColumn", qualifier: rightRel.label, name },
          };
          predAst = predAst === null ? eq : { kind: "binary", op: "and", lhs: predAst, rhs: eq };
          const mi = j.kind === "right" ? ri : li;
          const ex = merges.findIndex((m) => m.name === name.toLowerCase());
          if (ex >= 0) merges.splice(ex, 1);
          merges.push({ name: name.toLowerCase(), index: mi });
          hidden.push(li, ri);
        }
        const partial = mkScope(seg, k + 1);
        joinPreds.push(resolveBooleanFilter(partial, predAst!, ptypes));
      } else if (j.on !== null) {
        const partial = mkScope(seg, k + 1);
        joinPreds.push(resolveBooleanFilter(partial, j.on, ptypes));
      } else {
        joinPreds.push(null);
      }
    }

    const scope = new Scope(rels, this, parent, true, ctes);
    scope.merges = merges;
    scope.hidden = hidden;

    // Expand GROUP BY (including ROLLUP / CUBE / GROUPING SETS) into a list of grouping sets, resolve
    // each set's columns to flat row indices, and build the master grouping-column list (groupKeys) —
    // the ordered union of every set's columns, i.e. the columns groupable in at least one set
    // (spec/design/aggregates.md §12). A plain GROUP BY a, b expands to a single set [a, b]; no GROUP
    // BY expands to a single empty set (the whole-table grand total). An unknown column is 42703, an
    // outer (correlated) key is degenerate and 0A000 (§26).
    // Each grouping term is one of (aggregates.md §15): a bare/qualified COLUMN; a select-list ORDINAL
    // (a bare integer literal — `GROUP BY 1`); an output ALIAS (a bare name that is not an input
    // column — PG's input-column-first rule); or a general EXPRESSION (`GROUP BY a+b`). A column key
    // keeps its real row slot (groupKeys holds its flat index); an expression key is MATERIALIZED —
    // its node collected into groupExprs and evaluated per row into a synthetic column inputWidth+k
    // whose index is the master key. groupKeyExprs records each master key's canonical AST (non-null
    // for expression keys) so a matching projection / HAVING / ORDER BY expression resolves to its
    // synthetic slot. The whole-row equality bucket machinery (resolvedSets, GROUPING SETS) is
    // unchanged — it works on master key indices.
    const expanded = expandGroupBy(sel.groupBy);
    const inputWidth = scope.width();
    const groupKeys: number[] = [];
    const groupKeyExprs: (GroupKeyExpr | null)[] = [];
    const groupExprs: RExpr[] = [];
    const resolvedSets: number[][] = expanded.map((set) =>
      set.map((key) => {
        const gr = resolveGroupTerm(scope, key, sel.items, ptypes);
        if (gr.kind === "column") {
          // `json` has no equality operator (PG ships no hash/btree opclass — spec/design/json.md §5),
          // so GROUP BY a json column is 42883. jsonb IS groupable.
          if (typeIsJson(scope.columnAt(gr.index).type)) {
            throw engineError(
              "undefined_function",
              "could not identify an equality operator for type json",
            );
          }
          const idx = gr.index;
          if (!groupKeys.includes(idx)) {
            groupKeys.push(idx);
            groupKeyExprs.push(null);
          }
          return idx;
        }
        // A general EXPRESSION key.
        if (gr.ty.kind === "json") {
          throw engineError(
            "undefined_function",
            "could not identify an equality operator for type json",
          );
        }
        // Reuse an identical expression key already registered (`GROUP BY a+b, a+b`).
        const pos = groupKeyExprs.findIndex((gk) => gk !== null && exprEqual(gk.canon, gr.canon));
        if (pos >= 0) return groupKeys[pos]!;
        const synth = inputWidth + groupExprs.length;
        groupExprs.push(gr.node);
        groupKeys.push(synth);
        groupKeyExprs.push({ canon: gr.canon, ty: gr.ty });
        return synth;
      }),
    );

    // Functional-dependency grouping (aggregates.md §16, PG): when there is a SINGLE grouping set
    // that contains every primary-key column of a base table T, T's PK functionally determines every
    // column of T, so any T column (and expressions over them) may appear ungrouped. Make them
    // groupable by adding T's remaining columns as extra master grouping keys — the grouping is
    // UNCHANGED (each is constant within a group, so bucketing by [pk…, others…] yields the same
    // partition as by [pk…] alone, even across a join). Restricted to a single set: PG rejects the
    // dependency when a grouping set omits the PK. A CTE / derived table / SRF has an empty pk (a
    // synthetic key), so only base tables with a real PK contribute.
    if (resolvedSets.length === 1) {
      const extra: number[] = [];
      for (const rel of scope.rels) {
        if (rel.qualifierOnly || rel.cte !== undefined || rel.table.pk.length === 0) continue;
        const pkGrouped = rel.table.pk.every((ord) => groupKeys.includes(rel.offset + ord));
        if (!pkGrouped) continue;
        for (let c = 0; c < rel.table.columns.length; c++) {
          const idx = rel.offset + c;
          if (!groupKeys.includes(idx) && !extra.includes(idx)) extra.push(idx);
        }
      }
      for (const idx of extra) {
        groupKeys.push(idx);
        groupKeyExprs.push(null);
        resolvedSets[0]!.push(idx);
      }
    }

    // An aggregate query has a GROUP BY or an aggregate in the select list. Its projection
    // resolves in collect mode — aggregates collect into synthetic slots and a non-grouped
    // column is 42803 (spec/design/aggregates.md §4/§6); a plain query resolves in Forbidden
    // mode (columns normal). Output names per grammar.md §8.
    // GROUP BY, an aggregate in the select list, OR a HAVING clause all make this an aggregate
    // query (HAVING alone groups the whole table — grammar.md §19).
    // An aggregate inside a window definition's keys also makes the query an aggregate query —
    // inline (`OVER (ORDER BY sum(x))`, caught by itemsHaveAggregate) or in a WINDOW-clause entry
    // (`WINDOW w AS (ORDER BY sum(x))`, scanned here before the desugar). spec/design/window.md §5.1.
    // Note sel.groupBy.length (not groupKeys): GROUP BY GROUPING SETS (()) has an empty master list
    // yet is still an aggregate query (the whole-table grand total).
    const isAgg =
      sel.groupBy.length > 0 ||
      itemsHaveAggregate(sel.items) ||
      sel.having !== null ||
      windowsHaveAggregate(sel.windows);
    // A window query (a select-list OVER call) resolves its projection in a window-aware mode, where
    // bare columns read the input/grouped row and window calls collect into synthetic slots
    // (spec/design/window.md §5.1). A grouped query that ALSO windows is both collecting AND windowing
    // (the window stage runs over the grouped rows — §2); a plain window query is only windowing.
    // A window function may appear in the SELECT list OR in an ORDER BY key (grammar.md §10): either
    // sets up the window machinery so the key can be sorted by the computed window value.
    const hasWindowSyntax = itemsHaveWindow(sel.items) || orderByHasWindow(sel.orderBy);
    // Window results land AFTER the materialized window keys, and (for a grouped query) after every
    // aggregate — neither final count is known until resolution finishes (an aggregate may be nested
    // in a later window argument or HAVING). So a window result carries the PLACEHOLDER base
    // WINDOW_RESULT_BASE, rebased afterwards to inputWidth+windowKeys.length+w (window.md §5.1); a
    // materialized window key carries WINDOW_KEY_BASE+k, rebased to inputWidth+k.
    const projAgg: AggCtx = hasWindowSyntax
      ? {
          collecting: isAgg,
          groupKeys,
          groupKeyExprs,
          specs: [],
          groupingSpecs: [],
          window: { base: WINDOW_RESULT_BASE, windowSpecs: [], windowKeys: [] },
        }
      : { collecting: isAgg, groupKeys, groupKeyExprs, specs: [], groupingSpecs: [] };
    // Resolve the WINDOW clause: an entry may extend an earlier entry (`w2 AS (w ORDER BY …)` —
    // window.md §5), so each is merged against the already-resolved earlier entries (a missing/
    // forward/self base is 42704; PARTITION/ORDER overrides and a framed base are 42P20). Every
    // entry is resolved, even unreferenced ones, matching PostgreSQL. The result is all-inline
    // (base = null) definitions the desugar pass copies/extends from.
    const windowsResolved = sel.windows.length > 0 ? resolveWindowClause(sel.windows) : sel.windows;
    // Desugar `OVER name` / `OVER (base …)` references to their WINDOW-clause definitions before
    // resolution (window.md §5). The projection resolves against the desugared items; a reference to
    // an undefined window is 42704. A plain query with no window clause/refs clones nothing extra.
    let itemsRef = sel.items;
    if (hasWindowSyntax) {
      const cloned = structuredClone(sel.items);
      desugarItems(cloned, windowsResolved);
      itemsRef = cloned;
    }
    const {
      nodes: projections,
      names: columnNames,
      types: columnTypes,
    } = resolveProjections(scope, itemsRef, projAgg, ptypes);
    let aggSpecs = projAgg.specs;
    let groupingSpecs: number[][] = projAgg.groupingSpecs ?? [];
    // The collected window specs + materialized window-key expressions (empty unless a window query).
    // spec/design/window.md §5.1.
    const windowSpecs: WindowSpec[] = projAgg.window?.windowSpecs ?? [];
    const windowKeys: RExpr[] = projAgg.window?.windowKeys ?? [];
    // hasWindow is computed after ORDER BY resolution (below) — an ORDER BY key may introduce the
    // first window spec, so the count is not final here.
    let hasWindow = false;
    // SELECT DISTINCT dedups the projected rows by equality, but `json` has no equality operator
    // (PG ships no opclass — spec/design/json.md §5), so a json output column under DISTINCT is
    // 42883. jsonb IS distinguishable (its btree equality, §5).
    if (sel.distinct && columnTypes.some((t) => t.kind === "json")) {
      throw engineError(
        "undefined_function",
        "could not identify an equality operator for type json",
      );
    }
    // HAVING resolves in collect mode with window functions FORBIDDEN (42P20 — HAVING runs BEFORE the
    // window stage, window.md §7), continuing the aggregate specs so its aggregates slot after the
    // projection's. It must be boolean (42804). A HAVING aggregate, like a projection one, is part of
    // the grouped row, so the window slots that follow are rebased over the final aggregate count.
    let having: RExpr | null = null;
    if (sel.having !== null) {
      const hctx: AggCtx = {
        collecting: true,
        groupKeys,
        groupKeyExprs,
        specs: aggSpecs,
        groupingSpecs,
      };
      const { node, type } = resolve(scope, sel.having, null, hctx, ptypes);
      if (type.kind !== "bool" && type.kind !== "null") {
        throw typeError("argument of HAVING must be boolean");
      }
      having = node;
      aggSpecs = hctx.specs;
      groupingSpecs = hctx.groupingSpecs ?? groupingSpecs;
    }
    // (The window / GROUPING() placeholder rebases run AFTER the ORDER BY resolution below, because an
    // ORDER BY key may itself introduce a window function / aggregate / GROUPING() — so the final spec
    // counts, and thus every placeholder's real slot, are not known until ORDER BY is resolved.)
    // Build the grouping sets (spec/design/aggregates.md §12). For an aggregate query with no GROUP BY
    // this is the single empty (whole-table) set; otherwise one entry per resolved set, each recording
    // its bucket key columns, the per-master-slot value source (or -1 = NULL), and the GROUPING() mask.
    const groupSets: GroupSet[] = isAgg
      ? resolvedSets.map((set) => {
          const slotSrc = new Array<number>(groupKeys.length).fill(-1);
          set.forEach((fidx, j) => {
            const p = groupKeys.indexOf(fidx);
            slotSrc[p] = j;
          });
          // bigint to match Rust/Go i64 exactly for >31 master columns (JS `<<` is 32-bit).
          let mask = 0n;
          for (let p = 0; p < slotSrc.length; p++) if (slotSrc[p] < 0) mask |= 1n << BigInt(p);
          return { keyCols: set.slice(), slotSrc, mask };
        })
      : [];
    // (The GROUPING SETS/window mutual-exclusion check and the GROUPING() placeholder rebase also run
    // after the ORDER BY resolution below — an ORDER BY GROUPING() grows groupingSpecs.)
    // SELECT DISTINCT over an aggregate query's output (output-row dedup) dedups the projected
    // group rows by equality, keeping the first occurrence, then LIMIT/OFFSET (aggregates.md §10) —
    // the same project->dedup->window pipeline as the non-aggregate DISTINCT path. The ORDER BY
    // restriction (each key must be a select-list item) is enforced once for both at the §11 block.
    const filter = sel.filter ? resolveBooleanFilter(scope, sel.filter, ptypes) : null;
    // ORDER BY resolution. In an aggregate query a key resolves against the GROUP KEYS — a
    // grouping column gives its synthetic-row slot, a non-grouping column is 42803 (the
    // grouping-error rule, grammar.md §18); the sort runs on the group rows. In a plain query
    // keys resolve against the FROM scope (a flat row index).
    // An outer (correlated) ORDER BY key — ordering by an enclosing-query constant — is degenerate
    // and 0A000 (§26).
    // ORDER BY resolution (spec/design/grammar.md §10). Each key is one of three modes (set at parse):
    // an output-column ORDINAL, a COLUMN reference, or a general EXPRESSION. A column / ordinal-to-column
    // key resolves to a real row slot (against the GROUP KEYS in an aggregate query — a grouping column
    // gives its synthetic slot, a non-grouping column is 42803; else against the FROM scope). A general-
    // expression key (and an ordinal pointing at a COMPUTED select-list item) is MATERIALIZED: its
    // expression is resolved here (introducing a new aggregate in a grouped query if it names one),
    // collected into orderExprs, and given a placeholder sort slot ORDER_EXPR_BASE+k rebased to
    // finalWidth+k below — the window-key precedent (window.md §5.1).
    const order: OrderSlot[] = [];
    const orderExprs: RExpr[] = [];
    const items = sel.items;
    for (const key of sel.orderBy) {
      // Classify the key into a row slot (a column / ordinal-to-column) or a source expression (a
      // general expression, or an ordinal pointing at a computed projection).
      let slotRes: Resolved | null = null;
      let orderExpr: Expr | null = null;
      if (key.ordinal !== null) {
        const ord = key.ordinal;
        const ncols = items.kind === "all" ? scope.width() : items.items.length;
        if (ord < 1 || ord > ncols) {
          throw engineError(
            "invalid_column_reference",
            `ORDER BY position ${ord} is not in select list`,
          );
        }
        const pos = ord - 1;
        if (items.kind === "all") {
          slotRes = { level: 0, index: pos };
        } else {
          const e = items.items[pos]!.expr;
          if (e.kind === "column") slotRes = scope.resolveBare(e.name);
          else if (e.kind === "qualifiedColumn")
            slotRes = scope.resolveQualified(e.qualifier, e.name);
          else orderExpr = e;
        }
      } else if (key.expr !== null) {
        orderExpr = key.expr;
      } else if (key.qualifier !== null) {
        // A qualified key (`t.a`) is always an input column — never an output alias (PG; §10).
        slotRes = scope.resolveQualified(key.qualifier, key.column);
      } else {
        // A bare name resolves an OUTPUT column (an AS alias or item's derived name) BEFORE an input
        // column — PostgreSQL's SQL92 rule (grammar.md §10). A match routes the item EXACTLY like the
        // same ORDER BY ordinal; no match falls through to the FROM scope (the prior behavior).
        const matched = orderAliasMatch(items, key.column, scope);
        if (matched === null) slotRes = scope.resolveBare(key.column);
        else if (matched.kind === "column") slotRes = scope.resolveBare(matched.name);
        else if (matched.kind === "qualifiedColumn")
          slotRes = scope.resolveQualified(matched.qualifier, matched.name);
        else orderExpr = matched;
      }

      if (orderExpr === null) {
        // A column / ordinal-to-column key resolves to a real row slot.
        const r = slotRes!;
        if (r.level !== 0) {
          // A correlated (outer) column ORDER BY key — the local sort row has no slot for an
          // enclosing-query column, so materialize it as an OuterColumn expression evaluated per row
          // against the outer-row environment (query.order_by_correlated), exactly like a general-
          // expression key. PostgreSQL accepts it (a degenerate constant leading key).
          const col = scope.columnOf(r);
          if (typeIsJson(col.type)) {
            throw engineError(
              "undefined_function",
              "could not identify an ordering operator for type json",
            );
          }
          let oCollation: Collation | null = null;
          if (key.collation !== null) {
            if (!typeIsText(col.type)) {
              throw typeError(
                `collations are not supported by type ${typeCanonicalName(col.type)}`,
              );
            }
            oCollation = resolveCollationName(scope.catalog, key.collation);
          } else if (col.collation !== null) {
            oCollation = resolveCollationName(scope.catalog, col.collation);
          }
          const k = orderExprs.length;
          orderExprs.push({ kind: "outerColumn", level: r.level, index: r.index });
          order.push({
            idx: ORDER_EXPR_BASE + k,
            descending: key.descending,
            nullsFirst: key.nullsFirst,
            collation: oCollation,
          });
          continue;
        }
        // `json` has no ordering operator (PG ships no btree opclass — spec/design/json.md §5):
        // ORDER BY a json column is 42883. jsonb IS orderable (its btree total order, §5).
        if (typeIsJson(scope.columnAt(r.index).type)) {
          throw engineError(
            "undefined_function",
            "could not identify an ordering operator for type json",
          );
        }
        const idx = r.index;
        // The sort key's collation (spec/design/collation.md §1/§7). An explicit COLLATE must be on a
        // text column (42804) and name a loaded collation ("C" → byte order, else 42704); absent a
        // clause, the key inherits the column's frozen (implicit) collation.
        let collation: Collation | null = null;
        if (key.collation !== null) {
          if (!typeIsText(scope.columnAt(idx).type)) {
            throw typeError(
              `collations are not supported by type ${typeCanonicalName(scope.columnAt(idx).type)}`,
            );
          }
          collation = resolveCollationName(scope.catalog, key.collation);
        } else {
          const cn = scope.columnAt(idx).collation;
          if (cn !== null) collation = resolveCollationName(scope.catalog, cn);
        }
        let slot = idx;
        if (isAgg) {
          slot = groupKeys.indexOf(idx);
          if (slot < 0) throw groupingErrorColumn(key.column);
        }
        order.push({
          idx: slot,
          descending: key.descending,
          nullsFirst: key.nullsFirst,
          collation,
        });
        continue;
      }

      // Resolve the key expression in the SAME context the projection used, so a window function /
      // GROUPING() / aggregate it contains collects into the shared specs and references the same
      // placeholders (rebased together after this loop — grammar.md §10): a grouped query collects over
      // the group keys + aggregates + GROUPING() calls (a new aggregate or GROUPING() the select list
      // lacks is allowed); a window query collects window specs/keys; a grouped+window query does both
      // (query.order_by_grouped_window); a plain query forbids aggregates (42803) and window functions
      // (42P20).
      const octx: AggCtx = hasWindowSyntax
        ? {
            collecting: isAgg,
            groupKeys,
            groupKeyExprs,
            specs: aggSpecs,
            groupingSpecs,
            window: { base: WINDOW_RESULT_BASE, windowSpecs, windowKeys },
          }
        : { collecting: isAgg, groupKeys, groupKeyExprs, specs: aggSpecs, groupingSpecs };
      const { node, type } = resolve(scope, orderExpr, null, octx, ptypes);
      aggSpecs = octx.specs;
      groupingSpecs = octx.groupingSpecs ?? groupingSpecs;
      // A correlated ORDER BY expression (one referencing an enclosing query) is allowed
      // (query.order_by_correlated): the outer column is a per-evaluation constant of the enclosing
      // row, evaluated against the outer-row environment still in scope when materializeOrderExprs
      // runs. PostgreSQL accepts it; it is a degenerate (constant) leading key.
      // A non-orderable result type — json (no btree opclass) — is 42883; jsonb orders.
      if (type.kind === "json") {
        throw engineError(
          "undefined_function",
          "could not identify an ordering operator for type json",
        );
      }
      // The collation of an expression key (collation.md §1): an explicit trailing COLLATE (rare —
      // parseExpr usually absorbs one into the key) must be on a text key (42804); otherwise it is
      // DERIVED from the key expression.
      let coll: Collation | null = null;
      if (key.collation !== null) {
        if (type.kind !== "text" && type.kind !== "null") {
          throw typeError(`collations are not supported by type ${rtName(type)}`);
        }
        coll = resolveCollationName(scope.catalog, key.collation);
      } else {
        coll = resolveDeriv(scope.catalog, deriveCollation(scope, orderExpr));
      }
      const k = orderExprs.length;
      orderExprs.push(node);
      order.push({
        idx: ORDER_EXPR_BASE + k,
        descending: key.descending,
        nullsFirst: key.nullsFirst,
        collation: coll,
      });
    }
    // All specs are now final (an ORDER BY key may have introduced a window function / aggregate /
    // GROUPING()). Recompute hasWindow and rebase every placeholder — in the projections, HAVING, AND
    // the materialized ORDER BY expressions — to its real trailing slot (window.md §5.1). The window
    // stage's row is [input… , materialized window keys… , window results…]; inputWidth is the grouped
    // row's width (group keys + every aggregate) for a grouped+window query, else the FROM scope width.
    hasWindow = windowSpecs.length > 0;
    if (hasWindow) {
      // The grouped row the window stage extends is `[master cols…, agg results…, GROUPING
      // results…]` (the GROUPING columns precede the window columns — aggregates.md §21), so a
      // grouped+window query's window input width includes the GROUPING() results.
      const inputWidth = isAgg
        ? groupKeys.length + aggSpecs.length + groupingSpecs.length
        : scope.width();
      const keyBase = inputWidth;
      const resultBase = inputWidth + windowKeys.length;
      // Bound each manual WINDOW_KEY_BASE rewrite to [WINDOW_KEY_BASE, 2·WINDOW_KEY_BASE) so a
      // GROUPING() placeholder (the higher GROUPING_GS_BASE) in a window key is not clobbered here
      // (it rebases below — §21).
      for (const spec of windowSpecs) {
        for (let j = 0; j < spec.partition.length; j++) {
          if (spec.partition[j] >= WINDOW_KEY_BASE && spec.partition[j] < WINDOW_KEY_BASE * 2) {
            spec.partition[j] = keyBase + (spec.partition[j] - WINDOW_KEY_BASE);
          }
        }
        for (const o of spec.order) {
          if (o.idx >= WINDOW_KEY_BASE && o.idx < WINDOW_KEY_BASE * 2) {
            o.idx = keyBase + (o.idx - WINDOW_KEY_BASE);
          }
        }
      }
      for (const p of projections) rebasePlaceholderCols(p, WINDOW_RESULT_BASE, resultBase);
      for (const oe of orderExprs) rebasePlaceholderCols(oe, WINDOW_RESULT_BASE, resultBase);
    }
    // GROUPING SETS / GROUPING() combined with window functions (spec/design/aggregates.md §21): the
    // window stage runs over the unioned grouping-set rows. The grouped row is `[master cols…, agg
    // results…, GROUPING results…]` and the window stage appends `[window keys…, window results…]`
    // after, so the two no longer collide — GROUPING rebases below the window bases.
    // Rebase the GROUPING() placeholder slots to their real trailing synthetic slots
    // groupKeys.length+aggSpecs.length+g (the GROUPING results follow the master columns and aggregate
    // results — §12), in the projections, HAVING, and the materialized ORDER BY expressions.
    if (groupingSpecs.length > 0) {
      const gbase = groupKeys.length + aggSpecs.length;
      for (const p of projections) rebasePlaceholderCols(p, GROUPING_GS_BASE, gbase);
      if (having !== null) rebasePlaceholderCols(having, GROUPING_GS_BASE, gbase);
      for (const oe of orderExprs) rebasePlaceholderCols(oe, GROUPING_GS_BASE, gbase);
    }
    // Rebase each materialized expression-key slot to its real trailing position now that the row layout
    // is final. The materialized order values are appended AFTER the input / window / grouped columns
    // (grammar.md §10): for a grouped+window query the grouped row is first extended by the window stage,
    // so the order values follow the window results.
    const orderValueBase =
      isAgg && hasWindow
        ? groupKeys.length +
          aggSpecs.length +
          groupingSpecs.length +
          windowKeys.length +
          windowSpecs.length
        : isAgg
          ? groupKeys.length + aggSpecs.length + groupingSpecs.length
          : hasWindow
            ? scope.width() + windowKeys.length + windowSpecs.length
            : scope.width();
    for (const o of order) {
      if (o.idx >= ORDER_EXPR_BASE) o.idx = orderValueBase + (o.idx - ORDER_EXPR_BASE);
    }

    // SELECT DISTINCT restriction (spec/design/grammar.md §11): once duplicates collapse, an ORDER BY
    // key must have a per-row value in the projected output — a bare/qualified column that is projected,
    // an ordinal (which names a select-list item by position), or a general expression that STRUCTURALLY
    // matches a select-list item. Otherwise 42P10 (matching PostgreSQL). Aliases are invisible to ORDER
    // BY (§8); a SELECT DISTINCT * projects every column, so the restriction never bites.
    if (sel.distinct && sel.orderBy.length > 0 && items.kind === "list") {
      const projected = new Set<number>();
      for (const it of items.items) {
        if (it.expr.kind === "column") {
          const r = scope.resolveBare(it.expr.name);
          if (r.level === 0) projected.add(r.index);
        } else if (it.expr.kind === "qualifiedColumn") {
          const r = scope.resolveQualified(it.expr.qualifier, it.expr.name);
          if (r.level === 0) projected.add(r.index);
        }
      }
      for (const key of sel.orderBy) {
        let inList: boolean;
        if (key.ordinal !== null) {
          inList = true;
        } else if (key.expr !== null) {
          const ke = key.expr;
          inList = items.items.some((it) => exprEqual(ke, it.expr));
        } else if (key.qualifier === null && orderAliasMatch(items, key.column, scope) !== null) {
          // A bare name that binds an output column (alias/derived name) names a select-list item, so
          // it is projected (the alias form, §10). Ambiguity was already raised in the loop above.
          inList = true;
        } else {
          const r =
            key.qualifier !== null
              ? scope.resolveQualified(key.qualifier, key.column)
              : scope.resolveBare(key.column);
          inList = r.level === 0 && projected.has(r.index);
        }
        if (!inList) {
          throw engineError(
            "invalid_column_reference",
            "for SELECT DISTINCT, ORDER BY expressions must appear in select list",
          );
        }
      }
    }

    // The join predicates were resolved above (alongside the USING/NATURAL merges, which the scope
    // now carries). Pair each with its join kind — the kind only changes how unmatched rows are
    // handled in the executor loop, not the predicate (grammar.md §15).
    const joins: PlanJoin[] = sel.joins.map((j, k) => ({ kind: j.kind, on: joinPreds[k]! }));

    // Assemble the owned LOGICAL plan (table NAMES + offsets/widths replace the scope's tables, so
    // the plan outlives the scope and a correlated subquery can re-execute it per row). Resolve
    // decides names, types, and errors — never an access path: plan.phys is zero-valued here, and
    // only the optimizeSelect pass below writes it (spec/design/planner.md §2).
    const planRels: PlanRel[] = scope.rels.map((rel, i) => ({
      tableName: rel.table.name,
      db: rel.db,
      offset: rel.offset,
      colCount: rel.table.columns.length,
      srf: srfPlans[i],
      cte: rel.cte,
      derived: derivedPlans[i],
      lateral: lateralFlags[i],
    }));
    const plan: SelectPlan = {
      kind: "select",
      rels: planRels,
      joins,
      filter,
      isAgg,
      groupKeys,
      groupExprs,
      groupSets,
      groupingSpecs,
      aggSpecs,
      hasWindow,
      windowSpecs,
      windowKeys,
      having,
      order,
      orderExprs,
      projections,
      columnNames,
      columnTypes,
      distinct: sel.distinct,
      limit: sel.limit,
      offset: sel.offset,
      relMasks: [],
      phys: {
        pkOrdered: false,
        pkReverse: false,
        indexOrder: null,
        joinPkOrdered: false,
        relBounds: [],
        relINLBounds: [],
      },
    };
    plan.relMasks = computeRelMasks(plan);
    // ——— Stage 2: logical rewrite rules (spec/design/planner.md §3) ———
    // No rewrite rules exist yet; the first (predicate pushdown / simplification, TODO.md) lands
    // here as pure plan→plan transforms. foldUncorrelatedInPlan is NOT a planner rewrite — it
    // executes subqueries and needs bound params, so it stays post-bind in the statement drivers.
    //
    // ——— Stage 3: physical/access-path selection (spec/design/planner.md §4) ———
    optimizeSelect(plan, scope.rels, this.readSnap(), this);
    return plan;
  }

  // resolveSRF resolves a FROM-clause set-returning function call (generate_series(...)) into a
  // SYNTHETIC one-column relation plus its resolved argument expressions (spec/design/functions.md
  // §10). Only generate_series exists this slice (any other name → 42883), with 2 or 3 integer
  // args (a wrong arity/type → 42883). Non-LATERAL: the args resolve against an EMPTY-local-rels
  // scope whose parent is the enclosing query, so $N and correlated outer columns resolve while a
  // sibling FROM table does not (42703/42P01). The produced column is typed at the PROMOTED
  // integer type of the args (PG); a NULL-typed arg contributes no width. Its NAME follows
  // PostgreSQL's single-column function-alias rule: the table alias when one is given
  // (generate_series(1,5) AS g ⇒ column g), else the function name generate_series.
  private resolveSRF(
    name: string,
    args: Expr[],
    alias: string | null,
    columnDefs: TypeFieldDef[] | null,
    parent: Scope | null,
    ctes: CteBinding[],
    ptypes: ParamTypes,
  ): { table: Table; srf: SrfPlan } {
    // The args see only params/outer — never sibling FROM tables (non-LATERAL); CTE bindings are
    // inherited so an arg subquery can reference a CTE (cte.md §2).
    const argScope = new Scope([], this, parent, true, ctes);
    const lname = name.toLowerCase();
    // Record-returning functions (R1, json-table.md §2): json[b]_to_record → one record row,
    // json[b]_to_recordset → setof record. They take their column shape from the C0 col-def list
    // `AS t(col type, …)`. Dispatched FIRST, before the col-def-list guard below.
    if (
      lname === "json_to_record" ||
      lname === "jsonb_to_record" ||
      lname === "json_to_recordset" ||
      lname === "jsonb_to_recordset"
    ) {
      const jsonb = lname.startsWith("jsonb");
      const set = lname.endsWith("set");
      return this.resolveJsonRecord(lname, jsonb, set, args, alias, columnDefs, argScope, ptypes);
    }
    // json[b]_populate_record(set) (R2, json-table.md §2): like json[b]_to_record(set) but the
    // column shape comes from the COMPOSITE TYPE of the (typically NULL) first argument.
    if (
      lname === "json_populate_record" ||
      lname === "jsonb_populate_record" ||
      lname === "json_populate_recordset" ||
      lname === "jsonb_populate_recordset"
    ) {
      const jsonb = lname.startsWith("jsonb");
      const set = lname.endsWith("set");
      return this.resolveJsonPopulate(lname, jsonb, set, args, alias, argScope, ptypes);
    }
    // A column-definition list is valid ONLY on a record-returning function (PG).
    if (columnDefs !== null) {
      throw engineError(
        "syntax_error",
        "a column definition list is only allowed for a record-returning function, not " + name,
      );
    }
    if (lname === "generate_series")
      return this.resolveGenerateSeries(args, alias, argScope, ptypes);
    if (lname === "unnest") return this.resolveUnnest(args, alias, argScope, ptypes);
    // json/jsonb two-column SRFs (B3, json-sql-functions.md §3): jsonb_each → (key text, value
    // jsonb), jsonb_each_text → (key text, value text). The json variants (verbatim sub-text,
    // json.md §4) are a deferred 0A000 follow-on. Built on the C0 multi-column synthetic table.
    switch (lname) {
      case "jsonb_each":
        return this.resolveJsonEach(
          lname,
          "jsonb_each",
          scalarT("jsonb"),
          args,
          alias,
          argScope,
          ptypes,
        );
      case "jsonb_each_text":
        return this.resolveJsonEach(
          lname,
          "jsonb_each_text",
          scalarT("text"),
          args,
          alias,
          argScope,
          ptypes,
        );
      case "json_each":
      case "json_each_text":
        throw engineError(
          "feature_not_supported",
          lname + " is not supported yet; use the jsonb variant",
        );
    }
    // jsonb_path_query(jsonb, jsonpath) (P2, jsonpath.md §5.2): the SRF form — one `jsonb` row per
    // item of the path's evaluation sequence over the context document. A bare string literal adapts.
    if (lname === "jsonb_path_query") {
      const forbidden: AggCtx = { collecting: false, groupKeys: [], specs: [] };
      const [ctx, path] = resolveJsonpathArgs(argScope, lname, args, forbidden, ptypes);
      const table = srfTable(lname, alias, scalarT("jsonb"));
      return { table, srf: { kind: "jsonb_path_query", args: [ctx, path] } };
    }
    // json/jsonb single-column SRFs (B2, json-sql-functions.md §3). The json `array_elements`
    // variants preserve the verbatim sub-text (json.md §4) and are a deferred 0A000 follow-on, like
    // the json accessor operators; the jsonb variants + `json_object_keys` ship here.
    switch (lname) {
      case "jsonb_array_elements":
        return this.resolveJsonSrf(
          lname,
          "jsonb_array_elements",
          scalarT("jsonb"),
          true,
          args,
          alias,
          argScope,
          ptypes,
        );
      case "jsonb_array_elements_text":
        return this.resolveJsonSrf(
          lname,
          "jsonb_array_elements_text",
          scalarT("text"),
          true,
          args,
          alias,
          argScope,
          ptypes,
        );
      case "jsonb_object_keys":
        return this.resolveJsonSrf(
          lname,
          "jsonb_object_keys",
          scalarT("text"),
          true,
          args,
          alias,
          argScope,
          ptypes,
        );
      case "json_object_keys":
        return this.resolveJsonSrf(
          lname,
          "json_object_keys",
          scalarT("text"),
          false,
          args,
          alias,
          argScope,
          ptypes,
        );
      case "json_array_elements":
      case "json_array_elements_text":
        throw engineError(
          "feature_not_supported",
          lname + " is not supported yet; use the jsonb variant",
        );
    }
    throw engineError("undefined_function", "function does not exist: " + name);
  }

  // resolveJsonSrf resolves a json/jsonb single-column SRF (B2, json-sql-functions.md §3): the one
  // argument is a json/jsonb value (a bare string literal adapts to the expected document type). The
  // synthetic column's type is fixed (`jsonb`/`text`). A NULL argument yields zero rows at exec.
  private resolveJsonSrf(
    name: string,
    kind: SrfKind,
    colTy: Type,
    jsonb: boolean,
    args: Expr[],
    alias: string | null,
    argScope: Scope,
    ptypes: ParamTypes,
  ): { table: Table; srf: SrfPlan } {
    if (args.length !== 1) throw noFuncOverload(name);
    const forbidden: AggCtx = { collecting: false, groupKeys: [], specs: [] };
    const { node, type } = resolve(argScope, args[0]!, jsonb ? "jsonb" : "json", forbidden, ptypes);
    const ok =
      type.kind === "null" || (jsonb && type.kind === "jsonb") || (!jsonb && type.kind === "json");
    if (!ok) throw noFuncOverload(name);
    const table = srfTable(name, alias, colTy);
    return { table, srf: { kind, args: [node] } };
  }

  // resolveJsonEach resolves a json/jsonb TWO-column SRF (B3 — jsonb_each / jsonb_each_text,
  // json-sql-functions.md §3): the one argument is a jsonb value (a bare string literal adapts). The
  // synthetic relation has the fixed columns `key text` and `value <valueTy>` (the C0 multi-column
  // synthetic table). A non-object argument → 22023 at exec; a NULL → zero rows.
  private resolveJsonEach(
    name: string,
    kind: SrfKind,
    valueTy: Type,
    args: Expr[],
    alias: string | null,
    argScope: Scope,
    ptypes: ParamTypes,
  ): { table: Table; srf: SrfPlan } {
    if (args.length !== 1) throw noFuncOverload(name);
    const forbidden: AggCtx = { collecting: false, groupKeys: [], specs: [] };
    const { node, type } = resolve(argScope, args[0]!, "jsonb", forbidden, ptypes);
    if (type.kind !== "jsonb" && type.kind !== "null") throw noFuncOverload(name);
    const table = srfTableCols(name, alias, [
      ["key", scalarT("text")],
      ["value", valueTy],
    ]);
    return { table, srf: { kind, args: [node] } };
  }

  // resolveJsonRecord resolves a json/jsonb RECORD-returning SRF (R1 — `json[b]_to_record` /
  // `json[b]_to_recordset`, json-table.md §2): the one argument is a json/jsonb document; the output
  // columns come from the C0 col-def list `AS t(col type, …)` (required — else 42601). The synthetic
  // table's columns are the declared types (a composite/array column type is a deferred 0A000).
  private resolveJsonRecord(
    name: string,
    jsonb: boolean,
    set: boolean,
    args: Expr[],
    alias: string | null,
    columnDefs: TypeFieldDef[] | null,
    argScope: Scope,
    ptypes: ParamTypes,
  ): { table: Table; srf: SrfPlan } {
    if (args.length !== 1) throw noFuncOverload(name);
    const forbidden: AggCtx = { collecting: false, groupKeys: [], specs: [] };
    const { node, type } = resolve(argScope, args[0]!, jsonb ? "jsonb" : "json", forbidden, ptypes);
    const ok =
      type.kind === "null" || (jsonb && type.kind === "jsonb") || (!jsonb && type.kind === "json");
    if (!ok) throw noFuncOverload(name);
    if (columnDefs === null) {
      throw engineError(
        "syntax_error",
        "a column definition list is required for function " + name,
      );
    }
    const columns: Column[] = [];
    for (const d of columnDefs) {
      // A composite/array column type in the col-def list is a deferred 0A000 follow-on.
      if (d.typeName.endsWith("[]") || this.compositeType(d.typeName) !== undefined) {
        throw engineError(
          "feature_not_supported",
          "a composite/array column in a record column-definition list is not supported yet",
        );
      }
      const [st, decimal, varcharLen] = resolveTypeAndTypmod(d.typeName, d.typeMod);
      columns.push({
        name: d.name,
        type: scalarT(st),
        decimal,
        varcharLen,
        primaryKey: false,
        notNull: false,
        default: null,
        defaultExpr: null,
        identity: null,
        collation: null,
      });
    }
    const table: Table = {
      name: alias ?? name,
      columns,
      pk: [],
      checks: [],
      indexes: [],
      fks: [],
      exclusions: [],
    };
    // The declared columns ride on the plan so the row generator can map members → columns by name.
    return {
      table,
      srf: { kind: "json_record", args: [node], recordSet: set, recordCols: columns },
    };
  }

  // resolveJsonPopulate resolves a json/jsonb POPULATE-RECORD SRF (R2 — `json[b]_populate_record(set)`,
  // json-table.md §2): the FIRST argument is a (typically NULL) value whose COMPOSITE TYPE supplies
  // the output column shape; the SECOND is the json/jsonb document. Reuses the R1 row machinery
  // (the `json_record` kind) — only the column source differs (a composite type vs a col-def list). A
  // non-composite first argument → 42804; an anonymous record base → 0A000.
  private resolveJsonPopulate(
    name: string,
    jsonb: boolean,
    set: boolean,
    args: Expr[],
    alias: string | null,
    argScope: Scope,
    ptypes: ParamTypes,
  ): { table: Table; srf: SrfPlan } {
    if (args.length !== 2) throw noFuncOverload(name);
    const forbidden: AggCtx = { collecting: false, groupKeys: [], specs: [] };
    // The base argument's COMPOSITE type fixes the columns (its value is unused — usually NULL).
    const { type: bt } = resolve(argScope, args[0]!, null, forbidden, ptypes);
    if (bt.kind !== "composite") {
      throw engineError(
        "datatype_mismatch",
        "the first argument of " + name + " must be a composite type",
      );
    }
    // A named composite supplies the columns; an anonymous record base is 0A000.
    if (bt.name === null) {
      throw engineError("feature_not_supported", "an anonymous record base is not supported yet");
    }
    const ctype = this.compositeType(bt.name);
    if (ctype === undefined) {
      throw engineError("undefined_object", "composite type no longer exists");
    }
    const columns: Column[] = ctype.fields.map((f: CompositeField) => ({
      name: f.name,
      type: f.type,
      decimal: f.decimal,
      varcharLen: f.varcharLen,
      primaryKey: false,
      notNull: false,
      default: null,
      defaultExpr: null,
      identity: null,
      collation: null,
    }));
    // The SECOND argument is the json/jsonb document.
    const { node: doc, type } = resolve(
      argScope,
      args[1]!,
      jsonb ? "jsonb" : "json",
      forbidden,
      ptypes,
    );
    const ok =
      type.kind === "null" || (jsonb && type.kind === "jsonb") || (!jsonb && type.kind === "json");
    if (!ok) throw noFuncOverload(name);
    const table: Table = {
      name: alias ?? name,
      columns,
      pk: [],
      checks: [],
      indexes: [],
      fks: [],
      exclusions: [],
    };
    // The SRF arg is the json DOCUMENT (the base value is unused); reuse the R1 row generator.
    return {
      table,
      srf: { kind: "json_record", args: [doc], recordSet: set, recordCols: columns },
    };
  }

  // resolveJsonTable resolves a `JSON_TABLE(ctx, path COLUMNS (…))` source (T1, json-table.md §3) →
  // its synthetic relation (the flattened columns), the `[ctx]` arg, and the resolved JtPlan. Port of
  // impl/rust/src/executor.rs `resolve_json_table`.
  private resolveJsonTable(
    jt: JsonTable,
    alias: string | null,
    parent: Scope | null,
    ctes: CteBinding[],
    ptypes: ParamTypes,
  ): { table: Table; srf: SrfPlan } {
    // The ctx / root path see only params + the lateral prefix (never sibling columns of THIS
    // relation) — an empty-local-rels scope chained to `parent`, exactly like an SRF (§44).
    const argScope = new Scope([], this, parent, true, ctes);
    const forbidden: AggCtx = { collecting: false, groupKeys: [], specs: [] };
    // The context item (json / jsonb / text, coerced to a jsonb document at eval).
    const rctx = resolve(argScope, jt.ctx, "jsonb", forbidden, ptypes);
    switch (rctx.type.kind) {
      case "jsonb":
      case "json":
      case "text":
      case "null":
        break;
      default:
        throw engineError(
          "datatype_mismatch",
          "the context item of JSON_TABLE must be json/jsonb/text, not " + rtName(rctx.type),
        );
    }
    // The root path — a constant jsonpath (a string literal compiles).
    const rpath = resolve(argScope, jt.path, "jsonpath", forbidden, ptypes);
    if (rpath.type.kind !== "jsonpath") {
      throw engineError("datatype_mismatch", "the path of JSON_TABLE must be a constant jsonpath");
    }
    if (rpath.node.kind !== "constJsonPath") {
      throw engineError("feature_not_supported", "a non-constant JSON_TABLE path is not supported");
    }
    const rootPath = rpath.node.value;
    const outColumns: Column[] = [];
    const columns = this.resolveJtColumns(jt.columns, outColumns);
    const width = outColumns.length;
    const table: Table = {
      name: alias ?? "json_table",
      columns: outColumns,
      pk: [],
      checks: [],
      indexes: [],
      fks: [],
      exclusions: [],
    };
    return {
      table,
      srf: { kind: "json_table", args: [rctx.node], jtPlan: { rootPath, width, columns } },
    };
  }

  // resolveJtColumns recursively resolves a `JSON_TABLE` COLUMNS tree, flattening the leaf columns
  // into `outColumns` (pre-order, declaration order) and assigning each its flat output index. Port
  // of impl/rust/src/executor.rs `resolve_jt_columns`.
  private resolveJtColumns(cols: JtColumn[], outColumns: Column[]): JtCol[] {
    const resolved: JtCol[] = [];
    for (const col of cols) {
      switch (col.kind) {
        case "ordinality": {
          const idx = outColumns.length;
          outColumns.push(jtColumn(col.name, "i32", null));
          resolved.push({ kind: "ordinality", idx });
          break;
        }
        case "regular": {
          if (col.array) {
            throw engineError(
              "feature_not_supported",
              "an array JSON_TABLE column is not supported yet",
            );
          }
          const st = jtScalarType(this, col.typeName);
          if (!col.keepQuotes) {
            throw engineError(
              "feature_not_supported",
              "JSON_TABLE OMIT QUOTES is not supported yet",
            );
          }
          const query = st === "json" || st === "jsonb";
          if (!query && col.wrapper !== "without") {
            throw engineError(
              "feature_not_supported",
              "a WRAPPER on a scalar JSON_TABLE column is not supported yet",
            );
          }
          const compiled = jtCompilePath(col.path, col.name);
          const idx = outColumns.length;
          outColumns.push(jtColumn(col.name, st, null));
          resolved.push({
            kind: "regular",
            idx,
            returning: st,
            decimal: null,
            path: compiled,
            query,
            wrapper: col.wrapper,
            onEmpty: col.onEmpty ?? "null",
            onError: col.onError ?? "null",
          });
          break;
        }
        case "exists": {
          const st = jtScalarType(this, col.typeName);
          const compiled = jtCompilePath(col.path, col.name);
          const idx = outColumns.length;
          outColumns.push(jtColumn(col.name, st, null));
          resolved.push({
            kind: "exists",
            idx,
            returning: st,
            path: compiled,
            onError: col.onError ?? "false",
          });
          break;
        }
        case "nested": {
          const compiled = jsonPathRender(jsonPathCompile(col.path));
          const nested = this.resolveJtColumns(col.columns, outColumns);
          resolved.push({ kind: "nested", path: compiled, columns: nested });
          break;
        }
      }
    }
    return resolved;
  }

  // jsonTableRows generates the rows of a `JSON_TABLE` SRF (T1, json-table.md §3) — the default-plan
  // recursive expansion (parent→child LEFT OUTER, sibling NESTED paths UNIONed). Port of
  // impl/rust/src/executor.rs `json_table_rows`.
  private jsonTableRows(srf: SrfPlan, env: EvalEnv, meter: Meter): Row[] {
    const plan = srf.jtPlan;
    if (plan === undefined) throw new Error("a json_table SRF carries its plan");
    const ctx = evalExpr(srf.args[0]!, [], env, meter);
    if (ctx.kind === "null") return [];
    const node = jsonArgNode(ctx);
    // The root path → the sequence of row items (a structural error here yields no rows).
    const root = jsonPathCompile(plan.rootPath);
    let items: JsonNode[];
    try {
      items = jsonPathEval(root, node);
    } catch {
      items = [];
    }
    // Expand the column tree over the root sequence → sparse rows, then materialize.
    const sparse = expandJtLevel(plan.columns, items, env, meter);
    const out: Row[] = [];
    for (const assignment of sparse) {
      meter.guard();
      meter.charge(COSTS.generatedRow);
      const row: Value[] = new Array(plan.width).fill(nullValue());
      for (const [idx, v] of assignment) {
        row[idx] = v;
      }
      out.push(row);
    }
    return out;
  }

  // resolveGenerateSeries resolves generate_series(start, stop[, step]) (spec/design/functions.md
  // §10): 2 or 3 integer args (a wrong arity/type → 42883). The produced column is typed at the
  // PROMOTED integer type of the args (PG); a NULL-typed arg contributes no width. All-NULL defaults
  // i64.
  private resolveGenerateSeries(
    args: Expr[],
    alias: string | null,
    argScope: Scope,
    ptypes: ParamTypes,
  ): { table: Table; srf: SrfPlan } {
    if (args.length !== 2 && args.length !== 3) throw noFuncOverload("generate_series");
    const forbidden: AggCtx = { collecting: false, groupKeys: [], specs: [] };
    const rargs: RExpr[] = [];
    let result: ScalarType | null = null;
    for (const a of args) {
      const { node, type } = resolve(argScope, a, "i64", forbidden, ptypes);
      if (type.kind === "int") {
        if (result === null || rank(type.ty) > rank(result)) result = type.ty;
      } else if (type.kind === "null") {
        // An untyped NULL/param adapts and contributes no width.
      } else {
        throw noFuncOverload("generate_series");
      }
      rargs.push(node);
    }
    const table = srfTable("generate_series", alias, scalarT(result ?? "i64"));
    return { table, srf: { kind: "generate_series", args: rargs } };
  }

  // resolveUnnest resolves unnest(anyarray) (spec/design/array-functions.md §9, §13): the single
  // argument must be an array (binding ELEM := its element type, the produced column's type), else
  // 42883 (a non-array, e.g. unnest(5)). A bare untyped NULL argument leaves ELEM undeterminable →
  // 42P18 (jed's polymorphic posture, like array_append(NULL, NULL)); a typed NULL array
  // (NULL::i32[]) resolves and yields zero rows at exec. ELEM may be a scalar OR a composite (AF7 —
  // unnest(composite[])): the synthetic column is typed at the bound element type directly
  // (typeFromResolved), so a composite array produces composite rows (an anonymous-composite element
  // has no catalog name → 0A000, not reachable from a typed array).
  private resolveUnnest(
    args: Expr[],
    alias: string | null,
    argScope: Scope,
    ptypes: ParamTypes,
  ): { table: Table; srf: SrfPlan } {
    if (args.length !== 1) throw noFuncOverload("unnest");
    const forbidden: AggCtx = { collecting: false, groupKeys: [], specs: [] };
    const { node, type } = resolve(argScope, args[0]!, null, forbidden, ptypes);
    if (type.kind === "array") {
      const elemTy = typeFromResolved(type.elem);
      const table = srfTable("unnest", alias, elemTy);
      return { table, srf: { kind: "unnest", args: [node] } };
    }
    if (type.kind === "null") throw indeterminatePoly();
    throw noFuncOverload("unnest");
  }

  // generateSeriesRows generates the rows of a generate_series(start, stop[, step]) FROM-clause
  // source (spec/design/functions.md §10), as one-column rows. The args evaluate ONCE against the
  // outer environment with no local row (non-LATERAL). PostgreSQL semantics: any NULL arg → zero
  // rows; a step of zero → 22023; start > stop with a positive step (or the reverse) → zero rows;
  // an i64 overflow while stepping STOPS the series cleanly (no trap). Each generated element
  // charges one generatedRow AT THE SOURCE, guarded so a maxCost ceiling aborts a runaway series
  // (54P01) mid-generation. Note (cross-core parity): TS values are bigint, which does NOT overflow
  // at 64 bits — so the i64 boundary must be detected EXPLICITLY here, or TS would emit rows Rust/Go
  // never reach.
  // resolveCatalogScope validates a catalog relation's database qualifier and returns the scope
  // string snapForScope resolves at exec (introspection.md §5): undefined (unqualified) ⇒ "main"
  // (the implicit scope); "main"/"temp" pass; any other qualifier must name a host attachment (else
  // 42P01, the checkTableQualifier wording). Unlike a user table there is no per-table existence
  // half — the relation exists in EVERY valid scope, so only the scope itself is validated.
  private resolveCatalogScope(qualifier: string | undefined): string {
    if (qualifier === undefined) return "main";
    const q = qualifier.toLowerCase();
    if (q === "main" || q === "temp") return q;
    if (this.attachReadSnap(q) === undefined) {
      throw engineError("undefined_table", `database "${qualifier}" is not attached`);
    }
    return q;
  }

  // jedTablesRows generates the rows of the jed_tables catalog relation (introspection.md §5): one
  // row per USER table of the scope's pinned catalog snapshot — the canonical (CREATE
  // TABLE-spelled) name — in ascending lowercased-name order (deterministic, no map-iteration
  // leak; the multiset is the contract, order without ORDER BY stays unspecified — CLAUDE.md §8).
  // Derived entirely from the resident catalog: zero page_read / storage_row_read; each produced
  // row charges one generated_row AT THE SOURCE, guarded so a maxCost ceiling aborts
  // deterministically (§13).
  private jedTablesRows(srf: SrfPlan, meter: Meter): Row[] {
    const snap = this.snapForScope(srf.introspectScope!);
    if (snap === undefined) {
      // The attachment was valid at plan time but is gone at exec (a detached-then-reused plan).
      throw engineError("undefined_table", `database "${srf.introspectScope}" is not attached`);
    }
    const out: Row[] = [];
    for (const t of snap.tablesSorted()) {
      meter.guard();
      meter.charge(COSTS.generatedRow);
      out.push([textValue(t.name)]);
    }
    return out;
  }

  // jedColumnsRows generates the rows of the jed_columns catalog relation (introspection.md §5):
  // one row per column of every user table of the scope's snapshot, in (lowercased table name,
  // ordinal) order. ordinal is 1-based CREATE TABLE order; type is the canonical type text
  // (catalogTypeText); not_null covers a declared NOT NULL and PRIMARY KEY membership; pk_ordinal
  // is the 1-based position in the PRIMARY KEY in KEY order (which may differ from declaration
  // order — constraints.md §3), NULL for a non-member. Cost mirrors jedTablesRows.
  private jedColumnsRows(srf: SrfPlan, meter: Meter): Row[] {
    const snap = this.snapForScope(srf.introspectScope!);
    if (snap === undefined) {
      throw engineError("undefined_table", `database "${srf.introspectScope}" is not attached`);
    }
    const out: Row[] = [];
    for (const t of snap.tablesSorted()) {
      for (let i = 0; i < t.columns.length; i++) {
        const c = t.columns[i]!;
        meter.guard();
        meter.charge(COSTS.generatedRow);
        const k = t.pk.indexOf(i);
        out.push([
          textValue(t.name),
          textValue(c.name),
          intValue(BigInt(i + 1)),
          textValue(catalogTypeText(c.type, c.decimal, c.varcharLen)),
          boolValue(c.notNull || c.primaryKey),
          k >= 0 ? intValue(BigInt(k + 1)) : nullValue(),
        ]);
      }
    }
    return out;
  }

  // jedIndexesRows generates the rows of the jed_indexes catalog relation (introspection.md §5.1):
  // one row per secondary index of every user table of the scope's snapshot, in (lowercased table
  // name, then the catalog's ascending index-name order) order. columns is the text[] of indexed
  // column names in index-key order (duplicates included); is_unique the catalog flag; method the
  // access-method name (btree/gin/gist). Cost mirrors jedTablesRows.
  private jedIndexesRows(srf: SrfPlan, meter: Meter): Row[] {
    const snap = this.snapForScope(srf.introspectScope!);
    if (snap === undefined) {
      throw engineError("undefined_table", `database "${srf.introspectScope}" is not attached`);
    }
    const out: Row[] = [];
    for (const t of snap.tablesSorted()) {
      for (const idx of t.indexes) {
        meter.guard();
        meter.charge(COSTS.generatedRow);
        out.push([
          textValue(idx.name),
          textValue(t.name),
          arrayValue(idx.keys.map((k) => textValue(indexKeyLabel(k, t)))),
          boolValue(idx.unique),
          textValue(idx.kind),
          // A partial index's predicate canonical text; NULL for a non-partial index (indexes.md §9).
          idx.predicate ? textValue(idx.predicate.exprText) : nullValue(),
        ]);
      }
    }
    return out;
  }

  // jedConstraintsRows generates the rows of the jed_constraints catalog relation (introspection.md
  // §5.1): one row per CHECK / UNIQUE / FK / EXCLUDE constraint of every user table of the scope's
  // snapshot, in (lowercased table name, then a fixed KIND order — check, unique, foreign_key,
  // exclude — each already held in ascending lowercased-name order). PRIMARY KEY / NOT NULL are
  // deliberately absent (they own no named object and are described by jed_columns). A UNIQUE
  // constraint IS its backing unique b-tree index (constraints.md §5), so type='unique' lists every
  // unique index; expression is the persisted canonical CHECK text (constraints.md §4.5). Cost
  // mirrors jedTablesRows.
  private jedConstraintsRows(srf: SrfPlan, meter: Meter): Row[] {
    const snap = this.snapForScope(srf.introspectScope!);
    if (snap === undefined) {
      throw engineError("undefined_table", `database "${srf.introspectScope}" is not attached`);
    }
    const textArr = (names: string[]): Value => arrayValue(names.map((n) => textValue(n)));
    const out: Row[] = [];
    for (const t of snap.tablesSorted()) {
      // CHECK: name / table / 'check' / NULL columns / expression text / NULL ref_*.
      for (const ck of t.checks) {
        meter.guard();
        meter.charge(COSTS.generatedRow);
        out.push([
          textValue(ck.name),
          textValue(t.name),
          textValue("check"),
          nullValue(),
          textValue(ck.exprText),
          nullValue(),
          nullValue(),
        ]);
      }
      // UNIQUE: every unique b-tree index (a UNIQUE constraint IS its unique index).
      for (const idx of t.indexes) {
        if (!idx.unique) continue;
        meter.guard();
        meter.charge(COSTS.generatedRow);
        out.push([
          textValue(idx.name),
          textValue(t.name),
          textValue("unique"),
          textArr(idx.keys.map((k) => indexKeyLabel(k, t))),
          nullValue(),
          nullValue(),
          nullValue(),
        ]);
      }
      // FOREIGN KEY: local columns / referenced (parent) table + columns (rendered from the
      // parent's canonical names — the parent always exists, it cannot be dropped while referenced,
      // constraints.md §6.10).
      for (const fk of t.fks) {
        meter.guard();
        meter.charge(COSTS.generatedRow);
        const parent = snap.table(fk.refTable);
        const refTable = parent !== undefined ? parent.name : fk.refTable;
        out.push([
          textValue(fk.name),
          textValue(t.name),
          textValue("foreign_key"),
          textArr(fk.columns.map((ord) => t.columns[ord]!.name)),
          nullValue(),
          textValue(refTable),
          textArr(fk.refColumns.map((ord) => parent?.columns[ord]?.name ?? "")),
        ]);
      }
      // EXCLUDE: the excluded columns in element order (the &&/= operators are a deferred column
      // addition — introspection.md §5.1).
      for (const exc of t.exclusions) {
        meter.guard();
        meter.charge(COSTS.generatedRow);
        out.push([
          textValue(exc.name),
          textValue(t.name),
          textValue("exclude"),
          textArr(exc.elements.map((el) => t.columns[el.column]!.name)),
          nullValue(),
          nullValue(),
          nullValue(),
        ]);
      }
    }
    return out;
  }

  private generateSeriesRows(srf: SrfPlan, env: EvalEnv, meter: Meter): Row[] {
    const evalInt = (e: RExpr): bigint | null => {
      const v = evalExpr(e, [], env, meter);
      if (v.kind === "int") return v.int;
      if (v.kind === "null") return null;
      throw new Error("the resolver restricts generate_series args to integers");
    };
    const start = evalInt(srf.args[0]!);
    const stop = evalInt(srf.args[1]!);
    const step = srf.args.length === 3 ? evalInt(srf.args[2]!) : 1n;
    // Any NULL argument yields zero rows (PG).
    if (start === null || stop === null || step === null) return [];
    if (step === 0n)
      throw engineError("invalid_parameter_value", "step size cannot be equal to zero");
    const out: Row[] = [];
    let cur = start;
    for (;;) {
      const inRange = step > 0n ? cur <= stop : cur >= stop;
      if (!inRange) break;
      meter.guard();
      meter.charge(COSTS.generatedRow);
      out.push([intValue(cur)]);
      // i64 overflow while stepping ends the series cleanly, matching PostgreSQL (and Rust/Go).
      const next = cur + step;
      if (next > 9223372036854775807n || next < -9223372036854775808n) break;
      cur = next;
    }
    return out;
  }

  // unnestRows generates the rows of an unnest(anyarray) FROM-clause source (spec/design/array-functions.md
  // §9), as one-column rows. The single array argument evaluates ONCE against the outer environment with no
  // local row (non-LATERAL). PostgreSQL semantics: a NULL array yields zero rows; the empty array {} yields
  // zero rows; otherwise one row per element in flattened row-major order (a multidimensional array flattens;
  // a NULL element is produced as a NULL row). Each produced element charges one generatedRow AT THE SOURCE,
  // guarded so a maxCost ceiling aborts a runaway unnest (54P01) mid-generation, exactly like generate_series.
  private unnestRows(srf: SrfPlan, env: EvalEnv, meter: Meter): Row[] {
    const v = evalExpr(srf.args[0]!, [], env, meter);
    // A NULL array → zero rows (PG; the empty_on_null discipline).
    if (v.kind === "null") return [];
    if (v.kind !== "array") throw new Error("the resolver restricts unnest's argument to an array");
    const out: Row[] = [];
    for (const e of v.elements) {
      meter.guard();
      meter.charge(COSTS.generatedRow);
      out.push([e]);
    }
    return out;
  }

  // jsonSrfRows generates the rows of a json/jsonb single-column SRF (B2, json-sql-functions.md §3). A
  // NULL argument yields zero rows (empty_on_null). array_elements[_text] over a non-array, or
  // object_keys over a non-object, is 22023. Each produced row charges one generatedRow.
  private jsonSrfRows(srf: SrfPlan, env: EvalEnv, meter: Meter): Row[] {
    const arg = evalExpr(srf.args[0]!, [], env, meter);
    // A NULL argument → zero rows (PG; the empty_on_null discipline).
    if (arg.kind === "null") return [];
    const node = jsonArgNode(arg);
    const out: Row[] = [];
    switch (srf.kind) {
      case "jsonb_array_elements":
      case "jsonb_array_elements_text": {
        if (node.kind !== "array")
          throw engineError("invalid_parameter_value", "cannot extract elements from a scalar");
        for (const e of node.elements) {
          meter.guard();
          meter.charge(COSTS.generatedRow);
          const v =
            srf.kind === "jsonb_array_elements_text"
              ? ((t) => (t === null ? nullValue() : textValue(t)))(nodeToText(e))
              : jsonbValue(e);
          out.push([v]);
        }
        break;
      }
      case "jsonb_object_keys":
      case "json_object_keys": {
        if (node.kind !== "object")
          throw engineError(
            "invalid_parameter_value",
            "cannot call jsonb_object_keys on a non-object",
          );
        for (const m of node.members) {
          meter.guard();
          meter.charge(COSTS.generatedRow);
          out.push([textValue(m.key)]);
        }
        break;
      }
      case "jsonb_each":
      case "jsonb_each_text": {
        if (node.kind !== "object")
          throw engineError(
            "invalid_parameter_value",
            "cannot call " + srf.kind + " on a non-object",
          );
        for (const m of node.members) {
          meter.guard();
          meter.charge(COSTS.generatedRow);
          // (key text, value): jsonb_each keeps the value node; _text renders ->>-style (a string
          // member's raw content, a JSON null → SQL NULL, else canonical).
          let value: Value;
          if (srf.kind === "jsonb_each_text") {
            const t = nodeToText(m.value);
            value = t === null ? nullValue() : textValue(t);
          } else {
            value = jsonbValue(m.value);
          }
          out.push([textValue(m.key), value]);
        }
        break;
      }
      // json[b]_to_record / _recordset (R1): map members → the col-def columns by name.
      case "json_record": {
        const cols = srf.recordCols ?? [];
        if (srf.recordSet === true) {
          if (node.kind !== "array")
            throw engineError(
              "invalid_parameter_value",
              "cannot call json_to_recordset on a non-array",
            );
          for (const e of node.elements) {
            meter.guard();
            meter.charge(COSTS.generatedRow);
            out.push(jsonRecordRow(e, cols, env, meter));
          }
        } else {
          meter.guard();
          meter.charge(COSTS.generatedRow);
          out.push(jsonRecordRow(node, cols, env, meter));
        }
        break;
      }
      // jsonb_path_query (P2): one jsonb row per path-evaluation-sequence item. The context node
      // (`node`) is already parsed above; evaluate the path (a NULL path → zero rows).
      case "jsonb_path_query": {
        const path = evalExpr(srf.args[1]!, [], env, meter);
        if (path.kind === "null") return out;
        if (path.kind !== "jsonpath") {
          throw new Error("resolver restricts the path argument to jsonpath");
        }
        const compiled = jsonPathCompile(path.text);
        for (const item of jsonPathEval(compiled, node)) {
          meter.guard();
          meter.charge(COSTS.generatedRow);
          out.push([jsonbValue(item)]);
        }
        break;
      }
      default:
        throw new Error("jsonSrfRows only handles the json SRF kinds");
    }
    return out;
  }

  // execSelectPlan executes a resolved SELECT against an outer-row environment (outer = the
  // enclosing rows, innermost last; empty at top level) and the bound parameters. The execute half
  // of the old runSelect: materialize, nested-loop join, WHERE, then aggregate / DISTINCT / window
  // + project. The per-row evaluator gets an EvalEnv carrying the outer rows + a runSubquery
  // callback, so a correlated subquery in any clause re-executes against them (grammar.md §26).
  // execStreamingScan executes the streaming primary-key-ordered scan path (spec/design/cost.md §3):
  // a single-table, no-blocking-operator query whose output order is already the table's primary-key
  // scan order — either no ORDER BY (the LIMIT short-circuit) or an ORDER BY satisfied by PK order
  // (plan.phys.pkOrdered, set by orderSatisfiedByPK) — streams scan→filter→project with NO sort, and (when
  // there is a LIMIT) stops the scan the instant the LIMIT/OFFSET window is filled, charging
  // storageRowRead only for the rows actually read. With no LIMIT it emits every survivor after
  // OFFSET (the sort is simply elided — same rows, same cost as the eager/sort path).
  // Cost-equivalent to the eager path EXCEPT that a LIMIT reads (and filters) fewer rows — the
  // deliberate cost change. pageRead is the full block (the bound's node count); only the row reads
  // short-circuit. Rows match the eager path exactly: the offset..offset+limit slice of the
  // primary-key-ordered filtered rows (which, for a pkOrdered query, IS the ORDER BY's result).
  // snapshotEngine builds a frozen read-snapshot Engine for a streaming cursor (spec/design/streaming.md
  // §5): the VISIBLE main / session-temp snapshots captured (the snapshots are immutable
  // copy-on-write, so sharing the references pins the roots and keeps them stable for the cursor's life,
  // isolated from later writes on the live handle) with NO open transaction — so the engine's reads see
  // exactly the captured frozen state — plus the session envelope the per-row eval / the cost meter read:
  // the cost ceilings + the SHARED lifetime gauge (the LifetimeBudget object — so streaming cost still
  // counts against lifetimeMaxCost), the SHARED seam (same object — uuid/clock draw from the injected
  // source), session vars, the time zone, and the currval/lastval session state. The cursor evaluates
  // its filter/projection against this engine, so the streaming cursor is self-contained — it does not
  // reference the live handle, so it survives Database.query's transient session (streaming.md §5).
  snapshotEngine(): Engine {
    const e = new Engine();
    e.committed = this.readSnap();
    e.pageSize = this.pageSize;
    e.paging = this.paging;
    e.readOnly = this.readOnly;
    const src = this.session;
    const dst = e.session;
    dst.maxCost = src.maxCost;
    dst.lifetime = src.lifetime; // shared LifetimeBudget — streaming cost counts (§5)
    dst.workMem = src.workMem;
    dst.seam = src.seam; // shared seam — uuid/clock draw from the injected source
    dst.vars = src.vars;
    dst.timeZone = src.timeZone;
    dst.sessionSeq = src.sessionSeq; // currval/lastval reads stay faithful
    dst.sessionLastName = src.sessionLastName;
    dst.tempCommitted = this.tempSnap();
    // The frozen read engine carries the same pinned attachment view so a streaming read of an attached
    // database (attached-databases.md §5) resolves through it; it never commits (read-only), so it needs
    // no core back-ref. tempCommitted above already froze the temp snapshot.
    e.attachedCommitted = this.attachReadView();
    return e;
  }

  // tryScanQuery serves stmt as a lazy STREAMING or BUFFERED query (spec/design/streaming.md §3/§4),
  // planning it EXACTLY ONCE and classifying streaming-vs-buffered from that single plan — the
  // plan-once replacement for the old tryStreamingQuery + tryBufferedQuery pair, each of which
  // re-planned the same statement. Returns {columnNames, cursor} for a top-level read SELECT; null for
  // a shape no scan lane covers (a non-SELECT, a write — incl. a nextval/setval SELECT, stmtIsWrite —
  // or a top-level set-op / VALUES / WITH), so the caller falls through to the deferred / materialized
  // paths. When holder is non-null (a prepared statement) a repeated execute over an unchanged catalog
  // reuses the cached plan and skips planning + the fold; ad-hoc callers pass null and still plan once.
  // (Returns a Cursor, not a Rows, to avoid the executor↔api import cycle.) The conformance corpus
  // drives the materialized execute() path, so this lane stays invisible to it (unit-tested to yield
  // identical rows + total cost under full drain, streaming.md §6).
  tryScanQuery(
    stmt: Statement,
    params: Value[],
    holder: ScanCacheHolder | null,
  ): { columnNames: string[]; columnTypes: string[]; cursor: Cursor } | null {
    if (stmt.kind !== "select" || stmtIsWrite(stmt)) return null;
    const snap = this.readSnap();
    const gen = snap.catGen;
    // The cache entry's identity key: the shared core when this engine belongs to one, else the bare
    // Engine itself (the low-level tooling path — object identity is GC-safe in JS, so a bare engine
    // caches without aliasing another).
    const ident = this.core ?? this;
    // Cache HIT: the plan was resolved against THIS database (same core — catGen is only monotonic
    // within one core) and the read snapshot's catalog is unchanged since (its catGen still matches),
    // and no relation name is shadowed by a session-local temp table the committed generation cannot
    // see (planTouchesTemp — the statement may have been filled on a different session). Reuse the
    // resolved plan + finalized param types — no planQuery, no fold, no param-type walk. A cached plan
    // carries no subquery to fold (planCacheable rejected any), so the shared plan is never mutated;
    // params are still bound per execute.
    if (
      holder !== null &&
      holder.cache !== null &&
      holder.cache.core === ident &&
      holder.cache.catGen === gen &&
      !this.planTouchesTemp(holder.cache.sp)
    ) {
      const c = holder.cache;
      return this.buildScanRows(c.sp, bindParams(params, c.ptys), 0n);
    }
    // MISS: plan once.
    const ptypes = new ParamTypes();
    const plan = this.planQuery(stmt, null, [], ptypes);
    if (plan.kind !== "select") return null; // set-op / VALUES / WITH — a scan lane does not cover it
    const sp = plan;
    const ptys = ptypes.finalize();
    const bound = bindParams(params, ptys);
    // Fold globally-uncorrelated subqueries to constants (at top level every surviving subquery is
    // uncorrelated) so the per-row eval re-enters nothing — keeping the cursor self-contained. The
    // fold's own cost was already charged to the shared lifetime gauge by its sub-executions; it is
    // added to the cursor's reported cost below. A cacheable plan has no subquery, so this is a no-op
    // (and is skipped on a hit) — cost stays identical.
    const subqueryCost = { value: 0n };
    this.foldUncorrelatedInSelect(sp, bound, EMPTY_CTE_CTX, subqueryCost);
    // Fill the cache only from committed state — so committed.catGen is strictly increasing over the
    // core's life and never aliases a rolled-back working generation, making the catGen equality on
    // a later HIT a sound "same catalog" identity check (a statement first executed inside an open
    // transaction re-plans until the tx commits) — and only for a reusable plan.
    if (
      holder !== null &&
      snap === this.committed &&
      !ptypes.uncacheable &&
      this.planCacheable(sp)
    ) {
      holder.cache = { core: ident, catGen: gen, sp, ptys };
    }
    return this.buildScanRows(sp, bound, subqueryCost.value);
  }

  // buildScanRows classifies a resolved plan (already folded + params bound) as streaming or buffered
  // and builds the matching lazy cursor. The streaming branch resolves the PK scan bound + the up-front
  // cost block (S3); the buffered branch runs its blocking part lazily on the first pull (S4). sp is
  // shared with a prepared statement's plan cache — a cache hit hands the SAME plan object here without
  // re-planning. Under full drain the rows + total cost are byte-identical to the eager path.
  buildScanRows(
    sp: SelectPlan,
    bound: Value[],
    subqueryCost: bigint,
  ): { columnNames: string[]; columnTypes: string[]; cursor: Cursor } {
    if (streamingScanEligible(sp)) {
      // Resolve the scan bound (the PK pushdown, if any) and the up-front cost block. An empty bound
      // (e.g. pk = NULL) admits no row.
      let keyB: KeyBound = unboundedBound();
      let empty = false;
      const sb = sp.phys.relBounds[0]!;
      if (sb !== null && sb.kind === "pk") {
        const b = buildKeyBound(sb.pk, bound, [], []);
        if (b === null) empty = true;
        else keyB = b;
      }
      const snap = this.snapshotEngine();
      const store = snap.lkpStoreScoped(sp.rels[0]!.db, sp.rels[0]!.tableName);
      const su = empty ? { pages: 0, slabs: 0 } : store.overlapScanUnits(keyB, sp.relMasks[0]!);
      const meter = snap.session.newMeter();
      meter.accrued = subqueryCost; // the folded constant cost (lifetime already charged)
      meter.charge(COSTS.pageRead * BigInt(su.pages) + COSTS.valueDecompress * BigInt(su.slabs));

      const env: EvalEnv = {
        params: bound,
        outer: [],
        runSubquery: (p, o) => snap.execQueryPlan(p, o, bound, EMPTY_CTE_CTX),
        seam: snap.session.seam,
        rng: new StmtRng(),
        ctes: EMPTY_CTE_CTX,
        exec: snap,
      };
      const gen = streamRows(sp, env, meter, store, keyB, empty);
      const source: RowSource = {
        nextRow: () => {
          const r = gen.next();
          return r.done ? undefined : r.value;
        },
        cost: () => meter.accrued,
        close: () => {
          gen.return(undefined);
        },
      };
      return {
        columnNames: sp.columnNames,
        columnTypes: typeNames(sp.columnTypes),
        cursor: Cursor.streaming(source),
      };
    }

    // Blocking (buffered) shape: buffers its input but yields the output one row at a time.
    const snap = this.snapshotEngine();
    const meter = snap.session.newMeter();
    meter.accrued = subqueryCost; // the folded constant cost (lifetime already charged)
    const env: EvalEnv = {
      params: bound,
      outer: [],
      runSubquery: (p, o) => snap.execQueryPlan(p, o, bound, EMPTY_CTE_CTX),
      seam: snap.session.seam,
      rng: new StmtRng(),
      ctes: EMPTY_CTE_CTX,
      exec: snap,
    };
    const gen = bufferedRows(snap, sp, env, meter, bound);
    const source: RowSource = {
      nextRow: () => {
        const r = gen.next();
        return r.done ? undefined : r.value;
      },
      cost: () => meter.accrued,
      close: () => {
        gen.return(undefined);
      },
    };
    return {
      columnNames: sp.columnNames,
      columnTypes: typeNames(sp.columnTypes),
      cursor: Cursor.streaming(source),
    };
  }

  // planCacheable reports whether a resolved scan plan may be memoized on a prepared statement. The
  // subquery / precompiled-regex exclusion is tracked separately (ParamTypes.uncacheable, set at the
  // node's birth). Here the relations are vetted: a set-returning / CTE / derived relation carries a
  // nested plan or generator we do not vet for reuse, and a temp table lives in a snapshot the cache
  // key (committed.catGen) does not track — so a plan referencing any of those is never cached (a point
  // lookup / plain join over persistent base tables has none).
  planCacheable(sp: SelectPlan): boolean {
    for (const r of sp.rels) {
      if (r.srf !== undefined || r.cte !== undefined || r.derived !== undefined) return false;
    }
    return !this.planTouchesTemp(sp);
  }

  // planTouchesTemp reports whether any of the plan's relations currently resolves to a SESSION-LOCAL
  // temporary table in THIS session's visible temp domain. Checked at cache fill (a temp plan is never
  // cached) and re-checked on every cache HIT: a statement is shared across sessions, and a plan
  // cached where a name was persistent must not be served on a session whose temp table shadows that
  // name — the temp domain is session-local, so the committed catGen the cache is keyed on cannot see
  // it. Cheap: one map lookup per relation, against a usually-empty temp catalog.
  planTouchesTemp(sp: SelectPlan): boolean {
    for (const r of sp.rels) {
      if (this.isTempTable(r.tableName)) return true;
    }
    return false;
  }

  // tryDeferredQuery tries to serve stmt as a lazy DEFERRED query (spec/design/streaming.md §4/§7) — the
  // query() path for a top-level set operation (UNION/INTERSECT/EXCEPT) or pure-query WITH. These are
  // blocking shapes whose output is already projected AND charged (no per-row top-level projection to
  // defer), so the only streaming win is lazy-yield (streaming.md §7): the cursor defers the whole
  // runSetOp / runWith to its FIRST pull — so a 54P01 cost abort, a 54P02 lifetime abort, or an
  // arithmetic trap surfaces DURING iteration, not at query() (§6) — then yields the buffered result one
  // row at a time over a frozen snapshot (§5). Returns null for any non-set-op/WITH statement, or a
  // write-classified one (a data-modifying WITH, a nextval/setval call — stmtIsWrite), which falls back
  // to the materialized dispatch path. Under full drain the rows + total cost are byte-identical to the
  // eager execute() path (it drives the SAME runSetOp / runWith, §6), so the corpus — which drives
  // execute() — stays green by construction; per-core unit tests pin query() == execute().
  tryDeferredQuery(
    stmt: Statement,
    params: Value[],
  ): { columnNames: string[]; columnTypes: string[]; cursor: Cursor } | null {
    // A write-classified statement (a data-modifying WITH, a sequence mutator) must take the write gate
    // and never streams (streaming.md §7 / sequences.md §4).
    if (stmtIsWrite(stmt)) return null;
    if (stmt.kind !== "setOp" && stmt.kind !== "with") return null;
    // Resolve the output column names + types up front (the Rows cursor exposes them before the first
    // pull). Planning is unmetered + deterministic, so the names read here are IDENTICAL to what the
    // deferred run produces (it reuses runSetOp/runWith verbatim, so there is no rows/cost drift). A
    // planning error (42P01/42804/…) surfaces at query(), matching the eager path.
    const { columnNames, columnTypes } = this.deferredColumnNames(stmt);
    const snap = this.snapshotEngine();
    // Run the whole set op / WITH on the FIRST pull (streaming.md §7), reusing the eager runSetOp /
    // runWith verbatim so the rows + cost match execute() exactly.
    const run =
      stmt.kind === "setOp" ? () => snap.runSetOp(stmt, params) : () => snap.runWith(stmt, params);
    let ran = false;
    let rows: Value[][] = [];
    let idx = 0;
    let cost = 0n; // 0 until the first pull runs the query, then SelectResult.cost (final)
    let done = false;
    const source: RowSource = {
      nextRow: () => {
        if (done) return undefined;
        if (!ran) {
          // A mid-run cost abort / arithmetic trap throws HERE (during iteration), not at query() (§6).
          const r = run();
          rows = r.rows;
          cost = r.cost;
          ran = true;
        }
        if (idx >= rows.length) {
          done = true;
          return undefined;
        }
        return rows[idx++]!;
      },
      cost: () => cost,
      close: () => {
        done = true;
        rows = [];
      },
    };
    return { columnNames, columnTypes, cursor: Cursor.streaming(source) };
  }

  // deferredColumnNames resolves the output column names of a top-level set operation / pure-query WITH
  // by planning only (no execution) — fills a deferred cursor's Rows metadata before its first pull
  // (tryDeferredQuery). Mirrors the planning prefix of runSetOp / runWith exactly so the names match the
  // deferred run's. Bound params are not needed: column names never depend on bound values.
  private deferredColumnNames(stmt: SetOp | WithQuery): {
    columnNames: string[];
    columnTypes: string[];
  } {
    const ptypes = new ParamTypes();
    if (stmt.kind === "setOp") {
      const plan = this.planQuery(stmt, null, [], ptypes);
      return { columnNames: plan.columnNames, columnTypes: typeNames(plan.columnTypes) };
    }
    // The planning prefix of runWith (cte.md): plan the CTE bindings, then the body with them visible.
    const bindings = this.planCteBindings(stmt.ctes, stmt.recursive, ptypes);
    const bodyQuery = cteBodyAsQuery(stmt.body); // pure-query WITH (DML excluded by stmtIsWrite)
    if (bodyQuery === null) throw new Error("a pure-query WITH is required here");
    const plan = this.planQuery(bodyQuery, null, bindings, ptypes);
    return { columnNames: plan.columnNames, columnTypes: typeNames(plan.columnTypes) };
  }

  private execStreamingScan(
    plan: SelectPlan,
    env: EvalEnv,
    meter: Meter,
    params: Value[],
  ): SelectResult {
    const store = this.lkpStoreScoped(plan.rels[0]!.db, plan.rels[0]!.tableName);

    // Resolve the scan bound (the PK pushdown, if any) and charge the pageRead block. This path is
    // single-table (gated below), so the only relation is relBounds[0]. A correlated bound resolves
    // against env.outer (the enclosing rows).
    // An INDEX bound never streams — the dispatch gate routes it to the eager path
    // (cost.md §3 "LIMIT short-circuit").
    let bound: KeyBound = unboundedBound();
    let empty = false;
    const sb = plan.phys.relBounds[0]!;
    if (sb !== null) {
      if (sb.kind !== "pk") throw new Error("the streaming path is gated to PK/full scans");
      const b = buildKeyBound(sb.pk, params, env.outer, []);
      if (b === null) empty = true;
      else bound = b;
    }
    const su = empty ? { pages: 0, slabs: 0 } : store.overlapScanUnits(bound, plan.relMasks[0]!);
    meter.charge(COSTS.pageRead * BigInt(su.pages) + COSTS.valueDecompress * BigInt(su.slabs));

    // limit is optional here: a pkOrdered query may have no LIMIT (it streams every survivor in
    // order, eliding the sort), while the LIMIT short-circuit always has one.
    const limit = plan.limit;
    const offset = plan.offset ?? 0n;
    const out: Value[][] = [];
    // DISTINCT (cost.md §3): when the scan already yields ORDER BY order, dedup runs streaming —
    // project EVERY scanned filtered row (the dedup key), drop a value already in `seen` keeping the
    // first (scan-order) occurrence, then the LIMIT/OFFSET window the DISTINCT rows. The sort is
    // elided; the projection is charged per scanned filtered row (the §3 asymmetry).
    const distinct = plan.distinct;
    const seen = new Set<string>();
    // Skip the scan entirely for LIMIT 0 (no window to fill).
    if (!empty && limit !== 0n) {
      let passed = 0n;
      const visit = (_key: Uint8Array, rawRow: Row): boolean => {
        meter.guard(); // enforce the cost ceiling per scanned row (CLAUDE.md §13)
        meter.charge(COSTS.storageRowRead);
        // Materialize the touched columns if the lazy load left them unfetched
        // (large-values.md §14) — a fresh copy only when needed (resolveColumns).
        const row = store.resolveColumns(rawRow, plan.relMasks[0]!);
        if (plan.filter !== null && !isTrue(evalExpr(plan.filter, row, env, meter))) {
          return true;
        }
        if (distinct) {
          // Project per scanned filtered row (the dedup key) and drop duplicates by first occurrence;
          // the OFFSET/LIMIT then window the DISTINCT rows.
          const tuple = plan.projections.map((p) => evalExpr(p, row, env, meter));
          const key = distinctRowKey(tuple);
          if (seen.has(key)) return true; // a duplicate of an already-emitted/seen value
          seen.add(key);
          passed += 1n;
          if (passed <= offset) return true;
          meter.charge(COSTS.rowProduced);
          out.push(tuple);
        } else {
          passed += 1n;
          if (passed <= offset) return true;
          meter.charge(COSTS.rowProduced);
          out.push(plan.projections.map((p) => evalExpr(p, row, env, meter)));
        }
        // Stop once a LIMIT window is filled; with no LIMIT, never stop early (emit every survivor
        // after OFFSET, in primary-key scan order).
        return limit === null ? true : BigInt(out.length) < limit;
      };
      // A pkReverse plan (ORDER BY the full PK all-DESC) walks the tree backward; everything else
      // (forward pkOrdered, or the no-ORDER-BY LIMIT short-circuit) walks forward.
      if (plan.phys.pkReverse) store.scanRangeRev(bound, visit);
      else store.scanRange(bound, visit);
    }
    return {
      columnNames: plan.columnNames,
      columnTypes: plan.columnTypes,
      rows: out,
      cost: meter.accrued,
    };
  }

  // windowTopNEligible reports whether a plain (non-grouped) window query can serve its LIMIT with a
  // TOP-N over the primary-key scan — reading only the first OFFSET+LIMIT rows instead of the whole
  // table (spec/design/window.md §5.2 "windowed top-N", cost.md §3). It is the window analog of the
  // streamingScanEligible LIMIT short-circuit, sound only when every window value at scan position k
  // depends solely on rows at positions <= k (a "backward" window over the scan order): then the first
  // OFFSET+LIMIT scan rows determine the first OFFSET+LIMIT output rows exactly.
  //
  // The gate (all must hold): a single base-table full/PK-bounded scan (no join/SRF/CTE/derived, no
  // index/GIN/GiST bound — those read the full admitted set), a plain window (hasWindow && !isAgg), not
  // DISTINCT, a LIMIT present, and an outer ORDER BY the PK scan already satisfies (pkOrdered, so the
  // scan order IS the output order and no post-window sort reorders rows). No compound (materialized)
  // window key (windowKeys) and no general-expression ORDER BY (orderExprs) — those append synthetic
  // columns; a bare PK-column window is the shape that streams. Finally EVERY window spec must be
  // prefix-safe (windowSpecPrefixSafe). Rows are byte-identical to the eager path; only the accrued
  // cost drops (fewer rows scanned/folded), the deliberate cost change (like the streaming LIMIT
  // short-circuit — cross-core identical because every core caps at the same OFFSET+LIMIT).
  private windowTopNEligible(plan: SelectPlan): boolean {
    if (
      !plan.hasWindow ||
      plan.isAgg ||
      plan.distinct ||
      plan.limit === null ||
      !plan.phys.pkOrdered
    ) {
      return false;
    }
    if (plan.rels.length !== 1 || plan.joins.length !== 0) return false;
    const rel = plan.rels[0]!;
    if (rel.srf !== undefined || rel.cte !== undefined || rel.derived !== undefined) return false;
    if (needsEagerScan(plan.phys.relBounds[0])) return false;
    if (plan.windowKeys.length !== 0 || plan.orderExprs.length !== 0) return false;
    const table = this.lkpTableScoped(rel.db, rel.tableName);
    if (table === undefined) return false;
    return plan.windowSpecs.every((spec) =>
      this.windowSpecPrefixSafe(spec, plan, table, rel.offset),
    );
  }

  // windowSpecPrefixSafe reports whether one window function's value at scan position k depends solely
  // on rows at positions <= k, so truncating the input to the first OFFSET+LIMIT rows is exact
  // (spec/design/window.md §5.2). It requires: no PARTITION BY (the whole scan is one partition, so scan
  // order = partition order); a window ORDER BY the PRIMARY KEY satisfies in the SAME direction as the
  // outer pkOrdered scan (so the window's "preceding" is the scan's preceding — the sort is a no-op);
  // and a backward plan/frame:
  //   - rowNumber / rank / denseRank / lag → backward (position, earlier-peer count, or a look-BACK
  //     offset); never depend on later rows or the total partition size.
  //   - an aggregate / firstValue / lastValue / nthValue window → backward iff its FRAME does not look
  //     forward (frameBackwardSafe).
  //   - percentRank / cumeDist / ntile depend on the total partition size N; lead looks FORWARD — all
  //     rejected.
  private windowSpecPrefixSafe(
    spec: WindowSpec,
    plan: SelectPlan,
    table: Table,
    offset: number,
  ): boolean {
    if (spec.partition.length !== 0 || spec.order.length === 0) return false;
    const dir = orderSatisfiedByPK(this.readSnap(), table, offset, spec.order);
    if (dir === null || dir.reverse !== plan.phys.pkReverse) return false;
    // The order covers the full (unique) PK ⇒ singleton peer groups (needed for a RANGE/GROUPS
    // CURRENT-ROW frame end, which otherwise spans forward peers).
    const unique = spec.order.length >= pkIndices(table).length;
    switch (spec.plan) {
      case "rowNumber":
      case "rank":
      case "denseRank":
      case "lag":
        return true;
      case "agg":
      case "firstValue":
      case "lastValue":
      case "nthValue":
        return frameBackwardSafe(spec.frame, unique);
      default:
        // percentRank / cumeDist / ntile need the total partition size N; lead looks forward.
        return false;
    }
  }

  // execWindowTopN serves a windowed top-N (spec/design/window.md §5.2, cost.md §3): a plain window
  // query whose LIMIT is answerable from the first OFFSET+LIMIT primary-key-scan rows (the gate is
  // windowTopNEligible). It streams the PK scan, applies WHERE, and collects survivors until it has
  // OFFSET+LIMIT of them — then runs the ordinary window stage over that PREFIX and emits the
  // OFFSET..OFFSET+LIMIT slice. Because every window value at scan position k depends only on rows at
  // positions <= k (windowSpecPrefixSafe), and the outer ORDER BY is the PK scan order (pkOrdered) so
  // no sort reorders rows, the rows are byte-identical to the eager whole-table path; only the accrued
  // cost is lower (fewer rows scanned, filtered, and folded) — the deliberate short-circuit, mirroring
  // execStreamingScan's LIMIT stop. pageRead is the full block up front (only per-row work
  // short-circuits, like the streaming scan).
  private execWindowTopN(plan: SelectPlan, env: EvalEnv, meter: Meter, params: Value[]): Emitter {
    const store = this.lkpStoreScoped(plan.rels[0]!.db, plan.rels[0]!.tableName);

    // The scan bound (the PK pushdown, if any) + its pageRead block, exactly as execStreamingScan.
    let bound: KeyBound = unboundedBound();
    let empty = false;
    const sb = plan.phys.relBounds[0]!;
    if (sb !== null) {
      if (sb.kind !== "pk") throw new Error("the windowed top-N path is gated to PK/full scans");
      const b = buildKeyBound(sb.pk, params, env.outer, []);
      if (b === null) empty = true;
      else bound = b;
    }
    const su = empty ? { pages: 0, slabs: 0 } : store.overlapScanUnits(bound, plan.relMasks[0]!);
    meter.charge(COSTS.pageRead * BigInt(su.pages) + COSTS.valueDecompress * BigInt(su.slabs));

    const limit = plan.limit!; // non-null (windowTopNEligible)
    const offset = plan.offset ?? 0n;
    const cap = offset + limit; // OFFSET+LIMIT survivors suffice (a backward window over the scan)

    // Collect the first `cap` surviving rows in PK scan order (respecting pkReverse), charging
    // storageRowRead per scanned row and the WHERE operator_evals — the streaming-scan feed, minus the
    // projection (the window stage runs before projection). Stop the instant `cap` survivors are in
    // hand: a genuine early-out, so the window fold sees only the prefix it needs.
    const rows: Row[] = [];
    if (!empty && limit !== 0n) {
      const visit = (_key: Uint8Array, rawRow: Row): boolean => {
        meter.guard(); // enforce the cost ceiling per scanned row (CLAUDE.md §13)
        meter.charge(COSTS.storageRowRead);
        const row = store.resolveColumns(rawRow, plan.relMasks[0]!);
        if (plan.filter !== null && !isTrue(evalExpr(plan.filter, row, env, meter))) return true;
        rows.push(row);
        return BigInt(rows.length) < cap; // stop once the OFFSET+LIMIT window is filled
      };
      if (plan.phys.pkReverse) store.scanRangeRev(bound, visit);
      else store.scanRange(bound, visit);
    }

    // The window stage over the collected prefix — identical to the eager path (§5.2), just fewer rows.
    applyWindowStage(rows, plan.windowSpecs, plan.windowKeys, env, meter);

    // The prefix is already in outer ORDER BY order (pkOrdered), so the sort is elided. Slice the
    // OFFSET..OFFSET+LIMIT window and project on emission — only an emitted row charges rowProduced +
    // projection cost (the eager non-DISTINCT window path's "project", streaming.md §4).
    const n = BigInt(rows.length);
    const start = offset < n ? offset : n;
    const end = limit < n - start ? start + limit : n;
    return { rows, start: Number(start), end: Number(end), mode: "project" };
  }

  // execIndexOrderScan is the streaming secondary-index-order scan (cost.md §3 "secondary-index
  // order"): an ORDER BY the PK scan does NOT satisfy but a B-tree index does, with a LIMIT (the gate
  // — plan.phys.indexOrder non-null). It walks the index store forward in key order, peels the fixed-width
  // PK suffix off the END of each entry key (the "key-suffix skip"), point-looks-up the row, applies
  // the residual filter, and STOPS once the LIMIT/OFFSET window is filled — a top-N that elides the
  // blocking sort (and, for a collated index, the collate units). The index-tree pageRead is charged
  // up front as the full block (like the streaming PK scan — only the per-row work short-circuits);
  // each scanned entry then charges its point-lookup's pageRead/valueDecompress + one storageRowRead,
  // plus rowProduced and projection operator_evals per produced row.
  private execIndexOrderScan(
    plan: SelectPlan,
    io: IndexOrder,
    env: EvalEnv,
    meter: Meter,
  ): SelectResult {
    const store = this.lkpStoreScoped(plan.rels[0]!.db, plan.rels[0]!.tableName);
    const istore = this.lkpIndexStore(io.nameKey);
    // Up-front index-tree pageRead (the full block; the index store has no payload, so no slabs).
    meter.charge(COSTS.pageRead * BigInt(istore.nodeCount()));

    const limit = plan.limit;
    const offset = plan.offset ?? 0n;
    const out: Value[][] = [];
    if (limit !== 0n) {
      let passed = 0n;
      // An index store has no payload columns, so its rows carry nothing to mask — whole-row scan.
      istore.scanRange(unboundedBound(), (ekey) => {
        meter.guard(); // enforce the cost ceiling per scanned entry (CLAUDE.md §13)
        // Peel the fixed-width PK suffix off the END of the index entry key (indexes.md §3): the
        // entry key is `<index columns> ‖ storage_key`, and storage_key is exactly io.pkWidth bytes.
        const rowKey = ekey.slice(ekey.length - io.pkWidth);
        const u = store.getWithUnits(rowKey, plan.relMasks[0]!);
        if (u.row === undefined) throw new Error("an index entry references a stored row");
        meter.charge(
          COSTS.pageRead * BigInt(u.pages) +
            COSTS.valueDecompress * BigInt(u.slabs) +
            COSTS.storageRowRead,
        );
        const row = store.resolveColumns(u.row, plan.relMasks[0]!);
        if (plan.filter !== null && !isTrue(evalExpr(plan.filter, row, env, meter))) {
          return true;
        }
        passed += 1n;
        if (passed <= offset) return true;
        meter.charge(COSTS.rowProduced);
        out.push(plan.projections.map((p) => evalExpr(p, row, env, meter)));
        // Stop once a LIMIT window is filled (a top-N over the index order).
        return limit === null ? true : BigInt(out.length) < limit;
      });
    }
    return {
      columnNames: plan.columnNames,
      columnTypes: plan.columnTypes,
      rows: out,
      cost: meter.accrued,
    };
  }

  // execStreamingSort is the streaming external sort for a single-table ORDER BY (spec/design/spill.md
  // §4/§5, streaming.md §4/§7). It streams scan→filter→sorter, so the input is never materialized in the
  // executor heap; the sorter spills sorted runs to disk under workMem (file-backed databases) and
  // k-way-merges them at finish. It runs the BLOCKING part (scan + sort + the OFFSET skip) and returns a
  // "sorted" Emitter holding the SortedRows pull iterator positioned at the first output row — so the
  // window's rowProduced + projection is charged LAZILY by the caller's emitter drive, one row per pull
  // (the §4/§7 output-laziness follow-on: the output array is never built and an early exit skips the
  // rows it never pulls). Results + cost under full drain are byte-identical to the eager sort: the same
  // pageRead block, storageRowRead per scanned row, filter operator_eval, and rowProduced per windowed
  // row accrue — only the sort, which is unmetered (cost.md §3), now spills. Gated (by the caller) to a
  // single table, no join, non-aggregate, non-DISTINCT, with an ORDER BY and no index bound.
  private execStreamingSort(
    plan: SelectPlan,
    env: EvalEnv,
    meter: Meter,
    params: Value[],
  ): Emitter {
    const store = this.lkpStoreScoped(plan.rels[0]!.db, plan.rels[0]!.tableName);

    // Resolve the scan bound (the PK pushdown, if any) and charge the pageRead + valueDecompress block
    // up front — identical to the eager scan (cost.md §3). An INDEX bound never reaches here.
    let bound: KeyBound = unboundedBound();
    let empty = false;
    const sb = plan.phys.relBounds[0]!;
    if (sb !== null) {
      if (sb.kind !== "pk") throw new Error("the streaming sort path is gated to PK/full scans");
      const b = buildKeyBound(sb.pk, params, env.outer, []);
      if (b === null) empty = true;
      else bound = b;
    }
    const su = empty ? { pages: 0, slabs: 0 } : store.overlapScanUnits(bound, plan.relMasks[0]!);
    meter.charge(COSTS.pageRead * BigInt(su.pages) + COSTS.valueDecompress * BigInt(su.slabs));

    // Build the sorted source in ORDER BY order, deferring the window's rowProduced + projection to the
    // lazy emitter drive (the caller). Two ways to sort, both yielding a SortedRows pull iterator over
    // the survivors:
    //
    // A collated ORDER BY cannot use the C-ordered Sorter / spill (collated keys are slice 1e), and
    // collation is in-memory only this slice — so materialize the survivors and sort them with the
    // collation-aware decorate sorter (spec/design/collation.md §8), then wrap the sorted array as an
    // in-memory SortedRows. The metered costs (storageRowRead per scanned row, rowProduced per windowed
    // output) are identical to the Sorter path; the sort itself is unmetered like every sort (cost.md §3).
    let total: bigint;
    let sorted: SortedRows;
    if (plan.order.some((k) => k.collation !== null)) {
      const rows: Row[] = [];
      if (!empty) {
        // Read-only SELECT feed: reconstruct only the touched columns (Track A1).
        store.scanRange(bound, (_key, rawRow) => {
          meter.guard();
          meter.charge(COSTS.storageRowRead);
          const row = store.resolveColumns(rawRow, plan.relMasks[0]!);
          if (plan.filter !== null && !isTrue(evalExpr(plan.filter, row, env, meter))) {
            return true;
          }
          rows.push(row);
          return true;
        });
      }
      sortRows(rows, plan.order);
      total = BigInt(rows.length);
      sorted = new SortedRows(rows, null);
    } else {
      // Stream the scan → filter → sorter. ORDER BY is blocking, so the scan never short-circuits: every
      // in-range row is read (charging storageRowRead), its touched columns resolved (large-values.md
      // §14), the WHERE applied (charging operator_eval), and a survivor pushed into the sorter, which
      // spills when it exceeds the budget.
      const sorter = this.newSorterFor(plan.order);
      if (!empty) {
        // Read-only SELECT feed: reconstruct only the touched columns (Track A1).
        store.scanRange(bound, (_key, rawRow) => {
          meter.guard(); // enforce the cost ceiling per scanned row (CLAUDE.md §13)
          meter.charge(COSTS.storageRowRead);
          const row = store.resolveColumns(rawRow, plan.relMasks[0]!);
          if (plan.filter !== null && !isTrue(evalExpr(plan.filter, row, env, meter))) {
            return true;
          }
          sorter.push(row);
          return true; // never stop early — the sort must see every row
        });
      }
      total = BigInt(sorter.total);
      sorted = sorter.finish();
    }

    // LIMIT / OFFSET window over the sort's total row count (known without materializing the output).
    // Clamp in the bigint domain (CLAUDE.md §8). The OFFSET skip is part of the blocking part (unwindowed
    // — no rowProduced), done now so `sorted` is positioned at the first output row; the emitter drive
    // then yields exactly `end-start` rows, charging rowProduced + projection per pull (streaming.md
    // §4/§7).
    const offset = plan.offset ?? 0n;
    const start = offset < total ? offset : total;
    let end = total;
    if (plan.limit !== null && plan.limit < total - start) end = start + plan.limit;
    try {
      for (let i = 0n; i < start; i++) sorted.next(); // skip the OFFSET rows (unwindowed)
    } catch (e) {
      sorted.close(); // release any spilled runs if the OFFSET skip throws
      throw e;
    }
    return sortedEmitter(sorted, Number(end - start));
  }

  // execStreamingJoin is a streaming two-table INNER/CROSS join whose ORDER BY is satisfied by the
  // OUTER (first) relation's PK scan order (cost.md §3 "JOIN"). A left-deep nested loop produces
  // combined rows in (outer PK, inner key) order — which IS the requested order — so the sort is
  // elided, and with a LIMIT the loop STOPS once the window is filled. Both tables are still
  // materialized in full (storageRowRead = the sum of cardinalities, the join contract); only the
  // ON/WHERE operator_evals and rowProduced short-circuit. Gated (by the caller / plan.phys.joinPkOrdered)
  // to exactly two non-lateral base relations, an INNER/CROSS join, a LIMIT, and a forward outer-PK
  // ORDER BY.
  private execStreamingJoin(
    plan: SelectPlan,
    env: EvalEnv,
    meter: Meter,
    params: Value[],
    outer: Row[],
  ): SelectResult {
    const leftRows = this.materializeRel(plan, 0, outer, [], env, params, meter);
    const rightRows = this.materializeRel(plan, 1, outer, [], env, params, meter);
    const on = plan.joins[0]!.on;

    const limit = plan.limit;
    const offset = plan.offset ?? 0n;
    const out: Value[][] = [];
    if (limit !== 0n) {
      let passed = 0n;
      // biome-ignore lint/suspicious/noLabelVar: `outer` is a loop label for the nested-join break/continue, not a variable.
      outer: for (const left of leftRows) {
        for (const right of rightRows) {
          const combined = [...left, ...right];
          // INNER: keep the pair iff its ON is TRUE (3VL); CROSS: keep every pair (no ON).
          if (on !== null && !isTrue(evalExpr(on, combined, env, meter))) continue;
          // The residual WHERE over the combined row (per surviving pair).
          if (plan.filter !== null && !isTrue(evalExpr(plan.filter, combined, env, meter)))
            continue;
          passed += 1n;
          if (passed <= offset) continue;
          meter.guard(); // enforce the cost ceiling per produced row (CLAUDE.md §13)
          meter.charge(COSTS.rowProduced);
          out.push(plan.projections.map((p) => evalExpr(p, combined, env, meter)));
          // Stop the whole nested loop once the LIMIT window is filled.
          if (limit !== null && BigInt(out.length) >= limit) break outer;
        }
      }
    }
    return {
      columnNames: plan.columnNames,
      columnTypes: plan.columnTypes,
      rows: out,
      cost: meter.accrued,
    };
  }

  // newSorterFor builds a Sorter for order, bounded by this handle's workMem. Spilling is enabled only
  // when a spillSink is present — a durable host that can spill to disk sets one (file.ts →
  // FileSpillSink, writing runs next to the database file); an in-memory or OPFS database leaves it
  // null and sorts fully resident (spill.md §2).
  private newSorterFor(order: OrderSlot[]): Sorter {
    const compare: RowCompare = (a, b) => {
      for (const k of order) {
        const c = keyCmp(a[k.idx]!, b[k.idx]!, k.descending, k.nullsFirst);
        if (c !== 0) return c;
      }
      return 0;
    };
    return new Sorter(compare, this.session.workMem, this.spillSink);
  }

  // materializeRel materializes one FROM relation ri into its rows, given the current outer-row stack
  // `outer` (spec/design/grammar.md §15/§44). A base table is scanned (a PK/index bound may seek via
  // outer); an SRF is generated; a CTE / derived table is delivered / run in place. For a CORRELATED
  // LATERAL relation (§44) the caller passes outer EXTENDED with the combined left-hand row, so the
  // body / SRF args read that row as their immediate outer; a non-lateral relation is passed the
  // query's own outer and its parent=null body simply ignores it (a parent=null plan holds no
  // outerColumn, so the two are observably identical).
  private materializeRel(
    plan: SelectPlan,
    ri: number,
    outer: Row[],
    left: Row,
    baseEnv: EvalEnv,
    params: Value[],
    meter: Meter,
  ): Row[] {
    const rel = plan.rels[ri]!;
    const env: EvalEnv = { ...baseEnv, outer };
    // A set-returning relation is generated, not scanned (functions.md §10): produce its rows,
    // charging generated_row per element (its args read outer — implicitly lateral, §44).
    if (rel.srf !== undefined) {
      switch (rel.srf.kind) {
        case "unnest":
          return this.unnestRows(rel.srf, env, meter);
        case "generate_series":
          return this.generateSeriesRows(rel.srf, env, meter);
        case "jsonb_array_elements":
        case "jsonb_array_elements_text":
        case "jsonb_object_keys":
        case "json_object_keys":
        case "jsonb_each":
        case "jsonb_each_text":
        case "json_record":
        case "jsonb_path_query":
          return this.jsonSrfRows(rel.srf, env, meter);
        case "json_table":
          return this.jsonTableRows(rel.srf, env, meter);
        case "jed_tables":
          return this.jedTablesRows(rel.srf, meter);
        case "jed_columns":
          return this.jedColumnsRows(rel.srf, meter);
        case "jed_indexes":
          return this.jedIndexesRows(rel.srf, meter);
        case "jed_constraints":
          return this.jedConstraintsRows(rel.srf, meter);
      }
    }
    // A CTE reference delivers its rows from the per-statement context (cte.md §3/§5): a MATERIALIZED
    // CTE reads its buffer (charging cte_scan_row, guarded so a runaway scan aborts 54P01); an INLINE
    // CTE runs its body in place. (A CTE is never lateral.)
    if (rel.cte !== undefined) {
      const ci = rel.cte;
      if (env.ctes.modes[ci] === "materialize") {
        const buf = env.ctes.buffers[ci]!;
        for (let i = 0; i < buf.length; i++) {
          meter.guard();
          meter.charge(COSTS.cteScanRow);
        }
        return buf.slice();
      }
      // Only a plain (query) CTE is ever inlined; a data-modifying CTE is always materialized
      // (writable-cte.md §3), so its buffer was filled above.
      const src = env.ctes.bindings[ci]!.source;
      if (src.kind !== "query") {
        throw new Error("a data-modifying CTE is always materialized, never inlined");
      }
      const r = this.execQueryPlan(src.plan, outer, params, env.ctes);
      meter.charge(r.cost);
      return r.rows;
    }
    // A DERIVED TABLE runs its body in place (grammar.md §42), charging its intrinsic cost — no
    // cte_scan_row. Non-lateral it was planned parent=null and ignores outer; a LATERAL body (§44)
    // reads the left-hand row from outer.
    if (rel.derived !== undefined) {
      const r = this.execQueryPlan(rel.derived, outer, params, env.ctes);
      meter.charge(r.cost);
      return r.rows;
    }
    // A base table: scan in primary-key order via a scanSource (the page_read block + per-row
    // storage_row_read accrue inside the generator — cost.md §3). A PK/index bound seeks/ranges
    // instead of a full walk; an empty bound reads nothing.
    const store = this.lkpStoreScoped(rel.db, rel.tableName);
    let rows: Row[];
    let nodeCount: number;
    let slabs = 0;
    // An index-nested-loop bound (per-outer-row seek) takes precedence over the once-materialized bound
    // and resolves its sibling source from the current left row (cost.md §3 "JOIN"); else the
    // once-materialized relBounds.
    const relBound = plan.phys.relINLBounds[ri] ?? plan.phys.relBounds[ri]!;
    if (relBound !== null && relBound.kind === "index") {
      const r = this.indexBoundRows(
        rel.tableName,
        relBound.index,
        params,
        outer,
        plan.relMasks[ri]!,
        left,
      );
      rows = r.rows;
      nodeCount = r.pages;
      slabs = r.slabs;
    } else if (relBound !== null && relBound.kind === "gin") {
      // Re-find the constant query Q in the WHERE filter (the same conjunct plan-time ginMatch
      // chose — gin.md §6); the @>/&& predicate also stays the residual filter downstream.
      const m = plan.filter !== null ? ginMatch(plan.filter, relBound.gin.colGlobal) : null;
      const r = this.ginBoundRows(
        rel.tableName,
        relBound.gin,
        m?.query ?? null,
        env,
        meter,
        plan.relMasks[ri]!,
      );
      // SELECT discards the storage keys (UPDATE/DELETE keep them — gin.md §6).
      rows = r.entries.map((e) => e.row);
      nodeCount = r.pages;
      slabs = r.slabs;
    } else if (relBound !== null && relBound.kind === "gist") {
      // Re-find the constant query Q (the conjunct plan-time analysis chose — gist.md §5/§6); the
      // &&/@>/= predicate also stays the residual filter downstream (always-recheck).
      const q = plan.filter !== null ? gistQueryOperand(plan.filter, relBound.gist) : null;
      const r = this.gistBoundRows(rel.tableName, relBound.gist, q, env, meter, plan.relMasks[ri]!);
      rows = r.entries.map((e) => e.row);
      nodeCount = r.pages;
      slabs = r.slabs;
    } else if (relBound !== null && relBound.kind === "pk") {
      const b = buildKeyBound(relBound.pk, params, outer, left);
      if (b === null) {
        rows = [];
        nodeCount = 0;
      } else {
        // Read-only SELECT feed: reconstruct only the touched columns (Track A1) — a Packed leaf skips
        // decoding the untouched ones. Cost- and result-identical for a consumer that reads only the
        // touched set (packed-leaf.md §11).
        const u = store.rangeScanWithUnits(b, plan.relMasks[ri]!);
        rows = u.entries.map((e) => e.row);
        nodeCount = u.pages;
        slabs = u.slabs;
      }
    } else if (relBound !== null && relBound.kind === "pkSet") {
      // Merged PK point-set (cost.md §3 "OR / IN-list"): a union of point probes over the distinct
      // sorted keys; the whole WHERE stays the residual filter downstream.
      const r = this.pkKeySetRows(store, relBound.pkSet, params, outer, plan.relMasks[ri]!, left);
      rows = r.entries.map((e) => e.row);
      nodeCount = r.pages;
      slabs = r.slabs;
    } else if (relBound !== null && relBound.kind === "indexSet") {
      // Merged secondary-index point-set (cost.md §3 "OR / IN-list").
      const r = this.indexKeySetRows(
        rel.tableName,
        relBound.indexSet,
        params,
        outer,
        plan.relMasks[ri]!,
        left,
      );
      rows = r.rows;
      nodeCount = r.pages;
      slabs = r.slabs;
    } else {
      // Read-only full-scan SELECT feed: reconstruct only the touched columns (Track A1).
      const u = store.scanWithUnits(plan.relMasks[ri]!);
      rows = u.entries.map((e) => e.row);
      nodeCount = u.pages;
      slabs = u.slabs;
    }
    // Materialize this relation's touched columns where the lazy load left unfetched references
    // (large-values.md §14) — exactly the static set the cost block charges.
    for (let i = 0; i < rows.length; i++) {
      rows[i] = store.resolveColumns(rows[i]!, plan.relMasks[ri]!);
    }
    meter.charge(COSTS.valueDecompress * BigInt(slabs));
    const tableRows: Row[] = [];
    for (const row of scanSource(rows, nodeCount, meter)) {
      tableRows.push(row);
    }
    return tableRows;
  }

  private execSelectPlan(
    plan: SelectPlan,
    outer: Row[],
    params: Value[],
    ctes: CteCtx,
  ): SelectResult {
    // Run the blocking part to an Emitter, then drive the emission EAGERLY into an array (the
    // materialized execute() path the conformance corpus drives — byte-unchanged). The lazy query()
    // path drives the SAME Emitter row by row via a bufferedRows generator (streaming.md §4); both
    // charge the identical units at the identical sites, so the totals agree (streaming.md §6).
    const env: EvalEnv = {
      params,
      outer,
      // A subquery inherits the same CTE context (a CTE reference works at any nesting depth —
      // cte.md §2/§5).
      runSubquery: (p, o) => this.execQueryPlan(p, o, params, ctes),
      seam: this.session.seam,
      rng: new StmtRng(),
      ctes,
      exec: this,
    };
    const meter = this.session.newMeter();
    const em = this.execSelectEmit(plan, env, meter, params);
    return {
      columnNames: plan.columnNames,
      columnTypes: plan.columnTypes,
      rows: this.drainEmitterEager(em, plan, env, meter),
      cost: meter.accrued,
    };
  }

  // drainEmitterEager builds the full output array from the Emitter — the materialized execute() drive
  // (spec/design/streaming.md §4). The lazy query() drive (bufferedRows) emits the same rows one at a
  // time instead; both charge the identical units in the identical order, so totals agree (§6).
  private drainEmitterEager(em: Emitter, plan: SelectPlan, env: EvalEnv, meter: Meter): Value[][] {
    if (em.mode === "final") return em.rows;
    if (em.mode === "sorted") {
      // The streaming sort's lazy output: pull every windowed row from the SortedRows iterator, charging
      // rowProduced + the projection per row — exactly the eager window loop execStreamingSort ran before
      // its output went lazy (streaming.md §4/§7).
      const sorted = em.sorted!;
      try {
        const out: Value[][] = [];
        for (let i = 0; i < em.end; i++) {
          const row = sorted.next();
          if (row === null) break;
          meter.guard(); // enforce the cost ceiling per produced row (CLAUDE.md §13)
          meter.charge(COSTS.rowProduced);
          out.push(plan.projections.map((p) => evalExpr(p, row, env, meter)));
        }
        return out;
      } finally {
        sorted.close(); // a LIMIT/error may stop the merge early — release any undrained runs
      }
    }
    if (em.mode === "columnar") {
      // Columnar projection (packed-leaf.md §11 Track A2/A3): gather each windowed output row from the
      // dense lanes — a bare-column projection with no full-width row — charging rowProduced per row,
      // exactly the "project" drive over a bare-column projection (whose eval is a zero-cost slot read). A
      // set `sel` (the A3 filter's survivors) maps output row j to lane position sel[j].
      const cols = em.cols!;
      const projCols = em.projCols!;
      const sel = em.sel;
      const out: Value[][] = [];
      for (let j = em.start; j < em.end; j++) {
        meter.guard(); // enforce the cost ceiling per produced row (CLAUDE.md §13)
        meter.charge(COSTS.rowProduced);
        const l = sel === undefined ? j : sel[j]!;
        out.push(projCols.map((c) => cols[c]![l]!));
      }
      return out;
    }
    const out: Value[][] = [];
    for (let i = em.start; i < em.end; i++) {
      meter.guard(); // enforce the cost ceiling per produced row (CLAUDE.md §13)
      meter.charge(COSTS.rowProduced);
      if (em.mode === "identity") out.push(em.rows[i]!);
      else out.push(plan.projections.map((p) => evalExpr(p, em.rows[i]!, env, meter)));
    }
    return out;
  }

  // projectColumnar runs the A2/A3 columnar gather for a vectorizedProjectEligible plan (packed-leaf.md
  // §11 Track A2/A3): it scans only the touched columns of the single base relation into dense per-column
  // lanes (never a full-width Row), charges the identical scan cost block, applies any WHERE predicate over
  // the lanes into a selection vector (A3), and returns a "columnar" Emitter that gathers each surviving
  // output row from the lanes on emission. Returns null (declining to the caller's row path) for an
  // in-memory store (its Decoded leaves share rows zero-copy, so a lane gather would only add allocation),
  // a spillable touched column (the columnar feed has no value-resolution step — this also covers a filter
  // over a spillable column), or a projection column out of range / unmasked (a safety net, never expected
  // — a projected column is touched, hence masked). Cost-neutral by construction: the same page_read (same
  // node visits) / value_decompress (0) / storage_row_read (× rowCount) / operator_eval (the filter over
  // each scanned row) as the row path, then rowProduced per emitted (surviving) row charged by the emitter
  // drive — exactly the "project" drive over a bare-column projection.
  private projectColumnar(
    plan: SelectPlan,
    env: EvalEnv,
    meter: Meter,
    params: Value[],
  ): Emitter | null {
    const rel = plan.rels[0]!;
    const store = this.lkpStoreScoped(rel.db, rel.tableName);
    // File-backed only: an in-memory store's row path is already zero-copy.
    if (!store.isFileBacked()) return null;
    const mask = plan.relMasks[0]!;
    // No touched column may spill — so the feed's value_decompress slab count is 0 and no unfetched value
    // is left unresolved. The mask includes the filter's columns (collectTouched), so this also declines a
    // filter over a spillable column to the row path.
    if (store.anySpillableTouched(mask)) return null;
    // Each projected column must be a valid, masked table ordinal — else its gathered lane would be empty.
    const projCols: number[] = [];
    for (const p of plan.projections) {
      if (p.kind !== "column") return null;
      const idx = p.index;
      if (idx < 0 || idx >= mask.length || !mask[idx]) return null;
      projCols.push(idx);
    }

    // Determine the scan bound exactly as materializeRel does: a PK-range bound, or the full scan. An
    // empty bound (a contradictory PK predicate) admits no rows — skip the scan entirely (0 pages/rows).
    let cols: Value[][] = mask.map(() => []);
    let rowCount = 0;
    let pages = 0;
    const slabs = 0;
    let doScan = true;
    let b = unboundedBound();
    const relBound = plan.phys.relBounds[0];
    if (relBound !== null && relBound !== undefined && relBound.kind === "pk") {
      const bb = buildKeyBound(relBound.pk, params, env.outer, []);
      if (bb === null) doScan = false;
      else b = bb;
    }
    if (doScan) {
      const r = store.columnarScanMasked(b, mask);
      cols = r.cols;
      rowCount = r.rowCount;
      pages = r.pages;
    }
    // Charge the scan cost block identically to materializeRel + scanSource: page_read × nodes,
    // value_decompress × slabs (0 here), storage_row_read × rowCount. On the unmetered lane (the caller
    // gates) this bulk charge reproduces the per-row accrual (guard is a no-op).
    meter.charge(
      COSTS.pageRead * BigInt(pages) +
        COSTS.valueDecompress * BigInt(slabs) +
        COSTS.storageRowRead * BigInt(rowCount),
    );

    // A3: apply the WHERE predicate over the lanes into a selection vector (undefined ⇒ all rows survive).
    let sel: number[] | undefined;
    let nEmit = rowCount;
    if (plan.filter !== null) {
      sel = filterColumnar(plan.filter, cols, mask, rowCount, env, meter);
      nEmit = sel.length;
    }

    return { rows: [], start: 0, end: nEmit, mode: "columnar", cols, projCols, sel };
  }

  // vectorizedAggEligible reports whether plan is a shape execVectorizedAgg specializes: a single-base-
  // table SUM/COUNT/MIN/MAX/AVG with no DISTINCT / FILTER / HAVING / window / ORDER BY, over a full or
  // primary-key-bounded scan, that is EITHER whole-table (no GROUP BY) OR grouped by a single bare
  // integer column. Mostly pure plan inspection — it charges nothing, so a bail is free and the general
  // path runs with identical results + cost; the single-key case additionally reads the group-key
  // column's static type from the table store (a one-time lookup, not per row) to confirm it is a scalar
  // integer (so the int64-keyed bucket is a bijection of the value-canonical group key — groupByIntKey).
  private vectorizedAggEligible(plan: SelectPlan): boolean {
    if (!plan.isAgg) return false;
    // One base table, no join.
    if (plan.rels.length !== 1 || plan.joins.length !== 0) return false;
    const rel = plan.rels[0]!;
    if (
      rel.srf !== undefined ||
      rel.cte !== undefined ||
      rel.derived !== undefined ||
      rel.lateral === true
    ) {
      return false;
    }
    // Full scan or a primary-key bound only — an index / GIN / GiST / point-set bound changes the scan
    // mechanics and residual filter (needsEagerScan), so it keeps the scalar path.
    if (needsEagerScan(plan.phys.relBounds[0])) return false;
    // Exactly one grouping set (ROLLUP/CUBE/GROUPING SETS produce several — deferred), no materialized
    // expression keys (`GROUP BY a + b`), and no GROUPING() calls.
    if (
      plan.groupSets.length !== 1 ||
      plan.groupExprs.length !== 0 ||
      plan.groupingSpecs.length !== 0
    ) {
      return false;
    }
    const gset = plan.groupSets[0]!;
    if (gset.keyCols.length === 0) {
      // Whole-table aggregation: the () grand-total group, no master grouping columns.
      if (plan.groupKeys.length !== 0) return false;
    } else if (gset.keyCols.length === 1) {
      // Single-key GROUP BY: the sole master grouping column is this key, its synthetic slot is 0, and
      // the key is a bare scalar-INTEGER column of the base table.
      if (plan.groupKeys.length !== 1 || plan.groupKeys[0] !== gset.keyCols[0]) return false;
      if (gset.slotSrc.length !== 1 || gset.slotSrc[0] !== 0) return false;
      const store = this.lkpStoreScoped(rel.db, rel.tableName);
      if (!store.columnIsInteger(gset.keyCols[0]! - rel.offset)) return false;
    } else {
      return false;
    }
    // No blocking / re-shaping operator beyond the fold. LIMIT/OFFSET is honored via the window bounds
    // below, so it need not bail.
    if (plan.distinct || plan.having !== null || plan.hasWindow || plan.order.length !== 0)
      return false;
    if (plan.aggSpecs.length === 0) return false;
    return plan.aggSpecs.every((s) => vectorizedSpecEligible(s));
  }

  // execVectorizedAgg runs a vectorizedAggEligible plan and returns the already-grouped output as a
  // "project"-mode buffer Emitter under the query's LIMIT/OFFSET window — exactly the emitter the scalar
  // aggregate branch returns, so emission + cost are identical either way. It reuses the scalar scan
  // (materializeRel) + WHERE for exact cost + survivor determination, then folds each aggregate over the
  // survivors with the shared Acc (byte-identical acc state, hence finalize). A file-backed store gathers
  // only its touched columns columnar (aggColumnar — never a full-width row, the allocation dividend); an
  // in-memory store (or a columnar decline) folds over the materialized rows. Only runs on the unmetered
  // lane (the caller gates).
  private execVectorizedAgg(
    plan: SelectPlan,
    env: EvalEnv,
    meter: Meter,
    params: Value[],
  ): Emitter {
    const gset = plan.groupSets[0]!;

    // A2/A3 columnar fast path (packed-leaf.md §11 Track A2/A3): a file-backed aggregate gathers only its
    // touched columns into dense lanes and folds columnar — never a full-width row. A WHERE (A3) is
    // applied over the lanes into a selection vector rather than forcing the row path. Declines (null) to
    // the row path below for an in-memory store or a spillable touched column. Cost-neutral by
    // construction (aggColumnar charges the identical scan block).
    let srows = this.aggColumnar(plan, gset, env, params, meter);
    if (srows === null) {
      // Row path: scan the single base relation through the same path the eager executor uses (so the
      // pageRead / valueDecompress / storageRowRead block is charged identically — materializeRel), then
      // apply the residual WHERE per scanned row through the ordinary evaluator (its operatorEval charges
      // + 3VL survivor test byte-identical to the scalar WHERE loop).
      const rows = this.materializeRel(plan, 0, env.outer, [], env, params, meter);
      let survivors: Row[];
      if (plan.filter === null) {
        survivors = rows;
      } else {
        survivors = [];
        for (const r of rows) if (isTrue(evalExpr(plan.filter, r, env, meter))) survivors.push(r);
      }
      const at: LaneAt = (j, col) => survivors[j]![col]!;
      srows =
        gset.keyCols.length === 0
          ? [foldAggWhole(plan.aggSpecs, at, survivors.length, meter)]
          : groupByIntKey(plan.aggSpecs, gset.keyCols[0]!, at, survivors.length, meter);
    }

    // LIMIT/OFFSET window over the synthetic rows, mirroring the scalar branch's windowBounds (clamped in
    // the bigint domain before indexing). Emit as "project" — the drive charges rowProduced + the
    // projection over each windowed synthetic row exactly as for a scalar aggregate result.
    const n = BigInt(srows.length);
    const start = plan.offset === null ? 0n : plan.offset < n ? plan.offset : n;
    const end = plan.limit !== null && plan.limit < n - start ? start + plan.limit : n;
    return { rows: srows, start: Number(start), end: Number(end), mode: "project" };
  }

  // aggColumnar runs the A2/A3 columnar gather for a vectorized aggregate (packed-leaf.md §11 Track
  // A2/A3): it scans only the touched columns of the single base relation into dense per-column lanes
  // (never a full-width Row), charges the identical scan cost block, applies any WHERE predicate over the
  // lanes into a selection vector (A3), and folds each aggregate columnar over the survivors — returning
  // the finalized synthetic rows (the whole-table grand total or one per group). Returns null (declining
  // to the caller's row path) when the store is in-memory (its Decoded leaves share rows zero-copy), when
  // a touched column can spill (the columnar feed has no value-resolution step — this also covers a
  // filter over a spillable column), or when a needed column ordinal is out of range / unmasked (a safety
  // net, never expected for an eligible plan). Cost-neutral by construction: same pageRead /
  // valueDecompress (0) / storageRowRead / operatorEval (the filter) / aggregateAccumulate / rowProduced
  // as the row path.
  private aggColumnar(
    plan: SelectPlan,
    gset: GroupSet,
    env: EvalEnv,
    params: Value[],
    meter: Meter,
  ): Value[][] | null {
    const rel = plan.rels[0]!;
    const store = this.lkpStoreScoped(rel.db, rel.tableName);
    // File-backed only: an in-memory store's row path is already zero-copy.
    if (!store.isFileBacked()) return null;
    const mask = plan.relMasks[0]!;
    // No touched column may spill — so the feed's valueDecompress slab count is 0 and no unfetched value
    // is left unresolved. This declines a filter or operand over a spillable column to the row path.
    if (store.anySpillableTouched(mask)) return null;
    // Every column the fold reads (each aggregate operand + the group key) must be a valid, masked table
    // ordinal — else its gathered lane would be empty. Also declines a (never-expected) non-zero offset.
    const need = (idx: number): boolean => idx >= 0 && idx < mask.length && mask[idx] === true;
    for (const spec of plan.aggSpecs) {
      if (spec.operand !== null && spec.operand.kind === "column" && !need(spec.operand.index)) {
        return null;
      }
    }
    if (gset.keyCols.length === 1 && !need(gset.keyCols[0]!)) return null;

    // Determine the scan bound exactly as materializeRel does: a PK-range bound, or the full scan. An
    // empty bound (a contradictory PK predicate) admits no rows — skip the scan entirely.
    let doScan = true;
    let b = unboundedBound();
    const relBound = plan.phys.relBounds[0];
    if (relBound !== null && relBound !== undefined && relBound.kind === "pk") {
      const bb = buildKeyBound(relBound.pk, params, env.outer, []);
      if (bb === null) doScan = false;
      else b = bb;
    }

    const grouped = gset.keyCols.length === 1;
    const keyCol = grouped ? gset.keyCols[0]! : 0;

    // Fold each scanned row's touched columns straight into its accumulator during ONE tree walk — no
    // per-column lane is materialized, so a whole-table / single-int-key aggregate is O(1) memory instead
    // of the O(rows) whole-column gather the lane path paid (float.md §7, packed-leaf.md §11). A WHERE
    // predicate (A3) is evaluated over a single reusable masked scratch row read via colAt (untouched
    // columns NULL) — byte-identical input + operator_eval to the lane filter.
    const whole: Acc[] = grouped ? [] : plan.aggSpecs.map((s) => newAccFromSpec(s));
    const groups: { key: Value; accs: Acc[] }[] = [];
    const index = new Map<bigint, number>();
    let nullGi = -1;
    const scratch: Row = plan.filter !== null ? new Array(mask.length).fill(nullValue()) : [];
    let nsurv = 0;
    let rowCount = 0;
    let pages = 0;

    if (doScan) {
      const visit = (n: PNode, i: number): void => {
        if (plan.filter !== null) {
          for (let c = 0; c < mask.length; c++) {
            if (mask[c]) scratch[c] = colAt(n, i, c);
          }
          if (!isTrue(evalExpr(plan.filter, scratch, env, meter))) return;
        }
        nsurv++;
        let accs: Acc[];
        if (grouped) {
          const kv = colAt(n, i, keyCol);
          let gi: number;
          if (kv.kind === "int") {
            const g = index.get(kv.int);
            if (g === undefined) {
              gi = groups.length;
              index.set(kv.int, gi);
              groups.push({ key: kv, accs: plan.aggSpecs.map((s) => newAccFromSpec(s)) });
            } else {
              gi = g;
            }
          } else {
            // A NULL integer key buckets into one sentinel group (matching the scalar/lane path).
            if (nullGi < 0) {
              nullGi = groups.length;
              groups.push({ key: nullValue(), accs: plan.aggSpecs.map((s) => newAccFromSpec(s)) });
            }
            gi = nullGi;
          }
          accs = groups[gi]!.accs;
        } else {
          accs = whole;
        }
        for (let s = 0; s < plan.aggSpecs.length; s++) {
          const spec = plan.aggSpecs[s]!;
          const oc = operandCol(spec);
          foldAcc(accs[s]!, oc === null ? nullValue() : colAt(n, i, oc), meter);
        }
      };
      const r = store.foldScanMasked(b, visit);
      rowCount = r.rowCount;
      pages = r.nodes;
    }

    // Charge the identical cost totals (unmetered lane — charge order is invisible): the scan block
    // (pageRead × nodes; valueDecompress × 0 — no spillable touched column gated above; storageRowRead ×
    // rowCount) and aggregateAccumulate once per (survivor × spec). The filter's operator_eval was
    // charged per scanned row inside the walk.
    meter.charge(COSTS.pageRead * BigInt(pages) + COSTS.storageRowRead * BigInt(rowCount));
    meter.charge(COSTS.aggregateAccumulate * BigInt(nsurv) * BigInt(plan.aggSpecs.length));

    return grouped
      ? groups.map(({ key, accs }) => [key, ...accs.map((a) => finalizeAcc(a))])
      : [whole.map((a) => finalizeAcc(a))];
  }

  // execSelectEmit runs a SelectPlan's blocking part and returns an Emitter describing how to emit its
  // output rows (spec/design/streaming.md §4, S4): the scan / join / WHERE / window / ORDER BY / GROUP
  // BY / DISTINCT all run here (charging their cost into meter), producing either a windowed buffer
  // (projected lazily on emission) or, for the special input-streaming paths, a fully-formed result.
  // The caller drives the emission — eagerly (execSelectPlan, the materialized execute() path) or lazily
  // (a bufferedRows generator, the query() path). The env's StmtRng threads the per-statement entropy
  // through both the blocking part and the (possibly deferred) projection (streaming.md §6).
  execSelectEmit(plan: SelectPlan, env: EvalEnv, meter: Meter, params: Value[]): Emitter {
    // Vectorized single-table aggregate (the PAX/vectorization program's executor track): a
    // SUM/COUNT/MIN/MAX/AVG with no DISTINCT / FILTER / HAVING / window / ORDER BY, either whole-table or
    // grouped by a single integer column, folds columnar / int64-bucketed instead of the row-at-a-time
    // group machinery below. Gated to the unmetered lane so a metered query's deterministic abort row
    // stays the scalar path's; results and accrued cost are byte-identical either way (the conformance
    // corpus proves both). Ineligible / metered ⇒ skipped and the general aggregate branch runs
    // unchanged. (An aggregate plan skips every streaming fast-path below — they all require !isAgg — so
    // this front-position placement is only for clarity, mirroring the Go/Rust cores' ordering.)
    if (meter.isUnmetered() && this.vectorizedAggEligible(plan)) {
      return this.execVectorizedAgg(plan, env, meter, params);
    }

    // Streaming primary-key-ordered scan (spec/design/cost.md §3): a single-table query with no
    // blocking operator beyond an ORDER BY the scan already satisfies — either no ORDER BY with a
    // LIMIT (the LIMIT short-circuit), or an ORDER BY satisfied by the table's primary-key scan order
    // (plan.phys.pkOrdered) — streams scan→filter→project with NO sort, and with a LIMIT STOPS the scan
    // once the window is filled, so storageRowRead counts only the rows actually read. A pkOrdered
    // DISTINCT streams too: the dedup runs in scan order (the sort elided), so it short-circuits a
    // top-N like the non-DISTINCT case. A non-PK-ordered ORDER BY, a no-ORDER-BY DISTINCT, aggregate,
    // or join must see every row, so it keeps the eager path below. pageRead stays the full block.
    if (streamingScanEligible(plan)) {
      return finalEmitter(this.execStreamingScan(plan, env, meter, params).rows);
    }

    // Streaming secondary-index-order scan (cost.md §3 "secondary-index order"): the planner set
    // indexOrder only for a single-table, non-aggregate/window/DISTINCT, no-bound, LIMITed query
    // whose ORDER BY a B-tree index satisfies (and the PK scan does not). Walk the index +
    // point-lookup; the eager sort is elided.
    if (plan.phys.indexOrder !== null) {
      return finalEmitter(this.execIndexOrderScan(plan, plan.phys.indexOrder, env, meter).rows);
    }

    // Streaming external sort (spec/design/spill.md §5): a single-table, no-join, non-aggregate,
    // non-DISTINCT query with an ORDER BY the scan does NOT already satisfy (!plan.phys.pkOrdered — caught
    // above) streams scan→filter→sorter, so the input is never materialized in the executor heap and
    // the sort spills sorted runs to disk under workMem (file-backed databases). DISTINCT/aggregate/
    // join take the eager path below, and an index bound does not stream (like the LIMIT
    // short-circuit). Results + cost are identical to the eager sort (the sort is unmetered —
    // cost.md §3; spill.md §6).
    if (
      plan.order.length > 0 &&
      !plan.phys.pkOrdered &&
      plan.orderExprs.length === 0 && // a materialized expression key takes the eager path below
      plan.rels.length === 1 &&
      plan.joins.length === 0 &&
      !plan.isAgg &&
      !plan.hasWindow &&
      !plan.distinct &&
      !needsEagerScan(plan.phys.relBounds[0]) &&
      // A set-returning relation takes the eager path (functions.md §10).
      plan.rels[0]!.srf === undefined &&
      // A CTE reference takes the eager path (cte.md §5).
      plan.rels[0]!.cte === undefined &&
      // A derived table takes the eager path (grammar.md §42).
      plan.rels[0]!.derived === undefined
    ) {
      // The streaming sort yields its output LAZILY (streaming.md §4/§7) — execStreamingSort runs the
      // scan + sort + OFFSET skip and returns a "sorted" Emitter over the SortedRows pull iterator; the
      // window's rowProduced + projection is charged by the emitter drive.
      return this.execStreamingSort(plan, env, meter, params);
    }

    // Streaming two-table join (cost.md §3 "JOIN"): the planner set joinPkOrdered only for a two-table
    // INNER/CROSS join whose ORDER BY the OUTER relation's PK scan order satisfies, with a LIMIT. The
    // nested loop drives the outer in PK order so the output is already ordered — the sort is elided
    // and the loop short-circuits a top-N.
    if (plan.phys.joinPkOrdered) {
      return finalEmitter(this.execStreamingJoin(plan, env, meter, params, env.outer).rows);
    }

    // Windowed top-N (spec/design/window.md §5.2, cost.md §3): a plain window query whose LIMIT is
    // answerable from the first OFFSET+LIMIT PK-scan rows (a backward window over the PK-ordered scan)
    // scans only that prefix instead of the whole table — the window analog of the streaming LIMIT
    // short-circuit. Ineligible window queries fall through to the eager materialize below.
    if (this.windowTopNEligible(plan)) {
      return this.execWindowTopN(plan, env, meter, params);
    }

    // Columnar projection fast path (packed-leaf.md §11 Track A2/A3): a bare-column projection over a
    // single-table full/PK-bounded scan with no ORDER BY / LIMIT / OFFSET / blocking operator gathers only
    // its touched columns into dense lanes and emits from them — never the full-width row the materialize
    // path below allocates per record (the allocation dividend on a wide table). A WHERE predicate (A3) is
    // applied over the lanes into a selection vector rather than forcing the row path. Gated to the
    // unmetered lane (so a metered query's per-eval guards stay the row path's) and to file-backed stores
    // with no spillable touched column (projectColumnar declines otherwise, falling through to the
    // identical-cost row path). Cost-neutral by construction.
    if (meter.isUnmetered() && vectorizedProjectEligible(plan)) {
      const em = this.projectColumnar(plan, env, meter, params);
      if (em !== null) return em;
    }

    // Materialize each relation once, in primary-key order (base tables drain a scanSource — the
    // page_read block + per-row storage_row_read accrue inside the generator, cost.md §3). The nested
    // loop re-reads from these in-memory buffers, which are not stores and charge nothing. A
    // CORRELATED LATERAL relation (§44) depends on the left-hand row, so it cannot be materialized up
    // front — an empty placeholder holds its slot and the join loop re-materializes it per left row.
    // An INDEX-NESTED-LOOP relation (cost.md §3 "JOIN") likewise depends on the left-hand row (its
    // bound seeks per outer row), so it is not materialized up front either — an empty placeholder
    // holds its slot and the join loop re-materializes it per left row.
    const materialized: Row[][] = plan.rels.map((rel, ri) =>
      rel.lateral === true || plan.phys.relINLBounds[ri] !== null
        ? []
        : this.materializeRel(plan, ri, env.outer, [], env, params, meter),
    );

    // Left-deep nested-loop join. `running` holds the combined rows over the relations joined
    // so far (starting with the first table's rows). For each join, concatenate every running
    // row with every right-table row; CROSS keeps all pairs, INNER keeps a pair iff its ON
    // predicate is TRUE (three-valued — a NULL join key never matches). LEFT/FULL additionally
    // emit each unmatched left row NULL-extended over the right side; RIGHT/FULL emit each
    // unmatched right row NULL-extended over the left side. The NULL-extension pushes evaluate
    // no ON (no operator_eval — spec/design/cost.md §3). Output order is deterministic: running
    // order (outer) then right key order (inner), each unmatched left row after its (empty)
    // match run, all unmatched right rows last in right key order (CLAUDE.md §10).
    const nullRow = (n: number): Row => Array.from({ length: n }, () => nullValue());
    // A FROM-less SELECT has no relations: seed `running` with ONE virtual zero-column row
    // instead of a table's rows (grammar.md §34). No scan ran, so no scan cost accrued.
    let running: Row[] = plan.rels.length === 0 ? [[]] : materialized[0]!;
    for (let k = 0; k < plan.joins.length; k++) {
      const on = plan.joins[k]!.on;
      const kind = plan.joins[k]!.kind;
      const emitLeft = kind === "left" || kind === "full";
      const emitRight = kind === "right" || kind === "full";
      // NULL-pad widths come from the PLAN, never a sampled row, so they are correct even when
      // `running`/`rightRows` is empty: the right table begins at flat offset rels[k+1].offset
      // (= the width of every running row) and is that many columns wide.
      const leftPad = plan.rels[k + 1]!.offset;
      const rightPad = plan.rels[k + 1]!.colCount;
      const next: Row[] = [];
      // A CORRELATED LATERAL relation (§44): re-materialize it ONCE PER combined left-hand row, with
      // that row pushed onto the outer-row stack as the body's immediate outer (the correlated-
      // subquery mechanism). The plan guarantees INNER/CROSS/LEFT here (RIGHT/FULL to a correlated
      // lateral is 42P10), so there is no unmatched-right emission.
      if (plan.rels[k + 1]!.lateral === true) {
        for (const left of running) {
          const rightRows = this.materializeRel(
            plan,
            k + 1,
            [...env.outer, left],
            [],
            env,
            params,
            meter,
          );
          let leftMatched = false;
          for (const right of rightRows) {
            const combined = left.concat(right);
            if (on === null || isTrue(evalExpr(on, combined, env, meter))) {
              next.push(combined);
              leftMatched = true;
            }
          }
          if (emitLeft && !leftMatched) next.push(left.concat(nullRow(rightPad)));
        }
        running = next;
        continue;
      }
      // An INDEX-NESTED-LOOP inner relation (cost.md §3 "JOIN"): re-materialize it ONCE PER combined
      // left-hand row, its scan bounded per outer row by the SIBLING columns of that row (a
      // per-outer-row seek instead of a full scan). Detection restricts this to the RIGHT/nullable side
      // of an INNER/CROSS/LEFT join, so there is never an unmatched-RIGHT emission (RIGHT/FULL are
      // excluded — a preserved side cannot be bounded per outer row). The whole ON/WHERE stays applied
      // (the ON here, the WHERE below), so rows are unchanged.
      if (plan.phys.relINLBounds[k + 1] !== null) {
        for (const left of running) {
          const rightRows = this.materializeRel(plan, k + 1, env.outer, left, env, params, meter);
          let leftMatched = false;
          for (const right of rightRows) {
            const combined = left.concat(right);
            if (on === null || isTrue(evalExpr(on, combined, env, meter))) {
              next.push(combined);
              leftMatched = true;
            }
          }
          if (emitLeft && !leftMatched) next.push(left.concat(nullRow(rightPad)));
        }
        running = next;
        continue;
      }
      const rightRows = materialized[k + 1]!;
      const rightMatched: boolean[] = new Array(rightRows.length).fill(false);
      for (const left of running) {
        let leftMatched = false;
        for (let ri = 0; ri < rightRows.length; ri++) {
          const combined = left.concat(rightRows[ri]!);
          if (on === null || isTrue(evalExpr(on, combined, env, meter))) {
            next.push(combined);
            leftMatched = true;
            rightMatched[ri] = true;
          }
        }
        if (emitLeft && !leftMatched) next.push(left.concat(nullRow(rightPad)));
      }
      if (emitRight) {
        for (let ri = 0; ri < rightRows.length; ri++) {
          if (!rightMatched[ri]) next.push(nullRow(leftPad).concat(rightRows[ri]!));
        }
      }
      running = next;
    }

    // WHERE over the combined rows. A WHERE arithmetic can throw (22003/22012); each surviving
    // combined row's filter accrues operator_eval.
    const rows: Row[] = [];
    for (const row of running) {
      if (plan.filter === null || isTrue(evalExpr(plan.filter, row, env, meter))) rows.push(row);
    }

    // WINDOW stage (spec/design/window.md §5.2): a blocking operator over the post-WHERE rows,
    // running BEFORE the query ORDER BY / DISTINCT / LIMIT. Each window function's per-row result is
    // APPENDED to its row (so the projection reads result i at flat slot inputWidth + i), the rows
    // keep their scan order, and the query ORDER BY below re-sorts the extended rows. A window query
    // never enters the streaming fast-paths above. A GROUPED window query (§2) runs the window stage
    // over the GROUPED rows instead, inside the aggregate branch below — so it is gated to plain
    // (non-aggregate) windows here.
    if (plan.hasWindow && !plan.isAgg) {
      applyWindowStage(rows, plan.windowSpecs, plan.windowKeys, env, meter);
    }

    // ORDER BY: stable sort applying each key left to right — the first non-equal key decides,
    // and a full tie keeps the scan order (JS Array#sort is stable). Each key's NULL placement
    // is decoupled from its value-direction flip (spec/design/grammar.md §10). Aggregate queries
    // sort their GROUP rows in the aggregate branch below — not these pre-aggregation rows — so
    // this is gated to plain queries.
    if (!plan.isAgg && plan.order.length > 0) {
      // Materialize each general-expression ORDER BY key (grammar.md §10): evaluate it against the
      // post-WHERE (post-window) row and append the value, so its sort slot finalWidth+k reads the
      // appended column and the slot-based sort below is unchanged — the window-key precedent. The
      // evaluation is metered per node (cost.md §3); a no-op for a column/ordinal-only ORDER BY.
      materializeOrderExprs(rows, plan.orderExprs, env, meter);
      sortRows(rows, plan.order);
    }

    // LIMIT / OFFSET window bounds over a result of `len` rows. Clamp in the bigint domain
    // against the row count, then index — never let a huge count cross 2^53 via Number
    // (CLAUDE.md §8; grammar.md §9). The counts are already non-negative (parser).
    const windowBounds = (len: number): [number, number] => {
      const n = BigInt(len);
      const start = plan.offset === null ? 0n : plan.offset < n ? plan.offset : n;
      const end = plan.limit !== null && plan.limit < n - start ? start + plan.limit : n;
      return [Number(start), Number(end)];
    };

    // Build the output rows. The two paths differ in pipeline order
    // (spec/design/grammar.md §11): without DISTINCT the window slices the sorted source
    // rows and ONLY the windowed rows are projected; with DISTINCT every (sorted) filtered
    // row is projected — dedup must see them all — duplicates drop by first occurrence, and
    // the window then slices the DISTINCT rows.
    if (plan.isAgg) {
      // Aggregate query — group + accumulate (aggregates.md §5). Bucket the post-WHERE rows by
      // their group-key values; the bucket key is the value-canonical distinctRowKey (it
      // collapses 1.5/1.50 and groups NULL with NULL), and the Map is only an index — output
      // order comes from the insertion-ordered `groups`, never Map iteration (no order leak —
      // §8/§10). Whole-table aggregation (no GROUP BY) is one pre-created empty-key group, so it
      // emits ONE row even over zero input; GROUP BY over an empty table creates no groups ->
      // zero rows. Each (row × aggregate) charges aggregateAccumulate; the bucketing/finalize is
      // unmetered (cost.md §3).
      const newAccs = (): Acc[] => plan.aggSpecs.map((s) => newAccFromSpec(s));
      // One DISTINCT dedup set per DISTINCT aggregate (null for a plain aggregate — COUNT(DISTINCT
      // x), aggregates.md §5). Keyed on distinctRowKey, the same value-canonical form as the
      // group-key bucketing (so 1.5 == 1.50 and -0.0 == 0.0).
      const newSeen = (): (Set<string> | null)[] =>
        plan.aggSpecs.map((s) => (s.distinct ? new Set<string>() : null));
      // One grouping set per plan.groupSets (spec/design/aggregates.md §12): a plain GROUP BY /
      // whole-table aggregate has exactly one; ROLLUP / CUBE / GROUPING SETS have several. Each set is
      // bucketed independently over the SAME post-WHERE rows and its groups projected into the shared
      // synthetic row [master_columns…, aggregate_results…, GROUPING_results…]: a column not grouped
      // in this set is NULL, and each GROUPING() value comes from this set's mask. The scan
      // (storageRowRead) is upstream and counted once; aggregateAccumulate + operand evals accrue per
      // (set × row × passing aggregate). The per-set index Map is never iterated — output order comes
      // from the insertion-ordered groups then the set order (no Map-order leak — §8/§10).
      // Materialize the general-expression GROUP BY keys (aggregates.md §15): evaluate each per
      // post-WHERE row ONCE (charging its operatorEvals, like an aggregate operand) and append the
      // value at flat slot inputWidth + k, so a master grouping-key index pointing there reads it.
      // Done before the (possibly multi-) grouping-set loop so each row is extended once and the
      // values are shared across sets. A plain column GROUP BY appends nothing. Detach from the
      // (possibly shared) stored row before appending — the scan yields references to the page
      // store's own arrays, so appending in place would corrupt them across statements (the
      // materializeOrderExprs / applyWindowStage precedent).
      if (plan.groupExprs.length > 0) {
        for (let ri = 0; ri < rows.length; ri++) {
          meter.guard();
          const row = rows[ri]!.slice();
          for (const ge of plan.groupExprs) row.push(evalExpr(ge, row, env, meter));
          rows[ri] = row;
        }
      }
      let groupRows: Value[][] = [];
      for (const gset of plan.groupSets) {
        const index = new Map<string, number>();
        const groups: { keys: Value[]; accs: Acc[]; seen: (Set<string> | null)[] }[] = [];
        // An empty grouping set (the () / whole-table grand total) is one pre-created group, so it
        // emits ONE row even over zero input; a non-empty set over empty input emits nothing.
        if (gset.keyCols.length === 0) {
          groups.push({ keys: [], accs: newAccs(), seen: newSeen() });
          index.set("", 0);
        }
        for (const row of rows) {
          meter.guard(); // enforce the cost ceiling per folded row (CLAUDE.md §13)
          const keys = gset.keyCols.map((gk) => row[gk]!);
          const k = distinctRowKey(keys);
          let gi = index.get(k);
          if (gi === undefined) {
            gi = groups.length;
            index.set(k, gi);
            groups.push({ keys, accs: newAccs(), seen: newSeen() });
          }
          const accs = groups[gi]!.accs;
          const seen = groups[gi]!.seen;
          plan.aggSpecs.forEach((spec, i) => {
            // FILTER (WHERE cond): a row for which the filter is not TRUE (FALSE or NULL) contributes
            // nothing to THIS aggregate — its operand is not evaluated and it is not accumulated
            // (aggregates.md §11). The filter's own operatorEvals are charged (it is evaluated per row,
            // like the operand); aggregateAccumulate is charged only for a row that passes. The
            // pass/fold decision is deterministic (scan order is cross-core identical).
            if (spec.filter !== undefined && spec.filter !== null) {
              if (!isTrue(evalExpr(spec.filter, row, env, meter))) return;
            }
            meter.charge(COSTS.aggregateAccumulate);
            // A hypothetical-set aggregate (rank/dense_rank/… — aggregates.md §19) buffers the row's
            // WITHIN GROUP key TUPLE (no NULL-skip — every row counts, sorted by NULLS FIRST/LAST). The
            // hypothetical row itself is evaluated per group at finalize. No DISTINCT (rejected at resolve).
            if (spec.hypo !== undefined && spec.hypo !== null) {
              const hp = spec.hypo;
              const tuple = hp.keys.map((k) => evalExpr(k, row, env, meter));
              accs[i]!.hypoRows!.push(tuple);
              return;
            }
            const v = spec.operand === null ? nullValue() : evalExpr(spec.operand, row, env, meter);
            // DISTINCT: skip a NULL (never folded by any aggregate) and any value already folded into
            // this group — the FIRST occurrence in scan order wins, so the set of folded values (and
            // the decimalWork fold charges) is order-deterministic and cross-core identical.
            const dedup = seen[i];
            if (dedup) {
              if (v.kind === "null") return;
              const dk = distinctRowKey([v]);
              if (dedup.has(dk)) return;
              dedup.add(dk);
            }
            foldAcc(accs[i]!, v, meter);
          });
        }
        // Build one synthetic row per group of this set: each master grouping column's value (NULL
        // where this set doesn't group it), then the aggregate results, then each GROUPING() value
        // (computed from this set's mask — spec/design/aggregates.md §12).
        for (const g of groups) {
          const srow: Value[] = [];
          for (const src of gset.slotSrc) srow.push(src < 0 ? nullValue() : g.keys[src]!);
          for (let si = 0; si < g.accs.length; si++) {
            const a = g.accs[si]!;
            // An ordered-set aggregate's percentile fraction (the direct argument) is evaluated PER
            // GROUP here, against the synthetic row's grouping-key values (aggregates.md §13/§17) — so
            // it may reference grouping columns. Unmetered (the finalize step, like the sort), via a
            // scratch meter. mode has none.
            if (
              a.plan === "percentileDisc" ||
              a.plan === "percentileCont" ||
              a.plan === "orderedSetContInterval"
            ) {
              const fe = plan.aggSpecs[si]!.osaFrac;
              if (fe !== undefined && fe !== null) {
                a.osaFrac = evalExpr(fe, srow, env, new Meter());
              }
            }
            // A hypothetical-set aggregate is finalized INLINE here (not via finalizeAcc) because it
            // needs the spec's per-key sort specs: evaluate the hypothetical row's direct args per group
            // (against the synthetic row, like a fraction — unmetered scratch meter), then count its rank
            // among the buffered key tuples (aggregates.md §19).
            const hp = plan.aggSpecs[si]!.hypo;
            if (hp !== undefined && hp !== null) {
              const hyp = hp.args.map((arg) => evalExpr(arg, srow, env, new Meter()));
              srow.push(finalizeHypothetical(a.plan, a.hypoRows!, hyp, hp.sorts));
              continue;
            }
            srow.push(finalizeAcc(a));
          }
          for (const positions of plan.groupingSpecs) {
            srow.push(intValue(groupingValue(positions, gset.mask)));
          }
          groupRows.push(srow);
        }
      }
      // HAVING: filter the grouped rows (after aggregation, before ORDER BY). The predicate is
      // evaluated against each group's synthetic row (charging its operatorEvals per group);
      // only a TRUE result keeps the group. A dropped group charges no rowProduced (§8).
      if (plan.having !== null) {
        groupRows = groupRows.filter((srow) => isTrue(evalExpr(plan.having!, srow, env, meter)));
      }
      // WINDOW stage over the grouped rows (spec/design/window.md §2): runs AFTER GROUP BY/HAVING and
      // BEFORE the query ORDER BY. It appends each window result to the grouped row [group_keys…,
      // agg_results…], so the projection reads window result w at slot groupKeys+aggSpecs+w (the
      // rebased slot — §5.1). The group-key slots the ORDER BY below sorts on are unchanged (they
      // precede the appended results).
      if (plan.hasWindow) {
        applyWindowStage(groupRows, plan.windowSpecs, plan.windowKeys, env, meter);
      }
      // ORDER BY over the grouped output (a column/ordinal key is a synthetic group-key slot; an
      // expression key is materialized against the grouped row and appended — grammar.md §10).
      if (plan.order.length > 0) {
        materializeOrderExprs(groupRows, plan.orderExprs, env, meter);
        sortRows(groupRows, plan.order);
      }
      if (plan.distinct) {
        // SELECT DISTINCT: project EVERY grouped row (charging its projection operatorEvals, the §3
        // asymmetry — like the non-aggregate DISTINCT path below), dedup by equality keeping the
        // first occurrence in the (already ORDER-BY-sorted) order, then LIMIT/OFFSET. `seen` is
        // membership-only; output order comes from the deterministic group iteration / sort, never
        // Set iteration (no order leak — CLAUDE.md §8/§10).
        const seen = new Set<string>();
        const distinctRows: Value[][] = [];
        for (const srow of groupRows) {
          const tuple = plan.projections.map((p) => evalExpr(p, srow, env, meter));
          const key = distinctRowKey(tuple);
          if (!seen.has(key)) {
            seen.add(key);
            distinctRows.push(tuple);
          }
        }
        // The dedup already projected every grouped row (the §3 asymmetry, charged above), so emission
        // is Identity — window + charge rowProduced, deferred to the drive (streaming.md §4).
        const [start, end] = windowBounds(distinctRows.length);
        return { rows: distinctRows, start, end, mode: "identity" };
      }
      // Window then project on emission; only an emitted row charges rowProduced + projection cost.
      // Deferred to the drive (streaming.md §4).
      const [start, end] = windowBounds(groupRows.length);
      return { rows: groupRows, start, end, mode: "project" };
    }
    if (plan.distinct) {
      // Project every filtered row (charging projection cost per row, the §3 asymmetry),
      // keeping first occurrences. `seen` is membership-only: output order comes from the
      // deterministic source iteration, never from Set iteration (no order leak — §8/§10).
      const seen = new Set<string>();
      const distinctRows: Value[][] = [];
      for (const row of rows) {
        const tuple = plan.projections.map((p) => evalExpr(p, row, env, meter));
        const key = distinctRowKey(tuple);
        if (!seen.has(key)) {
          seen.add(key);
          distinctRows.push(tuple);
        }
      }
      // LIMIT / OFFSET applies to the DISTINCT rows; only the emitted rows charge rowProduced
      // (spec/design/cost.md §3). The rows were already projected for their dedup key (the §3
      // asymmetry, charged above), so emission is Identity — deferred to the drive (streaming.md §4).
      const [start, end] = windowBounds(distinctRows.length);
      return { rows: distinctRows, start, end, mode: "identity" };
    }
    // Window the sorted rows BEFORE projection (above), so rows skipped by OFFSET or excluded by LIMIT
    // accrue no rowProduced/projection cost; project on emission — deferred to the drive (streaming.md
    // §4). (ORDER BY's sort comparisons are not metered — spec/design/cost.md §3.)
    const [start, end] = windowBounds(rows.length);
    return { rows, start, end, mode: "project" };
  }

  // ---- Uncorrelated subquery folding (spec/design/grammar.md §26) ----------------------
  //
  // After the whole statement tree is planned + the parameters bound, this bottom-up pass walks
  // every "subquery" RExpr node in the plan tree: it first folds within the node's own sub-plan,
  // then — if the subquery references NO enclosing scope (a global constant, PG's "initplan") —
  // executes it ONCE and replaces it with a constant (scalar -> its value; EXISTS -> a boolean; IN
  // -> an "inValues" over the result column), accruing the subquery's cost once (preserving the
  // committed once-only cost — cost.md §3). A CORRELATED subquery is left in place; the evaluator
  // re-executes it per outer row. So after this pass the only surviving "subquery" nodes are correlated.

  private foldUncorrelatedInPlan(
    plan: QueryPlan,
    bound: Value[],
    ctes: CteCtx,
    cost: { value: bigint },
  ): void {
    if (plan.kind === "select") {
      this.foldUncorrelatedInSelect(plan, bound, ctes, cost);
      return;
    }
    if (plan.kind === "values") {
      // A VALUES-body value may itself hold an (uncorrelated) scalar subquery to fold once before
      // the rows are produced (grammar.md §42; the §26 fold).
      for (const row of plan.rows) {
        for (let c = 0; c < row.length; c++) {
          row[c] = this.foldUncorrelatedInRExpr(row[c]!, bound, ctes, cost);
        }
      }
      return;
    }
    if (plan.kind === "with") {
      // A nested WITH body is not folded here against the enclosing ctes — its inner subqueries
      // reference the nested CTEs (a different scope, materialized only when the node runs), so they
      // are left to the evaluator, exactly like a derived table's body (spec/design/cte.md §7). The
      // whole nested-WITH subquery is itself folded by the caller if uncorrelated (executed once via
      // execWithPlan).
      return;
    }
    this.foldUncorrelatedInPlan(plan.lhs, bound, ctes, cost);
    this.foldUncorrelatedInPlan(plan.rhs, bound, ctes, cost);
  }

  private foldUncorrelatedInSelect(
    sp: SelectPlan,
    bound: Value[],
    ctes: CteCtx,
    cost: { value: bigint },
  ): void {
    for (const j of sp.joins)
      if (j.on !== null) j.on = this.foldUncorrelatedInRExpr(j.on, bound, ctes, cost);
    if (sp.filter !== null) sp.filter = this.foldUncorrelatedInRExpr(sp.filter, bound, ctes, cost);
    if (sp.having !== null) sp.having = this.foldUncorrelatedInRExpr(sp.having, bound, ctes, cost);
    for (const s of sp.aggSpecs) {
      if (s.operand !== null)
        s.operand = this.foldUncorrelatedInRExpr(s.operand, bound, ctes, cost);
    }
    sp.projections = sp.projections.map((p) => this.foldUncorrelatedInRExpr(p, bound, ctes, cost));
    // A set-returning relation's arguments may themselves contain an (uncorrelated) subquery to
    // fold once before the generator runs (functions.md §10).
    for (const rel of sp.rels) {
      if (rel.srf !== undefined) {
        rel.srf.args = rel.srf.args.map((a) => this.foldUncorrelatedInRExpr(a, bound, ctes, cost));
      }
    }
  }

  // foldUncorrelatedInRExpr folds this node if it is an uncorrelated "subquery", else recurses into
  // its children. It RETURNS the (possibly replaced) node; the caller reassigns the field.
  private foldUncorrelatedInRExpr(
    e: RExpr,
    bound: Value[],
    ctes: CteCtx,
    cost: { value: bigint },
  ): RExpr {
    switch (e.kind) {
      case "subquery": {
        // Bottom-up: fold within this subquery's own sub-plan (and its IN lhs) first, so a
        // globally-uncorrelated subquery nested inside it is already a constant before we run it.
        if (e.lhs !== null) e.lhs = this.foldUncorrelatedInRExpr(e.lhs, bound, ctes, cost);
        this.foldUncorrelatedInPlan(e.plan, bound, ctes, cost);
        if (queryPlanReferencesOuter(e.plan, 0)) return e; // correlated — re-run per outer row
        // Uncorrelated: execute ONCE and fold to a constant / inValues.
        const r = this.execQueryPlan(e.plan, [], bound, ctes);
        cost.value += r.cost;
        if (e.subKind === "scalar") {
          if (r.rows.length > 1) {
            throw engineError(
              "cardinality_violation",
              "more than one row returned by a subquery used as an expression",
            );
          }
          return valueToRExpr(r.rows.length === 1 ? r.rows[0]![0]! : nullValue());
        }
        if (e.subKind === "exists") {
          return { kind: "constBool", value: r.rows.length > 0 !== e.negated };
        }
        if (e.subKind === "quantified") {
          // An uncorrelated quantified subquery folds to a constant-array `quantified`
          // (array-functions.md §11.6): its single column becomes a 1-D array and the node reuses
          // the array form's 3VL fold — no per-row re-execution.
          const elements = r.rows.map((row) => row[0]!);
          return {
            kind: "quantified",
            op: e.op!,
            all: e.all!,
            lhs: e.lhs!,
            array: valueToRExpr(arrayValue(elements)),
          };
        }
        // in
        const list = r.rows.map((row) => row[0]!);
        return { kind: "inValues", lhs: e.lhs!, list, negated: e.negated };
      }
      case "cast":
      case "arrayCast":
      case "neg":
      case "not":
      case "isNull":
      case "isJson":
      case "jsonCtor":
        e.operand = this.foldUncorrelatedInRExpr(e.operand, bound, ctes, cost);
        return e;
      case "arith":
      case "compare":
      case "and":
      case "or":
      case "distinct":
      case "like":
      case "regex":
        e.lhs = this.foldUncorrelatedInRExpr(e.lhs, bound, ctes, cost);
        e.rhs = this.foldUncorrelatedInRExpr(e.rhs, bound, ctes, cost);
        return e;
      case "jsonGet":
      case "jsonHasKey":
      case "jsonDelete":
        e.base = this.foldUncorrelatedInRExpr(e.base, bound, ctes, cost);
        e.arg = this.foldUncorrelatedInRExpr(e.arg, bound, ctes, cost);
        return e;
      case "jsonContains":
      case "jsonConcat":
        e.a = this.foldUncorrelatedInRExpr(e.a, bound, ctes, cost);
        e.b = this.foldUncorrelatedInRExpr(e.b, bound, ctes, cost);
        return e;
      case "casing":
        e.arg = this.foldUncorrelatedInRExpr(e.arg, bound, ctes, cost);
        return e;
      case "atTimeZone":
        e.zone = this.foldUncorrelatedInRExpr(e.zone, bound, ctes, cost);
        e.value = this.foldUncorrelatedInRExpr(e.value, bound, ctes, cost);
        return e;
      case "dateTrunc":
        e.unit = this.foldUncorrelatedInRExpr(e.unit, bound, ctes, cost);
        e.value = this.foldUncorrelatedInRExpr(e.value, bound, ctes, cost);
        if (e.zone) e.zone = this.foldUncorrelatedInRExpr(e.zone, bound, ctes, cost);
        return e;
      case "extract":
        e.value = this.foldUncorrelatedInRExpr(e.value, bound, ctes, cost);
        return e;
      case "dateConvert":
        e.inner = this.foldUncorrelatedInRExpr(e.inner, bound, ctes, cost);
        return e;
      case "case":
        e.arms = e.arms.map((arm) => ({
          cond: this.foldUncorrelatedInRExpr(arm.cond, bound, ctes, cost),
          result: this.foldUncorrelatedInRExpr(arm.result, bound, ctes, cost),
        }));
        e.els = this.foldUncorrelatedInRExpr(e.els, bound, ctes, cost);
        return e;
      case "greatestLeast":
      case "coalesce":
      case "scalarFunc":
      case "arrayFunc":
      case "regexFunc":
      case "rangeFunc":
      case "rangeCtor":
      case "rangeOp":
      case "rangeSetOp":
      case "variadic":
      case "jsonBuild":
      case "jsonSetInsert":
      case "jsonObjectFromArrays":
      case "jsonPathFn":
      case "jsonSqlFn":
        e.args = e.args.map((a) => this.foldUncorrelatedInRExpr(a, bound, ctes, cost));
        return e;
      case "row":
        e.fields = e.fields.map((f) => this.foldUncorrelatedInRExpr(f, bound, ctes, cost));
        return e;
      case "array":
        e.elements = e.elements.map((el) => this.foldUncorrelatedInRExpr(el, bound, ctes, cost));
        return e;
      case "field":
        e.base = this.foldUncorrelatedInRExpr(e.base, bound, ctes, cost);
        return e;
      case "subscript":
        e.base = this.foldUncorrelatedInRExpr(e.base, bound, ctes, cost);
        e.subscripts = e.subscripts.map((s) =>
          s.isSlice
            ? {
                isSlice: true,
                lower:
                  s.lower === null
                    ? null
                    : this.foldUncorrelatedInRExpr(s.lower, bound, ctes, cost),
                upper:
                  s.upper === null
                    ? null
                    : this.foldUncorrelatedInRExpr(s.upper, bound, ctes, cost),
              }
            : {
                isSlice: false,
                index: this.foldUncorrelatedInRExpr(s.index, bound, ctes, cost),
              },
        );
        return e;
      case "inValues":
        e.lhs = this.foldUncorrelatedInRExpr(e.lhs, bound, ctes, cost);
        return e;
      case "quantified":
        e.lhs = this.foldUncorrelatedInRExpr(e.lhs, bound, ctes, cost);
        e.array = this.foldUncorrelatedInRExpr(e.array, bound, ctes, cost);
        return e;
      default:
        return e; // leaves: column, outerColumn, param, const*
    }
  }
}

// scanSource streams a base table's already-materialized rows as a pull-based generator — the
// Volcano seam the streaming + point-lookup work (TODO Phase 6) builds on. The caller decides full
// scan vs primary-key bound (passing the matching rows + the visited-node count); this generator just
// charges the pageRead block (one per visited B-tree node — spec/design/cost.md §3 "page_read") once,
// before the first row, then storageRowRead per row yielded: the same units in the same order as the
// inline scan loop it replaced. The block fires before any row even for an empty scan (nodeCount 0 ⇒ a
// no-op charge, driven by the consuming for-of's first next()), so the accrued total never moves. The
// consumer drains it fully in this slice (no short-circuit), keeping the laziness unobservable and the
// cost identical to Go/Rust.
function* scanSource(rows: Row[], nodeCount: number, meter: Meter): Generator<Row> {
  meter.charge(COSTS.pageRead * BigInt(nodeCount));
  for (const row of rows) {
    // Enforce the cost ceiling before pulling the next row (CLAUDE.md §13): a runaway scan (or a
    // JOIN/correlated re-scan built on this source) stops deterministically once accrued cost
    // reaches the limit. No-op when unlimited (spec/design/cost.md §6).
    meter.guard();
    meter.charge(COSTS.storageRowRead);
    yield row;
  }
}

// ---- Primary-key predicate pushdown (spec/design/cost.md §3 "bounded scan / point lookup") ----
//
// A single-table WHERE on the primary key bounds the storage-key range a scan must visit. Detection is
// two-stage: detectPkBound at plan time (structural — which conjuncts are PK comparisons), buildKeyBound
// at exec time (the const values, and any $N, are known only then). The bound is a SUPERSET of the
// matching keys: the whole WHERE stays the residual filter (re-applied to each scanned row), so the
// result is always correct — the bound only narrows which rows are scanned, and page_read/storageRowRead
// drop to what it touches. The unbounded case keeps the full scan, so its cost never moves.

// ScanBound is a per-relation scan bound (cost.md §3): a primary-key range, a
// secondary-index equality (spec/design/indexes.md §5), a GIN-bounded scan over an array column
// (spec/design/gin.md §6), a GiST-bounded scan, or a MERGED point-set (an OR / IN-list of key
// equalities lowered to a union of point probes — cost.md §3 "OR / IN-list"). The PK bound wins
// when several apply (it is the row's own key — no second tree, range-capable, strictly cheaper);
// the ordered-index equality bound wins over GIN (gin.md §6). The point-set bounds (pkSet/indexSet)
// are a LAST-RESORT access path, chosen only when no contiguous PK/index/GIN/GiST bound applies, so
// they never displace an existing plan.
export type ScanBound =
  | { kind: "pk"; pk: PkBound }
  | { kind: "index"; index: IndexBound }
  | { kind: "gin"; gin: GinBound }
  | { kind: "gist"; gist: GistBound }
  | { kind: "pkSet"; pkSet: PkKeySet }
  | { kind: "indexSet"; indexSet: IndexKeySet };

// needsEagerScan reports whether a bound needs the general eager materialize path (materializeRel /
// the DML scan) rather than a single-contiguous-range fast path (streaming scan, columnar project,
// vectorized aggregate, streaming sort, join top-N). True for a second-tree gather (index / GIN /
// GiST) and for a merged OR/IN point-set (pkSet / indexSet — a union of probes, cost.md §3
// "OR / IN-list"); false for a null bound or a plain PK contiguous bound (which every fast path
// handles via a single buildKeyBound). Every single-table fast-path gate consults this so the
// point-set bounds are interpreted in exactly ONE place (materializeRel), never silently dropped to
// a full scan by a fast path that only understands `pk`. Nil-safe (a null/undefined bound is not eager).
export function needsEagerScan(sb: ScanBound | null | undefined): boolean {
  if (sb === null || sb === undefined) return false;
  return (
    sb.kind === "index" ||
    sb.kind === "gin" ||
    sb.kind === "gist" ||
    sb.kind === "pkSet" ||
    sb.kind === "indexSet"
  );
}

// PkKeySet is the plan-time result of an OR / IN-list disjunction of primary-key equalities
// (`pk = a OR pk = b OR …`, or the equivalent `pk IN (a, b, …)` which desugars to that OR-chain —
// cost.md §3 "OR / IN-list"). srcs is the equality const-sources, one per disjunct, in source order
// (a bind param, an outer/correlated column, or a literal — isConstSource of the PK type). At exec
// time each src encodes into the PK key space; the resulting keys are de-duplicated and sorted, and
// each becomes a point probe [k, k]. The whole WHERE stays the residual filter (the union is a
// superset), so the result is unchanged. coll is the PK's key collation (null for a C key).
export type PkKeySet = { pkType: ScalarType; coll: Collation | null; srcs: RExpr[] };

// IndexKeySet is the PkKeySet analog over a leading B-tree secondary-index column (indexes.md §5):
// each distinct encoded value becomes an index point probe (prefix scan + per-entry row lookup), and
// the rows are gathered in ascending value order. tailTypes is the remaining key components' types
// (as in IndexBound) — the per-entry key-suffix skip.
export type IndexKeySet = {
  nameKey: string;
  colType: ScalarType;
  coll: Collation | null;
  tailTypes: ScalarType[];
  srcs: RExpr[];
};

// GistBound is the plan-time result of GiST analysis (spec/design/gist.md §5): the chosen GiST index
// (lowest lowercased name whose range column has a `col && const` / `col @> const` conjunct), the
// descent strategy, and the column's global scope index. Like GinBound, the constant query operand is
// NOT stored (re-found in plan.filter at exec time by gistMatch). No element type — the gather
// descends the resident R-tree (gist.md §4.1), whose bounds are already decoded.
export type GistBound = {
  nameKey: string;
  strategy: GistStrategy;
  colGlobal: number;
  // scalarType is the GiST-indexed column's scalar type for the scalar `=` opclass (strategy "equal",
  // GX2): gistBoundRows encodes the equality constant to its order-preserving key bytes with it.
  // Undefined for range_ops, whose &&/@> query is a range constant the R-tree compares directly.
  scalarType?: ScalarType;
};

// GinStrategy is which array operator a GIN bound accelerates (spec/design/gin.md §6): @>
// (contains, mode ALL → posting-list intersection), && (overlaps, mode ANY → union), = ANY
// ("member" — `c = ANY(col)`, the single-term @> reduction: one scalar term, its lone posting
// list), or array = ("equal" — `col = Q`, the @>-superset gather + residual =). For "member" the
// query operand recovered by ginMatch is the scalar c, not an array; for "equal" it is the array Q
// whose distinct non-NULL elements gather the same superset as `@> Q` (equal arrays have identical
// element multisets, so col = Q ⟹ col @> Q), made exact by the residual = filter.
export type GinStrategy = "contains" | "overlaps" | "member" | "equal";

// GinBound is the plan-time result of GIN analysis (spec/design/gin.md §6): the chosen GIN
// index (lowest lowercased name whose array column has a `col @> const` / `col && const`
// conjunct), the array ELEMENT type (for encode(term) — the term bytes), the operator
// strategy, and the column's global scope index. The constant query Q is NOT stored; it is
// re-found in plan.filter at exec time by ginMatch and evaluated there.
export type GinBound = {
  nameKey: string;
  elemType: ScalarType;
  strategy: GinStrategy;
  colGlobal: number;
};

// IndexEqCol is one column of an index access predicate's equality prefix (indexes.md §5.1): the
// column's storage type, its key collation (non-null only for a Full-collated text column), and every
// equality const-source bound to it. At exec time the sources must agree on one value (else the bound
// is provably empty). A collated column encodes its probe via the UCA sort key (encoding.md §2.12) to
// match the index's stored key form (collation.md §8).
export type IndexEqCol = { colType: ScalarType; coll: Collation | null; srcs: RExpr[] };

// IndexRange is the optional trailing range of an index access predicate (indexes.md §5.1): a range
// on the key column immediately after the equality prefix. Its column is fixed-width (never collated).
export type IndexRange = { colType: ScalarType; terms: BoundTerm[] };

// IndexBound is the plan-time result of index analysis (indexes.md §5.1): the chosen index (lowest
// lowercased name yielding a non-empty access predicate) and the predicate — a maximal EQUALITY PREFIX
// on the leading key columns (eqCols) plus an OPTIONAL RANGE on the next column (range). At exec time
// buildIndexBound turns these into a concrete index-key range: the equality prefix bytes P =
// concatenated present slots, then the range (if any) intersected relative to P. suffixTypes are the
// types of the index columns AFTER the equality prefix (columns[eqCols.length..]) — the range column
// (if any) plus every trailing column — each FIXED-WIDTH so an admitted entry's row-key suffix is
// recovered by width-skipping them past P.
export type IndexBound = {
  nameKey: string;
  eqCols: IndexEqCol[];
  range: IndexRange | null;
  suffixTypes: ScalarType[];
};

// buildIndexAccessPredicate constructs an index access predicate for idx over rel (indexes.md §5.1): a
// maximal EQUALITY PREFIX on the leading key columns plus an OPTIONAL RANGE on the next column. It
// walks the index's key columns in key order against the WHERE AND-chain, consuming a column with an
// agreed equality conjunct into the prefix and stopping at the first column that has no equality
// (taking its range conjuncts, if any, as the trailing range). null for a non-B-tree index, a Skewed
// collated bound column (whose stored keys are at the file's pinned version — collation.md §12), no
// bound at all, or an ineligible suffix (a column after the equality prefix that is not a fixed-width
// scalar — the width-based key-suffix skip needs it). siblingCutoff opens the index-nested-loop door
// (>= 0 admits a bare sibling "column" node with index < cutoff as a bound source, resolved per outer
// row); -1 is the ordinary once-materialized bound.
export function buildIndexAccessPredicate(
  filter: RExpr,
  rel: ScopeRel,
  idx: IndexDef,
  siblingCutoff: number,
  snap: Snapshot,
  engine: Engine,
): IndexBound | null {
  if (idx.kind !== "btree") return null;
  // Resolve the index's key elements (column ordinals + resolved expression keys). A resolution
  // failure yields no bound (a full scan — always sound). indexes.md §5.
  let rindex: ResolvedIndex;
  try {
    rindex = engine.resolveIndex(rel.table, idx);
  } catch {
    return null;
  }
  // A PARTIAL index holds only its qualifying rows (indexes.md §9), so it is usable ONLY when the
  // query's WHERE implies the index predicate. jed's test is syntactic (PG's, not a prover): the WHERE
  // AND-chain must contain a conjunct STRUCTURALLY EQUAL to the resolved predicate. A miss yields no
  // bound — a correct full scan. (The resolved predicate is in table-local column coords; a WHERE
  // conjunct is global, so it is matched shifted by rel.offset.)
  if (
    rindex.predicate !== undefined &&
    !filterImpliesPredicate(filter, rindex.predicate, rel.offset)
  ) {
    return null;
  }
  const eqCols: IndexEqCol[] = [];
  let range: IndexRange | null = null;
  for (const key of rindex.keys) {
    // Each key element yields (its scalar key type, its key collation, the matcher against a WHERE
    // conjunct operand). A non-scalar / skewed element stops the prefix.
    let ty: ScalarType;
    let coll: Collation | null;
    let matcher: KeyMatch;
    if (key.kind === "column") {
      const ci = key.column;
      const s = typeAsScalar(rel.table.columns[ci]!.type);
      if (s === undefined) break; // a range/array/composite column cannot be seeked
      // Collation.md §8/§12: a Skewed collated column refuses the bound (its stored keys are wrong
      // for the loaded bundle) — stop the prefix. C/Full admissible.
      const ctx = keyCollationCtx(snap, rel.table.columns[ci]!);
      if (ctx === null) break;
      ty = s;
      coll = ctx.coll;
      matcher = { kind: "column", index: rel.offset + ci };
    } else {
      // An expression key seeks only when its result is a scalar and its collation is C (the common
      // `lower(email)` shape). A collated-expression bound is a deferred follow-on (§5). Match a
      // WHERE operand structurally against the key.
      const s = typeAsScalar(key.type);
      if (s === undefined) break;
      if (key.coll !== null) break;
      ty = s;
      coll = null;
      matcher = { kind: "expr", expr: key.expr, offset: rel.offset };
    }
    const colColl = coll !== null ? coll.name : null;
    const eqs: RExpr[] = [];
    const ranges: BoundTerm[] = [];
    const walk = (e: RExpr): void => {
      if (e.kind === "and") {
        walk(e.lhs);
        walk(e.rhs);
        return;
      }
      const t = asBoundTerm(e, matcher, ty, colColl, siblingCutoff);
      if (t !== null) {
        if (t.op === "eq") eqs.push(t.src);
        else ranges.push(t);
      }
    };
    walk(filter);
    if (eqs.length > 0) {
      eqCols.push({ colType: ty, coll, srcs: eqs });
      continue; // extend the equality prefix
    }
    if (ranges.length > 0) range = { colType: ty, terms: ranges };
    break; // first non-equality element ends the prefix (with or without a trailing range)
  }
  if (eqCols.length === 0 && range === null) return null; // nothing bound
  // Eligibility: every key element from the range element onward (keys[eqCols.length..]) is
  // width-skipped past the known equality prefix to recover the storage key, so each must be a
  // fixed-width scalar (a column's type, or an expression's result type). The equality-prefix
  // elements may be any width — their slots are matched as the known prefix bytes.
  const suffixTypes: ScalarType[] = [];
  for (const key of rindex.keys.slice(eqCols.length)) {
    const s =
      key.kind === "column"
        ? typeAsScalar(rel.table.columns[key.column]!.type)
        : typeAsScalar(key.type);
    if (s === undefined || !isFixedWidth(s)) return null;
    suffixTypes.push(s);
  }
  return { nameKey: idx.name.toLowerCase(), eqCols, range, suffixTypes };
}

// detectScanBound picks one relation's scan bound (cost.md §3; indexes.md §5): the
// single-column PK bound first; else, among the relation's indexes (held in ascending
// lowercased-name order — the deterministic tie-break), the first that yields a non-empty
// access predicate (buildIndexAccessPredicate); else null (full scan).
export function detectScanBound(
  filter: RExpr,
  rel: ScopeRel,
  snap: Snapshot,
  engine: Engine,
): ScanBound | null {
  // A host-attached relation full-scans this slice (attached-databases.md §8): the bounded-scan exec
  // path resolves index stores unscoped, so no PK/index/GiST/GIN bound may apply to an attachment.
  if (isAttachmentScope(rel.db)) return null;
  const pkLocal = primaryKeyIndex(rel.table);
  if (pkLocal >= 0) {
    // Ordered-equality pushdown is scalar-only; a non-scalar (range) PK skips it (point-lookup
    // deferred for containers — ranges.md §10), falling through to a full scan + residual filter.
    const sty = typeAsScalar(rel.table.columns[pkLocal]!.type);
    if (sty !== undefined) {
      // The PK column's key collation form (collation.md §8/§12): null ⇒ collated but Skewed ⇒
      // refuse pushdown (full heap-scan recompute — the read-safety rule §12); else { coll } where
      // coll is null (C, raw-byte key) or the Full-collated table (push via the sort key).
      const ctx = keyCollationCtx(snap, rel.table.columns[pkLocal]!);
      if (ctx !== null) {
        const bp = detectPkBound(filter, rel.offset + pkLocal, sty, ctx.coll);
        if (bp !== null) return { kind: "pk", pk: bp };
      }
    }
  }
  for (const idx of rel.table.indexes) {
    // An index access predicate (indexes.md §5.1): a maximal equality prefix + optional trailing range
    // over a B-tree index's leading key columns. null for a GIN/GiST index (handled by the passes
    // below), an ineligible suffix, or no bound. Indexes are held in ascending lowercased-name order,
    // so the first non-null wins — the deterministic tie-break.
    const ib = buildIndexAccessPredicate(filter, rel, idx, -1, snap, engine);
    if (ib !== null) return { kind: "index", index: ib };
  }
  // GiST bound (gist.md §5) — a `col && const` / `col @> const` over a range column; the ordered loop
  // above already skipped the GiST index (its leading column is a non-scalar range).
  const gtb = detectGistBound(filter, rel.table.indexes, rel.table.columns, rel.offset);
  if (gtb !== null) return { kind: "gist", gist: gtb };
  // GIN bound (gin.md §6) — after the PK and ordered-index equality bounds.
  const gb = detectGinBound(filter, rel.table.indexes, rel.table.columns, rel.offset);
  if (gb !== null) return { kind: "gin", gin: gb };
  // LAST RESORT — an OR / IN-list of key equalities lowered to merged point probes (cost.md §3
  // "OR / IN-list"). Reached only when no contiguous PK/index/GIN/GiST bound applied above, so this
  // never displaces an existing plan. The primary key wins over a secondary index (its own key — no
  // second tree), matching detectScanBound's ordering.
  if (pkLocal >= 0) {
    const sty = typeAsScalar(rel.table.columns[pkLocal]!.type);
    if (sty !== undefined) {
      const ctx = keyCollationCtx(snap, rel.table.columns[pkLocal]!);
      if (ctx !== null) {
        const srcs = detectKeySet(filter, rel.offset + pkLocal, sty, ctx.coll);
        if (srcs !== null) return { kind: "pkSet", pkSet: { pkType: sty, coll: ctx.coll, srcs } };
      }
    }
  }
  for (const idx of rel.table.indexes) {
    if (idx.kind !== "btree") continue;
    // A PARTIAL index is not used for the OR/IN point-set this slice (indexes.md §9): the merged
    // point-lookup path carries no predicate-implication gate, so it stays non-partial (a follow-on) —
    // falling through leaves a correct full scan.
    if (idx.predicate !== undefined) continue;
    // The OR/IN merged-point-lookup bound is column-only this slice (an expression index takes the
    // access-predicate path — indexes.md §5; OR/IN over an expression key is a follow-on).
    const cols = indexColumnOrdinals(idx);
    if (cols === null) continue;
    const ci = cols[0]!;
    const ty = typeAsScalar(rel.table.columns[ci]!.type);
    if (ty === undefined) continue;
    if (
      cols.slice(1).some((c) => {
        const ts = typeAsScalar(rel.table.columns[c]!.type);
        return ts === undefined || !isFixedWidth(ts);
      })
    ) {
      continue;
    }
    const ctx = keyCollationCtx(snap, rel.table.columns[ci]!);
    if (ctx === null) continue;
    const srcs = detectKeySet(filter, rel.offset + ci, ty, ctx.coll);
    if (srcs !== null) {
      const tailTypes = cols.slice(1).map((c) => typeScalar(rel.table.columns[c]!.type));
      return {
        kind: "indexSet",
        indexSet: { nameKey: idx.name.toLowerCase(), colType: ty, coll: ctx.coll, tailTypes, srcs },
      };
    }
  }
  return null;
}

// detectKeySet finds an OR / IN-list disjunction of equalities on ONE key column (at global index
// keyIdx) and returns its equality const-sources (one per disjunct), or null if the filter has no
// such shape (cost.md §3 "OR / IN-list"). `x IN (a, b, c)` desugars to `x = a OR x = b OR x = c` at
// resolve time (grammar.md §20), so an IN-list and a hand-written OR-of-equalities present the
// identical tree — this handles both. The filter's top-level AND-chain is flattened; the FIRST
// conjunct that reduces to a pure disjunction of `keycol = const` equalities is used (the rest of the
// WHERE stays the residual filter). A conjunct reduces iff it is a `keycol = const`, or an OR of two
// reducing operands — an AND, a NOT, a range comparison, or an equality on a different column makes it
// non-reducing, so a mixed disjunction (`pk = 1 OR x = 2`) or a NOT IN (`NOT (pk = 1 OR …)`) correctly
// yields no bound. Conservative + sound: an unrecognized filter contributes no bound.
export function detectKeySet(
  filter: RExpr | null,
  keyIdx: number,
  keyType: ScalarType,
  coll: Collation | null,
): RExpr[] | null {
  const colColl = coll !== null ? coll.name : null;
  let found: RExpr[] | null = null;
  const walkAnd = (e: RExpr | null): void => {
    if (found !== null || e === null) return;
    if (e.kind === "and") {
      walkAnd(e.lhs);
      walkAnd(e.rhs);
      return;
    }
    const srcs = reduceKeySet(e, keyIdx, keyType, colColl);
    if (srcs !== null) found = srcs;
  };
  walkAnd(filter);
  return found;
}

// reduceKeySet reduces one predicate to the set of equality const-sources it bounds keyIdx with, or
// null if it is not a pure disjunction of `keycol = const` (detectKeySet). Descends OR nodes only; a
// single `keycol = const` leaf is the base case (reusing asBoundTerm, siblingCutoff -1 — no sibling
// references in a once-materialized bound).
export function reduceKeySet(
  e: RExpr,
  keyIdx: number,
  keyType: ScalarType,
  colColl: string | null,
): RExpr[] | null {
  if (e.kind === "or") {
    const l = reduceKeySet(e.lhs, keyIdx, keyType, colColl);
    if (l === null) return null;
    const r = reduceKeySet(e.rhs, keyIdx, keyType, colColl);
    if (r === null) return null;
    return l.concat(r);
  }
  const t = asBoundTerm(e, { kind: "column", index: keyIdx }, keyType, colColl, -1);
  if (t !== null && t.op === "eq") return [t.src];
  return null;
}

// detectINLBound detects an index-nested-loop scan bound for a join inner relation rel (cost.md §3
// "JOIN"): a primary-key (or leading secondary-index column) comparison to a SIBLING column of an
// EARLIER join relation, taken from the join's `on` predicate OR the `whereFilter`. Unlike
// detectScanBound (constants only), this admits a bare sibling column (a "column" node whose global
// index is < rel.offset), resolved per outer row from the current combined left-hand row — the join
// analog of a correlated subquery's outer reference (query.correlated_pushdown). So the inner relation
// seeks per outer row instead of full-scanning for every outer row: O(N·M) → O(N·log M).
//
// Returns non-null only when the resulting bound has >= 1 sibling term (a "column" src); a
// constant-only bound is the ordinary once-materialized relBounds path. Constant terms on the same key
// ride along and tighten the per-outer-row seek. The whole on/where stays the residual filter (a
// superset), so the ROWS are unchanged; only the inner re-scan cost drops. Caller restricts this to a
// base table that is the right/nullable side of an INNER/CROSS/LEFT join.
export function detectINLBound(
  on: RExpr | null,
  whereFilter: RExpr | null,
  rel: ScopeRel,
  snap: Snapshot,
): ScanBound | null {
  // A host-attached inner relation full-scans per outer row this slice (attached-databases.md §8): the
  // seek would resolve its index store unscoped. Index-nested-loop over an attachment is a perf follow-on.
  if (isAttachmentScope(rel.db)) return null;
  const cutoff = rel.offset;
  const collect = (keyIdx: number, ty: ScalarType, coll: Collation | null): BoundTerm[] => {
    const colColl = coll !== null ? coll.name : null;
    const terms: BoundTerm[] = [];
    const walk = (e: RExpr | null): void => {
      if (e === null) return;
      if (e.kind === "and") {
        walk(e.lhs);
        walk(e.rhs);
        return;
      }
      const t = asBoundTerm(e, { kind: "column", index: keyIdx }, ty, colColl, cutoff);
      if (t !== null) terms.push(t);
    };
    walk(on);
    walk(whereFilter);
    return terms;
  };
  const hasSibling = (terms: BoundTerm[]): boolean => terms.some((t) => t.src.kind === "column");
  // Primary-key bound first (the row's own key — range-capable, strictly cheaper).
  const pkLocal = primaryKeyIndex(rel.table);
  if (pkLocal >= 0) {
    const sty = typeAsScalar(rel.table.columns[pkLocal]!.type);
    if (sty !== undefined) {
      const ctx = keyCollationCtx(snap, rel.table.columns[pkLocal]!);
      if (ctx !== null) {
        const terms = collect(rel.offset + pkLocal, sty, ctx.coll);
        if (hasSibling(terms)) return { kind: "pk", pk: { pkType: sty, terms, coll: ctx.coll } };
      }
    }
  }
  // Else a leading secondary-index equality bound to a sibling (indexes in ascending lowercased name
  // order — the deterministic tie-break, matching detectScanBound).
  for (const idx of rel.table.indexes) {
    if (idx.kind !== "btree") continue;
    // The index-nested-loop sibling bound is column-only this slice (an expression index takes the
    // access-predicate path — indexes.md §5; an INL bound over an expression key is a follow-on).
    const cols = indexColumnOrdinals(idx);
    if (cols === null) continue;
    const ci = cols[0]!;
    const ty = typeAsScalar(rel.table.columns[ci]!.type);
    if (ty === undefined) continue;
    if (
      cols.slice(1).some((c) => {
        const ts = typeAsScalar(rel.table.columns[c]!.type);
        return ts === undefined || !isFixedWidth(ts);
      })
    ) {
      continue;
    }
    const ctx = keyCollationCtx(snap, rel.table.columns[ci]!);
    if (ctx === null) continue;
    const terms = collect(rel.offset + ci, ty, ctx.coll);
    const eqs: RExpr[] = [];
    let siblingEq = false;
    for (const t of terms) {
      if (t.op === "eq") {
        eqs.push(t.src);
        if (t.src.kind === "column") siblingEq = true;
      }
    }
    if (siblingEq) {
      // This slice keeps the index-nested-loop bound single-column-equality (a leading key column
      // bound to a sibling); a multi-column / range INL bound is a follow-on (cost.md §3
      // "index-nested-loop"). suffixTypes are the trailing columns (columns[1..], fixed-width by the
      // check above), width-skipped past the single equality slot.
      const suffixTypes = cols.slice(1).map((c) => typeScalar(rel.table.columns[c]!.type));
      return {
        kind: "index",
        index: {
          nameKey: idx.name.toLowerCase(),
          eqCols: [{ colType: ty, coll: ctx.coll, srcs: eqs }],
          range: null,
          suffixTypes,
        },
      };
    }
  }
  return null;
}

// keyCollationCtx reports the collation a key over col is STORED under, deciding whether — and how —
// a comparison bound may push down to that key (spec/design/collation.md §8/§12). Three outcomes:
//   - { coll: null }  — col is C (or non-text): the key is raw bytes (encoding.md §2.4), always
//     pushable, the unchanged fast path.
//   - { coll }        — col is collated and the collation is Full (its file pin matches the loaded
//     bundle): the key is the UCA sort key (encoding.md §2.12), pushable using coll to encode the
//     probe in the same form.
//   - null            — col is collated but Skewed (its file pin differs from the loaded bundle):
//     push is REFUSED. The scan stays a full heap-scan that recomputes against the LOADED table (the
//     read-safety rule §12; seeking a loaded-version probe in a file-version B-tree would mis-match —
//     the tripwire suites/collation/skew.test stays green only because this refuses). An unresolvable
//     collation likewise refuses rather than mis-encoding.
export function keyCollationCtx(snap: Snapshot, col: Column): { coll: Collation | null } | null {
  if (col.collation === null) return { coll: null };
  if (snap.collationSkew(col.collation) !== undefined) return null;
  const c = snap.resolveCollation(col.collation);
  return c !== undefined ? { coll: c } : null;
}

// orderSatisfiedByPK reports whether a single base relation's ORDER BY is satisfied by its
// PRIMARY-KEY scan order (spec/design/cost.md §3), and in which DIRECTION: it returns
// { reverse } where reverse=true means the order is all-DESC over the full PK, served by a REVERSE
// scan, and reverse=false means all-ASC (forward); null when the sort cannot be elided. The
// direction comes from the first ORDER BY key; every PK-prefix key must share it (no mixed
// ASC/DESC). Two asymmetric coverage rules, both grounded in the eager sort being a STABLE sort
// that breaks ties in input = PK-ascending order: forward (ASC) allows a strict PREFIX of the PK
// (the remaining columns tie-break ascending, exactly the input order the stable sort preserves);
// reverse (DESC) requires the FULL PK (order.length >= pk.length) because a strict DESC prefix of a
// composite PK would have the eager sort break ties in PK-ascending input order, which a reverse
// scan inverts — so reverse is restricted to the unique full key, where no ties remain. The PK
// columns are NOT NULL, so a key's NULLS FIRST|LAST is a no-op and is ignored.
export function orderSatisfiedByPK(
  snap: Snapshot,
  table: Table,
  offset: number,
  order: OrderSlot[],
): { reverse: boolean } | null {
  const pk = pkIndices(table);
  if (pk.length === 0) return null; // no PK (synthetic rowid order is not a user-visible column)
  const reverse = order[0]!.descending; // direction comes from the first ORDER BY key
  if (reverse && order.length < pk.length) return null; // reverse needs the full (unique) PK
  const m = Math.min(order.length, pk.length);
  for (let i = 0; i < m; i++) {
    const o = order[i]!;
    if (o.descending !== reverse) return null; // every PK-prefix key must share the scan direction
    if (o.idx !== offset + pk[i]!) return null; // must be the i-th PK column, in key order
    // The ORDER BY key must sort by the SAME order the stored PK key realizes. A raw-byte
    // (C/non-text) key matches a key with no collation; a Full-collated key matches the SAME
    // collation; a Skewed/unresolvable collation never matches (its stored keys are at the file's
    // pinned version, so the scan order would be wrong for the loaded one — §12).
    const ctx = keyCollationCtx(snap, table.columns[pk[i]!]!);
    if (ctx === null) return null; // Skewed / unresolvable
    if (ctx.coll === null) {
      if (o.collation !== null) return null; // raw-byte key, but the ORDER BY key carries a collation
    } else if (o.collation === null || o.collation.name !== ctx.coll.name) {
      return null;
    }
  }
  return { reverse };
}

// pkStorageWidth returns the fixed byte width of a table's stored primary key (encodePkKey = the
// bare per-column order-preserving keys concatenated, no NULL tags — a PK is NOT NULL), or null when
// ANY PK column is variable-width (text/decimal/bytea/interval) or non-scalar (range/composite), or
// the table has no PK. Used by the secondary-index-order scan to peel the PK suffix off the END of
// each index entry key (the "key-suffix skip", cost.md §3) — sound only when that suffix is a known
// fixed length.
export function pkStorageWidth(table: Table): number | null {
  const pk = pkIndices(table);
  if (pk.length === 0) return null; // a no-PK table keys on a synthetic rowid — not handled here
  let w = 0;
  for (const ci of pk) {
    const ty = table.columns[ci]!.type;
    if (ty.kind !== "scalar" || !isFixedWidth(ty.scalar)) return null; // non-scalar / variable-width
    w += widthBytes(ty.scalar);
  }
  return w;
}

// IndexOrder is the secondary-index-order plan: walk a B-tree index in key order to satisfy an ORDER
// BY without a sort, point-looking-up each row by its primary key (cost.md §3).
export type IndexOrder = { nameKey: string; pkWidth: number };

// orderSatisfiedByIndex reports whether a single base relation's ORDER BY is satisfied by walking one
// of its B-tree SECONDARY indexes in key order (cost.md §3 "secondary-index order"), and which index.
// The index store holds its entries in (indexed columns, storage key) order, so a forward walk
// delivers rows in ORDER BY <indexed columns> ASC NULLS LAST order, ties broken by the PK — exactly
// the eager stable sort's tie-break. Returns non-null iff the ORDER BY keys are EXACTLY a B-tree
// index's columns (same count, same columns in key order), each ASC with default NULLS LAST (the
// index stores NULL as 0x01 after a present 0x00 → NULLS LAST; an explicit NULLS FIRST does not
// match) and sorting by the column's stored key collation (Skewed/unresolvable → refuse, §12), AND
// the table's PK is fixed-width. The exact-match requirement is load-bearing: a strict prefix of a
// multi-column index would tie-break by the remaining index columns, not the PK.
export function orderSatisfiedByIndex(
  snap: Snapshot,
  table: Table,
  offset: number,
  order: OrderSlot[],
): IndexOrder | null {
  const pkWidth = pkStorageWidth(table);
  if (pkWidth === null) return null;
  for (const idx of table.indexes) {
    if (idx.kind !== "btree") continue; // only an ordered B-tree realizes the column order
    // A PARTIAL index is not used for ORDER-BY skip-sort this slice (indexes.md §9): it holds only its
    // qualifying rows, so walking it would drop rows unless the query implies the predicate — that gate
    // lives only on the access-predicate bound. Stays non-partial (a follow-on); full-scan + sort.
    if (idx.predicate !== undefined) continue;
    // ORDER-BY skip-sort is column-only this slice (matching ORDER BY against an expression index key
    // is a follow-on — indexes.md §5).
    const cols = indexColumnOrdinals(idx);
    if (cols === null) continue;
    if (order.length !== cols.length) continue; // ORDER BY must be EXACTLY the index columns
    let matches = true;
    for (let i = 0; i < order.length; i++) {
      const o = order[i]!;
      if (o.descending || o.nullsFirst) {
        matches = false; // ASC + NULLS LAST only — the order a forward index walk realizes
        break;
      }
      if (o.idx !== offset + cols[i]!) {
        matches = false;
        break;
      }
      const ctx = keyCollationCtx(snap, table.columns[cols[i]!]!);
      if (ctx === null) {
        matches = false; // Skewed / unresolvable — never walked for order (§12)
        break;
      }
      if (ctx.coll === null) {
        if (o.collation !== null) {
          matches = false;
          break;
        }
      } else if (o.collation === null || o.collation.name !== ctx.coll.name) {
        matches = false;
        break;
      }
    }
    if (matches) return { nameKey: idx.name.toLowerCase(), pkWidth };
  }
  return null;
}

// detectGinBound detects a GIN-bounded scan over columns/indexes (gin.md §6): the lowest-named GIN
// index whose array column at offset+ci has a GIN-accelerable conjunct (`col @> const`,
// `col && const`, `const = ANY(col)`, or `col = const`). Factored out so the SELECT planner
// (detectScanBound) and the UPDATE/DELETE scan both use the identical detection — the mutations
// pass their own table's indexes/columns at offset 0.
export function detectGinBound(
  filter: RExpr | null,
  indexes: IndexDef[],
  columns: Column[],
  offset: number,
): GinBound | null {
  if (filter === null) return null;
  for (const idx of indexes) {
    if (idx.kind !== "gin") continue;
    const ci = indexFirstColumn(idx);
    const colGlobal = offset + ci;
    const colType = columns[ci]!.type;
    if (colType.kind !== "array") continue; // a GIN column is always an array (the gate); defensive
    const m = ginMatch(filter, colGlobal);
    if (m !== null) {
      return {
        nameKey: idx.name.toLowerCase(),
        elemType: typeScalar(colType.elem),
        strategy: m.strategy,
        colGlobal,
      };
    }
  }
  return null;
}

// ginMatch finds the first WHERE AND-chain conjunct a GIN index on colGlobal accelerates
// (spec/design/gin.md §6): `col @> Q` (contains), `col && Q` (overlaps), `c = ANY(col)`
// (membership), or `col = Q` (exact array equality) where the query operand is a constant
// (references no column / outer / subquery). @> is asymmetric (the indexed column must be the LEFT
// operand — `Q @> col` is the non-accelerated <@); && and array = are symmetric; = ANY requires the
// column be ANY's array operand and c the scalar. Returns the strategy and the constant query
// operand (the scalar c for "member", the array Q otherwise). Used at plan time (strategy) and exec
// time (recover the operand from plan.filter), so the two agree on the same conjunct by construction.
export function ginMatch(
  filter: RExpr,
  colGlobal: number,
): { strategy: GinStrategy; query: RExpr } | null {
  if (filter.kind === "and") {
    return ginMatch(filter.lhs, colGlobal) ?? ginMatch(filter.rhs, colGlobal);
  }
  if (filter.kind === "arrayFunc" && filter.args.length === 2) {
    const a = filter.args[0]!;
    const b = filter.args[1]!;
    if (filter.func === "contains") {
      if (isColumnRef(a, colGlobal) && rexprIsConstant(b))
        return { strategy: "contains", query: b };
    } else if (filter.func === "overlaps") {
      if (isColumnRef(a, colGlobal) && rexprIsConstant(b))
        return { strategy: "overlaps", query: b };
      if (isColumnRef(b, colGlobal) && rexprIsConstant(a))
        return { strategy: "overlaps", query: a };
    }
  }
  // `col = Q` — exact array equality (gin.md §6). Commutative: the column may be either operand, the
  // constant array Q the other. Recovered operand is Q; ginBoundRows reads it via "equal" (the
  // @>-superset gather + the residual =). <> is NOT matched (only "eq"). When the column is an array,
  // the other constant operand is necessarily an array too (resolve rejects an array/scalar =).
  if (filter.kind === "compare" && filter.op === "eq") {
    if (isColumnRef(filter.lhs, colGlobal) && rexprIsConstant(filter.rhs))
      return { strategy: "equal", query: filter.rhs };
    if (isColumnRef(filter.rhs, colGlobal) && rexprIsConstant(filter.lhs))
      return { strategy: "equal", query: filter.lhs };
  }
  // `c = ANY(col)` — the array spelling of membership (gin.md §6): the GIN column must be ANY's
  // ARRAY operand and c (the scalar lhs) a constant. Only = ANY (not = ALL, not any other
  // comparison/quantifier — those are not a single-term posting gather). The recovered query operand
  // is the scalar c; ginBoundRows reads it via "member".
  if (
    filter.kind === "quantified" &&
    filter.op === "eq" &&
    !filter.all &&
    isColumnRef(filter.array, colGlobal) &&
    rexprIsConstant(filter.lhs)
  ) {
    return { strategy: "member", query: filter.lhs };
  }
  return null;
}

// detectGistBound detects a GiST-bounded scan over columns/indexes (spec/design/gist.md §5): the
// lowest-named GiST index whose range column at offset+ci has a `col && const` / `col @> const`
// conjunct. Factored out so the SELECT planner (detectScanBound) and the UPDATE/DELETE scan share the
// identical detection (the GIN precedent) — the mutations pass their indexes/columns at offset 0.
export function detectGistBound(
  filter: RExpr | null,
  indexes: IndexDef[],
  columns: Column[],
  offset: number,
): GistBound | null {
  if (filter === null) return null;
  for (const idx of indexes) {
    if (idx.kind !== "gist") continue;
    // The planner gather is single-operator: only a single-column GiST index accelerates a
    // `col && Q` / `col @> Q` / `col = Q` conjunct. A multi-column GiST index (an EXCLUDE backing
    // structure, gist.md §7) is probed only by the constraint, never the planner.
    if (idx.keys.length !== 1) continue;
    const ci = indexFirstColumn(idx);
    const colGlobal = offset + ci;
    const colType = columns[ci]!.type;
    if (colType.kind === "range") {
      // range_ops (GX1): a `col && Q` / `col @> Q` conjunct.
      const m = gistMatch(filter, colGlobal);
      if (m !== null) {
        return { nameKey: idx.name.toLowerCase(), strategy: m.strategy, colGlobal };
      }
    } else if (isGistScalarType(colType)) {
      // scalar `=` opclass (GX2): a `col = Q` conjunct over a fixed-width keyable scalar.
      if (gistScalarMatch(filter, colGlobal) !== null) {
        return {
          nameKey: idx.name.toLowerCase(),
          strategy: "equal",
          colGlobal,
          scalarType: typeScalar(colType),
        };
      }
    }
  }
  return null;
}

// gistScalarMatch finds the first WHERE AND-chain conjunct a GiST scalar `=` opclass on colGlobal
// accelerates (spec/design/gist.md §6): `col = Q` where Q is a constant (re-evaluable per scan).
// Equality is commutative (the column may be either operand). <> and the inequalities are not
// accelerated (the `=` opclass has only the equal strategy). Returns the constant operand — used at
// plan time (existence) and exec time (recover from plan.filter).
export function gistScalarMatch(filter: RExpr, colGlobal: number): { query: RExpr } | null {
  if (filter.kind === "and") {
    return gistScalarMatch(filter.lhs, colGlobal) ?? gistScalarMatch(filter.rhs, colGlobal);
  }
  if (filter.kind === "compare" && filter.op === "eq") {
    if (isColumnRef(filter.lhs, colGlobal) && rexprIsConstant(filter.rhs))
      return { query: filter.rhs };
    if (isColumnRef(filter.rhs, colGlobal) && rexprIsConstant(filter.lhs))
      return { query: filter.lhs };
  }
  return null;
}

// gistQueryOperand recovers a GiST bound's constant query operand from the live filter at exec time —
// gistMatch for range_ops (&&/@>), gistScalarMatch for the scalar `=` opclass. Centralizes the
// strategy dispatch so every scan site (SELECT / UPDATE / DELETE) recovers the operand uniformly.
export function gistQueryOperand(filter: RExpr, gb: GistBound): RExpr | null {
  if (gb.strategy === "equal") return gistScalarMatch(filter, gb.colGlobal)?.query ?? null;
  return gistMatch(filter, gb.colGlobal)?.query ?? null;
}

// gistMatch finds the first WHERE AND-chain conjunct a GiST range_ops index on colGlobal accelerates
// (spec/design/gist.md §5): `col && Q` (overlap — symmetric) or `col @> Q` (contains — asymmetric,
// the column must be the LEFT operand; `Q @> col` is the non-accelerated <@). Q must be a constant.
// The other range operators stay full-scan this slice. Returns the strategy and the constant query
// operand — used at plan time (strategy) and exec time (recover from plan.filter).
export function gistMatch(
  filter: RExpr,
  colGlobal: number,
): { strategy: GistStrategy; query: RExpr } | null {
  if (filter.kind === "and") {
    return gistMatch(filter.lhs, colGlobal) ?? gistMatch(filter.rhs, colGlobal);
  }
  if (filter.kind === "rangeOp" && filter.args.length === 2) {
    const a = filter.args[0]!;
    const b = filter.args[1]!;
    if (filter.op === "overlaps") {
      // && — symmetric in its operands.
      if (isColumnRef(a, colGlobal) && rexprIsConstant(b))
        return { strategy: "overlaps", query: b };
      if (isColumnRef(b, colGlobal) && rexprIsConstant(a))
        return { strategy: "overlaps", query: a };
    } else if (filter.op === "contains") {
      // @> — the indexed column must be the container (LEFT).
      if (isColumnRef(a, colGlobal) && rexprIsConstant(b))
        return { strategy: "contains", query: b };
    }
  }
  return null;
}

// isColumnRef reports whether e is a reference to the column at global scope index colGlobal.
export function isColumnRef(e: RExpr, colGlobal: number): boolean {
  return e.kind === "column" && e.index === colGlobal;
}

// rexprIsConstant reports whether e is evaluable without a current/outer row (so its value is the
// same for every scanned row — computable once). False for any column, correlated outer column, or
// subquery; true for literals, params, and pure operations over them. Used to admit a GIN query
// operand Q (spec/design/gin.md §6: a constant query only this slice).
export function rexprIsConstant(e: RExpr): boolean {
  switch (e.kind) {
    case "column":
    case "outerColumn":
    case "subquery":
      return false;
    case "dateClock":
      // Row-independent but EXECUTION-scoped (the statement clock + session zone) —
      // conservatively not a "constant", so no plan-time consumer ever evaluates it without a
      // live statement environment (date.md §6).
      return false;
    case "row":
      return e.fields.every(rexprIsConstant);
    case "array":
      return e.elements.every(rexprIsConstant);
    case "field":
      return rexprIsConstant(e.base);
    case "cast":
    case "arrayCast":
    case "neg":
    case "not":
    case "isNull":
    case "isJson":
    case "jsonCtor":
      return rexprIsConstant(e.operand);
    case "arith":
    case "compare":
    case "and":
    case "or":
    case "distinct":
    case "like":
    case "regex":
      return rexprIsConstant(e.lhs) && rexprIsConstant(e.rhs);
    case "jsonGet":
    case "jsonHasKey":
    case "jsonDelete":
      return rexprIsConstant(e.base) && rexprIsConstant(e.arg);
    case "jsonContains":
    case "jsonConcat":
      return rexprIsConstant(e.a) && rexprIsConstant(e.b);
    case "casing":
      return rexprIsConstant(e.arg);
    case "atTimeZone":
      return rexprIsConstant(e.zone) && rexprIsConstant(e.value);
    case "dateTrunc":
      return (
        rexprIsConstant(e.unit) &&
        rexprIsConstant(e.value) &&
        (e.zone === null || rexprIsConstant(e.zone))
      );
    case "extract":
      return rexprIsConstant(e.value);
    case "dateConvert":
      return rexprIsConstant(e.inner);
    case "case":
      return (
        e.arms.every((a) => rexprIsConstant(a.cond) && rexprIsConstant(a.result)) &&
        rexprIsConstant(e.els)
      );
    case "greatestLeast":
    case "coalesce":
    case "scalarFunc":
    case "arrayFunc":
    case "regexFunc":
    case "rangeFunc":
    case "rangeCtor":
    case "rangeOp":
    case "rangeSetOp":
    case "variadic":
    case "jsonBuild":
    case "jsonSetInsert":
    case "jsonObjectFromArrays":
    case "jsonPathFn":
    case "jsonSqlFn":
      return e.args.every(rexprIsConstant);
    case "inValues":
      return rexprIsConstant(e.lhs);
    case "quantified":
      return rexprIsConstant(e.lhs) && rexprIsConstant(e.array);
    default:
      // Every leaf constant (constInt/constArray/param/…) is constant; a subscript / any other node
      // is treated conservatively as non-constant (no GIN accel; the residual filter still applies).
      return e.kind === "param" || e.kind.startsWith("const");
  }
}

// ResolvedKey is one key element of an index resolved for a statement's maintenance
// (spec/design/indexes.md §4): a plain column (by ordinal — encoded from columns[ord].type +
// colls[ord]), or a resolved expression carrying its RExpr, its encoding Type (the result type
// from resolvedToKeyType), and its collation (evaluated against each row, unmetered, to yield the
// key value). Built once per statement by Engine.resolveIndex from an IndexDef.
export type ResolvedKey =
  | { kind: "column"; column: number }
  | { kind: "expr"; expr: RExpr; type: Type; coll: Collation | null };

// ResolvedIndex is an index resolved for one statement's maintenance: the def's identity
// (name / unique / kind) plus its per-element ResolvedKeys. Owned (no borrow of the catalog) so the
// write paths can mutate stores while holding it. GIN/GiST indexes are always plain-column (this
// slice), so their entry builders read the ordinals back via resolvedIndexColumnOrdinals.
export type ResolvedIndex = {
  name: string;
  unique: boolean;
  kind: "btree" | "gin" | "gist";
  keys: ResolvedKey[];
  // predicate is a PARTIAL index's resolved WHERE predicate (spec/design/indexes.md §9): evaluated
  // against each row (unmetered, like a key expression), a row is indexed / constrained ONLY when it
  // is TRUE. undefined for an ordinary (full) index — every row is indexed.
  predicate?: RExpr;
};

// resolvedIndexColumnOrdinals are the plain-column ordinals of a GIN/GiST index (always all columns,
// this slice) — throws if a resolved key is an expression (structurally impossible for GIN/GiST).
export function resolvedIndexColumnOrdinals(rindex: ResolvedIndex): number[] {
  return rindex.keys.map((k) => {
    if (k.kind !== "column") throw new Error("GIN/GiST index keys are plain columns");
    return k.column;
  });
}

// resolvedToKeyType is the order-preserving key Type an index-expression result encodes under, or
// null when the result type is not key-encodable (a composite / json / unknown result — 0A000 at
// CREATE INDEX). Every scalar is keyable (encoding.md §2); a keyable-scalar-element array/range is too.
export function resolvedToKeyType(rt: ResolvedType): Type | null {
  switch (rt.kind) {
    case "int":
    case "float":
      return scalarT(rt.ty);
    case "bool":
      return scalarT("boolean");
    case "text":
      return scalarT("text");
    case "decimal":
      return scalarT("decimal");
    case "bytea":
      return scalarT("bytea");
    case "uuid":
      return scalarT("uuid");
    case "timestamp":
      return scalarT("timestamp");
    case "timestamptz":
      return scalarT("timestamptz");
    case "interval":
      return scalarT("interval");
    case "date":
      return scalarT("date");
    case "array": {
      const et = resolvedToKeyType(rt.elem);
      if (et === null || !typeIsKeyableScalar(et)) return null; // a composite-element array is not keyable
      return { kind: "array", elem: et };
    }
    case "range": {
      const et = resolvedToKeyType(rt.elem);
      if (et === null) return null;
      return { kind: "range", elem: et };
    }
    default: // null, composite, json, jsonb, jsonpath
      return null;
  }
}

// indexKeySlot returns one key element's (value, encoding type, collation) for a row: the column
// value (a column key) or the evaluated expression (an expression key — unmetered, env for the
// immutable eval). Index maintenance is unmetered (cost.md §3), so a throwaway Meter absorbs the
// eval charge.
export function indexKeySlot(
  key: ResolvedKey,
  columns: Column[],
  colls: (Collation | null)[],
  row: Row,
  env: EvalEnv,
): { value: Value; type: Type; coll: Collation | null } {
  if (key.kind === "column") {
    return { value: row[key.column]!, type: columns[key.column]!.type, coll: colls[key.column]! };
  }
  return { value: evalExpr(key.expr, row, env, new Meter()), type: key.type, coll: key.coll };
}

// indexEntryKey builds a secondary-index entry key (spec/design/indexes.md §3): each key element as
// the encoding.md §2.2 nullable slot — 0x00 + the type's bare order-preserving key bytes when
// present, the lone 0x01 for NULL (always tagged, even for a NOT NULL column) — then the row's
// storage key as the suffix. A column key's value is always resident (never unfetched: an indexable
// fixed-width type never spills, and a large text/bytea would over-RECORD_MAX the entry, rejected
// 0A000 at insert). An expression key evaluates against the row (§4); a referenced spilled value
// faults in through the evaluator's Unfetched backstop.
export function indexEntryKey(
  columns: Column[],
  colls: (Collation | null)[],
  rindex: ResolvedIndex,
  storageKey: Uint8Array,
  row: Row,
  env: EvalEnv,
): Uint8Array {
  const parts: Uint8Array[] = [];
  for (const key of rindex.keys) {
    const { value, type, coll } = indexKeySlot(key, columns, colls, row, env);
    if (value.kind === "null") {
      parts.push(Uint8Array.of(0x01));
    } else {
      // present tag, then the type's order-preserving key (range-aware §2.11, collated-text-aware §2.12)
      parts.push(Uint8Array.of(0x00), encodeTypedKey(type, value, coll));
    }
  }
  parts.push(storageKey);
  return concatBytes(parts);
}

// indexRowQualifies reports whether a row is indexed by rindex (spec/design/indexes.md §9): always
// for an ordinary index, and for a PARTIAL index iff its WHERE predicate evaluates to TRUE (the 3VL
// WHERE rule — FALSE and NULL are excluded). The predicate eval is unmetered maintenance work (like a
// key expression's — cost.md §3), so a throwaway Meter absorbs its charge.
export function indexRowQualifies(rindex: ResolvedIndex, row: Row, env: EvalEnv): boolean {
  if (rindex.predicate === undefined) return true;
  return isTrue(evalExpr(rindex.predicate, row, env, new Meter()));
}

// indexEntryKeys returns the index entries a row contributes (spec/design/gin.md §4/§5): exactly
// one for an ordered (B-tree) index — the §3 nullable-slot entry key — or one per DISTINCT non-NULL
// element for a GIN index. Every write path (build, INSERT, DELETE, UPDATE) treats an index
// uniformly as "a row maps to a set of entries." A PARTIAL index contributes the EMPTY set for a row
// whose predicate is not TRUE (spec/design/indexes.md §9), which is what makes INSERT/DELETE/UPDATE
// maintenance uniform (the UPDATE old-set/new-set diff handles a row entering/leaving/moving for
// free). env evaluates any expression key element or the partial predicate (B-tree only — GIN/GiST
// are plain-column, this slice).
export function indexEntryKeys(
  columns: Column[],
  colls: (Collation | null)[],
  rindex: ResolvedIndex,
  storageKey: Uint8Array,
  row: Row,
  env: EvalEnv,
): Uint8Array[] {
  if (!indexRowQualifies(rindex, row, env)) return []; // partial index: a non-qualifying row → no entry
  if (rindex.kind === "gin")
    return ginEntries(columns, resolvedIndexColumnOrdinals(rindex), storageKey, row);
  if (rindex.kind === "gist")
    return gistEntries(columns, resolvedIndexColumnOrdinals(rindex), storageKey, row);
  return [indexEntryKey(columns, colls, rindex, storageKey, row, env)];
}

// indexEntryKeysColumns returns the entry keys for a COLUMN-ONLY index, WITHOUT an eval env
// (spec/design/indexes.md §4) — the collation-realign rebuild path, which runs on a Snapshot with no
// Engine to evaluate an expression key. An expression index is C-collated (its keys never change on
// a collation upgrade — indexes.md §1), so it is rebuilt at the Engine level instead; this asserts
// the index is plain-column.
export function indexEntryKeysColumns(
  columns: Column[],
  colls: (Collation | null)[],
  def: IndexDef,
  storageKey: Uint8Array,
  row: Row,
): Uint8Array[] {
  const cols = indexColumnOrdinals(def);
  if (cols === null) throw new Error("indexEntryKeysColumns called on an expression index");
  if (def.kind === "gin") return ginEntries(columns, cols, storageKey, row);
  if (def.kind === "gist") return gistEntries(columns, cols, storageKey, row);
  const parts: Uint8Array[] = [];
  for (const ci of cols) {
    const v = row[ci]!;
    if (v.kind === "null") parts.push(Uint8Array.of(0x01));
    else parts.push(Uint8Array.of(0x00), encodeTypedKey(columns[ci]!.type, v, colls[ci]!));
  }
  parts.push(storageKey);
  return [concatBytes(parts)];
}

// gistOpclassFor is the opclass for a GiST index over a column of type colType (gist.md §5/§6):
// range_ops for a range column (its element subtype as a ColType — the codec/comparator key for the
// R-tree bounds, §4.1), the scalar `=` opclass otherwise (a fixed-width keyable scalar, the CREATE
// INDEX gate). Computed consistently in gistEntries, the resident-tree rebuild, and the serializer.
export function gistOpclassFor(colType: Type): GistOpclass {
  if (colType.kind === "range") {
    return gistRangeOpclass({ kind: "scalar", scalar: typeScalar(colType.elem) });
  }
  return GIST_SCALAR_OPCLASS;
}

// gistEntries builds a GiST index's entry keys for one row (spec/design/gist.md §4.1/§7): exactly one
// leaf key, the per-column component bounds concatenated then ‖ storage_key (the GIN term ‖ skey
// pattern), so all existing index maintenance (insert/update/delete) reuses it unchanged. A
// single-column GX1/GX2 index has one component; an EXCLUDE backing index one per WITH column. A NULL
// in ANY indexed column produces no entry (the §7 exclusion NULL rule — a row with a NULL excluded
// column never conflicts and is left out of the tree). The empty range is a real value and IS indexed.
export function gistEntries(
  columns: Column[],
  cols: number[],
  storageKey: Uint8Array,
  row: Row,
): Uint8Array[] {
  const inputs: GistLeafInput[] = [];
  for (const ci of cols) {
    const colType = columns[ci]!.type;
    const v = row[ci]!;
    if (v.kind === "null") return []; // any NULL excluded column → row not indexed (NULL rule)
    if (colType.kind === "range" && v.kind === "range") {
      inputs.push({ range: { kind: "scalar", scalar: typeScalar(colType.elem) }, value: v });
    } else if (colType.kind === "range") {
      return []; // unreachable: a range column holds a range or NULL (handled above)
    } else {
      // scalar `=` opclass: the column is a FIXED-WIDTH keyable (the gate), so the key encoding is
      // collation-free and infallible.
      inputs.push({ scalarKey: encodeKeyValue(typeScalar(colType), v, null) });
    }
  }
  return [gistLeafKeyMulti(inputs, storageKey)];
}

// exclusionProbeQuery builds a row's EXCLUDE conjunction probe (spec/design/gist.md §7): one GiST
// query operand + strategy per excluded column, in the backing index's column order. Returns null
// (the row is EXEMPT, never conflicts) when the NULL rule fires (any excluded column is NULL) or when
// a && element holds the empty range (empty && anything is FALSE, so the conjunction can never be
// TRUE — this also sidesteps the empty-range overlap-descend trap, gist.md §5). The query is fed to
// the resident GiST tree's search, whose leaf recheck IS the full conjunction, so a hit is a conflict.
export function exclusionProbeQuery(
  columns: Column[],
  exc: ExclusionConstraint,
  row: Row,
): { query: GistQuery[]; strats: GistStrategy[] } | null {
  const query: GistQuery[] = [];
  const strats: GistStrategy[] = [];
  for (const el of exc.elements) {
    const v = row[el.column]!;
    if (v.kind === "null") return null; // NULL rule: exempt
    if (el.op === "overlaps") {
      if (v.kind !== "range" || v.empty) return null; // empty && anything is FALSE → exempt
      query.push({ rng: v });
      strats.push("overlaps");
    } else {
      const k = encodeKeyValue(typeScalar(columns[el.column]!.type), v, null);
      query.push({ skey: k });
      strats.push("equal");
    }
  }
  return { query, strats };
}

// exclusionPairConflicts reports whether the (expr_i op_i) conjunction holds between two rows
// (spec/design/gist.md §7). Used for the in-batch new-row-vs-new-row check (the resident GiST tree
// holds only stored rows). A NULL in any excluded column of either row, or an empty range under &&
// (rangeOverlaps of an empty range is FALSE), makes that element not-TRUE → no conflict. Returns true
// only when EVERY element is definitely TRUE.
export function exclusionPairConflicts(
  columns: Column[],
  exc: ExclusionConstraint,
  a: Row,
  b: Row,
): boolean {
  for (const el of exc.elements) {
    const va = a[el.column]!;
    const vb = b[el.column]!;
    if (va.kind === "null" || vb.kind === "null") return false;
    let ok: boolean;
    if (el.op === "overlaps") {
      ok = va.kind === "range" && vb.kind === "range" && rangeOverlaps(va, vb);
    } else {
      const ka = encodeKeyValue(typeScalar(columns[el.column]!.type), va, null);
      const kb = encodeKeyValue(typeScalar(columns[el.column]!.type), vb, null);
      ok = bytesEq(ka, kb);
    }
    if (!ok) return false;
  }
  return true;
}

// ginEntries builds a GIN index's entry keys for one row (spec/design/gin.md §4): one entry per
// DISTINCT non-NULL array element — encode(element) ‖ storage_key, NO presence tag (a term is never
// NULL) and an empty payload. A NULL array column value and an empty array yield no entries (so
// they appear in no posting list). Returned sorted by term (= encoded-byte order for the integer
// element types). This slice: a single integer-element array column.
// isGinElementType reports whether elem is an element type a GIN (array_ops) index admits — the
// integers, boolean, uuid, date, timestamp, timestamptz (spec/design/gin.md §3): a GIN term IS the
// element's order-preserving key encoding (§4) and a term carries no length/terminator framing, so
// only the FIXED-WIDTH keyables qualify. The variable-width keyables (text, bytea, decimal) — valid
// ordered-index / PK keys — are 0A000 here, as is float. interval is fixed-width keyable (its 16-byte
// span key landed, encoding.md §2.10) but its GIN element support is a separate follow-on slice
// (gin.md §3/§10), so it is not yet admitted here.
export function isGinElementType(elem: Type): boolean {
  return (
    typeIsInteger(elem) ||
    typeIsBoolean(elem) ||
    typeIsUuid(elem) ||
    typeIsTimestamp(elem) ||
    typeIsTimestamptz(elem) ||
    typeIsDate(elem)
  );
}

// Resolve the EXCLUDE access method, element columns, duplicate-column rule, and operator/opclass
// pairing once for both CREATE TABLE and ALTER TABLE (spec/design/gist.md §7).
function resolveExclusionDefinition(
  table: Table,
  def: ExcludeDef,
): { columns: number[]; elements: ExclusionElement[] } {
  if (def.using !== null && def.using.toLowerCase() !== "gist")
    throw engineError(
      "undefined_object",
      `access method ${def.using} does not support exclusion constraints`,
    );
  const columns: number[] = [];
  const elements: ExclusionElement[] = [];
  for (const el of def.elements) {
    const column = columnIndex(table, el.column);
    if (column < 0)
      throw engineError("undefined_column", `column ${el.column} named in key does not exist`);
    if (columns.includes(column))
      throw engineError(
        "duplicate_column",
        `column ${el.column} appears twice in exclusion constraint`,
      );
    const ty = table.columns[column]!.type;
    let op: ExclusionOp;
    if (el.op === "&&") {
      if (ty.kind !== "range")
        throw engineError(
          "undefined_object",
          `data type ${typeCanonicalName(ty)} has no default operator class for access method gist that accepts operator &&`,
        );
      op = "overlaps";
    } else if (el.op === "=") {
      if (isGistScalarType(ty)) op = "equal";
      else if (isGistDeferredScalarType(ty))
        throw engineError(
          "feature_not_supported",
          `an exclusion constraint with = over ${typeCanonicalName(ty)} is not supported yet`,
        );
      else
        throw engineError(
          "undefined_object",
          `data type ${typeCanonicalName(ty)} has no default operator class for access method gist`,
        );
    } else
      throw engineError(
        "feature_not_supported",
        `exclusion constraint operator ${el.op} is not supported yet`,
      );
    columns.push(column);
    elements.push({ column, op });
  }
  return { columns, elements };
}

// isGistScalarType reports whether the scalar `=` GiST opclass admits this column type (gist.md §6):
// the FIXED-WIDTH keyables — integers, boolean, uuid, date, timestamp, timestamptz — whose bound is
// [min,max] over the order-preserving key encoding, compared as raw bytes (no decode, no collation).
// Exactly isGinElementType's set, kept a separate predicate so the two surfaces evolve independently.
export function isGistScalarType(ty: Type): boolean {
  return (
    typeIsInteger(ty) ||
    typeIsBoolean(ty) ||
    typeIsUuid(ty) ||
    typeIsTimestamp(ty) ||
    typeIsTimestamptz(ty) ||
    typeIsDate(ty)
  );
}

// isGistDeferredScalarType reports a keyable scalar the GiST scalar `=` opclass will eventually admit
// but defers this slice (gist.md §6/§11): the VARIABLE-width / collation-sensitive keyables — text,
// bytea, decimal, interval. A column of one of these is 0A000 ("not supported yet"), not 42704.
export function isGistDeferredScalarType(ty: Type): boolean {
  return typeIsText(ty) || typeIsBytea(ty) || typeIsDecimal(ty) || typeIsInterval(ty);
}

export function ginEntries(
  columns: Column[],
  cols: number[],
  storageKey: Uint8Array,
  row: Row,
): Uint8Array[] {
  const ci = cols[0]!;
  const colType = columns[ci]!.type;
  if (colType.kind !== "array")
    throw new Error("a GIN index column is an array (CREATE INDEX gate)");
  const elemTy = typeScalar(colType.elem);
  const v = row[ci]!;
  if (v.kind !== "array") return [];
  // Dedup by the encoded term (the encoding is a bijection: byte-dedup == value-dedup, byte-sort ==
  // value-sort) generically over every admitted element type.
  const seen = new Set<string>();
  const terms: Uint8Array[] = [];
  for (const el of v.elements) {
    if (el.kind === "null") continue; // a NULL element carries no term; a non-keyable element is impossible
    // a GIN element is fixed-width (isGinElementType excludes text), so it never collates.
    const term = encodeKeyValue(elemTy, el, null);
    const k = byteKey(term);
    if (!seen.has(k)) {
      seen.add(k);
      terms.push(term);
    }
  }
  terms.sort(cmpBytes);
  return terms.map((term) => {
    const out = new Uint8Array(term.length + storageKey.length);
    out.set(term, 0);
    out.set(storageKey, term.length);
    return out;
  });
}

// cmpBytes compares two byte strings lexicographically (-1/0/1), the on-disk storage-key order.
export function cmpBytes(a: Uint8Array, b: Uint8Array): number {
  const n = Math.min(a.length, b.length);
  for (let i = 0; i < n; i++) {
    if (a[i]! !== b[i]!) return a[i]! - b[i]!;
  }
  return a.length - b.length;
}

// byteKey is a stable string key for a (small) byte string — used to dedup / count storage keys in
// the GIN posting combine. Storage keys are short (an encoded PK or rowid), so per-char is fine.
export function byteKey(a: Uint8Array): string {
  let s = "";
  for (let i = 0; i < a.length; i++) s += String.fromCharCode(a[i]!);
  return s;
}

// intersectPostings returns the storage keys present in EVERY posting list (the @> mode-ALL
// combine), sorted ascending. Each posting list holds distinct keys (one (term,row) entry per row),
// so a per-list count == the number of lists means the key is in all of them.
export function intersectPostings(postings: Uint8Array[][]): Uint8Array[] {
  if (postings.length === 0) return [];
  const count = new Map<string, number>();
  for (const list of postings) {
    for (const k of list) {
      const key = byteKey(k);
      count.set(key, (count.get(key) ?? 0) + 1);
    }
  }
  const need = postings.length;
  const out: Uint8Array[] = [];
  for (const k of postings[0]!) {
    if (count.get(byteKey(k)) === need) out.push(k);
  }
  out.sort(cmpBytes);
  return out;
}

// unionPostings returns the storage keys present in ANY posting list (the && mode-ANY combine),
// deduplicated and sorted ascending.
export function unionPostings(postings: Uint8Array[][]): Uint8Array[] {
  const seen = new Set<string>();
  const out: Uint8Array[] = [];
  for (const list of postings) {
    for (const k of list) {
      const key = byteKey(k);
      if (!seen.has(key)) {
        seen.add(key);
        out.push(k);
      }
    }
  }
  out.sort(cmpBytes);
  return out;
}

// bytesDiff returns the entries in a that are not in b (set difference over byte strings),
// preserving a's order — the UPDATE symmetric-difference for GIN / B-tree maintenance (gin.md §5).
export function bytesDiff(a: Uint8Array[], b: Uint8Array[]): Uint8Array[] {
  return a.filter((x) => !b.some((y) => bytesEq(x, y)));
}

// encodePkKey is a row's PRIMARY-KEY STORAGE KEY (spec/design/encoding.md §2.3): the
// concatenation of the members' bare encodings in key order — every keyable type is fixed-width,
// so the concatenation is self-delimiting and byte comparison equals the tuple's logical order.
// Shared by the INSERT duplicate check and the ON CONFLICT arbiter probe (upsert.md §3); a PK
// column is NOT NULL, so there is no presence tag.
export function encodePkKey(
  table: Table,
  pk: number[],
  colls: (Collation | null)[],
  row: Row,
): Uint8Array {
  const parts: Uint8Array[] = [];
  for (const i of pk) {
    const pkv = row[i]!; // non-null: a PK member is NOT NULL
    if (pkv.kind === "uuid") {
      parts.push(pkv.bytes.slice());
    } else if (pkv.kind === "bool") {
      parts.push(encodeBool(pkv.value));
    } else if (pkv.kind === "int") {
      parts.push(encodeInt(typeScalar(table.columns[i]!.type), pkv.int));
    } else if (pkv.kind === "timestamp" || pkv.kind === "timestamptz") {
      parts.push(encodeInt(typeScalar(table.columns[i]!.type), pkv.micros));
    } else if (pkv.kind === "date") {
      parts.push(encodeInt(typeScalar(table.columns[i]!.type), pkv.days));
    } else if (pkv.kind === "text") {
      // text: C terminated-escape (§2.4) or the collated UCA sort key (§2.12).
      parts.push(collatedTextKey(colls[i]!, pkv.text));
    } else if (pkv.kind === "bytea") {
      parts.push(encodeTerminated(pkv.bytes));
    } else if (pkv.kind === "decimal") {
      parts.push(pkv.dec.encodeKey());
    } else if (pkv.kind === "interval") {
      parts.push(intervalEncodeKey(pkv.iv));
    } else if (pkv.kind === "f64") {
      // float: the fixed-width float-order-preserving key (encoding.md §2.8) — NOT the int codec.
      parts.push(encodeFloat64Key(pkv.value));
    } else if (pkv.kind === "f32") {
      parts.push(encodeFloat32Key(pkv.value));
    } else if (pkv.kind === "range") {
      // the recursive range-bounds container key (encoding.md §2.11, the first container key)
      parts.push(encodeTypedKey(table.columns[i]!.type, pkv, null));
    } else if (pkv.kind === "array") {
      // the recursive array-elements-terminated container key (encoding.md §2.14, second container key)
      parts.push(encodeTypedKey(table.columns[i]!.type, pkv, null));
    } else {
      throw engineError(
        "data_corrupted",
        "a primary key must be an integer, boolean, uuid, text, bytea, decimal, interval, float, range, array, or timestamp value",
      );
    }
  }
  const total = parts.reduce((acc, b) => acc + b.length, 0);
  const key = new Uint8Array(total);
  let off = 0;
  for (const b of parts) {
    key.set(b, off);
    off += b.length;
  }
  return key;
}

// Arbiter is which uniqueness constraint an ON CONFLICT arbitrates (spec/design/upsert.md §2):
// the primary key (isPK), or a unique index by position in table.indexes (indexPos).
export type Arbiter = { isPK: true } | { isPK: false; indexPos: number };

// ConflictPlan is a resolved ON CONFLICT clause (spec/design/upsert.md), built by resolveOnConflict.
export type ConflictPlan = {
  // arb is the arbiter constraint; null = no target (legal only with DO NOTHING — any uniqueness
  // conflict is then skipped).
  arb: Arbiter | null;
  doUpdate: boolean;
  assignments: AssignPlan[];
  filter: RExpr | null;
};

// resolveArbiter resolves an ON CONFLICT target into an Arbiter (spec/design/upsert.md §2): a
// column list is matched as an order-independent SET against a unique index / the primary key (no
// match → 42P10); ON CONSTRAINT name names a unique index or the synthesized <table>_pkey (miss →
// 42704). A null target → null arbiter (legal only with DO NOTHING).
export function resolveArbiter(table: Table, target: ConflictTarget | null): Arbiter | null {
  if (target === null) return null;
  const pk = pkIndices(table);
  if (target.kind === "columns") {
    const want = new Set<number>();
    for (const c of target.columns) {
      const idx = columnIndex(table, c);
      if (idx < 0) throw engineError("undefined_column", "column does not exist: " + c);
      want.add(idx);
    }
    if (pk.length > 0 && sameIntSet(pk, want)) return { isPK: true };
    for (let i = 0; i < table.indexes.length; i++) {
      const def = table.indexes[i]!;
      // A conflict-target COLUMN list matches only a plain-column unique index (an expression unique
      // index is arbitrated by ON CONSTRAINT <name> — upsert.md §3). A PARTIAL unique index is NOT
      // matched by a bare column list (PostgreSQL requires the predicate to be restated — a deferred
      // upsert follow-on, indexes.md §9): a column target that only a partial index covers reports
      // "no matching arbiter", agreeing with PG.
      const cols = indexColumnOrdinals(def);
      if (def.unique && def.predicate === undefined && cols !== null && sameIntSet(cols, want))
        return { isPK: false, indexPos: i };
    }
    throw engineError(
      "invalid_column_reference",
      "there is no unique or exclusion constraint matching the ON CONFLICT specification",
    );
  }
  const pkey = table.name.toLowerCase() + "_pkey";
  if (pk.length > 0 && target.name.toLowerCase() === pkey) return { isPK: true };
  for (let i = 0; i < table.indexes.length; i++) {
    const def = table.indexes[i]!;
    if (def.unique && def.name.toLowerCase() === target.name.toLowerCase())
      return { isPK: false, indexPos: i };
  }
  throw engineError(
    "undefined_object",
    `constraint ${target.name} for table ${table.name} does not exist`,
  );
}

// sameIntSet reports whether the array's values (as a set) equal the given set.
export function sameIntSet(arr: number[], set: Set<number>): boolean {
  const seen = new Set(arr);
  if (seen.size !== set.size) return false;
  for (const v of seen) if (!set.has(v)) return false;
  return true;
}

// arbiterKey is the arbiter key of a candidate row (spec/design/upsert.md §3): the storage key for
// a PK arbiter (never NULL), or the unique-index prefix for an index arbiter (null when a nullable
// arbiter column is NULL — NULLS DISTINCT, so the row never conflicts). An expression-index arbiter
// evaluates its key expressions through env (Engine.arbiterProbeKey builds it).
export function arbiterKey(
  arb: Arbiter,
  table: Table,
  pk: number[],
  colls: (Collation | null)[],
  rindexes: ResolvedIndex[],
  row: Row,
  env: EvalEnv,
): Uint8Array | null {
  if (arb.isPK) return encodePkKey(table, pk, colls, row);
  return indexPrefixKey(table.columns, colls, rindexes[arb.indexPos]!, row, env);
}

// indexPrefixKey builds a row's UNIQUENESS PROBE KEY for one unique index
// (spec/design/indexes.md §8): the §3 entry key's slot prefix — without the storage-key
// suffix — or null when any component is NULL (NULLS DISTINCT: such a tuple never
// conflicts). Two rows conflict iff they yield the same non-null prefix. An expression key's value
// enters the probe exactly like a column value (evaluated against the row through env).
export function indexPrefixKey(
  columns: Column[],
  colls: (Collation | null)[],
  rindex: ResolvedIndex,
  row: Row,
  env: EvalEnv,
): Uint8Array | null {
  // A partial index constrains only its qualifying rows (indexes.md §9): a non-qualifying row is
  // exempt from uniqueness, exactly like a NULL-bearing prefix (returns null).
  if (!indexRowQualifies(rindex, row, env)) return null;
  const parts: Uint8Array[] = [];
  for (const key of rindex.keys) {
    const { value, type, coll } = indexKeySlot(key, columns, colls, row, env);
    if (value.kind === "null") return null;
    // present tag, then the type's order-preserving key (range-aware §2.11, collated-text-aware §2.12)
    parts.push(Uint8Array.of(0x00), encodeTypedKey(type, value, coll));
  }
  return concatBytes(parts);
}

// uniqueProbeBound is the half-open byte range [prefix, byte-successor(prefix)) — every
// index entry whose slot prefix equals prefix (the suffix makes tree keys unique, so
// equal prefixes sit adjacent). The uniqueness probes range over it (indexes.md §8).
export function uniqueProbeBound(prefix: Uint8Array): KeyBound {
  return { lo: prefix, loInc: true, hi: prefixSuccessor(prefix), hiInc: false };
}

// bytesEq reports byte equality of two keys.
export function bytesEq(a: Uint8Array, b: Uint8Array): boolean {
  return compareBytes(a, b) === 0;
}

// encodeKeyValue is the order-preserving key bytes for one keyable value (encoding.md §2),
// matching the PK / index encoders. `value` is non-NULL and of a keyable type (a foreign-key
// column always is — its type equals a PK/UNIQUE parent column, CREATE TABLE §6.2).
// collatedTextKey is the order-preserving key body for a text value (encoding.md §2.12): the
// collation's UCA sort key when coll is non-null (a non-C collated column), else the C
// text-terminated-escape body (§2.4). The sort key throws (0A000) on a code point the collation does
// not map — propagated, so a collated INSERT of an unmapped string aborts the write.
export function collatedTextKey(coll: Collation | null, s: string): Uint8Array {
  return coll !== null ? collationSortKey(coll, s) : encodeTerminated(SQL_BYTE_ENCODER.encode(s));
}

export function encodeKeyValue(ty: ScalarType, value: Value, coll: Collation | null): Uint8Array {
  if (value.kind === "int") return encodeInt(ty, value.int);
  if (value.kind === "bool") return encodeBool(value.value);
  if (value.kind === "uuid") return value.bytes.slice();
  if (value.kind === "timestamp" || value.kind === "timestamptz")
    return encodeInt(ty, value.micros);
  if (value.kind === "date") return encodeInt(ty, value.days);
  if (value.kind === "text") return collatedTextKey(coll, value.text);
  if (value.kind === "bytea") return encodeTerminated(value.bytes);
  if (value.kind === "decimal") return value.dec.encodeKey();
  if (value.kind === "interval") return intervalEncodeKey(value.iv);
  if (value.kind === "f64") return encodeFloat64Key(value.value);
  if (value.kind === "f32") return encodeFloat32Key(value.value);
  throw new Error("a foreign-key column is a key-encodable type (CREATE TABLE §6.2 gate)");
}

// encodeTypedKey is the order-preserving key bytes for one keyable value given its column Type — the
// range-aware encoder threaded through every key path (PK, index entry/prefix, FK probe). A range
// recurses into the range-bounds container codec (encoding.md §2.11), pulling its element scalar from
// the column type; every other keyable value ignores the wrapper and dispatches on its scalar via
// encodeKeyValue. value is non-NULL (callers handle the NULL slot tag), and a range column always
// holds a range value, so the scalar arm never sees a range type. coll selects a text column's key
// form (§2.12); it never applies to a range element (no range subtype is text).
export function encodeTypedKey(ty: Type, value: Value, coll: Collation | null): Uint8Array {
  if (value.kind === "range") {
    if (ty.kind !== "range") {
      throw new Error("a range key value has a range column type");
    }
    return encodeRangeKey(typeScalar(ty.elem), value);
  }
  if (value.kind === "array") {
    if (ty.kind !== "array") {
      throw new Error("an array key value has an array column type");
    }
    return encodeArrayKey(typeScalar(ty.elem), value);
  }
  return encodeKeyValue(typeScalar(ty), value, coll);
}

// encodeArrayKey is the order-preserving array-elements-terminated key for an array value
// (encoding.md §2.14) — the engine's second container key, recursing into each element's own key.
// Reproduces the in-memory array total order (array.md §5) under memcmp: per flattened (row-major)
// element a marker (0x01 present ‖ the element key, 0x02 NULL) so present sorts before NULL and a
// shorter list reaches the 0x00 terminator first; then the shape suffix (ndim, then per dimension a
// u32 BE length and the i32 int-be-signflip lower bound). The element is a key-encodable scalar (float
// elements included since the §2.8 lift; the DDL gate rejects only a composite element 0A000), so the
// per-element key is encodeKeyValue with the C byte order (a collated array-element key is not a
// feature this slice).
export function encodeArrayKey(
  elem: ScalarType,
  a: { dims: number[]; lbounds: number[]; elements: Value[] },
): Uint8Array {
  const out: number[] = [];
  for (const e of a.elements) {
    if (e.kind === "null") {
      out.push(0x02); // NULL element — sorts after every present element
      continue;
    }
    out.push(0x01); // present element marker
    for (const b of encodeKeyValue(elem, e, null)) out.push(b);
  }
  out.push(0x00); // terminator — a shorter element list sorts before a longer one
  out.push(a.dims.length & 0xff); // ndim
  for (let d = 0; d < a.dims.length; d++) {
    const n = a.dims[d]! >>> 0;
    out.push((n >>> 24) & 0xff, (n >>> 16) & 0xff, (n >>> 8) & 0xff, n & 0xff);
    for (const b of encodeInt("i32", BigInt(a.lbounds[d]!))) out.push(b);
  }
  return Uint8Array.from(out);
}

// typeIsKeyableScalar reports whether a Type is a key-encodable scalar — the element-type gate for
// typeIsArrayKeyable. With float keys exercised (§2.8) every scalar is keyable; only the recursive
// composite container is excluded (it is not a scalar Type).
export function typeIsKeyableScalar(t: Type): boolean {
  return (
    typeIsInteger(t) ||
    typeIsBoolean(t) ||
    typeIsText(t) ||
    typeIsBytea(t) ||
    typeIsDecimal(t) ||
    typeIsUuid(t) ||
    typeIsTimestamp(t) ||
    typeIsTimestamptz(t) ||
    typeIsDate(t) ||
    typeIsInterval(t) ||
    typeIsFloat(t)
  );
}

// typeIsArrayKeyable reports whether t is an array whose element is a key-encodable scalar — so the
// array is a valid PRIMARY KEY / index / UNIQUE / FK key (encoding.md §2.14, array-elements-terminated).
// A float-element array (f64[]/f32[]) IS keyable (the §2.8 lift); only a composite-element array is
// NOT keyable (composite is not yet keyable).
export function typeIsArrayKeyable(t: Type): boolean {
  return t.kind === "array" && typeIsKeyableScalar(t.elem);
}

// FkProbe is a built foreign-key probe (spec/design/constraints.md §6.4/§6.8): the bytes to look
// up in the parent, tagged with which physical tree to probe — the parent's PK store (bare member
// encodings concatenated, in PK key order) or a parent unique index's prefix (0x00-tagged slots,
// in index-key order, plus the lowercased index name). A discriminated union (the TS idiom), with
// fkProbeBytes returning the raw bytes for batch-membership comparison.
export type FkProbe =
  | { kind: "pk"; bytes: Uint8Array }
  | { kind: "unique"; index: string; prefix: Uint8Array };

// fkProbeBytes returns the raw probe bytes — used to compare against this statement's batch end
// state (§6.4). Two probes of one FK share the same byte space (a given FK always probes the PK or
// always a fixed unique index), so byte equality is a valid set membership test.
export function fkProbeBytes(p: FkProbe): Uint8Array {
  return p.kind === "pk" ? p.bytes : p.prefix;
}

// fkProbe builds the parent-key probe for `fk` from `row`, taking each referenced parent column's
// value from `row[ordinals[i]]` where `ordinals[i]` supplies `fk.refColumns[i]`. So the child side
// passes `ordinals = fk.columns` (local columns), and a self-reference batch entry passes
// `ordinals = fk.refColumns` (the row viewed as a parent). Returns null when any supplied value is
// NULL (MATCH SIMPLE exempt — §6.3). The probe uses the parent's PK when the referenced set is the
// PK, else the matching unique index (re-derived deterministically — §6.8).
export function fkProbe(
  fk: ForeignKey,
  parent: Table,
  parentColls: (Collation | null)[],
  row: Row,
  ordinals: number[],
): FkProbe | null {
  // MATCH SIMPLE: a NULL in any supplied (local/parent) column exempts the whole tuple.
  for (const o of ordinals) {
    if (row[o]!.kind === "null") return null;
  }
  // The value supplying parent column `pcol` (the fk pairing: refColumns[i] ⇄ ordinals[i]).
  const valueFor = (pcol: number): Value => {
    const i = fk.refColumns.indexOf(pcol);
    return row[ordinals[i]!]!;
  };
  // The probe must match the PARENT's stored key, so a collated parent key column uses the PARENT's
  // collation (encoding.md §2.12), independent of the child column's own collation.
  const refSet = sortedUnique(fk.refColumns);
  const pkSet = sortedUnique(parent.pk);
  if (parent.pk.length > 0 && sameSet(pkSet, refSet)) {
    const parts: Uint8Array[] = [];
    for (const pcol of parent.pk) {
      parts.push(encodeTypedKey(parent.columns[pcol]!.type, valueFor(pcol), parentColls[pcol]!));
    }
    return { kind: "pk", bytes: concatBytes(parts) };
  }
  const idx = parent.indexes.find((i) => {
    const cols = indexColumnOrdinals(i);
    return i.unique && cols !== null && sameSet(sortedUnique(cols), refSet);
  })!;
  const idxCols = indexColumnOrdinals(idx)!; // an FK target is a plain-column unique index
  const parts: Uint8Array[] = [];
  for (const pcol of idxCols) {
    parts.push(Uint8Array.of(0x00));
    parts.push(encodeTypedKey(parent.columns[pcol]!.type, valueFor(pcol), parentColls[pcol]!));
  }
  return {
    kind: "unique",
    index: idx.name.toLowerCase(),
    prefix: concatBytes(parts),
  };
}

// concatBytes concatenates a list of byte arrays into one (the key-build helper).
export function concatBytes(parts: Uint8Array[]): Uint8Array {
  const total = parts.reduce((acc, b) => acc + b.length, 0);
  const out = new Uint8Array(total);
  let off = 0;
  for (const b of parts) {
    out.set(b, off);
    off += b.length;
  }
  return out;
}

// sortedUnique returns a column-ordinal list as a sorted, deduplicated set (for the
// order-independent FK referenced-columns ⇄ PK/unique-key set comparison —
// spec/design/constraints.md §6.2).
export function sortedUnique(v: number[]): number[] {
  const s = [...v].sort((a, b) => a - b);
  const out: number[] = [];
  for (const x of s) {
    if (out.length === 0 || out[out.length - 1] !== x) out.push(x);
  }
  return out;
}

// sameSet reports whether two already-sorted-unique ordinal lists are equal.
export function sameSet(a: number[], b: number[]): boolean {
  return a.length === b.length && a.every((v, i) => v === b[i]);
}

// fkTypesEqual reports structural equality of two catalog Types — the FK same-type pairing gate
// (spec/design/constraints.md §6.2). An FK column is always a scalar (a key-encodable PK/UNIQUE
// type), but the comparison is full structural for completeness, mirroring Rust's `ty == ty`.
export function fkTypesEqual(a: Type, b: Type): boolean {
  if (a.kind === "scalar" && b.kind === "scalar") return a.scalar === b.scalar;
  if (a.kind === "composite" && b.kind === "composite") return a.name === b.name;
  if (a.kind === "array" && b.kind === "array") return fkTypesEqual(a.elem, b.elem);
  if (a.kind === "range" && b.kind === "range") return fkTypesEqual(a.elem, b.elem);
  return false;
}

// fkAction maps a parsed referential action to its persisted form, rejecting the unsupported
// write-actions (CASCADE / SET NULL / SET DEFAULT) as 0A000 (spec/design/constraints.md §6.6).
// `clause` is "DELETE" or "UPDATE" for the message.
export function fkAction(a: RefAction, clause: string): FkAction {
  if (a === "noAction") return "noAction";
  if (a === "restrict") return "restrict";
  const word = a === "cascade" ? "CASCADE" : a === "setNull" ? "SET NULL" : "SET DEFAULT";
  throw engineError("feature_not_supported", "ON " + clause + " " + word + " is not supported");
}

// prefixSuccessor is the byte-successor of a prefix: the smallest byte string greater
// than every string that extends p. Increment the last non-0xFF byte and truncate after
// it; an all-0xFF prefix has no successor (null ⇒ unbounded high end).
export function prefixSuccessor(p: Uint8Array): Uint8Array | null {
  let end = p.length;
  while (end > 0 && p[end - 1] === 0xff) end--;
  if (end === 0) return null;
  const s = p.slice(0, end);
  s[end - 1]!++;
  return s;
}

// BoundTerm is one `pk <op> const-source` from a WHERE AND-chain, normalized so the PK is the LEFT side
// (a `5 < pk` flips to `pk > 5`). src is the constant/parameter operand node.
export type BoundTerm = { op: BinaryOp; src: RExpr };

// PkBound is the plan-time result of PK analysis: the PK's storage type + the bound terms. The concrete
// key range is built per execution by buildKeyBound.
// coll is the key column's resolved collation when it is collated AND Full (loaded version matches
// the file pin) — the probe encodes via this collation's UCA sort key (encoding.md §2.12), seeking
// the same key FORM the B-tree stores (spec/design/collation.md §8). null for a C (raw-byte) key. A
// Skewed collated key never produces a PkBound (keyCollationCtx refuses the bound — collation.md §12).
export type PkBound = { pkType: ScalarType; terms: BoundTerm[]; coll: Collation | null };

// BoundKey is the outcome of encoding a const-source into the PK key space: a usable key, a NULL const
// (the comparison is 3VL-unknown ⇒ empty range), or an out-of-range integer (drop this half-bound).
export type BoundKey = { kind: "key"; key: Uint8Array } | { kind: "null" } | { kind: "outOfRange" };

// detectPkBound flattens the WHERE's top-level AND-chain (an OR is never descended — a disjunction is
// not a contiguous range) and collects every `pk <cmp> const-source` conjunct. null ⇒ full scan.
// Conservative + sound: an unrecognized conjunct contributes no bound and stays in the residual filter.
export function detectPkBound(
  filter: RExpr,
  pkIdx: number,
  pkType: ScalarType,
  coll: Collation | null,
): PkBound | null {
  const colColl = coll !== null ? coll.name : null;
  const terms: BoundTerm[] = [];
  const walk = (e: RExpr): void => {
    if (e.kind === "and") {
      walk(e.lhs);
      walk(e.rhs);
      return;
    }
    const t = asBoundTerm(e, { kind: "column", index: pkIdx }, pkType, colColl, -1);
    if (t !== null) terms.push(t);
  };
  walk(filter);
  return terms.length === 0 ? null : { pkType, terms, coll };
}

// KeyMatch is what a bound's key operand is (spec/design/indexes.md §5): a plain column at a global
// ordinal (the PK bound and a column index key), or a resolved index EXPRESSION matched structurally
// against a WHERE conjunct operand (an expression index key). For the expression form, the key's
// Column(i) is table-local and matches a WHERE Column(i + offset).
export type KeyMatch =
  | { kind: "column"; index: number }
  | { kind: "expr"; expr: RExpr; offset: number };

// keyMatches reports whether the WHERE operand x is the bound's key operand.
export function keyMatches(km: KeyMatch, x: RExpr): boolean {
  if (km.kind === "column") return x.kind === "column" && x.index === km.index;
  return rexprEqShifted(x, km.expr, km.offset);
}

// rexprEqShifted is a SOUND-if-incomplete structural equality for index-expression matching
// (spec/design/indexes.md §5): does the WHERE conjunct operand `a` (GLOBAL column indices) equal the
// resolved index key expression `b` (table-local Column(i), matched as Column(i + offset))? Covers the
// common index-expression shapes; any unrecognized / typmod-bearing shape returns false — a missed
// bound is always sound (a full scan + residual filter), matching PostgreSQL's syntactic (not semantic)
// index-expression matching.
export function rexprEqShifted(a: RExpr, b: RExpr, offset: number): boolean {
  switch (a.kind) {
    case "column":
      return b.kind === "column" && a.index === b.index + offset;
    case "constInt":
      return b.kind === "constInt" && a.value === b.value;
    case "constBool":
      return b.kind === "constBool" && a.value === b.value;
    case "constText":
      return b.kind === "constText" && a.value === b.value;
    case "constNull":
      return b.kind === "constNull";
    case "scalarFunc":
      return (
        b.kind === "scalarFunc" &&
        a.func === b.func &&
        a.args.length === b.args.length &&
        a.args.every((x, i) => rexprEqShifted(x, b.args[i]!, offset))
      );
    // COALESCE(a, b, …) is a legal (immutable-iff-args-are) index expression (grammar.md §51),
    // so an index on COALESCE(x, 0) must match the same spelling in a query.
    case "coalesce":
      return (
        b.kind === "coalesce" &&
        a.coerceDecimal === b.coerceDecimal &&
        a.args.length === b.args.length &&
        a.args.every((x, i) => rexprEqShifted(x, b.args[i]!, offset))
      );
    // GREATEST/LEAST(a, b, …) is likewise a legal index expression (grammar.md §52); a GREATEST
    // index must not match a LEAST query (the `greatest` discriminant is compared), nor an index
    // built under a different text collation (compared by name).
    case "greatestLeast":
      return (
        b.kind === "greatestLeast" &&
        a.greatest === b.greatest &&
        a.coerceDecimal === b.coerceDecimal &&
        (a.collation?.name ?? null) === (b.collation?.name ?? null) &&
        a.args.length === b.args.length &&
        a.args.every((x, i) => rexprEqShifted(x, b.args[i]!, offset))
      );
    case "arith":
      return (
        b.kind === "arith" &&
        a.op === b.op &&
        rexprEqShifted(a.lhs, b.lhs, offset) &&
        rexprEqShifted(a.rhs, b.rhs, offset)
      );
    case "cast":
      return (
        b.kind === "cast" &&
        a.target === b.target &&
        a.typmod === null &&
        b.typmod === null &&
        a.varcharLen === null &&
        b.varcharLen === null &&
        rexprEqShifted(a.operand, b.operand, offset)
      );
    case "neg":
      return b.kind === "neg" && rexprEqShifted(a.operand, b.operand, offset);
    case "not":
      return b.kind === "not" && rexprEqShifted(a.operand, b.operand, offset);
    case "casing":
      // lower(x)/upper(x) (spec/design/collation.md §16) resolve to a dedicated "casing" node —
      // NOT "scalarFunc" — so an index on lower(email) (the headline expression-index shape)
      // matches ONLY if this arm is present. The fold is deterministic (engine-global casing
      // regime, identical at index-build and query-eval), so the match is sound: same direction
      // + a matching argument.
      return b.kind === "casing" && a.upper === b.upper && rexprEqShifted(a.arg, b.arg, offset);
    case "compare":
      // A comparison (status = 'active', amt > 0) is the canonical partial-index predicate shape
      // (indexes.md §9): same operator + same derived collation + structurally-equal operands.
      return (
        b.kind === "compare" &&
        a.op === b.op &&
        (a.collation?.name ?? null) === (b.collation?.name ?? null) &&
        rexprEqShifted(a.lhs, b.lhs, offset) &&
        rexprEqShifted(a.rhs, b.rhs, offset)
      );
    case "and":
      return (
        b.kind === "and" &&
        rexprEqShifted(a.lhs, b.lhs, offset) &&
        rexprEqShifted(a.rhs, b.rhs, offset)
      );
    case "or":
      return (
        b.kind === "or" &&
        rexprEqShifted(a.lhs, b.lhs, offset) &&
        rexprEqShifted(a.rhs, b.rhs, offset)
      );
    case "isNull":
      return (
        b.kind === "isNull" &&
        a.negated === b.negated &&
        rexprEqShifted(a.operand, b.operand, offset)
      );
    default:
      return false;
  }
}

// filterImpliesPredicate reports whether the WHERE filter implies a PARTIAL index's predicate
// (spec/design/indexes.md §9). jed's syntactic test (PG's, not a prover): every top-level conjunct of
// pred must be present as a top-level conjunct of filter (so a conjunctive predicate a AND b is
// implied by a WHERE that lists both a and b). pred is in table-local column coords; a filter conjunct
// is global, so it is matched shifted by offset. Sound-if-conservative: a miss means the index is not
// used (a correct full scan + residual filter).
export function filterImpliesPredicate(filter: RExpr, pred: RExpr, offset: number): boolean {
  if (pred.kind === "and") {
    return (
      filterImpliesPredicate(filter, pred.lhs, offset) &&
      filterImpliesPredicate(filter, pred.rhs, offset)
    );
  }
  const contains = (f: RExpr): boolean =>
    f.kind === "and" ? contains(f.lhs) || contains(f.rhs) : rexprEqShifted(f, pred, offset);
  return contains(filter);
}

// asBoundTerm recognizes a single comparison conjunct: a comparison (=,<,<=,>,>=) with the bound's
// key operand (a bare LOCAL column, or an index EXPRESSION matched structurally — a correlated
// "outerColumn" is a different kind, so it never matches) on one side and a const-source of the key's
// own type on the other (a promoted comparison — e.g. intpk = 2.5 → a constDecimal — does not match,
// so it stays residual). The op is flipped when the key is on the right.
export function asBoundTerm(
  e: RExpr,
  km: KeyMatch,
  pkType: ScalarType,
  colColl: string | null,
  siblingCutoff: number,
): BoundTerm | null {
  if (e.kind !== "compare") return null;
  // A comparison bounds the key only when ITS resolved collation matches the key column's frozen
  // collation (colColl) — so the comparison orders text the SAME way the B-tree is keyed
  // (spec/design/collation.md §8). C key ⇔ a C/byte comparison (both null); a collated key ⇔ a
  // comparison under the SAME collation (the column's implicit collation, or an explicit
  // COLLATE "<that name>"). A comparison under a DIFFERENT collation — name COLLATE "C" over a
  // unicode column, COLLATE "de" over unicode — does NOT match: its order disagrees with the stored
  // keys, so it stays a full scan + residual filter. (A *skewed* collated key never reaches here —
  // keyCollationCtx refuses the whole bound, §12.) The probe is then encoded in the key column's
  // form (sort key for a Full-collated column — buildKeyBound/indexBoundRows).
  const cmpColl = e.collation !== null ? e.collation.name : null;
  if (cmpColl !== colColl) return null;
  if (e.op !== "eq" && e.op !== "lt" && e.op !== "le" && e.op !== "gt" && e.op !== "ge")
    return null;
  const isPk = (x: RExpr): boolean => keyMatches(km, x);
  if (isPk(e.lhs) && isConstSource(e.rhs, pkType, siblingCutoff)) return { op: e.op, src: e.rhs };
  if (isPk(e.rhs) && isConstSource(e.lhs, pkType, siblingCutoff))
    return { op: flipCmp(e.op), src: e.lhs };
  return null;
}

// isConstSource reports whether e is constant for the whole scan AND of a type that encodes into the PK
// key space: a same-family const literal, a NULL literal (⇒ a provably empty range), a bind parameter,
// or a bare correlated "outerColumn" — its value is a runtime constant for a given outer row, so the
// inner subquery's PK is bounded by the current outer row's column and seeks instead of re-scanning the
// whole inner table per outer row (cost.md §3 "bounded scan", grammar.md §26). A type-mismatched outer
// reference is wrapped in a cast by the resolver (as for a const literal), so it never arrives here bare.
//
// siblingCutoff opens the index-nested-loop door (cost.md §3 "JOIN"): when >= 0, a bare "column" node
// whose GLOBAL index is < siblingCutoff — a column of an EARLIER join relation — is a valid bound source,
// resolved per outer row from the combined left-hand row (like "outerColumn", a bare sibling column implies
// a type match — a mismatch is a cast, never bare). -1 (the ordinary once-materialized bound) accepts only
// literals/params/outer references.
export function isConstSource(e: RExpr, pkType: ScalarType, siblingCutoff: number): boolean {
  switch (e.kind) {
    case "param":
    case "constNull":
    case "outerColumn":
      return true;
    case "column":
      return siblingCutoff >= 0 && e.index < siblingCutoff;
    case "constInt":
      return isInteger(pkType);
    case "constBool":
      return isBool(pkType);
    case "constUuid":
      return isUuid(pkType);
    case "constTimestamp":
      return isTimestamp(pkType);
    case "constTimestamptz":
      return isTimestamptz(pkType);
    case "constDate":
      return isDate(pkType);
    case "constText":
      return isText(pkType);
    case "constBytea":
      return isBytea(pkType);
    case "constDecimal":
      return isDecimal(pkType);
    case "constInterval":
      return isInterval(pkType);
    default:
      return false;
  }
}

// flipCmp swaps a comparison's sense (for `const <op> pk` ⇒ `pk <flipped> const`). eq is symmetric.
export function flipCmp(op: BinaryOp): BinaryOp {
  switch (op) {
    case "lt":
      return "gt";
    case "le":
      return "ge";
    case "gt":
      return "lt";
    case "ge":
      return "le";
    default:
      return op;
  }
}

// buildKeyBound turns the plan-time terms into a concrete key range at exec time: encode each
// const-source and intersect the half-bounds. null ⇒ the range admits no key (a NULL const — 3VL — or
// contradictory bounds), so the scan reads nothing. An out-of-range integer const drops only its own
// half-bound (a wider, still sound, scan).
// outer carries the enclosing rows (innermost last) so a correlated "outerColumn" source resolves to
// the current outer row's value; it is empty for a top-level statement. left is the current combined
// left-hand row of a left-deep join, from which an index-nested-loop "column" (sibling) source resolves
// (empty outside the join loop — a sibling never appears there).
export function buildKeyBound(
  bp: PkBound,
  params: Value[],
  outer: Row[],
  left: Row,
): KeyBound | null {
  const b = unboundedBound();
  for (const t of bp.terms) {
    const r = encodeBoundKey(bp.pkType, t.src, params, outer, bp.coll, left);
    if (r.kind === "null") return null;
    if (r.kind === "outOfRange") continue;
    const key = r.key;
    switch (t.op) {
      case "eq":
        intersectLo(b, key, true);
        intersectHi(b, key, true);
        break;
      case "gt":
        intersectLo(b, key, false);
        break;
      case "ge":
        intersectLo(b, key, true);
        break;
      case "lt":
        intersectHi(b, key, false);
        break;
      case "le":
        intersectHi(b, key, true);
        break;
    }
  }
  return boundEmpty(b) ? null : b;
}

// buildIndexBound turns an index access predicate into a concrete index-key range at exec time
// (indexes.md §5.1). It encodes the equality prefix into p (the concatenated present slots), then — if
// there is a range column — starts from [P, P‖0x01) (the upper endpoint stops before the range
// column's NULL slot, since a range is never true for NULL) and intersects each range term; otherwise
// the range is [P, byte-successor(P)) (every entry extending P). null ⇒ the bound admits no key (a
// NULL / disagreeing prefix equality, a NULL range endpoint, or a contradictory range). prefixLen =
// p.length, the byte count the row-key suffix skip advances past the equality-prefix slots before
// width-skipping the remaining components.
export function buildIndexBound(
  ib: IndexBound,
  params: Value[],
  outer: Row[],
  left: Row,
): { bound: KeyBound; prefixLen: number } | null {
  const parts: Uint8Array[] = [];
  for (const ec of ib.eqCols) {
    // Every equality const-source on this column must encode to ONE agreed value: a NULL is
    // 3VL-never-true, a disagreement (`a = 1 AND a = 2`) is a contradiction, and an out-of-range
    // integer can equal no stored value — all provably empty.
    let agreed: Uint8Array | null = null;
    for (const src of ec.srcs) {
      const bk = encodeBoundKey(ec.colType, src, params, outer, ec.coll, left);
      if (bk.kind !== "key") return null;
      if (agreed === null) agreed = bk.key;
      else if (!bytesEq(agreed, bk.key)) return null;
    }
    parts.push(new Uint8Array([0x00]));
    parts.push(agreed!);
  }
  const p = concatBytes(parts);
  if (ib.range === null) {
    // Pure equality prefix: [P, byte-successor(P)).
    const b: KeyBound = { lo: p, loInc: true, hi: prefixSuccessor(p), hiInc: false };
    return boundEmpty(b) ? null : { bound: b, prefixLen: p.length };
  }
  // Equality prefix P + a range on the next column. Base: [P, P‖0x01) — present values only (the 0x01
  // NULL tag sorts after every 0x00 present slot at this position).
  const b: KeyBound = {
    lo: p,
    loInc: true,
    hi: concatBytes([p, new Uint8Array([0x01])]),
    hiInc: false,
  };
  for (const t of ib.range.terms) {
    // The range column is fixed-width (indexes.md §5.1 eligibility), so it is never collated: the
    // probe encodes with a null collation.
    const bk = encodeBoundKey(ib.range.colType, t.src, params, outer, null, left);
    if (bk.kind === "null") return null;
    if (bk.kind === "outOfRange") continue; // drop this half-bound (a wider, still-sound scan)
    const ps = concatBytes([p, new Uint8Array([0x00]), bk.key]); // P ‖ 0x00 ‖ encode(v)
    switch (t.op) {
      case "ge":
        intersectLo(b, ps, true);
        break;
      case "gt": {
        // `>` skips the whole `c = v` subtree: the smallest key after every P‖0x00‖v‖* entry.
        const s = prefixSuccessor(ps);
        if (s === null) return null; // no key exceeds max — empty (unreachable: ps starts 0x00)
        intersectLo(b, s, true);
        break;
      }
      case "lt":
        intersectHi(b, ps, false);
        break;
      case "le": {
        const s = prefixSuccessor(ps);
        if (s !== null) intersectHi(b, s, false); // null ⇒ everything ≤ max, keep the base hi (P‖0x01)
        break;
      }
      // "eq" never reaches range terms (folded into the equality prefix); "ne" never a bound term.
    }
  }
  return boundEmpty(b) ? null : { bound: b, prefixLen: p.length };
}

// encodeBoundKey encodes a const-source's value into the PK's storage key (the same codec INSERT uses —
// encodeInt for integer/timestamp widths, the raw 16 bytes for uuid, the 1-byte bool-byte for boolean).
// param/outerColumn resolve to a runtime Value first (the param table / the enclosing outer row) and
// then encode through the shared path.
export function encodeBoundKey(
  pkType: ScalarType,
  src: RExpr,
  params: Value[],
  outer: Row[],
  coll: Collation | null,
  left: Row,
): BoundKey {
  switch (src.kind) {
    case "constNull":
      return { kind: "null" };
    case "constInt":
      return inRange(pkType, src.value)
        ? { kind: "key", key: encodeInt(pkType, src.value) }
        : { kind: "outOfRange" };
    case "constBool":
      return { kind: "key", key: encodeBool(src.value) };
    case "constUuid":
      return { kind: "key", key: src.value.slice() };
    case "constTimestamp":
    case "constTimestamptz":
    case "constDate":
      return { kind: "key", key: encodeInt(pkType, src.value) };
    case "constText":
      return encodeTextBound(src.value, coll);
    case "constBytea":
      return { kind: "key", key: encodeTerminated(src.value) };
    case "constDecimal":
      return { kind: "key", key: src.value.encodeKey() };
    case "constInterval":
      return { kind: "key", key: intervalEncodeKey(src.value) };
    case "param":
      return encodeValueKey(pkType, params[src.index]!, coll);
    case "outerColumn":
      // A correlated reference: column index of the enclosing row level hops out — the same indexing
      // the evaluator uses for "outerColumn" (innermost outer row is last).
      return encodeValueKey(pkType, outer[outer.length - src.level]![src.index]!, coll);
    case "column":
      // Index-nested-loop: the GLOBAL column index of an earlier join relation, read from the current
      // combined left-hand row (cost.md §3 "JOIN"). The join loop always passes a `left` wide enough
      // (the running row spans columns [0, rel.offset), and a sibling index is < rel.offset); a stray
      // out-of-range index widens to a full scan rather than throw.
      return src.index < left.length
        ? encodeValueKey(pkType, left[src.index]!, coll)
        : { kind: "outOfRange" };
    default:
      return { kind: "outOfRange" };
  }
}

// encodeTextBound encodes a text probe into a key bound: the raw text-terminated-escape bytes for a C
// key (coll === null, the fast path, encoding.md §2.4), or the collation's UCA sort key
// (text-collated-sortkey, §2.12) for a Full-collated key. A sort-key build that fails on an unmapped
// code point (the 0A000 the write/compare path raises, collation.md §6) becomes outOfRange here: the
// probe matches no stored (always-mapped) key, so the term contributes no bound and the scan widens
// to a full scan + residual filter — which reproduces the exact non-pushdown answer (empty for =,
// since equality is byte-identity §7; the 0A000 for an ordering compare iff any row is scanned).
// Identical across cores (mirrors Rust encode_text_bound / Go encodeTextBound).
export function encodeTextBound(s: string, coll: Collation | null): BoundKey {
  if (coll === null) return { kind: "key", key: encodeTerminated(SQL_BYTE_ENCODER.encode(s)) };
  try {
    return { kind: "key", key: collationSortKey(coll, s) };
  } catch {
    return { kind: "outOfRange" };
  }
}

// encodeValueKey encodes a runtime Value (a bound param or a resolved outer column) into the PK's storage
// key. A NULL value makes the comparison 3VL-unknown (an empty range); a value of a kind no key can hold
// (or an integer outside the PK width) drops its half-bound, widening — still sound. coll selects a text
// value's key form (collated sort key vs raw bytes — encodeTextBound).
export function encodeValueKey(pkType: ScalarType, v: Value, coll: Collation | null): BoundKey {
  if (v.kind === "null") return { kind: "null" };
  if (v.kind === "bool") return { kind: "key", key: encodeBool(v.value) };
  if (v.kind === "uuid") return { kind: "key", key: v.bytes.slice() };
  if (v.kind === "text") return encodeTextBound(v.text, coll);
  if (v.kind === "bytea") return { kind: "key", key: encodeTerminated(v.bytes) };
  if (v.kind === "decimal") return { kind: "key", key: v.dec.encodeKey() };
  if (v.kind === "interval") return { kind: "key", key: intervalEncodeKey(v.iv) };
  if (v.kind === "int")
    return inRange(pkType, v.int)
      ? { kind: "key", key: encodeInt(pkType, v.int) }
      : { kind: "outOfRange" };
  if (v.kind === "date") return { kind: "key", key: encodeInt(pkType, v.days) };
  if (v.kind === "timestamp" || v.kind === "timestamptz")
    return { kind: "key", key: encodeInt(pkType, v.micros) };
  return { kind: "outOfRange" };
}

// encodeKeySet encodes an OR / IN-list's equality const-sources into the key space and returns a
// SORTED, DE-DUPLICATED set of encoded keys — the distinct point probes a merged point-set bound
// visits (cost.md §3 "OR / IN-list"). A src that is NULL (3VL-never-true) or does not encode into the
// key domain (an out-of-range integer — no stored key can equal it) contributes no point and is
// skipped (sound: the union stays a superset, and the residual filter re-checks each admitted row).
// Byte-dedup == value-dedup and byte-sort == value-sort under the order-preserving key encoding
// (encoding.md §2), so probing the sorted distinct keys yields rows in ascending key order with no
// row visited twice. Shared by the PK and secondary-index point-set executors.
export function encodeKeySet(
  keyType: ScalarType,
  srcs: RExpr[],
  params: Value[],
  outer: Row[],
  coll: Collation | null,
  left: Row,
): Uint8Array[] {
  const keys: Uint8Array[] = [];
  for (const src of srcs) {
    const bk = encodeBoundKey(keyType, src, params, outer, coll, left);
    if (bk.kind !== "key") continue;
    keys.push(bk.key);
  }
  keys.sort((a, b) => compareBytes(a, b));
  const out: Uint8Array[] = [];
  for (let i = 0; i < keys.length; i++) {
    if (i === 0 || !bytesEq(keys[i]!, keys[i - 1]!)) out.push(keys[i]!);
  }
  return out;
}

// intersectLo tightens b's lower bound to the more restrictive of (current, key); at an equal key an
// exclusive bound (inc=false) wins.
export function intersectLo(b: KeyBound, key: Uint8Array, inc: boolean): void {
  if (b.lo === null) {
    b.lo = key;
    b.loInc = inc;
    return;
  }
  const c = compareBytes(key, b.lo);
  if (c > 0 || (c === 0 && !inc)) {
    b.lo = key;
    b.loInc = inc;
  }
}

// intersectHi tightens b's upper bound to the more restrictive of (current, key); at an equal key an
// exclusive bound wins.
export function intersectHi(b: KeyBound, key: Uint8Array, inc: boolean): void {
  if (b.hi === null) {
    b.hi = key;
    b.hiInc = inc;
    return;
  }
  const c = compareBytes(key, b.hi);
  if (c < 0 || (c === 0 && !inc)) {
    b.hi = key;
    b.hiInc = inc;
  }
}

// boundEmpty reports whether the bound admits no key: lo above hi, or lo == hi with a non-inclusive
// endpoint.
export function boundEmpty(b: KeyBound): boolean {
  if (b.lo === null || b.hi === null) return false;
  const c = compareBytes(b.lo, b.hi);
  if (c > 0) return true;
  if (c === 0) return !(b.loInc && b.hiInc);
  return false;
}

// mutationPkBound detects a single-table UPDATE/DELETE's PK pushdown bound; null ⇒ full scan.
export function mutationPkBound(
  table: Table,
  filter: RExpr | null,
  snap: Snapshot,
): PkBound | null {
  if (filter === null) return null;
  const pkIdx = primaryKeyIndex(table);
  if (pkIdx < 0) return null;
  // Point-lookup pushdown is scalar-only; a non-scalar (range) PK skips it (deferred — ranges.md
  // §10), so a range PK WHERE k = … full-scans + residual-filters.
  const sty = typeAsScalar(table.columns[pkIdx]!.type);
  if (sty === undefined) return null;
  // A collated Skewed PK refuses pushdown (ctx === null) — though a skewed table's write is already
  // refused XX002 upstream (ensureCollationsWritable), so this is reached only for a C or
  // Full-collated PK (collation.md §8/§12).
  const ctx = keyCollationCtx(snap, table.columns[pkIdx]!);
  if (ctx === null) return null;
  return detectPkBound(filter, pkIdx, sty, ctx.coll);
}

// pkSetFor is the mutationPkBound analog for an OR / IN-list of primary-key equalities — a merged PK
// point-set bound for the UPDATE/DELETE scan (cost.md §3 "OR / IN-list"). Like mutationPkBound it
// applies only to a scalar, non-Skewed-collated PK. A secondary-index point-set for DML is the
// separate index-scans-for-DML follow-on, so mutations bound only by the primary key here.
export function pkSetFor(table: Table, filter: RExpr | null, snap: Snapshot): PkKeySet | null {
  if (filter === null) return null;
  const pkIdx = primaryKeyIndex(table);
  if (pkIdx < 0) return null;
  const sty = typeAsScalar(table.columns[pkIdx]!.type);
  if (sty === undefined) return null;
  const ctx = keyCollationCtx(snap, table.columns[pkIdx]!);
  if (ctx === null) return null;
  const srcs = detectKeySet(filter, pkIdx, sty, ctx.coll);
  if (srcs !== null) return { pkType: sty, coll: ctx.coll, srcs };
  return null;
}

// scanEntries returns the (key,row) entries a mutation scans + the page_read node count: a primary-key
// bound seeks/ranges, an empty bound yields entries=null (the caller charges nothing and mutates
// nothing), and no bound is the full scan (cost.md §3 "bounded scan").
export function scanEntries(
  store: TableStore,
  pkBound: PkBound | null,
  params: Value[],
  mask: boolean[],
): { entries: Entry[] | null; overlap: number; slabs: number } {
  if (pkBound !== null) {
    // Top-level statement: no enclosing query, so the bound never has a correlated source.
    const b = buildKeyBound(pkBound, params, [], []);
    if (b === null) return { entries: null, overlap: 0, slabs: 0 };
    const u = store.rangeScanWithUnits(b, mask);
    return { entries: u.entries, overlap: u.pages, slabs: u.slabs };
  }
  const u = store.scanWithUnits(mask);
  return { entries: u.entries, overlap: u.pages, slabs: u.slabs };
}

// ---- Subquery helpers (spec/design/grammar.md §26) ----------------------

// queryPlanReferencesOuter reports whether a plan references any scope STRICTLY OUTSIDE itself —
// i.e. it is correlated (spec/design/grammar.md §26). depth is how many nested-subquery frames we
// have descended INTO this plan (0 = its own clauses); an outerColumn at level points above iff
// level > depth. The fold pass calls it with depth 0 on a subquery's sub-plan to fold (uncorrelated)
// or leave (correlated) it.
export function queryPlanReferencesOuter(plan: QueryPlan, depth: number): boolean {
  if (plan.kind === "setOp") {
    return queryPlanReferencesOuter(plan.lhs, depth) || queryPlanReferencesOuter(plan.rhs, depth);
  }
  if (plan.kind === "values") {
    // A VALUES body is planned parent=null, so its values hold no outer reference of their own; a
    // folded-in subquery, however, may correlate to the target scope.
    for (const row of plan.rows)
      for (const e of row) if (rexprReferencesOuter(e, depth)) return true;
    return false;
  }
  if (plan.kind === "with") {
    // A nested WITH adds no correlation frame: its body is at the same depth, and the CTE bodies are
    // planned parent=null (no outer reference), so only the body can correlate (cte.md §7).
    return queryPlanReferencesOuter(plan.body, depth);
  }
  for (const j of plan.joins) if (j.on !== null && rexprReferencesOuter(j.on, depth)) return true;
  if (plan.filter !== null && rexprReferencesOuter(plan.filter, depth)) return true;
  if (plan.having !== null && rexprReferencesOuter(plan.having, depth)) return true;
  for (const s of plan.aggSpecs)
    if (s.operand !== null && rexprReferencesOuter(s.operand, depth)) return true;
  for (const p of plan.projections) if (rexprReferencesOuter(p, depth)) return true;
  // A materialized ORDER BY expression may itself carry a correlated reference (query.order_by_correlated):
  // a subquery whose ONLY outer reference is in its ORDER BY is still correlated and must re-execute per
  // outer row (else its OuterColumn reads an empty outer-row environment).
  for (const oe of plan.orderExprs) if (rexprReferencesOuter(oe, depth)) return true;
  // A set-returning relation's arguments may carry a correlated reference (an implicitly-lateral SRF
  // arg sees params / outer / an earlier sibling — functions.md §10, grammar.md §44), making the
  // enclosing query correlated. A LATERAL derived table's body is one frame deeper; a reference in it
  // back into this query's outer counts here too (§44).
  for (const rel of plan.rels) {
    if (rel.srf !== undefined) {
      for (const a of rel.srf.args) if (rexprReferencesOuter(a, depth)) return true;
    }
    if (rel.derived !== undefined && queryPlanReferencesOuter(rel.derived, depth + 1)) return true;
  }
  return false;
}

export function rexprReferencesOuter(e: RExpr, depth: number): boolean {
  switch (e.kind) {
    case "outerColumn":
      return e.level > depth;
    case "subquery":
      // A nested subquery's own clauses are one frame deeper; its IN lhs is at this frame.
      return (
        (e.lhs !== null && rexprReferencesOuter(e.lhs, depth)) ||
        queryPlanReferencesOuter(e.plan, depth + 1)
      );
    case "inValues":
      return rexprReferencesOuter(e.lhs, depth);
    case "quantified":
      return rexprReferencesOuter(e.lhs, depth) || rexprReferencesOuter(e.array, depth);
    case "cast":
    case "arrayCast":
    case "neg":
    case "not":
    case "isNull":
    case "isJson":
    case "jsonCtor":
      return rexprReferencesOuter(e.operand, depth);
    case "arith":
    case "compare":
    case "and":
    case "or":
    case "distinct":
    case "like":
    case "regex":
      return rexprReferencesOuter(e.lhs, depth) || rexprReferencesOuter(e.rhs, depth);
    case "jsonGet":
    case "jsonHasKey":
    case "jsonDelete":
      return rexprReferencesOuter(e.base, depth) || rexprReferencesOuter(e.arg, depth);
    case "jsonContains":
    case "jsonConcat":
      return rexprReferencesOuter(e.a, depth) || rexprReferencesOuter(e.b, depth);
    case "casing":
      return rexprReferencesOuter(e.arg, depth);
    case "atTimeZone":
      return rexprReferencesOuter(e.zone, depth) || rexprReferencesOuter(e.value, depth);
    case "dateTrunc":
      return (
        rexprReferencesOuter(e.unit, depth) ||
        rexprReferencesOuter(e.value, depth) ||
        (e.zone !== null && rexprReferencesOuter(e.zone, depth))
      );
    case "extract":
      return rexprReferencesOuter(e.value, depth);
    case "dateConvert":
      return rexprReferencesOuter(e.inner, depth);
    case "case":
      return (
        e.arms.some(
          (arm) => rexprReferencesOuter(arm.cond, depth) || rexprReferencesOuter(arm.result, depth),
        ) || rexprReferencesOuter(e.els, depth)
      );
    case "greatestLeast":
    case "coalesce":
    case "scalarFunc":
    case "arrayFunc":
    case "regexFunc":
    case "rangeFunc":
    case "rangeCtor":
    case "rangeOp":
    case "rangeSetOp":
    case "variadic":
    case "jsonBuild":
    case "jsonSetInsert":
    case "jsonObjectFromArrays":
    case "jsonPathFn":
    case "jsonSqlFn":
      return e.args.some((a) => rexprReferencesOuter(a, depth));
    case "row":
      return e.fields.some((f) => rexprReferencesOuter(f, depth));
    case "array":
      return e.elements.some((el) => rexprReferencesOuter(el, depth));
    case "field":
      return rexprReferencesOuter(e.base, depth);
    case "subscript":
      return (
        rexprReferencesOuter(e.base, depth) ||
        rSubscriptBounds(e.subscripts).some((b) => rexprReferencesOuter(b, depth))
      );
    default:
      return false; // leaves: column, param, const*
  }
}

// rSubscriptBounds is the bound RExprs of a list of resolved subscript specs (each index, or a
// slice's present lower/upper bounds) — for the RExpr tree walkers (spec/design/array.md §6).
export function rSubscriptBounds(subs: RSubscript[]): RExpr[] {
  const out: RExpr[] = [];
  for (const s of subs) {
    if (!s.isSlice) out.push(s.index);
    else {
      if (s.lower !== null) out.push(s.lower);
      if (s.upper !== null) out.push(s.upper);
    }
  }
  return out;
}

// collectTouched marks the combined-row columns an expression STATICALLY references — the
// touched set (cost.md §3 "The touched set"; large-values.md §14). Depth bookkeeping mirrors
// rexprReferencesOuter: walking the target plan's own clauses is depth 0 (a column touches);
// inside a nested subquery a column indexes the subquery's own row (ignored) and an outer
// column with level === depth is a correlated reference back into the target scope (touches).
// Purely syntactic — a never-taken CASE branch still touches — so the set is deterministic and
// cross-core identical (a §8 contract).
// computeRelMasks computes the TOUCHED SET per relation (cost.md §3 "The touched set";
// large-values.md §14): the columns this query statically references, collected depth-aware so a
// correlated subquery's outer reference back into this scope counts. An aggregate query's
// projections / HAVING / ORDER BY index the synthetic group row, whose inputs are exactly the
// group keys + aggregate arguments collected here; a plain query's projections and ORDER BY keys
// index the combined row directly. An ANNOTATION of the logical plan, not an optimization
// (spec/design/planner.md §2): the mask is a correctness input to the lazy/masked scan — a wrong
// mask is a disk-mode NULL-folding bug, not a slow plan — so it is computed by the resolve half,
// before any physical rule runs.
function computeRelMasks(plan: SelectPlan): boolean[][] {
  const totalCols = plan.rels.reduce((a, r) => a + r.colCount, 0);
  const touched: boolean[] = new Array(totalCols).fill(false);
  if (plan.filter !== null) collectTouched(plan.filter, 0, touched);
  for (const j of plan.joins) if (j.on !== null) collectTouched(j.on, 0, touched);
  if (plan.isAgg) {
    // A column grouping key is a real input column (mark it); an expression grouping key has a
    // SYNTHETIC index (inputWidth + k, out of touched's range) — its real input columns are reached
    // through its materialized groupExprs node instead (aggregates.md §15).
    for (const gk of plan.groupKeys) if (gk < totalCols) touched[gk] = true;
    for (const ge of plan.groupExprs) collectTouched(ge, 0, touched);
    for (const s of plan.aggSpecs) {
      if (s.operand !== null) collectTouched(s.operand, 0, touched);
      // An aggregate reads real input columns beyond its operand: the FILTER predicate
      // (agg(x) FILTER (WHERE cond) — aggregates.md §11), an ordered-set direct argument, and a
      // hypothetical-set's WITHIN GROUP key operands / direct args (aggregates.md §13/§19). Without
      // these the referenced column is left unfetched by the lazy/masked scan (large-values.md §14)
      // and folds as NULL — a memory-vs-disk divergence (count(*) FILTER, rank() WITHIN GROUP).
      if (s.filter !== undefined && s.filter !== null) collectTouched(s.filter, 0, touched);
      if (s.osaFrac !== undefined && s.osaFrac !== null) collectTouched(s.osaFrac, 0, touched);
      if (s.hypo !== undefined && s.hypo !== null) {
        for (const k of s.hypo.keys) collectTouched(k, 0, touched);
        for (const a of s.hypo.args) collectTouched(a, 0, touched);
      }
    }
  } else {
    for (const p of plan.projections) collectTouched(p, 0, touched);
    // A column-key ORDER BY slot is a real input column (< totalCols) — mark it; a materialized
    // expression-key slot is synthetic (>= totalCols, after rebase) whose input columns are reached
    // through its orderExprs expression instead (collected below).
    for (const o of plan.order) if (o.idx < totalCols) touched[o.idx] = true;
    // Each materialized ORDER BY expression key reads real input columns (a plain query resolves it
    // against the FROM scope; a grouped query reaches them through its group keys / aggregate
    // arguments, already marked above).
    for (const oe of plan.orderExprs) collectTouched(oe, 0, touched);
    // A window query also reads each window function's PARTITION BY + ORDER BY keys, beyond what
    // the projection's window-result slots reference. A bare-column key is a real input slot
    // (< totalCols) — mark it; a materialized expression key is a synthetic slot (>= totalCols,
    // after rebase) whose input columns are reached through its windowKeys expression (below).
    for (const spec of plan.windowSpecs) {
      for (const pk of spec.partition) if (pk < totalCols) touched[pk] = true;
      for (const o of spec.order) if (o.idx < totalCols) touched[o.idx] = true;
      // The window function's ARGUMENT operands (sum(amount)'s amount, lag(v, off, def)'s
      // value/offset/default) and its FILTER read real input columns too — the row-based window
      // stage evaluates them per frame row (window.md §5.2). Without this the operand column is
      // left unfetched by the lazy/masked scan (large-values.md §14) and folds as NULL. Mirrors
      // the aggregate branch's collectTouched(s.operand) above.
      for (const a of spec.args) collectTouched(a, 0, touched);
      if (spec.filter !== undefined && spec.filter !== null)
        collectTouched(spec.filter, 0, touched);
    }
    // Each materialized window-key expression reads real input columns (a plain window query
    // resolves its keys against the FROM scope).
    for (const ke of plan.windowKeys) collectTouched(ke, 0, touched);
  }
  // A set-returning relation's arguments and a LATERAL derived table's body read real input columns
  // too — an implicitly-lateral SRF arg / lateral body sees an earlier sibling relation (functions.md
  // §10, grammar.md §44). Applies to aggregate and plain queries alike. Without this the referenced
  // column is left unfetched by the lazy/masked scan (large-values.md §14) and the SRF/body reads
  // NULL — a memory-vs-disk divergence.
  for (const r of plan.rels) {
    if (r.srf !== undefined) {
      // A LATERAL SRF (any SRF at position i>0) resolves its sibling columns as outerColumn at level
      // 1 (the same frame the runtime pushes) — so collect at depth 1, not 0. An i==0 SRF has no
      // sibling correlation, so depth 1 marks nothing there.
      for (const a of r.srf.args) collectTouched(a, 1, touched);
    }
    if (r.derived !== undefined) collectTouchedPlan(r.derived, 1, touched);
  }
  return plan.rels.map((r) => touched.slice(r.offset, r.offset + r.colCount));
}

export function collectTouched(e: RExpr, depth: number, touched: boolean[]): void {
  switch (e.kind) {
    case "column":
      // A Column index beyond the real columns is a SYNTHETIC slot (an aggregate or window result,
      // spec/design/window.md §5.1), not a table column — it touches no stored data, so the bound
      // check skips it rather than going out of range.
      if (depth === 0 && e.index < touched.length) touched[e.index] = true;
      return;
    case "outerColumn":
      // A correlated reference into the scope we are collecting for (its frame is `depth` levels up).
      // The index is a slot in that target scope's combined row; bounds-checked like the Column case.
      // Callers collect at the depth matching the reference's level — a correlated subquery at its
      // nesting depth, a LATERAL SRF arg at depth 1 (its sibling frame — functions.md §10).
      if (e.level === depth && depth > 0 && e.index < touched.length) touched[e.index] = true;
      return;
    case "subquery":
      if (e.lhs !== null) collectTouched(e.lhs, depth, touched);
      collectTouchedPlan(e.plan, depth + 1, touched);
      return;
    case "inValues":
      collectTouched(e.lhs, depth, touched);
      return;
    case "quantified":
      collectTouched(e.lhs, depth, touched);
      collectTouched(e.array, depth, touched);
      return;
    case "cast":
    case "arrayCast":
    case "neg":
    case "not":
    case "isNull":
    case "isJson":
    case "jsonCtor":
      collectTouched(e.operand, depth, touched);
      return;
    case "arith":
    case "compare":
    case "and":
    case "or":
    case "distinct":
    case "like":
    case "regex":
      collectTouched(e.lhs, depth, touched);
      collectTouched(e.rhs, depth, touched);
      return;
    case "jsonGet":
    case "jsonHasKey":
    case "jsonDelete":
      collectTouched(e.base, depth, touched);
      collectTouched(e.arg, depth, touched);
      return;
    case "jsonContains":
    case "jsonConcat":
      collectTouched(e.a, depth, touched);
      collectTouched(e.b, depth, touched);
      return;
    case "casing":
      collectTouched(e.arg, depth, touched);
      return;
    case "atTimeZone":
      collectTouched(e.zone, depth, touched);
      collectTouched(e.value, depth, touched);
      return;
    case "dateTrunc":
      collectTouched(e.unit, depth, touched);
      collectTouched(e.value, depth, touched);
      if (e.zone !== null) collectTouched(e.zone, depth, touched);
      return;
    case "extract":
      collectTouched(e.value, depth, touched);
      return;
    case "dateConvert":
      collectTouched(e.inner, depth, touched);
      return;
    case "case":
      for (const arm of e.arms) {
        collectTouched(arm.cond, depth, touched);
        collectTouched(arm.result, depth, touched);
      }
      collectTouched(e.els, depth, touched);
      return;
    case "greatestLeast":
    case "coalesce":
    case "scalarFunc":
    case "arrayFunc":
    case "regexFunc":
    case "rangeFunc":
    case "rangeCtor":
    case "rangeOp":
    case "rangeSetOp":
    case "variadic":
    case "jsonBuild":
    case "jsonSetInsert":
    case "jsonObjectFromArrays":
    case "jsonPathFn":
    case "jsonSqlFn":
      for (const a of e.args) collectTouched(a, depth, touched);
      return;
    case "row":
      for (const f of e.fields) collectTouched(f, depth, touched);
      return;
    case "array":
      for (const el of e.elements) collectTouched(el, depth, touched);
      return;
    case "field":
      collectTouched(e.base, depth, touched);
      return;
    case "subscript":
      collectTouched(e.base, depth, touched);
      for (const b of rSubscriptBounds(e.subscripts)) collectTouched(b, depth, touched);
      return;
    default: // leaves: param, const*
  }
}

// collectTouchedPlan walks a nested plan's expression surfaces for outer references back into
// the target scope — the same five surfaces selectPlanReferencesOuter checks (slot lists like
// group keys / ORDER BY index the nested plan's own rows and can never reach outward).
export function collectTouchedPlan(plan: QueryPlan, depth: number, touched: boolean[]): void {
  if (plan.kind === "select") {
    for (const j of plan.joins) if (j.on !== null) collectTouched(j.on, depth, touched);
    if (plan.filter !== null) collectTouched(plan.filter, depth, touched);
    if (plan.having !== null) collectTouched(plan.having, depth, touched);
    for (const s of plan.aggSpecs)
      if (s.operand !== null) collectTouched(s.operand, depth, touched);
    for (const p of plan.projections) collectTouched(p, depth, touched);
    // A materialized ORDER BY expression and a set-returning relation's args / a LATERAL derived body
    // can each carry a correlated reference back into the target scope (the same surfaces
    // selectPlanReferencesOuter checks — query.order_by_correlated, functions.md §10, grammar.md §44).
    // collectTouchedPlan MUST cover every surface that function does, or an outer column read only
    // through one of them is left unfetched by the lazy/masked scan (large-values.md §14) and the
    // correlated subquery re-executes against NULL — a memory-vs-disk divergence.
    for (const oe of plan.orderExprs) collectTouched(oe, depth, touched);
    for (const rel of plan.rels) {
      if (rel.srf !== undefined) {
        for (const a of rel.srf.args) collectTouched(a, depth, touched);
      }
      if (rel.derived !== undefined) collectTouchedPlan(rel.derived, depth + 1, touched);
    }
  } else if (plan.kind === "values") {
    for (const row of plan.rows) for (const e of row) collectTouched(e, depth, touched);
  } else if (plan.kind === "with") {
    // A nested WITH's correlated references live in its body (the CTE bodies are parent=null);
    // recurse into the body at the same depth (spec/design/cte.md §7).
    collectTouchedPlan(plan.body, depth, touched);
  } else {
    collectTouchedPlan(plan.lhs, depth, touched);
    collectTouchedPlan(plan.rhs, depth, touched);
  }
}

// WINDOW_RESULT_BASE is the placeholder base a grouped+window query's window results carry until
// rebaseWindowResults rewrites them to groupKeys.length+aggSpecs.length+w (spec/design/window.md
// §5.1). Far above any real column/synthetic-slot count, and below 2^31 so it is valid on a 32-bit
// usize (the Rust wasm32 build) as well as an exact number here. Kept identical across the three cores.
// (Written as 2**28, not 1<<28, to match the WINDOW_KEY/GROUPING bases below where a 1<<N would risk wrap.)
export const WINDOW_RESULT_BASE = 2 ** 28;

// WINDOW_KEY_BASE is the placeholder base a materialized window-key expression (a non-column
// PARTITION BY / ORDER BY key — `PARTITION BY a + b`) carries until the rebase pass rewrites it to
// its real synthetic slot inputWidth+k (spec/design/window.md §5.1). Disjoint from
// WINDOW_RESULT_BASE's range, below 2**31 (32-bit-usize / wasm32 safe). A bare-column key is NOT
// materialized — it keeps its real row slot. (2 ** 29.)
export const WINDOW_KEY_BASE = 2 ** 29;

// GROUPING_GS_BASE is the placeholder base a GROUPING(...) call carries until the rebase pass rewrites
// it to its real trailing synthetic slot groupKeys.length+aggSpecs.length+g (the GROUPING results
// follow the master columns + aggregate results — spec/design/aggregates.md §12). Disjoint from the
// window bases, below 2**31 (32-bit-usize / wasm32 safe). GROUPING is mutually exclusive with window
// functions, so its placeholders never coexist with the window ones in a projection. (2 ** 30.)
export const GROUPING_GS_BASE = 2 ** 30;

// ORDER_EXPR_BASE is the placeholder base a materialized ORDER BY EXPRESSION key's sort slot carries
// until it is rebased to its real trailing slot finalRowWidth+k (the materialized order values are
// appended after the input / window / grouped columns — grammar.md §10). Used only in the OrderSlot
// idx field (a different namespace from the RExpr column bases above), but kept disjoint and below
// 2**31 (32-bit-usize / wasm32 safe) for the same reasons. A column / ordinal key keeps its real slot.
export const ORDER_EXPR_BASE = 2 ** 27;

// MAX_GROUPING_SETS bounds a GROUP BY's total expansion (CUBE of n columns alone is 2^n). Beyond this
// the statement is aborted 54001 (statement_too_complex) — jed's structural-complexity gate (a
// deliberate divergence from PostgreSQL's per-construct "CUBE is limited to 12 elements" / 54011; jed
// bounds the total expansion instead). spec/design/aggregates.md §12.
export const MAX_GROUPING_SETS = 4096;

// GroupSet is one resolved grouping set of a GROUP BY (spec/design/aggregates.md §12). A plain GROUP
// BY has exactly one; ROLLUP/CUBE/GROUPING SETS produce several. Each is bucketed independently over
// the post-WHERE rows and its groups projected into the shared synthetic row, whose first
// groupKeys.length slots are the master grouping columns (the ordered union of all sets' columns).
export type GroupSet = {
  // keyCols: the flat input-row indices this set buckets on (its key, in key order). Empty = one
  // grand-total group (always emits one row, even over an empty input — the () / whole-table case).
  keyCols: number[];
  // slotSrc: per master grouping-column slot (length groupKeys.length): >= 0 if this set includes
  // that column (its synthetic value is the bucket key's slotSrc[p]-th component), else -1 (NULL).
  slotSrc: number[];
  // mask: the GROUPING() bitmask for rows from this set — bit p set iff master slot p is NOT in it.
  mask: bigint;
};

// groupItemSetCount is the number of grouping sets a single GROUP BY term expands to, saturating well
// below MAX_GROUPING_SETS+1 so a huge CUBE cannot overflow the product before the limit check.
export function groupItemSetCount(item: GroupItem): number {
  switch (item.kind) {
    case "set":
      return 1;
    case "rollup":
      return item.groups.length + 1;
    case "cube":
      return item.groups.length >= 20 ? MAX_GROUPING_SETS + 1 : 2 ** item.groups.length;
    case "groupingSets": {
      let total = 0;
      for (const el of item.elems) {
        total += groupItemSetCount(el);
        if (total > MAX_GROUPING_SETS) return MAX_GROUPING_SETS + 1;
      }
      return total;
    }
  }
}

// expandGroupItem expands a single GROUP BY term into its grouping sets, each a list of column Exprs
// (ROLLUP/CUBE/GROUPING SETS and nesting — spec/design/aggregates.md §12). The per-set column order
// is textual; the set order is deterministic and identical across cores (tests compare with rowsort).
export function expandGroupItem(item: GroupItem): Expr[][] {
  switch (item.kind) {
    case "set":
      return [item.cols.slice()];
    case "rollup": {
      // The prefixes longest-first down to the empty set — n+1 sets.
      const out: Expr[][] = [];
      for (let k = item.groups.length; k >= 0; k--) {
        const set: Expr[] = [];
        for (let i = 0; i < k; i++) set.push(...item.groups[i]!);
        out.push(set);
      }
      return out;
    }
    case "cube": {
      // Every subset of the column groups — 2^n sets (bit i = include group i).
      const n = item.groups.length;
      const out: Expr[][] = [];
      for (let mask = 0; mask < 2 ** n; mask++) {
        const set: Expr[] = [];
        for (let i = 0; i < n; i++) if (mask & (1 << i)) set.push(...item.groups[i]!);
        out.push(set);
      }
      return out;
    }
    case "groupingSets": {
      const out: Expr[][] = [];
      for (const el of item.elems) out.push(...expandGroupItem(el));
      return out;
    }
  }
}

// expandGroupBy expands a whole GROUP BY clause into its grouping sets: the cross-product of the
// top-level terms' expansions. An empty clause yields one empty set (the whole-table grand total).
// Aborts 54001 if the expansion exceeds MAX_GROUPING_SETS (spec/design/aggregates.md §12).
export function expandGroupBy(items: GroupItem[]): Expr[][] {
  let total = 1;
  for (const it of items) {
    total *= groupItemSetCount(it);
    if (total > MAX_GROUPING_SETS) {
      throw engineError(
        "statement_too_complex",
        `too many grouping sets (the limit is ${MAX_GROUPING_SETS})`,
      );
    }
  }
  let acc: Expr[][] = [[]];
  for (const it of items) {
    const exp = expandGroupItem(it);
    const next: Expr[][] = [];
    for (const a of acc) for (const s of exp) next.push([...a, ...s]);
    acc = next;
  }
  return acc;
}

// GroupKeyResolved is the resolution of one GROUP BY grouping term (aggregates.md §15): either an
// input COLUMN at a flat row index, or a general EXPRESSION to materialize (its resolved node + type
// + canonical AST). Mirrors Rust's GroupKeyResolved enum.
export type GroupKeyResolved =
  | { kind: "column"; index: number }
  | { kind: "expr"; node: RExpr; ty: ResolvedType; canon: Expr };

// resolveGroupTerm resolves one GROUP BY grouping term to a column or a materialized expression
// (aggregates.md §15). Classifies the term: a bare integer literal is a select-list ORDINAL (1-based;
// out of range 42P10) whose target select item is then resolved as a term; otherwise it is a column
// / alias / general expression (resolveGroupNamed).
export function resolveGroupTerm(
  scope: Scope,
  term: Expr,
  items: SelectItems,
  params: ParamTypes,
): GroupKeyResolved {
  // Only a *bare* integer literal is an ordinal — `GROUP BY 1`; `GROUP BY 1 + 1` is a constant
  // expression (PG). The parser folds a unary minus into the value, so a negative is just out of
  // range. The select list fixes the position count: `*` expands to the scope width.
  if (term.kind === "literal" && term.literal.kind === "int") {
    const n = term.literal.int;
    const ncols = items.kind === "all" ? BigInt(scope.width()) : BigInt(items.items.length);
    if (n < 1n || n > ncols) {
      throw engineError("invalid_column_reference", `GROUP BY position ${n} is not in select list`);
    }
    const pos = Number(n - 1n);
    if (items.kind === "all") {
      // `SELECT *` — the ordinal names the column at that scope position directly.
      return { kind: "column", index: pos };
    }
    return resolveGroupExpr(scope, items.items[pos]!.expr, params);
  }
  return resolveGroupNamed(scope, term, items, params);
}

// resolveGroupNamed resolves a non-ordinal grouping term: a bare/qualified column, an output alias,
// or a general expression (aggregates.md §15). A bare name resolves an INPUT column FIRST, then —
// only if there is no such column — an output alias (PG's rule, the opposite of ORDER BY's
// output-first rule).
export function resolveGroupNamed(
  scope: Scope,
  term: Expr,
  items: SelectItems,
  params: ParamTypes,
): GroupKeyResolved {
  if (term.kind === "column") {
    let r: Resolved;
    try {
      r = scope.resolveBare(term.name);
    } catch (e) {
      // No input column of this name: try an output alias (`SELECT a+b AS s … GROUP BY s`). If none
      // matches either, propagate the original 42703.
      if (e instanceof EngineError && e.state === "undefined_column") {
        const aexpr = orderAliasMatch(items, term.name, scope);
        if (aexpr !== null) return resolveGroupExpr(scope, aexpr, params);
      }
      throw e;
    }
    if (r.level !== 0) {
      throw engineError(
        "feature_not_supported",
        "GROUP BY may not reference an outer query column",
      );
    }
    return { kind: "column", index: r.index };
  }
  if (term.kind === "qualifiedColumn") {
    const r = scope.resolveQualified(term.qualifier, term.name);
    if (r.level !== 0) {
      throw engineError(
        "feature_not_supported",
        "GROUP BY may not reference an outer query column",
      );
    }
    return { kind: "column", index: r.index };
  }
  return resolveGroupExpr(scope, term, params);
}

// resolveGroupExpr resolves a grouping expression (the target of an ordinal/alias, or a general
// `GROUP BY a+b`). A plain column expression stays a COLUMN key (so the projection's bare-column path
// matches it); anything else is MATERIALIZED — resolved against the input row with aggregates
// forbidden (an aggregate in GROUP BY is 42803), its canonical AST kept for projection matching
// (aggregates.md §15).
export function resolveGroupExpr(scope: Scope, e: Expr, params: ParamTypes): GroupKeyResolved {
  if (e.kind === "column") {
    const r = scope.resolveBare(e.name);
    if (r.level === 0) return { kind: "column", index: r.index };
  } else if (e.kind === "qualifiedColumn") {
    const r = scope.resolveQualified(e.qualifier, e.name);
    if (r.level === 0) return { kind: "column", index: r.index };
  }
  const sub: AggCtx = { collecting: false, groupKeys: [], specs: [] };
  const { node, type } = resolve(scope, e, null, sub, params);
  return { kind: "expr", node, ty: type, canon: e };
}

// matchGroupExpr returns the synthetic key slot (master position) and resolved type if e structurally
// matches a general-expression GROUP BY key in this aggregate context (aggregates.md §15). Only fires
// in a collecting context with groupKeyExprs; an aggregate operand / FILTER resolves under Forbidden
// (no groupKeyExprs), so a grouping expression there is correctly NOT remapped (it is a per-row
// value, not the group key).
export function matchGroupExpr(ag: AggCtx, e: Expr): { slot: number; ty: ResolvedType } | null {
  const gke = ag.groupKeyExprs;
  if (gke === undefined) return null;
  for (let p = 0; p < gke.length; p++) {
    const gk = gke[p];
    if (gk !== null && gk !== undefined && exprEqual(gk.canon, e)) return { slot: p, ty: gk.ty };
  }
  return null;
}

// groupingValue computes a GROUPING(args) result for a group from the grouping set whose mask is
// given: bit (k-1-j) of the result is bit positions[j] of mask (spec/design/aggregates.md §12).
export function groupingValue(positions: number[], mask: bigint): bigint {
  const k = positions.length;
  let r = 0n;
  for (let j = 0; j < k; j++) {
    const bit = (mask >> BigInt(positions[j]!)) & 1n;
    r |= bit << BigInt(k - 1 - j);
  }
  return r;
}

// rebaseWindowResults rewrites a grouped+window projection's window-result placeholder slots to their
// real grouped-row slot (spec/design/window.md §5.1). During resolution a window result of index w is
// assigned the placeholder WINDOW_RESULT_BASE+w, because its real slot
// groupKeys.length+aggSpecs.length+w is unknown until every aggregate (including any nested in a later
// window argument or HAVING) has been collected. It descends into a subquery's lhs (current row space)
// but NOT its plan (those columns index the subquery's own rows; a nested grouped+window plan was
// already rebased when it was built). Mirrors collectTouched's variant coverage.
//
// The rewrite is bounded to slots in [from, 2·from): each placeholder base is 2× the previous
// (WINDOW_RESULT_BASE=2**28, WINDOW_KEY_BASE=2**29, GROUPING_GS_BASE=2**30) and a base's placeholder
// count is far below that gap, so bounding to [from, 2·from) keeps the bases isolated — a
// window-result rebase no longer clobbers a GROUPING() placeholder (the two now COEXIST in a
// GROUPING SETS + window query — aggregates.md §21).
export function rebasePlaceholderCols(e: RExpr, from: number, target: number): void {
  switch (e.kind) {
    case "column":
      if (e.index >= from && e.index < from * 2) e.index = target + (e.index - from);
      return;
    case "outerColumn":
      return;
    case "subquery":
      if (e.lhs !== null) rebasePlaceholderCols(e.lhs, from, target); // current row space only; not the plan
      return;
    case "inValues":
      rebasePlaceholderCols(e.lhs, from, target);
      return;
    case "quantified":
      rebasePlaceholderCols(e.lhs, from, target);
      rebasePlaceholderCols(e.array, from, target);
      return;
    case "cast":
    case "arrayCast":
    case "neg":
    case "not":
    case "isNull":
    case "isJson":
    case "jsonCtor":
      rebasePlaceholderCols(e.operand, from, target);
      return;
    case "arith":
    case "compare":
    case "and":
    case "or":
    case "distinct":
    case "like":
    case "regex":
      rebasePlaceholderCols(e.lhs, from, target);
      rebasePlaceholderCols(e.rhs, from, target);
      return;
    case "casing":
      rebasePlaceholderCols(e.arg, from, target);
      return;
    case "atTimeZone":
      rebasePlaceholderCols(e.zone, from, target);
      rebasePlaceholderCols(e.value, from, target);
      return;
    case "dateTrunc":
      rebasePlaceholderCols(e.unit, from, target);
      rebasePlaceholderCols(e.value, from, target);
      if (e.zone !== null) rebasePlaceholderCols(e.zone, from, target);
      return;
    case "extract":
      rebasePlaceholderCols(e.value, from, target);
      return;
    case "dateConvert":
      rebasePlaceholderCols(e.inner, from, target);
      return;
    case "case":
      for (const arm of e.arms) {
        rebasePlaceholderCols(arm.cond, from, target);
        rebasePlaceholderCols(arm.result, from, target);
      }
      rebasePlaceholderCols(e.els, from, target);
      return;
    case "greatestLeast":
    case "coalesce":
    case "scalarFunc":
    case "arrayFunc":
    case "regexFunc":
    case "rangeFunc":
    case "rangeCtor":
    case "rangeOp":
    case "rangeSetOp":
    case "variadic":
    case "jsonBuild":
    case "jsonSetInsert":
    case "jsonObjectFromArrays":
    case "jsonPathFn":
    case "jsonSqlFn":
      for (const a of e.args) rebasePlaceholderCols(a, from, target);
      return;
    case "jsonGet":
    case "jsonHasKey":
    case "jsonDelete":
      rebasePlaceholderCols(e.base, from, target);
      rebasePlaceholderCols(e.arg, from, target);
      return;
    case "jsonContains":
    case "jsonConcat":
      rebasePlaceholderCols(e.a, from, target);
      rebasePlaceholderCols(e.b, from, target);
      return;
    case "row":
      for (const f of e.fields) rebasePlaceholderCols(f, from, target);
      return;
    case "array":
      for (const el of e.elements) rebasePlaceholderCols(el, from, target);
      return;
    case "field":
      rebasePlaceholderCols(e.base, from, target);
      return;
    case "subscript":
      rebasePlaceholderCols(e.base, from, target);
      for (const b of rSubscriptBounds(e.subscripts)) rebasePlaceholderCols(b, from, target);
      return;
    default: // leaves: param, const*
  }
}

// valueToRExpr builds the constant rExpr for a folded subquery value (§26). The static type is
// carried separately (the node's type), so a NULL value here is just constNull.
export function valueToRExpr(v: Value): RExpr {
  switch (v.kind) {
    case "int":
      return { kind: "constInt", value: v.int };
    case "f32":
      return { kind: "constFloat", ty: "f32", value: v.value };
    case "f64":
      return { kind: "constFloat", ty: "f64", value: v.value };
    case "bool":
      return { kind: "constBool", value: v.value };
    case "text":
      return { kind: "constText", value: v.text };
    case "decimal":
      return { kind: "constDecimal", value: v.dec };
    case "bytea":
      return { kind: "constBytea", value: v.bytes };
    case "uuid":
      return { kind: "constUuid", value: v.bytes };
    case "timestamp":
      return { kind: "constTimestamp", value: v.micros };
    case "timestamptz":
      return { kind: "constTimestamptz", value: v.micros };
    case "date":
      return { kind: "constDate", value: v.days };
    case "interval":
      return { kind: "constInterval", value: v.iv };
    case "json":
      return { kind: "constJson", value: v.text };
    case "jsonb":
      return { kind: "constJsonb", value: v.node };
    case "jsonpath":
      return { kind: "constJsonPath", value: v.text };
    case "composite":
      // A folded composite constant: fold each field and wrap in a ROW node so eval rebuilds the
      // composite value (spec/design/composite.md).
      return { kind: "row", fields: v.fields.map(valueToRExpr) };
    case "array":
      // A folded array constant — preserve its full shape (dims/lbounds) in a const node.
      return { kind: "constArray", value: v };
    case "range":
      // A folded range constant (already canonical).
      return { kind: "constRange", value: v };
    default:
      return { kind: "constNull" };
  }
}

// distinctRowKey encodes a projected row into a collision-free string key for DISTINCT
// dedup. Each field carries a type tag (n/i/b) and a payload, joined by a separator no
// field can contain, so e.g. (1,23) and (12,3) do not collide (spec/design/grammar.md §11).
// NULL == NULL falls out (both encode "n"), matching the NULL-safe DISTINCT rule. Ints use
// bigint.toString() — exact, never the lossy `number` path (CLAUDE.md §8).
export function distinctRowKey(row: Value[]): string {
  return row.map(distinctValueKey).join("|");
}

// distinctValueKey encodes one value into a collision-free string key for DISTINCT/GROUP BY dedup
// (spec/design/grammar.md §11). A composite recurses element-wise under a length-prefixed 'c' tag,
// so composites group/dedup structurally — NULL-safe, with NULL fields included (spec/design/composite.md
// §5). Shared by distinctRowKey (which joins the per-field keys with a separator no scalar key can
// contain).
export function distinctValueKey(v: Value): string {
  switch (v.kind) {
    case "composite":
      // Length-prefix the field count and each field's key so a composite never collides with a
      // scalar key and nested composites stay unambiguous.
      return (
        "c" + v.fields.length.toString() + ":" + v.fields.map((f) => distinctValueKey(f)).join(",")
      );
    case "array":
      // An array keys structurally INCLUDING its shape (spec/design/array.md §5): the dims and
      // lower bounds (so [2:4]={1,2,3} and {1,2,3} bucket apart — array_eq considers them), then
      // each element's own key. NULL elements key as 'n' (btree equality — NULLs mutually equal).
      return (
        "a" +
        v.dims.join(":") +
        ";" +
        v.lbounds.join(";") +
        "=" +
        v.elements.map((el) => distinctValueKey(el)).join(",")
      );
    case "range":
      // A range keys structurally over its CANONICAL form (spec/design/ranges.md §6): the empty
      // flag, the inclusivity flags, and each bound's own key (an infinite/null bound keys as
      // 'n', like a NULL array element). Two equal canonical ranges have identical fields, so
      // this buckets exactly like the range_cmp equality. The 'r' tag + flag chars keep it
      // collision-free against scalar/array keys.
      if (v.empty) return "re";
      return (
        "r" +
        (v.lowerInc ? "[" : "(") +
        (v.upperInc ? "]" : ")") +
        (v.lower === null ? "n" : distinctValueKey(v.lower)) +
        "," +
        (v.upper === null ? "n" : distinctValueKey(v.upper))
      );
    case "json":
      // json keys verbatim under a distinct 'j' tag (json is not SQL-comparable, but a value-level
      // dedup key keeps a DISTINCT over a json literal collision-free — spec/design/json.md §4).
      return "j" + v.text.length.toString() + ":" + v.text;
    case "jsonb":
      // jsonb keys by its canonical render under a distinct 'J' tag — the canonical form makes the
      // text a pure function of the value, so jsonNodeCmp-equal values share a key (§5).
      return "J" + jsonbOut(v.node);
    case "jsonpath":
      // jsonpath is not SQL-comparable (42883 at resolve), but a value-level dedup key under a
      // distinct 'p' tag keeps it collision-free (mirrors the Rust Hash impl — spec/design/jsonpath.md).
      return "p" + v.text.length.toString() + ":" + v.text;
    case "null":
      return "n";
    case "int":
      return "i" + v.int.toString();
    case "bool":
      return v.value ? "b1" : "b0";
    case "text":
      // Length-prefix the content so the separator byte cannot be confused with a text
      // value that contains it (the value is arbitrary UTF-8).
      return "t" + v.text.length.toString() + ":" + v.text;
    case "decimal":
      // Value-canonical key so 1.5 and 1.50 collapse to one DISTINCT bucket (decimal.md §5).
      return "d" + v.dec.canonicalString();
    case "bytea":
      // A distinct 'y' tag over the hex form (collision-free), so a bytea never collides
      // with a text value of the same bytes.
      return "y" + renderByteaHex(v.bytes);
    case "uuid":
      // A distinct 'u' tag over the canonical form, so a uuid never collides with a
      // bytea/text of the same bytes.
      return "u" + renderUuid(v.bytes);
    case "timestamp":
      // The i64 microsecond instant under a distinct 's' tag: two literals for the same
      // instant (12:00:00 and 12:00:00.0) share micros and bucket together; the infinity
      // sentinels are ordinary int values with their own buckets.
      return "s" + v.micros.toString();
    case "timestamptz":
      // The i64 UTC-instant micros under a distinct 'z' tag: offsets are normalized to UTC
      // at parse, so +00 and +05-of-the-same-instant bucket together.
      return "z" + v.micros.toString();
    case "interval":
      // The canonical 128-bit span as a decimal string under a distinct 'v' tag, so
      // span-equal intervals ('1 mon' / '30 days' / '720:00:00') collapse to one DISTINCT/
      // GROUP BY bucket while each value renders its own fields (spec/design/interval.md §2).
      return "v" + intervalSpan(v.iv).toString();
    case "f32":
    case "f64":
      // The TOTAL-order canonical key so -0 and +0 collapse to one bucket and all NaNs to one
      // (float.md §3): canonicalize -0 → +0, map every NaN to a single sentinel string. Distinct
      // tags 'f'/'g' per width so a f32 never collides with a f64 of the same number
      // (they are different typed columns; the tag keeps the key total). The number's toString
      // is the shortest round-trip — unique per binary value, so distinct values get distinct
      // keys after the -0/NaN normalization.
      return (
        (v.kind === "f32" ? "f" : "g") +
        (Number.isNaN(v.value) ? "NaN" : renderFloat(canonFloat(v.value)))
      );
    default:
      // unfetched never reaches a projected dedup row (the scan layer resolves touched columns).
      throw new Error("BUG: unfetched large value escaped the storage layer");
  }
}

// ============================================================================
// Resolved expression layer (mirrors impl/rust executor.rs, impl/go executor.go).
//
// Parse → Expr (names) → resolve → RExpr (column indices, known result types, folded
// constants) → eval per row → Value. The resolver is where all type-checking and the
// literal range-check live; the evaluator is a pure tree-walk. eval throws on a 22003 /
// 22012 (the TS idiom), so callers need no Result type.
// ============================================================================

// ResolvedType is the static type of a resolved expression. "null" is an untyped NULL
// literal (its integer type, if needed, is settled by the surrounding operator/context).
export type ResolvedType =
  | { kind: "int"; ty: ScalarType }
  // The float family (spec/design/float.md): ty is f32 or f64. A strict island — no
  // implicit cross-family coercion (int/decimal ⊕ float is 42804); within-family widening
  // (f32 → f64) is the only implicit edge. ty carries the width so arithmetic rounds
  // at the right precision (Math.fround for f32) and the on-disk codec picks the codec.
  | { kind: "float"; ty: ScalarType }
  | { kind: "bool" }
  | { kind: "text" } // the text family (one collation, C); does not promote
  | { kind: "decimal" } // the decimal family (one type; the per-column typmod is separate)
  | { kind: "bytea" } // the bytea family (raw bytes); does not promote
  | { kind: "uuid" } // the uuid family (fixed 16 bytes); does not promote. The first non-integer key.
  | { kind: "timestamp" } // zoneless instant; does not compare/cast to timestamptz
  | { kind: "timestamptz" } // UTC instant; does not compare/cast to timestamp
  | { kind: "date" } // calendar date (i32 days); strict island, no compare/cast to timestamp
  | { kind: "interval" } // a span; compares only with itself, by the canonical span
  // The json family (verbatim text — spec/design/json.md §4). NOT comparable (PG ships no btree/hash
  // opclass — §5): a comparison/ORDER BY/DISTINCT on json resolves to 42883.
  | { kind: "json" }
  // The jsonb family (canonical binary — spec/design/json.md §2). Comparable with itself by PG's
  // total btree order (§5).
  | { kind: "jsonb" }
  // The jsonpath type (spec/design/jsonpath.md, P1a). NOT comparable (42883); literal-only.
  | { kind: "jsonpath" }
  // A composite (row) type (spec/design/composite.md §5). `name` is non-null for a named catalog
  // type — rendered in the `# types:` output and the basis for cross-comparability — or null for an
  // anonymous ROW(...) result. `fields` are the resolved (name, type) pairs in declaration order
  // (the basis for field access — S4 — and structural assignability).
  | {
      kind: "composite";
      name: string | null;
      fields: { name: string; type: ResolvedType }[];
    }
  // An array type (spec/design/array.md §2), carrying its resolved element type. Two arrays are
  // comparable iff their element types are comparable; assignable to an array column of the same
  // element type.
  | { kind: "array"; elem: ResolvedType }
  // A range type (spec/design/ranges.md §2), carrying its resolved element (subtype) type. Two
  // ranges are comparable iff their elements are equal; the element is one of the six scalar subtypes.
  | { kind: "range"; elem: ResolvedType }
  | { kind: "null" };

// RSubscript is one resolved subscript spec in a "subscript" RExpr (spec/design/array.md §6): an
// index `a[i]`, or a slice `a[m:n]` whose bounds may be null (omitted: `a[:n]`/`a[m:]`/`a[:]`).
export type RSubscript =
  | { isSlice: false; index: RExpr }
  | { isSlice: true; lower: RExpr | null; upper: RExpr | null };

// RExpr is a resolved expression over fixed column indices. Arithmetic/neg nodes carry
// their (promotion-tower) result type so the computed value can be range-checked.
export type RExpr =
  | { kind: "column"; index: number }
  // A bind parameter, by 0-based index into the bound-values array passed to evalExpr. Its
  // static type was inferred from context at resolve (spec/design/api.md §5); the value is
  // supplied (and coerced) before evaluation.
  | { kind: "param"; index: number }
  | { kind: "constInt"; value: bigint }
  // A float constant: `ty` is the width (f32/f64); for f32 `value` is already
  // Math.fround'd (spec/design/float.md §4).
  | { kind: "constFloat"; ty: ScalarType; value: number }
  | { kind: "constBool"; value: boolean }
  | { kind: "constText"; value: string }
  | { kind: "constDecimal"; value: Decimal }
  | { kind: "constBytea"; value: Uint8Array }
  | { kind: "constUuid"; value: Uint8Array }
  | { kind: "constTimestamp"; value: bigint }
  | { kind: "constTimestamptz"; value: bigint }
  | { kind: "constDate"; value: bigint }
  | { kind: "constInterval"; value: Interval }
  // A json constant — JSON text stored VERBATIM (spec/design/json.md §4), validated well-formed at
  // resolve.
  | { kind: "constJson"; value: string }
  // A jsonb constant — the canonical tagged-node tree (spec/design/json.md §2), parsed + canonicalized
  // at resolve.
  | { kind: "constJsonb"; value: JsonNode }
  // A jsonpath constant — the canonical normalized source text (spec/design/jsonpath.md, P1a),
  // compiled + rendered at resolve.
  | { kind: "constJsonPath"; value: string }
  | { kind: "constNull" }
  // A ROW(...) constructor (spec/design/composite.md §1): evaluate each field and assemble a
  // composite value. Also the folded form of a composite constant (valueToRExpr wraps each field's
  // constant). One operator_eval per node (cost.md §9).
  | { kind: "row"; fields: RExpr[] }
  // An ARRAY[...] constructor (spec/design/array.md §1): evaluate each element and assemble an array
  // value. `nested` stacks sub-arrays into one higher dimension (§4). One operator_eval per node.
  | { kind: "array"; elements: RExpr[]; nested: boolean }
  // A folded array constant (the valueToRExpr form), preserving its shape; evaluates to it directly.
  | { kind: "constArray"; value: Value }
  // A folded range constant ('[1,5)'::i32range, already canonicalized); evaluates to it directly.
  | { kind: "constRange"; value: Value }
  // Field selection `(composite).field` (spec/design/composite.md §S4): evaluate `base` to a
  // composite value and return its `index`-th field (the field ordinal, fixed at resolve). A
  // whole-value-NULL composite yields NULL for any field. One operator_eval per node.
  | { kind: "field"; base: RExpr; index: number }
  // Array subscript `base[..][..]` (spec/design/array.md §6): one or more subscript specs applied to
  // `base`. All-index access reads one element (NULL when the subscript count ≠ ndim or any index is
  // out of range); a slice (any spec a slice) returns a sub-array, with a scalar index i meaning 1:i.
  // A NULL array or any NULL bound yields NULL. One operator_eval per node.
  | {
      kind: "subscript";
      base: RExpr;
      subscripts: RSubscript[];
      isSlice: boolean;
    }
  | {
      kind: "cast";
      target: ScalarType;
      typmod: DecimalTypmod | null;
      // A varchar(n) text target's max length — truncate the result to n code points (the
      // explicit-cast rule, spec/design/types.md §15). null for any non-text / unbounded target.
      varcharLen: number | null;
      operand: RExpr;
    }
  // A cast that INVOLVES an array type (spec/design/array.md §7), none expressible by the scalar
  // `cast` node (whose `target` is a ScalarType): runtime text → T[] (array_in per row), array →
  // text (array_out per row), and element-wise array → other-element-array (each element through the
  // scalar cast). `toElem` is the target element ColType for the two array-producing casts and null
  // for array → text; the eval branches on the runtime value (text vs array).
  | { kind: "arrayCast"; toElem: ColType | null; operand: RExpr }
  | { kind: "neg"; result: ScalarType; operand: RExpr }
  | { kind: "not"; operand: RExpr }
  | { kind: "arith"; op: BinaryOp; result: ScalarType; lhs: RExpr; rhs: RExpr }
  // The derived collation (spec/design/collation.md §7): null is the C / default byte order (the
  // unchanged fast path); a non-null collation orders the ORDERING comparisons (< <= > >=) by its UCA
  // sort key. =/<> stay byte-equality (deterministic-collation equality IS byte-identity), but it is
  // derived + conflict-checked (42P21) for every comparison op.
  | {
      kind: "compare";
      op: BinaryOp;
      lhs: RExpr;
      rhs: RExpr;
      collation: Collation | null;
    }
  | { kind: "and"; lhs: RExpr; rhs: RExpr }
  | { kind: "or"; lhs: RExpr; rhs: RExpr }
  // A jsonb accessor operator (`-> ->> #> #>>`, spec/design/json-sql-functions.md §1, J4). `op`
  // selects field/index vs path and text-vs-jsonb; `base` evaluates to a jsonb document; `arg` is
  // the key (text), array index (integer), or path (`text[]`). The result is jsonb (`-> #>`) or
  // text (`->> #>>`), and is SQL NULL when the access misses (or when base/arg is NULL — strict).
  | { kind: "jsonGet"; op: JsonGetOp; base: RExpr; arg: RExpr }
  // `a @> b` jsonb deep containment (spec/design/json-sql-functions.md §1, J5) — does `a` contain
  // `b`. `<@` resolves to this with the operands swapped. Boolean; strict (a NULL operand → NULL).
  | { kind: "jsonContains"; a: RExpr; b: RExpr }
  // `jsonb ? text` / `?| text[]` / `?& text[]` key-existence (spec/design/json-sql-functions.md §1,
  // J5). `hasKeyKind` selects one-key / any-key / all-keys. Boolean; strict.
  | { kind: "jsonHasKey"; hasKeyKind: HasKeyKind; base: RExpr; arg: RExpr }
  // `a || b` jsonb concatenate / shallow-merge (spec/design/json-sql-functions.md §1, J6). Result
  // jsonb; strict (a NULL operand → SQL NULL).
  | { kind: "jsonConcat"; a: RExpr; b: RExpr }
  // `jsonb - text|int|text[]` (delete key/index/keys) and `jsonb #- text[]` (delete at path) — the J6
  // mutation deletes (spec/design/json-sql-functions.md §1). `deleteKind` selects the form; `base` is
  // the jsonb document, `arg` the key/index/key-array/path. Result jsonb; strict; a delete from a
  // scalar (or an integer index into an object) is `22023`.
  | { kind: "jsonDelete"; deleteKind: DeleteKind; base: RExpr; arg: RExpr }
  | { kind: "isNull"; operand: RExpr; negated: boolean }
  // `operand IS [NOT] JSON …` (json-sql-functions.md §5): well-formedness + optional kind /
  // unique-keys test over a string / json / jsonb operand. A NULL operand → NULL; else a definite
  // boolean (NOT-negated when `negated`).
  | {
      kind: "isJson";
      operand: RExpr;
      negated: boolean;
      jsonKind: JsonPredicateKind;
      uniqueKeys: boolean;
    }
  // `JSON(text [(WITH|WITHOUT) UNIQUE [KEYS]])` (json-sql-functions.md §5): validate a string as a
  // `json` value (verbatim). Malformed → 22P02; `WITH UNIQUE KEYS` on a duplicate key → 22030.
  // STRICT (a NULL operand → SQL NULL).
  | { kind: "jsonCtor"; operand: RExpr; uniqueKeys: boolean }
  | { kind: "distinct"; lhs: RExpr; rhs: RExpr; negated: boolean }
  | { kind: "like"; lhs: RExpr; rhs: RExpr; negated: boolean; insensitive: boolean }
  // `lhs ~ rhs` / `~*` / `!~` / `!~*` — regex match (regex.md), matched by the hand-written Pike VM
  // (regex.ts). `program` is the precompiled NFA for a CONSTANT pattern (compiled once at resolve,
  // the `col ~ 'literal'` case — regex.md §5); null means the pattern is non-constant (compiled per
  // row at eval). `compileCharged` is the one-shot flag charging a precompiled program's
  // regex_compile cost once per statement execution (on first eval), not per row.
  | {
      kind: "regex";
      lhs: RExpr;
      rhs: RExpr;
      negated: boolean;
      insensitive: boolean;
      program: RegexProgram | null;
      compileCharged: boolean;
    }
  // upper(text)/lower(text) — Unicode case folding (collation.md §16). upper selects the direction;
  // folds via the engine-global property table or the ASCII baseline. A NULL operand propagates.
  | { kind: "casing"; upper: boolean; arg: RExpr }
  | { kind: "atTimeZone"; zone: RExpr; value: RExpr; toTimestamptz: boolean }
  // date_trunc(unit, value[, zone]) (timezones.md §9.1): truncate value down to unit. For a
  // timestamptz value the truncation is in zone (3-arg) or the session zone (2-arg). The result
  // family is the value family.
  | { kind: "dateTrunc"; unit: RExpr; value: RExpr; zone: RExpr | null }
  // EXTRACT(field FROM value) (timezones.md §9.2): the numeric value of field (lowercased, validated
  // at resolve). For a timestamptz value every field but `epoch` is computed in the session zone.
  | { kind: "extract"; field: string; value: RExpr }
  // A cross-family datetime cast (timezones.md §9.3) to `to` (timestamp/timestamptz/date) from
  // another datetime family — or the runtime text → date cast (date.md §6). The casts crossing
  // the timestamptz boundary consult the session zone.
  | { kind: "dateConvert"; inner: RExpr; to: ScalarType }
  // A clock-relative date literal — 'today'/'now' (0), 'tomorrow' (+1), 'yesterday' (−1) —
  // resolved to a STABLE node, never folded (date.md §6): at eval it reads the STATEMENT clock
  // (once per statement, like now()) and takes its day in the SESSION zone (charging timezone),
  // shifted by offsetDays. Flagged non-immutable at birth (42P17 in an index expression).
  // 'epoch' is not this node — it folds to the constant 1970-01-01.
  | { kind: "dateClock"; offsetDays: bigint }
  | {
      kind: "case";
      arms: { cond: RExpr; result: RExpr }[];
      els: RExpr;
      coerceDecimal: boolean;
    }
  // A resolved COALESCE(a, b, …) (grammar.md §51) — lazy like `case`: arguments are evaluated
  // left to right, each at most once, stopping at the first non-NULL (the second sanctioned
  // short-circuit, cost.md §3). Argument types unify exactly like CASE result arms;
  // `coerceDecimal` widens integer arguments when the unified type is decimal.
  | { kind: "coalesce"; args: RExpr[]; coerceDecimal: boolean }
  // A resolved GREATEST(a, b, …) / LEAST(a, b, …) (grammar.md §52) — the variadic max/min. EAGER
  // (unlike `coalesce`): every argument is evaluated. NULL arguments are ignored; the result is
  // NULL only when every argument is NULL. `greatest` selects max vs min; the winner is chosen by
  // the unified type's total order (valueCmp). `coerceDecimal` widens integer arguments when the
  // unified type is decimal.
  | {
      kind: "greatestLeast";
      args: RExpr[];
      coerceDecimal: boolean;
      greatest: boolean;
      collation: Collation | null;
    }
  // A scalar-function call (spec/design/functions.md §9, float.md §8), evaluated per row in any
  // context. `result` is the static result type — for abs over an integer/float it is the
  // operand's own type (range-checked / fround'd at that width), for round over int/decimal it is
  // decimal, and for the float math functions (ceil/floor/.../sqrt/exp/.../tan) it is f64 per
  // the catalog (only abs is operand-typed). `argWidth` carries the operand's float width so the
  // evaluator can Math.fround a f32 result of abs (the only width-preserving float func).
  | {
      kind: "scalarFunc";
      func: ScalarFuncName;
      args: RExpr[];
      result: ScalarType;
      argWidth?: ScalarType;
    }
  // A polymorphic array-function call (spec/design/array-functions.md §3), evaluated per row.
  // Distinct from "scalarFunc": it resolves over anyarray/anyelement (§2) and its builders return an
  // array; the result type lives in the surrounding ResolvedType (carried out of resolve), not on the
  // node. NULL handling is per-kernel (the introspectors propagate, the builders are non-strict), so
  // — unlike "scalarFunc" — there is no blanket NULL short-circuit at eval.
  | { kind: "arrayFunc"; func: ArrayFuncName; args: RExpr[] }
  // A polymorphic range-accessor call (spec/design/range-functions.md §1, RF1), evaluated per row.
  // Like "arrayFunc", it resolves over a pseudo-family (anyrange, binding ELEM := the element type)
  // and the result type lives in the surrounding ResolvedType (carried out of resolve), not on the
  // node; the kernel recovers everything from the operand range value (self-describing). All are
  // STRICT (a NULL range → NULL), handled in the eval kernel.
  | { kind: "rangeFunc"; func: RangeFuncName; args: RExpr[] }
  // A regex scalar function (spec/design/regex.md §8 — regexp_replace → text, regexp_match → text[]).
  // Like "arrayFunc" the result type lives in the surrounding ResolvedType. STRICT (a NULL arg →
  // NULL). `program` is the precompiled NFA for a constant pattern (regex.md §5), `compileCharged`
  // the one-shot flag charging its regex_compile cost once per execution.
  | {
      kind: "regexFunc";
      func: "replace" | "match" | "like" | "count" | "substr" | "instr";
      args: RExpr[];
      program: RegexProgram | null;
      compileCharged: boolean;
    }
  // A range CONSTRUCTOR call (spec/design/range-functions.md §2 — `i32range(lo, hi[, bounds])` and
  // the five siblings, plus the int4range/int8range aliases). `elem` is the range's element scalar
  // (the result range type is recovered from it, a bijection); `args` are the 2 bounds plus an
  // optional bounds-flags TEXT. Non-strict (null = "none"): a NULL bound is an infinite bound,
  // handled in the kernel. The kernel coerces each bound to `elem` (assignment-style), reads the
  // bounds flags, and finalizes (canonicalize / order-check / empty-normalize).
  | { kind: "rangeCtor"; elem: ScalarType; args: RExpr[] }
  // A range BOOLEAN operator (spec/design/range-functions.md §3 — `@> <@ && << >> &< &> -|-`).
  // `args` are the two operands. STRICT: a NULL operand → NULL (handled in the eval arm). `elem` is
  // the range's element scalar — used only by the "containsElem"/"elemContainedBy" element overloads
  // to coerce the bare-element operand to the range's element type at eval; unused (but carried) for
  // the range-against-range operators.
  | { kind: "rangeOp"; op: RangeOpName; args: RExpr[]; elem: ScalarType }
  // A range SET operator (spec/design/range-functions.md §4 — `+` union, `-` difference, `*`
  // intersection, and range_merge). `args` are the two range operands. STRICT: a NULL operand → NULL
  // (handled in the eval arm). Unlike "rangeOp" it carries no element scalar — the kernels work off
  // the self-describing operand values, and the result range type is fixed at resolve. The kernels
  // (rangeUnion/rangeIntersect/rangeMinus) live in range.ts; `+`/`-` raise 22000 on a non-contiguous
  // result.
  | { kind: "rangeSetOp"; op: RangeSetOpName; args: RExpr[] }
  // A VARIADIC argument-counting call (spec/design/array-functions.md §12 — num_nulls/num_nonnulls).
  // Non-strict (null = "none"), like "arrayFunc": no blanket NULL short-circuit. `arrayForm` records
  // the call shape — false = the spread form (count `args`' null-ness directly, never NULL); true =
  // the VARIADIC-array form (one `args` operand — a NULL array → NULL, else count its flattened
  // elements' null-ness). Result is always i32.
  | {
      kind: "variadic";
      func: VariadicFuncName;
      args: RExpr[];
      arrayForm: boolean;
    }
  // A VARIADIC json/jsonb builder (json-sql-functions.md §2 — json[b]_build_array / _object).
  // Non-strict: a NULL argument is included as JSON null (array) or a value (object). `json` selects
  // the json (compact / PG builder-spacing) vs jsonb (canonical) render; `arrayForm` records the
  // VARIADIC-array call shape (the lone array operand is spread; a NULL array → SQL NULL). The result
  // type (json/jsonb) lives in the surrounding ResolvedType (carried out of resolve), not on the node.
  | {
      kind: "jsonBuild";
      buildKind: JsonBuildKind;
      json: boolean;
      args: RExpr[];
      arrayForm: boolean;
    }
  // `jsonb_set` / `jsonb_insert` (json-sql-functions.md §2): a jsonb path mutation. `args` is
  // `[target jsonb, path text[], value jsonb, flag boolean]` — STRICT (any NULL → SQL NULL). `mode`
  // selects replace-or-create ("set") vs insert ("insert"); the boolean flag is create_if_missing
  // (set) / insert_after (insert), defaulting to true / false respectively (supplied at resolve).
  | {
      kind: "jsonSetInsert";
      mode: PathSetMode;
      args: RExpr[];
    }
  // `json_object` / `jsonb_object` (json-sql-functions.md §2): build an object from text array(s).
  // `args` is one `text[]` of alternating keys/values, or two `text[]` (keys, values). The VALUES are
  // always JSON strings (a NULL value → JSON null); a NULL key → 22004. STRICT in the whole array
  // argument(s). `json` selects the json (insertion order + dups + " : " spacing) vs jsonb (canonical)
  // result.
  | {
      kind: "jsonObjectFromArrays";
      json: boolean;
      args: RExpr[];
    }
  // A scalar jsonpath query function (P2, jsonpath.md §5): jsonb_path_exists / jsonb_path_query_first
  // / jsonb_path_query_array. `args` = `[ctx jsonb, path jsonpath]`; STRICT (any NULL → SQL NULL).
  // The path is recompiled from its canonical text at eval.
  | {
      kind: "jsonPathFn";
      pathFnKind: JsonPathFnKind;
      args: RExpr[];
    }
  // A SQL/JSON query function `JSON_EXISTS` / `JSON_VALUE` / `JSON_QUERY` (json-sql-functions.md §5,
  // S2). `args` = `[ctx, path]` (the SRF-style arg list, so the generic RExpr walks recurse for
  // free): `ctx` produces the context jsonb (or json/text, coerced), `path` the jsonpath; the
  // behaviors / wrapper / quotes drive the result. The result type is fixed at resolve.
  | {
      kind: "jsonSqlFn";
      sqlKind: JsonSqlKind;
      args: RExpr[];
      // The RETURNING scalar type ("boolean" for JSON_EXISTS; the JSON_VALUE scalar target;
      // "jsonb"/"json" for JSON_QUERY) — drives the result coercion.
      returning: ScalarType;
      decimal: DecimalTypmod | null;
      wrapper: JsonWrapper;
      keepQuotes: boolean;
      onEmpty: JsonOnBehavior;
      onError: JsonOnBehavior;
    }
  // A correlated column reference (spec/design/grammar.md §26): column `index` of the enclosing
  // row `level` hops out (1 = immediate parent). A leaf — reads from the outer-row environment.
  | { kind: "outerColumn"; level: number; index: number }
  // A CORRELATED subquery, re-executed once per outer row at eval (uncorrelated ones are folded to
  // a constant / inValues before exec). `lhs`/`negated` apply to the IN form.
  | {
      kind: "subquery";
      plan: QueryPlan;
      subKind: SubqueryKind;
      lhs: RExpr | null;
      negated: boolean;
      // For subKind "quantified" (array-functions.md §11.6): the comparison op + ALL flag, so the
      // body's single column folds through quantifiedMembership exactly like the array form.
      op?: BinaryOp;
      all?: boolean;
    }
  // A folded uncorrelated `IN (subquery)`: the subquery ran once yielding `list`; per row it tests
  // `lhs` for three-valued membership (empty → negated; a NULL with no positive match → NULL).
  | { kind: "inValues"; lhs: RExpr; list: Value[]; negated: boolean }
  // A quantified array comparison `lhs op ANY/ALL(array)` (spec/design/array-functions.md §11) — the
  // array spelling of IN. At eval `lhs` is evaluated once, `array` once; then a 3-valued fold over the
  // array's flattened elements (ANY = OR-fold, ALL = AND-fold), charging per element like "inValues".
  | {
      kind: "quantified";
      op: BinaryOp;
      all: boolean;
      lhs: RExpr;
      array: RExpr;
    };

// SubqueryKind selects which subquery form a "subquery" RExpr is (spec/design/grammar.md §26).
export type SubqueryKind = "scalar" | "exists" | "in" | "quantified";

// JsonGetOp selects which jsonb accessor operator a "jsonGet" RExpr applies
// (spec/design/json-sql-functions.md §1): "arrow" `->` — field by key (text arg) or element by
// index (integer arg), result jsonb; "arrowText" `->>` — same access, rendered as text; "hashArrow"
// `#>` — get at a `text[]` path, result jsonb; "hashArrowText" `#>>` — get at a `text[]` path,
// rendered as text.
export type JsonGetOp = "arrow" | "arrowText" | "hashArrow" | "hashArrowText";

// HasKeyKind selects which jsonb key-existence operator a "jsonHasKey" RExpr applies
// (spec/design/json-sql-functions.md §1, J5): "one" `?` — a single key (text) exists; "any" `?|` —
// any key of a `text[]` exists; "all" `?&` — all keys of a `text[]` exist.
export type HasKeyKind = "one" | "any" | "all";

// DeleteKind selects which jsonb delete form a "jsonDelete" RExpr applies
// (spec/design/json-sql-functions.md §1, J6): "key" `jsonb - text` — delete a key (object) or
// matching string elements (array); "index" `jsonb - int` — delete the array element at an index;
// "keys" `jsonb - text[]` — delete each key; "path" `jsonb #- text[]` — delete the element at a path.
export type DeleteKind = "key" | "index" | "keys" | "path";

// ScalarFuncName is the internal identity of a scalar-function node. abs/round span int/decimal
// AND float overloads; the rest (ceil…tan) are float-only (spec/design/float.md §8). The
// exact-vs-transcendental split is a conformance-layer concern (the R tag + the determinism
// ledger), not a code distinction here — all are ordinary per-row function nodes.
export type ScalarFuncName =
  | "abs"
  | "round"
  | "ceil"
  | "floor"
  | "trunc"
  | "sqrt"
  | "exp"
  | "ln"
  | "log10"
  // log — base-10 (1-arg) / arbitrary-base (2-arg) logarithm over decimal (decimal.md §8).
  // Decimal-only (no float `log`); the EXACT-numeric kernel, IN-CONTRACT.
  | "log"
  | "pow"
  | "sin"
  | "cos"
  | "tan"
  // cbrt — the real cube root (float.md §8). Transcendental, exempted; no domain restriction
  // (cbrt of a negative is the negative real root).
  | "cbrt"
  // pi() → f64 — the constant π (float.md §8). Zero-arg; IN-CONTRACT (the same f64 literal in
  // every core), not in the transcendental ledger.
  | "pi"
  // radians(x) → f64 — degrees → radians (float.md §8): x · RADIANS_PER_DEGREE. A single
  // correctly-rounded IEEE multiply, IN-CONTRACT (not ledgered).
  | "radians"
  // degrees(x) → f64 — radians → degrees (float.md §8): x / RADIANS_PER_DEGREE. A single
  // correctly-rounded IEEE divide, IN-CONTRACT (not ledgered).
  | "degrees"
  // asin(x) → f64 — inverse sine in radians (float.md §8). Transcendental, exempted; domain
  // [-1, 1], |x| > 1 (or ±Inf) → 22003, NaN propagates.
  | "asin"
  // acos(x) → f64 — inverse cosine in radians (float.md §8). Transcendental, exempted; same
  // domain [-1, 1] as asin.
  | "acos"
  // atan(x) → f64 — inverse tangent in radians (float.md §8). Transcendental, exempted; no
  // domain restriction (atan(±Inf) = ±π/2).
  | "atan"
  // atan2(y, x) → f64 — quadrant-aware inverse tangent of y/x (float.md §8). Transcendental,
  // exempted; two float operands (widened to f64), no domain trap.
  | "atan2"
  // cot(x) → f64 — the cotangent, 1/tan(x) (float.md §8). Transcendental, exempted; cot(0) =
  // +Infinity (no trap).
  | "cot"
  // Hyperbolic functions (float.md §8) — transcendental, exempted. sinh/cosh/tanh/asinh have no
  // domain trap (sinh/cosh overflow to ±Inf, PG-faithful); acosh traps below 1, atanh outside
  // [-1, 1] (atanh(±1) = ±Inf is admissible).
  | "sinh"
  | "cosh"
  | "tanh"
  | "asinh"
  | "acosh"
  | "atanh"
  // sign(x) → -1 / 0 / +1 (float.md §8). Decimal → numeric (scale 0), float → f64 (EXACT,
  // in-contract; sign(NaN) = sign(±0) = 0, sign(±Inf) = ±1). Dispatches on the operand, like abs.
  | "sign"
  // div(a, b) → numeric — the TRUNCATED (toward zero) integer quotient at scale 0 (PG div). Computed
  // exactly as (a − a%b)/b; resolver-routed (the catalog name "div" belongs to the `/` operator).
  | "div"
  // gcd(a, b) → the greatest common divisor (non-negative), EXACT/in-contract. Integer → promoted
  // integer (an overflowing-magnitude result → 22003); a decimal operand → numeric at scale
  // max(sₐ, s_b). gcd(0, 0) = 0. Resolver-routed.
  | "gcd"
  // lcm(a, b) → the least common multiple (non-negative), EXACT/in-contract, |a/gcd·b|. lcm(_, 0) =
  // 0. Integer → the promoted type (overflow → 22003); decimal → numeric. Resolver-routed.
  | "lcm"
  // factorial(n) → numeric — n! at scale 0 (PG factorial(bigint)). A negative operand → 22003. The
  // O(n) multiply loop is metered per step (decimal_work, guarded) so the cost ceiling bounds it (§13).
  | "factorial"
  // width_bucket(op, low, high, count) → i32 — the equi-width histogram bucket. Two overloads
  // (numeric exact, float in f64); dispatches on the operand. 2201G on a bad count / equal bounds
  // (and, for float, a NaN operand / infinite bound); a result past int4 → 22003.
  | "width_bucket"
  // scale(numeric) → i32 — the decimal's display (fractional-digit) scale (decimal.md).
  | "scale"
  // min_scale(numeric) → i32 — the smallest scale that represents the value exactly (trailing
  // fractional zeros dropped); zero has min_scale 0 (decimal.md).
  | "min_scale"
  // trim_scale(numeric) → numeric — the value re-scaled down to its min_scale (trailing zeros
  // removed), value-identical (decimal.md).
  | "trim_scale"
  // make_interval — builds an interval from its (named/defaulted) integer components plus the
  // f64 secs (spec/design/functions.md §11). The one scalar function returning interval.
  | "make_interval"
  // make_timestamp/make_timestamptz — the make_interval siblings (named, un-defaulted) §11.
  | "make_timestamp"
  | "make_timestamptz"
  | "make_date"
  | "current_date"
  | "date_part"
  // uuid extractors (spec/design/functions.md §12): pure inspectors of a uuid's bits.
  // uuid_extract_version → i16 (NULL off-RFC-variant); uuid_extract_timestamp → timestamptz
  // (the embedded instant for v1/v7, else NULL).
  | "uuid_extract_version"
  | "uuid_extract_timestamp"
  // uuid generators (spec/design/entropy.md §3): volatile. uuidv4 → random; uuidv7 → ms timestamp
  // + monotonic counter + random, with an optional interval shift.
  | "uuidv4"
  | "uuidv7"
  // current-time functions (spec/design/entropy.md §5): now → timestamptz, the statement clock read
  // ONCE and reused (STABLE; current_timestamp is parser sugar for it); clock_timestamp →
  // timestamptz, the clock seam read on EVERY call (VOLATILE).
  | "now"
  | "clock_timestamp"
  // Sequence value functions (spec/design/sequences.md §4/§6). nextval → i64, advance the named
  // sequence (VOLATILE; MUTATES the working snapshot via pendingSeq, so the statement is a write).
  // currval → i64, the value nextval/setval last produced for the named sequence IN THIS SESSION.
  // setval → i64, set the counter (also a write); lastval → i64, the most-recent-nextval value.
  | "nextval"
  | "currval"
  | "setval"
  | "lastval"
  // Session-variable read (spec/design/session.md §6.1): current_setting(text[, bool]) → text reads
  // the named session variable from the session's variable map. STABLE; 42704 on an unset name unless
  // the two-arg missing_ok is true (→ NULL).
  | "current_setting"
  // json/jsonb processing functions (B1, spec/design/json-sql-functions.md §2). The json* and jsonb*
  // variants share a kernel; the only difference is the json overload parses the verbatim text first.
  // All propagate a SQL NULL input.
  // json[b]_typeof → the JSON type name (object/array/string/number/boolean/null).
  | "jsonb_typeof"
  | "json_typeof"
  // json[b]_array_length → the array element count; a non-array is 22023.
  | "jsonb_array_length"
  | "json_array_length"
  // json[b]_strip_nulls → recursively remove object members whose value is JSON null.
  | "jsonb_strip_nulls"
  | "json_strip_nulls"
  // jsonb_pretty → an indented multi-line render.
  | "jsonb_pretty"
  // to_jsonb(anyelement) → the JSON image of any value (the valueToNode kernel). STRICT.
  | "to_jsonb"
  // to_json(anyelement) → the value's JSON image as `json` (the same kernel, per-type rendered:
  // a jsonb input spaced-canonical, a json input verbatim, else compact). STRICT.
  | "to_json"
  // JSON_SCALAR(anyelement) → the value's JSON scalar as `json` (number/boolean/string). STRICT.
  | "json_scalar"
  // JSON_SERIALIZE(json|jsonb) → the value's text serialization (json verbatim, jsonb canonical).
  | "json_serialize"
  // --- string / text functions (spec/design/string-functions.md). All STRICT (NULL propagates via
  // the generic scalarFunc short-circuit). Character functions count Unicode CODE POINTS — TS strings
  // are UTF-16, so iterate with [...s] (code-point units), NOT .length; octet/bit functions count
  // UTF-8 bytes (via TextEncoder). length(text) → i32 — the number of characters. length('héllo') = 5.
  | "length"
  // octet_length(text) → i32 — the number of UTF-8 bytes (utf8ByteLength). octet_length('héllo') = 6.
  | "octet_length"
  // bit_length(text) → i32 — the number of UTF-8 bits = octet_length × 8. bit_length('héllo') = 48.
  | "bit_length"
  // substr(text, start[, count]) → text — the function form of SUBSTRING (1-based, code-point
  // indexed). A negative count is 22011 (string-functions.md §3).
  | "substr"
  // left(text, n) → text — the first n characters; a negative n drops the last |n| (§3).
  | "left"
  // right(text, n) → text — the last n characters; a negative n drops the first |n| (§3).
  | "right"
  // lpad(text, length[, fill]) → text — left-pad to `length` chars with `fill` (default space);
  // a longer string truncates; an over-large length traps 54000 (§3).
  | "lpad"
  // rpad(text, length[, fill]) → text — the right-hand mirror of lpad (§3).
  | "rpad"
  // btrim(text[, chars]) → text — trim characters in the `chars` set from both ends (§3).
  | "btrim"
  // ltrim(text[, chars]) → text — trim the `chars` set from the LEADING end only (§3).
  | "ltrim"
  // rtrim(text[, chars]) → text — trim the `chars` set from the TRAILING end only (§3).
  | "rtrim"
  // replace(text, from, to) → text — replace every occurrence of substring `from` with `to` (§3).
  | "replace"
  // translate(text, from, to) → text — per-character map/delete by position in `from`/`to` (§3).
  | "translate"
  // repeat(text, n) → text — the string concatenated n times; over-large result traps 54000 (§3).
  | "repeat"
  // reverse(text) → text — the code points in reverse order (§3).
  | "reverse"
  // strpos(text, substring) → i32 — 1-based code-point position of the first match, else 0 (§3).
  | "strpos"
  // split_part(text, delimiter, n) → text — the n-th field of the split; n=0 traps 22023 (§3).
  | "split_part"
  // starts_with(text, prefix) → boolean — true iff the string begins with `prefix` (§3).
  | "starts_with"
  // ascii(text) → i32 — the Unicode code point of the first character; empty → 0 (§3).
  | "ascii"
  // chr(int) → text — the one-character string for a Unicode code point; bad point traps (§3).
  | "chr"
  // initcap(text) → text — titlecase each word (ASCII word boundaries + ASCII case fold, §3).
  | "initcap"
  // to_hex(int) → text — lowercase hex of the value's 64-bit two's-complement pattern (§3).
  | "to_hex"
  // encode(bytea, format) → text — render bytes as hex / base64 / escape (§3).
  | "encode"
  // decode(text, format) → bytea — parse hex / base64 / escape back to binary (§3).
  | "decode"
  // quote_literal(text) → text — wrap as a SQL string literal (§3).
  | "quote_literal"
  // quote_ident(text) → text — wrap as a SQL identifier (§3).
  | "quote_ident"
  // quote_nullable(text) → text — like quote_literal but NON-STRICT (NULL → 'NULL', §3).
  | "quote_nullable";

// ArrayFuncName is the internal identity of a polymorphic array-function node
// (spec/design/array-functions.md §3). Each name is single-arity; the kernel recovers everything
// from the operand values (the array's own shape header).
export type ArrayFuncName =
  | "array_ndims"
  | "array_length"
  | "array_lower"
  | "array_upper"
  | "cardinality"
  | "array_dims"
  | "array_append"
  | "array_prepend"
  | "array_cat"
  | "array_remove"
  | "array_replace"
  | "array_position"
  | "array_positions"
  | "array_to_json"
  // The containment/overlap operators `@>`/`<@`/`&&` (array-functions.md §10) — not catalog function
  // names; resolved via resolveContainment, which selects these kernel ids directly.
  | "contains"
  | "contained_by"
  | "overlaps";

// RangeFuncName is the internal identity of a polymorphic range-accessor node
// (spec/design/range-functions.md §1, RF1). Each name is single-arity; the kernel recovers
// everything from the operand range value (self-describing). lower/upper yield the bound value
// (ELEM) or NULL when empty/unbounded; the rest yield boolean. All are STRICT (a NULL range → NULL).
export type RangeFuncName =
  | "lower"
  | "upper"
  | "isempty"
  | "lower_inc"
  | "upper_inc"
  | "lower_inf"
  | "upper_inf";

// RangeOpName is the internal identity of a range BOOLEAN operator node
// (spec/design/range-functions.md §3, RF3). Each is a binary infix operator returning a definite
// boolean (a NULL operand short-circuits to NULL at eval, like the array containment operators).
// "containsElem"/"elemContainedBy" are the element overloads of @>/<@ (the other operand is a bare
// element coerced to the range's element type); the rest are range-against-range. The kernels live in
// range.ts.
export type RangeOpName =
  | "contains" // a @> b — range a contains range b
  | "containsElem" // r @> e — range r contains element e (the element overload of @>)
  | "containedBy" // a <@ b — range a is contained by range b
  | "elemContainedBy" // e <@ r — element e is contained by range r (the element overload of <@)
  | "overlaps" // a && b — ranges a and b overlap
  | "before" // a << b — a is strictly left of b
  | "after" // a >> b — a is strictly right of b
  | "overleft" // a &< b — a does not extend to the right of b
  | "overright" // a &> b — a does not extend to the left of b
  | "adjacent"; // a -|- b — a and b are adjacent

// RangeSetOpName is the internal identity of a range SET operator node (spec/design/range-functions.md
// §4, RF4). Each combines two ranges over a common element type into a new range. "union"/"difference"
// raise 22000 on a non-contiguous result; "intersect"/"merge" never error. The kernels live in
// range.ts.
export type RangeSetOpName =
  | "union" // a + b — the smallest single range covering both (22000 if they leave a gap)
  | "intersect" // a * b — the overlap (empty when the ranges are disjoint)
  | "difference" // a - b — the part of a not in b (22000 if b splits a in two)
  | "merge"; // range_merge(a, b) — like union but spans any gap silently (never errors)

// VariadicFuncName is the internal identity of a VARIADIC counting-function node
// (spec/design/array-functions.md §12). Both return i32; the call form lives on the node.
export type VariadicFuncName = "num_nulls" | "num_nonnulls";

// JsonBuildKind selects which json/jsonb builder a "jsonBuild" RExpr node is (json-sql-functions.md
// §2): "array" — json[b]_build_array, every argument is one array element (NULL → JSON null);
// "object" — json[b]_build_object, alternating key/value arguments (odd count / NULL key → 22023).
export type JsonBuildKind = "array" | "object";

// JsonPathFnKind selects which scalar jsonpath query function a "jsonPathFn" RExpr node is
// (jsonpath.md §5): "exists" — jsonb_path_exists → boolean (the sequence is non-empty);
// "queryFirst" — jsonb_path_query_first → the first sequence item, or NULL if empty;
// "queryArray" — jsonb_path_query_array → the sequence wrapped in a JSON array;
// "match" — jsonb_path_match (and the `@@` operator) → the single boolean the path/predicate
// produces (22038 if not exactly one boolean item).
export type JsonPathFnKind =
  | "exists"
  | "queryFirst"
  | "queryArray"
  | "match"
  | "matchSilent";

// JsonSqlKind selects which SQL/JSON query function a "jsonSqlFn" RExpr node is
// (json-sql-functions.md §5, S2): "exists" — JSON_EXISTS → boolean (non-empty sequence); errors
// honor ON ERROR (default FALSE); "value" — JSON_VALUE → a single scalar coerced to the RETURNING
// type (default text); "query" — JSON_QUERY → a json/jsonb value (wrapper / quotes controlled).
export type JsonSqlKind = "exists" | "value" | "query";

// ============================================================================
// Query plans — the resolved, owned form of a query, executable repeatedly (a correlated
// subquery is re-run once per outer row). planQuery (the resolve half of the old runSelect)
// produces a QueryPlan; execQueryPlan (the execute half) consumes it against an outer-row
// environment. The split lets a subquery be resolved ONCE — so its structural/type errors fire
// even over an empty outer — yet executed many times (spec/design/grammar.md §26).
// ============================================================================

// PlanRel is one relation in a SELECT plan: the table name (looked up in the store at exec), the
// flat offset of its first column, and its column count (for NULL-padding). When `srf` is set the
// relation is a COMPUTED set-returning function (generate_series) rather than a base table:
// tableName is then the function name (never looked up in the store) and the executor generates
// the rows instead of scanning (spec/design/functions.md §10).
// When `cte` is set, the relation is a reference to common-table-expression `cte` (the index into
// the statement's CTE list — spec/design/cte.md), not a base table: `tableName` is then the CTE
// name (never looked up in the store) and the executor delivers its rows from the per-statement
// CteCtx (a materialized buffer, or the inlined body run in place).
// A `derived` plan marks a DERIVED TABLE — `FROM (SELECT …) [AS] t` (grammar.md §42): a
// parenthesized subquery used as a relation, mechanically an anonymous always-inlined
// single-reference CTE. tableName is the alias (never looked up in the store); the executor runs
// this plan in place (it was planned parent=null, so it reads no outer row), charging its intrinsic
// cost — no cte_scan_row.
// `lateral` is true when this relation is a CORRELATED LATERAL item (spec/design/grammar.md §44):
// its derived body / SRF args reference an earlier sibling (or an enclosing query), so the executor
// re-materializes it ONCE PER combined left-hand row (with that row pushed as its immediate outer —
// the correlated-subquery mechanism), rather than materializing it once. Always false for the first
// relation; only a srf or derived relation is ever lateral.
export type PlanRel = {
  tableName: string;
  // db is the relation's explicit database qualifier (attached-databases.md §3), passed to the
  // scope-aware store funnels at exec (lkpStoreScoped etc.). undefined for a bare implicit-scope name →
  // the funnels fall through to the temp-first walk (behavior-neutral for every unqualified query).
  db?: string;
  offset: number;
  colCount: number;
  srf?: SrfPlan;
  cte?: number;
  derived?: QueryPlan;
  lateral?: boolean;
};

// SrfKind selects which set-returning function an SrfPlan is, picking the row generator at exec
// (spec/design/functions.md §10, array-functions.md §9). The dispatch is hand-written per core.
//   "generate_series" — generate_series(start, stop[, step]), an integer series (functions.md §10).
//   "unnest"          — unnest(anyarray), one row per array element, flattened (array-functions.md §9).
//   "jsonb_array_elements"      — one `jsonb` row per array element (json-sql-functions.md §3).
//   "jsonb_array_elements_text" — one `text` row per array element (the `->>`-style render).
//   "jsonb_object_keys"         — one `text` row per object key, in canonical key order.
//   "json_object_keys"          — one `text` row per object key, in INPUT order (duplicates kept).
//   "jsonb_each"                — one `(key text, value jsonb)` row per object member, canonical order.
//   "jsonb_each_text"           — one `(key text, value text)` row per member (the `->>`-style value).
//   "json_record"               — json[b]_to_record / _recordset (R1, json-table.md §2): map a JSON
//                                 object's members to the C0 col-def-list columns by name + coerce.
//                                 The `recordSet`/`recordCols` fields on the plan carry the form +
//                                 declared columns.
export type SrfKind =
  | "generate_series"
  | "unnest"
  | "jsonb_array_elements"
  | "jsonb_array_elements_text"
  | "jsonb_object_keys"
  | "json_object_keys"
  | "jsonb_each"
  | "jsonb_each_text"
  | "json_record"
  // jsonb_path_query(jsonb, jsonpath) (P2, jsonpath.md §5.2): one `jsonb` row per item of the path's
  // evaluation sequence over the context document. `args` is `[ctx, path]`.
  | "jsonb_path_query"
  // JSON_TABLE(ctx, path COLUMNS (…)) (T1, json-table.md §3): a multi-column relation produced by the
  // recursive default-plan expansion. `args` is `[ctx]`; the resolved column tree is the SrfPlan's
  // `jtPlan` field.
  | "json_table"
  // The jed_tables catalog relation (spec/design/introspection.md §5): a read-only COMPUTED
  // relation — one row per user table of the qualified database, derived at execution from its
  // pinned catalog snapshot. Not a function (it is resolved as a table name), but it rides the SRF
  // plan shape so every "computed, not scanned" gate handles it: no store, no index pushdown, no
  // PK order, excluded from the fast-path lanes. `args` is empty; the scope is the SrfPlan's
  // introspectScope.
  | "jed_tables"
  // The jed_columns catalog relation (introspection.md §5) — one row per column of every user
  // table of the qualified database, in (table, ordinal) order.
  | "jed_columns"
  // The jed_indexes catalog relation (introspection.md §5.1, slice I2) — one row per secondary
  // index of every user table (name, table, columns, is_unique, method).
  | "jed_indexes"
  // The jed_constraints catalog relation (introspection.md §5.1, slice I2) — one row per CHECK /
  // UNIQUE / FK / EXCLUDE constraint of every user table.
  | "jed_constraints";

// SrfPlan is a resolved set-returning-function row source (spec/design/functions.md §10,
// array-functions.md §9). kind selects the generator: generate_series(start, stop[, step]) (args =
// 2 or 3 integers) or unnest(anyarray) (args = the single array expression). Non-LATERAL, so each
// arg evaluates against the params/outer environment with no local row. The produced column's type
// lives on the synthetic relation (built in resolveSRF).
// recordSet/recordCols apply only to the `json_record` kind (R1, json-table.md §2): recordSet
// selects the recordset form (one row per array element) vs. the single record row, and recordCols
// is the declared C0 col-def-list columns used to map JSON members → columns by name + coerce.
export type SrfPlan = {
  kind: SrfKind;
  args: RExpr[];
  recordSet?: boolean;
  recordCols?: Column[];
  // The resolved column tree for a `JSON_TABLE` SRF (the `json_table` kind, T1, json-table.md §3),
  // else absent.
  jtPlan?: JtPlan;
  // The validated database scope of a catalog relation (the `jed_tables` / `jed_columns` kinds —
  // introspection.md §5): "main" (also the unqualified default), "temp", or a lowercased
  // attachment name. Absent for every other kind.
  introspectScope?: string;
};

// catalogRelKind classifies a relation name as a built-in catalog relation (introspection.md §5):
// jed_tables / jed_columns, case-insensitively (identifier resolution folds case; grammar.md §3
// leaves no quoted escape). Built-in names resolve in every database's relation namespace, checked
// AFTER a statement-local CTE (a CTE shadows a catalog relation — PG-matching, oracle-checked) and
// BEFORE the user catalog (post-I0 the two can never collide; for a pre-reservation legacy file the
// built-in wins and the user relation is unreachable by name — §5).
export type CatalogRelKind = "jed_tables" | "jed_columns" | "jed_indexes" | "jed_constraints";

export function catalogRelKind(name: string): CatalogRelKind | undefined {
  const lname = name.toLowerCase();
  if (
    lname === "jed_tables" ||
    lname === "jed_columns" ||
    lname === "jed_indexes" ||
    lname === "jed_constraints"
  ) {
    return lname;
  }
  return undefined;
}

// isCatalogRelName reports whether name is a built-in catalog relation (jed_tables / jed_columns).
// The write paths use it to reject a catalog relation as a mutation/DDL target (42809 — a catalog
// relation is read-only, introspection.md §5); the privilege gate uses it so a built-in is
// SELECT-gated exactly like a user table under an explicit-grant session envelope.
export function isCatalogRelName(name: string): boolean {
  return catalogRelKind(name) !== undefined;
}

// checkCatalogRelWrite rejects a mutation target (INSERT / UPDATE / DELETE / CREATE INDEX ON)
// naming a built-in catalog relation: 42809 wrong_object_type, `cannot modify system relation`
// (introspection.md §5 — the relations are read-only computed views of the catalog). Checked by
// NAME, before qualifier validation: the built-in resolves in every database's namespace, so the
// rejection is scope-independent.
export function checkCatalogRelWrite(name: string): void {
  if (isCatalogRelName(name)) {
    throw engineError("wrong_object_type", `cannot modify system relation "${name.toLowerCase()}"`);
  }
}

// catalogRelTable builds the FIXED synthetic schema of a catalog relation (introspection.md §5).
// Unlike an SRF's single-column alias rule, a FROM alias renames the RELATION only — the column
// names are part of the introspection surface. Growth is by ADDING columns (consumers select by
// name, not position — §5).
export function catalogRelTable(kind: CatalogRelKind): Table {
  const mkCol = (name: string, ty: Type, notNull: boolean): Column => ({
    name,
    type: ty,
    decimal: null,
    varcharLen: null,
    primaryKey: false,
    notNull,
    default: null,
    defaultExpr: null,
    identity: null,
    collation: null,
  });
  const col = (name: string, ty: ScalarType, notNull: boolean): Column =>
    mkCol(name, scalarT(ty), notNull);
  // A text[] member-list column (introspection.md §5.1 — the indexed / member column names).
  const textArr = (name: string, notNull: boolean): Column =>
    mkCol(name, arrayT(scalarT("text")), notNull);
  const table = (name: string, columns: Column[]): Table => ({
    name,
    columns,
    pk: [],
    checks: [],
    indexes: [],
    fks: [],
    exclusions: [],
  });
  switch (kind) {
    case "jed_tables":
      return table("jed_tables", [col("name", "text", true)]);
    case "jed_columns":
      return table("jed_columns", [
        col("table_name", "text", true),
        col("name", "text", true),
        col("ordinal", "i32", true),
        col("type", "text", true),
        col("not_null", "boolean", true),
        col("pk_ordinal", "i32", false),
      ]);
    case "jed_indexes":
      return table("jed_indexes", [
        col("name", "text", true),
        col("table_name", "text", true),
        textArr("columns", true),
        col("is_unique", "boolean", true),
        col("method", "text", true),
        // A partial index's predicate canonical text; NULL for a non-partial index (indexes.md §9).
        col("predicate", "text", false),
      ]);
    default: // "jed_constraints"
      return table("jed_constraints", [
        col("name", "text", true),
        col("table_name", "text", true),
        col("type", "text", true),
        textArr("columns", false),
        col("expression", "text", false),
        col("ref_table", "text", false),
        textArr("ref_columns", false),
      ]);
  }
}

// catalogTypeText renders a column's declared type in the CANONICAL introspection form
// (introspection.md §5): the scalar's canonical name with its typmod applied at the leaf
// (varchar(10), decimal(8,2)), a composite's name as created, a range's canonical id (i32range,
// numrange, …), and `[]` appended for an array (the typmod applies to the element: varchar(5)[]).
// This text is a compatibility surface the moment it ships — pinned by the corpus.
export function catalogTypeText(ty: Type, dec: DecimalTypmod | null, vlen: number | null): string {
  if (ty.kind === "array") return catalogTypeText(ty.elem, dec, vlen) + "[]";
  if (ty.kind === "scalar" && ty.scalar === "text" && vlen !== null) {
    return `varchar(${vlen})`;
  }
  if (ty.kind === "scalar" && ty.scalar === "decimal" && dec !== null) {
    return `decimal(${dec.precision},${dec.scale})`;
  }
  // The scalar / composite / range canonical rendering is shared with error messages (types.ts):
  // composite → its name as created, range → the ranges.toml id.
  return typeCanonicalName(ty);
}

// JtPlan is a resolved `JSON_TABLE` plan (T1, json-table.md §3) — the compiled root path + the
// column tree. `width` is the total flattened output-column count.
export type JtPlan = {
  // The compiled root jsonpath (its evaluation over `ctx` yields the row items).
  rootPath: string;
  // The total number of flattened output columns.
  width: number;
  // The top-level column tree.
  columns: JtCol[];
};

// JtCol is one resolved `JSON_TABLE` column (json-table.md §3.3), a discriminated union. Leaf
// columns carry their flat output index `idx`.
export type JtCol =
  // `FOR ORDINALITY` — the level's 1-based row counter.
  | { kind: "ordinality"; idx: number }
  // A regular column: evaluate `path` over the row item, apply JSON_VALUE (scalar) or JSON_QUERY
  // (json/jsonb) semantics, coerce to `returning`.
  | {
      kind: "regular";
      idx: number;
      returning: ScalarType;
      decimal: DecimalTypmod | null;
      path: string;
      // JSON_QUERY semantics (json/jsonb returning) vs JSON_VALUE (scalar).
      query: boolean;
      wrapper: JsonWrapper;
      onEmpty: JsonOnBehavior;
      onError: JsonOnBehavior;
    }
  // An `EXISTS` column: JSON_EXISTS of `path`, coerced to `returning` (bool/int).
  | { kind: "exists"; idx: number; returning: ScalarType; path: string; onError: JsonOnBehavior }
  // A `NESTED PATH` subtree: expanded over the row item (the default-plan LEFT OUTER / sibling UNION).
  | { kind: "nested"; path: string; columns: JtCol[] };

// srfTable builds a set-returning function's SYNTHETIC one-column relation (spec/design/functions.md
// §10). The table's name is the function name (the un-aliased label fallback); the lone column's
// NAME follows PostgreSQL's single-column function-alias rule — the table alias when one is given,
// else the function name — and its TYPE is colTy (the promoted integer for generate_series, the
// bound element type for unnest).
export function srfTable(funcName: string, alias: string | null, colTy: Type): Table {
  return {
    name: funcName,
    columns: [
      {
        name: alias ?? funcName,
        type: colTy,
        decimal: null,
        varcharLen: null,
        primaryKey: false,
        notNull: false,
        default: null,
        defaultExpr: null,
        identity: null,
        collation: null,
      },
    ],
    pk: [],
    checks: [],
    indexes: [],
    fks: [],
    exclusions: [],
  };
}

// srfTableCols builds a MULTI-COLUMN synthetic table for a set-returning function (C0,
// json-table.md §1) — the generalization of srfTable to N named/typed columns. The column NAMES are
// fixed by the function (e.g. jsonb_each → key, value); the FROM alias renames the RELATION, not its
// columns. Used by json[b]_each[_text] (and, with a col-def list, the record functions).
export function srfTableCols(
  funcName: string,
  alias: string | null,
  cols: [string, Type][],
): Table {
  return {
    name: alias ?? funcName,
    columns: cols.map(([name, type]) => ({
      name,
      type,
      decimal: null,
      varcharLen: null,
      primaryKey: false,
      notNull: false,
      default: null,
      defaultExpr: null,
      identity: null,
      collation: null,
    })),
    pk: [],
    checks: [],
    indexes: [],
    fks: [],
    exclusions: [],
  };
}

// jsonRecordRow builds one output row for `json[b]_to_record(set)` (R1): map each declared column to
// the JSON object's member of that name, coercing it to the column type. A missing member or a JSON
// null → SQL NULL; a non-object node → 22023. (json-table.md §2)
export function jsonRecordRow(node: JsonNode, cols: Column[], env: EvalEnv, meter: Meter): Row {
  if (node.kind !== "object") {
    throw engineError(
      "invalid_parameter_value",
      "argument of json_to_record must be a JSON object",
    );
  }
  const row: Value[] = [];
  for (const col of cols) {
    const member = node.members.find((m) => m.key === col.name)?.value;
    if (member === undefined || member.kind === "null") {
      row.push(nullValue()); // missing / JSON null → SQL NULL
    } else {
      row.push(coerceJsonMember(member, col.type, col.decimal, env, meter));
    }
  }
  return row;
}

// coerceJsonMember coerces a JSON member node to a record column's type (R1, the JSON_VALUE scalar
// path): a `jsonb` column embeds the node, a `json` column its canonical text, every other scalar
// coerces the node's `->>`-style text through the cast machinery (so `"42"` / `42` → an `int`
// column, etc.). A composite/array column type is a deferred 0A000.
export function coerceJsonMember(
  node: JsonNode,
  colTy: Type,
  decimal: DecimalTypmod | null,
  env: EvalEnv,
  meter: Meter,
): Value {
  if (colTy.kind !== "scalar") {
    throw engineError(
      "feature_not_supported",
      "a composite/array record column is not supported yet",
    );
  }
  const st = colTy.scalar;
  if (st === "jsonb") return jsonbValue(node);
  if (st === "json") return jsonValue(jsonbOut(node));
  const text = nodeToText(node);
  if (text === null) return nullValue();
  const { node: rexpr } = coerceStringLiteral(text, st, decimal, null);
  return evalExpr(rexpr, [], env, meter);
}

// isSqljsonError reports whether an error is a SQL/JSON error the query functions' `ON ERROR` clause
// catches: a data exception (class `22`). Resource / cost aborts (class `53`/`54`) propagate
// unconditionally. Port of impl/rust/src/executor.rs `is_sqljson_error`.
export function isSqljsonError(e: unknown): e is EngineError {
  return e instanceof EngineError && e.code().startsWith("22");
}

// applyJsonBehavior applies a constant `ON ERROR` / `ON EMPTY` behavior → a value of the RETURNING
// type. `underlying` is the SQL/JSON error this behavior replaces (rethrown verbatim by `error`).
// Port of impl/rust/src/executor.rs `apply_json_behavior`.
export function applyJsonBehavior(
  behavior: JsonOnBehavior,
  underlying: EngineError,
  returning: ScalarType,
  env: EvalEnv,
  meter: Meter,
): Value {
  switch (behavior) {
    case "error":
      throw underlying;
    case "null":
      return nullValue();
    case "true":
      return boolValue(true);
    case "false":
      return boolValue(false);
    case "unknown":
      return nullValue();
    case "emptyArray":
      return jsonNodeAsReturning({ kind: "array", elements: [] }, returning, env, meter);
    case "emptyObject":
      return jsonNodeAsReturning({ kind: "object", members: [] }, returning, env, meter);
  }
}

// jsonNodeAsReturning renders a json result node as the RETURNING type: `jsonb` embeds, `json` its
// canonical text, any other scalar coerces the node's `->>`-style text through the cast machinery.
// Port of impl/rust/src/executor.rs `json_node_as_returning`.
export function jsonNodeAsReturning(
  node: JsonNode,
  returning: ScalarType,
  env: EvalEnv,
  meter: Meter,
): Value {
  return coerceJsonMember(node, scalarT(returning), null, env, meter);
}

// evalJsonSqlResult applies the SQL/JSON query-function semantics (JSON_VALUE / JSON_QUERY) to an
// evaluated sequence. (JSON_EXISTS is handled inline — non-empty → true.) Port of
// impl/rust/src/executor.rs `eval_json_sql_result`.
export function evalJsonSqlResult(
  kind: JsonSqlKind,
  seq: JsonNode[],
  returning: ScalarType,
  decimal: DecimalTypmod | null,
  wrapper: JsonWrapper,
  onEmpty: JsonOnBehavior,
  onError: JsonOnBehavior,
  env: EvalEnv,
  meter: Meter,
): Value {
  switch (kind) {
    case "exists":
      return boolValue(seq.length > 0);
    case "value": {
      if (seq.length === 0) {
        return applyJsonBehavior(
          onEmpty,
          engineError("no_sql_json_item", "no SQL/JSON item"),
          returning,
          env,
          meter,
        );
      }
      if (seq.length > 1) {
        return applyJsonBehavior(
          onError,
          engineError(
            "more_than_one_sql_json_item",
            "JSON path expression in JSON_VALUE should return singleton scalar item",
          ),
          returning,
          env,
          meter,
        );
      }
      const item = seq[0]!;
      // JSON_VALUE requires a SCALAR item (PG 2203F otherwise).
      if (item.kind === "array" || item.kind === "object") {
        return applyJsonBehavior(
          onError,
          engineError(
            "sql_json_member_not_found",
            "JSON path expression in JSON_VALUE should return singleton scalar item",
          ),
          returning,
          env,
          meter,
        );
      }
      // Coerce the scalar to the RETURNING type (a JSON null → SQL NULL). A coercion failure is a
      // SQL/JSON error honored by ON ERROR.
      try {
        return coerceJsonMember(item, scalarT(returning), decimal, env, meter);
      } catch (e) {
        if (isSqljsonError(e)) {
          return applyJsonBehavior(onError, e, returning, env, meter);
        }
        throw e;
      }
    }
    case "query": {
      let node: JsonNode;
      switch (wrapper) {
        case "unconditional":
          node = { kind: "array", elements: seq };
          break;
        case "conditional":
          node = seq.length === 1 ? seq[0]! : { kind: "array", elements: seq };
          break;
        case "without": {
          if (seq.length === 0) {
            return applyJsonBehavior(
              onEmpty,
              engineError("no_sql_json_item", "no SQL/JSON item"),
              returning,
              env,
              meter,
            );
          }
          if (seq.length > 1) {
            return applyJsonBehavior(
              onError,
              engineError(
                "more_than_one_sql_json_item",
                "JSON path expression in JSON_QUERY should return singleton item without wrapper",
              ),
              returning,
              env,
              meter,
            );
          }
          node = seq[0]!;
          break;
        }
      }
      return jsonNodeAsReturning(node, returning, env, meter);
    }
  }
}

// ----------------------------------------------------------------------------------------------
// JSON_TABLE helpers (T1, json-table.md §3)
// ----------------------------------------------------------------------------------------------

// JtAssign is a sparse assignment of a `JSON_TABLE` row — `[flat column index, value]` pairs;
// unassigned columns are NULL (the LEFT-OUTER / sibling-UNION fill).
export type JtAssign = [number, Value][];

// jtColumn builds a synthetic `JSON_TABLE` output column. Port of impl/rust/src/executor.rs
// `jt_column`.
export function jtColumn(name: string, ty: ScalarType, decimal: DecimalTypmod | null): Column {
  return {
    name,
    type: scalarT(ty),
    decimal,
    varcharLen: null,
    primaryKey: false,
    notNull: false,
    default: null,
    defaultExpr: null,
    identity: null,
    collation: null,
  };
}

// jtScalarType resolves a `JSON_TABLE` column type name → its scalar type (a composite → 0A000, an
// unknown name → 42704). Port of impl/rust/src/executor.rs `jt_scalar_type`.
export function jtScalarType(db: Engine, typeName: string): ScalarType {
  const st = scalarTypeFromName(typeName);
  if (st !== undefined) return st;
  if (db.compositeType(typeName) !== undefined) {
    throw engineError(
      "feature_not_supported",
      "a composite JSON_TABLE column is not supported yet",
    );
  }
  throw engineError("undefined_object", `type "${typeName}" does not exist`);
}

// jtCompilePath compiles a `JSON_TABLE` column path — the explicit `PATH p`, or the default
// `$.<column_name>` — to its canonical rendered form (validating; malformed → 42601). Port of
// impl/rust/src/executor.rs `jt_compile_path`.
export function jtCompilePath(path: string | null, name: string): string {
  const src = path ?? `$.${name}`;
  return jsonPathRender(jsonPathCompile(src));
}

// expandJtLevel expands a `JSON_TABLE` COLUMNS level over a sequence of row items → the sparse rows
// (the parent→child LEFT OUTER product with sibling NESTED paths UNIONed, json-table.md §3.3). Port
// of impl/rust/src/executor.rs `expand_jt_level`.
export function expandJtLevel(
  cols: JtCol[],
  items: JsonNode[],
  env: EvalEnv,
  meter: Meter,
): JtAssign[] {
  const rows: JtAssign[] = [];
  for (let i = 0; i < items.length; i++) {
    meter.guard();
    const item = items[i]!;
    const ord = BigInt(i + 1);
    // This level's non-nested columns (regular / exists / ordinality).
    const local: JtAssign = [];
    for (const col of cols) {
      switch (col.kind) {
        case "ordinality":
          local.push([col.idx, intValue(ord)]);
          break;
        case "regular": {
          const v = evalJtRegular(
            item,
            col.path,
            col.query,
            col.returning,
            col.decimal,
            col.wrapper,
            col.onEmpty,
            col.onError,
            env,
            meter,
          );
          local.push([col.idx, v]);
          break;
        }
        case "exists": {
          const v = evalJtExists(item, col.path, col.returning, col.onError);
          local.push([col.idx, v]);
          break;
        }
        case "nested":
          break;
      }
    }
    // The NESTED siblings, expanded over this item (UNIONed + LEFT OUTER fill).
    const nested = cols.filter((c): c is JtCol & { kind: "nested" } => c.kind === "nested");
    const nestedRows = expandJtNested(nested, item, env, meter);
    for (const nr of nestedRows) {
      rows.push([...local, ...nr]);
    }
  }
  return rows;
}

// expandJtNested expands the NESTED siblings of a level over one parent item — the default-plan
// UNION of the siblings (each row fills only its own subtree), with the parent→child LEFT OUTER fill
// (no child rows at all → one all-NULL nested row). Port of impl/rust/src/executor.rs
// `expand_jt_nested`.
export function expandJtNested(
  children: (JtCol & { kind: "nested" })[],
  item: JsonNode,
  env: EvalEnv,
  meter: Meter,
): JtAssign[] {
  if (children.length === 0) return [[]];
  const union: JtAssign[] = [];
  for (const child of children) {
    const p = jsonPathCompile(child.path);
    let childSeq: JsonNode[];
    try {
      childSeq = jsonPathEval(p, item);
    } catch {
      childSeq = [];
    }
    union.push(...expandJtLevel(child.columns, childSeq, env, meter));
  }
  if (union.length === 0) union.push([]);
  return union;
}

// evalJtRegular evaluates a regular `JSON_TABLE` column over a row item — JSON_VALUE (scalar) /
// JSON_QUERY (json/jsonb) semantics, with the column's wrapper / ON EMPTY / ON ERROR. Port of
// impl/rust/src/executor.rs `eval_jt_regular`.
export function evalJtRegular(
  item: JsonNode,
  path: string,
  query: boolean,
  returning: ScalarType,
  decimal: DecimalTypmod | null,
  wrapper: JsonWrapper,
  onEmpty: JsonOnBehavior,
  onError: JsonOnBehavior,
  env: EvalEnv,
  meter: Meter,
): Value {
  const p = jsonPathCompile(path);
  let seq: JsonNode[];
  try {
    seq = jsonPathEval(p, item);
  } catch (e) {
    if (isSqljsonError(e)) {
      return applyJsonBehavior(onError, e, returning, env, meter);
    }
    throw e;
  }
  const kind: JsonSqlKind = query ? "query" : "value";
  return evalJsonSqlResult(kind, seq, returning, decimal, wrapper, onEmpty, onError, env, meter);
}

// evalJtExists evaluates an `EXISTS` `JSON_TABLE` column over a row item — JSON_EXISTS, coerced to
// the column type (a NON-empty sequence is true; a structural error honors ON ERROR, default FALSE).
// Port of impl/rust/src/executor.rs `eval_jt_exists`.
export function evalJtExists(
  item: JsonNode,
  path: string,
  returning: ScalarType,
  onError: JsonOnBehavior,
): Value {
  const p = jsonPathCompile(path);
  let exists: boolean;
  try {
    exists = jsonPathEval(p, item).length > 0;
  } catch (e) {
    if (isSqljsonError(e)) {
      switch (onError) {
        case "error":
          throw e;
        case "true":
          exists = true;
          break;
        case "unknown":
          return nullValue();
        default:
          exists = false;
          break;
      }
    } else {
      throw e;
    }
  }
  // Coerce the boolean to the column type (a `boolean` column → bool; an integer column → 1/0).
  if (isBool(returning)) {
    return boolValue(exists);
  }
  if (isInteger(returning)) {
    return intValue(BigInt(exists ? 1 : 0));
  }
  throw engineError(
    "feature_not_supported",
    "an EXISTS JSON_TABLE column must be boolean or integer this slice",
  );
}

// PlanJoin is one join in a SELECT plan: its kind and resolved ON predicate (null for CROSS). The
// right relation is rels[k+1].
export type PlanJoin = { kind: JoinKind; on: RExpr | null };

// OrderSlot is a resolved ORDER BY key: a flat/synthetic slot + per-key direction flags + an optional
// collation. A null collation is the C/value order; a non-null collation orders this key by its UCA
// sort key (spec/design/collation.md §8) via the decorate sorter — it never reaches the spill Sorter
// (collation is in-memory only this slice), which ignores the field.
export type OrderSlot = {
  idx: number;
  descending: boolean;
  nullsFirst: boolean;
  collation: Collation | null;
};

// SelectPlan is a resolved SELECT, executable against an outer-row environment (the execute half
// of the old runSelect, lifted to a value so a correlated subquery can re-run it per outer row).
export type SelectPlan = {
  kind: "select";
  rels: PlanRel[];
  joins: PlanJoin[];
  filter: RExpr | null;
  isAgg: boolean;
  groupKeys: number[];
  // groupExprs is the materialized general-expression GROUP BY keys (`GROUP BY a + b`,
  // aggregates.md §15), in synthetic-slot order. Before bucketing, each post-WHERE row evaluates
  // these and appends the values at flat slots inputWidth + k, so a master grouping key index in
  // groupKeys / groupSets may point at one — the whole-row bucket machinery stays slot-based. Empty
  // when every grouping key is a plain column (the common case, byte-identical to before).
  groupExprs: RExpr[];
  // groupSets are the grouping sets to compute (spec/design/aggregates.md §12). A plain GROUP BY
  // (and the whole-table aggregate) is a single set; ROLLUP/CUBE/GROUPING SETS produce several.
  groupSets: GroupSet[];
  // groupingSpecs has one entry per GROUPING() call in the projection / HAVING, in synthetic-slot
  // order: the master-grouping-column positions of its arguments. Each call's value per group row is
  // computed from the row's grouping-set mask and appended after the aggregate results.
  groupingSpecs: number[][];
  aggSpecs: AggSpec[];
  // hasWindow is true when the select list has a window function — the query runs the blocking
  // WINDOW stage (after WHERE, before ORDER BY/LIMIT) and takes the eager path (never streaming).
  // Mutually exclusive with isAgg in S0 (spec/design/window.md §5.2).
  hasWindow: boolean;
  // windowSpecs holds one resolved window function per select-list OVER call (empty unless
  // hasWindow). The window stage appends each spec's per-row result after the input columns and the
  // materialized window keys, so the projection references result i as flat slot
  // inputWidth + windowKeys.length + i (spec/design/window.md §5.1).
  windowSpecs: WindowSpec[];
  // windowKeys is the materialized window-key expressions (a non-column PARTITION BY / ORDER BY key —
  // `PARTITION BY a + b`, `ORDER BY a % 2`), in synthetic-slot order. Before the window stage each row
  // evaluates these and appends the values at flat slots inputWidth + k, so the slot-based partition /
  // sort / frame machinery is unchanged. Empty when every window key is a bare column.
  windowKeys: RExpr[];
  having: RExpr | null;
  order: OrderSlot[];
  // orderExprs is the materialized ORDER BY expression-key expressions (`ORDER BY a + 1`,
  // `ORDER BY abs(b)`), in the order their sort slots reference them. Just before the sort each row
  // evaluates these and appends the values at finalRowWidth + k (after any window / grouped columns),
  // so the slot-based sort stays unchanged — the window-key precedent (window.md §5.1). Empty when
  // every ORDER BY key is a bare column or ordinal (the common case, byte-identical to before).
  orderExprs: RExpr[];
  projections: RExpr[];
  columnNames: string[];
  columnTypes: ResolvedType[];
  distinct: boolean;
  limit: bigint | null;
  offset: bigint | null;
  // relMasks is the TOUCHED SET per relation (cost.md §3 "The touched set"; large-values.md §14):
  // which of its columns this query statically references. Drives the chain-pageRead /
  // valueDecompress portion of the scan's up-front cost block — an untouched spilled or
  // compressed column charges nothing, however many records the bound admits. An ANNOTATION of the
  // logical plan, not an optimization: a wrong mask is a disk-mode NULL-folding correctness bug,
  // not a slow plan — so it is computed by the resolve half (computeRelMasks), never by a physical
  // rule (spec/design/planner.md §2).
  relMasks: boolean[][];
  // phys is the plan's physical / access-path decisions — set ONLY by the optimizeSelect pass
  // (optimize.ts); zero-valued when resolve hands the plan over (spec/design/planner.md §4).
  phys: PhysicalPlan;
};

// PhysicalPlan is the physical/access-path half of a SelectPlan: every field is the output of one
// discrete rule of the optimizeSelect pass (spec/design/planner.md §4), applied in a fixed order
// after the resolve half has built the logical plan. A zero-valued PhysicalPlan is always correct —
// the executor then full-scans and eager-sorts.
export type PhysicalPlan = {
  // pkOrdered reports that ORDER BY is satisfied by the single base relation's PRIMARY-KEY scan
  // order — the table tree already yields rows in this order, so the sort is elided (and with a
  // LIMIT the scan short-circuits a top-N). True iff the query is a single-table, non-aggregate,
  // non-DISTINCT SELECT whose ORDER BY keys are a prefix of the PK columns, all one direction with
  // the column's stored key collation (spec/design/cost.md §3 "ORDER BY satisfied by primary-key
  // order"). Secondary-index order is a follow-on.
  pkOrdered: boolean;
  // pkReverse is the PK scan direction when pkOrdered: true ⇒ the order is all-DESC over the full
  // PK, served by a REVERSE scan; false ⇒ all-ASC (forward). Always false when !pkOrdered.
  pkReverse: boolean;
  // indexOrder reports that ORDER BY is satisfied by walking a B-tree SECONDARY index in key order
  // (with a LIMIT top-N) — non-null when the PK scan does not satisfy the order but the index does
  // (cost.md §3 "secondary-index order"). Mutually exclusive with pkOrdered (the PK scan is
  // cheaper). null keeps the eager/streaming sort.
  indexOrder: IndexOrder | null;
  // joinPkOrdered reports that ORDER BY is satisfied by the OUTER relation's PK scan order in a
  // two-table INNER/CROSS join (cost.md §3 "JOIN"): the nested loop drives the outer in PK order, so
  // its output is already in order — the sort is elided and a LIMIT short-circuits the loop. Set only
  // for exactly two non-lateral base relations, a LIMIT, and a forward outer-PK ORDER BY.
  joinPkOrdered: boolean;
  // Primary-key predicate pushdown, ONE entry per relation in rels: the WHERE conjuncts that bound
  // that relation's storage key, so its scan seeks/ranges instead of walking the whole B-tree
  // (cost.md §3 "bounded scan"). null ⇒ a full scan of that relation. In a JOIN each base table is
  // bounded independently by the WHERE predicates on its OWN primary key against a CONSTANT
  // (literal/param/outer) — a cross-relation `b.pk = a.x` is the index-nested-loop case (a
  // follow-on). The residual filter stays the WHOLE `filter`, re-applied after the join.
  relBounds: (ScanBound | null)[];
  // relINLBounds is the INDEX-NESTED-LOOP scan bounds, one per relation (cost.md §3 "JOIN"). Non-null
  // for a join inner relation whose primary key / indexed column is compared to a SIBLING column of an
  // earlier relation (`a JOIN b ON b.pk = a.x`) — a per-outer-row bound resolved from the combined
  // left-hand row. When set, that relation is NOT materialized once up front; the join loop
  // re-materializes it per left row (like a correlated LATERAL), seeking instead of full-scanning —
  // O(N·M) → O(N·log M). null ⇒ the ordinary once-materialized relBounds path. A non-null entry takes
  // precedence over relBounds for that relation.
  relINLBounds: (ScanBound | null)[];
};

// SetOpPlan is a resolved set operation: both operands planned with the same parent scope, the
// unified output types, and the trailing ORDER BY / LIMIT / OFFSET resolved by output column.
export type SetOpPlan = {
  kind: "setOp";
  op: SetOpKind;
  all: boolean;
  lhs: QueryPlan;
  rhs: QueryPlan;
  columnNames: string[];
  columnTypes: ResolvedType[];
  order: OrderSlot[];
  limit: bigint | null;
  offset: bigint | null;
};

// ValuesPlan is a resolved VALUES-body relation (spec/design/grammar.md §42), executable to its
// literal rows — the FROM-position sibling of INSERT … VALUES. rows[r][c] is row r, column c, each
// resolved as a CONSTANT (the body is non-LATERAL, planned parent=null, so it reads no row).
// columnTypes is the per-column type unified across the rows like a set operation (§25), and
// columnNames is column1, column2, … (PostgreSQL; the derived table's optional column-rename list
// overrides them at the synthetic relation). All rows have columnTypes.length values.
export type ValuesPlan = {
  kind: "values";
  rows: RExpr[][];
  columnTypes: ResolvedType[];
  columnNames: string[];
};

// WithPlan is a planned nested `WITH … query_expr` (spec/design/cte.md §7): the nested CTE bindings
// + their inline/materialize modes, and the inner query plan that references them. At execution the
// bindings are materialized once and `body` runs against a fresh CTE context (they establish their
// own scope — the enclosing context is NOT chained in, the documented narrowing §7). columnTypes /
// columnNames mirror the body's, so a WithPlan exposes its output columns like any other plan.
export type WithPlan = {
  kind: "with";
  bindings: CteBinding[];
  modes: CteMode[];
  body: QueryPlan;
  columnNames: string[];
  columnTypes: ResolvedType[];
};

// QueryPlan is a resolved query expression: a SELECT plan, a set-op plan, a VALUES-body relation, or
// a nested WITH plan (mirrors QueryExpr's bodies). A VALUES plan is only ever produced as a
// derived-table body.
export type QueryPlan = SelectPlan | SetOpPlan | ValuesPlan | WithPlan;

// ScanCache is a prepared statement's memoized scan plan (spec/design/api.md §2.4): the resolved
// SelectPlan (shared by reference, so a cache hit rebuilds the cursor around the SAME plan object and
// re-plans nothing) plus the finalized $N param types, stamped with the database identity (core) and
// committed catalog generation (catGen) they were resolved against. A statement is a standalone value
// shared across sessions, so a hit requires the same core — catGen is only monotonic within one core;
// two databases can share a generation number with different schemas — AND the same generation (any
// DDL bumps it and the next execute re-plans), and re-checks that no plan relation is shadowed by the
// executing session's temp domain (planTouchesTemp). Filled only for a reusable plan read from
// committed state. core is the engine's shared core when it has one, else the bare Engine itself
// (object identity is GC-safe in JS) — so the low-level tooling path caches too, without aliasing.
export type ScanCache = {
  core: AttachmentCore | Engine;
  catGen: bigint;
  sp: SelectPlan;
  ptys: ScalarType[];
};
// ScanCacheHolder is the mutable slot the executor reads/writes. A PreparedStatement owns one and
// threads it through queryStmt → tryScanQuery (executor.ts is import-cycle-free of api.ts, so the
// holder — not the PreparedStatement — crosses the seam). null cache = empty.
export type ScanCacheHolder = { cache: ScanCache | null };

// CteMode is how a referenced CTE is evaluated (spec/design/cte.md §3, cost.md §3). Decided per CTE
// from its reference count and [NOT] MATERIALIZED hint: a single-reference CTE is "inline", a
// multi-reference (or MATERIALIZED) one is "materialize".
//   "inline":      run the body in place at each reference (re-evaluates per outer row under
//                  correlation, matching PostgreSQL); charges the body's intrinsic cost, no
//                  cte_scan_row.
//   "materialize": run the body once, buffer the rows; each reference scans the buffer, charging
//                  cte_scan_row per buffered row.
export type CteMode = "inline" | "materialize";

// CteBinding is a planned common table expression (spec/design/cte.md), built by planCteBindings for
// the whole statement so the scopes that reference its synthetic `table` can see it. `name` is
// lowercased for case-insensitive FROM matching; `table` is the synthetic relation exposing the
// body's output columns; `source` is the planned body (a query plan, or — spec/design/writable-cte.md
// — a data-modifying statement); `hint` is the [NOT] MATERIALIZED override (true/false/null); `refs`
// counts the FROM references resolved to it during planning (the inline-vs-materialize decision —
// cost.md §3).
// For a RECURSIVE CTE (spec/design/recursive-cte.md) `source` holds the non-recursive (anchor) term
// (its column types fix the synthetic relation's) and `recursive` carries the recursive term + the
// UNION ALL flag; the binding is in scope inside its own recursive term, so the self-reference
// resolves to it.
export type RecursiveTerm = { plan: QueryPlan; unionAll: boolean };
export type CteBinding = {
  name: string;
  table: Table;
  source: CteSource;
  recursive: RecursiveTerm | null;
  hint: boolean | null;
  refs: number;
};

// CteSource is what a CTE binding evaluates to (spec/design/cte.md, writable-cte.md). A plain CTE
// holds a planned query body; a DATA-MODIFYING CTE holds the statement to execute (for its effect +
// RETURNING buffer). A data-modifying CTE is always materialized (writable-cte.md §3), so the
// inline-execution path never touches a "dml" source.
export type CteSource = { kind: "query"; plan: QueryPlan } | { kind: "dml"; dm: DmCte };

// DmCte is a data-modifying CTE's body (spec/design/writable-cte.md): the INSERT/UPDATE/DELETE to run
// (cloned from the AST, executed with the statement's CTE context threaded in) and whether it has no
// RETURNING clause — in which case a FROM reference to it is 0A000 (§5).
export type DmCte = { stmt: DmStmt; noReturning: boolean };

// DmStmt is a data-modifying statement in a writable-CTE position (a CTE body or the WITH primary).
export type DmStmt = Insert | Update | Delete;

// CteCtx is the per-statement CTE execution context, threaded through exec_* and EvalEnv so a FROM
// reference (any nesting depth) can deliver a CTE's rows (spec/design/cte.md §5). `modes` and
// `bindings` are fixed after planning; `buffers` is filled before the main query runs — one slot per
// CTE in list order, holding the materialized rows of a "materialize" CTE (an empty placeholder for
// an "inline" one, whose body is run in place from `bindings[ci].source` instead). `bindings` also
// serves a data-modifying CTE's own inner queries, which resolve against the earlier bindings when
// the writable-CTE orchestrator executes them (writable-cte.md §2). EMPTY_CTE_CTX is the empty
// context for every non-WITH execution path.
export type CteCtx = { modes: CteMode[]; bindings: CteBinding[]; buffers: Row[][] };
export const EMPTY_CTE_CTX: CteCtx = { modes: [], bindings: [], buffers: [] };

// EvalEnv is the environment threaded into the per-row evaluator (spec/design/grammar.md §26): the
// bound parameters, the stack of enclosing rows (innermost LAST) a correlated reference reads, and
// a runSubquery callback (a correlated subquery re-runs its inner plan against the pushed stack).
// outer is empty at the top level; an outerColumn at frame `level` reads outer[outer.length-level].
export type EvalEnv = {
  params: Value[];
  outer: Row[];
  runSubquery(plan: QueryPlan, outer: Row[]): SelectResult;
  // The entropy+clock seam (spec/design/entropy.md §5): `seam` is the handle's injected random/clock
  // functions (a reference to the Engine's Seam — handle-scoped); `rng` is the per-statement
  // uuidv7 counter + once-resolved clock. Only the volatile uuid generators touch either.
  seam: Seam;
  rng: StmtRng;
  // The statement's CTE execution context (spec/design/cte.md §5), so a FROM reference at any
  // nesting depth delivers a CTE's rows. EMPTY_CTE_CTX for every non-WITH statement.
  ctes: CteCtx;
  // The executing Engine handle, so the sequence value functions (nextval/currval — sequences.md
  // §4/§6) can resolve a name to a catalog sequence and advance/read it (mirrors Rust's env.exec —
  // the same access the clock seam already uses). Only nextval/currval touch it.
  exec: Engine;
};

// ============================================================================
// Aggregate resolution + accumulation (spec/design/aggregates.md).
//
// An aggregate query's select list resolves in "collect" mode: each aggregate call is
// collected into an AggSpec (its plan + resolved argument) and replaced by a reference to a
// synthetic-row slot (a "column" RExpr indexing the finalized aggregate results), so the
// existing evaluator projects the result with no new node. Outside collect mode (WHERE / ON /
// an aggregate's own argument / any non-aggregate query) a column resolves normally and an
// aggregate call is a 42803 grouping error.
// ============================================================================

// AggPlan is the runtime plan for one aggregate, fixed at resolve from the function + operand
// type (the PG widening — spec/design/aggregates.md §3).
export type AggPlan =
  | "countStar" // COUNT(*) — count every row
  | "count" // COUNT(expr) — count non-NULL inputs
  | "sumInt" // SUM(i16|i32) — accumulate i64, result i64 (trap at i64)
  | "sumDecimal" // SUM(i64|decimal) — accumulate decimal, result decimal
  | "avg" // AVG — decimal sum + count; result sum/count (NULL if count 0)
  // SUM/AVG over float: the ORDER-INDEPENDENT CANONICAL-ORDER FOLD (float.md §7). Inputs are
  // COLLECTED (not streamed), then at finalize: resolve NaN/±Inf, -0-canonicalize + sort the finite
  // values by the total order, fold left at the width (fround per add for f32), trapping 22003
  // on overflow. Result keeps the input width (same_as_input). avgFloat divides the sum by the
  // count, rounded once. The width rides on the Acc.
  | "sumFloat"
  | "avgFloat"
  | "min"
  | "max"
  // jsonb_agg / json_agg / jsonb_agg_strict / json_agg_strict (json-sql-functions.md, B4): aggregate
  // a group's values into one JSON array, one element per input row in scan order. The element image
  // is the to_jsonb kernel (valueToNode), so deferred sources (float/datetime/composite/…) propagate
  // 0A000. `asJson` selects the json result type (vs jsonb) — BOTH render via the spaced jsonb_out;
  // `strict` skips a NULL-valued row (the non-strict variants keep it as JSON null). An empty/zero-row
  // group → SQL NULL, but a group whose rows were all dropped by the strict filter → an empty array []
  // (the `seen` flag distinguishes the two).
  | "jsonAgg"
  // json_object_agg / jsonb_object_agg (and the `_unique` variants, B4) — aggregate a group's (key,
  // value) pairs (carried as a Row operand) into one JSON object (json-sql-functions.md §4). The
  // `jsonAsJson` flag selects the json (insertion order + dups + " : " spacing, brace-padded) vs jsonb
  // (canonical, last-wins) render; `jsonUnique` errors 22030 on a duplicate key. An empty group → NULL
  // (the `seen` flag). Hand-resolved (the single-operand aggregate catalog can't express a pair).
  | "jsonObjectAgg"
  // Ordered-set aggregates (spec/design/aggregates.md §13). The WITHIN GROUP direction + percentile
  // fraction ride on the AggSpec/Acc, not the plan.
  | "mode" // mode() — the most frequent value (tie → first in sort order)
  | "percentileDisc" // percentile_disc(f) — the discrete percentile (an actual input value)
  | "percentileCont" // percentile_cont(f) — the continuous (interpolated) percentile, f64
  // percentile_cont(f) over an INTERVAL input — the continuous percentile interpolated in the
  // interval domain (lo + (hi−lo)·pct, PG interval_lerp); result interval (spec/design/aggregates.md
  // §13). Values are buffered as Value::Interval (in osaVals), NOT widened to f64.
  | "orderedSetContInterval"
  // Hypothetical-set aggregates (spec/design/aggregates.md §19): rank/dense_rank/percent_rank/
  // cume_dist used WITH a WITHIN GROUP clause. They share the four window-function names but the
  // WITHIN GROUP clause routes them here. Each buffers every group row's WITHIN GROUP key TUPLE
  // (on the Acc's hypoRows); at finalize the per-group hypothetical row (the direct args) is
  // counted against the buffered tuples by the spec's per-key sort specs (it needs them, so it is
  // finalized inline in the group-emission loop, not via finalizeAcc). The result formula is per
  // kind.
  | "hypoRank" // rank(args) — 1 + the number of group rows that sort strictly before; result i64
  | "hypoDenseRank" // dense_rank(args) — 1 + the number of DISTINCT values strictly before; result i64
  | "hypoPercentRank" // percent_rank(args) — (rank − 1) / N; result f64
  | "hypoCumeDist"; // cume_dist(args) — (#rows ≤ hyp + 1) / (N + 1); result f64

// AggSpec is one resolved aggregate: its plan and its resolved argument (evaluated per input
// row against the real row). operand is null for COUNT(*). distinct (COUNT(DISTINCT x),
// aggregates.md §5) folds only the distinct non-NULL argument values — the fold loop keeps a
// per-group value-canonical set and skips a value already seen. Only set in the aggregation stage;
// a window aggregate is never DISTINCT (0A000, rejected at resolve).
export type AggSpec = {
  plan: AggPlan;
  operand: RExpr | null;
  floatWidth?: ScalarType;
  distinct?: boolean;
  // The resolved FILTER (WHERE cond) boolean predicate (SUM(x) FILTER (WHERE cond) —
  // aggregates.md §11); null/undefined for an unfiltered aggregate. The fold loop evaluates it per
  // input row and folds only the rows for which it is TRUE (so the filter applies before DISTINCT).
  filter?: RExpr | null;
  // For the "jsonAgg" plan (B4): asJson selects the json result type (vs jsonb); strict skips a
  // NULL-valued row. Both ride on the Acc, fixed at resolve.
  jsonAsJson?: boolean;
  jsonStrict?: boolean;
  // For the "jsonObjectAgg" plan (B4): unique → error 22030 on a duplicate key. asJson rides on
  // jsonAsJson above (json vs jsonb render). Fixed at resolve.
  jsonUnique?: boolean;
  // Ordered-set aggregate parameters (mode/percentile_* — aggregates.md §13/§17), set only for the
  // mode/percentileDisc/percentileCont plans. osaDesc is the WITHIN GROUP sort direction; osaFrac is
  // the resolved **direct argument** (the percentile fraction) — resolved in the grouped context so
  // it references grouping columns by their synthetic key slots (a non-grouped column is 42803,
  // matching PG's "direct arguments … must use only grouped columns") and is evaluated **per group**
  // at finalize against the synthetic row. null for mode (no direct argument).
  osaDesc?: boolean;
  osaFrac?: RExpr | null;
  // The WITHIN GROUP key's collation (aggregates.md §13) — set for an explicit COLLATE on the key
  // or a column's frozen non-C collation, null/undefined for the default byte (C) order. The
  // finalize sort applies it to the buffered text values.
  osaCollation?: Collation | null;
  // Set for a hypothetical-set aggregate (rank/dense_rank/percent_rank/cume_dist WITHIN GROUP —
  // aggregates.md §19): the hypothetical-row direct args (evaluated PER GROUP at finalize, like an
  // OSA fraction — they may reference grouping columns), the WITHIN GROUP key operands (evaluated PER
  // ROW during the fold and buffered as a tuple on the Acc), and the per-key sort specs. Null/undefined
  // otherwise. (operand is null here — the keys are buffered as a tuple from hypo.keys.)
  hypo?: HypoParams | null;
};

// KeySort is a single WITHIN GROUP ordering-key sort spec (aggregates.md §13/§19): direction, NULL
// placement, and optional collation (text keys only).
export type KeySort = {
  desc: boolean;
  nullsFirst: boolean;
  collation: Collation | null;
};

// HypoParams are the resolve-time parameters of a hypothetical-set aggregate (aggregates.md §19).
// args are the hypothetical-row direct arguments (evaluated PER GROUP at finalize, so they may
// reference grouping columns); keys are the WITHIN GROUP key operands (evaluated PER ROW during the
// fold and buffered as a tuple); sorts is the per-key ordering spec. The three arrays have equal
// length (the arity check at resolve).
export type HypoParams = {
  args: RExpr[];
  keys: RExpr[];
  sorts: KeySort[];
};

// AggCtx threads the aggregate-resolution mode through resolve. collecting === false is the
// Forbidden mode (a funcCall is 42803; columns resolve normally); collecting === true is an
// aggregate query's projection (a funcCall collects into specs and resolves to a synthetic slot
// groupKeys.length + index; a column resolves to its position among groupKeys if it is a
// grouping key, else 42803). groupKeys holds the resolved flat indices of the GROUP BY columns
// (empty for whole-table aggregation). The synthetic row is [group_key_values..., agg_results...].
//
// `window` is set (and collecting === false) for a non-aggregate WINDOW query's projection
// (spec/design/window.md §5.1). Bare columns resolve to the real input row (like Forbidden); a
// funcCall carrying an OVER clause collects into windowSpecs and resolves to the synthetic slot
// base + windowIndex, where base is the input row's flat width — the window stage appends each
// function's result after the input columns. S0 narrows window + aggregate/GROUP BY to 0A000 (so
// `collecting` and `window` are never both set), and an aggregate in a window context is 42803.
// GroupKeyExpr records a general-expression GROUP BY key (`GROUP BY a + b`, aggregates.md §15): its
// canonical AST (so a matching projection / HAVING / ORDER BY expression resolves to its synthetic
// slot) and its resolved type.
export type GroupKeyExpr = { canon: Expr; ty: ResolvedType };

export type AggCtx = {
  collecting: boolean;
  groupKeys: number[];
  // groupKeyExprs is parallel to groupKeys: for each master grouping key, a non-null GroupKeyExpr
  // (canonical AST + resolved type) if it is a general EXPRESSION key (`GROUP BY a + b`,
  // aggregates.md §15) — so a projection / HAVING / ORDER BY expression that structurally matches it
  // resolves to that group's synthetic slot — or null for a plain COLUMN key (matched by the column
  // path instead). Undefined in a Forbidden context (no grouping-expression remapping there).
  groupKeyExprs?: (GroupKeyExpr | null)[];
  specs: AggSpec[];
  // window collects window functions (windowSpecs) and the materialized window-key expressions
  // (windowKeys — a non-column PARTITION BY / ORDER BY key, `PARTITION BY a + b`). A window result
  // carries the placeholder slot base WINDOW_RESULT_BASE+w; a materialized window key carries
  // WINDOW_KEY_BASE+k — both rebased once the row layout is final (spec/design/window.md §5.1).
  window?: { base: number; windowSpecs: WindowSpec[]; windowKeys: RExpr[] };
  // groupingSpecs collects one entry per GROUPING(c1,…,ck) call from the projection / HAVING — the
  // master-grouping-column POSITIONS (indices into groupKeys) of its arguments. Each call resolves to
  // the placeholder slot GROUPING_GS_BASE+index, rebased after resolution to its real trailing
  // synthetic slot (spec/design/aggregates.md §12).
  groupingSpecs?: number[][];
};

// WindowSpec is one resolved window function (spec/design/window.md §5.1): its plan, the resolved
// PARTITION BY key column slots (flat input-row indices), and the resolved within-partition ORDER
// BY (sort keys over the input row, PK tie-break applied by the stable sort over the PK-ordered
// scan).
export type WindowSpec = {
  plan: WindowPlan;
  partition: number[];
  order: OrderSlot[];
  // Resolved function arguments (empty for the no-argument ranking functions; ntile's bucket-count
  // argument is the one entry). Evaluated against the partition's first sorted row (window.md §4).
  // For an aggregate window (plan "agg") the aggregate operand is args[0] (empty for COUNT(*)).
  args: RExpr[];
  // For an aggregate window (plan "agg", spec/design/window.md §6): the resolved aggregate plan +
  // float width (riding on the Acc), fixed at resolve from the function + operand type.
  aggPlan?: AggPlan;
  aggFloatWidth?: ScalarType;
  // For a json[b]_agg window aggregate (B4 plan "jsonAgg"): the asJson / strict flags fixed at
  // resolve, threaded into newAcc by applyWindowStage.
  aggJsonAsJson?: boolean;
  aggJsonStrict?: boolean;
  // The resolved explicit frame (S4, ROWS mode); undefined/null is the default frame (RANGE
  // UNBOUNDED PRECEDING TO CURRENT ROW with an ORDER BY, the whole partition without — window.md §6).
  frame?: ResolvedFrame | null;
  // `agg(x) FILTER (WHERE cond) OVER (…)` — a per-frame-row boolean restricting which frame rows fold
  // into the window aggregate (aggregates.md §20). Non-null only for an aggregate window function (a
  // non-aggregate window function with FILTER is 0A000). A FILTER disables the sliding-frame
  // optimization (a filtered row can't be cleanly un-folded) — every frame re-folds.
  filter?: RExpr | null;
};

// ResolvedFrame is a resolved window frame (spec/design/window.md §6): ROWS physical offsets,
// GROUPS peer-group offsets (both integer counts), and RANGE value offsets over the ordering key.
export type ResolvedFrame = {
  mode: FrameMode;
  start: ResolvedBound;
  end: ResolvedBound;
  // EXCLUDE … — rows dropped from [lo, hi) per current row (window.md §6).
  exclude: FrameExclusion;
};

// A resolved frame boundary. preceding/following carry the offset as a Value: an int Value (the
// row/group count) for ROWS/GROUPS, or the numeric Value (int over an integer key, decimal over a
// decimal key) added to / subtracted from the ordering key for RANGE.
export type ResolvedBound =
  | { kind: "unboundedPreceding" }
  | { kind: "preceding"; offset: Value }
  | { kind: "currentRow" }
  | { kind: "following"; offset: Value }
  | { kind: "unboundedFollowing" };

// WindowPlan is the runtime plan for one window function (spec/design/window.md §4). S0:
// row_number only; ranking / offset / aggregate-window / frame plans land in S1–S4.
export type WindowPlan =
  // ROW_NUMBER() — the 1-based sequence position within the partition (frame-insensitive).
  | "rowNumber"
  // RANK() — 1 + rows in earlier peer groups (ties share a rank, then a gap).
  | "rank"
  // DENSE_RANK() — 1 + earlier peer groups (ties share a rank, no gap).
  | "denseRank"
  // PERCENT_RANK() — (rank-1)/(N-1), 0 when N=1; decimal (divergence D2).
  | "percentRank"
  // CUME_DIST() — (rows through the current peer group)/N; decimal (divergence D2).
  | "cumeDist"
  // NTILE(n) — distribute the partition into n ranked buckets, larger buckets first; i64.
  | "ntile"
  // LAG(value [, offset [, default]]) — the value `offset` rows BEFORE the current row (by sorted
  // position); the result type is the value expression's type.
  | "lag"
  // LEAD(value [, offset [, default]]) — the value `offset` rows AFTER the current row.
  | "lead"
  // An aggregate used as a window function (S3): sum/count/min/max/avg(...) OVER (...), folded over
  // the row's default frame (running with a window ORDER BY, whole-partition without — window.md §6).
  // Reuses the aggregate Acc kernels; the resolved AggPlan rides on the spec's aggPlan field, the
  // operand (if any) on args[0] (empty for COUNT(*)).
  | "agg"
  // FIRST_VALUE(v) / LAST_VALUE(v) — the value of the frame's first / last row (S4). args[0] is the
  // value expression; frame-sensitive.
  | "firstValue"
  | "lastValue"
  // NTH_VALUE(v, n) — the value of the frame's n-th row, NULL if the frame has < n rows (S4).
  // args[0] is the value, args[1] the position; frame-sensitive.
  | "nthValue";

// Acc is a running aggregate accumulator (one per AggSpec), folded per input row then finalized.
// For float SUM/AVG the finite inputs fold into `floatTotal` in scan order (a STREAMING running total —
// float.md §7, fold order ledgered non-deterministic), with the NaN/±Inf presence tracked in the flags
// so the special-value resolution stays order-independent; `floatWidth` (fixed at resolve) re-rounds
// `floatTotal` to binary32 each add when f32.
export type Acc = {
  plan: AggPlan;
  count: bigint;
  sumInt: bigint;
  sumDec: Decimal;
  seen: boolean;
  cur: Value | null;
  floatTotal: number;
  floatNaN: boolean;
  floatPosInf: boolean;
  floatNegInf: boolean;
  floatWidth: ScalarType;
  // For the "jsonAgg" plan (B4): the accumulated element nodes (the array body, in scan order) and
  // the two flags fixed at resolve (asJson → json result; strict → skip a NULL-valued row).
  jsonNodes: JsonNode[];
  jsonAsJson: boolean;
  jsonStrict: boolean;
  // For the "jsonObjectAgg" plan (B4): the (key, value) pairs in row order (the key already coerced
  // to text). `jsonUnique` errors 22030 on a duplicate key; `jsonAsJson` (above) selects json vs jsonb
  // finalize; `seen` (above) distinguishes a zero-row group (→ NULL) from a non-empty one.
  jsonPairs: [string, Value][];
  jsonUnique: boolean;
  // Ordered-set aggregate state (spec/design/aggregates.md §13): the WITHIN GROUP direction +
  // the **evaluated** percentile fraction for this group, plus the collected non-NULL values
  // (percentileCont widens to f64 into osaFloats; mode/percentileDisc keep the Value in osaVals).
  // osaFrac is the per-group fraction Value — the direct argument is evaluated per group against the
  // synthetic row just before finalize (aggregates.md §13/§17): a Value for percentile_* (it may be
  // NULL → NULL result, or numeric), null for mode. Sorted + computed at finalize.
  osaDesc?: boolean;
  osaFrac?: Value | null;
  // The WITHIN GROUP key collation (aggregates.md §13) applied to the finalize sort of the buffered
  // text values; null/undefined is the default byte (C) order.
  osaCollation?: Collation | null;
  osaVals?: Value[];
  osaFloats?: number[];
  // Hypothetical-set state (spec/design/aggregates.md §19): every group row's buffered WITHIN GROUP
  // key TUPLE (no NULL-skip — every row counts). At finalize (in the group-emission loop, where the
  // per-group hypothetical row + the spec's sort specs are available) finalizeHypothetical counts how
  // that hypothetical row would rank. Undefined for every non-hypothetical plan.
  hypoRows?: Value[][];
};

export function newAcc(
  plan: AggPlan,
  floatWidth: ScalarType = "f64",
  jsonAsJson = false,
  jsonStrict = false,
  jsonUnique = false,
): Acc {
  return {
    plan,
    count: 0n,
    sumInt: 0n,
    sumDec: Decimal.fromBigInt(0n),
    seen: false,
    cur: null,
    floatTotal: 0,
    floatNaN: false,
    floatPosInf: false,
    floatNegInf: false,
    floatWidth,
    jsonNodes: [],
    jsonAsJson,
    jsonStrict,
    jsonPairs: [],
    jsonUnique,
  };
}

// newAccFromSpec builds the accumulator for one resolved aggregate. Ordered-set aggregates
// (mode/percentile_* — aggregates.md §13) need their WITHIN GROUP direction + fraction (carried on
// the spec, not the plan); every other plan delegates to newAcc. Only the aggregation stage builds
// ordered-set accumulators — the window stage (which calls newAcc directly) never sees one (an
// ordered-set aggregate with OVER is 0A000, rejected at resolve).
export function newAccFromSpec(s: AggSpec): Acc {
  if (
    s.plan === "mode" ||
    s.plan === "percentileDisc" ||
    s.plan === "percentileCont" ||
    s.plan === "orderedSetContInterval"
  ) {
    const a = newAcc(s.plan);
    a.osaDesc = s.osaDesc;
    a.osaCollation = s.osaCollation ?? null;
    // The per-group fraction (osaFrac) is filled in just before finalize (the direct argument
    // evaluated against the synthetic row); mode keeps it null/undefined.
    a.osaVals = [];
    a.osaFloats = [];
    return a;
  }
  if (
    s.plan === "hypoRank" ||
    s.plan === "hypoDenseRank" ||
    s.plan === "hypoPercentRank" ||
    s.plan === "hypoCumeDist"
  ) {
    // A hypothetical-set aggregate (aggregates.md §19): buffer every row's WITHIN GROUP key tuple in
    // hypoRows; the per-key sort specs ride on the spec (hypo.sorts) and are read at finalize.
    const a = newAcc(s.plan);
    a.hypoRows = [];
    return a;
  }
  // Pass the json[b]_agg / object_agg flags through (the json plans ride them on the Acc, B4).
  return newAcc(
    s.plan,
    s.floatWidth ?? "f64",
    s.jsonAsJson ?? false,
    s.jsonStrict ?? false,
    s.jsonUnique ?? false,
  );
}

// cloneAcc deep-copies a running accumulator so the window stage can SNAPSHOT it at each peer-group
// boundary and finalize the snapshot without consuming the running fold (spec/design/window.md §6;
// the Rust `Acc: Clone`). Decimals are immutable (Decimal ops return fresh values) and the float fold
// is a scalar running total, so only the collected slices below need a real copy; `cur` is a Value
// (treated immutably by foldAcc/finalizeAcc).
export function cloneAcc(a: Acc): Acc {
  // Ordered-set accumulators are never windowed (clone is the window-stage snapshot), but copy the
  // collected slices anyway so a clone never aliases the original.
  return {
    ...a,
    jsonNodes: a.jsonNodes.slice(),
    jsonPairs: a.jsonPairs.slice(),
    osaVals: a.osaVals ? a.osaVals.slice() : undefined,
    osaFloats: a.osaFloats ? a.osaFloats.slice() : undefined,
    hypoRows: a.hypoRows ? a.hypoRows.map((r) => r.slice()) : undefined,
  };
}

// foldAcc folds one input value into the accumulator. NULL arguments are skipped (COUNT(*)
// ignores the value and always counts). Traps 22003 on SUM overflow at the result bound.
// A decimal SUM/AVG fold charges size-scaled decimal_work against the running accumulator
// (the `+` formula — spec/design/cost.md §3 "decimal_work"); MIN/MAX folds are direct Value
// compares like the sort's and stay unmetered.
export function foldAcc(a: Acc, v: Value, m: Meter): void {
  switch (a.plan) {
    case "countStar":
      a.count += 1n;
      break;
    case "count":
      if (v.kind !== "null") a.count += 1n;
      break;
    case "sumInt":
      if (v.kind === "int") {
        const s = a.sumInt + v.int;
        if (!inRange("i64", s)) throw overflow("i64");
        a.sumInt = s;
        a.seen = true;
      }
      break;
    case "sumDecimal":
      if (v.kind !== "null") {
        const inc = toDecimal(v);
        m.charge(COSTS.decimalWork * BigInt(workLinear(a.sumDec, inc) - 1));
        m.guard();
        // Uncapped: the running sum may exceed the §2 format cap mid-fold; only the FINAL
        // result is cap-checked (in finalizeAcc), matching PG and making the trap
        // order-independent (spec/design/decimal.md §2, determinism.md §7).
        a.sumDec = a.sumDec.addUncapped(inc);
        a.seen = true;
      }
      break;
    case "avg":
      if (v.kind !== "null") {
        const inc = toDecimal(v);
        m.charge(COSTS.decimalWork * BigInt(workLinear(a.sumDec, inc) - 1));
        m.guard();
        // Uncapped (as sumDecimal): the average's final divide brings the value back in range,
        // so AVG never traps on an over-cap intermediate sum the way PG does not.
        a.sumDec = a.sumDec.addUncapped(inc);
        a.count += 1n;
      }
      break;
    case "sumFloat":
    case "avgFloat":
      // Float SUM/AVG: fold each finite input into the running total in scan order (float.md §7 —
      // fold order ledgered non-deterministic); NaN/±Inf only set a flag (special-value resolution
      // stays order-independent). NULL is skipped (every aggregate). When f32 the running total is
      // re-rounded to binary32 each add (the width-correct fold).
      if (v.kind === "f32" || v.kind === "f64") {
        a.count += 1n;
        a.seen = true;
        if (Number.isNaN(v.value)) a.floatNaN = true;
        else if (v.value === Infinity) a.floatPosInf = true;
        else if (v.value === -Infinity) a.floatNegInf = true;
        else {
          const x = canonFloat(v.value); // -0 → +0
          a.floatTotal = a.floatWidth === "f32" ? Math.fround(a.floatTotal + x) : a.floatTotal + x;
        }
      }
      break;
    case "min":
    case "max":
      if (v.kind !== "null") {
        if (a.cur === null) a.cur = v;
        else {
          const c = valueCmp(a.cur, v);
          const keepCur = a.plan === "min" ? c <= 0 : c >= 0;
          if (!keepCur) a.cur = v;
        }
      }
      break;
    case "jsonAgg":
      // Called once per group row, NULL-valued rows INCLUDED. `seen` marks the group non-empty even
      // when the strict filter drops this row (so a one-NULL-row strict group finalizes to [] not
      // NULL). A kept element charges one generatedRow (the per-appended-element cost), then its JSON
      // image is the to_jsonb kernel (valueToNode) — deferred sources propagate 0A000.
      a.seen = true;
      if (!(a.jsonStrict && v.kind === "null")) {
        m.charge(COSTS.generatedRow);
        m.guard();
        a.jsonNodes.push(valueToNode(v));
      }
      break;
    case "jsonObjectAgg": {
      // Called once per group row. `seen` marks the group non-empty (so an empty group → NULL at
      // finalize). The operand is a Row(key, value) composite; split it back out, coerce the key to
      // text (NULL → 22023 "field name must not be null"), then push (key, value) in row order. The
      // _unique variant errors 22030 on a key already accumulated. Charges one generatedRow per pair.
      a.seen = true;
      m.charge(COSTS.generatedRow);
      m.guard();
      if (v.kind !== "composite" || v.fields.length !== 2) {
        throw new Error("BUG: object_agg operand is a 2-field Row");
      }
      const kv = v.fields[0]!;
      const vv = v.fields[1]!;
      // The key is coerced to text (text/integer/decimal/boolean); a NULL key → 22023 (a DIFFERENT
      // message from build_object's "key must not be null"), so it is handled before objectKeyText.
      if (kv.kind === "null") {
        throw engineError("invalid_parameter_value", "field name must not be null");
      }
      const key = objectKeyText(kv, 1);
      if (a.jsonUnique && a.jsonPairs.some(([k]) => k === key)) {
        throw engineError("duplicate_json_object_key_value", "duplicate JSON object key value");
      }
      a.jsonPairs.push([key, vv]);
      break;
    }
    case "mode":
    case "percentileDisc":
    case "percentileCont":
    case "orderedSetContInterval":
      // Collect the non-NULL aggregated argument (the WITHIN GROUP order key, evaluated per row).
      // percentileCont (the NUMERIC plan) widens each value to f64 up front (the correctly-rounded
      // cast, matching PG's numeric→float8); mode/percentileDisc/orderedSetContInterval keep the
      // Value (the interval plan interpolates in the interval domain at finalize).
      if (v.kind !== "null") {
        if (a.plan === "percentileCont") a.osaFloats!.push(percentileInputF64(v));
        else a.osaVals!.push(v);
      }
      break;
    case "hypoRank":
    case "hypoDenseRank":
    case "hypoPercentRank":
    case "hypoCumeDist":
      // A hypothetical-set aggregate buffers its key tuple in the fold LOOP (which has the row), not
      // through foldAcc (aggregates.md §19), so this is never reached.
      throw new Error("a hypothetical-set accumulator buffers tuples in the fold loop");
  }
}

// unfoldAcc removes one input value — the inverse of foldAcc — used ONLY by the sliding-window
// optimization (window.md §5.2/§8) for the exactly-invertible COUNT / COUNT(*) (integer counters:
// add-then-remove is exact and order-independent). Every other accumulator is never un-folded — a
// moving frame over SUM/AVG/MIN/MAX/float re-folds from scratch instead (decimal scale,
// intermediate-overflow trap order, and float non-associativity make them unsafe to invert).
export function unfoldAcc(a: Acc, v: Value, _m: Meter): void {
  switch (a.plan) {
    case "countStar":
      a.count -= 1n;
      break;
    case "count":
      if (v.kind !== "null") a.count -= 1n;
      break;
    default:
      throw new Error("only COUNT/COUNT(*) are un-folded by the sliding-window optimization");
  }
}

// finalizeAcc produces the aggregate's final value over the group. COUNT → its count (0 over
// empty); SUM/MIN/MAX → NULL over an empty/all-NULL group; AVG → sum/count (NULL if count 0).
export function finalizeAcc(a: Acc): Value {
  switch (a.plan) {
    case "countStar":
    case "count":
      return intValue(a.count);
    case "sumInt":
      return a.seen ? intValue(a.sumInt) : nullValue();
    case "sumDecimal":
      // checkCap is the only cap check for the fold: the FINAL sum traps 22003 if over the §2
      // cap (PG's make_result), but no intermediate does (decimal.md §2).
      return a.seen ? decimalValue(a.sumDec.checkCap()) : nullValue();
    case "avg":
      // div cap-checks its (in-range) result; the over-cap-capable running sum is never surfaced
      // directly, so AVG matches PG even when SUM would overflow.
      return a.count === 0n ? nullValue() : decimalValue(a.sumDec.div(Decimal.fromBigInt(a.count)));
    case "sumFloat": {
      if (!a.seen) return nullValue(); // empty / all-NULL group → NULL
      const s = resolveFloatFold(a);
      return a.floatWidth === "f32" ? float32Value(s) : float64Value(s);
    }
    case "avgFloat": {
      if (a.count === 0n) return nullValue();
      // AVG = SUM / count, the division ROUNDED ONCE at the input width (float.md §7). count is
      // exact; Number(count) is safe for any plausible group size.
      const s = resolveFloatFold(a);
      const avg = s / Number(a.count);
      const r = a.floatWidth === "f32" ? Math.fround(avg) : avg;
      return a.floatWidth === "f32" ? float32Value(r) : float64Value(r);
    }
    case "min":
    case "max":
      return a.cur ?? nullValue();
    case "jsonAgg": {
      // Zero-row group → SQL NULL; a group that saw rows (even all-dropped by strict) → an array.
      // Both result types render via the SAME spaced jsonb_out: jsonb carries the array node, json
      // carries that same canonical text (json_agg canonicalizes a json element — a documented
      // PG divergence, B4).
      if (!a.seen) return nullValue();
      const arr: JsonNode = { kind: "array", elements: a.jsonNodes };
      if (a.jsonAsJson) return jsonValue(jsonbOut(arr));
      return jsonbValue(arr);
    }
    case "jsonObjectAgg": {
      // Zero-row group → SQL NULL; else the JSON object. json keeps insertion order + dups with PG's
      // idiosyncratic " : " spacing and PADDED braces (`{ … }` — distinct from json_build_object,
      // which does NOT pad); jsonb canonicalizes last-wins (makeObject).
      if (!a.seen) return nullValue();
      if (a.jsonAsJson) {
        const parts = a.jsonPairs.map(
          ([k, v]) => `${jsonCompactOut({ kind: "string", value: k })} : ${elemJsonText(v)}`,
        );
        // PG's json_object_agg PADS the braces (`{ … }`).
        return jsonValue(`{ ${parts.join(", ")} }`);
      }
      const members: JsonMember[] = a.jsonPairs.map(([k, v]) => ({
        key: k,
        value: valueToNode(v),
      }));
      return jsonbValue(jsonMakeObject(members));
    }
    case "mode":
    case "percentileDisc":
    case "percentileCont":
    case "orderedSetContInterval":
      return finalizeOrderedSet(a);
    case "hypoRank":
    case "hypoDenseRank":
    case "hypoPercentRank":
    case "hypoCumeDist":
      // A hypothetical-set aggregate is finalized in the group-emission loop (it needs the spec's
      // per-key sort specs), never through finalizeAcc (aggregates.md §19).
      throw new Error("a hypothetical-set accumulator is finalized in the group-emission loop");
  }
}

// finalizeOrderedSet computes an ordered-set aggregate's value over its collected group
// (spec/design/aggregates.md §13). mode → the most frequent value (tie → first in WITHIN GROUP sort
// order); percentileDisc → an actual value at 1-based row ceil(p·N); percentileCont → the
// interpolated f64. The fraction range check (22003) fires here, after the NULL-fraction check and
// before the empty-group check — matching PG.
export function finalizeOrderedSet(a: Acc): Value {
  const desc = a.osaDesc === true;
  if (a.plan === "mode") {
    const vals = a.osaVals!;
    if (vals.length === 0) return nullValue();
    // Sort by the WITHIN GROUP order (honoring the key's collation), then take the first value of the
    // longest run of equal values. Run equality is value-canonical (byte equality), so the collation
    // affects only which tied value comes first.
    sortOsaVals(vals, a.osaCollation ?? null, desc);
    // The first value of the longest run of equal values — the most frequent, ties broken by sort
    // order (the first such run).
    let bestIdx = 0;
    let bestCount = 1;
    let runStart = 0;
    for (let i = 1; i < vals.length; i++) {
      if (valueCmp(vals[i]!, vals[runStart]!) === 0) {
        const runLen = i - runStart + 1;
        if (runLen > bestCount) {
          bestCount = runLen;
          bestIdx = runStart;
        }
      } else {
        runStart = i;
      }
    }
    return vals[bestIdx]!;
  }
  if (a.plan === "percentileDisc") {
    // percentile_disc: an actual sorted value at row ceil(p·N). The fraction may be a scalar or an
    // array (aggregates.md §18); finalizePercentile dispatches and applies the NULL / range-check /
    // empty rules per PG, computing each percentile over the sorted vals.
    const vals = a.osaVals!;
    sortOsaVals(vals, a.osaCollation ?? null, desc);
    return finalizePercentile(a.osaFrac, vals.length === 0, (p) => percentileDiscAt(vals, p));
  }
  if (a.plan === "orderedSetContInterval") {
    // percentile_cont over interval input: interpolate in the interval domain (PG interval_lerp —
    // aggregates.md §13). Values are sorted by their canonical span (interval has no collation, so
    // sortOsaVals uses the value order).
    const vals = a.osaVals!;
    sortOsaVals(vals, a.osaCollation ?? null, desc);
    return finalizePercentile(a.osaFrac, vals.length === 0, (p) => {
      const n = vals.length;
      const pos = p * (n - 1);
      const first = Math.floor(pos);
      const second = Math.ceil(pos);
      const lo = expectInterval(vals[first]!);
      if (first === second) return intervalValue(lo);
      const hi = expectInterval(vals[second]!);
      return intervalValue(intervalLerp(lo, hi, pos - first));
    });
  }
  // percentileCont
  const fs = a.osaFloats!;
  fs.sort((x, y) => dirCmp(floatTotalCmp(x, y), desc));
  return finalizePercentile(a.osaFrac, fs.length === 0, (p) =>
    float64Value(percentileContAt(fs, p)),
  );
}

// finalizePercentile applies the percentile fraction (scalar or array) to a sorted group, computing
// each percentile via compute (spec/design/aggregates.md §13/§18). PG's check order is preserved: a
// scalar null/NULL fraction → NULL; otherwise the range check (22003) fires per fraction BEFORE the
// empty-group check; an empty/all-NULL group → NULL (the whole result, even for an array). For an
// array fraction the result is an array with one percentile per element (a NULL element → a NULL
// element), after every non-NULL element has passed the range check.
export function finalizePercentile(
  frac: Value | null | undefined,
  empty: boolean,
  compute: (p: number) => Value,
): Value {
  if (frac === null || frac === undefined || frac.kind === "null") return nullValue();
  if (frac.kind === "array") {
    // Range-check every non-NULL element FIRST (before the empty-group check, PG).
    const fracs: (number | null)[] = [];
    for (const el of frac.elements) {
      const pf = fractionToF64(el);
      if (pf !== null) checkPercentileFraction(pf);
      fracs.push(pf);
    }
    if (empty) return nullValue(); // an empty/all-NULL group → NULL (not an array of NULLs), PG
    const out: Value[] = [];
    for (const pf of fracs) {
      out.push(pf === null ? nullValue() : compute(pf));
    }
    const n = out.length;
    return { kind: "array", dims: [n], lbounds: [1], elements: out };
  }
  const p = fractionToF64(frac);
  if (p === null) return nullValue();
  checkPercentileFraction(p);
  if (empty) return nullValue();
  return compute(p);
}

// expectInterval returns the Interval of a buffered interval Value (an orderedSetContInterval group
// only ever buffers intervals — the resolver gates the operand to interval).
export function expectInterval(v: Value): Interval {
  if (v.kind !== "interval") throw new Error("percentile_cont(interval) buffered a non-interval");
  return v.iv;
}

// fractionToF64 converts an evaluated percentile fraction (the direct argument, evaluated per group)
// to f64 (aggregates.md §13/§17). null / a NULL Value → null (a NULL fraction yields NULL). A numeric
// value (the resolver restricts the fraction to a numeric family) widens via the IEEE / correctly-
// rounded decimal cast. The range check (22003) is applied by the caller after this.
export function fractionToF64(frac: Value | null | undefined): number | null {
  if (frac === null || frac === undefined || frac.kind === "null") return null;
  switch (frac.kind) {
    case "f64":
    case "f32":
      return frac.value;
    case "int":
      return Number(frac.int);
    case "decimal":
      return Number(frac.dec.render());
    default:
      throw new Error("a non-numeric percentile fraction is rejected at resolve");
  }
}

// percentileDiscAt computes percentile_disc over the already-sorted group values: the value at row
// ceil(p·N) (1-based), i.e. the smallest K with K/N ≥ p (PG orderedsetaggs.c). Caller guarantees
// non-empty + the fraction in range. Reads vals non-destructively (returns the picked element by
// reference, never removing it) so an array fraction can read it repeatedly. spec/design/aggregates.md §13.
export function percentileDiscAt(vals: Value[], p: number): Value {
  const n = vals.length;
  // PG: rownum = ceil(p·N) (1-based), then the value at max(rownum, 1).
  const rownum = Math.ceil(p * n);
  let idx = rownum >= 1 ? rownum - 1 : 0;
  if (idx > n - 1) idx = n - 1;
  return vals[idx]!;
}

// percentileContAt computes percentile_cont over the already-sorted f64 group values: interpolate
// between the two bracketing rows, in f64 with PG's exact operation order — bit-identical across
// cores and to PG (spec/design/aggregates.md §13). Caller guarantees non-empty + the fraction in
// range.
export function percentileContAt(floats: number[], p: number): number {
  const n = floats.length;
  const pos = p * (n - 1);
  const first = Math.floor(pos);
  const second = Math.ceil(pos);
  if (first === second) return floats[first]!;
  const lo = floats[first]!;
  const hi = floats[second]!;
  const proportion = pos - first;
  return lo + proportion * (hi - lo);
}

// dirCmp applies a WITHIN GROUP sort direction to a comparison result (DESC reverses).
export function dirCmp(c: number, desc: boolean): number {
  return desc ? -c : c;
}

// sortOsaVals sorts an ordered-set aggregate's buffered values by its WITHIN GROUP order
// (aggregates.md §13). With no collation, the value-canonical comparison (the same total order
// ORDER BY/MIN/MAX use). With a collation, a stable decorate-sort by the precomputed collation sort
// key bytes (a collated key is always text; an unmapped code point fails 0A000 at this deterministic
// point, like the query ORDER BY). JS Array.prototype.sort is stable, so a comparator that returns 0
// for collation-equal keys keeps them in scan order — deterministic and cross-core identical.
export function sortOsaVals(vals: Value[], collation: Collation | null, desc: boolean): void {
  if (collation === null) {
    vals.sort((a, b) => dirCmp(valueCmp(a, b), desc));
    return;
  }
  // Decorate each value with its collation sort key (text only), sort stably by the key bytes, then
  // undecorate. The keys are built once up front so a sortKey failure (0A000 for an unmapped code
  // point) surfaces at this deterministic point rather than inside the comparator.
  const deco: { key: Uint8Array; val: Value }[] = vals.map((v) => {
    if (v.kind !== "text") {
      throw new Error("a collated WITHIN GROUP key buffers only text");
    }
    return { key: collationSortKey(collation, v.text), val: v };
  });
  deco.sort((a, b) => dirCmp(cmpBytes(a.key, b.key), desc));
  for (let i = 0; i < deco.length; i++) vals[i] = deco[i]!.val;
}

// finalizeHypothetical computes a hypothetical-set aggregate's value (aggregates.md §19): given the
// buffered group key tuples rows, the per-group hypothetical row hyp, and the WITHIN GROUP per-key
// sort specs, count where hyp would rank. rank = 1 + rows strictly before hyp; dense_rank = 1 +
// distinct values strictly before; percent_rank = (rank-1)/N; cume_dist = (#rows ≤ hyp + 1)/(N+1) —
// PG's orderedsetaggs.c formulas exactly. Over an empty group: rank/dense_rank 1, percent_rank 0,
// cume_dist 1.
export function finalizeHypothetical(
  plan: AggPlan,
  rows: Value[][],
  hyp: Value[],
  sorts: KeySort[],
): Value {
  const n = rows.length;
  if (n === 0) {
    switch (plan) {
      case "hypoRank":
      case "hypoDenseRank":
        return intValue(1n);
      case "hypoPercentRank":
        return float64Value(0.0);
      case "hypoCumeDist":
        return float64Value(1.0);
      default:
        throw new Error("finalizeHypothetical only for the hypothetical-set plans");
    }
  }
  let strictlyBefore = 0n;
  let le = 0n; // rows that sort ≤ hyp (for cume_dist's rank with flag +1)
  // The distinct strictly-before key tuples (for dense_rank), value-canonical (the group-key
  // distinctRowKey, the same form the GROUP BY bucketing uses — collapses 1.5/1.50, NULL with NULL).
  const distinct = new Set<string>();
  for (const r of rows) {
    const ord = hypoCmp(r, hyp, sorts);
    if (ord < 0) {
      strictlyBefore += 1n;
      le += 1n;
      distinct.add(distinctRowKey(r));
    } else if (ord === 0) {
      le += 1n;
    }
  }
  switch (plan) {
    case "hypoRank":
      return intValue(strictlyBefore + 1n);
    case "hypoDenseRank":
      return intValue(BigInt(distinct.size) + 1n);
    case "hypoPercentRank":
      return float64Value(Number(strictlyBefore) / n);
    case "hypoCumeDist":
      return float64Value(Number(le + 1n) / (n + 1));
    default:
      throw new Error("finalizeHypothetical only for the hypothetical-set plans");
  }
}

// hypoCmp compares a buffered key tuple a to the hypothetical row b by the WITHIN GROUP order
// (aggregates.md §19): the first key whose comparison is non-equal decides. Each key honors its NULL
// placement, direction, and collation (a collated text key can fail 0A000).
export function hypoCmp(a: Value[], b: Value[], sorts: KeySort[]): number {
  for (let i = 0; i < sorts.length; i++) {
    const ord = compareHypoKey(a[i]!, b[i]!, sorts[i]!);
    if (ord !== 0) return ord;
  }
  return 0;
}

// compareHypoKey compares one WITHIN GROUP key pair under its sort spec (NULL placement + direction +
// collation), mirroring the query ORDER BY key comparison plus the collated-text path (aggregates.md
// §19).
export function compareHypoKey(a: Value, b: Value, ks: KeySort): number {
  if (a.kind === "null" && b.kind === "null") return 0;
  if (a.kind === "null") return ks.nullsFirst ? -1 : 1;
  if (b.kind === "null") return ks.nullsFirst ? 1 : -1;
  let base: number;
  if (ks.collation !== null && a.kind === "text" && b.kind === "text") {
    base = collatedCmp(ks.collation, a.text, b.text);
  } else {
    base = valueCmp(a, b);
  }
  return dirCmp(base, ks.desc);
}

// checkPercentileFraction is the percentile fraction range gate (aggregates.md §13): < 0, > 1, or
// NaN is 22003 (numeric_value_out_of_range), matching PG's "percentile value … is not between 0 and
// 1". Called per group at finalize, after the NULL-fraction check.
export function checkPercentileFraction(p: number): void {
  if (Number.isNaN(p) || p < 0 || p > 1) {
    throw engineError("numeric_value_out_of_range", `percentile value ${p} is not between 0 and 1`);
  }
}

// percentileInputF64 widens a numeric value to f64 for percentile_cont (aggregates.md §13): integers
// via Number(), decimals via the correctly-rounded Number(render()) cast (matching PG's
// numeric→float8), floats unchanged. The resolver restricts the operand to a numeric family.
export function percentileInputF64(v: Value): number {
  switch (v.kind) {
    case "int":
      return Number(v.int);
    case "f32":
    case "f64":
      return v.value;
    case "decimal":
      return Number(v.dec.render());
    default:
      throw new Error("resolver restricts percentile_cont to a numeric operand");
  }
}

// resolveFloatFold finalizes a float SUM's STREAMING scan-order running total (float.md §7; the fold
// order is ledgered non-deterministic). The steps are all order-independent given the accumulated
// state:
//   1. Special values first: any NaN → NaN; else both +Inf and -Inf → NaN; else +Inf → +Inf; else
//      -Inf → -Inf; else the finite running total.
//   2. The running `floatTotal` IS the sum (already width-correct — f32 was re-rounded each add). If
//      it reached ±Inf from finite inputs it is a finite-overflow 22003 (a final isFinite test is
//      equivalent to a per-add one — finite + ±Inf cannot recover to finite; PG yields ±Inf, a
//      documented divergence).
export function resolveFloatFold(a: Acc): number {
  if (a.floatNaN) return NaN;
  if (a.floatPosInf && a.floatNegInf) return NaN;
  if (a.floatPosInf) return Infinity;
  if (a.floatNegInf) return -Infinity;
  const s = a.floatWidth === "f32" ? Math.fround(a.floatTotal) : a.floatTotal;
  if (!Number.isFinite(s)) throw overflow(a.floatWidth); // running total overflowed to ±Inf
  return s;
}

// itemsHaveAggregate reports whether any select item contains an aggregate call.
export function itemsHaveAggregate(items: SelectItems): boolean {
  if (items.kind === "all") return false;
  return items.items.some((it) => exprHasAggregate(it.expr));
}

// windowDefHasAggregate reports whether a window definition's PARTITION BY / ORDER BY keys contain an
// aggregate (`OVER (ORDER BY sum(x))` — spec/design/window.md §5.1). Such an aggregate makes the query
// an aggregate query (a whole-table aggregate if there is no GROUP BY), exactly as a top-level
// aggregate would, so the window keys resolve against the grouped row. Used by both the inline-over
// walk in exprHasAggregate and the WINDOW-clause scan that computes isAgg.
export function windowDefHasAggregate(wd: WindowDef): boolean {
  return wd.partition.some(exprHasAggregate) || wd.order.some((k) => exprHasAggregate(k.expr));
}

// windowsHaveAggregate reports whether any WINDOW-clause entry's keys contain an aggregate (`WINDOW w
// AS (ORDER BY sum(x))`), which — like a top-level aggregate — makes the query an aggregate query
// (spec/design/window.md §5.1). The entries are still named references at this point (the OVER-name
// desugar runs later), so the WINDOW clause is scanned directly.
export function windowsHaveAggregate(windows: [string, WindowDef][]): boolean {
  return windows.some(([, wd]) => windowDefHasAggregate(wd));
}

// isAggregateName reports whether name (case-insensitive) is a catalog aggregate, one of the
// hand-resolved json[b]_object_agg[_unique] aggregates (no catalog row, B4), or an ordered-set
// aggregate (mode/percentile_*, §13 — also not catalog rows, their result/arg mold is special).
export function isAggregateName(name: string): boolean {
  const lname = name.toLowerCase();
  return (
    AGGREGATES.some((a) => a.surface.toLowerCase() === lname) ||
    objectAggClassify(name) !== null ||
    isOrderedSetAggregateName(name)
  );
}

// objectAggClassify classifies a json[b]_object_agg[_unique] name → { asJson, unique }, else null.
// These 2-argument aggregates are hand-resolved (the single-operand aggregate catalog can't express a
// key/value pair), like jsonb_set among the scalar functions (json-sql-functions.md §4).
export function objectAggClassify(name: string): { asJson: boolean; unique: boolean } | null {
  switch (name.toLowerCase()) {
    case "jsonb_object_agg":
      return { asJson: false, unique: false };
    case "json_object_agg":
      return { asJson: true, unique: false };
    case "jsonb_object_agg_unique":
      return { asJson: false, unique: true };
    case "json_object_agg_unique":
      return { asJson: true, unique: true };
    default:
      return null;
  }
}

// isOrderedSetAggregateName reports whether name (case-insensitive) is an ordered-set aggregate
// surface (mode / percentile_cont / percentile_disc — spec/design/aggregates.md §13). These take a
// WITHIN GROUP (ORDER BY …) clause and are resolved by resolveOrderedSetAggregate, intercepted before
// the generic aggregate/scalar dispatch.
export function isOrderedSetAggregateName(name: string): boolean {
  const lname = name.toLowerCase();
  return lname === "mode" || lname === "percentile_cont" || lname === "percentile_disc";
}

// astSubscriptExprs is the sub-expressions of a list of AST subscript specs (each index, or a
// slice's present bounds) — for the Expr tree walkers (spec/design/array.md §6).
export function astSubscriptExprs(subs: SubscriptSpec[]): Expr[] {
  const out: Expr[] = [];
  for (const s of subs) {
    if (!s.isSlice) out.push(s.index);
    else {
      if (s.lower !== null) out.push(s.lower);
      if (s.upper !== null) out.push(s.upper);
    }
  }
  return out;
}

// exprHasAggregate reports whether an expression tree contains an AGGREGATE call anywhere. A
// scalar-function call is not itself an aggregate but may CONTAIN one (abs(sum(x))), so its
// arguments are walked.
export function exprHasAggregate(e: Expr): boolean {
  switch (e.kind) {
    case "funcCall":
      // An aggregate name carrying OVER (inline or a named-window reference) is a WINDOW function,
      // not a bare aggregate (window.md §5.1) — so it does not mark the query as aggregate; its
      // arguments are still walked for nested aggregates. (Detection runs before the OVER-name desugar.)
      // An aggregate INSIDE the inline window definition's keys (`rank() OVER (ORDER BY sum(x))`)
      // also makes the query an aggregate query — those keys resolve against the grouped row (§5.1).
      // A hypothetical-set name with a WITHIN GROUP clause (`rank(x) WITHIN GROUP (…)`) is an
      // aggregate (aggregates.md §19).
      return (
        (e.over == null && e.overName == null && isAggregateName(e.name)) ||
        (e.withinGroup != null && isHypotheticalSetName(e.name)) ||
        e.args.some(exprHasAggregate) ||
        (e.over != null && windowDefHasAggregate(e.over))
      );
    case "cast":
      return exprHasAggregate(e.inner);
    case "extract":
      return exprHasAggregate(e.source);
    case "collate":
      return exprHasAggregate(e.inner);
    case "unary":
      return exprHasAggregate(e.operand);
    case "isNull":
    case "isJson":
    case "jsonCtor":
      return exprHasAggregate(e.operand);
    case "jsonExists":
    case "jsonValue":
    case "jsonQuery":
      return exprHasAggregate(e.ctx) || exprHasAggregate(e.path);
    case "binary":
    case "isDistinct":
      return exprHasAggregate(e.lhs) || exprHasAggregate(e.rhs);
    case "in":
      return exprHasAggregate(e.lhs) || e.list.some(exprHasAggregate);
    case "between":
      return exprHasAggregate(e.lhs) || exprHasAggregate(e.lo) || exprHasAggregate(e.hi);
    case "like":
    case "regex":
      return exprHasAggregate(e.lhs) || exprHasAggregate(e.rhs);
    case "case":
      return (
        (e.operand !== null && exprHasAggregate(e.operand)) ||
        e.whens.some((w) => exprHasAggregate(w.cond) || exprHasAggregate(w.result)) ||
        (e.els !== null && exprHasAggregate(e.els))
      );
    case "coalesce":
    case "greatestLeast":
      return e.args.some(exprHasAggregate);
    case "row":
      return e.fields.some(exprHasAggregate);
    case "array":
      return e.elements.some(exprHasAggregate);
    case "fieldAccess":
    case "fieldStar":
      return exprHasAggregate(e.base);
    case "qualifiedStar":
      return false; // `t.*` is a leaf relation reference — no aggregate
    case "subscript":
      return exprHasAggregate(e.base) || astSubscriptExprs(e.subscripts).some(exprHasAggregate);
    case "quantified":
      return exprHasAggregate(e.lhs) || exprHasAggregate(e.array);
    default:
      return false;
  }
}

// itemsHaveWindow reports whether any select item contains a window-function call (a funcCall
// carrying OVER). A window query resolves its projection in window mode (spec/design/window.md §5.1).
export function itemsHaveWindow(items: SelectItems): boolean {
  if (items.kind === "all") return false;
  return items.items.some((it) => exprHasWindow(it.expr));
}

// orderByHasWindow reports whether any ORDER BY key is (or contains) a window function, so a query
// whose only OVER call sits in the ORDER BY still sets up the window machinery (grammar.md §10,
// window.md §5.1). An ordinal/column key carries no expression.
export function orderByHasWindow(keys: OrderKey[]): boolean {
  return keys.some((k) => k.expr !== null && exprHasWindow(k.expr));
}

// exprHasWindow reports whether an expression tree contains a window-function call anywhere (a
// funcCall whose `over` is set). An ordinary call may CONTAIN one in its arguments
// (abs(row_number() OVER ())), so the arguments are walked; a window call's own PARTITION BY /
// ORDER BY may not contain a window function (rejected at resolve, 42P20), so they are not walked
// here. A subquery is an independent query — a window inside it is the subquery's own.
export function exprHasWindow(e: Expr): boolean {
  switch (e.kind) {
    case "funcCall":
      return e.over != null || e.overName != null || e.args.some(exprHasWindow);
    case "cast":
      return exprHasWindow(e.inner);
    case "extract":
      return exprHasWindow(e.source);
    case "collate":
      return exprHasWindow(e.inner);
    case "unary":
      return exprHasWindow(e.operand);
    case "isNull":
    case "isJson":
    case "jsonCtor":
      return exprHasWindow(e.operand);
    case "jsonExists":
    case "jsonValue":
    case "jsonQuery":
      return exprHasWindow(e.ctx) || exprHasWindow(e.path);
    case "binary":
    case "isDistinct":
      return exprHasWindow(e.lhs) || exprHasWindow(e.rhs);
    case "in":
      return exprHasWindow(e.lhs) || e.list.some(exprHasWindow);
    case "between":
      return exprHasWindow(e.lhs) || exprHasWindow(e.lo) || exprHasWindow(e.hi);
    case "like":
    case "regex":
      return exprHasWindow(e.lhs) || exprHasWindow(e.rhs);
    case "case":
      return (
        (e.operand !== null && exprHasWindow(e.operand)) ||
        e.whens.some((w) => exprHasWindow(w.cond) || exprHasWindow(w.result)) ||
        (e.els !== null && exprHasWindow(e.els))
      );
    case "coalesce":
    case "greatestLeast":
      return e.args.some(exprHasWindow);
    case "row":
      return e.fields.some(exprHasWindow);
    case "array":
      return e.elements.some(exprHasWindow);
    case "fieldAccess":
    case "fieldStar":
      return exprHasWindow(e.base);
    case "qualifiedStar":
      return false; // `t.*` is a leaf relation reference — no window function
    case "subscript":
      return exprHasWindow(e.base) || astSubscriptExprs(e.subscripts).some(exprHasWindow);
    case "quantified":
      return exprHasWindow(e.lhs) || exprHasWindow(e.array);
    default:
      return false;
  }
}

// extendWindow applies the base-window merge rules (spec/design/window.md §5, PostgreSQL
// transformWindowDefinitions): a definition that names a base copies the base's PARTITION BY and —
// if the base has one — its ORDER BY, and supplies its own frame. The extender may not add a
// PARTITION BY (42P20, even when the base has none), may add an ORDER BY only when the base has
// none (42P20 otherwise), and the base must not carry a frame (42P20). The three checks fire in
// PostgreSQL's priority order: PARTITION, then ORDER, then frame. Returns the merged inline
// definition (base = null).
export function extendWindow(base: WindowDef, ext: WindowDef, baseName: string): WindowDef {
  if (ext.partition.length > 0) {
    throw engineError(
      "windowing_error",
      `cannot override PARTITION BY clause of window "${baseName}"`,
    );
  }
  if ((base.order?.length ?? 0) > 0 && ext.order.length > 0) {
    throw engineError("windowing_error", `cannot override ORDER BY clause of window "${baseName}"`);
  }
  if (base.frame != null) {
    throw engineError(
      "windowing_error",
      `cannot copy window "${baseName}" because it has a frame clause`,
    );
  }
  return {
    base: null,
    partition: base.partition,
    order: base.order.length > 0 ? base.order : ext.order,
    frame: ext.frame,
  };
}

// resolveWindowClause resolves a WINDOW clause into all-inline definitions (spec/design/window.md
// §5). Entries are processed left-to-right; an entry naming a base extends an already-resolved
// earlier entry (a self- or forward-reference is therefore "does not exist" — 42704), via
// extendWindow. Every entry is resolved — even ones no OVER references — matching PostgreSQL's
// whole-clause check.
export function resolveWindowClause(windows: [string, WindowDef][]): [string, WindowDef][] {
  const resolved: [string, WindowDef][] = [];
  for (const [name, def] of windows) {
    let r = def;
    if (def.base != null && def.base !== "") {
      const base = lookupWindow(resolved, def.base);
      r = extendWindow(base, def, def.base);
    }
    resolved.push([name, r]);
  }
  return resolved;
}

// lookupWindow finds a (resolved, base = null) window definition by name in `windows`,
// case-insensitively, returning a structured clone (to avoid aliasing), or throws 42704
// `window "<name>" does not exist`.
export function lookupWindow(windows: [string, WindowDef][], name: string): WindowDef {
  const found = windows.find(([n]) => n.toLowerCase() === name.toLowerCase());
  if (found === undefined) {
    throw engineError("undefined_object", `window "${name}" does not exist`);
  }
  return structuredClone(found[1]);
}

// desugarItems rewrites `OVER name` / `OVER (base …)` references in a select list to their
// WINDOW-clause definitions before resolution (spec/design/window.md §5): a pure `overName`
// reference gets the named definition copied into `over`, an inline `over` with a base is merged
// onto the named base (extendWindow); an undefined name is 42704. After this every window call
// carries an inline `over` (base = null), so resolution (S0–S4) handles named and inline windows
// uniformly. Mutates `items`.
export function desugarItems(items: SelectItems, windows: [string, WindowDef][]): void {
  if (items.kind === "all") return;
  for (const it of items.items) {
    desugarNamedWindows(it.expr, windows);
  }
}

// desugarNamedWindows is the recursive Expr walk behind desugarItems: it replaces a funcCall's
// `overName` with the matching WINDOW-clause definition (case-insensitively), throwing 42704 for an
// undefined name. Mirrors Rust's desugar_named_windows exactly (leaves, subscripts, and subqueries
// carry no top-level window ref to rewrite).
export function desugarNamedWindows(e: Expr, windows: [string, WindowDef][]): void {
  switch (e.kind) {
    case "funcCall":
      if (e.overName != null) {
        // `OVER name` — a pure reference: copy the named definition whole, frame included (no merge
        // rules; copying a framed window is forbidden only for the extend form below — §5).
        e.over = lookupWindow(windows, e.overName);
        e.overName = null;
      } else if (e.over != null && e.over.base != null && e.over.base !== "") {
        // `OVER (base …)` — an extend: merge the inline definition onto the named base.
        const base = lookupWindow(windows, e.over.base);
        e.over = extendWindow(base, e.over, e.over.base);
      }
      for (const a of e.args) desugarNamedWindows(a, windows);
      return;
    case "cast":
      desugarNamedWindows(e.inner, windows);
      return;
    case "extract":
      desugarNamedWindows(e.source, windows);
      return;
    case "collate":
      desugarNamedWindows(e.inner, windows);
      return;
    case "unary":
    case "isNull":
    case "isJson":
    case "jsonCtor":
      desugarNamedWindows(e.operand, windows);
      return;
    case "jsonExists":
    case "jsonValue":
    case "jsonQuery":
      desugarNamedWindows(e.ctx, windows);
      desugarNamedWindows(e.path, windows);
      return;
    case "binary":
    case "isDistinct":
      desugarNamedWindows(e.lhs, windows);
      desugarNamedWindows(e.rhs, windows);
      return;
    case "in":
      desugarNamedWindows(e.lhs, windows);
      for (const x of e.list) desugarNamedWindows(x, windows);
      return;
    case "quantified":
      desugarNamedWindows(e.lhs, windows);
      desugarNamedWindows(e.array, windows);
      return;
    case "between":
      desugarNamedWindows(e.lhs, windows);
      desugarNamedWindows(e.lo, windows);
      desugarNamedWindows(e.hi, windows);
      return;
    case "like":
    case "regex":
      desugarNamedWindows(e.lhs, windows);
      desugarNamedWindows(e.rhs, windows);
      return;
    case "row":
      for (const x of e.fields) desugarNamedWindows(x, windows);
      return;
    case "array":
      for (const x of e.elements) desugarNamedWindows(x, windows);
      return;
    case "fieldAccess":
    case "fieldStar":
      desugarNamedWindows(e.base, windows);
      return;
    case "qualifiedStar":
      return; // a leaf relation reference — no named window to desugar
    case "case":
      if (e.operand !== null) desugarNamedWindows(e.operand, windows);
      for (const w of e.whens) {
        desugarNamedWindows(w.cond, windows);
        desugarNamedWindows(w.result, windows);
      }
      if (e.els !== null) desugarNamedWindows(e.els, windows);
      return;
    case "coalesce":
    case "greatestLeast":
      for (const a of e.args) desugarNamedWindows(a, windows);
      return;
    // Leaves, subscripts, and subqueries (independent) carry no top-level window ref to rewrite.
    default:
      return;
  }
}

// NamedCheck is one statement-resolved CHECK constraint: its name (for the 23514 message)
// and the resolved expression evaluated per candidate row.
export type NamedCheck = { name: string; node: RExpr };

// evalChecks evaluates a row's CHECK constraints in name order (constraints.md §4.4):
// TRUE and NULL pass; the first FALSE aborts with 23514 and PG's message. Shared by the
// INSERT and UPDATE write paths.
export function evalChecks(
  checks: NamedCheck[],
  relation: string,
  row: Row,
  env: EvalEnv,
  meter: Meter,
): void {
  for (const c of checks) {
    const v = evalExpr(c.node, row, env, meter);
    if (v.kind === "bool" && !v.value) {
      throw checkViolation(relation, c.name);
    }
  }
}

// rejectCheckStructure applies the structural CHECK-expression rejections
// (spec/design/constraints.md §4.1) in a single depth-first pre-order walk before
// resolution: a subquery is 0A000, an aggregate call 42803, a bind parameter 42P02 — PG's
// codes and messages (oracle-probed; PG interleaves these with resolution in parse order,
// a documented micro-order divergence).
export function rejectCheckStructure(e: Expr): void {
  switch (e.kind) {
    case "scalarSubquery":
    case "exists":
    case "inSubquery":
    case "quantifiedSubquery":
      throw engineError("feature_not_supported", "cannot use subquery in check constraint");
    case "param":
      throw engineError("undefined_parameter", "there is no parameter $" + e.index.toString());
    case "funcCall":
      if (isAggregateName(e.name)) {
        throw engineError(
          "grouping_error",
          "aggregate functions are not allowed in check constraints",
        );
      }
      for (const a of e.args) rejectCheckStructure(a);
      return;
    case "cast":
      return rejectCheckStructure(e.inner);
    case "extract":
      return rejectCheckStructure(e.source);
    case "collate":
      return rejectCheckStructure(e.inner);
    case "unary":
    case "isNull":
    case "isJson":
    case "jsonCtor":
      return rejectCheckStructure(e.operand);
    case "jsonExists":
    case "jsonValue":
    case "jsonQuery":
      rejectCheckStructure(e.ctx);
      rejectCheckStructure(e.path);
      return;
    case "binary":
    case "isDistinct":
    case "like":
    case "regex":
      rejectCheckStructure(e.lhs);
      return rejectCheckStructure(e.rhs);
    case "in":
      rejectCheckStructure(e.lhs);
      for (const elem of e.list) rejectCheckStructure(elem);
      return;
    case "between":
      rejectCheckStructure(e.lhs);
      rejectCheckStructure(e.lo);
      return rejectCheckStructure(e.hi);
    case "case":
      if (e.operand !== null) rejectCheckStructure(e.operand);
      for (const w of e.whens) {
        rejectCheckStructure(w.cond);
        rejectCheckStructure(w.result);
      }
      if (e.els !== null) rejectCheckStructure(e.els);
      return;
    case "coalesce":
    case "greatestLeast":
      for (const a of e.args) rejectCheckStructure(a);
      return;
    case "row":
      for (const f of e.fields) rejectCheckStructure(f);
      return;
    case "array":
      for (const el of e.elements) rejectCheckStructure(el);
      return;
    case "fieldAccess":
    case "fieldStar":
      return rejectCheckStructure(e.base);
    case "qualifiedStar":
      return; // cannot syntactically reach a CHECK (select-item-only); accept structurally
    case "subscript":
      rejectCheckStructure(e.base);
      for (const x of astSubscriptExprs(e.subscripts)) rejectCheckStructure(x);
      return;
    case "quantified":
      rejectCheckStructure(e.lhs);
      return rejectCheckStructure(e.array);
    default: // column, qualifiedColumn, literal
      return;
  }
}

// rejectDefaultStructure is the structural pre-walk for a DEFAULT expression
// (spec/design/constraints.md §2), run before name/type resolution (the same micro-order
// divergence from PG that rejectCheckStructure carries). A default extends the CHECK rejections
// with one more: it may NOT reference a column (it is computed before the row exists). Codes
// match PostgreSQL (oracle-probed): a column reference / subquery is 0A000, an aggregate 42803,
// a parameter 42P02.
export function rejectDefaultStructure(e: Expr): void {
  switch (e.kind) {
    case "column":
    case "qualifiedColumn":
      throw engineError(
        "feature_not_supported",
        "cannot use column reference in DEFAULT expression",
      );
    case "scalarSubquery":
    case "exists":
    case "inSubquery":
    case "quantifiedSubquery":
      throw engineError("feature_not_supported", "cannot use subquery in DEFAULT expression");
    case "param":
      throw engineError("undefined_parameter", "there is no parameter $" + e.index.toString());
    case "funcCall":
      if (isAggregateName(e.name)) {
        throw engineError(
          "grouping_error",
          "aggregate functions are not allowed in DEFAULT expressions",
        );
      }
      for (const a of e.args) rejectDefaultStructure(a);
      return;
    case "cast":
      return rejectDefaultStructure(e.inner);
    case "extract":
      return rejectDefaultStructure(e.source);
    case "collate":
      return rejectDefaultStructure(e.inner);
    case "unary":
    case "isNull":
    case "isJson":
    case "jsonCtor":
      return rejectDefaultStructure(e.operand);
    case "jsonExists":
    case "jsonValue":
    case "jsonQuery":
      rejectDefaultStructure(e.ctx);
      rejectDefaultStructure(e.path);
      return;
    case "binary":
    case "isDistinct":
    case "like":
    case "regex":
      rejectDefaultStructure(e.lhs);
      return rejectDefaultStructure(e.rhs);
    case "in":
      rejectDefaultStructure(e.lhs);
      for (const elem of e.list) rejectDefaultStructure(elem);
      return;
    case "between":
      rejectDefaultStructure(e.lhs);
      rejectDefaultStructure(e.lo);
      return rejectDefaultStructure(e.hi);
    case "case":
      if (e.operand !== null) rejectDefaultStructure(e.operand);
      for (const w of e.whens) {
        rejectDefaultStructure(w.cond);
        rejectDefaultStructure(w.result);
      }
      if (e.els !== null) rejectDefaultStructure(e.els);
      return;
    case "coalesce":
    case "greatestLeast":
      for (const a of e.args) rejectDefaultStructure(a);
      return;
    case "row":
      for (const f of e.fields) rejectDefaultStructure(f);
      return;
    case "array":
      for (const el of e.elements) rejectDefaultStructure(el);
      return;
    case "fieldAccess":
    case "fieldStar":
      return rejectDefaultStructure(e.base);
    case "qualifiedStar":
      return; // cannot syntactically reach a DEFAULT (select-item-only); accept structurally
    case "subscript":
      rejectDefaultStructure(e.base);
      for (const x of astSubscriptExprs(e.subscripts)) rejectDefaultStructure(x);
      return;
    case "quantified":
      rejectDefaultStructure(e.lhs);
      return rejectDefaultStructure(e.array);
    default: // literal, typedLiteral
      return;
  }
}

// indexNamePart is the auto-name part for one index key element (spec/design/indexes.md §2, PG's
// ChooseIndexColumnNames): a column key contributes its (lowercased) column name; a bare-function-call
// expression its function name (`lower(email)` → `lower`); any other expression the literal `expr`.
export function indexNamePart(elem: IndexKeyElem): string {
  if (elem.kind === "column") return elem.name.toLowerCase();
  if (elem.expr.kind === "funcCall") return elem.expr.name.toLowerCase();
  return "expr";
}

// indexKeyLabel is one index key element's introspection label (introspection.md §5.1): a column
// key shows its column name, an expression key its canonical text — the same `columns text[]` cell.
export function indexKeyLabel(k: IndexKey, t: Table): string {
  return k.kind === "column" ? t.columns[k.column]!.name : k.exprText;
}

// indexExprNonimmutableCall reports whether an index-key expression calls a NON-IMMUTABLE built-in
// (spec/design/indexes.md §2): the entropy/clock seam (`uuidv4`/`uuidv7`/`now`/`clock_timestamp` —
// `current_timestamp` desugars to `now`) or the sequence functions
// (`nextval`/`currval`/`setval`/`lastval`) / `current_setting`. Such a function would let the index
// drift from the table, so it is 42P17 at CREATE INDEX. The walk mirrors checkReferencedColumns
// (subqueries are already rejected by resolution). The session-timezone hazard (an expression over
// timestamptz) is handled separately by the caller, so this covers only calls.
export function indexExprNonimmutableCall(e: Expr): boolean {
  const isNonimmutable = (name: string): boolean => {
    switch (name.toLowerCase()) {
      case "uuidv4":
      case "uuidv7":
      case "now":
      case "clock_timestamp":
      case "current_date":
      case "nextval":
      case "currval":
      case "setval":
      case "lastval":
      case "current_setting":
        return true;
      default:
        return false;
    }
  };
  switch (e.kind) {
    case "funcCall":
      return isNonimmutable(e.name) || e.args.some(indexExprNonimmutableCall);
    case "cast":
    case "collate":
      return indexExprNonimmutableCall(e.inner);
    case "extract":
      return indexExprNonimmutableCall(e.source);
    case "unary":
    case "isNull":
    case "isJson":
    case "jsonCtor":
      return indexExprNonimmutableCall(e.operand);
    case "jsonExists":
    case "jsonValue":
    case "jsonQuery":
      return indexExprNonimmutableCall(e.ctx) || indexExprNonimmutableCall(e.path);
    case "binary":
    case "isDistinct":
    case "like":
    case "regex":
      return indexExprNonimmutableCall(e.lhs) || indexExprNonimmutableCall(e.rhs);
    case "in":
      return indexExprNonimmutableCall(e.lhs) || e.list.some(indexExprNonimmutableCall);
    case "between":
      return (
        indexExprNonimmutableCall(e.lhs) ||
        indexExprNonimmutableCall(e.lo) ||
        indexExprNonimmutableCall(e.hi)
      );
    case "case":
      return (
        (e.operand !== null && indexExprNonimmutableCall(e.operand)) ||
        e.whens.some(
          (w) => indexExprNonimmutableCall(w.cond) || indexExprNonimmutableCall(w.result),
        ) ||
        (e.els !== null && indexExprNonimmutableCall(e.els))
      );
    // COALESCE is a pure combinator — immutable iff its arguments are (grammar.md §51).
    case "coalesce":
    case "greatestLeast":
      return e.args.some(indexExprNonimmutableCall);
    case "row":
      return e.fields.some(indexExprNonimmutableCall);
    case "array":
      return e.elements.some(indexExprNonimmutableCall);
    case "fieldAccess":
    case "fieldStar":
      return indexExprNonimmutableCall(e.base);
    case "subscript":
      return (
        indexExprNonimmutableCall(e.base) ||
        astSubscriptExprs(e.subscripts).some(indexExprNonimmutableCall)
      );
    case "quantified":
      return indexExprNonimmutableCall(e.lhs) || indexExprNonimmutableCall(e.array);
    default:
      // column / qualifiedColumn / literal / typedLiteral / param, and any subquery form (rejected by
      // resolution before this walk).
      return false;
  }
}

// indexExprHasSubquery reports whether an index-key expression contains a SUBQUERY
// (spec/design/indexes.md §2): a scalar subquery, EXISTS, IN (subquery), or a quantified subquery.
// A subquery reads other rows, so it is not a deterministic function of this row — 0A000 at CREATE
// INDEX (PostgreSQL: "cannot use subquery in index expression"). Unlike an aggregate/window
// (rejected by resolution), the resolver admits an uncorrelated subquery, so it is caught here.
export function indexExprHasSubquery(e: Expr): boolean {
  switch (e.kind) {
    case "scalarSubquery":
    case "exists":
    case "inSubquery":
    case "quantifiedSubquery":
      return true;
    case "cast":
    case "collate":
      return indexExprHasSubquery(e.inner);
    case "extract":
      return indexExprHasSubquery(e.source);
    case "unary":
    case "isNull":
    case "isJson":
    case "jsonCtor":
      return indexExprHasSubquery(e.operand);
    case "fieldAccess":
    case "fieldStar":
      return indexExprHasSubquery(e.base);
    case "jsonExists":
    case "jsonValue":
    case "jsonQuery":
      return indexExprHasSubquery(e.ctx) || indexExprHasSubquery(e.path);
    case "binary":
    case "isDistinct":
    case "like":
    case "regex":
      return indexExprHasSubquery(e.lhs) || indexExprHasSubquery(e.rhs);
    case "in":
      return indexExprHasSubquery(e.lhs) || e.list.some(indexExprHasSubquery);
    case "quantified":
      return indexExprHasSubquery(e.lhs) || indexExprHasSubquery(e.array);
    case "between":
      return (
        indexExprHasSubquery(e.lhs) || indexExprHasSubquery(e.lo) || indexExprHasSubquery(e.hi)
      );
    case "case":
      return (
        (e.operand !== null && indexExprHasSubquery(e.operand)) ||
        e.whens.some((w) => indexExprHasSubquery(w.cond) || indexExprHasSubquery(w.result)) ||
        (e.els !== null && indexExprHasSubquery(e.els))
      );
    case "coalesce":
    case "greatestLeast":
      return e.args.some(indexExprHasSubquery);
    case "funcCall":
      return e.args.some(indexExprHasSubquery);
    case "row":
      return e.fields.some(indexExprHasSubquery);
    case "array":
      return e.elements.some(indexExprHasSubquery);
    case "subscript":
      return (
        indexExprHasSubquery(e.base) || astSubscriptExprs(e.subscripts).some(indexExprHasSubquery)
      );
    default:
      // column / qualifiedColumn / literal / typedLiteral / param / qualifiedStar — no subquery.
      return false;
  }
}

// rejectIndexPredicateStructure applies the structural rejections for a PARTIAL-index predicate
// (spec/design/indexes.md §9) before resolution: a subquery is 0A000 (cannot use subquery in index
// predicate) and a bind parameter $N is 42P02 (there is no parameter $N) — both admitted by the
// ordinary resolver, so caught here (the aggregate 42803 / window 42P20 / non-boolean 42804
// rejections then fall out of the Forbidden-context boolean resolve). Reuses indexExprHasSubquery for
// the subquery walk, then finds the first param.
export function rejectIndexPredicateStructure(e: Expr): void {
  if (indexExprHasSubquery(e)) {
    throw engineError("feature_not_supported", "cannot use subquery in index predicate");
  }
  const n = indexExprFirstParam(e);
  if (n !== null) {
    throw engineError("undefined_parameter", "there is no parameter $" + n.toString());
  }
}

// indexExprFirstParam returns the 1-based index of the first bind parameter $N in an expression, or
// null if it has none (used by rejectIndexPredicateStructure). Mirrors indexExprHasSubquery's walk.
export function indexExprFirstParam(e: Expr): number | null {
  switch (e.kind) {
    case "param":
      return e.index;
    case "cast":
    case "collate":
      return indexExprFirstParam(e.inner);
    case "extract":
      return indexExprFirstParam(e.source);
    case "unary":
    case "isNull":
    case "isJson":
    case "jsonCtor":
      return indexExprFirstParam(e.operand);
    case "fieldAccess":
    case "fieldStar":
      return indexExprFirstParam(e.base);
    case "jsonExists":
    case "jsonValue":
    case "jsonQuery":
      return indexExprFirstParam(e.ctx) ?? indexExprFirstParam(e.path);
    case "binary":
    case "isDistinct":
    case "like":
    case "regex":
      return indexExprFirstParam(e.lhs) ?? indexExprFirstParam(e.rhs);
    case "in": {
      const l = indexExprFirstParam(e.lhs);
      if (l !== null) return l;
      for (const x of e.list) {
        const p = indexExprFirstParam(x);
        if (p !== null) return p;
      }
      return null;
    }
    case "quantified":
      return indexExprFirstParam(e.lhs) ?? indexExprFirstParam(e.array);
    case "between":
      return indexExprFirstParam(e.lhs) ?? indexExprFirstParam(e.lo) ?? indexExprFirstParam(e.hi);
    case "case": {
      if (e.operand !== null) {
        const o = indexExprFirstParam(e.operand);
        if (o !== null) return o;
      }
      for (const w of e.whens) {
        const c = indexExprFirstParam(w.cond) ?? indexExprFirstParam(w.result);
        if (c !== null) return c;
      }
      return e.els !== null ? indexExprFirstParam(e.els) : null;
    }
    case "coalesce":
    case "greatestLeast": {
      for (const a of e.args) {
        const p = indexExprFirstParam(a);
        if (p !== null) return p;
      }
      return null;
    }
    case "funcCall": {
      for (const a of e.args) {
        const p = indexExprFirstParam(a);
        if (p !== null) return p;
      }
      return null;
    }
    case "row": {
      for (const f of e.fields) {
        const p = indexExprFirstParam(f);
        if (p !== null) return p;
      }
      return null;
    }
    case "array": {
      for (const x of e.elements) {
        const p = indexExprFirstParam(x);
        if (p !== null) return p;
      }
      return null;
    }
    case "subscript": {
      const b = indexExprFirstParam(e.base);
      if (b !== null) return b;
      for (const x of astSubscriptExprs(e.subscripts)) {
        const p = indexExprFirstParam(x);
        if (p !== null) return p;
      }
      return null;
    }
    default:
      // column / qualifiedColumn / literal / typedLiteral / qualifiedStar — no param.
      return null;
  }
}

// checkReferencedColumns returns the distinct columns a CHECK expression references, as
// indices into columns — the input to PG's auto-naming rule (constraints.md §4.3: exactly
// one distinct column → <table>_<col>_check). Resolution already validated every
// reference, so an unknown name is simply skipped; a qualified reference counts its column
// like a bare one (oracle-probed).
export function checkReferencedColumns(e: Expr, columns: Column[]): number[] {
  const out: number[] = [];
  const note = (name: string): void => {
    const lower = name.toLowerCase();
    const i = columns.findIndex((c) => c.name.toLowerCase() === lower);
    if (i >= 0 && !out.includes(i)) out.push(i);
  };
  const walk = (e: Expr): void => {
    switch (e.kind) {
      case "column":
      case "qualifiedColumn":
        note(e.name);
        return;
      case "cast":
        return walk(e.inner);
      case "extract":
        return walk(e.source);
      case "collate":
        return walk(e.inner);
      case "unary":
      case "isNull":
      case "isJson":
      case "jsonCtor":
        return walk(e.operand);
      case "jsonExists":
      case "jsonValue":
      case "jsonQuery":
        walk(e.ctx);
        walk(e.path);
        return;
      case "binary":
      case "isDistinct":
      case "like":
      case "regex":
        walk(e.lhs);
        return walk(e.rhs);
      case "in":
        walk(e.lhs);
        for (const elem of e.list) walk(elem);
        return;
      case "between":
        walk(e.lhs);
        walk(e.lo);
        return walk(e.hi);
      case "case":
        if (e.operand !== null) walk(e.operand);
        for (const w of e.whens) {
          walk(w.cond);
          walk(w.result);
        }
        if (e.els !== null) walk(e.els);
        return;
      case "coalesce":
      case "greatestLeast":
        for (const a of e.args) walk(a);
        return;
      case "funcCall":
        for (const a of e.args) walk(a);
        return;
      case "row":
        for (const f of e.fields) walk(f);
        return;
      case "array":
        for (const el of e.elements) walk(el);
        return;
      case "fieldAccess":
      case "fieldStar":
        return walk(e.base);
      case "qualifiedStar":
        return; // `t.*` cannot appear in a CHECK expression (select-item-only); no columns to note
      case "subscript":
        walk(e.base);
        for (const x of astSubscriptExprs(e.subscripts)) walk(x);
        return;
      case "quantified":
        walk(e.lhs);
        return walk(e.array);
      default: // literal, param; subqueries unreachable in a validated check
        return;
    }
  };
  walk(e);
  return out;
}

// resolveAggregate resolves an aggregate call into a synthetic-row reference, collecting its
// AggSpec. Valid only in collect mode; in Forbidden mode (WHERE/ON/nested) it is 42803. The
// operand resolves in a fresh Forbidden sub-context (a nested aggregate is 42803; its columns
// resolve against the real row). The result type follows the PG widening (aggregates.md §3).
export function resolveAggregate(
  scope: Scope,
  e: { name: string; args: Expr[]; star: boolean; distinct: boolean; filter?: Expr | null },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (!ag.collecting) {
    throw engineError("grouping_error", "aggregate functions are not allowed here");
  }
  const name = e.name.toLowerCase();
  const sub: AggCtx = { collecting: false, groupKeys: [], specs: [] };
  // json[b]_object_agg[_unique] take TWO operands (key, value) — resolve both and encode as a Row
  // operand for the single-operand aggregate framework (the fold splits the composite back out, B4).
  const objAgg = objectAggClassify(name);
  if (objAgg !== null) {
    if (e.star || e.args.length !== 2) throw noAggOverload(name);
    const rk = resolve(scope, e.args[0]!, null, sub, params);
    const rv = resolve(scope, e.args[1]!, null, sub, params);
    const operandRow: RExpr = { kind: "row", fields: [rk.node, rv.node] };
    const result: ResolvedType = objAgg.asJson ? { kind: "json" } : { kind: "jsonb" };
    const slot = ag.groupKeys.length + ag.specs.length;
    ag.specs.push({
      plan: "jsonObjectAgg",
      operand: operandRow,
      jsonAsJson: objAgg.asJson,
      jsonUnique: objAgg.unique,
    });
    return { node: { kind: "column", index: slot }, type: result };
  }
  let plan: AggPlan;
  let operand: RExpr | null;
  let result: ResolvedType;
  // The input float width for a float SUM/AVG (so the canonical fold rounds at the right width).
  let floatWidth: ScalarType | undefined;
  // The B4 json[b]_agg flags (asJson / strict), set for the "jsonAgg" plan only.
  let jsonFlags: JsonAggFlags | undefined;
  if (e.star) {
    // Only COUNT has a star overload (aggregates.md §3); SUM(*) etc. is a syntax error.
    if (!aggregateHasStar(name))
      throw engineError("syntax_error", "* is only valid as the argument of COUNT");
    plan = "countStar";
    operand = null;
    result = { kind: "int", ty: "i64" };
  } else {
    // One operand, resolved in a fresh Forbidden sub-context. The registry validates the (surface,
    // operand-family) overload exists (else 42883) and yields its result code; the plan + result
    // type follow from it (the PG widening). Each aggregate takes exactly one argument.
    if (e.args.length !== 1) {
      throw engineError(
        "undefined_function",
        "no aggregate function matches the given argument count",
      );
    }
    // An aggregate's argument may not contain a window function (PG 42803 — window.md §7): the window
    // stage runs AFTER aggregation, so a window result cannot be folded into an aggregate.
    if (exprHasWindow(e.args[0])) {
      throw engineError(
        "grouping_error",
        "aggregate function calls cannot contain window function calls",
      );
    }
    const r = resolve(scope, e.args[0], null, sub, params);
    operand = r.node;
    const desc = lookupAggregateOverload(name, r.type);
    if (!desc) throw noAggOverload(name);
    [plan, result, floatWidth, jsonFlags] = aggregatePlan(name, desc.result, r.type);
  }
  // FILTER (WHERE cond): resolve the per-row predicate against the input row with aggregates
  // FORBIDDEN — an aggregate inside FILTER is 42803, matching PG (aggregates.md §11). A non-boolean
  // condition (or an untyped NULL, always unknown → folds no row) is 42804. The fold loop evaluates
  // this per row and folds only the rows for which it is TRUE.
  let filter: RExpr | null = null;
  if (e.filter !== undefined && e.filter !== null) {
    const fsub: AggCtx = { collecting: false, groupKeys: [], specs: [] };
    const rf = resolve(scope, e.filter, null, fsub, params);
    if (rf.type.kind !== "bool" && rf.type.kind !== "null") {
      throw typeError("argument of FILTER must be type boolean");
    }
    filter = rf.node;
  }
  // Aggregate results follow the group-key values in the synthetic row.
  const slot = ag.groupKeys.length + ag.specs.length;
  ag.specs.push({
    plan,
    operand,
    floatWidth,
    distinct: e.distinct,
    filter,
    jsonAsJson: jsonFlags?.asJson,
    jsonStrict: jsonFlags?.strict,
  });
  return { node: { kind: "column", index: slot }, type: result };
}

// resolveOrderedSetAggregate resolves agg(direct_args) WITHIN GROUP (ORDER BY key) — mode,
// percentile_cont, percentile_disc (spec/design/aggregates.md §13). Like resolveAggregate it is valid
// only in collect mode (else 42803) and folds into the same AggSpec list, returning a synthetic-row
// reference. The WITHIN GROUP key is the aggregate's operand (resolved with aggregates forbidden — a
// nested aggregate is 42803); the parenthesized args are the per-group direct argument (the
// percentile fraction; empty for mode).
export function resolveOrderedSetAggregate(
  scope: Scope,
  e: {
    name: string;
    args: Expr[];
    distinct: boolean;
    filter?: Expr | null;
    withinGroup?: OrderKey[] | null;
  },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (!ag.collecting) {
    throw engineError("grouping_error", "aggregate functions are not allowed here");
  }
  // DISTINCT cannot decorate an ordered-set aggregate (PG: a 42601 syntax error).
  if (e.distinct) {
    throw engineError("syntax_error", "DISTINCT is not allowed with ordered-set aggregates");
  }
  const name = e.name.toLowerCase();
  const keys = e.withinGroup ?? [];
  // Exactly one WITHIN GROUP sort key (PG models a second as a missing overload → 42883).
  if (keys.length !== 1) throw noAggOverload(name);
  const key = keys[0]!;
  // The aggregated argument: the WITHIN GROUP order key, resolved per row with aggregates FORBIDDEN (a
  // nested aggregate in the order key is 42803, matching PG). A general-expression key (`ORDER BY a + b`)
  // carries expr; a bare/qualified column key carries column (rebuilt here as an Expr so both paths
  // share one resolve).
  const keyExpr: Expr =
    key.expr !== null && key.expr !== undefined
      ? key.expr
      : key.qualifier !== null && key.qualifier !== undefined && key.qualifier !== ""
        ? { kind: "qualifiedColumn", qualifier: key.qualifier, name: key.column }
        : { kind: "column", name: key.column };
  const sub: AggCtx = { collecting: false, groupKeys: [], specs: [] };
  const r = resolve(scope, keyExpr, null, sub, params);
  const operand = r.node;
  const optype = r.type;

  // The WITHIN GROUP key's COLLATION drives the sort (aggregates.md §13): an explicit COLLATE on the
  // key (text operand only — else "collations are not supported by type T", like the query ORDER BY),
  // else a bare/qualified column key inherits its column's frozen collation; otherwise the default C
  // (byte) order. Resolved to the loaded Collation (42704 if not loaded). The finalize sort applies it
  // (an unmapped code point → 0A000 there).
  let collation: Collation | null = null;
  if (key.collation !== null && key.collation !== undefined) {
    if (optype.kind !== "text" && optype.kind !== "null") {
      throw typeError(`collations are not supported by type ${rtName(optype)}`);
    }
    collation = resolveCollationName(scope.catalog, key.collation);
  } else if (key.expr === null || key.expr === undefined) {
    // A bare/qualified column key with no explicit COLLATE inherits the column's frozen collation.
    const res =
      key.qualifier !== null && key.qualifier !== undefined && key.qualifier !== ""
        ? scope.resolveQualified(key.qualifier, key.column)
        : scope.resolveBare(key.column);
    const cn = scope.columnOf(res).collation;
    if (cn !== null) collation = resolveCollationName(scope.catalog, cn);
  }

  let plan: AggPlan;
  let frac: RExpr | null;
  let result: ResolvedType;
  if (name === "mode") {
    // mode() takes no direct argument; mode(x) matches no overload (42883).
    if (e.args.length !== 0) throw noAggOverload(name);
    plan = "mode";
    frac = null;
    result = optype;
  } else if (name === "percentile_disc") {
    // An ARRAY fraction (percentile_disc(ARRAY[…])) returns an array of percentiles, one per element;
    // a scalar fraction returns one value (aggregates.md §18).
    const f = resolveOsaFraction(scope, name, e.args, ag, params);
    frac = f.node;
    plan = "percentileDisc";
    result = arrayIf(optype, f.isArray);
  } else {
    // percentile_cont interpolates: over a NUMERIC input it widens to f64 and returns f64; over an
    // INTERVAL input it interpolates in the interval domain (PG interval_lerp) and returns interval.
    // Any other WITHIN GROUP type matches no overload (42883). An ARRAY fraction makes the result an
    // array of those percentiles (aggregates.md §18).
    const f = resolveOsaFraction(scope, name, e.args, ag, params);
    frac = f.node;
    if (optype.kind === "int" || optype.kind === "decimal" || optype.kind === "float") {
      plan = "percentileCont";
      result = arrayIf({ kind: "float", ty: "f64" }, f.isArray);
    } else if (optype.kind === "interval") {
      plan = "orderedSetContInterval";
      result = arrayIf({ kind: "interval" }, f.isArray);
    } else {
      throw noAggOverload(name);
    }
  }

  // FILTER (WHERE cond): resolved per input row with aggregates forbidden, exactly as for an ordinary
  // aggregate (aggregates.md §11) — a non-boolean cond is 42804, a nested aggregate 42803.
  let filter: RExpr | null = null;
  if (e.filter !== undefined && e.filter !== null) {
    const fsub: AggCtx = { collecting: false, groupKeys: [], specs: [] };
    const rf = resolve(scope, e.filter, null, fsub, params);
    if (rf.type.kind !== "bool" && rf.type.kind !== "null") {
      throw typeError("argument of FILTER must be type boolean");
    }
    filter = rf.node;
  }

  const slot = ag.groupKeys.length + ag.specs.length;
  ag.specs.push({
    plan,
    operand,
    distinct: false,
    filter,
    osaDesc: key.descending,
    osaFrac: frac,
    osaCollation: collation,
  });
  return { node: { kind: "column", index: slot }, type: result };
}

// resolveOsaFraction resolves an ordered-set aggregate's direct argument — the percentile fraction
// (aggregates.md §13/§17). The fraction is evaluated **once per group**, so it may be any expression
// over **grouping columns** (resolved here in the grouped agg context, so a grouping column binds its
// synthetic key slot and a non-grouped column is 42803 — PG's "direct arguments … must use only
// grouped columns"; a constant folds the usual way). An aggregate inside the fraction is 42803 (PG
// forbids nesting). Resolved with a float hint so a bare numeric literal folds to f64. The returned
// node is stored and evaluated per group at finalize. Returns { node, isArray } — a NUMERIC array
// fraction (percentile_cont(ARRAY[…])) computes one percentile per element and returns an array (§18).
// A non-numeric fraction or a wrong argument count matches no overload (42883); a NULL fraction yields
// a NULL result at finalize.
export function resolveOsaFraction(
  scope: Scope,
  name: string,
  args: Expr[],
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; isArray: boolean } {
  if (args.length !== 1) throw noAggOverload(name); // wrong argument count
  // The fraction is evaluated before the fold (it is a direct argument, not an aggregate operand),
  // so a nested aggregate is illegal — 42803, matching PG.
  if (exprHasAggregate(args[0]!)) {
    throw engineError("grouping_error", "aggregate function calls cannot be nested");
  }
  const r = resolve(scope, args[0]!, "f64", ag, params);
  if (
    r.type.kind === "null" ||
    r.type.kind === "float" ||
    r.type.kind === "int" ||
    r.type.kind === "decimal"
  ) {
    return { node: r.node, isArray: false };
  }
  // A NUMERIC array fraction returns an array of percentiles, one per element (aggregates.md §18).
  if (
    r.type.kind === "array" &&
    (r.type.elem.kind === "float" || r.type.elem.kind === "int" || r.type.elem.kind === "decimal")
  ) {
    return { node: r.node, isArray: true };
  }
  throw noAggOverload(name); // a non-numeric fraction matches no overload
}

// arrayIf returns Array(t) when isArray, else t — the result type of an ordered-set aggregate whose
// direct argument is an array vs. a scalar fraction (aggregates.md §18).
export function arrayIf(t: ResolvedType, isArray: boolean): ResolvedType {
  return isArray ? { kind: "array", elem: t } : t;
}

// isHypotheticalSetName reports whether name is a hypothetical-set aggregate surface — rank /
// dense_rank / percent_rank / cume_dist used with WITHIN GROUP (spec/design/aggregates.md §19).
// These names are ALSO window functions; the WITHIN GROUP clause routes them here instead of the
// window path.
export function isHypotheticalSetName(name: string): boolean {
  const lname = name.toLowerCase();
  return (
    lname === "rank" || lname === "dense_rank" || lname === "percent_rank" || lname === "cume_dist"
  );
}

// resolveHypotheticalSetAggregate resolves a hypothetical-set aggregate f(direct_args) WITHIN GROUP
// (ORDER BY keys) — rank, dense_rank, percent_rank, cume_dist (spec/design/aggregates.md §19). The
// direct args are the hypothetical row; the WITHIN GROUP keys are the sort columns. Their counts must
// match (else 42883). Each key operand is buffered per row; each direct arg is evaluated per group
// (it may reference grouping columns) and coerced to the key's type. Like the other ordered-set
// aggregates, OVER is 0A000, DISTINCT is 42601, and it is valid only in a collecting context.
export function resolveHypotheticalSetAggregate(
  scope: Scope,
  e: {
    name: string;
    args: Expr[];
    distinct: boolean;
    filter?: Expr | null;
    withinGroup?: OrderKey[] | null;
  },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (!ag.collecting) {
    throw engineError("grouping_error", "aggregate functions are not allowed here");
  }
  if (e.distinct) {
    throw engineError("syntax_error", "DISTINCT is not allowed with ordered-set aggregates");
  }
  const name = e.name.toLowerCase();
  const keys = e.withinGroup ?? [];
  // The number of hypothetical direct arguments must match the number of ordering columns (PG models
  // a mismatch as a missing overload → 42883).
  if (e.args.length === 0 || e.args.length !== keys.length) {
    throw noAggOverload(name);
  }
  // Resolve each WITHIN GROUP key operand (per row, aggregates forbidden) + its sort spec, then the
  // matching direct argument (per group, in the grouped context so it may reference grouping columns)
  // coerced to the key's type.
  const keyNodes: RExpr[] = [];
  const sorts: KeySort[] = [];
  const argNodes: RExpr[] = [];
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i]!;
    const arg = e.args[i]!;
    // The WITHIN GROUP order key, resolved per row with aggregates FORBIDDEN (a nested aggregate is
    // 42803). A general-expression key carries expr; a bare/qualified column key carries column.
    const keyExpr: Expr =
      key.expr !== null && key.expr !== undefined
        ? key.expr
        : key.qualifier !== null && key.qualifier !== undefined && key.qualifier !== ""
          ? { kind: "qualifiedColumn", qualifier: key.qualifier, name: key.column }
          : { kind: "column", name: key.column };
    const sub: AggCtx = { collecting: false, groupKeys: [], specs: [] };
    const r = resolve(scope, keyExpr, null, sub, params);
    const ktype = r.type;
    // The key's collation (explicit COLLATE — text only — or a bare/qualified column's frozen
    // collation), §13. An unknown name is 42704; a COLLATE on a non-text key is 42804.
    let collation: Collation | null = null;
    if (key.collation !== null && key.collation !== undefined) {
      if (ktype.kind !== "text" && ktype.kind !== "null") {
        throw typeError(`collations are not supported by type ${rtName(ktype)}`);
      }
      collation = resolveCollationName(scope.catalog, key.collation);
    } else if (key.expr === null || key.expr === undefined) {
      const res =
        key.qualifier !== null && key.qualifier !== undefined && key.qualifier !== ""
          ? scope.resolveQualified(key.qualifier, key.column)
          : scope.resolveBare(key.column);
      const cn = scope.columnOf(res).collation;
      if (cn !== null) collation = resolveCollationName(scope.catalog, cn);
    }
    // The hypothetical direct arg, evaluated per group (grouped context); a literal adapts to the
    // key's scalar type via the hint. Its type must match the key's family (else 42883).
    const kt = typeFromResolved(ktype);
    const hint: ScalarType | null = kt.kind === "scalar" ? kt.scalar : null;
    const ar = resolve(scope, arg, hint, ag, params);
    if (!hypoArgCompatible(ar.type, ktype)) {
      throw noAggOverload(name);
    }
    keyNodes.push(r.node);
    sorts.push({ desc: key.descending, nullsFirst: key.nullsFirst, collation });
    argNodes.push(ar.node);
  }

  // FILTER (WHERE cond): per-input-row predicate (aggregates forbidden); restricts buffered rows.
  let filter: RExpr | null = null;
  if (e.filter !== undefined && e.filter !== null) {
    const fsub: AggCtx = { collecting: false, groupKeys: [], specs: [] };
    const rf = resolve(scope, e.filter, null, fsub, params);
    if (rf.type.kind !== "bool" && rf.type.kind !== "null") {
      throw typeError("argument of FILTER must be type boolean");
    }
    filter = rf.node;
  }

  let plan: AggPlan;
  let result: ResolvedType;
  switch (name) {
    case "rank":
      plan = "hypoRank";
      result = { kind: "int", ty: "i64" };
      break;
    case "dense_rank":
      plan = "hypoDenseRank";
      result = { kind: "int", ty: "i64" };
      break;
    case "percent_rank":
      plan = "hypoPercentRank";
      result = { kind: "float", ty: "f64" };
      break;
    case "cume_dist":
      plan = "hypoCumeDist";
      result = { kind: "float", ty: "f64" };
      break;
    default:
      throw new Error("isHypotheticalSetName gates the four names above");
  }
  const slot = ag.groupKeys.length + ag.specs.length;
  ag.specs.push({
    plan,
    operand: null,
    distinct: false,
    filter,
    hypo: { args: argNodes, keys: keyNodes, sorts },
  });
  return { node: { kind: "column", index: slot }, type: result };
}

// hypoArgCompatible reports whether a hypothetical direct argument of type arg is comparable with the
// WITHIN GROUP key of type key (aggregates.md §19). A NULL arg is always allowed; otherwise the two
// must be the same scalar family (numeric Int/Decimal/Float each only match themselves — both float
// kinds match each other since the value comparator orders them — so the buffered key tuple and the
// hypothetical row compare meaningfully).
export function hypoArgCompatible(arg: ResolvedType, key: ResolvedType): boolean {
  if (arg.kind === "null") return true;
  return (
    (arg.kind === "int" && key.kind === "int") ||
    (arg.kind === "decimal" && key.kind === "decimal") ||
    (arg.kind === "float" && key.kind === "float") ||
    (arg.kind === "text" && key.kind === "text") ||
    (arg.kind === "bool" && key.kind === "bool") ||
    (arg.kind === "bytea" && key.kind === "bytea") ||
    (arg.kind === "uuid" && key.kind === "uuid") ||
    (arg.kind === "timestamp" && key.kind === "timestamp") ||
    (arg.kind === "timestamptz" && key.kind === "timestamptz") ||
    (arg.kind === "date" && key.kind === "date") ||
    (arg.kind === "interval" && key.kind === "interval")
  );
}

// resolveGrouping resolves GROUPING(c1, …, ck) (spec/design/aggregates.md §12) — the grouping-sets
// membership function. Valid only in a grouped query's projection / HAVING (collecting); each
// argument must be one of the master grouping columns, else 42803 (matching PostgreSQL). Returns an
// integer (i32) whose bit (k-1-j) is 1 iff c_j is grouped away in the row's grouping set. The value
// is computed per group row at execution from the grouping set's mask, so the call resolves to the
// placeholder slot GROUPING_GS_BASE+index (rebased to its real trailing synthetic slot afterwards).
export function resolveGrouping(
  scope: Scope,
  e: { name: string; args: Expr[]; star: boolean },
  ag: AggCtx,
): { node: RExpr; type: ResolvedType } {
  if (e.star) {
    // GROUPING(*) — PG raises a syntax error; mirror the COUNT-only `*` message (42601).
    throw engineError("syntax_error", "* is only valid as the argument of COUNT");
  }
  if (e.args.length === 0) {
    // GROUPING() with no arguments — PG raises a syntax error (42601).
    throw engineError("syntax_error", "GROUPING requires at least one argument");
  }
  const groupingArgErr = () =>
    engineError(
      "grouping_error",
      "arguments to GROUPING must be grouping expressions of the associated query level",
    );
  // GROUPING is meaningful only in a grouped query (collecting) — including a grouped query that ALSO
  // has window functions (GROUPING SETS + window, aggregates.md §21). Outside a grouped query (a plain
  // window query, or a Forbidden context) its arguments cannot be grouping expressions.
  if (!ag.collecting) throw groupingArgErr();
  const positions: number[] = [];
  for (const arg of e.args) {
    let r: { level: number; index: number };
    if (arg.kind === "column") r = scope.resolveBare(arg.name);
    else if (arg.kind === "qualifiedColumn") r = scope.resolveQualified(arg.qualifier, arg.name);
    // A non-column argument is never a grouping column (jed groups by columns only).
    else throw groupingArgErr();
    if (r.level !== 0) throw groupingArgErr();
    const pos = ag.groupKeys.indexOf(r.index);
    if (pos < 0) throw groupingArgErr();
    positions.push(pos);
  }
  if (ag.groupingSpecs === undefined) ag.groupingSpecs = [];
  const slot = GROUPING_GS_BASE + ag.groupingSpecs.length;
  ag.groupingSpecs.push(positions);
  return { node: { kind: "column", index: slot }, type: { kind: "int", ty: "i32" } };
}

// collectColumn resolves a column reference (already at real flat index `idx`) under an
// aggregate context. In Forbidden mode (and Window mode — a window query's bare columns are not
// grouped, spec/design/window.md §5.1) it reads the real input row directly; in collect mode it
// must be a grouping key — resolved to its synthetic-row slot (its position among the group keys)
// — else 42803.
export function collectColumn(
  scope: Scope,
  ag: AggCtx,
  idx: number,
  name: string,
): { node: RExpr; type: ResolvedType } {
  const type = resolvedTypeOfCol(scope.columnAt(idx).type, scope.catalog);
  if (!ag.collecting) return { node: { kind: "column", index: idx }, type };
  const pos = ag.groupKeys.indexOf(idx);
  if (pos < 0) throw groupingErrorColumn(name);
  return { node: { kind: "column", index: pos }, type };
}

// noAggOverload is 42883 — an aggregate over an operand family it has no overload for.
export function noAggOverload(fn: string): EngineError {
  return engineError("undefined_function", "no " + fn + " aggregate for that argument type");
}

// noFuncOverload is 42883 — a scalar function over argument types it has no overload for.
export function noFuncOverload(fn: string): EngineError {
  return engineError("undefined_function", "no " + fn + " function for those argument types");
}

// isWindowOnlyName reports whether name is a registered WINDOW-only function surface
// (row_number/rank/…). Data-driven over the catalog (WINDOWS). Such a function REQUIRES an OVER
// clause — used without one it is 42809 (spec/design/window.md §7). The catalog aggregates double
// as window functions but are not in WINDOWS, so they are still valid without OVER.
export function isWindowOnlyName(name: string): boolean {
  const lname = name.toLowerCase();
  return WINDOWS.some((w) => w.surface.toLowerCase() === lname);
}

// resolveWindowCall resolves a window-function call `f(args) OVER (window_definition)`
// (spec/design/window.md §5.1). Valid only in a window query's projection (ag.window set);
// anywhere else (WHERE / JOIN ON / HAVING / an aggregate query) it is 42P20. The call collects
// into a WindowSpec and resolves to the synthetic slot base + windowIndex. S0: only row_number().
export function resolveWindowCall(
  scope: Scope,
  e: { name: string; args: Expr[]; star: boolean; over: WindowDef; filter?: Expr | null },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  const lname = e.name.toLowerCase();
  // The plan + result type from the function name. S0: only row_number(); an aggregate name with
  // OVER (a window aggregate) is deferred to S3; any other name is 42883.
  let plan: WindowPlan;
  let result: ResolvedType;
  // The frame-insensitive no-argument ranking functions (S0/S1): row_number/rank/dense_rank → i64.
  const noArgI64: Record<string, WindowPlan> = {
    row_number: "rowNumber",
    rank: "rank",
    dense_rank: "denseRank",
  };
  // The frame-insensitive no-argument ratio functions (S1): percent_rank/cume_dist → f64
  // (PG's float8 — the ratio is the IEEE correctly-rounded f64 division, window.md §4).
  const noArgRatio: Record<string, WindowPlan> = {
    percent_rank: "percentRank",
    cume_dist: "cumeDist",
  };
  // Resolved function arguments (empty for the no-argument ranking functions; ntile's bucket-count
  // argument is the one entry — window.md §4).
  const wargs: RExpr[] = [];
  // The sub-context window ARGUMENTS resolve in (spec/design/window.md §5.1). In a grouped query
  // (ag.collecting) they resolve against the grouped row — a nested aggregate collects into the
  // query's SHARED specs (JS arrays are by-reference, so pushes are visible to ag) and a bare column
  // must be a grouping key (else 42803) — while a nested window is 42P20 (`sub` has no `window`). In
  // a plain window query `sub` is Forbidden (no aggregate/window nesting). `grouped`/`ag.groupKeys`
  // also map the window's PARTITION BY / ORDER BY columns to grouped-row slots.
  // A GROUPING(...) nested in a window argument (GROUPING SETS + window, aggregates.md §21) collects
  // into the query's SHARED groupingSpecs — the same by-reference share as `specs` — so the placeholder
  // it returns is rebased with the rest. Mirrors Rust's mem::take + write-back of grouping_specs.
  const grouped = ag.collecting;
  if (grouped && ag.groupingSpecs === undefined) ag.groupingSpecs = [];
  const sub: AggCtx = grouped
    ? {
        collecting: true,
        groupKeys: ag.groupKeys,
        groupKeyExprs: ag.groupKeyExprs,
        specs: ag.specs,
        groupingSpecs: ag.groupingSpecs,
      }
    : { collecting: false, groupKeys: [], specs: [] };
  if (lname in noArgI64) {
    if (e.star || e.args.length !== 0) {
      throw engineError("undefined_function", `${lname} takes no arguments`);
    }
    plan = noArgI64[lname]!;
    result = { kind: "int", ty: "i64" };
  } else if (lname in noArgRatio) {
    if (e.star || e.args.length !== 0) {
      throw engineError("undefined_function", `${lname} takes no arguments`);
    }
    plan = noArgRatio[lname]!;
    result = { kind: "float", ty: "f64" };
  } else if (lname === "ntile") {
    // ntile(n) — one integer bucket-count argument (window.md §4), resolved in a fresh Forbidden
    // sub-context (no aggregate/window nesting in a window argument). The argument must be int or
    // null (42804).
    if (e.star || e.args.length !== 1) {
      throw engineError("undefined_function", "ntile takes exactly one argument");
    }
    const r = resolve(scope, e.args[0]!, null, sub, params);
    if (r.type.kind !== "int" && r.type.kind !== "null") {
      throw typeError("argument of ntile must be integer");
    }
    wargs.push(r.node);
    plan = "ntile";
    result = { kind: "int", ty: "i64" };
  } else if (lname === "lag" || lname === "lead") {
    // lag/lead(value [, offset [, default]]) — window.md §4. The value expression's type is the
    // result; offset is an integer (default 1); default (returned when the offset leaves the
    // partition) must match the value type. Args resolved in a fresh Forbidden sub-context.
    if (e.star || e.args.length === 0 || e.args.length > 3) {
      throw engineError("undefined_function", `${lname} takes 1 to 3 arguments`);
    }
    const vr = resolve(scope, e.args[0]!, null, sub, params);
    const vty = vr.type;
    // A scalar hint for the default argument: an int(s)/float(s) value type carries its width down
    // so an integer/float default literal resolves to the same scalar (matching the value type).
    const hint: ScalarType | null = vty.kind === "int" || vty.kind === "float" ? vty.ty : null;
    wargs.push(vr.node);
    if (e.args.length >= 2) {
      const or = resolve(scope, e.args[1]!, null, sub, params);
      if (or.type.kind !== "int" && or.type.kind !== "null") {
        throw typeError(`offset of ${lname} must be integer`);
      }
      wargs.push(or.node);
    }
    if (e.args.length === 3) {
      const dr = resolve(scope, e.args[2]!, hint, sub, params);
      if (dr.type.kind !== "null" && !resolvedTypeEqual(dr.type, vty)) {
        throw typeError(`default of ${lname} must match the value type`);
      }
      wargs.push(dr.node);
    }
    plan = lname === "lag" ? "lag" : "lead";
    result = vty;
  } else if (isAggregateName(lname)) {
    // An aggregate used as a window function (S3): reuse the aggregate overload resolution to get the
    // plan + result type; applyWindowStage folds it over the default frame (running with a window
    // ORDER BY, whole-partition without — spec/design/window.md §6). The operand → args[0].
    let aggPlan: AggPlan;
    let aggFloatWidth: ScalarType | undefined;
    let aggJsonFlags: JsonAggFlags | undefined;
    if (e.star) {
      // Only COUNT has a star overload (aggregates.md §3); SUM(*) etc. is a syntax error.
      if (!aggregateHasStar(lname))
        throw engineError("syntax_error", "* is only valid as the argument of COUNT");
      aggPlan = "countStar";
      result = { kind: "int", ty: "i64" };
    } else {
      // One operand, resolved in a fresh Forbidden sub-context (no aggregate/window nesting in a
      // window argument). The registry validates the (surface, operand-family) overload (else 42883).
      if (e.args.length !== 1) {
        throw engineError(
          "undefined_function",
          "no aggregate function matches the given argument count",
        );
      }
      const r = resolve(scope, e.args[0]!, null, sub, params);
      const desc = lookupAggregateOverload(lname, r.type);
      if (!desc) throw noAggOverload(lname);
      [aggPlan, result, aggFloatWidth, aggJsonFlags] = aggregatePlan(lname, desc.result, r.type);
      wargs.push(r.node); // the aggregate operand → args[0]
    }
    plan = "agg";
    // Resolve the window definition + collect the spec here (it carries the extra aggPlan fields),
    // returning early so the shared collection below (which omits them) is not also run.
    const [partition, order, frame] = resolveWindowDef(
      scope,
      e.over,
      sub,
      ag.window?.windowKeys ?? [],
      params,
    );
    // FILTER (WHERE cond) on a window aggregate (aggregates.md §20): a per-frame-row boolean over the
    // INPUT row, resolved with aggregates forbidden (a nested aggregate is 42803, a non-boolean 42804)
    // — exactly the non-window FILTER rule (§11). The window stage folds only the frame rows it keeps.
    let rfilter: RExpr | null = null;
    if (e.filter !== undefined && e.filter !== null) {
      const fsub: AggCtx = { collecting: false, groupKeys: [], specs: [] };
      const rf = resolve(scope, e.filter, null, fsub, params);
      if (rf.type.kind !== "bool" && rf.type.kind !== "null") {
        throw typeError("argument of FILTER must be type boolean");
      }
      rfilter = rf.node;
    }
    if (ag.window === undefined) {
      throw engineError("windowing_error", "window functions are not allowed here");
    }
    const slot = ag.window.base + ag.window.windowSpecs.length;
    ag.window.windowSpecs.push({
      plan,
      partition,
      order,
      args: wargs,
      aggPlan,
      aggFloatWidth,
      aggJsonAsJson: aggJsonFlags?.asJson,
      aggJsonStrict: aggJsonFlags?.strict,
      frame,
      filter: rfilter,
    });
    return { node: { kind: "column", index: slot }, type: result };
  } else if (lname === "first_value" || lname === "last_value" || lname === "nth_value") {
    // Frame-sensitive value pickers (S4, window.md §4). first/last_value take one value
    // expression (→ result type); nth_value takes the value + an integer position.
    if (e.star) {
      throw engineError("syntax_error", "* is only valid as the argument of COUNT");
    }
    const want = lname === "nth_value" ? 2 : 1;
    if (e.args.length !== want) {
      throw engineError("undefined_function", `${lname} takes ${want} argument(s)`);
    }
    const vr = resolve(scope, e.args[0]!, null, sub, params);
    wargs.push(vr.node);
    if (lname === "first_value") {
      plan = "firstValue";
    } else if (lname === "last_value") {
      plan = "lastValue";
    } else {
      const nr = resolve(scope, e.args[1]!, null, sub, params);
      if (nr.type.kind !== "int" && nr.type.kind !== "null") {
        throw typeError("position of nth_value must be integer");
      }
      wargs.push(nr.node);
      plan = "nthValue";
    }
    result = vr.type;
  } else {
    throw engineError("undefined_function", `${lname} is not a window function`);
  }
  // Resolve the window definition (PARTITION BY / ORDER BY expressions → slots, explicit frame).
  // Keys resolve in `sub` (the grouped collecting ctx sharing ag.specs, or plain Forbidden); a
  // non-column key materializes into windowKeys at a WINDOW_KEY_BASE+k placeholder. Before collecting.
  const [partition, order, frame] = resolveWindowDef(
    scope,
    e.over,
    sub,
    ag.window?.windowKeys ?? [],
    params,
  );
  // A window function is allowed only in a window query's projection. In WHERE / a JOIN ON /
  // HAVING / an aggregate query `ag.window` is unset → 42P20 (window.md §7).
  if (ag.window === undefined) {
    throw engineError("windowing_error", "window functions are not allowed here");
  }
  const slot = ag.window.base + ag.window.windowSpecs.length;
  ag.window.windowSpecs.push({ plan, partition, order, args: wargs, frame });
  return { node: { kind: "column", index: slot }, type: result };
}

// windowKeySlot maps a resolved window-key expression to the slot the window stage indexes
// (spec/design/window.md §5.1). A bare column / aggregate (a "column" RExpr) keeps its real row slot —
// the input slot for a plain query, the grouped-row slot for a grouped one — so a column-only window
// is byte-identical to before. Any compound expression is materialized into windowKeys at the
// placeholder slot WINDOW_KEY_BASE+k (rebased once the row layout is final). A key referencing an
// enclosing query (a correlated window — clause names it) is the deferred follow-on (0A000).
export function windowKeySlot(rexpr: RExpr, clause: string, windowKeys: RExpr[]): number {
  if (rexprReferencesOuter(rexpr, 0)) {
    throw engineError("feature_not_supported", `${clause} may not reference an outer query column`);
  }
  if (rexpr.kind === "column") return rexpr.index;
  const k = windowKeys.length;
  windowKeys.push(rexpr);
  return WINDOW_KEY_BASE + k;
}

// resolveWindowDef resolves the PARTITION BY and within-partition ORDER BY (→ sort keys) of an
// OVER (...) clause. Each key is a general expression (spec/design/window.md §5.1) resolved against
// keyCtx: a plain window query passes a Forbidden ctx (columns → real input slots, an aggregate is
// 42803), a grouped one passes a collecting ctx sharing the query's aggregate specs (a bare column →
// its grouping-column slot or 42803, an aggregate sum(x) collects → its agg slot). A bare-column /
// aggregate key keeps its real slot; any compound key is materialized into windowKeys at a
// WINDOW_KEY_BASE+k placeholder. A key referencing an enclosing-query column (a correlated window) is
// 0A000; a window function inside a key is rejected by keyCtx (42P20).
export function resolveWindowDef(
  scope: Scope,
  wd: WindowDef,
  keyCtx: AggCtx,
  windowKeys: RExpr[],
  params: ParamTypes,
): [number[], OrderSlot[], ResolvedFrame | null] {
  const partition: number[] = [];
  for (const key of wd.partition) {
    const { node } = resolve(scope, key, null, keyCtx, params);
    partition.push(windowKeySlot(node, "PARTITION BY", windowKeys));
  }
  const order: OrderSlot[] = [];
  // The ORDER BY key types, captured in lockstep with order — a RANGE value-offset frame folds
  // key ± offset over the single ordering key, so it needs the key's type (§6).
  const orderTypes: Type[] = [];
  for (const key of wd.order) {
    const { node, type } = resolve(scope, key.expr, null, keyCtx, params);
    // The sort-key collation. An explicit trailing COLLATE (rare — parseExpr usually absorbs a
    // COLLATE into the key expression) must be on a text key (42804); otherwise the collation is
    // DERIVED from the key expression (collation.md §1) — a COLLATE inside it is explicit, a bare
    // text column is its frozen implicit collation, every other shape resets to none (C). A collated
    // window ORDER BY honors the collation in both the per-partition sort and peer determination
    // (window.md §3/§5); COLLATE "C" resolves to null (the raw-byte fast path).
    let collation: Collation | null = null;
    if (key.collation !== null) {
      if (type.kind !== "text" && type.kind !== "null") {
        throw typeError(`collations are not supported by type ${rtName(type)}`);
      }
      collation = resolveCollationName(scope.catalog, key.collation);
    } else {
      collation = resolveDeriv(scope.catalog, deriveCollation(scope, key.expr));
    }
    const slot = windowKeySlot(node, "window ORDER BY", windowKeys);
    order.push({ idx: slot, descending: key.descending, nullsFirst: key.nullsFirst, collation });
    orderTypes.push(typeFromResolved(type));
  }
  // The explicit frame (window.md §6): ROWS / GROUPS integer-count offsets, RANGE value offsets.
  let frame: ResolvedFrame | null = null;
  if (wd.frame !== undefined && wd.frame !== null) {
    frame = resolveFrame(wd.frame, order, orderTypes);
  }
  return [partition, order, frame];
}

// resolveFrame resolves an explicit frame clause (spec/design/window.md §6). GROUPS requires an
// ORDER BY (42P20); a RANGE value offset requires exactly one ORDER BY column (42P20) of an integer,
// decimal, or float type (a timestamp/date key is the deferred D4 follow-on, any other type is
// 0A000). A negative offset is 22013. Mirrors Rust's resolve_frame.
export function resolveFrame(
  f: WindowFrame,
  order: OrderSlot[],
  orderTypes: Type[],
): ResolvedFrame {
  const isOffset = (b: FrameBound): boolean => b.kind === "preceding" || b.kind === "following";
  const hasOffset = isOffset(f.start) || isOffset(f.end);
  switch (f.mode) {
    case "rows":
      return {
        mode: "rows",
        start: resolveIntBound(f.start),
        end: resolveIntBound(f.end),
        exclude: f.exclude,
      };
    case "groups":
      if (order.length === 0) {
        throw engineError("windowing_error", "GROUPS mode requires an ORDER BY clause");
      }
      return {
        mode: "groups",
        start: resolveIntBound(f.start),
        end: resolveIntBound(f.end),
        exclude: f.exclude,
      };
    default: // "range"
      if (hasOffset) {
        if (order.length !== 1) {
          throw engineError(
            "windowing_error",
            "RANGE with offset PRECEDING/FOLLOWING requires exactly one ORDER BY column",
          );
        }
        const kt = orderTypes[0]!;
        if (!(typeIsInteger(kt) || typeIsDecimal(kt) || typeIsFloat(kt))) {
          throw engineError(
            "feature_not_supported",
            `RANGE with offset PRECEDING/FOLLOWING is not supported for column type ${typeCanonicalName(kt)}`,
          );
        }
        return {
          mode: "range",
          start: resolveRangeBound(f.start, kt),
          end: resolveRangeBound(f.end, kt),
          exclude: f.exclude,
        };
      }
      // RANGE with only UNBOUNDED / CURRENT ROW bounds — peer/edge based, any number of ORDER BY
      // keys (or none); no key arithmetic, so it reuses the plain bound resolution.
      return {
        mode: "range",
        start: resolveIntBound(f.start),
        end: resolveIntBound(f.end),
        exclude: f.exclude,
      };
  }
}

// resolveIntBound resolves a ROWS/GROUPS frame bound: the offset of `n PRECEDING`/`n FOLLOWING` must
// be a non-negative integer literal (22013 if negative; a non-literal/non-integer offset is 0A000).
export function resolveIntBound(b: FrameBound): ResolvedBound {
  const offsetOf = (e: Expr): Value => {
    if (e.kind === "literal" && e.literal.kind === "int") {
      const n = e.literal.int;
      if (n >= 0n) return intValue(n);
      throw engineError(
        "invalid_preceding_or_following_size",
        "frame starting or ending offset must not be negative",
      );
    }
    throw engineError(
      "feature_not_supported",
      "frame offset must be a non-negative integer literal",
    );
  };
  switch (b.kind) {
    case "unboundedPreceding":
      return { kind: "unboundedPreceding" };
    case "currentRow":
      return { kind: "currentRow" };
    case "unboundedFollowing":
      return { kind: "unboundedFollowing" };
    case "preceding":
      return { kind: "preceding", offset: offsetOf(b.offset) };
    case "following":
      return { kind: "following", offset: offsetOf(b.offset) };
  }
}

// resolveRangeBound resolves a RANGE value-offset bound (window.md §6). The offset literal must be a
// non-negative numeric matching the ordering key type: an integer key takes an integer offset (a
// decimal offset is 0A000, matching PG); a decimal key takes an integer (widened) or decimal offset;
// a float key takes an integer or decimal offset converted to f64 (PG's in_range_float*_float8 — the
// offset is float8 for both f32 and f64 keys). The decimal→f64 conversion traps 22003 on overflow
// (jed's float-cast rule); an int offset is always finite.
export function resolveRangeBound(b: FrameBound, kt: Type): ResolvedBound {
  const offsetOf = (e: Expr): Value => {
    if (e.kind === "literal" && e.literal.kind === "int") {
      const n = e.literal.int;
      if (n < 0n) {
        throw engineError(
          "invalid_preceding_or_following_size",
          "frame starting or ending offset must not be negative",
        );
      }
      if (typeIsFloat(kt)) return float64Value(Number(n));
      return typeIsDecimal(kt) ? decimalValue(Decimal.fromBigInt(n)) : intValue(n);
    }
    if (e.kind === "literal" && e.literal.kind === "decimal") {
      // The select items (and so this frame offset) are structuredClone'd during window desugaring,
      // which strips the Decimal prototype — rebuild a real Decimal from its parts.
      const lit = e.literal.dec;
      const d = Decimal.fromParts(lit.neg, lit.scale, lit.limbs);
      if (d.neg && !d.isZero()) {
        throw engineError(
          "invalid_preceding_or_following_size",
          "frame starting or ending offset must not be negative",
        );
      }
      if (typeIsFloat(kt)) {
        // PG computes in_range_float*_float8 in float8 (even for an f32 key), so the offset is f64.
        const f = Number(d.render());
        if (!Number.isFinite(f)) throw overflow("f64");
        return float64Value(f);
      }
      if (!typeIsDecimal(kt)) {
        throw engineError(
          "feature_not_supported",
          `RANGE with offset PRECEDING/FOLLOWING is not supported for column type ${typeCanonicalName(kt)} and offset type decimal`,
        );
      }
      return decimalValue(d);
    }
    throw engineError(
      "feature_not_supported",
      "frame offset must be a non-negative numeric literal",
    );
  };
  switch (b.kind) {
    case "unboundedPreceding":
      return { kind: "unboundedPreceding" };
    case "currentRow":
      return { kind: "currentRow" };
    case "unboundedFollowing":
      return { kind: "unboundedFollowing" };
    case "preceding":
      return { kind: "preceding", offset: offsetOf(b.offset) };
    case "following":
      return { kind: "following", offset: offsetOf(b.offset) };
  }
}

// === Function registry (spec/design/extensibility.md §5) ============================
// Resolution for the named scalar functions and the aggregates is DATA-DRIVEN: instead of
// re-encoding the name set in hand-written switches (the old known-name gate + result-type match
// + name→variant match), it consults the generated catalog descriptor tables (OPERATORS rows
// with kind === "function", and AGGREGATES) through the lookups below, keyed by (name,
// arg_families). The per-row KERNEL is still reached by id (the `func` name / the `plan`) and
// hand-written per core — §5 forbids codegenning the kernels. The only function-specific
// hand-written data are the result-code / plan interpreters; the spec_constants test proves them
// total over the catalog. Host-registered functions would extend these lookups.

// argFamily is the family a resolved type satisfies, for matching a catalog argFamilies slot.
// null for the NULL family: an untyped NULL matches no *concrete* family (so abs(NULL)/sum(NULL)
// find no overload — 42883), and only the wildcard "any" slot accepts it.
export function argFamily(t: ResolvedType): string | null {
  switch (t.kind) {
    case "int":
      return "integer";
    case "decimal":
      return "decimal";
    case "float":
      return "float";
    case "bool":
      return "boolean";
    case "text":
      return "text";
    case "bytea":
      return "bytea";
    case "uuid":
      return "uuid";
    case "timestamp":
      return "timestamp";
    case "timestamptz":
      return "timestamptz";
    case "date":
      return "date";
    case "interval":
      return "interval";
    case "json":
      return "json";
    case "jsonb":
      return "jsonb";
    case "jsonpath":
      return "jsonpath";
    case "composite":
      // No catalog function takes a composite this slice; it matches no concrete family (only the
      // wildcard "any" slot, via familyMatches) — spec/design/composite.md.
      return null;
    case "array":
      // No built-in function/aggregate argument family for arrays this slice.
      return null;
    case "range":
      // No concrete built-in argument family for ranges this slice (the polymorphic `anyrange`
      // family is matched separately by the range resolver — RF1).
      return null;
    case "null":
      return null;
  }
}

// familyMatches reports whether a resolved argument satisfies one catalog family slot. "any"
// accepts everything (NULL included); a concrete family matches only its own type.
export function familyMatches(slot: string, t: ResolvedType): boolean {
  return slot === "any" || argFamily(t) === slot;
}

// isScalarFuncName reports whether name (lowercased) is a registered scalar function (catalog
// kind === "function") — the data-driven replacement for the old hand-written known-name gate.
export function isScalarFuncName(name: string): boolean {
  return OPERATORS.some((o) => o.kind === "function" && o.name === name);
}

// isVariadicFuncName reports whether name (lowercased) is a VARIADIC scalar function
// (array-functions.md §12) — a kind === "function" row with `variadic` set (num_nulls/num_nonnulls).
export function isVariadicFuncName(name: string): boolean {
  return OPERATORS.some((o) => o.kind === "function" && o.variadic && o.name === name);
}

// lookupScalarOverload returns the matched scalar-function overload row for name over the resolved
// argument types: the kind === "function" catalog row whose argFamilies agree by arity + per-slot
// family. undefined ⇒ no overload (42883). make_interval resolves on its own path (§11).
export function lookupScalarOverload(name: string, tys: ResolvedType[]): OperatorDesc | undefined {
  return OPERATORS.find(
    (o) =>
      o.kind === "function" &&
      o.name === name &&
      o.argFamilies.length === tys.length &&
      o.argFamilies.every((slot, i) => familyMatches(slot, tys[i]!)),
  );
}

// resolvedScalarType is the concrete ScalarType carried by a numeric resolved type (for the
// "promoted" / "same_as_input" result rules). Only reached for the numeric families they admit.
export function resolvedScalarType(t: ResolvedType): ScalarType {
  switch (t.kind) {
    case "int":
    case "float":
      return t.ty;
    case "decimal":
      return "decimal";
    default:
      throw new Error("resolvedScalarType: non-numeric operand");
  }
}

// scalarResultType is the result ScalarType of a scalar function from its catalog result code
// (functions.md §9): "promoted" = the (single) operand's own type; otherwise the code is a literal
// scalar-type id (e.g. "decimal", "f64", "interval", "i16", "timestamptz", "uuid").
export function scalarResultType(code: string, tys: ResolvedType[]): ScalarType {
  if (code === "promoted") return resolvedScalarType(tys[0]!);
  const ty = scalarTypeFromName(code);
  if (ty === undefined) throw new Error("scalarResultType: unknown result code " + code);
  return ty;
}

// aggregateHasStar reports whether aggregate surface (lowercased) has a COUNT(*)-style star
// overload — only COUNT does. The data-driven replacement for the special-cased star arm.
export function aggregateHasStar(surface: string): boolean {
  return AGGREGATES.some((a) => a.surface.toLowerCase() === surface && a.arg === "star");
}

// lookupAggregateOverload returns the matched aggregate overload row for surface (lowercased) over
// a single operand of resolved type t: the arg === "expr" catalog row whose lone argFamilies slot
// matches. undefined ⇒ no overload (42883, e.g. SUM(text)). MIN/MAX/COUNT take "any".
export function lookupAggregateOverload(
  surface: string,
  t: ResolvedType,
): AggregateDesc | undefined {
  return AGGREGATES.find(
    (a) =>
      a.surface.toLowerCase() === surface &&
      a.arg === "expr" &&
      a.argFamilies.length === 1 &&
      familyMatches(a.argFamilies[0]!, t),
  );
}

// aggregatePlan is the runtime plan + result type (+ the float width that rides on the Acc) for an
// aggregate over operand type t, from the matched overload's surface + catalog result code (the PG
// widening — aggregates.md §3). The plan is the aggregate's kernel id (fold/finalize switch on it);
// selecting it from the registered result code keeps the name gate + overload validation
// data-driven while the kernel stays hand-written (§5). surface is the lowercased call name.
export function aggregatePlan(
  surface: string,
  code: string,
  t: ResolvedType,
): [AggPlan, ResolvedType, ScalarType | undefined, JsonAggFlags?] {
  if (surface === "count") return ["count", { kind: "int", ty: "i64" }, undefined];
  if (surface === "sum" && code === "sum_widen") {
    // SUM(i16|i32) → i64; SUM(i64) → decimal (PG widening).
    if (t.kind === "int" && t.ty === "i64") return ["sumDecimal", { kind: "decimal" }, undefined];
    return ["sumInt", { kind: "int", ty: "i64" }, undefined];
  }
  if (surface === "sum" && code === "decimal")
    return ["sumDecimal", { kind: "decimal" }, undefined];
  if (surface === "sum" && code === "same_as_input" && t.kind === "float") {
    // SUM/AVG over float stay the input width (the canonical-order fold — float.md §7).
    return ["sumFloat", { kind: "float", ty: t.ty }, t.ty];
  }
  if (surface === "avg" && code === "decimal") return ["avg", { kind: "decimal" }, undefined];
  if (surface === "avg" && code === "same_as_input" && t.kind === "float") {
    return ["avgFloat", { kind: "float", ty: t.ty }, t.ty];
  }
  if (surface === "min" && code === "same_as_input") return ["min", t, undefined];
  if (surface === "max" && code === "same_as_input") return ["max", t, undefined];
  // jsonb_agg / json_agg / jsonb_agg_strict / json_agg_strict (B4). The (surface, result-code) pair
  // selects the result type + the two flags; the result code is "jsonb" or "json". asJson = the json
  // result type; strict = the _strict variant (skip a NULL-valued row).
  if (surface === "jsonb_agg" && code === "jsonb")
    return ["jsonAgg", { kind: "jsonb" }, undefined, { asJson: false, strict: false }];
  if (surface === "json_agg" && code === "json")
    return ["jsonAgg", { kind: "json" }, undefined, { asJson: true, strict: false }];
  if (surface === "jsonb_agg_strict" && code === "jsonb")
    return ["jsonAgg", { kind: "jsonb" }, undefined, { asJson: false, strict: true }];
  if (surface === "json_agg_strict" && code === "json")
    return ["jsonAgg", { kind: "json" }, undefined, { asJson: true, strict: true }];
  throw new Error(`aggregatePlan: unhandled (${surface}, ${code})`);
}

// JsonAggFlags carries the two B4 flags fixed at resolve (asJson → json result type; strict → skip a
// NULL-valued row), threaded onto the AggSpec / WindowSpec so newAcc can build the matching Acc.
export type JsonAggFlags = { asJson: boolean; strict: boolean };

// resolveFuncCall resolves a function call: an aggregate (COUNT/SUM/MIN/MAX/AVG), a scalar
// function (abs/round/…, spec/design/functions.md §9), the named/defaulted make_interval (§11), or
// 42883 for any other name. Aggregates and scalar functions share the call syntax (grammar.md §17);
// they are distinguished here. Named notation (name => value) is valid only for a function that
// declares parameter names (make_interval); on every other function it is 42883.
export function resolveFuncCall(
  scope: Scope,
  e: {
    name: string;
    args: Expr[];
    argNames: (string | null)[];
    star: boolean;
    distinct: boolean;
    filter?: Expr | null;
    variadic: boolean;
  },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  const lname = e.name.toLowerCase();
  // DISTINCT is an aggregate-only modifier: `abs(DISTINCT x)` is 42809 (PG's wrong_object_type,
  // "DISTINCT specified, but <fn> is not an aggregate function" — aggregates.md §5). Checked before
  // the per-kind dispatch so it covers every non-aggregate path (scalar, array, …).
  if (e.distinct && !isAggregateName(lname)) {
    throw engineError(
      "wrong_object_type",
      `DISTINCT specified, but ${lname} is not an aggregate function`,
    );
  }
  // FILTER is likewise aggregate-only: `abs(x) FILTER (WHERE …)` is 42809 (PG's wrong_object_type,
  // "FILTER specified, but <fn> is not an aggregate function" — aggregates.md §11). Same placement
  // as DISTINCT, so it covers every non-aggregate path before the per-kind dispatch.
  if (e.filter !== undefined && e.filter !== null && !isAggregateName(lname)) {
    throw engineError(
      "wrong_object_type",
      `FILTER specified, but ${lname} is not an aggregate function`,
    );
  }
  // The VARIADIC keyword is valid only on a VARIADIC function (array-functions.md §12); on any
  // other (non-variadic) name it is 42883 (no such overload). Caught before the per-kind dispatch.
  if (e.variadic && !isVariadicFuncName(lname)) throw noFuncOverload(lname);
  if (isVariadicFuncName(lname)) {
    rejectNamed(lname, e.argNames);
    return resolveVariadicFunc(scope, e, ag, params);
  }
  // make_interval is the one named/defaulted function — it keeps its own resolver (§11).
  if (lname === "make_interval") return resolveMakeInterval(scope, e, ag, params);
  // make_timestamp / make_timestamptz are its named (un-defaulted) siblings (§11); make_timestamptz
  // is overloaded on arity (a session-zone 6-arg form + an explicit-zone 7-arg form). Their own
  // resolver picks the overload and normalizes named notation.
  if (lname === "make_timestamp" || lname === "make_timestamptz" || lname === "make_date") {
    return resolveMakeTimestamp(scope, lname, e, ag, params);
  }
  // lower/upper are overloaded across the range accessors (range → element) and the text casing
  // functions (text → text, collation.md §16). Resolve the single argument once and branch on its
  // type, BEFORE the by-name kind dispatch (which would force the range path for both). functions.md §9
  if (lname === "lower" || lname === "upper") {
    rejectNamed(lname, e.argNames);
    if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
    return resolveLowerUpper(scope, lname, e, ag, params);
  }
  // timezone(zone, value) is the desugar of `value AT TIME ZONE zone` (grammar.md §49, timezones.md
  // §6) and a callable function. Overloaded on the value's family (timestamptz → timestamp, timestamp
  // → timestamptz), so it resolves before the generic by-name dispatch. functions.md §9
  if (lname === "timezone") {
    rejectNamed(lname, e.argNames);
    if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
    return resolveTimezone(scope, e, ag, params);
  }
  // date_trunc(unit, value[, zone]) (timezones.md §9.1) — polymorphic on the value family (the result
  // type is the value type) + an optional 3rd zone arg only on a timestamptz, so it resolves before
  // the generic by-name dispatch (which has no such polymorphism).
  if (lname === "date_trunc") {
    rejectNamed(lname, e.argNames);
    if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
    return resolveDateTrunc(scope, e, ag, params);
  }
  // GROUPING(c1, …, ck) — the grouping-sets membership function (spec/design/aggregates.md §12). It
  // is not an aggregate (no DISTINCT/FILTER — those already errored 42809 above) and only resolves
  // inside a grouped query, so it is intercepted before the by-name dispatch.
  if (lname === "grouping") {
    rejectNamed(lname, e.argNames);
    return resolveGrouping(scope, e, ag);
  }
  // jsonb_set / jsonb_insert (json-sql-functions.md §2) take a jsonb target, a text[] path (a bare
  // `'{a,b}'` literal adapts, like `#>`), a jsonb new value, and an optional boolean flag.
  // Hand-resolved (like the accessor operators) — the text[] + adapting-literal + optional-flag
  // signature is outside the catalog family mold.
  if (lname === "jsonb_set" || lname === "jsonb_insert") {
    rejectNamed(lname, e.argNames);
    if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
    const mode: PathSetMode = lname === "jsonb_set" ? "set" : "insert";
    return resolveJsonbSetInsert(scope, lname, mode, e.args, ag, params);
  }
  // `json_object` / `jsonb_object` (json-sql-functions.md §2) build an object from one text[] of
  // alternating keys/values, or two text[] (keys, values). Hand-resolved (the text[] arg + adapting
  // literal are outside the catalog family mold), like jsonb_set.
  if (lname === "json_object" || lname === "jsonb_object") {
    rejectNamed(lname, e.argNames);
    if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
    return resolveJsonObject(scope, lname, lname === "json_object", e.args, ag, params);
  }
  // The scalar jsonpath query functions (P2, jsonpath.md §5): `(ctx jsonb, path jsonpath)`. Hand-
  // resolved (the jsonpath arg + adapting-literal are outside the catalog family mold).
  {
    const pathFnKind: JsonPathFnKind | null =
      lname === "jsonb_path_exists"
        ? "exists"
        : lname === "jsonb_path_query_first"
          ? "queryFirst"
          : lname === "jsonb_path_query_array"
            ? "queryArray"
            : lname === "jsonb_path_match"
              ? "match"
              : null;
    if (pathFnKind !== null) {
      rejectNamed(lname, e.argNames);
      if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
      return resolveJsonpathFn(scope, lname, pathFnKind, e.args, ag, params);
    }
  }
  // Otherwise the registry (the catalog descriptor tables) decides whether the name is an
  // aggregate, a scalar function, or undefined — no hand-written name lists (extensibility.md §5).
  if (isAggregateName(lname)) {
    rejectNamed(lname, e.argNames);
    return resolveAggregate(scope, e, ag, params);
  }
  // The polymorphic array functions (array-functions.md §2) are also kind === "function", so they
  // must be intercepted BEFORE the generic scalar path — their anyarray/anyelement slots need §2
  // unification, which lookupScalarOverload's exact-family match cannot do.
  if (isArrayFuncName(lname)) {
    rejectNamed(lname, e.argNames);
    return resolveArrayFunc(scope, e, ag, params);
  }
  // The polymorphic range accessors (range-functions.md §1) are kind === "function" too, with an
  // anyrange slot the generic scalar path cannot unify — intercept BEFORE the scalar gate.
  if (isRangeFuncName(lname)) {
    rejectNamed(lname, e.argNames);
    return resolveRangeFunc(scope, e, ag, params);
  }
  // A range CONSTRUCTOR (range-functions.md §2): a call whose name is a range type name/alias. Like
  // the array/range functions it is kind === "function", so it must be intercepted BEFORE the generic
  // scalar path (isScalarFuncName matches every function row, the constructor rows included) — its
  // concrete-range result + element coercion are not the family-matched scalar mold.
  if (isRangeCtorName(lname)) {
    rejectNamed(lname, e.argNames);
    return resolveRangeCtor(scope, e, ag, params);
  }
  // The regex scalar functions (regex.md §8 / §8b) are kind === "function" too, but return via a
  // dedicated regexFunc node, so they are intercepted before the generic scalar path.
  if (
    lname === "regexp_replace" ||
    lname === "regexp_match" ||
    lname === "regexp_like" ||
    lname === "regexp_count" ||
    lname === "regexp_substr" ||
    lname === "regexp_instr"
  ) {
    rejectNamed(lname, e.argNames);
    return resolveRegexFunc(scope, e, ag, params);
  }
  // `mod(a, b)` is the function spelling of the `%` (mod) operator — route it to the SAME arithmetic
  // machinery so mod() and % are observably identical (promotion, the integer/decimal/float kernels,
  // 22012/22003). PG's mod() is integer/numeric only; jed additionally accepts mod(float), the
  // `%`-over-float extension. Only the two-arg form is mod(); else fall through → 42883.
  if (lname === "mod" && e.args.length === 2) {
    rejectNamed(lname, e.argNames);
    if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
    return resolveBinary(scope, "mod", e.args[0]!, e.args[1]!, ag, params);
  }
  // `div(a, b)` — the truncated (toward zero) integer quotient of two numerics, at scale 0 (PG
  // div(numeric, numeric)). Resolver-routed because the catalog name "div" already belongs to the
  // `/` operator. Accepts integer + decimal operands (integers promote); a float/other operand →
  // 42883. Two-arg only; else fall through → 42883.
  if (lname === "div" && e.args.length === 2) {
    rejectNamed(lname, e.argNames);
    if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
    const p = resolveOperandPair(scope, e.args[0]!, e.args[1]!, ag, params);
    const numericOK = (t: ResolvedType) =>
      t.kind === "int" || t.kind === "decimal" || t.kind === "null";
    if (!numericOK(p.lt) || !numericOK(p.rt)) throw noFuncOverload("div");
    return scalarFuncNode("div", [p.rl, p.rr], "decimal", undefined);
  }
  // `gcd(a, b)` / `lcm(a, b)` — resolver-routed for the same integer-promotion the arithmetic
  // operators do (a function row's "promoted" result would take only the first operand's width).
  // EXACT/in-contract; integer → promoted integer, a decimal operand → numeric.
  if ((lname === "gcd" || lname === "lcm") && e.args.length === 2) {
    rejectNamed(lname, e.argNames);
    if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
    const { args, result } = resolveIntOrDecimalPair(
      scope,
      lname,
      e.args[0]!,
      e.args[1]!,
      ag,
      params,
    );
    return scalarFuncNode(lname, args, result, undefined);
  }
  // `width_bucket(op, low, high, count)` — resolver-routed so the three value operands reconcile
  // across the integer/decimal families PG's implicit casts span (all-integer or mixed
  // integer/decimal → numeric; all-float → float). count must be integer. result int4.
  if (lname === "width_bucket" && e.args.length === 4) {
    rejectNamed(lname, e.argNames);
    if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
    const rargs: RExpr[] = [];
    const tys: ResolvedType[] = [];
    for (const a of e.args) {
      const r = resolve(scope, a, null, ag, params);
      rargs.push(r.node);
      tys.push(r.type);
    }
    if (tys[3]!.kind !== "int" && tys[3]!.kind !== "null") throw noFuncOverload("width_bucket");
    const anyFloat =
      tys[0]!.kind === "float" || tys[1]!.kind === "float" || tys[2]!.kind === "float";
    const ok = (t: ResolvedType) =>
      anyFloat
        ? t.kind === "float" || t.kind === "null"
        : t.kind === "int" || t.kind === "decimal" || t.kind === "null";
    if (!ok(tys[0]!) || !ok(tys[1]!) || !ok(tys[2]!)) throw noFuncOverload("width_bucket");
    return scalarFuncNode("width_bucket", rargs, "i32", undefined);
  }
  if (isScalarFuncName(lname)) {
    rejectNamed(lname, e.argNames);
    return resolveScalarFunc(scope, e, ag, params);
  }
  throw engineError("undefined_function", "function does not exist: " + e.name);
}

// resolveRegexFunc resolves regexp_replace/regexp_match (regex.md §8) → a regexFunc node whose result
// type (text / text[]) lives in the surrounding ResolvedType. Both are STRICT (text args, NULL
// propagates). A constant pattern is precompiled once here (regex.md §5) — but only when the
// case-insensitive `i` flag is statically known (the flags arg absent or a constant).
export function resolveRegexFunc(
  scope: Scope,
  e: { name: string; args: Expr[]; star: boolean },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
  const name = e.name.toLowerCase();
  let func: "replace" | "match" | "like" | "count" | "substr" | "instr";
  let flagsIdx = -1;
  // intPositions are the integer-typed argument indices; source(0) and pattern(1) are always text.
  let intPositions: number[] = [];
  const n = e.args.length;
  if (name === "regexp_replace" && n === 3) func = "replace";
  else if (name === "regexp_replace" && n === 4) {
    func = "replace";
    flagsIdx = 3;
  } else if (name === "regexp_match" && n === 2) func = "match";
  else if (name === "regexp_match" && n === 3) {
    func = "match";
    flagsIdx = 2;
  } else if (name === "regexp_like" && n === 2) func = "like";
  else if (name === "regexp_like" && n === 3) {
    func = "like";
    flagsIdx = 2;
  } else if (name === "regexp_count" && n === 2) func = "count";
  else if (name === "regexp_count" && n === 3) {
    func = "count";
    intPositions = [2];
  } else if (name === "regexp_count" && n === 4) {
    func = "count";
    flagsIdx = 3;
    intPositions = [2];
  } else if (name === "regexp_substr" && n === 2) func = "substr";
  else if (name === "regexp_substr" && n === 3) {
    func = "substr";
    intPositions = [2];
  } else if (name === "regexp_substr" && n === 4) {
    func = "substr";
    intPositions = [2, 3];
  } else if (name === "regexp_substr" && n === 5) {
    func = "substr";
    flagsIdx = 4;
    intPositions = [2, 3];
  } else if (name === "regexp_substr" && n === 6) {
    func = "substr";
    flagsIdx = 4;
    intPositions = [2, 3, 5];
  } else if (name === "regexp_instr" && n === 2) func = "instr";
  else if (name === "regexp_instr" && n === 3) {
    func = "instr";
    intPositions = [2];
  } else if (name === "regexp_instr" && n === 4) {
    func = "instr";
    intPositions = [2, 3];
  } else if (name === "regexp_instr" && n === 5) {
    func = "instr";
    intPositions = [2, 3, 4];
  } else if (name === "regexp_instr" && n === 6) {
    func = "instr";
    flagsIdx = 5;
    intPositions = [2, 3, 4];
  } else if (name === "regexp_instr" && n === 7) {
    func = "instr";
    flagsIdx = 5;
    intPositions = [2, 3, 4, 6];
  } else throw noFuncOverload(name);

  const rargs: RExpr[] = [];
  for (let i = 0; i < e.args.length; i++) {
    if (intPositions.includes(i)) {
      const r = resolve(scope, e.args[i], "i64", ag, params);
      if (r.type.kind !== "int" && r.type.kind !== "null") throw noFuncOverload(name);
      rargs.push(r.node);
    } else {
      const r = resolve(scope, e.args[i], "text", ag, params);
      requireTextOrNull(r.type);
      rargs.push(r.node);
    }
  }
  // Precompile a constant pattern (rargs[1]) once, folding it for a statically-constant `i` flag.
  let insensitive: boolean | null = false;
  if (flagsIdx >= 0) {
    const f = rargs[flagsIdx];
    insensitive = f.kind === "constText" ? f.value.includes("i") : null;
  }
  let program: RegexProgram | null = null;
  if (rargs[1].kind === "constText" && insensitive !== null) {
    const pat = insensitive ? foldLowerSimple(rargs[1].value, loadedProperty()) : rargs[1].value;
    program = compileRegex(pat);
  }
  // A precompiled program carries the one-shot compileCharged cost flag mutated on first eval, so a
  // reused plan would under-charge the 2nd+ execute — never cache such a plan.
  if (program !== null) params.uncacheable = true;
  let type: ResolvedType;
  if (func === "replace" || func === "substr") type = { kind: "text" };
  else if (func === "match") type = { kind: "array", elem: { kind: "text" } };
  else if (func === "like") type = { kind: "bool" };
  else type = { kind: "int", ty: "i32" }; // count, instr
  return { node: { kind: "regexFunc", func, args: rargs, program, compileCharged: false }, type };
}

// rejectNamed throws 42883 if any argument is named — named notation is valid only for a function
// that declares parameter names (PG's "function ... has no parameter named X").
export function rejectNamed(name: string, argNames: (string | null)[]): void {
  for (const n of argNames) {
    if (n !== null) {
      throw engineError(
        "undefined_function",
        "function " + name + ' has no parameter named "' + n + '"',
      );
    }
  }
}

// scalarFuncDesc returns the lone scalar-function catalog row of this name (e.g. make_interval),
// reading named/default/family metadata for named-notation resolution (functions.md §11) from the
// generated catalog table (CLAUDE.md §5) rather than re-hardcoding it.
export function scalarFuncDesc(name: string): OperatorDesc | undefined {
  return OPERATORS.find((o) => o.kind === "function" && o.name === name);
}

// scalarFuncDescArity is scalarFuncDesc restricted to a given arity — for a named function
// overloaded on arity (make_timestamptz: a 6-arg session-zone form + a 7-arg explicit-zone form),
// so named-notation resolution reads the right slot list (functions.md §11).
export function scalarFuncDescArity(name: string, arity: number): OperatorDesc | undefined {
  return OPERATORS.find((o) => o.kind === "function" && o.name === name && o.arity === arity);
}

// familyHint is the type context offered to an untyped literal in a function-argument slot of the
// given family, so it adapts (functions.md §11): an integer slot offers i64, a float slot offers
// f64 (so a bare 0/1.5 becomes f64 for secs), a text slot offers text (so a bare 'UTC' adapts to
// the make_timestamptz timezone slot). Other families offer no hint (null).
export function familyHint(family: string): ScalarType | null {
  if (family === "integer") return "i64";
  if (family === "float") return "f64";
  if (family === "text") return "text";
  return null;
}

// defaultExpr materializes a catalog DEFAULT (an integer-literal string, verify.rb-checked) as an
// Expr so an omitted trailing argument resolves through the normal literal path — adapting to its
// slot's family (e.g. "0" → f64 for secs). functions.md §11.
export function defaultExpr(lit: string): Expr {
  return { kind: "literal", literal: { kind: "int", int: BigInt(lit) } };
}

// normalizeNamedArgs maps a call's positional + named arguments onto a function's positional
// parameter slots, filling omitted trailing slots from desc.argDefaults (PostgreSQL named notation
// + DEFAULTs, functions.md §11). Returns the positional Expr array of length desc.arity. Errors:
// 42601 a positional arg after a named one (also caught at parse) or a duplicated name; 42883 an
// unknown parameter name, too many arguments, or a missing non-defaulted slot (no overload).
export function normalizeNamedArgs(
  desc: OperatorDesc,
  args: Expr[],
  argNames: (string | null)[],
): Expr[] {
  const arity = desc.arity;
  const slots: (Expr | null)[] = new Array(arity).fill(null);
  const namesEmpty = argNames.length === 0;
  let seenNamed = false;
  for (let i = 0; i < args.length; i++) {
    const nm = namesEmpty ? null : argNames[i];
    if (nm === null || nm === undefined) {
      if (seenNamed) {
        throw engineError("syntax_error", "positional argument cannot follow named argument");
      }
      if (i >= arity) throw noFuncOverload(desc.name); // too many positional arguments
      slots[i] = args[i]!;
      continue;
    }
    seenNamed = true;
    const idx = desc.argNames.findIndex((p) => p.toLowerCase() === nm.toLowerCase());
    if (idx < 0) {
      throw engineError(
        "undefined_function",
        "function " + desc.name + ' has no parameter named "' + nm + '"',
      );
    }
    if (slots[idx] !== null) {
      throw engineError("syntax_error", 'argument name "' + nm + '" used more than once');
    }
    slots[idx] = args[i]!;
  }
  const firstDefaulted = arity - desc.argDefaults.length;
  const out: Expr[] = [];
  for (let i = 0; i < arity; i++) {
    const slot = slots[i];
    if (slot !== null) {
      out.push(slot);
    } else if (i >= firstDefaulted) {
      out.push(defaultExpr(desc.argDefaults[i - firstDefaulted]!));
    } else {
      throw noFuncOverload(desc.name); // missing required argument
    }
  }
  return out;
}

// resolveMakeInterval resolves make_interval(years, months, weeks, days, hours, mins, secs) — the
// engine's first named + defaulted function (functions.md §11). Normalize named/positional args +
// defaults onto the seven slots, resolve each with its declared family as the type hint (so a bare
// numeric literal adapts to the f64 secs slot), and emit a make_interval node. The arguments
// keep their families (no promotion); a wrong family in a slot is 42883.
export function resolveMakeInterval(
  scope: Scope,
  e: { name: string; args: Expr[]; argNames: (string | null)[]; star: boolean },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
  const desc = scalarFuncDesc("make_interval");
  if (desc === undefined) throw new Error("make_interval is in the catalog");
  const positional = normalizeNamedArgs(desc, e.args, e.argNames);
  const rargs: RExpr[] = [];
  for (let i = 0; i < positional.length; i++) {
    const fam = desc.argFamilies[i]!;
    const r = resolve(scope, positional[i]!, familyHint(fam), ag, params);
    // Type-check against the declared family. A NULL adapts (NULL propagates); a f32 secs is
    // read at eval and widened losslessly to f64 (no cast node — cost matches the cores).
    const ok =
      r.type.kind === "null" ||
      (fam === "integer" && r.type.kind === "int") ||
      (fam === "float" && r.type.kind === "float");
    if (!ok) throw noFuncOverload("make_interval");
    rargs.push(r.node);
  }
  return scalarFuncNode("make_interval", rargs, "interval", undefined);
}

// resolveMakeTimestamp resolves make_timestamp(year, month, mday, hour, min, sec) /
// make_timestamptz(…[, timezone]) — the named (but un-defaulted) make_interval siblings
// (functions.md §11). make_timestamptz is overloaded on arity: a 6-arg form (interpret in the
// session zone) and a 7-arg form (an explicit timezone text). The right overload is chosen by
// whether the call supplies a 7th positional argument or names the timezone parameter; the chosen
// catalog row then drives named-notation normalization. Each slot resolves with its declared family
// as the type hint (a bare numeric literal adapts to the f64 sec slot, a bare string to the text
// timezone slot); a wrong family in a slot is 42883.
export function resolveMakeTimestamp(
  scope: Scope,
  name: string, // "make_timestamp" | "make_timestamptz" | "make_date"
  e: { name: string; args: Expr[]; argNames: (string | null)[]; star: boolean },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
  const isTz = name === "make_timestamptz";
  // Pick the overload: the 7-arg explicit-zone form is selected by a 7th positional argument or a
  // named timezone; otherwise the 6-arg form. make_timestamp has only the 6-arg form and
  // make_date only its 3-arg (year, month, day) form.
  let arity = name === "make_date" ? 3 : 6;
  if (isTz) {
    const namesEmpty = e.argNames.length === 0;
    let positional = 0;
    let namesTimezone = false;
    for (let i = 0; i < e.args.length; i++) {
      const nm = namesEmpty ? null : e.argNames[i];
      if (nm === null || nm === undefined) positional++;
      else if (nm.toLowerCase() === "timezone") namesTimezone = true;
    }
    if (positional > 6 || namesTimezone) arity = 7;
  }
  const desc = scalarFuncDescArity(name, arity);
  if (desc === undefined) throw noFuncOverload(name);
  const positional = normalizeNamedArgs(desc, e.args, e.argNames);
  const rargs: RExpr[] = [];
  for (let i = 0; i < positional.length; i++) {
    const fam = desc.argFamilies[i]!;
    const r = resolve(scope, positional[i]!, familyHint(fam), ag, params);
    // Type-check against the declared family. A NULL adapts (NULL propagates); a f32 sec is read at
    // eval and widened losslessly to f64 (no cast node — cost matches the cores).
    const ok =
      r.type.kind === "null" ||
      (fam === "integer" && r.type.kind === "int") ||
      (fam === "float" && r.type.kind === "float") ||
      (fam === "text" && r.type.kind === "text");
    if (!ok) throw noFuncOverload(name);
    rargs.push(r.node);
  }
  if (name === "make_date") return scalarFuncNode("make_date", rargs, "date", undefined);
  return isTz
    ? scalarFuncNode("make_timestamptz", rargs, "timestamptz", undefined)
    : scalarFuncNode("make_timestamp", rargs, "timestamp", undefined);
}

// f64ToMicros converts make_interval's secs (double precision) to a microsecond count: one
// correctly-rounded multiply, rounded half-away-from-zero to a bigint (the engine's one mode —
// float.md §6, via floatToIntHalfAway). A non-finite or out-of-i64-range product traps 22008
// (interval out of range), matching PG and the other cores.
export function f64ToMicros(secs: number): bigint {
  const p = secs * 1_000_000;
  if (!Number.isFinite(p)) throw engineError("datetime_field_overflow", "interval out of range");
  const r = floatToIntHalfAway(p); // bigint, half-away-from-zero
  if (r < -9223372036854775808n || r > 9223372036854775807n) {
    throw engineError("datetime_field_overflow", "interval out of range");
  }
  return r;
}

// resolveScalarFunc resolves a scalar-function call (abs/round) into a per-row scalarFunc node.
// Unlike an aggregate it is legal in any context, so its arguments resolve in the SAME ag
// context (a nested aggregate is still collected in a projection and 42803 in WHERE). The
// overload is picked by the argument families; no match is 42883. spec/design/functions.md §9.
export function resolveScalarFunc(
  scope: Scope,
  e: { name: string; args: Expr[]; star: boolean },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
  let name = e.name.toLowerCase() as ScalarFuncName;
  // char_length / character_length are SQL-standard aliases of length (string-functions.md) with NO
  // catalog row of their own, so rewrite them to length BEFORE the lookup (unlike power/ceiling,
  // which DO have their own catalog rows and are looked up by the spelled name — matching Rust/Go).
  if ((name as string) === "char_length" || (name as string) === "character_length")
    name = "length";
  const rargs: RExpr[] = [];
  const tys: ResolvedType[] = [];
  for (const a of e.args) {
    const r = resolve(scope, a, null, ag, params);
    rargs.push(r.node);
    tys.push(r.type);
  }
  // Pick the overload by argument families and its result type by the catalog `result` code
  // (extensibility.md §5) — by the SPELLED name, so `power(numeric,numeric)` and `power(float,float)`
  // both resolve (the decimal `power` row has no `pow` alias, matching Rust/Go).
  const desc = lookupScalarOverload(name, tys);
  if (!desc) throw noFuncOverload(name);
  // Eval-kernel aliases that share a backing kernel id: `power(x, y)` is PG's name for jed's pow (the
  // name gap, float.md §8); `ceiling` is PG's alias of `ceil` (functions.md §9). The catalog lookup
  // above used the spelled name (both have catalog rows); the kernel reuses pow/ceil.
  let func: ScalarFuncName = name;
  if ((func as string) === "power") func = "pow";
  if ((func as string) === "ceiling") func = "ceil";
  // Every float function computes at the operand's float width (argWidth), so a f32 operand
  // rounds at binary32 even where the catalog's result is f64; abs(float) also keeps that width
  // as its result. Non-float args carry no width. pow is the one (float, float) function — it
  // promotes its mixed-width pair to a common width and widens both arguments to it.
  let argWidth: ScalarType | undefined;
  if (func === "pow" && tys[0].kind === "float" && tys[1].kind === "float") {
    argWidth = promoteFloat(tys[0].ty, tys[1].ty);
    rargs[0] = widenFloatTo(rargs[0]!, tys[0].ty, argWidth);
    rargs[1] = widenFloatTo(rargs[1]!, tys[1].ty, argWidth);
  } else if (tys.length >= 1 && tys[0].kind === "float") {
    argWidth = tys[0].ty;
  }
  const result = scalarResultType(desc.result, tys);
  return scalarFuncNode(func, rargs, result, argWidth);
}

// scalarFuncNode builds a resolved scalar-function node + its public type.
export function scalarFuncNode(
  func: ScalarFuncName,
  args: RExpr[],
  result: ScalarType,
  argWidth: ScalarType | undefined,
): { node: RExpr; type: ResolvedType } {
  return {
    node: { kind: "scalarFunc", func, args, result, argWidth },
    type: resolvedTypeOf(result),
  };
}

// resolveVariadicFunc resolves a VARIADIC scalar-function call (num_nulls/num_nonnulls —
// array-functions.md §12). The lone catalog row's last parameter is variadic; the call is EITHER a
// spread of trailing arguments OR (with the VARIADIC keyword) a single array passed directly.
// Non-strict (null = "none"): the node carries no blanket NULL short-circuit. The result type is the
// catalog `result` (i32 here), independent of the arguments.
export function resolveVariadicFunc(
  scope: Scope,
  e: { name: string; args: Expr[]; star: boolean; variadic: boolean },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
  const name = e.name.toLowerCase();
  const desc = scalarFuncDesc(name)!;
  const k = desc.arity; // declared parameter count (the last is variadic)
  const varFamily = desc.argFamilies[k - 1]!; // the variadic element family (last slot)
  // The json/jsonb builders share the spread/array-form validation below but emit their own eval node
  // and a json/jsonb result; the count functions (num_nulls/num_nonnulls) keep RExpr "variadic".
  const jsonBuild = jsonBuildClassify(name);
  const rargs: RExpr[] = [];

  if (e.variadic) {
    // VARIADIC-array form: exactly k args (fixed params + the one array). The fixed params match
    // their concrete families; the last operand MUST be an array (else 42804).
    if (e.args.length !== k) throw noFuncOverload(name);
    for (let i = 0; i < e.args.length; i++) {
      const r = resolve(scope, e.args[i]!, null, ag, params);
      if (i + 1 === k) {
        // the variadic (array) operand
        if (r.type.kind !== "array") {
          // A non-array operand (incl. a bare untyped NULL) is 42804 — PG's exact code.
          throw engineError("datatype_mismatch", "VARIADIC argument must be an array");
        }
        // "any" accepts any element type; a concrete variadic family must match.
        if (varFamily !== "any" && !familyMatches(varFamily, r.type.elem))
          throw noFuncOverload(name);
      } else if (!familyMatches(desc.argFamilies[i]!, r.type)) {
        throw noFuncOverload(name);
      }
      rargs.push(r.node);
    }
  } else {
    // Spread form: at least `k` args (so a variadic function needs ≥1 variadic arg — num_nulls() is
    // 42883). The json builders are the exception: a ZERO-arg spread is valid (json_build_array() →
    // [], json_build_object() → {}), so their floor is the fixed-param count (k-1 = 0). The fixed
    // params match their concrete families; every argument from the variadic slot onward matches the
    // variadic element family ("any" ⇒ all).
    const minArgs = jsonBuild !== null ? k - 1 : k;
    if (e.args.length < minArgs) throw noFuncOverload(name);
    for (let i = 0; i < e.args.length; i++) {
      const r = resolve(scope, e.args[i]!, null, ag, params);
      const slot = i < k - 1 ? desc.argFamilies[i]! : varFamily;
      if (!familyMatches(slot, r.type)) throw noFuncOverload(name);
      rargs.push(r.node);
    }
  }

  const result = scalarResultType(desc.result, []);
  if (jsonBuild !== null) {
    return {
      node: {
        kind: "jsonBuild",
        buildKind: jsonBuild.buildKind,
        json: jsonBuild.json,
        args: rargs,
        arrayForm: e.variadic,
      },
      type: resolvedTypeOf(result),
    };
  }
  return {
    node: { kind: "variadic", func: name as VariadicFuncName, args: rargs, arrayForm: e.variadic },
    type: resolvedTypeOf(result),
  };
}

// jsonBuildClassify classifies a VARIADIC json/jsonb builder name → { buildKind, json }, or null for
// the count functions (num_nulls/num_nonnulls keep RExpr "variadic"). json-sql-functions.md §2.
export function jsonBuildClassify(
  name: string,
): { buildKind: JsonBuildKind; json: boolean } | null {
  switch (name) {
    case "jsonb_build_array":
      return { buildKind: "array", json: false };
    case "json_build_array":
      return { buildKind: "array", json: true };
    case "jsonb_build_object":
      return { buildKind: "object", json: false };
    case "json_build_object":
      return { buildKind: "object", json: true };
    default:
      return null;
  }
}

// === Polymorphic array-function resolution (spec/design/array-functions.md §2) ======
// The anyarray/anyelement pseudo-families are not real families (argFamily returns null for an
// array), so the generic lookupScalarOverload cannot match an array function. These helpers add the
// unification: one type variable ELEM, bound from an anyarray slot's element type and an anyelement
// slot's type by structural equality, read back into the reserved result codes anyarray (= ELEM[])
// and anyelement (= ELEM).

// isArrayFuncName reports whether name (lowercased) is a polymorphic array function — a
// kind === "function" catalog row whose argFamilies mention anyarray/anyelement. Data-driven.
export function isArrayFuncName(name: string): boolean {
  return OPERATORS.some(
    (o) =>
      o.kind === "function" &&
      o.name === name &&
      o.argFamilies.some((f) => f === "anyarray" || f === "anyelement"),
  );
}

// resolvedTypeEqual reports structural equality of two resolved types (the unification check):
// integers/floats by width, arrays recursively by element type, composites by name + field types,
// everything else by kind.
// The ScalarType of a scalar resolved type, or null for a container/null type (composite / array /
// range / json / null). Used by the element-wise array→array cast resolver (spec/design/array.md §7)
// to decide whether the source element is a scalar with an admitted scalarPairCastable cast.
export function resolvedToScalar(t: ResolvedType): ScalarType | null {
  switch (t.kind) {
    case "int":
    case "float":
      return t.ty;
    case "bool":
      return "boolean";
    case "text":
      return "text";
    case "decimal":
      return "decimal";
    case "bytea":
      return "bytea";
    case "uuid":
      return "uuid";
    case "timestamp":
      return "timestamp";
    case "timestamptz":
      return "timestamptz";
    case "date":
      return "date";
    case "interval":
      return "interval";
    default:
      return null; // composite / array / range / json / jsonb / jsonpath / null
  }
}

// Whether jed admits an element-wise array→array cast from source element scalar `from` to target
// element scalar `to` (spec/design/array.md §7). Mirrors the scalar cast matrix (spec/types/casts.toml)
// for the pairs an array element can take: numeric↔numeric, text→numeric/boolean/uuid, boolean⇄i32,
// uuid⇄text, uuid⇄bytea. The identity (from === to) is handled by the caller. A pair outside this set
// is rejected (42804) at resolve.
export function scalarPairCastable(from: ScalarType, to: ScalarType): boolean {
  const numeric = (t: ScalarType) => isInteger(t) || isDecimal(t) || isFloat(t);
  if (numeric(from) && numeric(to)) return true;
  if (isText(from) && (numeric(to) || isBool(to) || isUuid(to))) return true;
  if (isBool(from) && to === "i32") return true;
  if (from === "i32" && isBool(to)) return true;
  if (isUuid(from) && (isText(to) || isBytea(to))) return true;
  if (isBytea(from) && isUuid(to)) return true;
  return false;
}

export function resolvedTypeEqual(a: ResolvedType, b: ResolvedType): boolean {
  if (a.kind !== b.kind) return false;
  if (a.kind === "int" || a.kind === "float") return a.ty === (b as { ty: ScalarType }).ty;
  if (a.kind === "array" || a.kind === "range")
    return resolvedTypeEqual(a.elem, (b as { elem: ResolvedType }).elem);
  if (a.kind === "composite") {
    const bc = b as {
      name: string | null;
      fields: { name: string; type: ResolvedType }[];
    };
    if (a.name !== bc.name || a.fields.length !== bc.fields.length) return false;
    return a.fields.every((f, i) => resolvedTypeEqual(f.type, bc.fields[i]!.type));
  }
  return true;
}

// matchPoly matches an overload's slots (which may contain anyarray/anyelement) against the resolved
// argument types, returning { elem, matched }. When matched, elem is null if every polymorphic arg was
// an untyped NULL (ELEM undeterminable). Three passes: anyarray (binds ELEM := the element type),
// anyelement (may precede its binding array — array_prepend), then concrete family slots.
export function matchPoly(
  slots: readonly string[],
  tys: ResolvedType[],
): { elem: ResolvedType | null; matched: boolean } {
  let elem: ResolvedType | null = null;
  const unify = (x: ResolvedType): boolean => {
    if (elem === null) {
      elem = x;
      return true;
    }
    return resolvedTypeEqual(elem, x);
  };
  for (let j = 0; j < slots.length; j++) {
    if (slots[j] === "anyarray") {
      const t = tys[j]!;
      if (t.kind === "array") {
        if (!unify(t.elem)) return { elem: null, matched: false };
      } else if (t.kind !== "null") {
        return { elem: null, matched: false }; // a non-array where anyarray is required
      }
    }
  }
  // anyrange binds ELEM := the range's element type, like anyarray (both definitive, before
  // anyelement) — range-functions.md §1.
  for (let j = 0; j < slots.length; j++) {
    if (slots[j] === "anyrange") {
      const t = tys[j]!;
      if (t.kind === "range") {
        if (!unify(t.elem)) return { elem: null, matched: false };
      } else if (t.kind !== "null") {
        return { elem: null, matched: false }; // a non-range where anyrange is required
      }
    }
  }
  for (let j = 0; j < slots.length; j++) {
    if (slots[j] === "anyelement" && tys[j]!.kind !== "null") {
      if (!unify(tys[j]!)) return { elem: null, matched: false };
    }
  }
  for (let j = 0; j < slots.length; j++) {
    if (
      slots[j] !== "anyarray" &&
      slots[j] !== "anyrange" &&
      slots[j] !== "anyelement" &&
      !familyMatches(slots[j]!, tys[j]!)
    ) {
      return { elem: null, matched: false };
    }
  }
  return { elem, matched: true };
}

// polyResultType is the result ResolvedType of an array function from its catalog result code and the
// bound ELEM: anyarray → ELEM[], anyelement → ELEM (both 42P18 if ELEM is undeterminable); any other
// code is a concrete scalar id (i32, text).
export function polyResultType(code: string, elem: ResolvedType | null): ResolvedType {
  if (code === "anyarray") {
    if (elem === null) throw indeterminatePoly();
    return { kind: "array", elem };
  }
  if (code === "anyrange") {
    if (elem === null) throw indeterminatePoly();
    return { kind: "range", elem };
  }
  if (code === "anyelement") {
    if (elem === null) throw indeterminatePoly();
    return elem;
  }
  // A concrete array result `<scalar>[]` (array_positions → "i32[]"): the element type is fixed
  // (independent of ELEM), so the result is Array(scalar) (array-functions.md §8).
  if (code.endsWith("[]")) {
    const base = code.slice(0, -2);
    const bty = scalarTypeFromName(base);
    if (bty === undefined) throw new Error("polyResultType: unknown array element " + base);
    return { kind: "array", elem: resolvedTypeOf(bty) };
  }
  const ty = scalarTypeFromName(code);
  if (ty === undefined) throw new Error("polyResultType: unknown result code " + code);
  return resolvedTypeOf(ty);
}

// indeterminatePoly is the 42P18 raised when an array function's polymorphic type cannot be
// determined because every polymorphic argument was an untyped NULL (array_append(NULL, NULL)).
export function indeterminatePoly(): EngineError {
  return engineError(
    "indeterminate_datatype",
    "could not determine polymorphic type because input has type unknown",
  );
}

// elemScalarHint is the element type's ScalarType, for the literal-adaptation hint
// (array-functions.md §2): the bound array element type is threaded back as the ctx when re-resolving
// the polymorphic args, so a bare integer/decimal literal element adapts (with range-checking) to it.
// null for a composite/array/NULL element.
export function elemScalarHint(t: ResolvedType): ScalarType | null {
  switch (t.kind) {
    case "int":
    case "float":
      return t.ty;
    case "decimal":
      return "decimal";
    case "text":
      return "text";
    case "bool":
      return "boolean";
    case "bytea":
      return "bytea";
    case "uuid":
      return "uuid";
    case "timestamp":
      return "timestamp";
    case "timestamptz":
      return "timestamptz";
    case "date":
      return "date";
    case "interval":
      return "interval";
    case "json":
      return "json";
    case "jsonb":
      return "jsonb";
    case "jsonpath":
      return "jsonpath";
    default:
      return null;
  }
}

// resolveArrayFunc resolves a polymorphic array function call (array-functions.md §3): resolve the
// arguments, unify ELEM across the anyarray/anyelement slots to pick the overload (42883 on no match),
// and compute the result type from the matched result code. Two passes (§2): pass 1 resolves the
// arguments with no hint to discover the array's element type; if that element is a scalar, pass 2
// re-resolves the polymorphic-slot arguments with it as the ctx, so an untyped literal element (or an
// ARRAY[…] constructor argument) adapts to the array's element type, with a range check. The kernel id
// is the name; NULL handling lives in the eval kernel.
export function resolveArrayFunc(
  scope: Scope,
  e: { name: string; args: Expr[]; star: boolean },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
  const name = e.name.toLowerCase() as ArrayFuncName;
  // Each array-function name is single-overload; find its row by (name, arity). A wrong argument count
  // matches no overload (42883), exactly as a missing scalar overload does.
  const desc = OPERATORS.find(
    (o) => o.kind === "function" && o.name === name && o.arity === e.args.length,
  );
  if (!desc) throw noFuncOverload(name);
  const slots = desc.argFamilies;

  const rargs: RExpr[] = [];
  const tys: ResolvedType[] = [];
  for (const a of e.args) {
    const r = resolve(scope, a, null, ag, params);
    rargs.push(r.node);
    tys.push(r.type);
  }
  // Pass 2: adapt the polymorphic args to the array's element type, if it is a scalar. The hint is the
  // element type of the first anyarray argument.
  let hint: ScalarType | null = null;
  for (let j = 0; j < slots.length; j++) {
    if (slots[j] === "anyarray" && tys[j]!.kind === "array") {
      hint = elemScalarHint((tys[j] as { elem: ResolvedType }).elem);
      break;
    }
  }
  if (hint !== null) {
    for (let j = 0; j < slots.length; j++) {
      if (slots[j] === "anyarray" || slots[j] === "anyelement") {
        const r = resolve(scope, e.args[j]!, hint, ag, params);
        rargs[j] = r.node;
        tys[j] = r.type;
      }
    }
  }
  const { elem, matched } = matchPoly(slots, tys);
  if (!matched) throw noFuncOverload(name);
  const type = polyResultType(desc.result, elem);
  return { node: { kind: "arrayFunc", func: name, args: rargs }, type };
}

// isRangeFuncName reports whether name (lowercased) is a polymorphic range function — a
// kind === "function" catalog row whose argFamilies mention anyrange (range-functions.md §1).
// Data-driven, so a new range-function row wires here without touching this gate.
export function isRangeFuncName(name: string): boolean {
  return OPERATORS.some(
    (o) => o.kind === "function" && o.name === name && o.argFamilies.some((f) => f === "anyrange"),
  );
}

// rangeFuncId is the kernel id for range accessor name (each is single-arity, so the name selects
// the kernel). Total over the catalog's range-function names (isRangeFuncName gates the call).
export function rangeFuncId(name: string): RangeFuncName {
  switch (name) {
    case "lower":
    case "upper":
    case "isempty":
    case "lower_inc":
    case "upper_inc":
    case "lower_inf":
    case "upper_inf":
      return name;
    default:
      throw new Error("rangeFuncId: " + name + " is not a catalog range function");
  }
}

// resolveLowerUpper resolves lower/upper, overloaded across the range accessors and the text casing
// functions (functions.md §9, collation.md §16). The single argument resolves once (offering "text" as
// the literal-adaptation hint, so a bare NULL / untyped $1 adapts to text — the common case; a typed
// range keeps its range type and ignores the scalar hint). A text/NULL argument folds case ("casing",
// result text); a range argument is the bound accessor ("rangeFunc", result the element type);
// anything else is 42883 (no overload).
export function resolveLowerUpper(
  scope: Scope,
  name: string,
  e: { name: string; args: Expr[] },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (e.args.length !== 1) throw noFuncOverload(name);
  const r = resolve(scope, e.args[0], "text", ag, params);
  if (r.type.kind === "text" || r.type.kind === "null") {
    return {
      node: { kind: "casing", upper: name === "upper", arg: r.node },
      type: { kind: "text" },
    };
  }
  if (r.type.kind === "range") {
    return {
      node: { kind: "rangeFunc", func: rangeFuncId(name), args: [r.node] },
      type: r.type.elem,
    };
  }
  throw noFuncOverload(name);
}

// resolveTimezone resolves timezone(zone, value) — the desugar of `value AT TIME ZONE zone`
// (timezones.md §6). zone must be text (else 42804); the result family is the OTHER timestamp family
// of value: timestamptz → timestamp (render the instant locally) and timestamp → timestamptz
// (interpret the wall clock in the zone). Any other value family — or an untyped/NULL value, which
// cannot pick an overload — is 42883.
export function resolveTimezone(
  scope: Scope,
  e: { name: string; args: Expr[] },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (e.args.length !== 2) throw noFuncOverload("timezone");
  const zone = resolve(scope, e.args[0], "text", ag, params);
  const value = resolve(scope, e.args[1], null, ag, params);
  // A non-text zone, or a non-timestamp value, is 42883 — PG resolves AT TIME ZONE via function
  // overload (timezone(text, timestamptz) / timezone(text, timestamp)), so any other arg pair is "no
  // such function" (PG-matching, oracle-pinned), not a datatype_mismatch. A NULL zone is allowed (it
  // propagates to NULL at eval).
  const zoneOk = zone.type.kind === "text" || zone.type.kind === "null";
  if (zoneOk && value.type.kind === "timestamptz") {
    return {
      node: { kind: "atTimeZone", zone: zone.node, value: value.node, toTimestamptz: false },
      type: { kind: "timestamp" },
    };
  }
  if (zoneOk && value.type.kind === "timestamp") {
    return {
      node: { kind: "atTimeZone", zone: zone.node, value: value.node, toTimestamptz: true },
      type: { kind: "timestamptz" },
    };
  }
  throw noFuncOverload("timezone");
}

// resolveDateTrunc resolves date_trunc(unit, value[, zone]) (timezones.md §9.1). unit is text (a
// runtime value, validated at eval); value is timestamp / timestamptz / interval; the optional zone
// (text) is the 3-arg form, valid only for a timestamptz value. The result family is the value
// family. A non-text unit/zone, a non-datetime value, or the 3-arg form on a non-timestamptz value is
// 42883 (a date value also has no overload — jed has no implicit date->timestamp cast).
export function resolveDateTrunc(
  scope: Scope,
  e: { name: string; args: Expr[] },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (e.args.length !== 2 && e.args.length !== 3) throw noFuncOverload("date_trunc");
  const unit = resolve(scope, e.args[0], "text", ag, params);
  const value = resolve(scope, e.args[1], null, ag, params);
  if (unit.type.kind !== "text" && unit.type.kind !== "null") throw noFuncOverload("date_trunc");
  const vk = value.type.kind;
  if (vk !== "timestamp" && vk !== "timestamptz" && vk !== "interval") {
    throw noFuncOverload("date_trunc");
  }
  let zone: RExpr | null = null;
  if (e.args.length === 3) {
    if (vk !== "timestamptz") throw noFuncOverload("date_trunc");
    const z = resolve(scope, e.args[2], "text", ag, params);
    if (z.type.kind !== "text" && z.type.kind !== "null") throw noFuncOverload("date_trunc");
    zone = z.node;
  }
  return {
    node: { kind: "dateTrunc", unit: unit.node, value: value.node, zone },
    type: value.type,
  };
}

// resolveRangeFunc resolves a polymorphic range accessor over the anyrange pseudo-family
// (range-functions.md §1). Simpler than resolveArrayFunc — the accessors take a single anyrange arg
// with no anyelement arg, so there is no element-hint literal adaptation. lower/upper resolve to ELEM
// (the bound type), the rest to boolean. The kernel id is the name; NULL handling lives in the eval
// kernel.
export function resolveRangeFunc(
  scope: Scope,
  e: { name: string; args: Expr[]; star: boolean },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
  const name = e.name.toLowerCase();
  const desc = OPERATORS.find(
    (o) => o.kind === "function" && o.name === name && o.arity === e.args.length,
  );
  if (!desc) throw noFuncOverload(name);
  const slots = desc.argFamilies;

  const rargs: RExpr[] = [];
  const tys: ResolvedType[] = [];
  for (const a of e.args) {
    const r = resolve(scope, a, null, ag, params);
    rargs.push(r.node);
    tys.push(r.type);
  }
  const { elem, matched } = matchPoly(slots, tys);
  if (!matched) throw noFuncOverload(name);
  const type = polyResultType(desc.result, elem);
  // range_merge(anyrange, anyrange) → anyrange is a SET operation (= union, non-strict), not a scalar
  // accessor: emit the shared "rangeSetOp" node (range-functions.md §4). polyResultType already raised
  // 42P18 if the element was indeterminate (both args untyped NULL), so the result type is bound here.
  if (name === "range_merge") {
    return { node: { kind: "rangeSetOp", op: "merge", args: rargs }, type };
  }
  return {
    node: { kind: "rangeFunc", func: rangeFuncId(name), args: rargs },
    type,
  };
}

// isRangeCtorName reports whether name (lowercased) is a range CONSTRUCTOR call
// (range-functions.md §2): a call whose name is a range type name or alias (i32range/int4range/
// numrange/…). The constructor functions are the only ones whose name is a range type name, so
// rangeByName resolving is exactly the gate — data-driven over the RANGES table, no hand-written
// name list.
export function isRangeCtorName(name: string): boolean {
  return rangeByName(name) !== undefined;
}

// rangeBoundAssignable reports whether a bound argument of resolved type `t` is assignable to range
// element `elem`, mirroring the storeValue coercions the kernel will apply (range-functions.md §2):
// a NULL is an infinite bound (always ok); an integer adapts to an integer (range-checked) or
// decimal element; a decimal to a decimal element; an already-temporal value to its own element;
// and a string literal/text to a temporal element (parsed at eval). Anything else is no overload
// (42883).
export function rangeBoundAssignable(t: ResolvedType, elem: ScalarType): boolean {
  switch (t.kind) {
    case "null":
      return true;
    case "int":
      return isInteger(elem) || isDecimal(elem);
    case "decimal":
      return isDecimal(elem);
    case "timestamp":
      return isTimestamp(elem);
    case "timestamptz":
      return isTimestamptz(elem);
    case "date":
      return isDate(elem);
    case "text":
      return isTimestamp(elem) || isTimestamptz(elem) || isDate(elem);
    default:
      return false;
  }
}

// resolveRangeCtor resolves a range constructor call (i32range(lo, hi[, bounds]) and the five
// siblings, plus the int4range/int8range aliases — range-functions.md §2). The target range type
// comes from the call name (rangeByName, alias-aware); the result type is fixed (concrete), not
// polymorphic. Each bound resolves with the element scalar as the literal-adaptation context (so `1`
// adapts to the element width, `'2024-01-01'` to a date), then is type-checked assignable to the
// element; the optional third argument is the bounds-flags TEXT. The kernel (evalRangeCtor) does the
// element coercion (assignment-style, 22003), the flags parse (42601 / 22000), and finalize.
export function resolveRangeCtor(
  scope: Scope,
  e: { name: string; args: Expr[]; star: boolean },
  ag: AggCtx,
  params: ParamTypes,
): { node: RExpr; type: ResolvedType } {
  if (e.star) throw engineError("syntax_error", "* is only valid as the argument of COUNT");
  const name = e.name.toLowerCase();
  const desc = rangeByName(name);
  if (desc === undefined) throw new Error("isRangeCtorName gated the call");
  const elem = elementScalar(desc);
  // Only the 2-arg (lo, hi) and 3-arg (lo, hi, bounds) overloads exist.
  if (e.args.length !== 2 && e.args.length !== 3) throw noFuncOverload(name);
  const rargs: RExpr[] = [];
  for (let i = 0; i < e.args.length; i++) {
    const a = e.args[i]!;
    if (i < 2) {
      // A bound: offer the element scalar as the literal-adaptation hint, then check the resolved
      // type is assignable to the element (else no overload).
      const r = resolve(scope, a, elem, ag, params);
      if (!rangeBoundAssignable(r.type, elem)) throw noFuncOverload(name);
      rargs.push(r.node);
    } else {
      // The bounds-flags argument: TEXT (a NULL is allowed at resolve — the kernel traps it 22000
      // at eval, matching PG "flags argument must not be null").
      const r = resolve(scope, a, null, ag, params);
      if (r.type.kind !== "text" && r.type.kind !== "null") throw noFuncOverload(name);
      rargs.push(r.node);
    }
  }
  return {
    node: { kind: "rangeCtor", elem, args: rargs },
    type: { kind: "range", elem: resolvedTypeOf(elem) },
  };
}

// groupingErrorColumn is the 42803 for a non-aggregated column with no GROUP BY.
export function groupingErrorColumn(name: string): EngineError {
  return engineError(
    "grouping_error",
    "column " + name + " must appear in the GROUP BY clause or be used in an aggregate function",
  );
}

// ============================================================================
// Resolution scope (multi-table FROM — spec/design/grammar.md §15).
//
// A Scope is the ordered list of relations a SELECT's FROM clause puts in scope, each
// carrying the flat COLUMN OFFSET at which its columns begin in the concatenated (joined)
// row. A resolved column reference bakes a single flat index offset+local into "column", so
// the joined row is just each relation's row concatenated in FROM order and the evaluator is
// unchanged. A single-table SELECT / UPDATE / DELETE is a one-relation scope (offset 0).
//
// NOTE (forward-compat): the scope keys resolution ONLY on column name and type — never on a
// column's notNull / primaryKey flags. A column on the nullable side of a future outer join
// is NULL-extended at runtime regardless of its declared nullability (grammar.md §15).
// ============================================================================

// ScopeRel is one relation in a FROM scope: its label (alias, else table name, lower-cased
// for case-insensitive matching), the table, and the flat offset of its first column. A
// qualifierOnly relation is visible ONLY to qualified references — the RETURNING old/new
// row-version pseudo-relations (grammar.md §32): bare-column resolution skips it (no new
// ambiguity), every other statement never builds one.
// `cte` is set (to the CTE list index) when this relation is a reference to a CTE
// (spec/design/cte.md) rather than a base table — its `table` is the binding's synthetic relation
// and exec delivers its rows from the CteCtx. Undefined for a base table / SRF / pseudo-relation.
export type ScopeRel = {
  label: string;
  table: Table;
  offset: number;
  qualifierOnly?: boolean;
  cte?: number;
  // db is the relation's explicit database qualifier (attached-databases.md §3), carried from the
  // tableRef so the store is re-looked-up in the right database at exec (a store is resolved by name
  // per-access). undefined for a bare (implicit-scope) name — then the scoped funnels fall through to
  // the temp-first walk, so this is behavior-neutral for every unqualified query. It also gates off
  // index-bound pushdown for an attachment relation (detectScanBound / detectINLBound).
  db?: string;
};

// Resolved is how a column reference resolved against the scope CHAIN (spec/design/grammar.md
// §26): level === 0 is a LOCAL column of this query (a flat index into the joined row); level >= 1
// is a correlated OUTER reference to an enclosing query (level hops outward, index the flat column
// index within that ancestor's row).
export type Resolved = { level: number; index: number };

// MergeCol is a USING/NATURAL merged column (spec/design/grammar.md §15): `name` is the (lowercased)
// join column and `index` the flat row index a bare reference resolves to — the surviving side (the
// left column for INNER/LEFT, the right for RIGHT; FULL JOIN USING, a COALESCE, is deferred 0A000).
// Both underlying copies are recorded in the scope's `hidden` set.
export type MergeCol = { name: string; index: number };

// outerOf lifts a parent-scope resolution into the child's frame: one more hop outward.
export function outerOf(r: Resolved): Resolved {
  return { level: r.level + 1, index: r.index };
}

// naturalCommonCols is the USING column list a NATURAL join derives (spec/design/grammar.md §15):
// the column names common to the LEFT relations of the join (rels[seg..k]) and the right relation
// (rels[k+1]), in LEFT order with each name taken once (its first occurrence). An empty result
// degenerates the join to a CROSS join. (A merged column on the left keeps its underlying name, so a
// re-merge via a NATURAL chain is found here too.)
export function naturalCommonCols(rels: ScopeRel[], seg: number, k: number): string[] {
  const right = rels[k + 1]!;
  const seen = new Set<string>();
  const out: string[] = [];
  for (let i = seg; i <= k; i++) {
    for (const c of rels[i]!.table.columns) {
      const lc = c.name.toLowerCase();
      if (!seen.has(lc)) {
        seen.add(lc);
        if (columnIndex(right.table, c.name) >= 0) out.push(c.name);
      }
    }
  }
  return out;
}
